            | SemanticApplySpineMissingDirectValueBlocked -> "semantic_apply_spine_missing_direct_value_blocked"
            | SemanticRootCompleteStaleRetargetLiveReplayLivelockBlocked -> "semantic_root_complete_stale_retarget_live_replay_livelock_blocked"
            | SemanticOther x -> x

        // ALPHA979: this is the smallest compile-safe step away from stringly
        // scheduling in the new keyed global-fuse branch.  It does not pretend the
        // whole worklist is reimagined yet; it gives the fuse path a real decision
        // value carrying the repeat/cap evidence, with string rendering confined to
        // the logging / Frame.status boundary.
        type GlobalFuseReplayDecision =
            | ParentContinuationFuseDeferred of int * int
            | ParentContinuationFuseBlocked of int * int
            | OrphanGlobalFuseDeferred of int * int
            | OrphanGlobalFuseBlocked of int * int

        let globalFuseReplayDecisionRepeat decision =
            match decision with
            | ParentContinuationFuseDeferred(repeat, _)
            | ParentContinuationFuseBlocked(repeat, _)
            | OrphanGlobalFuseDeferred(repeat, _)
            | OrphanGlobalFuseBlocked(repeat, _) -> repeat

        let globalFuseReplayDecisionCap decision =
            match decision with
            | ParentContinuationFuseDeferred(_, cap)
            | ParentContinuationFuseBlocked(_, cap)
            | OrphanGlobalFuseDeferred(_, cap)
            | OrphanGlobalFuseBlocked(_, cap) -> cap

        let globalFuseReplayDecisionStatusId decision =
            match decision with
            | ParentContinuationFuseDeferred _ -> SemanticParentContinuationCycleDeferred
            | ParentContinuationFuseBlocked _ -> SemanticGlobalFuseParentContinuationCycleBlocked
            | OrphanGlobalFuseDeferred _ -> SemanticStepPartial
            | OrphanGlobalFuseBlocked _ -> SemanticGlobalFuseParentContinuationCycleBlocked

        let globalFuseReplayDecisionStatusText decision =
            decision |> globalFuseReplayDecisionStatusId |> semanticStatusToString


        type SemanticTerminalContract = {
            rank: int
            next: string
        }

        let private semanticTerminalContract status =
            match status with
            | SemanticMacroThunkMissingBlocked -> Some { rank = 100; next = "explicit_eval_worklist_macro_thunk_required" }
            | SemanticCodegenJpBodyDictMissingBlocked -> Some { rank = 99; next = "explicit_codegen_jp_body_dict_required" }
            | SemanticLiteralOpBodyStepperBlocked -> Some { rank = 95; next = "explicit_eval_worklist_literal_op_body_stepper_required" }
            | SemanticOpImplRequiredBlocked -> Some { rank = 94; next = "explicit_eval_worklist_op_impl_required" }
            | SemanticApplySeqUnknownReturnWitnessBlocked -> Some { rank = 93; next = "explicit_eval_worklist_apply_seq_unknown_return_witness_required" }
            | SemanticApplyContinuationAfterSeqUnknownBlocked -> Some { rank = 92; next = "explicit_eval_worklist_apply_continuation_after_seq_unknown_required" }
            | SemanticDynamicJoinApplyBlocked -> Some { rank = 92; next = "explicit_eval_worklist_dynamic_join_apply_required" }
            | SemanticApplySpineMissingDirectValueBlocked -> Some { rank = 92; next = "explicit_eval_worklist_apply_spine_store_required" }
            | SemanticSeqUnknownReturnWitnessBlocked -> Some { rank = 91; next = "explicit_eval_worklist_seq_unknown_return_witness_required" }
            | SemanticIfUnknownReturnConditionBlocked -> Some { rank = 90; next = "explicit_eval_worklist_if_unknown_return_condition_required" }
            | SemanticIfSymbolicConditionBlocked -> Some { rank = 89; next = "explicit_eval_worklist_if_symbolic_condition_required" }
            | SemanticRecordWithValueBlocked -> Some { rank = 88; next = "explicit_eval_worklist_record_with_stepper_required" }
            | SemanticAnnotTestBranchSelectionBlocked -> Some { rank = 87; next = "explicit_eval_worklist_annot_test_branch_selection_required" }
            | SemanticUnboxReplayBlocked -> Some { rank = 87; next = "explicit_eval_worklist_unbox_stepper_required" }
            | SemanticTypeApplyNominalConstructorStepperBlocked -> Some { rank = 87; next = "explicit_eval_worklist_type_apply_nominal_constructor_stepper_required" }
            | SemanticNominalConstructorStepperBlocked -> Some { rank = 86; next = "explicit_eval_worklist_nominal_constructor_stepper_required" }
            | SemanticTermTypeValueBlocked -> Some { rank = 86; next = "explicit_eval_worklist_term_type_value_required" }
            | SemanticReplayChildScheduleRepeatBlocked -> Some { rank = 85; next = "explicit_eval_worklist_replay_child_schedule_repeat_required" }
            | SemanticPairValueBlocked -> Some { rank = 84; next = "explicit_eval_worklist_pair_value_required" }
            | SemanticTypeApplyNestedForallStepperBlocked -> Some { rank = 84; next = "explicit_eval_worklist_type_apply_nested_forall_stepper_required" }
            | SemanticSeqTypeErrorBlocked -> Some { rank = 83; next = "explicit_eval_worklist_seq_type_error_required" }
            | SemanticLeafParentContinuationMissingBlocked -> Some { rank = 82; next = "explicit_eval_worklist_leaf_parent_continuation_required" }
            | SemanticUnitTestValueBlocked -> Some { rank = 82; next = "explicit_eval_worklist_unit_test_value_required" }
            | SemanticTypeApplyForallBodyStepperBlocked -> Some { rank = 81; next = "explicit_eval_worklist_type_apply_forall_body_stepper_required" }
            | SemanticTypeVariableValueMissingBlocked -> Some { rank = 80; next = "explicit_eval_worklist_type_variable_env_required" }
            | SemanticApplyContinuationExceptionBlocked -> Some { rank = 79; next = "explicit_eval_worklist_apply_continuation_exception_required" }
            | SemanticReplayFingerprintRepeatBlocked -> Some { rank = 79; next = "explicit_eval_worklist_replay_fingerprint_repeat_required" }
            // ALPHA1001: runtime 1000 emitted this bounded terminal 21 times but
            // highRankPinnedTerminal only retargets ranks >= 80.  Rank it at the
            // high-rank boundary so the existing pinned-terminal retarget path can
            // stop the manual-interrupt loop without inventing a value or BuildOk.
            | SemanticGlobalFuseParentContinuationCycleBlocked -> Some { rank = 80; next = "explicit_eval_worklist_global_fuse_parent_continuation_cycle_required" }
            | SemanticParentReplayStatusPreservedRepeatBlocked -> Some { rank = 78; next = "explicit_eval_worklist_parent_replay_status_preserved_required" }
            | SemanticReentrantReplayDriverStarvationBlocked -> Some { rank = 78; next = "explicit_eval_worklist_reentrant_replay_driver_starvation_required" }
            | SemanticRootCompleteStaleRetargetPendingNoQueueBlocked -> Some { rank = 77; next = "explicit_eval_worklist_root_complete_stale_retarget_required" }
            | SemanticRootCompleteStaleRetargetRepeatBlocked -> Some { rank = 77; next = "explicit_eval_worklist_root_complete_stale_retarget_required" }
            | SemanticAppRootBase16StaleRetargetHardcapBlocked -> Some { rank = 76; next = "explicit_eval_worklist_app_root_base16_stale_retarget_required" }
            | SemanticRootCompletePendingJobsBlocked -> Some { rank = 76; next = "explicit_eval_worklist_root_complete_pending_jobs_required" }
            | SemanticSelectedFrontierRepeatBlocked -> Some { rank = 76; next = "explicit_eval_worklist_selected_frontier_stepper_required" }
            | SemanticTjoinpointStepperBlocked -> Some { rank = 75; next = "explicit_eval_worklist_tjoinpoint_stepper_required" }
            | SemanticJoinpointValueBlocked -> Some { rank = 74; next = "explicit_eval_worklist_joinpoint_value_required" }
            | SemanticJoinpointTermStepperBlocked -> Some { rank = 72; next = "explicit_eval_worklist_joinpoint_term_stepper_required" }
            | SemanticReplayPayloadMissingBlocked -> Some { rank = 69; next = "explicit_eval_worklist_replay_payload_required" }
            // ALPHA1014: runtime 1013 showed a concrete replay-driver NullReferenceException
            // arriving after a generic rank-80 global-fuse pin. Rank this above global-fuse
            // and annot-test/unbox diagnostics, but still below concrete op/codegen terminals.
            | SemanticReplayDriverExceptionBlocked -> Some { rank = 88; next = "explicit_eval_worklist_replay_driver_exception_required" }
            | SemanticRootCompleteStaleRetargetLiveReplayLivelockBlocked -> Some { rank = 88; next = "explicit_eval_worklist_app_root_base16_live_replay_livelock_required" }
            | SemanticParentContinuationCycleBlocked -> Some { rank = 60; next = "explicit_eval_worklist_parent_continuation_cycle_required" }
            | SemanticStaleRootRetargetBlocked -> Some { rank = 55; next = "explicit_eval_worklist_stale_root_retarget_required" }
            | SemanticLetSuccessAllReadyApplyBlocked -> Some { rank = 45; next = "explicit_eval_worklist_let_success_all_ready_apply_required" }
            | SemanticDeferredFunctionReplayExceptionBlocked -> Some { rank = 40; next = "explicit_eval_worklist_deferred_function_replay_exception_required" }
            | SemanticLetSuccessApplyContinuationBlocked -> Some { rank = 35; next = "explicit_eval_worklist_let_success_apply_continuation_required" }
            | SemanticLetSuccessApplyExceptionBlocked -> Some { rank = 30; next = "explicit_eval_worklist_let_success_apply_exception_required" }
            | _ -> None

        let private semanticTerminalContractForText (status: string) =
            status |> semanticStatusOfString |> semanticTerminalContract

        // ALPHA1010: keep pushing the live-replay policy boundary toward DUs.
        // Runtime 1009 proved semantic_annot_test_branch_selection_blocked is now
        // the useful rank-87 frontier.  Treat it as a typed surface-now terminal
        // rather than another stringly deferrable status; active replay may still
        // defer soft replay/fingerprint/root terminals, but it cannot hide the
        // concrete branch-selection obligation.
        type LiveReplayTerminalPolicy =
            | DeferTerminalWhileLiveReplay
            | SurfaceTerminalDuringLiveReplay
            | TerminalNotLiveReplayPolicy

        // ALPHA1023: alpha1022 proved the app-root/base16 live hardcap can fire
        // after a real root write witness already exists.  Keep that decision as
        // a closed DU so the root-witness path can defer to finalization without
        // weakening the fail-closed terminal used when no witness exists.
        type AppRootBase16LiveReplayHardcapDecision =
            | AppRootWitnessCanFinalize
            | AppRootLiveReplayLivelockTerminal
            | AppRootLiveReplayDemote
            | AppRootQuiescedHardcapTerminal
            | AppRootPreserveRootEvidence

        let private appRootBase16LiveReplayHardcapDecisionToString decision =
            match decision with
            | AppRootWitnessCanFinalize -> "root_witness_can_finalize"
            | AppRootLiveReplayLivelockTerminal -> "live_replay_livelock_terminal"
            | AppRootLiveReplayDemote -> "live_replay_demote"
            | AppRootQuiescedHardcapTerminal -> "quiesced_hardcap_terminal"
            | AppRootPreserveRootEvidence -> "preserve_root_evidence"

        // ALPHA1024: keep cross-kind payload attachment as a closed decision.
        // Runtime 1023 showed term cells arriving while the canonical frame was ty;
        // dropping them as kind_mismatch_frame_ty_cell_term loses runnable replay work.
        // The safe path stores the cell as a deferred replay obligation whenever
        // there is pending/queued/active replay evidence, while preserving the old
        // fail-closed rejection when the mismatch is quiescent.
        type CrossKindPayloadAttachDecision =
            | CrossKindSwitchToFreshFrontier
            | CrossKindDeferAsReplayObligation
            | CrossKindRejectUnsafeMismatch

        let private crossKindPayloadAttachDecisionToString decision =
            match decision with
            | CrossKindSwitchToFreshFrontier -> "switch_to_fresh_frontier"
            | CrossKindDeferAsReplayObligation -> "defer_as_replay_obligation"
            | CrossKindRejectUnsafeMismatch -> "reject_unsafe_mismatch"

        // ALPHA1026: a repeated NullReferenceException after a root-complete
        // write witness is not the same thing as an uncovered semantic terminal.
        // Runtime 1025 showed Hopac replay reaching semantic_root_complete, then
        // rebuilding a let-success/apply continuation until the old null-repeat
        // cap pinned let_success_apply_continuation_null_repeat_terminal. Keep
        // the decision closed: terminal only when there is no root witness/live
        // replay evidence; otherwise preserve the witness or defer the still-live
        // replay tick without pretending BuildOk locally.
        type RootWitnessNullReplayDecision =
            | RootWitnessNullDeferLiveReplay
            | RootWitnessNullPreserveComplete
            | RootWitnessNullSurfaceTerminal

        let private rootWitnessNullReplayDecisionToString decision =
            match decision with
            | RootWitnessNullDeferLiveReplay -> "root_witness_null_defer_live_replay"
            | RootWitnessNullPreserveComplete -> "root_witness_null_preserve_complete"
            | RootWitnessNullSurfaceTerminal -> "root_witness_null_surface_terminal"

        // ALPHA1028: EUnbox replay can surface a real BigStack wait timeout through
        // the child detail. Do not schedule that child again as semantic_step_partial,
        // or the replay loop masks the true blocker until a manual interrupt.
        type UnboxChildReplayDecision =
            | UnboxChildScheduleReplay
            | UnboxChildBoundJoinStall
            | UnboxChildSurfaceBlocked

        let private unboxChildReplayDecisionToString decision =
            match decision with
            | UnboxChildScheduleReplay -> "schedule_replay"
            | UnboxChildBoundJoinStall -> "bound_bigstack_join_stall"
            | UnboxChildSurfaceBlocked -> "surface_blocked"

        let private liveReplayTerminalPolicyOfSemanticStatusId = function
            | SemanticParentContinuationCycleBlocked
            | SemanticRootCompletePendingJobsBlocked
            | SemanticAppRootBase16StaleRetargetHardcapBlocked
            | SemanticDynamicJoinApplyBlocked
            | SemanticReplayChildScheduleRepeatBlocked
            | SemanticRecordWithValueBlocked
            | SemanticReplayFingerprintRepeatBlocked
            | SemanticRootCompleteStaleRetargetPendingNoQueueBlocked -> DeferTerminalWhileLiveReplay
            // ALPHA1010: these are concrete obligations, not soft replay churn.
            // Let BigStack fail closed on the precise missing implementation/branch
            // selector instead of demoting them into a lower-rank global-fuse loop.
            | SemanticOpImplRequiredBlocked
            | SemanticAnnotTestBranchSelectionBlocked
            | SemanticUnboxReplayBlocked
            | SemanticApplySpineMissingDirectValueBlocked
            | SemanticRootCompleteStaleRetargetLiveReplayLivelockBlocked -> SurfaceTerminalDuringLiveReplay
            // ALPHA998: semantic_global_fuse_parent_continuation_cycle_blocked
            // is emitted only after the bounded global-fuse repeat cap is
            // exhausted. Runtime 997 showed that treating it as deferrable lets
            // active/queued replay suppress the terminal forever, producing a
            // manual interrupt instead of the intended fail-closed BuildError.
            | SemanticGlobalFuseParentContinuationCycleBlocked -> TerminalNotLiveReplayPolicy
            | _ -> TerminalNotLiveReplayPolicy

        let private isLiveReplayDeferrableSemanticStatusId statusId =
            match liveReplayTerminalPolicyOfSemanticStatusId statusId with
            | DeferTerminalWhileLiveReplay -> true
            | SurfaceTerminalDuringLiveReplay
            | TerminalNotLiveReplayPolicy -> false

        let private isLiveReplayDeferrableTerminalStatus status =
            status |> semanticStatusOfString |> isLiveReplayDeferrableSemanticStatusId

        // ALPHA342: single-flight continuation frontier.
        //
        // Alpha340 proved the bounded trampoline could advance the captured trace, but the log showed
        // several Hopac/JP waiters promoting and running the same cycle concurrently. A ConcurrentQueue
        // made that look like useful parallelism while actually duplicating the same frame and racing the
        // cursor. Keep one canonical frontier per evaluator cycle until typed replay can consume the continuation envelope.
        let private gate = obj()
        let mutable private frontier : Frame option = None
        let mutable private frontierTerm : Frame option = None
        let mutable private frontierTy : Frame option = None
        let mutable private activeRun = false
        let mutable private captureSeq = 0L
        let mutable private replaySeq = 0L
        let mutable private replayScheduledKey : string option = None
        let mutable private replayQueue : ReplayTask list = []
        // ALPHA649: same-run semantic-payload backfill cache.
        // Alpha648 reached semantic_replay_payload_missing_blocked even though
        // semantic cells for the same kind/site were observed earlier in the run.
        // Store only observed ReplayCell metadata; this never fabricates values.
        let private semanticCellsByKindSite = System.Collections.Concurrent.ConcurrentDictionary<string, ReplayCell>()
        // ALPHA535: remember the first missing-payload replay terminal so later
        // downstream terminals cannot shadow the root replay-payload contract.
        let mutable private pinnedReplayPayloadMissing : Frame option = None
        // ALPHA536: remember the strongest explicit terminal contract observed so a
        // downstream let-success/apply/deferred blocker cannot shadow the real upstream
        // missing stepper contract in retry_stop.
        let mutable private pinnedTerminalContract : Frame option = None
        // ALPHA594: durable per-BuildFile terminal ledger.  Alpha593 showed
        // the live pin can be cleared by root-complete shielding before the final
        // replay-root handoff branch asks for it; keep the strongest terminal
        // observed in this transaction without making it a semantic success.
        let mutable private durableTerminalContract : Frame option = None
        // ALPHA453: compact anti-repeat ledger for continuation replays that make no semantic progress.
        let private replayFingerprintRepeats = System.Collections.Generic.Dictionary<string,int>()
        // ALPHA546: compact ledger for child replay scheduling that repeats the same semantic child.
        // Alpha545 proved the final macro terminal is correct, but a 245s gap before retry_stop
        // was spent re-scheduling the same seq/apply/deferred children around parsing.spi:257.
        // Cap that repeat as a terminal contract so retry_stop can fail closed before JP watchdog.
        let private replayChildScheduleRepeats = System.Collections.Generic.Dictionary<string,int>()
        let private replay_child_schedule_repeat_cap = 8
        // ALPHA1012: annot-test ArgumentNullException(key) is a replay obligation
        // while at least one branch has just been scheduled.  Runtime 1011 showed
        // the true ELet branch was scheduled and BigStack immediately consumed the
        // rank-87 terminal before that short replay window could close.  Track the
        // exact annot-test branch key and pin only after a bounded repeat window.
        let private annotTestBranchSelectionGuardRepeats = System.Collections.Generic.Dictionary<string,int>()
        let private annot_test_branch_selection_guard_cap = 2
        let private noteAnnotTestBranchSelectionGuard (key: string) =
            lock gate (fun () ->
                let mutable prior = 0
                let nextCount = if annotTestBranchSelectionGuardRepeats.TryGetValue(key, &prior) then prior + 1 else 1
                annotTestBranchSelectionGuardRepeats.[key] <- nextCount
                nextCount)
        // ALPHA563: reentrant semantic-cell attachments can starve the replay loop without ever
        // reaching the child schedule repeat guard.  Runtime 562 emitted only reentrant-poke
        // suppressions for the same EOp/EV cells while an active driver stayed alive.  Count
        // those suppressions by semantic cell and promote the exact cell to a terminal contract.
        let private reentrantReplayPokeRepeats = System.Collections.Generic.Dictionary<string,int>()
        let private reentrant_replay_poke_repeat_cap = 64
        let private replayReentrantPokeKey (cell: ReplayCell) =
            sprintf "%s|%s|%d|%s" cell.kind cell.shape cell.nodeId cell.site
        let private noteReentrantReplayPoke (cell: ReplayCell) =
            let key = replayReentrantPokeKey cell
            let count =
                lock gate (fun () ->
                    let mutable prior = 0
                    let nextCount = if reentrantReplayPokeRepeats.TryGetValue(key, &prior) then prior + 1 else 1
                    reentrantReplayPokeRepeats.[key] <- nextCount
                    nextCount)
            count, key
        // ALPHA934: scheduled parent replay preservation is a liveness guard, not
        // an unbounded parking state. Runtime 933 proved the literal-op replay can
        // resolve, then the parent replay can be preserved/deferred again with no
        // new terminal before manual interrupt. Count the exact parent replay/cell
        // identity and fail closed only after repeated preservation of the same
        // typed replay obligation.
        let private parentReplayPreservedRepeats = System.Collections.Generic.Dictionary<string,int>()
        let private parent_replay_preserved_repeat_cap = 16
        let private parentReplayPreservedKey (task: ReplayTask) (cellOpt: ReplayCell option) =
            match cellOpt with
            | Some cell ->
                sprintf "%s|%s|%s|%s|%d|%s|%s"
                    task.driver task.key cell.kind cell.shape cell.nodeId cell.site cell.status
            | None ->
                sprintf "%s|%s|missing_cell" task.driver task.key

        let private noteParentReplayPreserved (task: ReplayTask) (cellOpt: ReplayCell option) =
            let key = parentReplayPreservedKey task cellOpt
            let count =
                lock gate (fun () ->
                    let mutable prior = 0
                    let nextCount = if parentReplayPreservedRepeats.TryGetValue(key, &prior) then prior + 1 else 1
                    parentReplayPreservedRepeats.[key] <- nextCount
                    nextCount)
            count, key
        // ALPHA993: a scheduled_parent_replay that has already hit the preserved-repeat cap is terminal.
        // Runtime 992 showed alpha992 fixed the NullReferenceException loop, then pinned
        // semantic_parent_replay_status_preserved_repeat_blocked while the same live replay
        // kept executing and required manual interruption. Once this cap is hit, remove the
        // replay task from the queue and publish the existing terminal instead of resuming it.
        // ALPHA992: a guarded NullReferenceException is liveness only while it
        // exposes fresh replay evidence. Runtime 991 kept reporting the same
        // let-success/apply-continuation null guards until manual interruption.
        // Count the exact replay task/cell identity and promote it to an
        // existing explicit terminal after a small cap instead of inventing a
        // new state or spinning semantic_step_partial forever.
        let private replayNullGuardRepeats = System.Collections.Generic.Dictionary<string,int>()
        let private replay_null_guard_repeat_cap = 8
        let private replayNullGuardKey (taskOpt: ReplayTask option) (cellOpt: ReplayCell option) (ex: exn) =
            let taskPart =
                match taskOpt with
                | Some task -> sprintf "%s|%s|%s" task.driver task.status task.key
                | None -> "missing_task"
            let cellPart =
                match cellOpt with
                | Some cell -> sprintf "%s|%s|%d|%s|%s" cell.kind cell.shape cell.nodeId cell.site cell.status
                | None -> "missing_cell"
            sprintf "%s|%s|%s" (ex.GetType().Name) taskPart cellPart
        let private noteReplayNullGuard (taskOpt: ReplayTask option) (cellOpt: ReplayCell option) (ex: exn) =
            let key = replayNullGuardKey taskOpt cellOpt ex
            let count =
                lock gate (fun () ->
                    let mutable prior = 0
                    let nextCount = if replayNullGuardRepeats.TryGetValue(key, &prior) then prior + 1 else 1
                    replayNullGuardRepeats.[key] <- nextCount
                    nextCount)
            count, key
        // ALPHA492: compact anti-repeat ledger for stale root-complete retargets.
        // A root-complete shell is evidence for its original cell only; if the same
        // different incoming cell repeatedly retargets it, quarantine that retarget
        // as a terminal blocker instead of spinning another continuation envelope.
        let private staleRootRetargetRepeats = System.Collections.Generic.Dictionary<string,int>()
        // ALPHA501: terminal ELet cycle repair attempts are capped per let/role/node.
        // This prevents retry-drain from endlessly re-scheduling the same child while
        // still allowing the live LetSpine to expose one more body/success replay.
        let private letTerminalCycleRepairs = System.Collections.Generic.Dictionary<string,int>()
        let private noteLetTerminalCycleRepairLocked (key: string) =
            let mutable prior = 0
            let next = if letTerminalCycleRepairs.TryGetValue(key, &prior) then prior + 1 else 1
            letTerminalCycleRepairs.[key] <- next
            next
        // ALPHA571: terminal parent-continuation cycle repairs are no longer
        // restricted to ELet.  Runtime 570 reached a repeated EApply/ETypeApply
        // cycle after the composite children had made real progress.  Keep a
        // separate cap so broad composite repair cannot spin forever.
        let private compositeTerminalCycleRepairs = System.Collections.Generic.Dictionary<string,int>()
        let private noteCompositeTerminalCycleRepairLocked (key: string) =
            let mutable prior = 0
            let next = if compositeTerminalCycleRepairs.TryGetValue(key, &prior) then prior + 1 else 1
            compositeTerminalCycleRepairs.[key] <- next
            next
        // ALPHA503: a ready replay duplicate can be real progress if the task was
        // produced by alpha502's leaf-yield terminal-let repair.  The old duplicate
        // guard suppressed the already-ready task and left retry_stop_drain looping
        // over duplicate=1.  Cap reruns by replay key so a bad envelope becomes a
        // typed repeat blocker instead of an unbounded scheduler spin.
        let private readyDuplicateReplayReruns = System.Collections.Generic.Dictionary<string,int>()
        let private noteReadyDuplicateReplayRerunLocked (key: string) =
            let mutable prior = 0
            let next = if readyDuplicateReplayReruns.TryGetValue(key, &prior) then prior + 1 else 1
            readyDuplicateReplayReruns.[key] <- next
            next
        // ALPHA679: retry_stop can churn on the same leaf-parent gap by yielding
        // a ty semantic_leaf_complete frontier to the same term continuation_envelope
        // over and over.  Count that exact leaf/alternate handoff and, after a small
        // cap, surface the real missing-parent terminal instead of producing MBs of
        // repeated yield logs.  This is a diagnostic/scheduler guard only.
        let private leafParentContinuationYieldRepeats = System.Collections.Generic.Dictionary<string,int>()
        let private leaf_parent_continuation_yield_cap = 16
        let private noteLeafParentContinuationYieldLocked (leaf: Frame) (alt: Frame) =
            let leafNode =
                match leaf.semanticCell with
                | Some cell -> cell.nodeId
                | None -> -1
            let altNode =
                match alt.semanticCell with
                | Some cell -> cell.nodeId
                | None -> -1
            let key = sprintf "%s|%s|%d|%s|%d|%s|%s|%d|%s" leaf.kind leaf.status leaf.cursor leaf.site leafNode alt.kind alt.status altNode alt.site
            let mutable prior = 0
            let next = if leafParentContinuationYieldRepeats.TryGetValue(key, &prior) then prior + 1 else 1
            leafParentContinuationYieldRepeats.[key] <- next
            next, key

        // ALPHA494: progress-bearing scheduler yields (fingerprint/stale-retarget)
        // can justify a bounded retry trampoline, but only if the selected frontier
        // is preserved across the immediate retry.  This counter is consumed by
        // BuildFile.retry_stop; it is not a semantic proof.
        let mutable private progressYieldCount = 0
        let private noteProgressYieldLocked () =
            progressYieldCount <- progressYieldCount + 1
        let tryConsumeProgressYield () =
            lock gate (fun () ->
                if progressYieldCount > 0 then
                    progressYieldCount <- progressYieldCount - 1
                    true
                else false)
        // ALPHA952: retry_stop must be able to distinguish a hard terminal from a
        // terminal-shaped frontier that still has a cooperative replay tick in flight.
        // This is a liveness hint only; it does not prove or fabricate semantic success.
        let hasProgressYield () =
            lock gate (fun () -> progressYieldCount > 0)
        // ALPHA1056: after a concrete root-complete write witness has decided that
        // a stale retarget should not be reinserted, stale progress-yield hints must
        // not keep retry_stop in the same pending=2 finalization loop.
        let drainProgressYield () =
            lock gate (fun () ->
                let n = progressYieldCount
                progressYieldCount <- 0
                n)
        // ALPHA484: replay-driver stack depth for suppressing semantic-cell-attached
        // self-pokes while the driver is already reducing that active typed replay.
        let mutable private replayDriverActiveDepth = 0
        let replayDriverActiveDepthValue () =
            lock gate (fun () -> replayDriverActiveDepth)

        let mutable private replayDriverStackFenceQueued = false

        // ALPHA434: kind-local frontier slots.
        // Alpha433 proved term replay can now reach semantic_root_complete and store source-key
        // values, but the remaining log alternated term/ty fuses through one canonical frontier,
        // causing kind_local_active_reset and missing_frontier churn.  Keep at most one parked
        // frame per evaluator kind; switching kinds parks the active frame instead of erasing it.
        let private slotSetLocked (frame: Frame) =
            match frame.kind with
            | "term" -> frontierTerm <- Some frame
            | "ty" -> frontierTy <- Some frame
            | _ -> ()

        let private slotGetLocked (kind: string) =
            match kind with
            | "term" -> frontierTerm
            | "ty" -> frontierTy
            | _ -> None

        let private saveFrontierLocked () =
            match frontier with
            | Some frame -> slotSetLocked frame
            | None -> ()

        let private selectKindLocked (kind: string) =
            if kind <> "term" && kind <> "ty" then false
            else
                match frontier with
                | Some frame when frame.kind = kind ->
                    slotSetLocked frame
                    true
                | _ ->
                    saveFrontierLocked ()
                    match slotGetLocked kind with
                    | Some frame ->
                        frontier <- Some frame
                        true
                    | None ->
                        false

        let private kindFromReason (text: string) =
            if System.String.IsNullOrWhiteSpace text then "unknown"
            elif text.Contains("ty_", System.StringComparison.Ordinal) || text.Contains("ty@", System.StringComparison.Ordinal) then "ty"
            elif text.Contains("term_", System.StringComparison.Ordinal) || text.Contains("term@", System.StringComparison.Ordinal) then "term"
            else "unknown"

        let parkActiveAndSelectKind (requestedKind: string) =
            lock gate (fun () ->
                let restored = selectKindLocked requestedKind
                if not restored then frontier <- None
                replayScheduledKey <- None
                replayQueue <- []
                replayDriverStackFenceQueued <- false
                activeRun <- false
                restored)

        // ALPHA390: write-gate witness ledger.  Alpha389 kept semantic_root_complete
        // absorbing inside the worklist, but the following retry invalidation could leave
        // BuildOk with only a BuildFile.replay_root_complete reason and no current
        // frontier cell.  Keep a short-lived typed proof for the writer; normal retry
        // control still uses hasReplayComplete() so stale completions cannot advance
        // evaluator state.
        let mutable private replayRootCompleteWitnessUtc = System.DateTime.MinValue
        let mutable private replayRootCompleteWitnessSummary = ""
        let private replayRootCompleteWitnessWindowMs = 120000.0

        // ALPHA424: stable root-complete retry ledger.
        // Alpha423 proved preserving the completed frontier is not enough: spiral.spi:2671
        // can keep proving the same cursor=trace_len root-complete cell for hundreds of
        // attempts, producing megabytes of replay logs without new information.  Track the
        // root-complete frontier fingerprint and let BuildFile stop after a small stable
        // repeat budget with a compact typed diagnostic.
        let mutable private stableRootCompleteKey = ""
        let mutable private stableRootCompleteCount = 0

        // ALPHA476: do not spend the bounded root-complete yield budget on the
        // exact same blocked-root -> selected-frontier pair forever.  The alpha475
        // runtime log proved the cap accounting works, but also proved that selecting
        // the same semantic_dynamic_join_apply_blocked term frontier 31+ times cycles
        // back to the same ty semantic_root_complete proof.
        let mutable private stableRootSelectedKey = ""
        let mutable private stableRootSelectedCount = 0
        let private stable_root_selected_frontier_repeat_cap = 8

        // ALPHA584: a selected-frontier repeat is terminal only after the real
        // typed stepper has been re-enqueued as a continuation envelope.  Runtime
        // 583 proved alpha583 ranks and aborts the repeat correctly, but also
        // showed the repeated EApply at core/listm.spi:27 was parked as a bare
        // semantic_step_partial frame with no replay queue.  Give that exact cell
        // a small, bounded replay escape before preserving the precise terminal.
        let private selectedFrontierStepperReplayAttempts = System.Collections.Generic.Dictionary<string,int>()
        let private selected_frontier_stepper_replay_cap = 2
        let private selected_frontier_stepper_rearm_cap = 2
        // Captured composite frontiers can arrive after a successful root-complete handoff:
        // the log shows an existing term/ESeq semantic cell, not a missing value. Give that
        // captured cell a bounded replay envelope before terminalizing selected-frontier repeat.
        let private selected_frontier_captured_cell_replay_cap = 4

        let private esc (s: string) =
            if Object.ReferenceEquals(s,null) then "null" else
                let s =
                    s.Replace("\\","\\\\")
                     .Replace("\"","\\\"")
                     .Replace("\r","\\r")
                     .Replace("\n","\\n")
                     .Replace("\t","\\t")
                "\"" + s + "\""

        // ALPHA1040: runtime 1039 proved a diagnostic reason could append the same
        // app-root finalization tag hundreds of times and create multi-hundred-KB
        // JSON lines. Keep the evidence, but make reason strings idempotent and
        // bounded at the diagnostic boundary; no replay value or terminal rank changes.
        let private compactReasonTag (tag: string) (reason: string) =
            if System.Object.ReferenceEquals(reason, null) || reason = "" then ""
            else
                let parts = reason.Split([|':'|], System.StringSplitOptions.RemoveEmptyEntries)
                let tagCount =
                    parts
                    |> Array.filter (fun part -> part = tag)
                    |> Array.length
                if tagCount > 0 then
                    let prefixParts =
                        parts
                        |> Array.takeWhile (fun part -> part <> tag)
                        |> Array.truncate 4
                    let prefix =
                        if prefixParts.Length = 0 then "reason"
                        else System.String.Join(":", prefixParts)
                    if tagCount = 1 then sprintf "%s:%s" prefix tag
                    else sprintf "%s:%s#repeat=%d" prefix tag tagCount
                else reason

        let private compactFrameReason (reason: string) =
            let tag = "app_root_base16_live_replay_root_witness_finalization_deferred"
            let r = compactReasonTag tag reason
            if System.Object.ReferenceEquals(r, null) then ""
            elif r.Length <= 768 then r
            else r.Substring(0, 768) + sprintf "…[+%d chars]" (r.Length - 768)

        let private boundedReasonAppend (reason: string) (tag: string) =
            let r = compactFrameReason reason
            if r.IndexOf(tag, System.StringComparison.Ordinal) >= 0 then compactFrameReason r
            elif System.String.IsNullOrEmpty r then tag
            else compactFrameReason (r + ":" + tag)

        type LogCompletenessPolicy =
            | FullFidelityJsonl
            | TruncatedPreview of int

        let private activeLogCompletenessPolicy = FullFidelityJsonl

        let private logCompletenessPolicyText policy =
            match policy with
            | FullFidelityJsonl -> "full_fidelity_jsonl"
            | TruncatedPreview n -> sprintf "truncated_preview_%d" n

        let terminalContractRank (status: string) =
            match semanticTerminalContractForText status with
            | Some contract -> contract.rank
            | None -> 0

        let isTerminalContractStatus (status: string) =
            match semanticTerminalContractForText status with
            | Some _ -> true
            | None -> false

        let terminalContractNext (status: string) =
            match semanticTerminalContractForText status with
            | Some contract -> contract.next
            | None -> "explicit_eval_worklist_real_stepper_required"

        let private pinTerminalContractLocked (event: string) (frame: Frame) =
            let isCurrentRootCompleteSite =
                frame.status = "semantic_root_complete"
                || (match frame.semanticCell with
                    | Some cell -> cell.status = "semantic_root_complete"
                    | None -> false)
            let pendingForTerminalPin =
                let mutable n = 0
                let seen = System.Collections.Generic.HashSet<string>()
                let add opt =
                    match opt with
                    | Some frame ->
                        let k = frame.kind + "|" + frame.key + "|" + frame.site
                        if seen.Add k then n <- n + 1
                    | None -> ()
                add frontier
                add frontierTerm
                add frontierTy
                n
            let replayRootWriteWitnessFreshForPin =
                let frontierComplete =
                    match frontier with
                    | Some frame when frame.status = "semantic_root_complete" -> true
                    | Some frame ->
                        match frame.semanticCell with
                        | Some cell when cell.status = "semantic_root_complete" -> true
                        | _ -> false
                    | None -> false
                if frontierComplete then true
                else
                    let ageMs = (System.DateTime.UtcNow - replayRootCompleteWitnessUtc).TotalMilliseconds
                    replayRootCompleteWitnessUtc <> System.DateTime.MinValue
                    && ageMs >= 0.0
                    && ageMs <= replayRootCompleteWitnessWindowMs
            let replayRootWriteWitnessSummaryForPin =
                if replayRootCompleteWitnessUtc = System.DateTime.MinValue then "none"
                else sprintf "%s age_ms=%.0f" replayRootCompleteWitnessSummary ((System.DateTime.UtcNow - replayRootCompleteWitnessUtc).TotalMilliseconds)
            let suppressAppRootStaleRetargetPin =
                frame.status = "semantic_root_complete_stale_retarget_repeat_blocked"
                && isCurrentRootCompleteSite
                && stableRootCompleteCount > 0
                && (match frame.semanticCell with
                    | Some cell -> cell.shape = "TRecord"
                    | None -> frame.key.Contains("#"))
            let suppressAppRootParentCyclePin =
                frame.status = "semantic_parent_continuation_cycle_blocked"
                && isCurrentRootCompleteSite
                && (stableRootCompleteCount > 0 || replayRootWriteWitnessFreshForPin)
                && pendingForTerminalPin <= 2
                && replayRootWriteWitnessFreshForPin
            let suppressSyntheticChildScheduleRepeatPin =
                frame.status = "semantic_replay_child_schedule_repeat_blocked"
                && pendingForTerminalPin > 0
                && replayRootWriteWitnessFreshForPin
                && (frame.site.EndsWith(":0", StringComparison.Ordinal)
                    || frame.key.Contains(":0", StringComparison.Ordinal)
                    || (match frame.semanticCell with
                        | Some cell -> cell.site.EndsWith(":0", StringComparison.Ordinal)
                        | None -> false))
            let suppressLiveReplayParentCyclePin =
                frame.status = "semantic_parent_continuation_cycle_blocked"
                && pendingForTerminalPin > 0
                && (replayQueue.Length > 0 || replayDriverActiveDepth > 0)
            let suppressLiveReplayAppRootBase16HardcapPin =
                frame.status = "semantic_app_root_base16_stale_retarget_hardcap_blocked"
                && pendingForTerminalPin > 0
                && (replayQueue.Length > 0 || replayDriverActiveDepth > 0 || progressYieldCount > 0)
            let suppressLiveReplayChildScheduleRepeatPin =
                isSemanticReplayChildScheduleRepeatBlockedStatusId (semanticStatusOfString frame.status)
                && pendingForTerminalPin > 0
                && (replayQueue.Length > 0 || replayDriverActiveDepth > 0 || progressYieldCount > 0)
            let suppressLiveReplayRecordWithValuePin =
                match semanticStatusOfString frame.status with
                | SemanticRecordWithValueBlocked ->
                    pendingForTerminalPin > 0
                    && (replayQueue.Length > 0 || replayDriverActiveDepth > 0 || progressYieldCount > 0)
                | _ -> false
            let suppressLiveReplayOpImplRequiredPin =
                match semanticStatusOfString frame.status with
                | SemanticOpImplRequiredBlocked ->
                    match liveReplayTerminalPolicyOfSemanticStatusId SemanticOpImplRequiredBlocked with
                    | DeferTerminalWhileLiveReplay ->
                        pendingForTerminalPin > 0
                        && (replayQueue.Length > 0 || replayDriverActiveDepth > 0 || progressYieldCount > 0 || replayRootWriteWitnessFreshForPin)
                    | SurfaceTerminalDuringLiveReplay
                    | TerminalNotLiveReplayPolicy -> false
                | _ -> false
            if suppressAppRootStaleRetargetPin then
                // ALPHA683: alpha682 showed that this same app-root TRecord can be
                // reattached as a stale-retarget terminal immediately after being
                // materialized back to semantic_root_complete.  Refuse to let that
                // diagnostic retarget become a durable terminal contract; the real
                // downstream parent-continuation/leaf frontier remains visible.
                DiagJson.emit (
                    sprintf "{\"kind\":\"eval_worklist_app_root_stale_retarget_pin_suppressed\",\"event\":%s,\"status\":%s,\"site\":%s,\"key\":%s,\"stable_count\":%d,\"single_flight\":1,\"next\":\"preserve_root_evidence\"}"
                        (esc event) (esc frame.status) (esc frame.site) (esc frame.key) stableRootCompleteCount)
            elif suppressAppRootParentCyclePin then
                // Runtime note: the demotion path can clear this app-root parent-cycle
                // terminal, but the stable-root ledger reset lets the same stale terminal
                // pin again before the next replay-root retry.  Suppress only this narrow
                // stale terminal while the replay-root write witness is still fresh.
                DiagJson.emit (
                    sprintf "{\"kind\":\"eval_worklist_app_root_parent_cycle_pin_suppressed\",\"event\":%s,\"status\":%s,\"site\":%s,\"key\":%s,\"stable_count\":%d,\"pending\":%d,\"witness\":%s,\"policy\":\"suppress_same_site_parent_cycle_terminal_after_replay_root_finalization\",\"writer_gate\":\"requires_existing_replay_root_write_witness\",\"single_flight\":1,\"next\":\"retry_clean_buildfile_with_replay_root_reason\"}"
                        (esc event) (esc frame.status) (esc frame.site) (esc frame.key) stableRootCompleteCount pendingForTerminalPin (esc replayRootWriteWitnessSummaryForPin))
            elif suppressSyntheticChildScheduleRepeatPin then
                DiagJson.emit (
                    sprintf "{\"kind\":\"eval_worklist_synthetic_child_schedule_repeat_pin_suppressed\",\"event\":%s,\"status\":%s,\"site\":%s,\"key\":%s,\"pending\":%d,\"witness\":%s,\"policy\":\"suppress_backend_spi_zero_synthetic_child_repeat_after_root_witness\",\"single_flight\":1,\"next\":\"preserve_root_complete_and_drain_pending_jobs\"}"
                        (esc event) (esc frame.status) (esc frame.site) (esc frame.key) pendingForTerminalPin (esc replayRootWriteWitnessSummaryForPin))
            elif suppressLiveReplayParentCyclePin then
                DiagJson.emit (
                    sprintf "{\"kind\":\"eval_worklist_live_replay_parent_cycle_pin_suppressed\",\"event\":%s,\"status\":%s,\"site\":%s,\"key\":%s,\"pending\":%d,\"queue_depth\":%d,\"active_depth\":%d,\"policy\":\"defer_parent_cycle_terminal_while_replay_queue_is_runnable\",\"single_flight\":1,\"next\":\"continue_active_replay_driver\"}"
                        (esc event) (esc frame.status) (esc frame.site) (esc frame.key) pendingForTerminalPin replayQueue.Length replayDriverActiveDepth)
            elif suppressLiveReplayAppRootBase16HardcapPin then
                DiagJson.emit (
                    sprintf "{\"kind\":\"eval_worklist_live_replay_app_root_base16_hardcap_pin_suppressed\",\"event\":%s,\"status\":%s,\"site\":%s,\"key\":%s,\"pending\":%d,\"queue_depth\":%d,\"active_depth\":%d,\"progress_yield_pending\":%d,\"policy\":\"defer_app_root_base16_hardcap_terminal_while_replay_is_runnable\",\"single_flight\":1,\"next\":\"continue_active_replay_driver\"}"
                        (esc event) (esc frame.status) (esc frame.site) (esc frame.key) pendingForTerminalPin replayQueue.Length replayDriverActiveDepth progressYieldCount)
            elif suppressLiveReplayChildScheduleRepeatPin then
                DiagJson.emit (
                    sprintf "{\"kind\":\"eval_worklist_live_replay_child_schedule_repeat_pin_suppressed\",\"event\":%s,\"status\":%s,\"site\":%s,\"key\":%s,\"pending\":%d,\"queue_depth\":%d,\"active_depth\":%d,\"progress_yield_pending\":%d,\"policy\":\"defer_child_schedule_repeat_terminal_pin_while_replay_is_runnable\",\"single_flight\":1,\"next\":\"continue_active_replay_driver\"}"
                        (esc event) (esc frame.status) (esc frame.site) (esc frame.key) pendingForTerminalPin replayQueue.Length replayDriverActiveDepth progressYieldCount)
            elif suppressLiveReplayRecordWithValuePin then
                DiagJson.emit (
                    sprintf "{\"kind\":\"eval_worklist_live_replay_record_with_value_pin_suppressed\",\"event\":%s,\"status\":%s,\"site\":%s,\"key\":%s,\"pending\":%d,\"queue_depth\":%d,\"active_depth\":%d,\"progress_yield_pending\":%d,\"policy\":\"defer_record_with_value_terminal_pin_while_replay_is_runnable\",\"single_flight\":1,\"next\":\"continue_active_replay_driver\"}"
                        (esc event) (esc frame.status) (esc frame.site) (esc frame.key) pendingForTerminalPin replayQueue.Length replayDriverActiveDepth progressYieldCount)
            elif suppressLiveReplayOpImplRequiredPin then
                DiagJson.emit (
                    sprintf "{\"kind\":\"eval_worklist_live_replay_op_impl_required_pin_suppressed\",\"event\":%s,\"status\":%s,\"site\":%s,\"key\":%s,\"pending\":%d,\"queue_depth\":%d,\"active_depth\":%d,\"progress_yield_pending\":%d,\"witness\":%s,\"policy\":\"defer_op_impl_terminal_pin_while_replay_or_root_witness_is_live\",\"single_flight\":1,\"next\":\"continue_active_replay_driver\"}"
                        (esc event) (esc frame.status) (esc frame.site) (esc frame.key) pendingForTerminalPin replayQueue.Length replayDriverActiveDepth progressYieldCount (esc replayRootWriteWitnessSummaryForPin))
            else
                let rank = terminalContractRank frame.status
                if rank > 0 then
                    let priorRank =
                        match pinnedTerminalContract with
                        | Some prior -> terminalContractRank prior.status
                        | None -> 0
                    let durablePriorRank =
                        match durableTerminalContract with
                        | Some prior -> terminalContractRank prior.status
                        | None -> 0
                    if durablePriorRank < rank then
                        durableTerminalContract <- Some frame
                    if priorRank < rank then
                        pinnedTerminalContract <- Some frame
                        DiagJson.emit (
                            sprintf "{\"kind\":\"eval_worklist_terminal_contract_pinned\",\"event\":%s,\"status\":%s,\"rank\":%d,\"prior_rank\":%d,\"site\":%s,\"key\":%s,\"log_completeness\":%s,\"single_flight\":1,\"next\":%s}"
                                (esc event) (esc frame.status) rank priorRank (esc frame.site) (esc frame.key) (esc (logCompletenessPolicyText activeLogCompletenessPolicy)) (esc (terminalContractNext frame.status)))

        let private pinTerminalContract (event: string) (frame: Frame) =
            lock gate (fun () -> pinTerminalContractLocked event frame)

        let pinSemanticTerminalContract (event: string) (kind: string) (status: string) (key: string) (site: string) (depth: int) (re: int) (maxRe: int) (reason: string) =
            // ALPHA1001: DU seam for terminal evidence that is emitted outside a
            // ReplayCell.  Runtime 1000 showed the global-fuse terminal was logged
            // as text but never pinned, so retargetGlobalFuseAbortMessage had no
            // durable frame to select.  This wrapper preserves the old string field
            // at the record boundary while routing policy through SemanticStatusId.
            let statusId = semanticStatusOfString status
            match semanticTerminalContract statusId with
            | Some contract ->
                let frame =
                    { kind = kind
                      key = key
                      site = site
                      depth = depth
                      re = re
                      maxRe = maxRe
                      trace = []
                      reason = reason
                      status = semanticStatusToString statusId
                      cursor = 32
                      semanticPayload = Some reason
                      semanticCell = None }
                pinTerminalContract event frame
                let liveReplayPolicy =
                    match liveReplayTerminalPolicyOfSemanticStatusId statusId with
                    | DeferTerminalWhileLiveReplay -> "defer_terminal_while_live_replay"
                    | SurfaceTerminalDuringLiveReplay -> "surface_terminal_during_live_replay"
                    | TerminalNotLiveReplayPolicy -> "terminal_not_live_replay_policy"
                DiagJson.emit (
                    sprintf "{\"kind\":\"eval_worklist_terminal_contract_pinned_from_status\",\"event\":%s,\"status\":%s,\"rank\":%d,\"kind2\":%s,\"site\":%s,\"key\":%s,\"reason\":%s,\"live_replay_policy\":%s,\"log_completeness\":%s,\"single_flight\":1,\"next\":%s}"
                        (esc event) (esc frame.status) contract.rank (esc kind) (esc site) (esc key) (esc reason) (esc liveReplayPolicy) (esc (logCompletenessPolicyText activeLogCompletenessPolicy)) (esc contract.next))
            | None -> ()

        let tryPinnedTerminalContract () =
            lock gate (fun () -> pinnedTerminalContract)

        let tryDurableTerminalContract () =
            lock gate (fun () -> durableTerminalContract)

        let pinCodegenJpBodyDictMissing (event: string) (jpKind: string) (bodyName: string) (keyText: string) (dictCount: int) (message: string) =
            // ALPHA940: alpha939 reached F# codegen and failed on a real missing JP
            // body dictionary after the explicit replay machinery had proven root-complete
            // evidence.  Make the codegen blocker visible to the same terminal-contract
            // machinery instead of leaving only a raw CODEGEN error line.
            // This function records evidence only; it does not create a body dictionary,
            // placeholder, writer artifact, replay-root proof or BuildOk.
            lock gate (fun () ->
                let statusId = SemanticCodegenJpBodyDictMissingBlocked
                let status = semanticStatusToString statusId
                let jpKindId = codegenJpKindOfString jpKind
                let jpKindText = codegenJpKindToString jpKindId
                let site = sprintf "codegen@%s:%s" jpKindText bodyName
                let key = sprintf "%s:%s:%s" jpKindText bodyName keyText
                let payload = sprintf "semantic_codegen_payload(kind=%s,body=%s,key=%s,dict=%d,message=%s)" jpKindText bodyName keyText dictCount message
                let frame =
                    { kind = "codegen"
                      key = key
                      site = site
                      depth = 0
                      re = 0
                      maxRe = 0
                      trace = []
                      reason = "codegen_jp_body_dict_missing"
                      status = status
                      cursor = 0
                      semanticPayload = Some payload
                      semanticCell = None }
                pinTerminalContractLocked event frame
                DiagJson.emit (
                    sprintf "{\"kind\":\"eval_worklist_codegen_jp_body_dict_missing_terminal_pinned\",\"event\":%s,\"jp_kind\":%s,\"body\":%s,\"key\":%s,\"dict\":%d,\"status\":%s,\"rank\":%d,\"single_flight\":1,\"next\":%s}"
                        (esc event) (esc jpKind) (esc bodyName) (esc keyText) dictCount (esc status) (terminalContractRank status) (esc (terminalContractNext status))))

        let resetDurableTerminalContractLedger () =
            lock gate (fun () -> durableTerminalContract <- None)

        let clearTerminalContractIf (status: string) (site: string) (key: string) =
            lock gate (fun () ->
                let matches (frame: Frame) =
                    frame.status = status
                    && (System.String.IsNullOrEmpty(site) || frame.site = site)
                    && (System.String.IsNullOrEmpty(key) || frame.key = key)
                let pinnedCleared =
                    match pinnedTerminalContract with
                    | Some frame when matches frame ->
                        pinnedTerminalContract <- None
                        true
                    | _ -> false
                let durableCleared =
                    match durableTerminalContract with
                    | Some frame when matches frame ->
                        durableTerminalContract <- None
                        true
                    | _ -> false
                pinnedCleared || durableCleared)


        let private compactTrace (tr: Trace) : Trace =
            let head = 16
            let tail = 16
            let n = tr.Length
            if n <= head + tail + 1 then tr
            else (tr |> List.truncate head) @ (tr |> List.rev |> List.truncate tail |> List.rev)

        let private kindFromSite (site: string) =
            if String.IsNullOrWhiteSpace site then "unknown"
            elif site.StartsWith("term@", StringComparison.Ordinal) then "term"
            elif site.StartsWith("ty@", StringComparison.Ordinal) then "ty"
            else "unknown"

        let private sameCycle (a: Frame) (b: Frame) =
            a.kind = b.kind && a.key = b.key && a.site = b.site

        // ALPHA859: keep retry-drain diagnostics in lexical order.
        // Alpha858 added cross-kind terminal telemetry above the old pendingCount
        // binding; F# does not forward-declare local lets, so pendingCount must be
        // available before those helpers call it.
        let pendingCount () =
            lock gate (fun () ->
                let mutable n = 0
                let seen = System.Collections.Generic.HashSet<string>()
                let add opt =
                    match opt with
                    | Some frame ->
                        let k = frame.kind + "|" + frame.key + "|" + frame.site
                        if seen.Add k then n <- n + 1
                    | None -> ()
                add frontier
                add frontierTerm
                add frontierTy
                n)

        let private liveReplayTerminalSuppressedLocked (status: string) =
            let statusId = semanticStatusOfString status
            let activeReplay = replayQueue.Length > 0 || replayDriverActiveDepth > 0 || progressYieldCount > 0
            match liveReplayTerminalPolicyOfSemanticStatusId statusId with
            | DeferTerminalWhileLiveReplay ->
                pendingCount() > 0 && activeReplay
            | SurfaceTerminalDuringLiveReplay
            | TerminalNotLiveReplayPolicy -> false

        let liveReplayTerminalSuppressed (status: string) =
            lock gate (fun () -> liveReplayTerminalSuppressedLocked status)

        let codegenJpBodyDictShouldDefer () =
            lock gate (fun () ->
                let liveFrame opt =
                    match opt with
                    | Some frame ->
                        let nonCodegen =
                            match evalKindOfString frame.kind with
                            | EvalCodegen -> false
                            | _ -> true
                        let liveStatus =
                            match frameStatusOfString frame.status with
                            | FrameSemanticRootComplete -> true
                            | statusId -> isLiveExplicitFrameStatusId statusId
                        nonCodegen && liveStatus
                    | None -> false
                liveFrame frontier
                || liveFrame frontierTerm
                || liveFrame frontierTy
                || replayQueue.Length > 0
                || replayDriverActiveDepth > 0
                || progressYieldCount > 0)

        // ALPHA858: terminal contracts are kind-local evidence.
        // Runtime 857 exposed a stale cross-kind selection bug: retry_stop_drain
        // had a live ty semantic_root_complete frontier at apps/spiral/spiral.spi:2670,
        // but preferred an older term semantic_replay_fingerprint_repeat_blocked
        // contract from trace.spi:121. Cross-kind pins remain evidence for their
        // own parked kind slot; they must not retarget the current global fuse.
        let private frameKindCompatible (requestedKind: string) (frame: Frame) =
            let rk = if System.String.IsNullOrWhiteSpace requestedKind then "unknown" else requestedKind
            rk = "unknown"
            || frame.kind = rk
            || frame.site.StartsWith(rk + "@", System.StringComparison.Ordinal)
            || frame.key.StartsWith(rk + ":", System.StringComparison.Ordinal)

        // ALPHA1040: cross-kind pinned terminals are useful once, but runtime 1039
        // emitted the same ignored pin more than a thousand times. Rate-limit by
        // requested-kind/pin/reason while preserving periodic receipts.
        let private crossKindPinnedTerminalIgnoredSeen = System.Collections.Concurrent.ConcurrentDictionary<string,int>()

        let private emitCrossKindPinnedTerminalIgnored (event: string) (requestedKind: string) (pinned: Frame) (rank: int) (why: string) =
            let emitKey = sprintf "%s|%s|%s|%s|%s|%s" event requestedKind pinned.kind pinned.status pinned.key why
            let repeatCount = crossKindPinnedTerminalIgnoredSeen.AddOrUpdate(emitKey, 1, fun _ old -> old + 1)
            if repeatCount <= 3 || repeatCount = 8 || repeatCount = 32 || repeatCount % 256 = 0 then
                DiagJson.emit (
                    sprintf "{\"kind\":\"eval_worklist_cross_kind_pinned_terminal_ignored\",\"event\":%s,\"requested_kind\":%s,\"pinned_kind\":%s,\"pinned_status\":%s,\"pinned_rank\":%d,\"pinned_site\":%s,\"pinned_key\":%s,\"reason\":%s,\"repeat_count\":%d,\"pending\":%d,\"single_flight\":1,\"next\":\"preserve_kind_local_frontier\"}"
                        (esc event) (esc requestedKind) (esc pinned.kind) (esc pinned.status) rank (esc pinned.site) (esc pinned.key) (esc why) repeatCount (pendingCount()))

        let private clearCurrentCrossKindPinnedTerminalLocked (pinned: Frame) =
            // Clear only the active terminal selector when it is exactly the stale
            // cross-kind frame we just rejected. This does not synthesize replay
            // value, root proof, writer output, codegen result, or BuildOk.
            match pinnedTerminalContract with
            | Some p when p.kind = pinned.kind && p.key = pinned.key && p.site = pinned.site && p.status = pinned.status ->
                pinnedTerminalContract <- None
                true
            | _ -> false

        // ALPHA464: same-node replay identity deliberately ignores site/env/cursor.
        // The alpha463 tail showed the same TJoinPoint' node reappearing through two
        // source sites while the scheduled_parent_replay payload still targeted that
        // node.  Treat this as self-poke churn, not a fresh child payload.
        let private sameReplayNode (a: ReplayCell) (b: ReplayCell) =
            a.kind = b.kind && a.shape = b.shape && a.nodeId = b.nodeId

        // ALPHA544: EJP0014 can be raised while other forced-sequential workers are
        // still converging on the real terminal contract.  Alpha543 showed a macro
        // thunk pin appearing shortly after a semantic_root_complete+pending-JP-body
        // deferral.  Wait briefly for an already-running worker to publish that pin
        // before the retry gate spends time on root-complete churn.  This is
        // diagnostic-only and fail-closed: it never marks replay complete, never
        // writes output, and only returns an existing high-rank terminal contract.
        let waitForPinnedTerminalContract (event: string) (tries: int) (sleepMs: int) =
            let maxTries = max 1 (min 256 tries)
            let delay = max 1 (min 50 sleepMs)
            let rec loop i =
                match tryPinnedTerminalContract() with
                | Some pinned when terminalContractRank pinned.status >= 90 ->
                    let rank = terminalContractRank pinned.status
                    DiagJson.emit (
                        sprintf "{\"kind\":\"eval_worklist_wait_for_pinned_terminal_contract_observed\",\"event\":%s,\"status\":%s,\"rank\":%d,\"site\":%s,\"key\":%s,\"remaining_tries\":%d,\"pending\":%d,\"single_flight\":1,\"next\":%s}"
                            (esc event) (esc pinned.status) rank (esc pinned.site) (esc pinned.key) i (pendingCount()) (esc (terminalContractNext pinned.status)))
                    Some pinned
                | _ when i <= 0 ->
                    DiagJson.emit (
                        sprintf "{\"kind\":\"eval_worklist_wait_for_pinned_terminal_contract_timeout\",\"event\":%s,\"tries\":%d,\"sleep_ms\":%d,\"pending\":%d,\"single_flight\":1,\"next\":\"continue_fail_closed\"}"
                            (esc event) maxTries delay (pendingCount()))
                    None
                | _ ->
                    System.Threading.Thread.Sleep delay
                    loop (i - 1)
            loop maxTries

        let private short (maxLen: int) (s: string) =
            // ALPHA1000: maxLen remains as call-site documentation only.  The
            // compiler log must preserve complete JSON/string payloads; report and
            // UI tools may summarize later, but the receipt itself must not lose
            // tail evidence.
            match activeLogCompletenessPolicy with
            | FullFidelityJsonl -> if Object.ReferenceEquals(s,null) then "" else s
            | TruncatedPreview _ ->
                if Object.ReferenceEquals(s,null) then ""
                elif maxLen <= 3 then s
                elif s.Length > maxLen then s.Substring(0, maxLen - 3) + "..."
                else s

        let private formatCellPayload (cell: ReplayCell) =
            sprintf "semantic_eval_payload(kind=%s,shape=%s,node_id=%d,env_term=%d/%d,env_type=%d/%d,seq_len=%d,cse_depth=%d,trace_depth=%d,site=%s,cursor=%d,step=%d,status=%s)"
                cell.kind cell.shape cell.nodeId cell.envGlobalTerm cell.envStackTerm cell.envGlobalType cell.envStackType cell.seqLen cell.cseDepth cell.traceDepth cell.site cell.cursor cell.step cell.status

        let private formatCell (cell: ReplayCell) =
            sprintf "semantic_eval_cell(kind=%s,shape=%s,node_id=%d,cursor=%d,step=%d,status=%s,site=%s)"
                cell.kind cell.shape cell.nodeId cell.cursor cell.step cell.status cell.site

        let private semanticCellSiteKey (kind: string) (site: string) =
            sprintf "%s|%s" kind site

        let private rememberSemanticCell (cell: ReplayCell) =
            try
                if not (String.IsNullOrWhiteSpace cell.kind) && not (String.IsNullOrWhiteSpace cell.site) then
                    semanticCellsByKindSite.[semanticCellSiteKey cell.kind cell.site] <- cell
            with _ -> ()

        let private trySemanticCellForFrame (frame: Frame) : ReplayCell option =
            try
                let mutable cell = Unchecked.defaultof<ReplayCell>
                if semanticCellsByKindSite.TryGetValue(semanticCellSiteKey frame.kind frame.site, &cell) then Some cell
                else None
            with _ -> None

        // ALPHA546: scheduling the same child identity again and again is now treated
        // as a typed terminal obligation, not as useful replay progress.  The key
        // intentionally ignores step/cursor because alpha545's watchdog gap changed
        // those counters while returning to the same child obligation.
        let private replayChildScheduleKey (role: string) (cell: ReplayCell) =
            sprintf "%s|%s|%s|%d|%s" role cell.kind cell.shape cell.nodeId cell.site

        let private noteReplayChildSchedule (role: string) (cell: ReplayCell) =
            let key = replayChildScheduleKey role cell
            let count =
                lock gate (fun () ->
                    let mutable prior = 0
                    let nextCount = if replayChildScheduleRepeats.TryGetValue(key, &prior) then prior + 1 else 1
                    replayChildScheduleRepeats.[key] <- nextCount
                    nextCount)
            count, key

        // ALPHA537: pin terminal replay contracts at the emission site, not only
        // when retry-drain later peeks the canonical frontier.  Alpha536 showed the
        // earlier literal/macro terminal receipts could be shadowed by a downstream
        // let-success continuation before pinTerminalContract saw them.
        let private pinTerminalCell (event: string) (reason: string) (cell: ReplayCell) =
            let status = cell.status
            if isTerminalContractStatus status then
                let frame =
                    { kind = cell.kind
                      key = sprintf "%s:%s#%d" cell.kind cell.site cell.nodeId
                      site = cell.site
                      depth = cell.traceDepth
                      re = 0
                      maxRe = 0
                      trace = []
                      reason = reason
                      status = status
                      cursor = cell.cursor
                      semanticPayload = Some (formatCellPayload cell)
                      semanticCell = Some cell }
                if liveReplayTerminalSuppressed status then
                    // ALPHA954: pinTerminalCell is above replayQueueDepth in declaration order;
                    // use the local queue under the gate instead of calling the later public helper.
                    let queueDepth = lock gate (fun () -> replayQueue.Length)
                    let activeDepth = replayDriverActiveDepthValue()
                    let progressYieldPending = hasProgressYield()
                    DiagJson.emit (
                        sprintf "{\"kind\":\"eval_worklist_terminal_cell_emission_suppressed_after_live_replay\",\"event\":%s,\"status\":%s,\"rank\":%d,\"node_id\":%d,\"shape\":%s,\"site\":%s,\"pending\":%d,\"queue_depth\":%d,\"active_depth\":%d,\"progress_yield_pending\":%b,\"policy\":\"typed_terminal_status_defers_cell_emission_while_replay_is_live\",\"single_flight\":1,\"next\":\"continue_active_replay_driver\"}"
                            (esc event) (esc status) (terminalContractRank status) cell.nodeId (esc cell.shape) (esc cell.site) (pendingCount()) queueDepth activeDepth progressYieldPending)
                else
                    pinTerminalContract event frame
                    DiagJson.emit (
                        sprintf "{\"kind\":\"eval_worklist_terminal_contract_emission_pinned\",\"event\":%s,\"status\":%s,\"rank\":%d,\"node_id\":%d,\"shape\":%s,\"site\":%s,\"log_completeness\":%s,\"single_flight\":1,\"next\":%s}"
                            (esc event) (esc status) (terminalContractRank status) cell.nodeId (esc cell.shape) (esc cell.site) (esc (logCompletenessPolicyText activeLogCompletenessPolicy)) (esc (terminalContractNext status)))


        // ALPHA545: dynamic-join apply blockers are real terminal contracts once the
        // concrete/dynamic bridge has failed closed.  Pin the blocked replay cell at
        // emission so retry/global-fuse selection sees the dynamic frontier before it
        // burns passes on a generic continuation envelope.
        let private pinDynamicJoinBlocker (event: string) (reason: string) (detail: string) (cell: ReplayCell) =
            let blockedCell = { cell with status = "semantic_dynamic_join_apply_blocked" }
            let dynamicJoinPinSuppressed = liveReplayTerminalSuppressed blockedCell.status
            pinTerminalCell event (reason + ":" + detail) blockedCell
            if dynamicJoinPinSuppressed then
                // ALPHA955: dynamic-join blockers are high-rank terminal evidence only
                // after the replay graph is actually quiet.  Runtime 954 showed the
                // same EApply dynamic-join cell scheduling let/apply replay children
                // immediately after being pinned, so keep the blocker fail-closed but
                // non-durable while the typed replay queue/driver/progress-yield is live.
                let queueDepth = lock gate (fun () -> replayQueue.Length)
                let activeDepth = replayDriverActiveDepthValue()
                let progressYieldPending = hasProgressYield()
                DiagJson.emit (
                    sprintf "{\"kind\":\"eval_worklist_dynamic_join_terminal_suppressed_after_live_replay\",\"event\":%s,\"node_id\":%d,\"shape\":%s,\"site\":%s,\"status\":%s,\"rank\":%d,\"reason\":%s,\"detail\":%s,\"pending\":%d,\"queue_depth\":%d,\"active_depth\":%d,\"progress_yield_pending\":%b,\"policy\":\"typed_dynamic_join_status_defers_while_replay_is_live\",\"single_flight\":1,\"next\":\"continue_active_replay_driver\"}"
                        (esc event) blockedCell.nodeId (esc blockedCell.shape) (esc blockedCell.site) (esc blockedCell.status) (terminalContractRank blockedCell.status) (esc reason) (esc detail) (pendingCount()) queueDepth activeDepth progressYieldPending)
            else
                DiagJson.emit (
                    sprintf "{\"kind\":\"eval_worklist_dynamic_join_terminal_pinned\",\"event\":%s,\"node_id\":%d,\"shape\":%s,\"site\":%s,\"status\":%s,\"rank\":%d,\"reason\":%s,\"detail\":%s,\"single_flight\":1,\"next\":%s}"
                        (esc event) blockedCell.nodeId (esc blockedCell.shape) (esc blockedCell.site) (esc blockedCell.status) (terminalContractRank blockedCell.status) (esc reason) (esc detail) (esc (terminalContractNext blockedCell.status)))
            blockedCell

        // ALPHA909: path-specific runtime archaeology must not be executable policy.
        // Keep old comments as documentation, but route active guards through typed
        // replay evidence: status, kind, shape, semantic cell/payload, pending work,
        // and fresh root-complete witnesses.  This prevents another sentinel/gibberish
        // cleanup while keeping the compiler generic for any Spiral project.
        let frameCellShapeIn (shapes: string list) (frame: Frame) =
            match frame.semanticCell with
            | Some cell -> shapes |> List.exists (fun shape -> cell.shape = shape)
            | None -> false

        let frameCellStatusIs (status: string) (frame: Frame) =
            match frame.semanticCell with
            | Some cell -> cell.status = status
            | None -> false

        let frameIsRootCompleteEvidence (frame: Frame) =
            frame.status = "semantic_root_complete" || frameCellStatusIs "semantic_root_complete" frame

        let frameHasSemanticEvidence (frame: Frame) =
            match frame.semanticCell, frame.semanticPayload with
            | Some _, _ -> true
            | _, Some payload -> not (System.String.IsNullOrWhiteSpace payload)
            | _ -> frame.key.Contains("#")

        let frameCellShapeOrSemanticEvidence (shapes: string list) (frame: Frame) =
            frameCellShapeIn shapes frame || frameHasSemanticEvidence frame

        let frameKindStatusShape (kind: string) (status: string) (shapes: string list) (frame: Frame) =
            frame.kind = kind && frame.status = status && frameCellShapeIn shapes frame

        let rootCompleteShieldsPinnedShape (status: string) (shapes: string list) (frame: Frame) (pinned: Frame) =
            frameIsRootCompleteEvidence frame
            && pinned.status = status
            && pendingCount() > 0
            && frameCellShapeOrSemanticEvidence shapes pinned

        // ALPHA538: retry_stop_drain should not let a lower-ranked replay-repeat or
        // downstream continuation shadow a high-rank terminal that was already pinned
        // at emission.  This only changes diagnostic selection; it does not mark replay
        // complete, hydrate missing payloads, or fabricate semantic values.
        let private preferPinnedTerminalForRetryDrain (event: string) (frame: Frame) =
            if event <> "retry_stop_drain" then Some frame
            else
                match tryPinnedTerminalContract() with
                | Some pinned when not (frameKindCompatible frame.kind pinned) ->
                    let rank = terminalContractRank pinned.status
                    let cleared = lock gate (fun () -> clearCurrentCrossKindPinnedTerminalLocked pinned)
                    emitCrossKindPinnedTerminalIgnored event frame.kind pinned rank (sprintf "active_frame_kind=%s status=%s cleared=%b" frame.kind frame.status cleared)
                    Some frame
                | Some pinned ->
                    let pinnedRank = terminalContractRank pinned.status
                    let frameRank = terminalContractRank frame.status
                    let pinnedBeatsRootComplete =
                        frame.status = "semantic_root_complete" && pinnedRank >= 90
                    let pinnedBeatsNonTerminal =
                        frameRank = 0
                        && pinnedRank >= 68
                        && (frame.status = "semantic_leaf_complete"
                            || frame.status = "semantic_root_complete"
                            || frame.status = "continuation_envelope"
                            || frame.status = "ready_explicit_loop"
                            || frame.status = "blocked_by_reentry")
                    let pinnedBeatsLowerTerminal =
                        pinnedRank >= 68
                        && pinnedRank > frameRank
                    // ALPHA577: when the active retry_stop frontier is already a
                    // semantic_root_complete proof, do not let a later stale TV
                    // terminal from pending-job drain replace it.  This is only a
                    // diagnostic/scheduling preference; writer gates still require
                    // the real root-complete witness and no type value is invented.
                    let rootCompleteShieldsStaleTypeVar =
                        frame.status = "semantic_root_complete"
                        && pinned.status = "semantic_type_variable_value_missing_blocked"
                        && pendingCount() > 0
                    let retargetShieldedByRootEvidence =
                        frame.status = "semantic_stale_root_retarget_blocked"
                        && pinned.status = "semantic_type_variable_value_missing_blocked"
                        && pendingCount() > 0
                    let rootCompleteShieldsPayloadMissing =
                        frame.status = "semantic_root_complete"
                        && pinned.status = "semantic_replay_payload_missing_blocked"
                        && pendingCount() > 0
                    let rootCompleteShieldsStaleTJoinPoint =
                        rootCompleteShieldsPinnedShape "semantic_tjoinpoint_stepper_blocked" ["TJoinPoint'"] frame pinned
                    let rootCompleteShieldsStaleSymbolicIf =
                        rootCompleteShieldsPinnedShape "semantic_if_symbolic_condition_blocked" ["EIfThenElse"] frame pinned
                    let rootCompleteShieldsStaleDynamicJoin =
                        rootCompleteShieldsPinnedShape "semantic_dynamic_join_apply_blocked" ["EApply"] frame pinned
                    let rootCompleteShieldsStaleMacroReplayRepeat =
                        rootCompleteShieldsPinnedShape "semantic_replay_fingerprint_repeat_blocked" ["EMacro"] frame pinned
                    let rootCompleteShieldsStaleNominalConstructor =
                        rootCompleteShieldsPinnedShape "semantic_type_apply_nominal_constructor_stepper_blocked" ["ENominal"] frame pinned
                    let rootCompleteShieldsTraceReplayRepeat =
                        rootCompleteShieldsPinnedShape "semantic_replay_fingerprint_repeat_blocked" ["EMacro"] frame pinned
                    let rootCompleteShieldsTraceUnionReplayRepeat =
                        rootCompleteShieldsPinnedShape "semantic_replay_fingerprint_repeat_blocked" ["TUnion"] frame pinned
                    let rootCompleteShieldsSameSiteStaleRetarget =
                        frameIsRootCompleteEvidence frame
                        && pinned.status = "semantic_root_complete_stale_retarget_repeat_blocked"
                        && pendingCount() > 0
                        && frame.site = pinned.site
                    let appRootShieldsCoreRealRootStaleRetarget =
                        rootCompleteShieldsPinnedShape "semantic_root_complete_stale_retarget_repeat_blocked" ["EAnnot"] frame pinned
                    let rootCompleteShieldsCoreRealApplyContinuationException =
                        frameIsRootCompleteEvidence frame
                        && pinned.status = "semantic_apply_continuation_exception_blocked"
                        && pendingCount() > 0
                        && frameHasSemanticEvidence pinned
                    let rootCompleteShieldsCoreMacroReplayRepeat =
                        rootCompleteShieldsPinnedShape "semantic_replay_fingerprint_repeat_blocked" ["EMacro"] frame pinned
                    let rootCompleteShieldsCoreRealLetReplayRepeat =
                        rootCompleteShieldsPinnedShape "semantic_replay_fingerprint_repeat_blocked" ["ELet"] frame pinned
                    let rootCompleteShieldsCoreForallBodyStepper =
                        rootCompleteShieldsPinnedShape "semantic_type_apply_forall_body_stepper_blocked" ["EOp"; "ETypeApply"] frame pinned
                    let appRootShieldsCoreUnboxStaleRetarget =
                        rootCompleteShieldsPinnedShape "semantic_root_complete_stale_retarget_repeat_blocked" ["EUnbox"] frame pinned
                    let appRootShieldsBackendOpImplRequired =
                        rootCompleteShieldsPinnedShape "semantic_op_impl_required_blocked" ["EOp"] frame pinned
                    let continuationEnvelopeShieldsCoreLetReplayRepeat =
                        isContinuationEnvelopeFrameStatus frame.status
                        && pinned.status = "semantic_replay_fingerprint_repeat_blocked"
                        && pendingCount() > 0
                        && frameCellShapeOrSemanticEvidence ["ELet"] pinned
                    let freshReplayRootWitnessAvailable =
                        let ageMs = (System.DateTime.UtcNow - replayRootCompleteWitnessUtc).TotalMilliseconds
                        replayRootCompleteWitnessUtc <> System.DateTime.MinValue
                        && ageMs >= 0.0
                        && ageMs <= replayRootCompleteWitnessWindowMs
                    let liveDrainShieldsFreshReplayRepeat =
                        isLiveExplicitFrameStatus frame.status
                        && pinned.status = "semantic_replay_fingerprint_repeat_blocked"
                        && pendingCount() > 0
                        && freshReplayRootWitnessAvailable
                        && (match pinned.semanticCell with
                            | Some cell -> cell.shape = "EMacro" || cell.shape = "ELet" || cell.shape = "ETypeApply"
                            | None -> pinned.key.Contains("#"))
                    let liveDrainShieldsFreshOpImplRequired =
                        (isLiveOrRootCompleteFrameStatus frame.status
                         || frame.status = "semantic_replay_driver_exception_blocked")
                        && pinned.status = "semantic_op_impl_required_blocked"
                        && pendingCount() > 0
                        && freshReplayRootWitnessAvailable
                        && frameCellShapeOrSemanticEvidence ["EOp"] pinned
                    let liveDrainShieldsFreshJoinpointValue =
                        isLiveOrRootCompleteFrameStatus frame.status
                        && pinned.status = "semantic_joinpoint_value_blocked"
                        && pendingCount() > 0
                        && freshReplayRootWitnessAvailable
                        && (frameIsRootCompleteEvidence frame || frameHasSemanticEvidence frame)
                    let leafCompleteAppRootShieldsSameSiteStaleRetarget =
                        frame.status = "semantic_leaf_complete"
                        && pinned.status = "semantic_root_complete_stale_retarget_repeat_blocked"
                        && pendingCount() > 0
                        && frame.site = pinned.site
                        && frameCellShapeOrSemanticEvidence ["EApply"; "EUnitTest"] frame
                    let retryDrainShieldsBackendAnnotStaleRetarget =
                        isLiveOrRootCompleteFrameStatus frame.status
                        && pinned.status = "semantic_root_complete_stale_retarget_repeat_blocked"
                        && pendingCount() > 0
                        && ((match frame.semanticCell with
                            | Some cell when cell.status = "semantic_root_complete" -> true
                            | _ -> frame.status = "semantic_root_complete")
                            || (let ageMs = (System.DateTime.UtcNow - replayRootCompleteWitnessUtc).TotalMilliseconds
                                replayRootCompleteWitnessUtc <> System.DateTime.MinValue
                                && ageMs >= 0.0
                                && ageMs <= replayRootCompleteWitnessWindowMs))
                        && frameCellShapeOrSemanticEvidence ["EAnnot"] pinned
                    let leafCompleteShieldsStaleTypeVar =
                        frame.status = "semantic_leaf_complete"
                        && pinned.status = "semantic_type_variable_value_missing_blocked"
                        && pendingCount() > 0
                    if leafCompleteAppRootShieldsSameSiteStaleRetarget then
                        // ALPHA687: runtime 686 shows that after the parent-continuation
                        // cycle yields a concrete same-site app EApply semantic_leaf_complete
                        // frontier, a freshly repinned semantic_root_complete_stale_retarget
                        // terminal at the same spiral.spi:2670 site can still outrank it.
                        // Clear only that stale diagnostic terminal preference and continue
                        // draining the concrete app leaf.  This does not synthesize a
                        // continuation, value, root proof, writer output, codegen result,
                        // or BuildOk.
                        let durableCleared =
                            lock gate (fun () ->
                                match pinnedTerminalContract with
                                | Some p when p.status = "semantic_root_complete_stale_retarget_repeat_blocked" && p.site = pinned.site ->
                                    pinnedTerminalContract <- None
                                | _ -> ()
                                match durableTerminalContract with
                                | Some p when p.status = "semantic_root_complete_stale_retarget_repeat_blocked" && p.site = pinned.site ->
                                    durableTerminalContract <- None
                                    true
                                | _ -> false)
                        DiagJson.emit (
                            sprintf "{\"kind\":\"eval_worklist_leaf_complete_shields_same_site_stale_retarget\",\"event\":%s,\"leaf_site\":%s,\"stale_site\":%s,\"leaf_status\":%s,\"stale_status\":%s,\"pending\":%d,\"durable_cleared\":%b,\"single_flight\":1,\"next\":\"drain_concrete_app_leaf\"}"
                                (esc event) (esc frame.site) (esc pinned.site) (esc frame.status) (esc pinned.status) (pendingCount()) durableCleared)
                        Some frame
                    elif rootCompleteShieldsCoreRealApplyContinuationException then
                        // ALPHA686: runtime 685 showed that the old core/real_core.spir:202
                        // apply-continuation exception pin can survive jp_wait_cycle_drain
                        // and then outrank the live app-root semantic_root_complete frontier
                        // during retry_stop_drain.  Clear only that diagnostic terminal
                        // preference and keep the app root canonical.  This does not
                        // synthesize an apply continuation, value, root proof, writer output,
                        // codegen result, or BuildOk.
                        let durableCleared =
                            lock gate (fun () ->
                                match pinnedTerminalContract with
                                | Some p when p.status = "semantic_apply_continuation_exception_blocked" && p.site = pinned.site ->
                                    pinnedTerminalContract <- None
                                | _ -> ()
                                match durableTerminalContract with
                                | Some p when p.status = "semantic_apply_continuation_exception_blocked" && p.site = pinned.site ->
                                    durableTerminalContract <- None
                                    true
                                | _ -> false)
                        DiagJson.emit (
                            sprintf "{\"kind\":\"eval_worklist_app_root_shields_core_real_apply_continuation_exception\",\"event\":%s,\"root_site\":%s,\"stale_site\":%s,\"root_status\":%s,\"stale_status\":%s,\"pending\":%d,\"durable_cleared\":%b,\"single_flight\":1,\"next\":\"preserve_root_evidence\"}"
                                (esc event) (esc frame.site) (esc pinned.site) (esc frame.status) (esc pinned.status) (pendingCount()) durableCleared)
                        Some frame
                    elif rootCompleteShieldsCoreMacroReplayRepeat then
                        // ALPHA688: runtime 687 shows that the same retry_stop_drain
                        // selection bug reappears after the alpha687 path: a stale
                        // core/core.spi:56 EMacro replay-fingerprint repeat terminal
                        // is preferred over the live app-root semantic_root_complete
                        // witness at apps/spiral/spiral.spi:2670.  Demote only this
                        // diagnostic pin and keep root evidence canonical; this does
                        // not synthesize replay values, continuations, writer output,
                        // codegen result, or BuildOk.
                        let durableCleared =
                            lock gate (fun () ->
                                match pinnedTerminalContract with
                                | Some p when p.status = "semantic_replay_fingerprint_repeat_blocked" && p.site = pinned.site ->
                                    pinnedTerminalContract <- None
                                | _ -> ()
                                match durableTerminalContract with
                                | Some p when p.status = "semantic_replay_fingerprint_repeat_blocked" && p.site = pinned.site ->
                                    durableTerminalContract <- None
                                    true
                                | _ -> false)
                        DiagJson.emit (
                            sprintf "{\"kind\":\"eval_worklist_app_root_core_macro_replay_repeat_demoted\",\"event\":%s,\"root_site\":%s,\"stale_site\":%s,\"root_status\":%s,\"stale_status\":%s,\"pending\":%d,\"durable_cleared\":%b,\"single_flight\":1,\"next\":\"preserve_root_evidence\"}"
                                (esc event) (esc frame.site) (esc pinned.site) (esc frame.status) (esc pinned.status) (pendingCount()) durableCleared)
                        Some frame
                    elif rootCompleteShieldsCoreRealLetReplayRepeat then
                        // ALPHA694: runtime 693 shows retry_stop_drain preferring a
                        // stale rank-79 core/real_core.spir:203 ELet replay-fingerprint
                        // repeat terminal over the live app-root semantic_root_complete
                        // frontier at apps/spiral/spiral.spi:2670.  Clear only that
                        // diagnostic terminal preference and keep existing app-root
                        // evidence canonical.  This does not synthesize replay values,
                        // continuations, root proofs, writer output, codegen result, or
                        // BuildOk.
                        let durableCleared =
                            lock gate (fun () ->
                                match pinnedTerminalContract with
                                | Some p when p.status = "semantic_replay_fingerprint_repeat_blocked" && p.site = pinned.site ->
                                    pinnedTerminalContract <- None
                                | _ -> ()
                                match durableTerminalContract with
                                | Some p when p.status = "semantic_replay_fingerprint_repeat_blocked" && p.site = pinned.site ->
                                    durableTerminalContract <- None
                                    true
                                | _ -> false)
                        DiagJson.emit (
                            sprintf "{\"kind\":\"eval_worklist_app_root_core_real_let_replay_repeat_demoted\",\"event\":%s,\"root_site\":%s,\"stale_site\":%s,\"root_status\":%s,\"stale_status\":%s,\"pending\":%d,\"durable_cleared\":%b,\"single_flight\":1,\"next\":\"preserve_root_evidence\"}"
                                (esc event) (esc frame.site) (esc pinned.site) (esc frame.status) (esc pinned.status) (pendingCount()) durableCleared)
                        Some frame
                    elif rootCompleteShieldsCoreForallBodyStepper then
                        // ALPHA696: runtime 695 shows retry_stop_drain preferring a
                        // rank-81 core/core.spi:56 EOp forall-body stepper terminal
                        // over the live app-root semantic_root_complete frontier at
                        // apps/spiral/spiral.spi:2670.  Clear only that diagnostic
                        // terminal preference and keep existing app-root evidence
                        // canonical.  This does not synthesize a forall body, value,
                        // continuation, root proof, writer output, codegen result,
                        // or BuildOk.
                        let durableCleared =
                            lock gate (fun () ->
                                match pinnedTerminalContract with
                                | Some p when p.status = "semantic_type_apply_forall_body_stepper_blocked" && p.site = pinned.site ->
                                    pinnedTerminalContract <- None
                                | _ -> ()
                                match durableTerminalContract with
                                | Some p when p.status = "semantic_type_apply_forall_body_stepper_blocked" && p.site = pinned.site ->
                                    durableTerminalContract <- None
                                    true
                                | _ -> false)
                        DiagJson.emit (
                            sprintf "{\"kind\":\"eval_worklist_app_root_core_forall_body_stepper_demoted\",\"event\":%s,\"root_site\":%s,\"stale_site\":%s,\"root_status\":%s,\"stale_status\":%s,\"pending\":%d,\"durable_cleared\":%b,\"single_flight\":1,\"next\":\"preserve_root_evidence\"}"
                                (esc event) (esc frame.site) (esc pinned.site) (esc frame.status) (esc pinned.status) (pendingCount()) durableCleared)
                        Some frame
                    elif appRootShieldsCoreUnboxStaleRetarget then
                        // ALPHA690: runtime 689 shows retry_stop_drain preferring a
                        // stale rank-77 core/core.spi:127 EUnbox root-complete retarget
                        // over the live app-root semantic_root_complete frontier at
                        // apps/spiral/spiral.spi:2670.  This clears only that diagnostic
                        // terminal preference and keeps the existing app-root evidence
                        // canonical.  It does not synthesize a value, continuation,
                        // root proof, writer output, codegen result, or BuildOk.
                        let durableCleared =
                            lock gate (fun () ->
                                match pinnedTerminalContract with
                                | Some p when p.status = "semantic_root_complete_stale_retarget_repeat_blocked" && p.site = pinned.site ->
                                    pinnedTerminalContract <- None
                                | _ -> ()
                                match durableTerminalContract with
                                | Some p when p.status = "semantic_root_complete_stale_retarget_repeat_blocked" && p.site = pinned.site ->
                                    durableTerminalContract <- None
                                    true
                                | _ -> false)
                        DiagJson.emit (
                            sprintf "{\"kind\":\"eval_worklist_app_root_core_unbox_stale_retarget_demoted\",\"event\":%s,\"root_site\":%s,\"stale_site\":%s,\"root_status\":%s,\"stale_status\":%s,\"pending\":%d,\"durable_cleared\":%b,\"single_flight\":1,\"next\":\"preserve_root_evidence\"}"
                                (esc event) (esc frame.site) (esc pinned.site) (esc frame.status) (esc pinned.status) (pendingCount()) durableCleared)
                        Some frame
                    elif liveDrainShieldsFreshOpImplRequired then
                        // ALPHA924: runtime 923 proved alpha923 resumed the idle deferred
                        // replay path, but retry_stop_drain still let a rank-94 core EOp
                        // semantic_op_impl_required pin outrank a live drain frontier while
                        // a fresh replay-root write witness existed.  Demote only the
                        // diagnostic terminal preference; the op implementation, value,
                        // continuation, root proof, writer output, codegen result, and
                        // BuildOk are still required from real replay evidence.
                        let durableCleared =
                            lock gate (fun () ->
                                match pinnedTerminalContract with
                                | Some p when p.status = "semantic_op_impl_required_blocked" && p.site = pinned.site ->
                                    pinnedTerminalContract <- None
                                | _ -> ()
                                match durableTerminalContract with
                                | Some p when p.status = "semantic_op_impl_required_blocked" && p.site = pinned.site ->
                                    durableTerminalContract <- None
                                    true
                                | _ -> false)
                        DiagJson.emit (
                            sprintf "{\"kind\":\"eval_worklist_live_drain_op_impl_required_demoted_after_root_witness\",\"event\":%s,\"frontier_site\":%s,\"stale_site\":%s,\"frontier_status\":%s,\"stale_status\":%s,\"pending\":%d,\"durable_cleared\":%b,\"witness\":%s,\"single_flight\":1,\"next\":\"drain_live_frontier_after_root_witness\"}"
                                (esc event) (esc frame.site) (esc pinned.site) (esc frame.status) (esc pinned.status) (pendingCount()) durableCleared (esc replayRootCompleteWitnessSummary))
                        Some frame
                    elif liveDrainShieldsFreshJoinpointValue then
                        // ALPHA926: runtime 925 moved past BackendSwitch repeat and
                        // reached fresh root-complete replay evidence, but retry_stop_drain
                        // still preferred a semantic_joinpoint_value_blocked pin over the
                        // live root/drain frontier until the clean retry budget exhausted.
                        // Demote only that diagnostic joinpoint terminal while a fresh
                        // replay-root witness is alive; no joinpoint value, continuation,
                        // writer output, codegen result, root proof, or BuildOk is synthesized.
                        let durableCleared =
                            lock gate (fun () ->
                                match pinnedTerminalContract with
                                | Some p when p.status = "semantic_joinpoint_value_blocked" && p.site = pinned.site ->
                                    pinnedTerminalContract <- None
                                | _ -> ()
                                match durableTerminalContract with
                                | Some p when p.status = "semantic_joinpoint_value_blocked" && p.site = pinned.site ->
                                    durableTerminalContract <- None
                                    true
                                | _ -> false)
