        // ALPHA456: reconstruct a ReplayCell from the exact compact payload emitted
        // by formatCellPayload.  This bridges scheduled_parent_replay tasks that
        // carry semantic_eval_payload(...) but arrive while the frontier cell slot is
        // empty/stale.  The parser is intentionally narrow and returns None on any
        // malformed field, keeping the replay driver fail-closed.
        let private tryReplayCellPayload (payload: string) : ReplayCell option =
            let tryInt (s: string) =
                let mutable v = 0
                if Int32.TryParse(s, &v) then Some v else None
            let tryPair (s: string) =
                let ix = if Object.ReferenceEquals(s,null) then -1 else s.IndexOf('/')
                if ix <= 0 || ix >= s.Length - 1 then None
                else
                    match tryInt (s.Substring(0, ix)), tryInt (s.Substring(ix + 1)) with
                    | Some a, Some b -> Some(a, b)
                    | _ -> None
            try
                if String.IsNullOrWhiteSpace payload then None
                else
                    let marker = "semantic_eval_payload("
                    let start = payload.IndexOf(marker, StringComparison.Ordinal)
                    if start < 0 then None
                    else
                        let bodyStart = start + marker.Length
                        let stop = payload.IndexOf(")", bodyStart, StringComparison.Ordinal)
                        if stop <= bodyStart then None
                        else
                            let body = payload.Substring(bodyStart, stop - bodyStart)
                            let fields = System.Collections.Generic.Dictionary<string,string>()
                            for part in body.Split([|','|], StringSplitOptions.None) do
                                let ix = part.IndexOf('=')
                                if ix > 0 then
                                    fields.[part.Substring(0, ix).Trim()] <- part.Substring(ix + 1).Trim()
                            let get k =
                                let mutable v = ""
                                if fields.TryGetValue(k, &v) then Some v else None
                            let kind = get "kind"
                            let shape = get "shape"
                            let nodeId = get "node_id" |> Option.bind tryInt
                            let envTerm = get "env_term" |> Option.bind tryPair
                            let envType = get "env_type" |> Option.bind tryPair
                            let seqLen = get "seq_len" |> Option.bind tryInt
                            let cseDepth = get "cse_depth" |> Option.bind tryInt
                            let traceDepth = get "trace_depth" |> Option.bind tryInt
                            let site = get "site"
                            let cursor = get "cursor" |> Option.bind tryInt
                            let step = get "step" |> Option.bind tryInt
                            let status = get "status"
                            match kind, shape, nodeId, envTerm, envType, seqLen, cseDepth, traceDepth, site, cursor, step, status with
                            | Some kind, Some shape, Some nodeId, Some (egt, est), Some (egty, esty), Some seqLen, Some cseDepth, Some traceDepth, Some site, Some cursor, Some step, Some status ->
                                Some { kind = kind; shape = shape; nodeId = nodeId; envGlobalTerm = egt; envStackTerm = est; envGlobalType = egty; envStackType = esty; seqLen = seqLen; cseDepth = cseDepth; traceDepth = traceDepth; site = site; cursor = cursor; step = step; status = status }
                            | _ -> None
            with _ -> None

        let snapshot (maxn: int) : Frame list =
            if maxn <= 0 then []
            else
                lock gate (fun () ->
                    let xs = ResizeArray<Frame>()
                    let seen = System.Collections.Generic.HashSet<string>()
                    let add opt =
                        match opt with
                        | Some frame ->
                            let k = frame.kind + "|" + frame.key + "|" + frame.site
                            if seen.Add k then xs.Add frame
                        | None -> ()
                    add frontier
                    add frontierTerm
                    add frontierTy
                    xs |> Seq.truncate maxn |> Seq.toList)

        let replayQueueDepth () =
            lock gate (fun () -> replayQueue.Length)

        let replayDriverStatus () =
            lock gate (fun () ->
                match replayQueue with
                | task :: _ -> sprintf "%s/%s" task.driver task.status
                | [] -> "none")

        let semanticPayloadStatus () =
            lock gate (fun () ->
                match frontier with
                | Some frame ->
                    match frame.semanticCell, frame.semanticPayload with
                    | Some _, _ -> "cell"
                    | _, Some p when not (String.IsNullOrWhiteSpace p) -> "semantic"
                    | _ -> "missing"
                | None -> "none")

        // ALPHA980: move the replay scheduler away from dumb status aliases.
        // A replay obligation carries the actual runnable/suppressed work item,
        // its liveness snapshot, and its terminal budget.  Strings are now only
        // a serialization boundary for JSON/status fields.
        type ReplayObligationKind =
            | ReplayObligationRun
            | ReplayObligationDefer
            | ReplayObligationBlock

        type ReplayObligationTarget = {
            kind : string
            shape : string
            site : string
            nodeId : int
            driver : string
        }

        type ReplayLivenessSnapshot = {
            pending : int
            queueDepth : int
            activeDepth : int
            payloadStatus : string
            hasDeferredCell : bool
            hasProgressYield : bool
        }

        type ReplayObligation = {
            obligation : ReplayObligationKind
            target : ReplayObligationTarget
            liveness : ReplayLivenessSnapshot
            reason : string
            repeat : int
            cap : int
        }

        let private replayObligationKindText = function
            | ReplayObligationRun -> "run"
            | ReplayObligationDefer -> "defer"
            | ReplayObligationBlock -> "block"

        let private replayObligationStatusText obligation =
            match obligation.obligation with
            | ReplayObligationRun -> "semantic_replay_obligation_run"
            | ReplayObligationDefer -> "semantic_replay_obligation_deferred"
            | ReplayObligationBlock -> "semantic_replay_obligation_blocked"

        let private captureReplayLiveness () =
            { pending = pendingCount()
              queueDepth = replayQueueDepth()
              activeDepth = lock gate (fun () -> replayDriverActiveDepth)
              payloadStatus = semanticPayloadStatus()
              hasDeferredCell = EvalReplayValueStore.hasDeferredReplayCell()
              hasProgressYield = hasProgressYield() }

        // ALPHA981: this helper must not shadow the typed replayDriverForKind above.
        // The typed helper is EvalKind -> ReplayDriverId; this one renders the
        // obligation target at the JSON/status boundary from a raw cell.kind tag.
        // Keeping the names distinct prevents F# from resolving the parent-resume
        // pipeline to the string helper and producing FS0001 at the later replay driver site.
        let private replayDriverTextForCellKind (kind: string) =
            match evalKindOfString kind with
            | EvalTerm -> replayDriverToString TermReplayDriver
            | EvalTy -> replayDriverToString TyReplayDriver
            | _ -> "unknown_replay_driver"

        let private replayObligationTargetFromCell (cell: ReplayCell) =
            { kind = cell.kind
              shape = cell.shape
              site = cell.site
              nodeId = cell.nodeId
              driver = replayDriverTextForCellKind cell.kind }

        let private makeReplayObligation obligation reason repeat cap cell =
            { obligation = obligation
              target = replayObligationTargetFromCell cell
              liveness = captureReplayLiveness()
              reason = reason
              repeat = repeat
              cap = cap }

        let private emitReplayObligation event kindName obligation =
            DiagJson.emit (
                sprintf "{\"kind\":%s,\"event\":%s,\"status\":%s,\"obligation\":%s,\"reason\":%s,\"target_kind\":%s,\"target_shape\":%s,\"target_site\":%s,\"target_node_id\":%d,\"target_driver\":%s,\"pending\":%d,\"queue_depth\":%d,\"active_depth\":%d,\"payload_status\":%s,\"has_deferred_cell\":%b,\"has_progress_yield\":%b,\"repeat\":%d,\"cap\":%d,\"single_flight\":1,\"next\":%s}"
                    (esc kindName) (esc event) (esc (replayObligationStatusText obligation)) (esc (replayObligationKindText obligation.obligation)) (esc obligation.reason)
                    (esc obligation.target.kind) (esc obligation.target.shape) (esc obligation.target.site) obligation.target.nodeId (esc obligation.target.driver)
                    obligation.liveness.pending obligation.liveness.queueDepth obligation.liveness.activeDepth (esc obligation.liveness.payloadStatus) obligation.liveness.hasDeferredCell obligation.liveness.hasProgressYield
                    obligation.repeat obligation.cap (esc obligation.target.driver))



        let tryPinnedReplayPayloadMissing () =
            lock gate (fun () -> pinnedReplayPayloadMissing)

        // ALPHA364: distinguish local leaf value resolution from root replay completion.
        // Alpha363 proved the old gate was still too permissive: a single EV leaf could mark
        // semantic_leaf_complete, trigger retry_after_replay_root_complete if not gated, and let an unstable write
        // path emit a tiny residual. Until a parent-continuation stack proves the root frame, local
        // value resolutions are semantic_leaf_complete and remain fail-closed.
        let hasReplayPartial () =
            lock gate (fun () ->
                match frontier with
                | Some frame when frame.status = "semantic_step_partial" || frame.status = "semantic_step_done" || frame.status = "semantic_leaf_complete" || frame.status = "semantic_parent_continuation_cycle_blocked" || frame.status = "semantic_type_variable_value_missing_blocked" || frame.status = "semantic_stale_root_retarget_blocked" || frame.status = "semantic_replay_driver_exception_blocked" || frame.status = "semantic_replay_payload_missing_blocked" || frame.status = "semantic_record_with_value_blocked" || frame.status = "semantic_seq_type_error_blocked" || frame.status = "semantic_replay_child_schedule_repeat_blocked" || frame.status = "semantic_macro_thunk_missing_blocked" || frame.status = "semantic_tjoinpoint_stepper_blocked" || frame.status = "semantic_literal_op_body_stepper_blocked" || frame.status = "semantic_let_success_apply_exception_blocked" || frame.status = "semantic_let_success_all_ready_apply_blocked" || frame.status = "semantic_let_success_apply_continuation_blocked" || frame.status = "semantic_apply_continuation_exception_blocked" || frame.status = "semantic_deferred_function_replay_exception_blocked" -> true
                | Some frame ->
                    match frame.semanticCell with
                    | Some cell when cell.status = "semantic_step_partial" || cell.status = "semantic_step_done" || cell.status = "semantic_leaf_complete" || cell.status = "semantic_parent_continuation_cycle_blocked" || cell.status = "semantic_type_variable_value_missing_blocked" || cell.status = "semantic_stale_root_retarget_blocked" || cell.status = "semantic_replay_driver_exception_blocked" || cell.status = "semantic_replay_payload_missing_blocked" || cell.status = "semantic_record_with_value_blocked" || cell.status = "semantic_seq_type_error_blocked" || cell.status = "semantic_replay_child_schedule_repeat_blocked" || cell.status = "semantic_macro_thunk_missing_blocked" || cell.status = "semantic_tjoinpoint_stepper_blocked" || cell.status = "semantic_literal_op_body_stepper_blocked" || cell.status = "semantic_let_success_apply_exception_blocked" || cell.status = "semantic_let_success_all_ready_apply_blocked" || cell.status = "semantic_let_success_apply_continuation_blocked" || cell.status = "semantic_apply_continuation_exception_blocked" || cell.status = "semantic_deferred_function_replay_exception_blocked" -> true
                    | _ -> false
                | None -> false)

        let hasReplayComplete () =
            lock gate (fun () ->
                match frontier with
                | Some frame when frame.status = "semantic_root_complete" -> true
                | Some frame ->
                    match frame.semanticCell with
                    | Some cell when cell.status = "semantic_root_complete" -> true
                    | _ -> false
                | None -> false)

        // ALPHA410: root-complete witnesses are kind-local for evaluator returns.
        // Alpha409 proved a term frontier could complete, after which a ty entry
        // incorrectly treated that term completion as a missing type value.
        // Keep the global witness for coarse diagnostics/write gating, but require
        // the frame or attached cell to match the caller kind before returning ty/term.
        // ALPHA411: active fuses are also kind-local.  Alpha410 proved the completed-kind
        // reset, then exposed a live ty fuse (file_system.spi:993) being consumed by
        // term_entry_global_fuse as a missing term value.  Reset active cross-kind fuses
        // before value-missing diagnostics so the requested evaluator can proceed normally.
        let frameReplayCompleteKind (kind: string) (frame: Frame) =
            // ALPHA448: a frame-level semantic_root_complete is not a proof for a newly
            // attached same-kind cell unless that cell is also complete.  Alpha447 proved
            // the old rule can keep attempting build for listm.spi:6 while the live cell
            // is a different TJoinPoint' at runtime.spi:330.
            let cellComplete =
                match frame.semanticCell with
                | Some cell when cell.kind = kind && cell.status = "semantic_root_complete" -> true
                | _ -> false
            let frameComplete =
                frame.kind = kind
                && frame.status = "semantic_root_complete"
                && (match frame.semanticCell with Some _ -> cellComplete | None -> true)
            frameComplete || cellComplete

        let frameReplayCompleteAny (frame: Frame) =
            let frameComplete = frame.status = "semantic_root_complete"
            let cellComplete =
                match frame.semanticCell with
                | Some cell when cell.status = "semantic_root_complete" -> true
                | _ -> false
            frameComplete || cellComplete

        let private rootCompleteFingerprintLocked () =
            match frontier with
            | Some frame when frameReplayCompleteAny frame ->
                let cellKey =
                    match frame.semanticCell with
                    | Some cell -> sprintf "%s:%s:%s:cursor=%d:step=%d:site=%s" cell.kind cell.shape cell.status cell.cursor cell.step cell.site
                    | None -> "cell:none"
                // ALPHA429: stable root-complete is semantic, but not oblivious to parent-continuation progress.
                // Alpha428 proved the ledger finally works, yet it also false-positive aborted while
                // the parent replay was still advancing through semantic_step_partial -> parent_resume ->
                // semantic_root_complete.  Keep node allocation ids out, but include replay cursor/step/site
                // so a genuinely moving parent continuation does not look like the same terminal proof.
                sprintf "%s|%s|%s|cursor=%d|trace=%d|frame_status=%s|queue=%d|%s" frame.kind frame.key frame.site frame.cursor frame.trace.Length frame.status replayQueue.Length cellKey
            | _ -> ""

        let private selectedFrontierFingerprintLocked (frame: Frame) =
            let cellKey =
                match frame.semanticCell with
                | Some cell -> sprintf "%s:%s:%s:cursor=%d:step=%d:site=%s" cell.kind cell.shape cell.status cell.cursor cell.step cell.site
                | None -> "cell:none"
            sprintf "%s|%s|%s|status=%s|cursor=%d|trace=%d|queue=%d|%s" frame.kind frame.key frame.site frame.status frame.cursor frame.trace.Length replayQueue.Length cellKey

        let private noteStableRootSelectedFrontierLocked (blockedRootKey: string) (selected: Frame) =
            let selectedKey = blockedRootKey + "=>" + selectedFrontierFingerprintLocked selected
            if selectedKey = stableRootSelectedKey then
                stableRootSelectedCount <- stableRootSelectedCount + 1
            else
                stableRootSelectedKey <- selectedKey
                stableRootSelectedCount <- 1
            stableRootSelectedCount, selectedKey

        let private noteSelectedFrontierStepperReplayLocked (key: string) =
            let mutable prior = 0
            let nextCount = if selectedFrontierStepperReplayAttempts.TryGetValue(key, &prior) then prior + 1 else 1
            selectedFrontierStepperReplayAttempts.[key] <- nextCount
            nextCount

        let noteRootCompleteHandoff () =
            lock gate (fun () ->
                let key = rootCompleteFingerprintLocked ()
                if System.String.IsNullOrWhiteSpace key then
                    stableRootCompleteKey <- ""
                    stableRootCompleteCount <- 0
                    0, "none"
                else
                    if key = stableRootCompleteKey then
                        stableRootCompleteCount <- stableRootCompleteCount + 1
                    else
                        stableRootCompleteKey <- key
                        stableRootCompleteCount <- 1
                    stableRootCompleteCount, key)

        let hasReplayCompleteKind (kind: string) =
            lock gate (fun () ->
                match frontier with
                | Some frame -> frameReplayCompleteKind kind frame
                | None -> false)

        let hasReplayCompleteOtherKind (kind: string) =
            lock gate (fun () ->
                match frontier with
                | Some frame -> frameReplayCompleteAny frame && frame.kind <> kind
                | None -> false)

        let private rememberReplayRootComplete (event: string) (outcome: string) (cell: ReplayCell) =
            replayRootCompleteWitnessUtc <- System.DateTime.UtcNow
            replayRootCompleteWitnessSummary <- sprintf "event=%s outcome=%s cell=%s" event outcome (formatCell cell)

        let hasReplayCompleteWriteWitness () =
            lock gate (fun () ->
                let frontierComplete =
                    match frontier with
                    | Some frame when frame.status = "semantic_root_complete" -> true
                    | Some frame ->
                        match frame.semanticCell with
                        | Some cell when cell.status = "semantic_root_complete" -> true
                        | _ -> false
                    | None -> false
                if frontierComplete then true
                else
                    let ageMs = (System.DateTime.UtcNow - replayRootCompleteWitnessUtc).TotalMilliseconds
                    replayRootCompleteWitnessUtc <> System.DateTime.MinValue
                    && ageMs >= 0.0
                    && ageMs <= replayRootCompleteWitnessWindowMs)

        let replayCompleteWriteWitnessSummary () =
            lock gate (fun () ->
                if replayRootCompleteWitnessUtc = System.DateTime.MinValue then "none"
                else sprintf "%s age_ms=%.0f" replayRootCompleteWitnessSummary ((System.DateTime.UtcNow - replayRootCompleteWitnessUtc).TotalMilliseconds))

        // ALPHA439: only completed semantic states are absorbing for the bounded
        // trampoline.  Alpha438 proved that treating semantic_step_partial as terminal
        // strands a real child replay at cursor=trace_len: ESeq schedules its first
        // child EApply, the child reports semantic_step_partial, and retry_stop aborts
        // with explicit_eval_worklist_real_stepper_required instead of building the
        // next replay continuation.  Keep root/leaf absorbing to preserve alpha389's
        // no-downgrade invariant, but let partial/done states flow back into the
        // continuation adapter when their trace cursor is exhausted.
        let private isSemanticTerminalStatus (status: string) =
            status = "semantic_root_complete"
            || status = "semantic_leaf_complete"
            || status = "semantic_parent_continuation_cycle_blocked"
            || status = semanticStatusToString SemanticRootCompleteStaleRetargetPendingNoQueueBlocked
            || status = "semantic_type_variable_value_missing_blocked"
            || status = "semantic_stale_root_retarget_blocked"
            || status = "semantic_replay_driver_exception_blocked"
            || status = "semantic_replay_payload_missing_blocked"
            || status = "semantic_seq_type_error_blocked"
            || status = "semantic_replay_child_schedule_repeat_blocked"
            || status = "semantic_replay_fingerprint_repeat_blocked"
            || status = "semantic_joinpoint_term_stepper_blocked"
            || status = "semantic_macro_thunk_missing_blocked"
            || status = "semantic_tjoinpoint_stepper_blocked"
            || status = "semantic_joinpoint_value_blocked"
            || status = "semantic_literal_op_body_stepper_blocked"
            || status = "semantic_let_success_apply_exception_blocked"
            || status = "semantic_let_success_all_ready_apply_blocked"
            || status = "semantic_let_success_apply_continuation_blocked"
            || status = "semantic_nominal_constructor_stepper_blocked"
            || status = "semantic_type_apply_forall_body_stepper_blocked"
            || status = "semantic_apply_continuation_exception_blocked"
            || status = "semantic_deferred_function_replay_exception_blocked"

        let private semanticTerminalNext (status: string) =
            if status = "semantic_root_complete" then "attempt_build"
            elif status = "semantic_leaf_complete" then "explicit_eval_worklist_parent_continuation_required"
            elif status = "semantic_parent_continuation_cycle_blocked" then "explicit_eval_worklist_parent_continuation_cycle_required"
            elif status = semanticStatusToString SemanticRootCompleteStaleRetargetPendingNoQueueBlocked then "explicit_eval_worklist_root_complete_stale_retarget_required"
            elif status = "semantic_type_variable_value_missing_blocked" then "explicit_eval_worklist_type_variable_env_required"
            elif status = "semantic_stale_root_retarget_blocked" then "explicit_eval_worklist_stale_root_retarget_required"
            elif status = "semantic_replay_driver_exception_blocked" then "explicit_eval_worklist_replay_driver_exception_required"
            elif status = "semantic_replay_payload_missing_blocked" then "explicit_eval_worklist_replay_payload_required"
            elif status = "semantic_seq_type_error_blocked" then "explicit_eval_worklist_seq_type_error_required"
            elif status = "semantic_replay_child_schedule_repeat_blocked" then "explicit_eval_worklist_replay_child_schedule_repeat_required"
            elif status = "semantic_replay_fingerprint_repeat_blocked" then "explicit_eval_worklist_replay_fingerprint_repeat_required"
            elif status = "semantic_joinpoint_term_stepper_blocked" then "explicit_eval_worklist_joinpoint_term_stepper_required"
            elif status = "semantic_macro_thunk_missing_blocked" then "explicit_eval_worklist_macro_thunk_required"
            elif status = "semantic_tjoinpoint_stepper_blocked" then "explicit_eval_worklist_tjoinpoint_stepper_required"
            elif status = "semantic_joinpoint_value_blocked" then "explicit_eval_worklist_joinpoint_value_required"
            elif status = "semantic_literal_op_body_stepper_blocked" then "explicit_eval_worklist_literal_op_body_stepper_required"
            elif status = "semantic_let_success_apply_exception_blocked" then "explicit_eval_worklist_let_success_apply_exception_required"
            elif status = "semantic_let_success_all_ready_apply_blocked" then "explicit_eval_worklist_let_success_all_ready_apply_required"
            elif status = "semantic_let_success_apply_continuation_blocked" then "explicit_eval_worklist_let_success_apply_continuation_required"
            elif status = "semantic_nominal_constructor_stepper_blocked" then "explicit_eval_worklist_nominal_constructor_stepper_required"
            elif status = "semantic_type_apply_forall_body_stepper_blocked" then "explicit_eval_worklist_type_apply_forall_body_stepper_required"
            elif status = "semantic_apply_continuation_exception_blocked" then "explicit_eval_worklist_apply_continuation_exception_required"
            elif status = "semantic_deferred_function_replay_exception_blocked" then "explicit_eval_worklist_deferred_function_replay_exception_required"
            else "explicit_eval_worklist_real_stepper_required"

        let private semanticPayloadOf (frame: Frame) =
            match frame.semanticCell, frame.semanticPayload with
            | Some cell, _ -> formatCellPayload cell
            | _, Some p when not (String.IsNullOrWhiteSpace p) -> p
            | _ ->
                match trySemanticCellForFrame frame with
                | Some cell -> formatCellPayload cell
                | None -> "semantic_eval_payload_missing"

        let private semanticCellOf (frame: Frame) =
            match frame.semanticCell with
            | Some cell -> Some cell
            | None -> trySemanticCellForFrame frame

        let private replayKey (frame: Frame) =
            sprintf "%s|%s|%s|%d|%d" frame.kind frame.key frame.site frame.cursor frame.trace.Length

        let private replayDriverFor (frame: Frame) =
            match frame.kind with
            | "term" -> "term_replay_driver"
            | "ty" -> "ty_replay_driver"
            | _ -> "unknown_replay_driver"

        // ALPHA465: classify the active replay driver's evaluator kind.
        // Alpha464 proved parent/child same-kind deferral, then exposed a cross-kind
        // poke hazard: a ty_entry TTerm cell can attach while a term_replay_driver
        // is already reducing a term continuation, and the generic poke restarts the
        // term driver from the ty event before the existing tick advances.
        let private replayTaskDriverKind (task: ReplayTask) =
            if task.driver.StartsWith("term_", StringComparison.Ordinal) then "term"
            elif task.driver.StartsWith("ty_", StringComparison.Ordinal) then "ty"
            else "unknown"

        let private activeReplayDriverKindMismatch (kind: string) =
            lock gate (fun () ->
                match replayQueue with
                | task :: _ ->
                    let taskKind = replayTaskDriverKind task
                    taskKind <> "unknown" && taskKind <> kind
                | [] -> false)

        let private replayDriverNextFor (task: ReplayTask) (hasCell: bool) (hasSemantic: bool) =
            match task.driver, hasCell, hasSemantic with
            | "term_replay_driver", true, _ -> "execute_term_eval_stepper"
            | "ty_replay_driver", true, _ -> "execute_ty_eval_stepper"
            | "term_replay_driver", false, true -> "wire_term_typed_replay_cell"
            | "ty_replay_driver", false, true -> "wire_ty_typed_replay_cell"
            | "term_replay_driver", false, false -> "wire_term_eval_payload"
            | "ty_replay_driver", false, false -> "wire_ty_eval_payload"
            | _, true, _ -> "execute_unknown_eval_stepper"
            | _, false, true -> "wire_unknown_typed_replay_cell"
            | _ -> "wire_unknown_eval_payload"

        // ALPHA349: typed replay-cell driver commit gate.
        //
        // Alpha347/348 proved the semantic payload can reach the replay driver and dispatch a reducer. It was still a
        // string envelope, so the driver could only say "wire_term_eval_stepper". Alpha347
        // keeps that textual envelope for diagnostics, but also carries a ReplayCell record
        // and emits a deterministic eval_worklist_replay_step. This is the first stack-safe
        // stepper boundary: it does not recurse into term/ty yet; it hands a typed cell to the
        // future executor and deduplicates repeated driver ticks.
        // ALPHA498: drain one preserved deferred replay child after the active driver
        // fully unwinds.  Alpha497 intentionally suppressed cross-kind/reentrant pokes while a
        // parent/root replay was already reducing; the missing piece is the safe handoff after
        // that active tick is done and no replay task remains queued.
        let private tryScheduleDeferredAfterActiveDriver (event: string) =
            let deferredOpt =
                // ALPHA916: annotated test bodies now arrive as the next concrete
                // replay obligation after the live-cycle defer.  Drain them before
                // macro/type catch-alls so the explicit EAnnotTest stepper gets a tick
                // instead of being hidden behind an older fingerprint-repeat terminal.
                match EvalReplayValueStore.tryTakeDeferredReplayCell "term" "EAnnotTest" -1 with
                | Some cell -> Some cell
                | None ->
                    // ALPHA971: direct EAnnot wrappers can surface after root-complete
                    // handoff while their inner/type children are still live. Drain
                    // them before macro/type catch-alls so the annotation spine keeps
                    // its own replay tick instead of being buried behind stale root proof.
                    match EvalReplayValueStore.tryTakeDeferredReplayCell "term" "EAnnot" -1 with
                    | Some cell -> Some cell
                    | None ->
                        // ALPHA562: do not starve term macro apply-args behind the ty catch-all.
                        // Runtime 561 showed EMacro apply_arg_child was repeatedly scheduled while
                        // a ty replay driver remained active, then terminalized as child_schedule_repeat.
                        match EvalReplayValueStore.tryTakeDeferredReplayCell "term" "EMacro" -1 with
                        | Some cell -> Some cell
                        | None ->
                            match EvalReplayValueStore.tryTakeDeferredReplayCell "ty" "TFun" -1 with
                            | Some cell -> Some cell
                            | None ->
                                match EvalReplayValueStore.tryTakeDeferredReplayCell "term" "EFun'" -1 with
                                | Some cell -> Some cell
                                | None ->
                                    match EvalReplayValueStore.tryTakeDeferredReplayCell "term" "" -1 with
                                    | Some cell -> Some cell
                                    | None -> EvalReplayValueStore.tryTakeDeferredReplayCell "ty" "" -1
            match deferredOpt with
            | Some deferredCell ->
                let replayCell : ReplayCell = {
                    kind = deferredCell.kind
                    shape = deferredCell.shape
                    nodeId = deferredCell.nodeId
                    envGlobalTerm = deferredCell.envGlobalTerm
                    envStackTerm = deferredCell.envStackTerm
                    envGlobalType = deferredCell.envGlobalType
                    envStackType = deferredCell.envStackType
                    seqLen = deferredCell.seqLen
                    cseDepth = deferredCell.cseDepth
                    traceDepth = deferredCell.traceDepth
                    site = deferredCell.site
                    cursor = deferredCell.cursor
                    step = deferredCell.step
                    status = "deferred_after_active_driver_ready"
                }
                let scheduled =
                    lock gate (fun () ->
                        if replayQueue.IsEmpty then
                            replaySeq <- replaySeq + 1L
                            let childDriver = if replayCell.kind = "ty" then "ty_replay_driver" elif replayCell.kind = "term" then "term_replay_driver" else "unknown_replay_driver"
                            let childKey = sprintf "deferred_after_active_driver|%s|%s|%d|%d" replayCell.kind replayCell.shape replayCell.nodeId replayCell.step
                            let childTask = { id = replaySeq; key = childKey; driver = childDriver; payload = formatCellPayload replayCell; status = "scheduled_replay"; event = event }
                            replayScheduledKey <- Some childKey
                            replayQueue <- [childTask]
                            true, childDriver, childKey, replaySeq
                        else
                            false, "", "", 0L)
                match scheduled with
                | true, childDriver, childKey, replayId ->
                    DiagJson.emit (
                        sprintf "{\"kind\":\"eval_worklist_deferred_after_active_driver_scheduled\",\"event\":%s,\"replay_id\":%d,\"driver\":%s,\"key\":%s,\"cell\":%s,\"queue_depth\":%d,\"single_flight\":1,\"next\":%s}"
                            (esc event) replayId (esc childDriver) (esc childKey) (esc (formatCell replayCell)) (replayQueueDepth()) (esc childDriver))
                    true
                | false, _, _, _ ->
                    EvalReplayValueStore.putDeferredReplayCell deferredCell
                    false
            | None -> false

        let private replayDriverStackFenceCap = 24

        let rec private runReplayDriver (event: string) =
            let activeDepthAfterEnter =
                lock gate (fun () ->
                    replayDriverActiveDepth <- replayDriverActiveDepth + 1
                    replayDriverActiveDepth)
            let scheduleReplayDriverTick (reason: string) (event': string) =
                let queueDepthAtYield, shouldSchedule =
                    lock gate (fun () ->
                        let qd = replayQueue.Length
                        let shouldSchedule = qd > 0 && not replayDriverStackFenceQueued
                        // ALPHA951: a cooperative handoff with runnable queue is real scheduler progress.
                        // Count it for retry_stop so root-complete/pending-job terminals do not abort
                        // before the fresh replay tick has a chance to consume the queued continuation.
                        if qd > 0 then noteProgressYieldLocked ()
                        if shouldSchedule then replayDriverStackFenceQueued <- true
                        qd, shouldSchedule)
                DiagJson.emit (
                    sprintf "{\"kind\":\"eval_worklist_replay_driver_cooperative_yielded\",\"event\":%s,\"reason\":%s,\"active_depth\":%d,\"queue_depth\":%d,\"scheduled_async\":%b,\"pending\":%d,\"policy\":\"break_replay_handoff_recursion_into_fresh_tick\",\"single_flight\":1,\"next\":\"threadpool_replay_driver_tick\"}"
                        (esc event') (esc reason) activeDepthAfterEnter queueDepthAtYield shouldSchedule (pendingCount()))
                if shouldSchedule then
                    System.Threading.ThreadPool.QueueUserWorkItem(System.Threading.WaitCallback(fun _ ->
                        try
                            lock gate (fun () -> replayDriverStackFenceQueued <- false)
                            runReplayDriver event'
                        with ex ->
                            lock gate (fun () -> replayDriverStackFenceQueued <- false)
                            DiagJson.emit (
                                sprintf "{\"kind\":\"eval_worklist_replay_driver_cooperative_async_error\",\"event\":%s,\"reason\":%s,\"error_type\":%s,\"message\":%s,\"queue_depth\":%d,\"pending\":%d,\"single_flight\":1,\"next\":\"explicit_replay_driver_cooperative_yield_error\"}"
                                    (esc event') (esc reason) (esc (ex.GetType().Name)) (esc ex.Message) (replayQueueDepth()) (pendingCount())))) |> ignore

            if activeDepthAfterEnter > replayDriverStackFenceCap then
                let queueDepthAtFence, shouldSchedule =
                    lock gate (fun () ->
                        let qd = replayQueue.Length
                        replayDriverActiveDepth <- max 0 (replayDriverActiveDepth - 1)
                        let shouldSchedule = qd > 0 && not replayDriverStackFenceQueued
                        // ALPHA951: the older depth fence is also progress-bearing when a task is queued.
                        if qd > 0 then noteProgressYieldLocked ()
                        if shouldSchedule then replayDriverStackFenceQueued <- true
                        qd, shouldSchedule)
                DiagJson.emit (
                    sprintf "{\"kind\":\"eval_worklist_replay_driver_stack_fence_yielded\",\"event\":%s,\"active_depth\":%d,\"cap\":%d,\"queue_depth\":%d,\"scheduled_async\":%b,\"pending\":%d,\"policy\":\"convert_nested_replay_recursion_to_async_trampoline\",\"single_flight\":1,\"next\":\"threadpool_replay_driver_tick\"}"
                        (esc event) activeDepthAfterEnter replayDriverStackFenceCap queueDepthAtFence shouldSchedule (pendingCount()))
                if shouldSchedule then
                    System.Threading.ThreadPool.QueueUserWorkItem(System.Threading.WaitCallback(fun _ ->
                        try
                            lock gate (fun () -> replayDriverStackFenceQueued <- false)
                            runReplayDriver event
                        with ex ->
                            lock gate (fun () -> replayDriverStackFenceQueued <- false)
                            DiagJson.emit (
                                sprintf "{\"kind\":\"eval_worklist_replay_driver_stack_fence_async_error\",\"event\":%s,\"error_type\":%s,\"message\":%s,\"queue_depth\":%d,\"pending\":%d,\"single_flight\":1,\"next\":\"explicit_replay_driver_stack_fence_error\"}"
                                    (esc event) (esc (ex.GetType().Name)) (esc ex.Message) (replayQueueDepth()) (pendingCount())))) |> ignore
            else
                let mutable executingTaskOpt : ReplayTask option = None
                let mutable executingCellOpt : ReplayCell option = None
                try
                    try
                        let taskOpt =
                            lock gate (fun () ->
                                match replayQueue with
                                | task :: rest ->
                                    let frontierCellOpt = frontier |> Option.bind semanticCellOf
                                    let taskCellOpt = tryReplayCellPayload task.payload
                                    // ALPHA510: when the canonical frontier is already parked as a
                                    // fingerprint-repeat blocker, the queued replay_continuation is the
                                    // fresher work item.  Do not let the stale frontier cell shadow the
                                    // task payload; otherwise alpha509 keeps re-capturing replay_id 1095
                                    // without ever committing the queued let_success child.
                                    let preferTaskPayloadOverRepeatFrontier =
                                        match frontier, taskCellOpt with
                                        | Some frame, Some _ ->
                                            frame.status = "semantic_replay_fingerprint_repeat_blocked"
                                            && task.payload.Contains("replay_continuation")
                                        | _ -> false
                                    // ALPHA860: the replay queue owns the identity of the work item being
                                    // driven.  Runtime 859 showed a queued deferred EForall' payload being
                                    // executed through an unrelated completed EUnitTest frontier cell.  A
                                    // frontier cell is only a fresher representation of this task when its
                                    // stable semantic identity matches the task payload identity.
                                    let replayCellProgressed (c: ReplayCell) =
                                        c.cursor > 0
                                        || c.step > 0
                                        || c.status = "semantic_step_partial"
                                        || c.status = "parent_continuation_ready"
                                        || c.status = "semantic_root_complete"
                                    let sameReplayIdentity (a: ReplayCell) (b: ReplayCell) =
                                        let sameStableNode =
                                            a.kind = b.kind
                                            && a.shape = b.shape
                                            && a.nodeId = b.nodeId
                                        sameStableNode
                                        && (
                                            a.site = b.site
                                            || replayCellProgressed a
                                            || replayCellProgressed b
                                        )
                                    let sameReplayIdentitySiteDrift (a: ReplayCell) (b: ReplayCell) =
                                        a.kind = b.kind
                                        && a.shape = b.shape
                                        && a.nodeId = b.nodeId
                                        && a.site <> b.site
                                        && (replayCellProgressed a || replayCellProgressed b)
                                    let preferTaskPayloadOverStaleFrontier =
                                        match frontierCellOpt, taskCellOpt with
                                        | Some frontierCell, Some taskCell ->
                                            not (sameReplayIdentity frontierCell taskCell)
                                        | _ -> false
                                    let preferTaskPayloadCell =
                                        preferTaskPayloadOverRepeatFrontier || preferTaskPayloadOverStaleFrontier
                                    let sameNodeSiteDriftReplayIdentity =
                                        match frontierCellOpt, taskCellOpt with
                                        | Some frontierCell, Some taskCell ->
                                            sameReplayIdentitySiteDrift frontierCell taskCell
                                        | _ -> false
                                    let taskPayloadCellText = match taskCellOpt with | Some c -> formatCell c | None -> "none"
                                    let frontierPayloadCellText = match frontierCellOpt with | Some c -> formatCell c | None -> "none"
                                    let payloadHydrated = Option.isSome taskCellOpt
                                    let cellOpt =
                                        if preferTaskPayloadCell then taskCellOpt
                                        else
                                            match frontierCellOpt with
                                            | Some _ -> frontierCellOpt
                                            | None -> taskCellOpt
                                    if payloadHydrated && not sameNodeSiteDriftReplayIdentity then
                                        match taskCellOpt, frontier with
                                        | Some cell, Some frame ->
                                            let frame' = { frame with semanticCell = Some cell; semanticPayload = Some (formatCellPayload cell) }
                                            frontier <- Some frame'
                                            slotSetLocked frame'
                                        | _ -> ()
                                    let hasCell = Option.isSome cellOpt
                                    let hasSemantic = hasCell || task.payload.Contains("semantic_eval_payload(")
                                    // ALPHA451: preserve the semantic identity of a queued parent replay.
                                    // Alpha450's defer guard looked for scheduled_parent_replay, but this
                                    // driver immediately rewrote the queued task to driver_ready_replay_cell
                                    // before attachSemanticCell could see it.  Keep the parent status stable;
                                    // readiness is still reflected by hasCell/next/outcome and the reducer can
                                    // now distinguish "resume parent" from an ordinary root replay.
                                    let status =
                                        if task.status = "scheduled_parent_replay" then "scheduled_parent_replay"
                                        elif hasCell then "driver_ready_replay_cell"
                                        elif hasSemantic then "driver_ready_semantic_payload"
                                        else "driver_blocked_semantic_payload"
                                    let task' = { task with status = status }
                                    replayQueue <- task' :: rest
                                    Some(task', hasSemantic, cellOpt, payloadHydrated, preferTaskPayloadOverRepeatFrontier, preferTaskPayloadOverStaleFrontier, sameNodeSiteDriftReplayIdentity, taskPayloadCellText, frontierPayloadCellText)
                                | [] -> None)
                        match taskOpt with
                        | Some (task, hasSemantic, cellOpt, payloadHydrated, preferTaskPayloadOverRepeatFrontier, preferTaskPayloadOverStaleFrontier, sameNodeSiteDriftReplayIdentity, taskPayloadCellText, frontierPayloadCellText) ->
                            executingTaskOpt <- Some task
                            executingCellOpt <- cellOpt
                            let hasCell = Option.isSome cellOpt
                            let outcome =
                                if hasCell then "typed_replay_cell_captured"
                                elif hasSemantic then "semantic_payload_captured"
                                else "semantic_payload_required"
                            let next = replayDriverNextFor task hasCell hasSemantic
                            DiagJson.emit (
                                sprintf "{\"kind\":\"eval_worklist_replay_driver\",\"event\":%s,\"replay_id\":%d,\"driver\":%s,\"status\":%s,\"queue_depth\":%d,\"outcome\":%s,\"payload\":%s,\"single_flight\":1,\"next\":%s}"
                                    (esc event) task.id (esc task.driver) (esc task.status) (replayQueueDepth()) (esc outcome) (esc task.payload) (esc next))
                            let mutable parentReplayPreservedBlocked = false
                            let mutable parentReplayPreservedBlockedKey = ""
                            if task.status = "scheduled_parent_replay" then
                                let parentReplayPreservedCount, parentReplayPreservedKey = noteParentReplayPreserved task cellOpt
                                DiagJson.emit (
                                    sprintf "{\"kind\":\"eval_worklist_parent_replay_status_preserved\",\"event\":%s,\"replay_id\":%d,\"driver\":%s,\"queue_depth\":%d,\"repeat_count\":%d,\"repeat_cap\":%d,\"repeat_key\":%s,\"single_flight\":1,\"next\":\"defer_same_kind_child_cell\"}"
                                        (esc event) task.id (esc task.driver) (replayQueueDepth()) parentReplayPreservedCount parent_replay_preserved_repeat_cap (esc parentReplayPreservedKey))
                                if parentReplayPreservedCount >= parent_replay_preserved_repeat_cap then
                                    parentReplayPreservedBlocked <- true
                                    parentReplayPreservedBlockedKey <- parentReplayPreservedKey
                                    match cellOpt with
                                    | Some parentCell ->
                                        let blockedCell = { parentCell with status = "semantic_parent_replay_status_preserved_repeat_blocked" }
                                        pinTerminalCell event ("parent_replay_status_preserved_repeat:" + parentReplayPreservedKey) blockedCell
                                        DiagJson.emit (
                                            sprintf "{\"kind\":\"eval_worklist_parent_replay_status_preserved_repeat_blocked\",\"event\":%s,\"replay_id\":%d,\"driver\":%s,\"cell\":%s,\"repeat_count\":%d,\"repeat_cap\":%d,\"repeat_key\":%s,\"queue_depth\":%d,\"single_flight\":1,\"next\":\"explicit_eval_worklist_parent_replay_status_preserved_required\"}"
                                                (esc event) task.id (esc task.driver) (esc (formatCell blockedCell)) parentReplayPreservedCount parent_replay_preserved_repeat_cap (esc parentReplayPreservedKey) (replayQueueDepth()))
                                    | None ->
                                        DiagJson.emit (
                                            sprintf "{\"kind\":\"eval_worklist_parent_replay_status_preserved_repeat_missing_cell\",\"event\":%s,\"replay_id\":%d,\"driver\":%s,\"repeat_count\":%d,\"repeat_cap\":%d,\"repeat_key\":%s,\"queue_depth\":%d,\"single_flight\":1,\"next\":\"explicit_eval_worklist_parent_replay_status_preserved_required\"}"
                                                (esc event) task.id (esc task.driver) parentReplayPreservedCount parent_replay_preserved_repeat_cap (esc parentReplayPreservedKey) (replayQueueDepth()))
                            if payloadHydrated then
                                DiagJson.emit (
                                    sprintf "{\"kind\":\"eval_worklist_replay_payload_cell_hydrated\",\"event\":%s,\"replay_id\":%d,\"driver\":%s,\"status\":%s,\"cell\":%s,\"queue_depth\":%d,\"single_flight\":1,\"next\":\"execute_typed_replay_cell\"}"
                                        (esc event) task.id (esc task.driver) (esc task.status) (esc (match cellOpt with | Some c -> formatCell c | None -> "none")) (replayQueueDepth()))
                            if sameNodeSiteDriftReplayIdentity then
                                DiagJson.emit (
                                    sprintf "{\"kind\":\"eval_worklist_replay_same_node_site_drift_preserved\",\"event\":%s,\"replay_id\":%d,\"driver\":%s,\"status\":%s,\"task_cell\":%s,\"frontier_cell\":%s,\"queue_depth\":%d,\"pending\":%d,\"policy\":\"same_node_progressed_replay_identity_survives_site_alias\",\"single_flight\":1,\"next\":\"execute_progressed_replay_cell\"}"
                                        (esc event) task.id (esc task.driver) (esc task.status)
                                        (esc taskPayloadCellText)
                                        (esc frontierPayloadCellText)
                                        (replayQueueDepth()) (pendingCount()))
                            if preferTaskPayloadOverStaleFrontier then
                                DiagJson.emit (
                                    sprintf "{\"kind\":\"eval_worklist_replay_payload_preferred_over_stale_frontier\",\"event\":%s,\"replay_id\":%d,\"driver\":%s,\"status\":%s,\"task_cell\":%s,\"frontier_cell\":%s,\"queue_depth\":%d,\"pending\":%d,\"single_flight\":1,\"next\":\"execute_payload_replay_cell\"}"
                                        (esc event) task.id (esc task.driver) (esc task.status)
                                        (esc taskPayloadCellText)
                                        (esc frontierPayloadCellText)
                                        (replayQueueDepth()) (pendingCount()))
                            if preferTaskPayloadOverRepeatFrontier then
                                DiagJson.emit (
                                    sprintf "{\"kind\":\"eval_worklist_replay_payload_preferred_over_repeat_frontier\",\"event\":%s,\"replay_id\":%d,\"driver\":%s,\"status\":%s,\"cell\":%s,\"queue_depth\":%d,\"pending\":%d,\"single_flight\":1,\"next\":\"execute_payload_replay_cell\"}"
                                        (esc event) task.id (esc task.driver) (esc task.status) (esc (match cellOpt with | Some c -> formatCell c | None -> "none")) (replayQueueDepth()) (pendingCount()))
                            match cellOpt with
                            | Some cell when parentReplayPreservedBlocked ->
                                let blockedCell = { cell with status = "semantic_parent_replay_status_preserved_repeat_blocked" }
                                lock gate (fun () ->
                                    replayQueue <- replayQueue |> List.filter (fun t -> t.id <> task.id)
                                    if replayQueue.IsEmpty then replayScheduledKey <- None
                                    match frontier with
                                    | Some frame ->
                                        let frame' = { frame with status = blockedCell.status; semanticCell = Some blockedCell; semanticPayload = Some (formatCellPayload blockedCell) }
                                        frontier <- Some frame'
                                        slotSetLocked frame'
                                    | None -> ())
                                DiagJson.emit (
                                    sprintf "{\"kind\":\"eval_worklist_parent_replay_status_preserved_repeat_terminal_handoff\",\"event\":%s,\"replay_id\":%d,\"driver\":%s,\"cell\":%s,\"repeat_key\":%s,\"queue_depth\":%d,\"single_flight\":1,\"next\":\"explicit_eval_worklist_parent_replay_status_preserved_required\"}"
                                        (esc event) task.id (esc task.driver) (esc (formatCell blockedCell)) (esc parentReplayPreservedBlockedKey) (replayQueueDepth()))
                            | Some cell ->
                                let cursorNow = (match frontier with Some f -> f.cursor | None -> cell.cursor)
                                let parentResumed =
                                    cell.status = "parent_continuation_ready"
                                    || task.status = "scheduled_parent_replay"
                                    || task.key.Contains("|parent|")
                                let letSuccessReducerReplay =
                                    cell.kind = "term"
                                    && cell.shape = "EApply"
                                    && cell.status = "let_success_ready"
                                let replayStepperStatus = if letSuccessReducerReplay then "let_success_ready" else "stepper_ready"
                                let cellReady = { cell with cursor = cursorNow; step = cell.step + 1; status = replayStepperStatus }
                                if letSuccessReducerReplay then
                                    DiagJson.emit (
                                        sprintf "{\"kind\":\"eval_worklist_let_success_status_preserved_for_reducer\",\"event\":%s,\"replay_id\":%d,\"driver\":%s,\"cell\":%s,\"queue_depth\":%d,\"pending\":%d,\"single_flight\":1,\"next\":\"execute_let_success_reducer_guard\"}"
                                            (esc event) task.id (esc task.driver) (esc (formatCell cellReady)) (replayQueueDepth()) (pendingCount()))
                                let continueToParent (childCell: ReplayCell) (outcome: string) =
                                    match EvalReplayValueStore.tryParentContinuation childCell.nodeId with
                                    | Some cont ->
                                        let edgeCount = EvalReplayValueStore.noteParentContinuationEdge childCell.kind childCell.shape childCell.nodeId cont
                                        if edgeCount > 8 then
                                            let tryLetSelfCycleEscape () =
                                                if childCell.kind = "term"
                                                   && childCell.shape = "ELet" then
                                                    match EvalReplayValueStore.tryLetSpine childCell.nodeId with
                                                    | Some spine ->
                                                        let missingBody =
                                                            spine.bodyNodeIds
                                                            |> Array.mapi (fun i nodeId -> i, nodeId)
                                                            |> Array.tryFind (fun (_, nodeId) -> not (EvalReplayValueStore.tryTermReady nodeId))
                                                        match missingBody with
                                                        | Some (i, nodeId) ->
                                                            let shape = if i < spine.bodyShapes.Length then spine.bodyShapes.[i] else "unknown"
                                                            let bodyCell = { childCell with kind = "term"; shape = shape; nodeId = nodeId; status = "let_body_ready" }
                                                            DiagJson.emit (
                                                                sprintf "{\"kind\":\"eval_worklist_parent_cycle_let_self_escape\",\"event\":%s,\"child\":%s,\"parent_kind\":%s,\"parent_shape\":%s,\"parent_node_id\":%d,\"role\":%s,\"escape\":\"schedule_missing_body\",\"cell\":%s,\"single_flight\":1,\"next\":\"schedule_let_body_replay\"}"
                                                                    (esc event) (esc (formatCell childCell)) (esc cont.parentKind) (esc cont.parentShape) cont.parentNodeId (esc cont.role) (esc (formatCell bodyCell)))
                                                            Some(outcome + "_let_self_cycle_missing_body_scheduled:" + cont.role, "semantic_step_partial", "schedule_let_body_replay", bodyCell)
                                                        | None when not (EvalReplayValueStore.tryTermReady spine.successNodeId) ->
                                                            let succCell = { childCell with kind = "term"; shape = spine.successShape; nodeId = spine.successNodeId; status = "let_success_ready" }
                                                            DiagJson.emit (
                                                                sprintf "{\"kind\":\"eval_worklist_parent_cycle_let_self_escape\",\"event\":%s,\"child\":%s,\"parent_kind\":%s,\"parent_shape\":%s,\"parent_node_id\":%d,\"role\":%s,\"escape\":\"schedule_success\",\"cell\":%s,\"single_flight\":1,\"next\":\"schedule_let_success_replay\"}"
                                                                    (esc event) (esc (formatCell childCell)) (esc cont.parentKind) (esc cont.parentShape) cont.parentNodeId (esc cont.role) (esc (formatCell succCell)))
                                                            Some(outcome + "_let_self_cycle_success_scheduled:" + cont.role, "semantic_step_partial", "schedule_let_success_replay", succCell)
                                                        | None ->
                                                            match EvalReplayValueStore.tryTermDetailed childCell.nodeId with
                                                            | Choice1Of2 value ->
                                                                EvalReplayValueStore.putTermValue childCell.nodeId value
                                                                let parentCell = { childCell with kind = cont.parentKind; shape = cont.parentShape; nodeId = cont.parentNodeId; status = "parent_continuation_ready" }
                                                                DiagJson.emit (
                                                                    sprintf "{\"kind\":\"eval_worklist_parent_cycle_let_self_escape\",\"event\":%s,\"child\":%s,\"parent_kind\":%s,\"parent_shape\":%s,\"parent_node_id\":%d,\"role\":%s,\"escape\":\"resolved_parent\",\"cell\":%s,\"single_flight\":1,\"next\":\"resume_parent_replay_driver\"}"
                                                                        (esc event) (esc (formatCell childCell)) (esc cont.parentKind) (esc cont.parentShape) cont.parentNodeId (esc cont.role) (esc (formatCell parentCell)))
                                                                Some(outcome + "_let_self_cycle_value_resolved:" + cont.role, "semantic_step_partial", "resume_parent_replay_driver", parentCell)
                                                            | Choice2Of2 _ -> None
                                                    | None -> None
                                                else None
                                            let tryLetBodyCycleEscape () =
                                                // ALPHA1043: completed let bodies are not restricted to EApply; alpha1042
                                                // reached backend.spi:2 only after a long stall before scheduling an EAnnot success child.
                                                if childCell.kind = "term"
                                                   && cont.parentKind = "term"
                                                   && cont.parentShape = "ELet"
                                                   && cont.role.StartsWith("let_body_", StringComparison.Ordinal)
                                                   && EvalReplayValueStore.tryTermReady childCell.nodeId then
                                                    match EvalReplayValueStore.tryLetSpine cont.parentNodeId with
                                                    | Some spine ->
                                                        let missingBody =
                                                            spine.bodyNodeIds
                                                            |> Array.mapi (fun i nodeId -> i, nodeId)
                                                            |> Array.tryFind (fun (_, nodeId) -> not (EvalReplayValueStore.tryTermReady nodeId))
                                                        match missingBody with
                                                        | Some (i, nodeId) ->
                                                            let shape = if i < spine.bodyShapes.Length then spine.bodyShapes.[i] else "unknown"
                                                            let bodyCell = { childCell with kind = "term"; shape = shape; nodeId = nodeId; status = "let_body_ready" }
                                                            DiagJson.emit (
                                                                sprintf "{\"kind\":\"eval_worklist_parent_cycle_let_escape\",\"event\":%s,\"child\":%s,\"parent_kind\":%s,\"parent_shape\":%s,\"parent_node_id\":%d,\"role\":%s,\"escape\":\"schedule_missing_body\",\"cell\":%s,\"single_flight\":1,\"next\":\"schedule_let_body_replay\"}"
                                                                    (esc event) (esc (formatCell childCell)) (esc cont.parentKind) (esc cont.parentShape) cont.parentNodeId (esc cont.role) (esc (formatCell bodyCell)))
                                                            Some(outcome + "_let_body_cycle_missing_body_scheduled:" + cont.role, "semantic_step_partial", "schedule_let_body_replay", bodyCell)
                                                        | None when not (EvalReplayValueStore.tryTermReady spine.successNodeId) ->
                                                            let succCell = { childCell with kind = "term"; shape = spine.successShape; nodeId = spine.successNodeId; status = "let_success_ready" }
                                                            DiagJson.emit (
                                                                sprintf "{\"kind\":\"eval_worklist_parent_cycle_let_escape\",\"event\":%s,\"child\":%s,\"parent_kind\":%s,\"parent_shape\":%s,\"parent_node_id\":%d,\"role\":%s,\"escape\":\"schedule_success\",\"cell\":%s,\"single_flight\":1,\"next\":\"schedule_let_success_replay\"}"
                                                                    (esc event) (esc (formatCell childCell)) (esc cont.parentKind) (esc cont.parentShape) cont.parentNodeId (esc cont.role) (esc (formatCell succCell)))
                                                            Some(outcome + "_let_body_cycle_success_scheduled:" + cont.role, "semantic_step_partial", "schedule_let_success_replay", succCell)
                                                        | None ->
                                                            let parentCell = { childCell with kind = cont.parentKind; shape = cont.parentShape; nodeId = cont.parentNodeId; status = "parent_continuation_ready" }
                                                            DiagJson.emit (
                                                                sprintf "{\"kind\":\"eval_worklist_parent_cycle_let_escape\",\"event\":%s,\"child\":%s,\"parent_kind\":%s,\"parent_shape\":%s,\"parent_node_id\":%d,\"role\":%s,\"escape\":\"retry_parent_once\",\"cell\":%s,\"single_flight\":1,\"next\":\"resume_parent_replay_driver\"}"
