                                        | Choice2Of2 detail ->
                                            match EvalReplayValueStore.tryAnnotTestSpine cellReady.nodeId with
                                            | Some spine ->
                                                match EvalReplayValueStore.tryTypeDetailed spine.typeNodeId with
