                                            let childRole = "tterm_term_child"
                                            let childKey = sprintf "%s|%s|%d|%d" task.key childRole cellCommitted.nodeId cellCommitted.step
                                            let childTask = { id = replaySeq; key = childKey; driver = "term_replay_driver"; payload = formatCellPayload cellCommitted; status = "scheduled_replay"; event = event }
                                            replayScheduledKey <- Some childKey
                                            replayQueue <- [childTask]
                                        elif shouldScheduleTFunChild then
                                            replaySeq <- replaySeq + 1L
                                            let childRole =
                                                if replayCell.status = "tfun_arg_ready" || cellReduced.status = "tfun_arg_dispatched" then "tfun_arg_child"
                                                else "tfun_body_child"
                                            let childKey = sprintf "%s|%s|%d|%d" task.key childRole cellCommitted.nodeId cellCommitted.step
                                            let childTask = { id = replaySeq; key = childKey; driver = "ty_replay_driver"; payload = formatCellPayload cellCommitted; status = "scheduled_replay"; event = event }
                                            replayScheduledKey <- Some childKey
                                            replayQueue <- [childTask]
                                        elif shouldScheduleTPairChild then
                                            replaySeq <- replaySeq + 1L
                                            let childRole =
                                                if replayCell.status = "tpair_left_ready" || cellReduced.status = "tpair_left_dispatched" then "tpair_left_child"
                                                else "tpair_right_child"
                                            let childKey = sprintf "%s|%s|%d|%d" task.key childRole cellCommitted.nodeId cellCommitted.step
                                            let childTask = { id = replaySeq; key = childKey; driver = "ty_replay_driver"; payload = formatCellPayload cellCommitted; status = "scheduled_replay"; event = event }
                                            replayScheduledKey <- Some childKey
                                            replayQueue <- [childTask]
                                        elif shouldScheduleDeferredChild then
                                            replaySeq <- replaySeq + 1L
                                            let childDriver = if cellCommitted.kind = "ty" then "ty_replay_driver" else "term_replay_driver"
                                            let childKey = sprintf "%s|deferred_%s_child|%d|%d" task.key cellCommitted.kind cellCommitted.nodeId cellCommitted.step
                                            let childTask = { id = replaySeq; key = childKey; driver = childDriver; payload = formatCellPayload cellCommitted; status = "scheduled_replay"; event = event }
                                            replayScheduledKey <- Some childKey
                                            replayQueue <- [childTask]
                                        elif shouldScheduleRecordWithChild then
                                            replaySeq <- replaySeq + 1L
                                            let childKey = sprintf "%s|record_with_child|%d|%d" task.key cellCommitted.nodeId cellCommitted.step
                                            let childTask = { id = replaySeq; key = childKey; driver = task.driver; payload = formatCellPayload cellCommitted; status = "scheduled_replay"; event = event }
                                            replayScheduledKey <- Some childKey
                                            replayQueue <- [childTask]
                                        elif shouldScheduleMacroChild then
                                            replaySeq <- replaySeq + 1L
                                            let childDriver = if cellCommitted.kind = "ty" then "ty_replay_driver" else "term_replay_driver"
                                            let childKey = sprintf "%s|macro_child|%d|%d" task.key cellCommitted.nodeId cellCommitted.step
                                            let childTask = { id = replaySeq; key = childKey; driver = childDriver; payload = formatCellPayload cellCommitted; status = "scheduled_replay"; event = event }
                                            replayScheduledKey <- Some childKey
                                            replayQueue <- [childTask]
                                        elif shouldScheduleSeqChild then
                                            replaySeq <- replaySeq + 1L
                                            let childKey = sprintf "%s|seq_child|%d|%d" task.key cellCommitted.nodeId cellCommitted.step
                                            let childTask = { id = replaySeq; key = childKey; driver = task.driver; payload = formatCellPayload cellCommitted; status = "scheduled_replay"; event = event }
                                            replayScheduledKey <- Some childKey
                                            replayQueue <- [childTask]
                                        elif shouldSchedulePairChild then
                                            replaySeq <- replaySeq + 1L
                                            let childRole =
                                                if replayCell.status = "pair_left_ready" || cellReduced.status = "pair_left_dispatched" then "pair_left_child"
                                                else "pair_right_child"
                                            let childKey = sprintf "%s|%s|%d|%d" task.key childRole cellCommitted.nodeId cellCommitted.step
                                            let childTask = { id = replaySeq; key = childKey; driver = "term_replay_driver"; payload = formatCellPayload cellCommitted; status = "scheduled_replay"; event = event }
                                            replayScheduledKey <- Some childKey
                                            replayQueue <- [childTask]
                                        elif shouldScheduleLetChild then
                                            replaySeq <- replaySeq + 1L
                                            let childRole =
                                                if commitNext = "schedule_let_success_replay" then "let_success_child"
                                                else "let_body_child"
                                            let childDriver = if cellCommitted.kind = "ty" then "ty_replay_driver" else "term_replay_driver"
                                            let childKey = sprintf "%s|%s|%d|%d" task.key childRole cellCommitted.nodeId cellCommitted.step
                                            let childTask = { id = replaySeq; key = childKey; driver = childDriver; payload = formatCellPayload cellCommitted; status = "scheduled_replay"; event = event }
                                            replayScheduledKey <- Some childKey
                                            replayQueue <- [childTask]
                                        replayQueue.Length)
                                // ALPHA434: materialize terminal root-complete term values into the
                                // source-key cache from the replay driver itself.  Alpha433 proved the
                                // final EApply at spiral.spi:2671 reaches semantic_root_complete, but only
                                // earlier EV/EForall nodes were stored by term_entry_global_fuse.  Store the
                                // committed root term too, so the next evaluator pass can return through the
                                // source-key preflight instead of repeating the same stable handoff.
                                if commitStatus = "semantic_root_complete" && cellCommitted.kind = "term" then
                                    match EvalReplayValueStore.tryTerm cellCommitted.nodeId with
                                    | Some value ->
                                        let sourceKey =
                                            EvalReplayValueStore.termSourceKey
                                                cellCommitted.site
                                                cellCommitted.shape
                                                cellCommitted.envGlobalTerm
                                                cellCommitted.envStackTerm
                                                cellCommitted.envGlobalType
                                                cellCommitted.envStackType
                                                cellCommitted.traceDepth
                                        EvalReplayValueStore.putTermSourceValue sourceKey value
                                        let sourceStoreRepeat =
                                            jp_note_source_value_store (sprintf "term|%s|driver_root_complete_store|%s|%s" event cellCommitted.shape sourceKey)
                                        if jp_should_emit_source_value_store sourceStoreRepeat then
                                            DiagJson.emit (
                                                sprintf "{\"kind\":\"eval_worklist_source_value_stored\",\"event\":%s,\"status\":\"semantic_root_complete\",\"shape\":%s,\"source_key\":%s,\"policy\":\"driver_root_complete_store\",\"repeat_count\":%d,\"sampled\":1,\"single_flight\":1,\"next\":\"return_term_value\"}"
                                                    (esc event) (esc cellCommitted.shape) (esc sourceKey) sourceStoreRepeat)
                                        // ALPHA929: driver-root stores are real semantic progress.
                                        // Runtime 928 made hundreds of root-complete replay returns but
                                        // jp_last_progress_ms stayed stale, so the JP watchdog killed a
                                        // live drain.  Refresh only the scheduler heartbeat; do not
                                        // synthesize a value, continuation, writer result, root proof,
                                        // codegen result, or BuildOk.
                                        jp_mark_progress ()
                                        DiagJson.emit (
                                            sprintf "{\"kind\":\"eval_worklist_root_complete_replay_progress_marked\",\"event\":%s,\"scope\":\"driver_root_store\",\"status\":\"semantic_root_complete\",\"kind2\":%s,\"shape\":%s,\"site\":%s,\"single_flight\":1,\"next\":\"watchdog_progress_refreshed\"}"
                                                (esc event) (esc cellCommitted.kind) (esc cellCommitted.shape) (esc cellCommitted.site))
                                        let clearedTypeTerminal = clearTerminalContractIf "semantic_term_type_value_blocked" "" ""
                                        if clearedTypeTerminal then
                                            DiagJson.emit (
                                                sprintf "{\"kind\":\"eval_worklist_root_complete_term_type_terminal_cleared\",\"event\":%s,\"source_key\":%s,\"site\":%s,\"shape\":%s,\"policy\":\"root_complete_progress_clears_stale_term_type_terminal\",\"single_flight\":1,\"next\":\"continue_replay_after_root_complete\"}"
                                                    (esc event) (esc sourceKey) (esc cellCommitted.site) (esc cellCommitted.shape))
                                    | None -> ()
                                // ALPHA577: persist completed type roots under the same
                                // conservative source/environment key shape used by term
                                // roots, so a later ty_entry_global_fuse can return the
                                // proven Ty instead of rehydrating stale TV children.
                                if commitStatus = "semantic_root_complete" && cellCommitted.kind = "ty" then
                                    match EvalReplayValueStore.tryType cellCommitted.nodeId with
                                    | Some value ->
                                        let sourceKey =
                                            EvalReplayValueStore.typeSourceKey
                                                cellCommitted.site
                                                cellCommitted.shape
                                                cellCommitted.envGlobalTerm
                                                cellCommitted.envStackTerm
                                                cellCommitted.envGlobalType
                                                cellCommitted.envStackType
                                                cellCommitted.traceDepth
                                        EvalReplayValueStore.putTypeSourceValue sourceKey value
                                        let sourceStoreRepeat =
                                            jp_note_source_value_store (sprintf "ty|%s|driver_root_complete_store|%s|%s" event cellCommitted.shape sourceKey)
                                        if jp_should_emit_source_value_store sourceStoreRepeat then
                                            DiagJson.emit (
                                                sprintf "{\"kind\":\"eval_worklist_type_source_value_stored\",\"event\":%s,\"status\":\"semantic_root_complete\",\"shape\":%s,\"source_key\":%s,\"policy\":\"driver_root_complete_store\",\"repeat_count\":%d,\"sampled\":1,\"single_flight\":1,\"next\":\"return_ty_value\"}"
                                                    (esc event) (esc cellCommitted.shape) (esc sourceKey) sourceStoreRepeat)
                                        // ALPHA929: type-root stores also prove semantic movement for the JP watchdog.
                                        jp_mark_progress ()
                                        DiagJson.emit (
                                            sprintf "{\"kind\":\"eval_worklist_root_complete_replay_progress_marked\",\"event\":%s,\"scope\":\"driver_root_store\",\"status\":\"semantic_root_complete\",\"kind2\":%s,\"shape\":%s,\"site\":%s,\"single_flight\":1,\"next\":\"watchdog_progress_refreshed\"}"
                                                (esc event) (esc cellCommitted.kind) (esc cellCommitted.shape) (esc cellCommitted.site))
                                        let clearedTypeTerminal = clearTerminalContractIf "semantic_term_type_value_blocked" "" ""
                                        if clearedTypeTerminal then
                                            DiagJson.emit (
                                                sprintf "{\"kind\":\"eval_worklist_root_complete_term_type_terminal_cleared\",\"event\":%s,\"source_key\":%s,\"site\":%s,\"shape\":%s,\"policy\":\"root_complete_progress_clears_stale_term_type_terminal\",\"single_flight\":1,\"next\":\"continue_replay_after_root_complete\"}"
                                                    (esc event) (esc sourceKey) (esc cellCommitted.site) (esc cellCommitted.shape))
                                    | None -> ()
                                DiagJson.emit (
                                    sprintf "{\"kind\":\"eval_worklist_replay_step\",\"event\":%s,\"replay_id\":%d,\"driver\":%s,\"cell\":%s,\"outcome\":\"typed_cell_ready\",\"single_flight\":1,\"next\":%s}"
                                        (esc event) task.id (esc task.driver) (esc (formatCell cellReady)) (esc next))
                                DiagJson.emit (
                                    sprintf "{\"kind\":\"eval_worklist_replay_reduce\",\"event\":%s,\"replay_id\":%d,\"driver\":%s,\"cell\":%s,\"outcome\":%s,\"single_flight\":1,\"next\":\"commit_replay_step\"}"
                                        (esc event) task.id (esc task.driver) (esc (formatCell cellReduced)) (esc reduceOutcome))
                                DiagJson.emit (
                                    sprintf "{\"kind\":\"eval_worklist_replay_commit\",\"event\":%s,\"replay_id\":%d,\"driver\":%s,\"cell\":%s,\"outcome\":%s,\"queue_depth\":%d,\"single_flight\":1,\"next\":%s}"
                                        (esc event) task.id (esc task.driver) (esc (formatCell cellCommitted)) (esc commitStatus) remainingQueue (esc commitNext))
                                if replayJoinpointTermRepeat then
                                    DiagJson.emit (
                                        sprintf "{\"kind\":\"eval_worklist_joinpoint_term_stepper_blocked\",\"event\":%s,\"replay_id\":%d,\"driver\":%s,\"repeat_count\":%d,\"fingerprint\":%s,\"cell\":%s,\"outcome\":%s,\"pending\":%d,\"single_flight\":1,\"next\":\"explicit_eval_worklist_joinpoint_term_stepper_required\"}"
                                            (esc event) task.id (esc task.driver) replayFingerprintRepeatCount (esc replayFingerprintKey) (esc (formatCell cellCommitted)) (esc reduceOutcome) (pendingCount()))
                                if smReal289PairTestFingerprintDemote then
                                    DiagJson.emit (
                                        sprintf "{\"kind\":\"eval_worklist_smreal289_pairtest_fingerprint_repeat_demoted\",\"event\":%s,\"replay_id\":%d,\"driver\":%s,\"repeat_count\":%d,\"fingerprint\":%s,\"cell\":%s,\"outcome\":%s,\"pending\":%d,\"policy\":\"preserve_testing_frontier_over_stale_pairtest_repeat\",\"single_flight\":1,\"next\":%s}"
                                            (esc event) task.id (esc task.driver) replayFingerprintRepeatCount (esc replayFingerprintKey) (esc (formatCell cellCommitted)) (esc reduceOutcome) (pendingCount()) (esc commitNext))
                                if replayFingerprintRepeat && not replayJoinpointTermRepeat then
                                    DiagJson.emit (
                                        sprintf "{\"kind\":\"eval_worklist_replay_fingerprint_repeat\",\"event\":%s,\"replay_id\":%d,\"driver\":%s,\"repeat_count\":%d,\"fingerprint\":%s,\"cell\":%s,\"outcome\":%s,\"pending\":%d,\"single_flight\":1,\"next\":\"explicit_eval_worklist_replay_fingerprint_repeat_required\"}"
                                            (esc event) task.id (esc task.driver) replayFingerprintRepeatCount (esc replayFingerprintKey) (esc (formatCell cellCommitted)) (esc reduceOutcome) (pendingCount()))
                                if shouldResumeParent then
                                    if parentResumeDriverRerouted then
                                        DiagJson.emit (
                                            sprintf "{\"kind\":\"eval_worklist_cross_kind_parent_resume_driver_rerouted\",\"event\":%s,\"from_driver\":%s,\"to_driver\":%s,\"cell_kind\":%s,\"cell_shape\":%s,\"cell_site\":%s,\"cell_node_id\":%d,\"queue_depth\":%d,\"single_flight\":1,\"next\":%s}"
                                                (esc event) (esc task.driver) (esc parentResumeDriver) (esc cellCommitted.kind) (esc cellCommitted.shape) (esc cellCommitted.site) cellCommitted.nodeId (replayQueueDepth()) (esc parentResumeDriver))
                                    DiagJson.emit (
                                        sprintf "{\"kind\":\"eval_worklist_parent_resume\",\"event\":%s,\"driver\":%s,\"prior_driver\":%s,\"cell\":%s,\"queue_depth\":%d,\"single_flight\":1,\"next\":%s}"
                                            (esc event) (esc parentResumeDriver) (esc task.driver) (esc (formatCell cellCommitted)) (replayQueueDepth()) (esc parentResumeDriver))
                                    scheduleReplayDriverTick "cooperative_replay_handoff" event
                                elif shouldScheduleApplyChild then
                                    let childRole =
                                        if commitNext = "schedule_apply_head_replay" then "apply_head_child"
                                        else "apply_arg_child"
                                    let childDriver = "term_replay_driver"
                                    DiagJson.emit (
                                        sprintf "{\"kind\":\"eval_worklist_apply_child_replay_scheduled\",\"event\":%s,\"driver\":%s,\"role\":%s,\"cell\":%s,\"queue_depth\":%d,\"single_flight\":1,\"next\":\"term_replay_driver\"}"
                                            (esc event) (esc childDriver) (esc childRole) (esc (formatCell cellCommitted)) (replayQueueDepth()))
                                    scheduleReplayDriverTick "cooperative_replay_handoff" event
                                elif shouldScheduleTypeApplyChild then
                                    let childRole =
                                        if commitNext = "schedule_type_apply_type_arg_replay" then "type_apply_type_arg_child"
                                        else "type_apply_function_child"
                                    let childDriver =
                                        if commitNext = "schedule_type_apply_type_arg_replay" then "ty_replay_driver"
                                        else "term_replay_driver"
                                    let childNext =
                                        if commitNext = "schedule_type_apply_type_arg_replay" then "ty_replay_driver"
                                        else "term_replay_driver"
                                    DiagJson.emit (
                                        sprintf "{\"kind\":\"eval_worklist_type_apply_child_replay_scheduled\",\"event\":%s,\"driver\":%s,\"role\":%s,\"cell\":%s,\"queue_depth\":%d,\"single_flight\":1,\"next\":%s}"
                                            (esc event) (esc childDriver) (esc childRole) (esc (formatCell cellCommitted)) (replayQueueDepth()) (esc childNext))
                                    scheduleReplayDriverTick "cooperative_replay_handoff" event
                                elif shouldScheduleTypeAwareOpChild then
                                    DiagJson.emit (
                                        sprintf "{\"kind\":\"eval_worklist_type_aware_op_child_replay_enqueued\",\"event\":%s,\"driver\":\"term_replay_driver\",\"role\":\"type_aware_op_child\",\"cell\":%s,\"queue_depth\":%d,\"single_flight\":1,\"next\":\"term_replay_driver\"}"
                                            (esc event) (esc (formatCell cellCommitted)) (replayQueueDepth()))
                                    scheduleReplayDriverTick "cooperative_replay_handoff" event
                                elif shouldScheduleTTermChild then
                                    DiagJson.emit (
                                        sprintf "{\"kind\":\"eval_worklist_tterm_child_replay_scheduled\",\"event\":%s,\"driver\":\"term_replay_driver\",\"role\":\"tterm_term_child\",\"cell\":%s,\"queue_depth\":%d,\"single_flight\":1,\"next\":\"term_replay_driver\"}"
                                            (esc event) (esc (formatCell cellCommitted)) (replayQueueDepth()))
                                    scheduleReplayDriverTick "cooperative_replay_handoff" event
                                elif shouldScheduleTFunChild then
                                    let childRole =
                                        if replayCell.status = "tfun_arg_ready" || cellReduced.status = "tfun_arg_dispatched" then "tfun_arg_child"
                                        else "tfun_body_child"
                                    DiagJson.emit (
                                        sprintf "{\"kind\":\"eval_worklist_tfun_child_replay_scheduled\",\"event\":%s,\"driver\":\"ty_replay_driver\",\"role\":%s,\"cell\":%s,\"queue_depth\":%d,\"single_flight\":1,\"next\":\"ty_replay_driver\"}"
                                            (esc event) (esc childRole) (esc (formatCell cellCommitted)) (replayQueueDepth()))
                                    scheduleReplayDriverTick "cooperative_replay_handoff" event
                                elif shouldScheduleTPairChild then
                                    let childRole =
                                        if replayCell.status = "tpair_left_ready" || cellReduced.status = "tpair_left_dispatched" then "tpair_left_child"
                                        else "tpair_right_child"
                                    DiagJson.emit (
                                        sprintf "{\"kind\":\"eval_worklist_tpair_child_replay_scheduled\",\"event\":%s,\"driver\":\"ty_replay_driver\",\"role\":%s,\"cell\":%s,\"queue_depth\":%d,\"single_flight\":1,\"next\":\"ty_replay_driver\"}"
                                            (esc event) (esc childRole) (esc (formatCell cellCommitted)) (replayQueueDepth()))
                                    scheduleReplayDriverTick "cooperative_replay_handoff" event
                                elif shouldScheduleDeferredChild then
                                    let childDriver = if cellCommitted.kind = "ty" then "ty_replay_driver" else "term_replay_driver"
                                    DiagJson.emit (
                                        sprintf "{\"kind\":\"eval_worklist_deferred_child_replay_scheduled\",\"event\":%s,\"driver\":%s,\"role\":\"deferred_replay_child\",\"cell\":%s,\"queue_depth\":%d,\"single_flight\":1,\"next\":%s}"
                                            (esc event) (esc childDriver) (esc (formatCell cellCommitted)) (replayQueueDepth()) (esc childDriver))
                                    scheduleReplayDriverTick "cooperative_replay_handoff" event
                                elif shouldScheduleRecordWithChild then
                                    DiagJson.emit (
                                        sprintf "{\"kind\":\"eval_worklist_record_with_child_replay_scheduled\",\"event\":%s,\"driver\":%s,\"cell\":%s,\"queue_depth\":%d,\"single_flight\":1,\"next\":\"term_replay_driver\"}"
                                            (esc event) (esc task.driver) (esc (formatCell cellCommitted)) (replayQueueDepth()))
                                    scheduleReplayDriverTick "cooperative_replay_handoff" event
                                elif shouldScheduleMacroChild then
                                    let childDriver = if cellCommitted.kind = "ty" then "ty_replay_driver" else "term_replay_driver"
                                    DiagJson.emit (
                                        sprintf "{\"kind\":\"eval_worklist_macro_child_replay_scheduled\",\"event\":%s,\"driver\":%s,\"cell\":%s,\"queue_depth\":%d,\"single_flight\":1,\"next\":%s}"
                                            (esc event) (esc childDriver) (esc (formatCell cellCommitted)) (replayQueueDepth()) (esc childDriver))
                                    scheduleReplayDriverTick "cooperative_replay_handoff" event
                                elif shouldScheduleSeqChild then
                                    DiagJson.emit (
                                        sprintf "{\"kind\":\"eval_worklist_seq_child_replay_scheduled\",\"event\":%s,\"driver\":%s,\"cell\":%s,\"queue_depth\":%d,\"single_flight\":1,\"next\":\"term_replay_driver\"}"
                                            (esc event) (esc task.driver) (esc (formatCell cellCommitted)) (replayQueueDepth()))
                                    scheduleReplayDriverTick "cooperative_replay_handoff" event
                                elif shouldSchedulePairChild then
                                    let childRole =
                                        if replayCell.status = "pair_left_ready" || cellReduced.status = "pair_left_dispatched" then "pair_left_child"
                                        else "pair_right_child"
                                    DiagJson.emit (
                                        sprintf "{\"kind\":\"eval_worklist_pair_child_replay_scheduled\",\"event\":%s,\"driver\":\"term_replay_driver\",\"role\":%s,\"cell\":%s,\"queue_depth\":%d,\"single_flight\":1,\"next\":\"term_replay_driver\"}"
                                            (esc event) (esc childRole) (esc (formatCell cellCommitted)) (replayQueueDepth()))
                                    scheduleReplayDriverTick "cooperative_replay_handoff" event
                                elif shouldScheduleLetChild then
                                    let childRole =
                                        if commitNext = "schedule_let_success_replay" then "let_success_child"
                                        else "let_body_child"
                                    let childDriver = if cellCommitted.kind = "ty" then "ty_replay_driver" else "term_replay_driver"
                                    DiagJson.emit (
                                        sprintf "{\"kind\":\"eval_worklist_let_child_replay_scheduled\",\"event\":%s,\"driver\":%s,\"role\":%s,\"cell\":%s,\"queue_depth\":%d,\"single_flight\":1,\"next\":%s}"
                                            (esc event) (esc childDriver) (esc childRole) (esc (formatCell cellCommitted)) (replayQueueDepth()) (esc childDriver))
                                    scheduleReplayDriverTick "cooperative_replay_handoff" event
                            | None -> ()
                        | None ->
                            DiagJson.emit (
                                sprintf "{\"kind\":\"eval_worklist_replay_driver\",\"event\":%s,\"replay_id\":0,\"driver\":\"none\",\"status\":\"empty\",\"queue_depth\":0,\"outcome\":\"no_replay_task\",\"single_flight\":1,\"next\":\"none\"}"
                                    (esc event))
                    with ex ->
                        let nullGuardRepeatCount, nullGuardRepeatKey =
                            if ex :? NullReferenceException then noteReplayNullGuard executingTaskOpt executingCellOpt ex
                            else 0, "not_null_guard"
                        let nullGuardRepeatBlocked = nullGuardRepeatCount >= replay_null_guard_repeat_cap
                        let rootWitnessNullLiveEvidence =
                            (replayQueueDepth() > 0)
                            || (replayDriverActiveDepthValue() > 0)
                            || hasProgressYield()
                            || EvalReplayValueStore.hasDeferredReplayCell()
                        let rootWitnessNullReplayDecision =
                            if ex :? NullReferenceException && hasReplayCompleteWriteWitness() && pendingCount() > 0 then
                                if nullGuardRepeatBlocked && rootWitnessNullLiveEvidence then RootWitnessNullDeferLiveReplay
                                elif nullGuardRepeatBlocked then RootWitnessNullPreserveComplete
                                else RootWitnessNullDeferLiveReplay
                            else RootWitnessNullSurfaceTerminal
                        let rootWitnessNullRepeatCanTerminal =
                            match rootWitnessNullReplayDecision with
                            | RootWitnessNullSurfaceTerminal -> true
                            | RootWitnessNullDeferLiveReplay
                            | RootWitnessNullPreserveComplete -> false
                        let letSuccessDriverNull =
                            ex :? NullReferenceException
                            && (match executingCellOpt with
                                | Some cell -> cell.kind = "term" && cell.shape = "EApply" && cell.status = "let_success_ready"
                                | None -> false)
                        let unitTestReplayDriverNull =
                            ex :? NullReferenceException
                            && (match executingCellOpt with
                                | Some cell ->
                                    cell.kind = "term"
                                    && cell.shape = "EUnitTest"
                                    && (cell.status = "semantic_step_partial"
                                        || cell.status = "unit_test_bind_ready"
                                        || cell.status = "unit_test_branch_ready")
                                | None -> false)
                        let applyContinuationDriverNull =
                            ex :? NullReferenceException
                            && (match executingCellOpt with
                                | Some cell ->
                                    cell.kind = "term"
                                    && ((cell.shape = "EApply"
                                         && (cell.status = "semantic_step_partial"
                                             || cell.status = "let_success_apply_continuation_deferred"
                                             || cell.status = "let_success_apply_continuation_root_witness_deferred"
                                             || cell.status = "apply_continuation_root_witness_null_guarded"
                                             || cell.status = "apply_continuation_root_witness_retry_guarded"))
                                        || (cell.shape = "EUnitTest"
                                            && (cell.status = "semantic_step_partial"
                                                || cell.status = "unit_test_bind_ready"
                                                || cell.status = "unit_test_branch_ready")))
                                | None -> false)
                        let applyContinuationRootWitnessNull =
                            applyContinuationDriverNull
                            && pendingCount() > 0
                            && hasReplayCompleteWriteWitness()
                        let applyContinuationRootWitnessRetryNull =
                            ex :? NullReferenceException
                            && pendingCount() > 0
                            && hasReplayCompleteWriteWitness()
                            && (match executingCellOpt with
                                | Some cell ->
                                    cell.kind = "term"
                                    && cell.shape = "EApply"
                                    && (cell.status = "apply_continuation_root_witness_null_guarded"
                                        || cell.status = "apply_continuation_root_witness_retry_guarded")
                                | None -> false)
                            && (match executingTaskOpt with
                                | Some task ->
                                    ((task.driver = "term_replay_driver") || (task.driver = "ty_replay_driver"))
                                    && task.payload.Contains("shape=EApply", StringComparison.Ordinal)
                                    && task.payload.Contains("apply_continuation_root_witness", StringComparison.Ordinal)
                                | None -> true)
                        let opContinuationRootWitnessNull =
                            ex :? NullReferenceException
                            && pendingCount() > 0
                            && hasReplayCompleteWriteWitness()
                            && (match executingCellOpt with
                                | Some cell ->
                                    cell.kind = "term"
                                    && cell.shape = "EOp"
                                    && cell.status = "semantic_step_partial"
                                | None -> false)
                            && (match executingTaskOpt with
                                | Some task ->
                                    task.driver = "term_replay_driver"
                                    && task.payload.Contains("shape=EOp", StringComparison.Ordinal)
                                    && task.payload.Contains("status=semantic_step_partial", StringComparison.Ordinal)
                                | None -> false)
                        let letSuccessApplyContinuationDriverNull =
                            applyContinuationDriverNull
                            && (match executingCellOpt with
                                | Some cell ->
                                    cell.kind = "term"
                                    && (cell.shape = "EApply" || cell.shape = "EUnitTest")
                                | None -> false)
                        let letSuccessApplyContinuationRootWitnessNull =
                            letSuccessApplyContinuationDriverNull
                            && pendingCount() > 0
                            && hasReplayCompleteWriteWitness()
                        let deferredFunctionPayloadNull =
                            match executingTaskOpt with
                            | Some task ->
                                task.payload.Contains("kind=term,shape=EFun'", StringComparison.Ordinal)
                                && task.payload.Contains("status=deferred_after_active_driver_ready", StringComparison.Ordinal)
                            | None -> false
                        let deferredFunctionDriverNull =
                            ex :? NullReferenceException
                            && ((match executingCellOpt with
                                 | Some cell -> cell.kind = "term" && cell.shape = "EFun'" && cell.status = "deferred_after_active_driver_ready"
                                 | None -> false)
                                || deferredFunctionPayloadNull)
                        let typeApplyArgDriverNull =
                            ex :? NullReferenceException
                            && pendingCount() > 0
                            && hasReplayCompleteWriteWitness()
                            && (match executingCellOpt with
                                | Some cell ->
                                    cell.kind = "term"
                                    && cell.shape = "ETypeApply"
                                    && cell.status = "semantic_step_partial"
                                | None -> false)
                            && (match executingTaskOpt with
                                | Some task ->
                                    task.driver = "term_replay_driver"
                                    && task.payload.Contains("shape=ETypeApply", StringComparison.Ordinal)
                                    && task.payload.Contains("status=semantic_step_partial", StringComparison.Ordinal)
                                | None -> false)
                        let pinnedSeqUnknownTerminal =
                            match tryPinnedTerminalContract() with
                            | Some pinned when pinned.status = "semantic_seq_unknown_return_witness_blocked" -> true
                            | _ -> false
                        let replayDriverExceptionKind =
                            if letSuccessDriverNull then ReplayExceptionLetSuccessApply
                            elif letSuccessApplyContinuationRootWitnessNull && nullGuardRepeatBlocked && rootWitnessNullRepeatCanTerminal then ReplayExceptionLetSuccessApplyContinuationRepeat
                            elif letSuccessApplyContinuationRootWitnessNull then ReplayExceptionLetSuccessApplyContinuationRootWitnessDeferred
                            elif letSuccessApplyContinuationDriverNull && pendingCount() > 0 && nullGuardRepeatBlocked && rootWitnessNullRepeatCanTerminal then ReplayExceptionLetSuccessApplyContinuationDriverRepeat
                            elif letSuccessApplyContinuationDriverNull && pendingCount() > 0 then ReplayExceptionLetSuccessApplyContinuationDriverDeferred
                            elif letSuccessApplyContinuationDriverNull then ReplayExceptionLetSuccessApplyContinuationDriverTerminal
                            elif applyContinuationRootWitnessNull && nullGuardRepeatBlocked && rootWitnessNullRepeatCanTerminal then ReplayExceptionApplyContinuationRootWitnessRepeat
                            elif applyContinuationRootWitnessNull then ReplayExceptionApplyContinuationRootWitnessDeferred
                            elif applyContinuationRootWitnessRetryNull && nullGuardRepeatBlocked && rootWitnessNullRepeatCanTerminal then ReplayExceptionApplyContinuationRootWitnessRetryRepeat
                            elif applyContinuationRootWitnessRetryNull then ReplayExceptionApplyContinuationRootWitnessRetryDeferred
                            elif opContinuationRootWitnessNull && nullGuardRepeatBlocked && rootWitnessNullRepeatCanTerminal then ReplayExceptionOpContinuationRootWitnessRepeat
                            elif opContinuationRootWitnessNull then ReplayExceptionOpContinuationRootWitnessDeferred
                            elif applyContinuationDriverNull && pinnedSeqUnknownTerminal then ReplayExceptionApplyContinuationAfterSeqUnknown
                            elif applyContinuationDriverNull then ReplayExceptionApplyContinuationDriverNull
                            elif deferredFunctionDriverNull then ReplayExceptionDeferredFunctionDriverNull
                            // ALPHA994/1016: ETypeApply replay nulls are terminal on first observation.
                            // Runtime 993 showed node-specific repeat keys resetting while the
                            // same core.spi:56 type-apply continuation rebuilt new replay ids.
                            elif typeApplyArgDriverNull then ReplayExceptionTypeApplyArgNull
                            else ReplayExceptionGeneric
                        let blockedSemanticStatusId =
                            match replayDriverExceptionKind with
                            | ReplayExceptionLetSuccessApply -> SemanticLetSuccessApplyExceptionBlocked
                            | ReplayExceptionLetSuccessApplyContinuationRepeat -> SemanticLetSuccessApplyContinuationBlocked
                            | ReplayExceptionLetSuccessApplyContinuationRootWitnessDeferred -> SemanticStepPartial
                            | ReplayExceptionLetSuccessApplyContinuationDriverRepeat -> SemanticLetSuccessApplyContinuationBlocked
                            | ReplayExceptionLetSuccessApplyContinuationDriverDeferred -> SemanticStepPartial
                            | ReplayExceptionLetSuccessApplyContinuationDriverTerminal -> SemanticLetSuccessApplyContinuationBlocked
                            | ReplayExceptionApplyContinuationRootWitnessRepeat -> SemanticApplyContinuationExceptionBlocked
                            | ReplayExceptionApplyContinuationRootWitnessDeferred -> SemanticStepPartial
                            | ReplayExceptionApplyContinuationRootWitnessRetryRepeat -> SemanticApplyContinuationExceptionBlocked
                            | ReplayExceptionApplyContinuationRootWitnessRetryDeferred -> SemanticStepPartial
                            | ReplayExceptionOpContinuationRootWitnessRepeat -> SemanticReplayDriverExceptionBlocked
                            | ReplayExceptionOpContinuationRootWitnessDeferred -> SemanticStepPartial
                            | ReplayExceptionApplyContinuationAfterSeqUnknown -> SemanticApplyContinuationAfterSeqUnknownBlocked
                            | ReplayExceptionApplyContinuationDriverNull -> SemanticApplyContinuationExceptionBlocked
                            | ReplayExceptionDeferredFunctionDriverNull -> SemanticDeferredFunctionReplayExceptionBlocked
                            | ReplayExceptionTypeApplyArgNull -> SemanticReplayDriverExceptionBlocked
                            | ReplayExceptionGeneric -> SemanticReplayDriverExceptionBlocked
                        let blockedStatus = semanticStatusToString blockedSemanticStatusId
                        let blockedCellStatus =
                            replayDriverExceptionKind
                            |> replayDriverExceptionCellStatusId
                            |> replayDriverExceptionCellStatusToString
                        let blockedReasonTag =
                            replayDriverExceptionKind
                            |> replayDriverExceptionReasonTagId
                            |> replayDriverExceptionReasonTagToString
                        let blockedNext =
                            replayDriverExceptionKind
                            |> replayDriverExceptionNextId
                            |> replayDriverExceptionNextToString
                        DiagJson.emit (
                            sprintf "{\"kind\":\"eval_worklist_replay_driver_exception\",\"event\":%s,\"error_type\":%s,\"message\":%s,\"queue_depth\":%d,\"pending\":%d,\"single_flight\":1,\"next\":\"surface_replay_driver_exception\"}"
                                (esc event) (esc (ex.GetType().Name)) (esc ex.Message) (replayQueueDepth()) (pendingCount()))
                        if ex :? NullReferenceException then
                            DiagJson.emit (
                                sprintf "{\"kind\":\"eval_worklist_null_guard_repeat\",\"event\":%s,\"repeat_count\":%d,\"repeat_cap\":%d,\"repeat_key\":%s,\"blocked\":%s,\"single_flight\":1,\"next\":%s}"
                                    (esc event) nullGuardRepeatCount replay_null_guard_repeat_cap (esc nullGuardRepeatKey) (if nullGuardRepeatBlocked then "true" else "false") (esc (if nullGuardRepeatBlocked then "terminalize_repeated_null_guard" else "allow_live_replay_retry")))
                        if ex :? NullReferenceException && hasReplayCompleteWriteWitness() && nullGuardRepeatBlocked then
                            DiagJson.emit (
                                sprintf "{\"kind\":\"eval_worklist_root_witness_null_repeat_deferred\",\"event\":%s,\"decision\":%s,\"repeat_count\":%d,\"repeat_cap\":%d,\"repeat_key\":%s,\"pending\":%d,\"queue_depth\":%d,\"active_depth\":%d,\"progress_yield\":%b,\"deferred_replay\":%b,\"witness\":%s,\"policy\":\"root_complete_witness_outvotes_repeated_null_replay_terminal_while_live\",\"single_flight\":1,\"next\":\"preserve_root_complete_or_resume_replay\"}"
                                    (esc event) (esc (rootWitnessNullReplayDecisionToString rootWitnessNullReplayDecision)) nullGuardRepeatCount replay_null_guard_repeat_cap (esc nullGuardRepeatKey) (pendingCount()) (replayQueueDepth()) (replayDriverActiveDepthValue()) (hasProgressYield()) (EvalReplayValueStore.hasDeferredReplayCell()) (esc (replayCompleteWriteWitnessSummary())))
                        let blocked =
                            lock gate (fun () ->
                                match replayQueue, frontier with
                                | task :: rest, Some frame ->
                                    let taskCellOpt = tryReplayCellPayload task.payload
                                    let cellText =
                                        match taskCellOpt with
                                        | Some cell -> formatCell cell
                                        | None ->
                                            match frame.semanticCell with
                                            | Some cell -> formatCell cell
                                            | None -> "none"
                                    let blockedCellOpt =
                                        match taskCellOpt with
                                        | Some cell -> Some { cell with status = blockedCellStatus }
                                        | None -> frame.semanticCell
                                    let baseReason = if isNull frame.reason then "" else frame.reason
                                    let frame' =
                                        { frame with
                                            status = blockedStatus
                                            reason = baseReason + ":" + blockedReasonTag + ":" + ex.GetType().Name
                                            semanticCell = blockedCellOpt
                                            semanticPayload = Some task.payload }
                                    replayQueue <- rest
                                    if replayQueue.IsEmpty then replayScheduledKey <- None
                                    frontier <- Some frame'
                                    slotSetLocked frame'
                                    Some(task.id, task.driver, task.status, task.payload, cellText, replayQueue.Length)
                                | task :: rest, None ->
                                    let cellText =
                                        match tryReplayCellPayload task.payload with
                                        | Some cell -> formatCell cell
                                        | None -> "none"
                                    replayQueue <- rest
                                    if replayQueue.IsEmpty then replayScheduledKey <- None
                                    Some(task.id, task.driver, task.status, task.payload, cellText, replayQueue.Length)
                                | [], Some frame ->
                                    // ALPHA513: the crashing replay task may already have
                                    // been consumed by the recursive driver before the
                                    // exception unwinds.  Pin the executing task/cell anyway
                                    // so the next retry pass cannot rebuild the same
                                    // continuation_envelope and throw again.
                                    match executingTaskOpt with
                                    | Some task ->
                                        let cellText =
                                            match executingCellOpt with
                                            | Some cell -> formatCell cell
                                            | None ->
                                                match frame.semanticCell with
                                                | Some cell -> formatCell cell
                                                | None -> "none"
                                        let blockedCellOpt =
                                            match executingCellOpt with
                                            | Some cell -> Some { cell with status = blockedCellStatus }
                                            | None ->
                                                match frame.semanticCell with
                                                | Some cell -> Some { cell with status = blockedCellStatus }
                                                | None -> None
                                        let baseReason = if isNull frame.reason then "" else frame.reason
                                        let frame' =
                                            { frame with
                                                status = blockedStatus
                                                reason = baseReason + ":" + blockedReasonTag + ":" + ex.GetType().Name
                                                semanticCell = blockedCellOpt
                                                semanticPayload = Some task.payload }
                                        replayScheduledKey <- None
                                        frontier <- Some frame'
                                        slotSetLocked frame'
                                        Some(task.id, task.driver, task.status, task.payload, cellText, 0)
                                    | None -> None
                                | [], _ -> None)
                        match blocked with
                        | Some (rid, driver, status, payload, cellText, qdAfter) ->
                            if letSuccessDriverNull then
                                DiagJson.emit (
                                    sprintf "{\"kind\":\"eval_worklist_let_success_driver_null_guarded\",\"event\":%s,\"replay_id\":%d,\"driver\":%s,\"status\":%s,\"error_type\":%s,\"message\":%s,\"cell\":%s,\"queue_depth_after\":%d,\"pending\":%d,\"single_flight\":1,\"next\":%s}"
                                        (esc event) rid (esc driver) (esc blockedStatus) (esc (ex.GetType().Name)) (esc ex.Message) (esc cellText) qdAfter (pendingCount()) (esc blockedNext))
                            if letSuccessApplyContinuationDriverNull then
                                DiagJson.emit (
                                    sprintf "{\"kind\":\"eval_worklist_let_success_apply_continuation_null_guarded\",\"event\":%s,\"replay_id\":%d,\"driver\":%s,\"status\":%s,\"error_type\":%s,\"message\":%s,\"cell\":%s,\"queue_depth_after\":%d,\"pending\":%d,\"single_flight\":1,\"next\":%s}"
                                        (esc event) rid (esc driver) (esc blockedStatus) (esc (ex.GetType().Name)) (esc ex.Message) (esc cellText) qdAfter (pendingCount()) (esc blockedNext))
                            if letSuccessApplyContinuationRootWitnessNull then
                                DiagJson.emit (
                                    sprintf "{\"kind\":\"eval_worklist_let_success_apply_continuation_root_witness_deferred\",\"event\":%s,\"replay_id\":%d,\"driver\":%s,\"status\":%s,\"error_type\":%s,\"message\":%s,\"cell\":%s,\"queue_depth_after\":%d,\"pending\":%d,\"witness\":%s,\"single_flight\":1,\"next\":%s}"
                                        (esc event) rid (esc driver) (esc blockedStatus) (esc (ex.GetType().Name)) (esc ex.Message) (esc cellText) qdAfter (pendingCount()) (esc (replayCompleteWriteWitnessSummary())) (esc blockedNext))
                            if applyContinuationRootWitnessNull then
                                DiagJson.emit (
                                    sprintf "{\"kind\":\"eval_worklist_apply_continuation_root_witness_null_guarded\",\"event\":%s,\"replay_id\":%d,\"driver\":%s,\"status\":%s,\"error_type\":%s,\"message\":%s,\"cell\":%s,\"queue_depth_after\":%d,\"pending\":%d,\"witness\":%s,\"single_flight\":1,\"next\":%s}"
                                        (esc event) rid (esc driver) (esc blockedStatus) (esc (ex.GetType().Name)) (esc ex.Message) (esc cellText) qdAfter (pendingCount()) (esc (replayCompleteWriteWitnessSummary())) (esc blockedNext))
                            if applyContinuationRootWitnessRetryNull then
                                DiagJson.emit (
                                    sprintf "{\"kind\":\"eval_worklist_apply_continuation_root_witness_retry_guarded\",\"event\":%s,\"replay_id\":%d,\"driver\":%s,\"status\":%s,\"error_type\":%s,\"message\":%s,\"cell\":%s,\"queue_depth_after\":%d,\"pending\":%d,\"witness\":%s,\"single_flight\":1,\"next\":%s}"
                                        (esc event) rid (esc driver) (esc blockedStatus) (esc (ex.GetType().Name)) (esc ex.Message) (esc cellText) qdAfter (pendingCount()) (esc (replayCompleteWriteWitnessSummary())) (esc blockedNext))
                            if opContinuationRootWitnessNull then
                                DiagJson.emit (
                                    sprintf "{\"kind\":\"eval_worklist_op_root_witness_null_guarded\",\"event\":%s,\"replay_id\":%d,\"driver\":%s,\"status\":%s,\"error_type\":%s,\"message\":%s,\"cell\":%s,\"queue_depth_after\":%d,\"pending\":%d,\"witness\":%s,\"single_flight\":1,\"next\":%s}"
                                        (esc event) rid (esc driver) (esc blockedStatus) (esc (ex.GetType().Name)) (esc ex.Message) (esc cellText) qdAfter (pendingCount()) (esc (replayCompleteWriteWitnessSummary())) (esc blockedNext))
                            if unitTestReplayDriverNull then
                                DiagJson.emit (
                                    sprintf "{\"kind\":\"eval_worklist_unit_test_driver_null_guarded\",\"event\":%s,\"replay_id\":%d,\"driver\":%s,\"status\":%s,\"error_type\":%s,\"message\":%s,\"cell\":%s,\"queue_depth_after\":%d,\"pending\":%d,\"single_flight\":1,\"next\":%s}"
                                        (esc event) rid (esc driver) (esc blockedStatus) (esc (ex.GetType().Name)) (esc ex.Message) (esc cellText) qdAfter (pendingCount()) (esc blockedNext))
                            if applyContinuationDriverNull then
                                DiagJson.emit (
                                    sprintf "{\"kind\":\"eval_worklist_apply_continuation_driver_null_guarded\",\"event\":%s,\"replay_id\":%d,\"driver\":%s,\"status\":%s,\"error_type\":%s,\"message\":%s,\"cell\":%s,\"queue_depth_after\":%d,\"pending\":%d,\"single_flight\":1,\"next\":%s}"
                                        (esc event) rid (esc driver) (esc blockedStatus) (esc (ex.GetType().Name)) (esc ex.Message) (esc cellText) qdAfter (pendingCount()) (esc blockedNext))
                            if deferredFunctionDriverNull then
                                DiagJson.emit (
                                    sprintf "{\"kind\":\"eval_worklist_deferred_function_driver_null_guarded\",\"event\":%s,\"replay_id\":%d,\"driver\":%s,\"status\":%s,\"error_type\":%s,\"message\":%s,\"cell\":%s,\"queue_depth_after\":%d,\"pending\":%d,\"single_flight\":1,\"next\":%s}"
                                        (esc event) rid (esc driver) (esc blockedStatus) (esc (ex.GetType().Name)) (esc ex.Message) (esc cellText) qdAfter (pendingCount()) (esc blockedNext))
                            if typeApplyArgDriverNull then
                                DiagJson.emit (
                                    sprintf "{\"kind\":\"eval_worklist_type_apply_arg_driver_null_guarded\",\"event\":%s,\"replay_id\":%d,\"driver\":%s,\"status\":%s,\"error_type\":%s,\"message\":%s,\"cell\":%s,\"queue_depth_after\":%d,\"pending\":%d,\"witness\":%s,\"single_flight\":1,\"next\":%s}"
                                        (esc event) rid (esc driver) (esc blockedStatus) (esc (ex.GetType().Name)) (esc ex.Message) (esc cellText) qdAfter (pendingCount()) (esc (replayCompleteWriteWitnessSummary())) (esc blockedNext))
                            DiagJson.emit (
                                sprintf "{\"kind\":\"eval_worklist_replay_driver_exception_blocked\",\"event\":%s,\"replay_id\":%d,\"driver\":%s,\"status\":%s,\"error_type\":%s,\"message\":%s,\"cell\":%s,\"payload\":%s,\"queue_depth_after\":%d,\"pending\":%d,\"single_flight\":1,\"next\":%s}"
                                    (esc event) rid (esc driver) (esc status) (esc (ex.GetType().Name)) (esc ex.Message) (esc cellText) (esc payload) qdAfter (pendingCount()) (esc blockedNext))
                            // ALPHA994: when an ETypeApply replay null has become the explicit
                            // semantic replay-driver terminal, pin the semantic terminal status
                            // rather than the lower-level cell status so pending/deferred live
                            // replay cannot outvote it on the next trampoline tick.
                            if blockedStatus = "semantic_replay_driver_exception_blocked" then
                                match executingCellOpt with
                                | Some cell ->
                                    let pinnedExceptionCell = { cell with status = blockedStatus }
                                    pinTerminalCell event ("replay_driver_exception:" + blockedReasonTag) pinnedExceptionCell
                                    DiagJson.emit (
                                        sprintf "{\"kind\":\"eval_worklist_replay_driver_exception_terminal_pinned\",\"event\":%s,\"replay_id\":%d,\"driver\":%s,\"reason\":%s,\"cell\":%s,\"queue_depth_after\":%d,\"pending\":%d,\"single_flight\":1,\"next\":\"stop_retry_drain_on_pinned_exception\"}"
                                            (esc event) rid (esc driver) (esc blockedReasonTag) (esc (formatCell pinnedExceptionCell)) qdAfter (pendingCount()))
                                | None -> ()
                            if qdAfter = 0 && not letSuccessApplyContinuationDriverNull && not letSuccessApplyContinuationRootWitnessNull && not applyContinuationRootWitnessNull && not applyContinuationRootWitnessRetryNull && not opContinuationRootWitnessNull then
                                DiagJson.emit (
                                    sprintf "{\"kind\":\"eval_worklist_empty_queue_replay_driver_exception_pinned\",\"event\":%s,\"replay_id\":%d,\"driver\":%s,\"error_type\":%s,\"cell\":%s,\"pending\":%d,\"single_flight\":1,\"next\":\"stop_retry_drain_on_pinned_exception\"}"
                                        (esc event) rid (esc driver) (esc (ex.GetType().Name)) (esc cellText) (pendingCount()))
                        | None -> ()
                finally
                    let deferredReplayPendingBeforeGate = EvalReplayValueStore.hasDeferredReplayCell()
                    let drainDeferred, terminalNoDeferred, terminalStatus =
                        lock gate (fun () ->
                            replayDriverActiveDepth <- max 0 (replayDriverActiveDepth - 1)
                            let terminalStatus =
                                match frontier with
                                | Some frame -> frame.status
                                | None -> "missing_terminal_frontier"
                            let pinnedTerminalStatusOpt =
                                match pinnedTerminalContract with
                                | Some pinned when terminalContractRank pinned.status >= 68 -> Some pinned.status
                                | _ -> None
                            let deferredReplayPending = deferredReplayPendingBeforeGate
                            let fingerprintRepeatHasDeferred status =
                                status = "semantic_replay_fingerprint_repeat_blocked" && deferredReplayPending
                            let pinnedTerminalNoDeferred =
                                match pinnedTerminalStatusOpt with
                                | Some pinnedStatus when fingerprintRepeatHasDeferred pinnedStatus -> false
                                | Some _ -> true
                                | None -> false
                            let terminalNoDeferred =
                                if fingerprintRepeatHasDeferred terminalStatus then false
                                else isTerminalContractStatus terminalStatus || pinnedTerminalNoDeferred
                            let effectiveTerminalStatus =
                                if isTerminalContractStatus terminalStatus then terminalStatus
                                else
                                    match pinnedTerminalStatusOpt with
                                    | Some pinnedStatus -> pinnedStatus
                                    | None -> terminalStatus
                            replayDriverActiveDepth = 0 && replayQueue.IsEmpty, terminalNoDeferred, effectiveTerminalStatus)
                    if drainDeferred && terminalNoDeferred then
                        DiagJson.emit (
                            sprintf "{\"kind\":\"eval_worklist_deferred_after_terminal_suppressed\",\"event\":%s,\"status\":%s,\"single_flight\":1,\"next\":\"explicit_terminal_replay_contract\"}"
                                (esc event)
                                (esc terminalStatus))
                    elif drainDeferred && tryScheduleDeferredAfterActiveDriver event then
                        scheduleReplayDriverTick "cooperative_replay_handoff" event

        let frontierSummary () =
            match snapshot 1 with
            | frame :: _ ->
                let cell =
                    match frame.semanticCell with
                    | Some c -> short 160 (formatCell c)
                    | None -> "none"
                sprintf "frontier kind=%s status=%s depth=%d re=%d/%d trace=%d cursor=%d replay_queue=%d driver=%s payload=%s cell=%s site=%s key=%s"
                    frame.kind frame.status frame.depth frame.re frame.maxRe frame.trace.Length frame.cursor (replayQueueDepth()) (replayDriverStatus()) (semanticPayloadStatus()) cell
                    (short 96 frame.site) (short 120 frame.key)
            | [] -> "frontier empty"

        let panel () =
            try
                let frames = snapshot 3
                if frames.IsEmpty then "" else
                    let sb = System.Text.StringBuilder()
                    sb.AppendFormat("eval.worklist pending={0} single_flight=1 active={1}", frames.Length, (if activeRun then 1 else 0)) |> ignore
                    frames
                    |> List.iteri (fun i frame ->
                        sb.AppendLine() |> ignore
                        let cell =
                            match frame.semanticCell with
                            | Some c -> short 120 (formatCell c)
                            | None -> "none"
                        let line =
                            sprintf "  #%d kind=%s status=%s depth=%d re=%d/%d trace=%d cursor=%d replay_queue=%d driver=%s payload=%s cell=%s site=%s"
                                i frame.kind frame.status frame.depth frame.re frame.maxRe frame.trace.Length frame.cursor (replayQueueDepth()) (replayDriverStatus()) (semanticPayloadStatus()) cell (short 92 frame.site)
                        sb.Append(line) |> ignore)
                    sb.ToString().TrimEnd()
            with _ -> ""

        let emitPanel (event: string) =
            try
                let n = pendingCount()
                let summary = frontierSummary()
                DiagJson.emit (
                    sprintf "{\"kind\":\"eval_worklist_panel\",\"event\":%s,\"pending\":%d,\"single_flight\":1,\"active\":%d,\"replay_queue\":%d,\"semantic_payload\":%s,\"summary\":%s}"
                        (esc event) n (if activeRun then 1 else 0) (replayQueueDepth()) (esc (semanticPayloadStatus())) (esc summary))
            with _ -> ()

        let fromCycleFuse (reason: string) : Frame =
            let key, site, depth, _gen, re, maxRe = TermCycleFuse.describe()
            { kind = kindFromSite site
              key = key
              site = site
              depth = depth
              re = re
              maxRe = maxRe
              trace = TermCycleFuse.traceSnapshot() |> compactTrace
              reason = reason
              status = "blocked_by_reentry"
              cursor = 0
              semanticPayload = None
              semanticCell = None }

        let emit (event: string) (frame: Frame) : unit =
            try
                DiagJson.emit (
                    sprintf "{\"kind\":\"eval_worklist_frame\",\"event\":%s,\"reason\":%s,\"frame_kind\":%s,\"key\":%s,\"site\":%s,\"depth\":%d,\"re\":%d,\"max_re\":%d,\"trace_lines\":%d,\"status\":%s,\"cursor\":%d,\"single_flight\":1}"
                        (esc event) (esc frame.reason) (esc frame.kind) (esc frame.key) (esc frame.site) frame.depth frame.re frame.maxRe frame.trace.Length (esc frame.status) frame.cursor)
            with _ -> ()

        let attachSemanticPayload (event: string) (payload: string) : unit =
            try
                let payload = short 1800 payload
                let attached =
                    lock gate (fun () ->
                        match frontier with
                        | Some frame ->
                            let frame' = { frame with semanticPayload = Some payload }
                            frontier <- Some frame'
                            true
                        | None -> false)
                DiagJson.emit (
                    sprintf "{\"kind\":\"eval_worklist_payload\",\"event\":%s,\"attached\":%d,\"semantic_payload\":%s,\"pending\":%d,\"single_flight\":1}"
                        (esc event) (if attached then 1 else 0) (esc (if attached then "semantic" else "missing_frontier")) (pendingCount()))
            with _ -> ()

        let attachSemanticCell (event: string) (cell: ReplayCell) : unit =
            try
                let payload = formatCellPayload cell |> short 1800
                rememberSemanticCell cell
                let attached, attachStatus =
                    lock gate (fun () ->
                        selectKindLocked cell.kind |> ignore
                        match frontier with
                        | Some frame when frame.kind = cell.kind ->
                            // ALPHA448: do not let a completed same-kind frame masquerade as
                            // completion for a different incoming semantic cell.  This was the
                            // alpha447 live-loop: frame=listm.spi:6/root_complete, cell=TJoinPoint'
                            // at runtime.spi:330.  Keep the trace shell, retarget it to the end,
                            // and force a continuation envelope so the typed replay driver handles
                            // the incoming cell instead of repeatedly attempting build.
                            // ALPHA450: when a scheduled parent replay is active, the incoming same-kind
                            // child cell is useful evidence, but it must not overwrite the parent cell that
                            // the queued replay task is about to reduce. Alpha449 showed the hot loop:
                            // ETypeApply(parent) -> EForall'(child) -> parent_resume -> child overwrite -> ...
                            let sameNodeParentReplayProtected =
                                match replayQueue, frame.semanticCell with
                                | task :: _, Some parent ->
                                    // ALPHA464: alpha463's tail is not a child-over-parent overwrite;
                                    // it is the active scheduled_parent_replay receiving the same
                                    // TJoinPoint' node as a fresh semantic cell and immediately poking
                                    // itself.  Defer that same-node payload so the queued parent replay
                                    // can advance instead of re-entering the same driver frame.
                                    let taskTargetsIncoming =
                                        task.payload.Contains(sprintf "node_id=%d" cell.nodeId)
                                        || task.key.Contains(sprintf "|parent|%d|" cell.nodeId)
                                    task.status = "scheduled_parent_replay"
                                    && taskTargetsIncoming
                                    && sameReplayNode parent cell
                                    && parent.status <> "semantic_root_complete"
                                    && parent.status <> "semantic_leaf_complete"
                                | _ -> false
                            let activeReplayCellProtected =
                                if sameNodeParentReplayProtected then false
                                else
                                    match replayQueue, frame.semanticCell with
                                    | task :: _, Some parent ->
                                        // ALPHA452: alpha451 preserved scheduled_parent_replay, but the same
                                        // overwrite hazard appears for a root continuation replay: a scheduled
                                        // EApply(trace.spi:295) is on the replay queue, then a late EUnitTest
                                        // child cell arrives and replaces the frontier before the driver reduces
                                        // the original continuation.  Protect any in-flight same-kind replay
                                        // cell whose queued payload/key points at the current frontier cell.
                                        let taskTargetsParent =
                                            task.payload.Contains(sprintf "node_id=%d" parent.nodeId)
                                            || task.key.Contains(sprintf "|parent|%d|" parent.nodeId)
                                            || (task.status = "scheduled_parent_replay" && task.key.Contains("|parent|"))
                                        let activeReplayStatus =
                                            task.status = "scheduled_parent_replay"
                                            || task.status = "scheduled_replay"
                                            || task.status = "driver_ready_replay_cell"
                                            || task.status = "driver_ready_semantic_payload"
                                        activeReplayStatus
                                        && taskTargetsParent
                                        && parent.kind = cell.kind
                                        && parent.nodeId <> cell.nodeId
                                        && parent.status <> "semantic_root_complete"
                                        && parent.status <> "semantic_leaf_complete"
                                    | _ -> false
                            let staleRootComplete =
                                if sameNodeParentReplayProtected || activeReplayCellProtected then false
                                else
                                    frame.status = "semantic_root_complete"
                                    && (match frame.semanticCell with
                                        | Some old -> old.nodeId <> cell.nodeId || old.site <> cell.site || old.shape <> cell.shape || old.kind <> cell.kind || old.status <> "semantic_root_complete"
                                        | None -> frame.site <> cell.site)
                            let staleRootRetargetCount =
                                if staleRootComplete then
                                    let key =
                                        sprintf "%s|%s|%s|%d|frame=%s|cursor=%d"
                                            cell.kind cell.shape cell.site cell.nodeId frame.key frame.cursor
                                    let mutable prior = 0
                                    let next = if staleRootRetargetRepeats.TryGetValue(key, &prior) then prior + 1 else 1
                                    staleRootRetargetRepeats.[key] <- next
                                    next
                                else 0
                            let staleRootRetargetQuarantined = staleRootComplete && staleRootRetargetCount > 3
                            // ALPHA581: a stale-root retarget must not overwrite an already
                            // replay-complete root frame even before quarantine.  Runtime 580
                            // showed repeated eval_worklist_stale_root_complete_retargeted before
                            // the final stale TV mask; defer the stale cell immediately.
                            let suppressRootCompleteRetarget =
                                staleRootComplete
                                && frameReplayCompleteAny frame
                            let rootCompleteStaleRetargetHardCap = 32
                            let rootCompleteStaleRetargetTerminal =
                                suppressRootCompleteRetarget
                                && staleRootRetargetCount >= rootCompleteStaleRetargetHardCap
                            // ALPHA674: runtime 673 hit the hard cap with the root and
                            // incoming cell describing the same ty/TRecord node/site/shape at
                            // spiral.spi:2670.  That is not a new stale terminal; it is the
                            // root-complete frame echoing its own semantic cell with a stale
                            // cell-status.  Align the cell with the already-proven frame and
                            // keep the root evidence instead of pinning a synthetic terminal.
                            let sameRootCompleteCellEcho =
                                rootCompleteStaleRetargetTerminal
                                && frame.status = "semantic_root_complete"
                                && (match frame.semanticCell with
                                    | Some old ->
                                        old.kind = cell.kind
                                        && old.nodeId = cell.nodeId
                                        && old.site = cell.site
                                        && old.shape = cell.shape
                                    | None ->
                                        frame.kind = cell.kind
                                        && frame.site = cell.site)
                            let sameSiteAppRootRetargetEcho =
                                // ALPHA863: alpha862 showed the same app-root hardcap can
                                // arrive as TRecord first and then as TFun at the identical
                                // ty@apps/spiral/spiral.spi:2670 site.  Once the live frame is
                                // semantic_root_complete and the incoming cell is same-kind and
                                // same-site app root evidence, shape is not a stronger proof of
                                // failure.  Preserve the root witness instead of pinning the
                                // synthetic stale-retarget terminal.
                                rootCompleteStaleRetargetTerminal
                                && frame.status = "semantic_root_complete"
                                && frame.kind = cell.kind
                                && frame.site = cell.site
                                && frameIsRootCompleteEvidence frame
                            let appRootBase16StaleRetargetEcho =
                                // ALPHA889: runtime 888 proved alpha888 did not hit the
                                // previous post-finalization demote.  The live root was the
                                // app tests frontier at spiral.spi:2670, while the stale
                                // incoming type cell was a core/base.spi:16 TUnion echo.
                                // The hardcap is still synthetic: keep the root frontier and
                                // leave the stale base16 cell deferred/quarantined instead of
                                // turning it into a terminal contract.
                                rootCompleteStaleRetargetTerminal
                                && frame.status = "semantic_root_complete"
                                && frame.kind = "ty"
                                && cell.kind = "ty"
                                && frameIsRootCompleteEvidence frame
                                && (cell.shape = "TUnion" || cell.shape = "TNominal")
                                && pendingCount() <= 2
                            let rootCompleteStaleRetargetShouldEmit =
                                staleRootRetargetCount <= 4
                                || staleRootRetargetCount = 8
                                || staleRootRetargetCount = 16
                                || staleRootRetargetCount = 32
                                || staleRootRetargetCount = rootCompleteStaleRetargetHardCap
                            let cursor' = if staleRootComplete then frame.trace.Length else frame.cursor
                            let cell' = { cell with cursor = cursor'; status = if staleRootRetargetQuarantined then "stale_root_retarget_quarantined" elif staleRootComplete then "stale_root_retargeted" else "captured" }
                            // ALPHA449: if a fresh same-kind semantic cell replaces a frame that was
                            // carrying a parent semantic cell, keep the typed child -> parent edge.
                            // Alpha448 ended with EOp(real_core.spir:150) as semantic_leaf_complete
                            // while the frame/key still represented the ETypeApply at spiral.spi:2671.
                            // Without this edge the driver can only repeat leaf_complete_parent_continuation_missing.
                            // ALPHA504: frame_semantic_child is an artificial edge used to
