                                        sprintf "{\"kind\":\"eval_worklist_root_complete_stale_retarget_repeat_blocked\",\"event\":%s,\"root_site\":%s,\"stale_site\":%s,\"root_status\":%s,\"stale_status\":%s,\"count\":%d,\"pending\":%d,\"single_flight\":1,\"next\":\"explicit_eval_worklist_root_complete_stale_retarget_required\"}"
                                            (esc event) (esc frame.site) (esc terminalCell.site) (esc frame.status) (esc terminalCell.status) staleRootRetargetCount (pendingCount()))
                                    pinTerminalContractLocked event terminalFrame
                                    terminalFrame
                                elif suppressRootCompleteRetarget && frame.status = "semantic_root_complete" && hasReplayCompleteWriteWitness() then
                                    // ALPHA1047: the pre-Hopac evaluator would already be done with
                                    // this type root. Preserve the witness, but do not reinsert a stale
                                    // retarget cell that keeps pending>0 forever.
                                    if rootCompleteStaleRetargetShouldEmit then
                                        DiagJson.emit (
                                            sprintf "{\"kind\":\"eval_worklist_root_complete_stale_retarget_suppressed_after_witness_no_reinsert\",\"event\":%s,\"root_site\":%s,\"stale_site\":%s,\"root_status\":%s,\"stale_status\":%s,\"count\":%d,\"pending\":%d,\"write_witness\":%b,\"single_flight\":1,\"policy\":\"pre_hopac_root_complete_beats_stale_retarget_replay\",\"next\":\"preserve_root_evidence_without_deferred_cell\"}"
                                                (esc event) (esc frame.site) (esc cell'.site) (esc frame.status) (esc cell'.status) staleRootRetargetCount (pendingCount()) (hasReplayCompleteWriteWitness()))
                                    frame
                                elif suppressRootCompleteRetarget then
                                    EvalReplayValueStore.putDeferredReplayCell {
                                        kind = cell'.kind
                                        shape = cell'.shape
                                        nodeId = cell'.nodeId
                                        envGlobalTerm = cell'.envGlobalTerm
                                        envStackTerm = cell'.envStackTerm
                                        envGlobalType = cell'.envGlobalType
                                        envStackType = cell'.envStackType
                                        seqLen = cell'.seqLen
                                        cseDepth = cell'.cseDepth
                                        traceDepth = cell'.traceDepth
                                        site = cell'.site
                                        cursor = cell'.cursor
                                        step = cell'.step
                                        status = cell'.status
                                    }
                                    if rootCompleteStaleRetargetShouldEmit then
                                        DiagJson.emit (
                                            sprintf "{\"kind\":\"eval_worklist_root_complete_stale_retarget_suppressed\",\"event\":%s,\"root_site\":%s,\"stale_site\":%s,\"root_status\":%s,\"stale_status\":%s,\"count\":%d,\"pending\":%d,\"single_flight\":1,\"next\":\"preserve_root_evidence\"}"
                                                (esc event) (esc frame.site) (esc cell'.site) (esc frame.status) (esc cell'.status) staleRootRetargetCount (pendingCount()))
                                    frame
                                elif staleRootComplete then
                                    let status' = if staleRootRetargetQuarantined then "semantic_stale_root_retarget_blocked" else "ready_explicit_loop"
                                    let reason' = frame.reason + (if staleRootRetargetQuarantined then ":stale_root_complete_retarget_quarantined" else ":stale_root_complete_retargeted")
                                    { frame with status = status'; cursor = cursor'; reason = reason'; semanticPayload = Some (formatCellPayload cell'); semanticCell = Some cell' }
                                else
                                    { frame with semanticPayload = Some (formatCellPayload cell'); semanticCell = Some cell' }
                            frontier <- Some frame'
                            slotSetLocked frame'
                            if staleRootComplete then
                                replayScheduledKey <- None
                                replayQueue <- []
                            true, (if sameNodeParentReplayProtected then "same_node_parent_replay_cell_deferred" elif activeReplayCellProtected then "parent_resume_cell_deferred" elif sameRootCompleteCellEcho then "same_root_complete_cell_echo_materialized" elif sameSiteAppRootRetargetEcho then "same_site_app_root_retarget_echo_materialized" elif appRootBase16StaleRetargetEcho then "app_root_base16_stale_retarget_hardcap_demoted" elif rootCompleteStaleRetargetTerminal then "root_complete_stale_retarget_repeat_blocked" elif suppressRootCompleteRetarget then "root_complete_stale_retarget_suppressed" elif staleRootRetargetQuarantined then "stale_root_complete_retarget_quarantined" elif staleRootComplete then "stale_root_complete_retargeted" elif frameDerivedParent then "cell_frame_parent_continuation" else "cell")
                        | Some frame ->
                            // ALPHA426: cross-kind payloads are backpressure, not noise.
                            // Alpha425 proved the old single canonical frontier could be ty while dozens of
                            // term cells were ready on other Hopac workers, emitting kind_mismatch_frame_ty_cell_term
                            // and starving the requested evaluator.  If the live TermCycleFuse now describes the
                            // cell's kind, switch the canonical frontier to that fresh cycle and attach the cell;
                            // otherwise keep alpha348's fail-closed mismatch policy.
                            let switched =
                                try
                                    if TermCycleFuse.isTripped() then
                                        let fresh = fromCycleFuse (sprintf "kind_mismatch_switch_%s_to_%s" frame.kind cell.kind)
                                        if fresh.kind = cell.kind then
                                            let cell' = { cell with cursor = fresh.cursor; status = "captured" }
                                            let frame' = { fresh with semanticPayload = Some (formatCellPayload cell'); semanticCell = Some cell' }
                                            frontier <- Some frame'
                                            replayScheduledKey <- None
                                            replayQueue <- []
                                            // ALPHA427: do not reset the stable root-complete ledger on a transient
                                            // kind-local frontier switch.  Alpha426 proved the same root-complete
                                            // frontier can be re-captured every attempt, keeping stable_count=1 until
                                            // the outer cap trips.  noteRootCompleteHandoff already resets on a genuinely
                                            // different fingerprint.
                                            Some(sprintf "kind_mismatch_switched_frame_%s_cell_%s" frame.kind cell.kind)
                                        else None
                                    else None
                                with _ -> None
                            match switched with
                            | Some status -> true, status
                            | None ->
                                let crossKindDecision =
                                    if pendingCount() > 0
                                       || replayQueueDepth() > 0
                                       || replayDriverActiveDepthValue() > 0
                                       || hasProgressYield()
                                       || EvalReplayValueStore.hasDeferredReplayCell() then
                                        CrossKindDeferAsReplayObligation
                                    else CrossKindRejectUnsafeMismatch
                                let frameShape =
                                    match frame.semanticCell with
                                    | Some frameCell -> frameCell.shape
                                    | None -> frame.kind
                                match crossKindDecision with
                                | CrossKindDeferAsReplayObligation ->
                                    EvalReplayValueStore.putDeferredReplayCell {
                                        kind = cell.kind
                                        shape = cell.shape
                                        nodeId = cell.nodeId
                                        envGlobalTerm = cell.envGlobalTerm
                                        envStackTerm = cell.envStackTerm
                                        envGlobalType = cell.envGlobalType
                                        envStackType = cell.envStackType
                                        seqLen = cell.seqLen
                                        cseDepth = cell.cseDepth
                                        traceDepth = cell.traceDepth
                                        site = cell.site
                                        cursor = cell.cursor
                                        step = cell.step
                                        status = cell.status
                                    }
                                    DiagJson.emit (
                                        sprintf "{\"kind\":\"eval_worklist_cross_kind_payload_deferred\",\"event\":%s,\"frame_kind\":%s,\"frame_shape\":%s,\"frame_site\":%s,\"cell_kind\":%s,\"cell_shape\":%s,\"cell_site\":%s,\"cell_node_id\":%d,\"decision\":%s,\"pending\":%d,\"queue_depth\":%d,\"active_depth\":%d,\"progress_yield\":%b,\"deferred_replay\":%b,\"policy\":\"cross_kind_payload_is_replay_obligation_not_dropped_noise\",\"single_flight\":1,\"next\":\"resume_matching_replay_driver\"}"
                                            (esc event) (esc frame.kind) (esc frameShape) (esc frame.site) (esc cell.kind) (esc cell.shape) (esc cell.site) cell.nodeId (esc (crossKindPayloadAttachDecisionToString crossKindDecision)) (pendingCount()) (replayQueueDepth()) (replayDriverActiveDepthValue()) (hasProgressYield()) (EvalReplayValueStore.hasDeferredReplayCell()))
                                    true, sprintf "cross_kind_payload_deferred_frame_%s_cell_%s" frame.kind cell.kind
                                | CrossKindRejectUnsafeMismatch ->
                                    // ALPHA348: a typed payload must belong to the same evaluator kind as the canonical frontier.
                                    // Alpha347 allowed ty_entry cells to overwrite a term frontier, producing a term_replay_driver
                                    // carrying semantic_eval_cell(kind=ty,...). Treat quiescent mismatches as observed but not attached.
                                    false, sprintf "kind_mismatch_frame_%s_cell_%s" frame.kind cell.kind
                                | CrossKindSwitchToFreshFrontier ->
                                    // This case is represented by Some status above; retain the arm so the DU is total.
                                    false, sprintf "kind_mismatch_frame_%s_cell_%s" frame.kind cell.kind
                        | None -> false, "missing_frontier")
                DiagJson.emit (
                    sprintf "{\"kind\":\"eval_worklist_payload\",\"event\":%s,\"attached\":%d,\"semantic_payload\":%s,\"semantic_cell\":%s,\"pending\":%d,\"single_flight\":1}"
                        (esc event) (if attached then 1 else 0) (esc attachStatus) (esc payload) (pendingCount()))
                if attached && attachStatus = "stale_root_complete_retargeted" then
                    DiagJson.emit (
                        sprintf "{\"kind\":\"eval_worklist_stale_root_complete_retargeted\",\"event\":%s,\"incoming_kind\":%s,\"incoming_shape\":%s,\"incoming_site\":%s,\"incoming_node_id\":%d,\"pending\":%d,\"single_flight\":1,\"next\":\"schedule_ty_replay_continuation\"}"
                            (esc event) (esc cell.kind) (esc cell.shape) (esc cell.site) cell.nodeId (pendingCount()))
                if attached && attachStatus = "stale_root_complete_retarget_quarantined" then
                    DiagJson.emit (
                        sprintf "{\"kind\":\"eval_worklist_stale_root_complete_retarget_quarantined\",\"event\":%s,\"incoming_kind\":%s,\"incoming_shape\":%s,\"incoming_site\":%s,\"incoming_node_id\":%d,\"pending\":%d,\"single_flight\":1,\"next\":\"explicit_eval_worklist_stale_root_retarget_required\"}"
                            (esc event) (esc cell.kind) (esc cell.shape) (esc cell.site) cell.nodeId (pendingCount()))
                if attached && attachStatus = "root_complete_stale_retarget_repeat_blocked" then
                    DiagJson.emit (
                        sprintf "{\"kind\":\"eval_worklist_root_complete_stale_retarget_repeat_blocked\",\"event\":%s,\"incoming_kind\":%s,\"incoming_shape\":%s,\"incoming_site\":%s,\"incoming_node_id\":%d,\"pending\":%d,\"single_flight\":1,\"next\":\"explicit_eval_worklist_root_complete_stale_retarget_required\"}"
                            (esc event) (esc cell.kind) (esc cell.shape) (esc cell.site) cell.nodeId (pendingCount()))
                if attached && attachStatus.StartsWith("cross_kind_payload_deferred_frame_") then
                    DiagJson.emit (
                        sprintf "{\"kind\":\"eval_worklist_cross_kind_payload_obligation_attached\",\"event\":%s,\"incoming_kind\":%s,\"incoming_shape\":%s,\"incoming_site\":%s,\"incoming_node_id\":%d,\"semantic_payload\":%s,\"pending\":%d,\"queue_depth\":%d,\"single_flight\":1,\"next\":\"resume_matching_replay_driver\"}"
                            (esc event) (esc cell.kind) (esc cell.shape) (esc cell.site) cell.nodeId (esc attachStatus) (pendingCount()) (replayQueueDepth()))
                if attached && attachStatus = "cell_frame_parent_continuation" then
                    DiagJson.emit (
                        sprintf "{\"kind\":\"eval_worklist_frame_parent_continuation\",\"event\":%s,\"child_kind\":%s,\"child_shape\":%s,\"child_site\":%s,\"child_node_id\":%d,\"pending\":%d,\"single_flight\":1,\"next\":\"resume_parent_replay_driver\"}"
                            (esc event) (esc cell.kind) (esc cell.shape) (esc cell.site) cell.nodeId (pendingCount()))
                if attached && (attachStatus = "parent_resume_cell_deferred" || attachStatus = "active_replay_cell_deferred" || attachStatus = "same_node_parent_replay_cell_deferred") then
                    DiagJson.emit (
                        sprintf "{\"kind\":\"eval_worklist_active_replay_cell_deferred\",\"event\":%s,\"child_kind\":%s,\"child_shape\":%s,\"child_site\":%s,\"child_node_id\":%d,\"defer_reason\":%s,\"pending\":%d,\"single_flight\":1,\"next\":\"poke_active_replay_driver\"}"
                            (esc event) (esc cell.kind) (esc cell.shape) (esc cell.site) cell.nodeId (esc attachStatus) (pendingCount()))
                    if attachStatus = "same_node_parent_replay_cell_deferred" then
                        DiagJson.emit (
                            sprintf "{\"kind\":\"eval_worklist_same_node_parent_replay_cell_deferred\",\"event\":%s,\"child_kind\":%s,\"child_shape\":%s,\"child_site\":%s,\"child_node_id\":%d,\"pending\":%d,\"single_flight\":1,\"next\":\"await_existing_parent_replay_tick\"}"
                                (esc event) (esc cell.kind) (esc cell.shape) (esc cell.site) cell.nodeId (pendingCount()))
                // ALPHA413: replay-driver poke after late semantic-cell attachment.
                // Alpha412 proved the continuation envelope can schedule ty_replay_driver
                // before the matching TMacro cell reaches the frontier, leaving the task in
                // driver_blocked_semantic_payload even after later ty_entry/ty_reentry_prefetch
                // attaches a concrete cell.  If a same-kind cell attached and a replay task is
                // waiting, immediately re-run the driver once; the driver still fail-closes unless
                // the cell is present and reducible.
                // ALPHA454: a deferred child cell is intentionally not the active replay cell.
                // Alpha453 showed the previous "poke after any attached cell" rule could recurse
                // forever before the parent ETypeApply replay reduced: EForall' was deferred,
                // the poke re-entered the same scheduled_parent_replay, and the parent never
                // reached eval_worklist_replay_step.  For deferred same-kind cells, leave the
                // queued parent/root replay intact and let the existing replay tick continue.
                if attached && replayQueueDepth() > 0 then
                    let suppressCrossKindReplayPoke = activeReplayDriverKindMismatch cell.kind
                    let replayDriverActiveNow = lock gate (fun () -> replayDriverActiveDepth > 0)
                    let suppressReentrantReplayPoke =
                        replayDriverActiveNow
                        && attachStatus = "cell"
                        && not suppressCrossKindReplayPoke
                    let suppressedReason =
                        if suppressCrossKindReplayPoke then "cross_kind_active_replay_driver"
                        elif suppressReentrantReplayPoke then "reentrant_replay_driver"
                        else attachStatus
                    let deferredChildAttachStatus =
                        attachStatus = "parent_resume_cell_deferred"
                        || attachStatus = "active_replay_cell_deferred"
                        || attachStatus = "same_node_parent_replay_cell_deferred"
                    // ALPHA923: deferred child cells only imply "await the existing replay tick"
                    // while a replay driver is actually active. Runtime 922 ended with a queued
                    // scheduled_parent_replay after deferred_after_active_driver_ready, but the late
                    // parent_resume_cell_deferred attachment suppressed the only idle poke and left
                    // the process alive until manual ^C. If the driver is idle, wake it exactly once;
                    // the existing single-flight/defer guards still protect active recursion.
                    let idleDeferredChildPoke = deferredChildAttachStatus && not replayDriverActiveNow
                    // ALPHA980: a cross-kind attachment with a queued replay but no active driver
                    // is also an obligation to run, not a reason to await a tick that may not exist.
                    let idleCrossKindPoke = suppressCrossKindReplayPoke && not replayDriverActiveNow
                    let suppressDeferredPoke =
                        (deferredChildAttachStatus && replayDriverActiveNow)
                        || (suppressCrossKindReplayPoke && replayDriverActiveNow)
                        || suppressReentrantReplayPoke
                    if suppressDeferredPoke then
                        let suppressKind = if suppressReentrantReplayPoke then "reentrant_replay_driver" else "deferred_child_cell"
                        DiagJson.emit (
                            sprintf "{\"kind\":\"eval_worklist_deferred_replay_poke_suppressed\",\"event\":%s,\"reason\":%s,\"queue_depth\":%d,\"semantic_payload\":%s,\"single_flight\":1,\"next\":\"await_existing_replay_tick\"}"
                                (esc event) (esc suppressKind) (replayQueueDepth()) (esc suppressedReason))
                        if suppressReentrantReplayPoke then
                            let reentrantCount, reentrantKey = noteReentrantReplayPoke cell
                            if reentrantCount = reentrant_replay_poke_repeat_cap then
                                let blockedCell = { cell with status = "semantic_reentrant_replay_driver_starvation_blocked" }
                                pinTerminalCell event ("reentrant_replay_driver_starvation:" + reentrantKey) blockedCell
                                DiagJson.emit (
                                    sprintf "{\"kind\":\"eval_worklist_reentrant_replay_driver_starvation_blocked\",\"event\":%s,\"incoming_kind\":%s,\"incoming_shape\":%s,\"incoming_site\":%s,\"incoming_node_id\":%d,\"repeat_count\":%d,\"repeat_cap\":%d,\"repeat_key\":%s,\"queue_depth\":%d,\"active_depth\":%d,\"single_flight\":1,\"next\":\"explicit_eval_worklist_reentrant_replay_driver_starvation_required\"}"
                                        (esc event) (esc cell.kind) (esc cell.shape) (esc cell.site) cell.nodeId reentrantCount reentrant_replay_poke_repeat_cap (esc reentrantKey) (replayQueueDepth()) (lock gate (fun () -> replayDriverActiveDepth)))
                            DiagJson.emit (
                                sprintf "{\"kind\":\"eval_worklist_reentrant_replay_driver_poke_suppressed\",\"event\":%s,\"incoming_kind\":%s,\"incoming_shape\":%s,\"incoming_site\":%s,\"incoming_node_id\":%d,\"queue_depth\":%d,\"active_depth\":%d,\"repeat_count\":%d,\"repeat_cap\":%d,\"repeat_key\":%s,\"semantic_payload\":%s,\"single_flight\":1,\"next\":\"continue_active_replay_driver\"}"
                                    (esc event) (esc cell.kind) (esc cell.shape) (esc cell.site) cell.nodeId (replayQueueDepth()) (lock gate (fun () -> replayDriverActiveDepth)) reentrantCount reentrant_replay_poke_repeat_cap (esc reentrantKey) (esc attachStatus))
                        elif suppressCrossKindReplayPoke then
                            let obligation = makeReplayObligation ReplayObligationDefer "cross_kind_active_replay_driver" 0 1 cell
                            emitReplayObligation event "eval_worklist_replay_obligation_deferred" obligation
                            DiagJson.emit (
                                sprintf "{\"kind\":\"eval_worklist_cross_kind_replay_poke_suppressed\",\"event\":%s,\"incoming_kind\":%s,\"incoming_shape\":%s,\"incoming_site\":%s,\"incoming_node_id\":%d,\"queue_depth\":%d,\"semantic_payload\":%s,\"single_flight\":1,\"next\":\"await_existing_replay_tick\"}"
                                    (esc event) (esc cell.kind) (esc cell.shape) (esc cell.site) cell.nodeId (replayQueueDepth()) (esc attachStatus))
                        elif attachStatus = "same_node_parent_replay_cell_deferred" then
                            DiagJson.emit (
                                sprintf "{\"kind\":\"eval_worklist_same_node_replay_poke_suppressed\",\"event\":%s,\"reason\":\"same_node_parent_replay_self_poke\",\"queue_depth\":%d,\"semantic_payload\":%s,\"single_flight\":1,\"next\":\"await_existing_parent_replay_tick\"}"
                                    (esc event) (replayQueueDepth()) (esc attachStatus))
                    else
                        if idleDeferredChildPoke then
                            DiagJson.emit (
                                sprintf "{\"kind\":\"eval_worklist_idle_deferred_replay_poke_resumed\",\"event\":%s,\"reason\":\"idle_deferred_child_cell\",\"queue_depth\":%d,\"semantic_payload\":%s,\"single_flight\":1,\"next\":\"run_replay_driver\"}"
                                    (esc event) (replayQueueDepth()) (esc attachStatus))
                        if idleCrossKindPoke then
                            let obligation = makeReplayObligation ReplayObligationRun "idle_cross_kind_replay_driver" 0 1 cell
                            emitReplayObligation event "eval_worklist_replay_obligation_run" obligation
                            DiagJson.emit (
                                sprintf "{\"kind\":\"eval_worklist_idle_cross_kind_replay_poke_resumed\",\"event\":%s,\"reason\":\"idle_cross_kind_replay_driver\",\"incoming_kind\":%s,\"incoming_shape\":%s,\"incoming_site\":%s,\"incoming_node_id\":%d,\"queue_depth\":%d,\"semantic_payload\":%s,\"single_flight\":1,\"next\":\"run_replay_driver\"}"
                                    (esc event) (esc cell.kind) (esc cell.shape) (esc cell.site) cell.nodeId (replayQueueDepth()) (esc attachStatus))
                        DiagJson.emit (
                            sprintf "{\"kind\":\"eval_worklist_replay_driver_poke\",\"event\":%s,\"reason\":\"semantic_cell_attached\",\"queue_depth\":%d,\"semantic_payload\":%s,\"single_flight\":1,\"next\":\"run_replay_driver\"}"
                                (esc event) (replayQueueDepth()) (esc attachStatus))
                        runReplayDriver event
            with _ -> ()

        let resetStableRootCompleteLedger () =
            lock gate (fun () ->
                stableRootCompleteKey <- ""
                stableRootCompleteCount <- 0)

        let reset () =
            lock gate (fun () ->
                frontier <- None
                frontierTerm <- None
                frontierTy <- None
                activeRun <- false
                replayScheduledKey <- None
                replayQueue <- []
                replayDriverStackFenceQueued <- false
                replayFingerprintRepeats.Clear()
                replayChildScheduleRepeats.Clear()
                reentrantReplayPokeRepeats.Clear()
                parentReplayPreservedRepeats.Clear()
                staleRootRetargetRepeats.Clear()
                leafParentContinuationYieldRepeats.Clear()
                progressYieldCount <- 0)

        let tryPeek () : Frame option =
            lock gate (fun () -> frontier)

        let capture (reason: string) : Frame =
            let fresh = fromCycleFuse reason
            let event, frame =
                lock gate (fun () ->
                    selectKindLocked fresh.kind |> ignore
                    match frontier with
                    | Some old when sameCycle old fresh ->
                        slotSetLocked old
                        "capture:dedup", old
                    | _ ->
                        captureSeq <- captureSeq + 1L
                        frontier <- Some fresh
                        slotSetLocked fresh
                        replayScheduledKey <- None
                        replayQueue <- []
                        // ALPHA427: captures may churn while the same root-complete proof recurs;
                        // keep the cross-attempt stable ledger and let noteRootCompleteHandoff
                        // decide whether the fingerprint is new or repeated.
                        "captured", fresh)
            emit event frame
            emitPanel "capture"
            frame


        let ensureCaptured (reason: string) : Frame option =
            let requestedKind = kindFromReason reason
            if requestedKind = "term" || requestedKind = "ty" then
                lock gate (fun () -> selectKindLocked requestedKind |> ignore)
            match tryPeek() with
            | Some frame when requestedKind = "unknown" || frame.kind = requestedKind -> Some frame
            | Some _ when TermCycleFuse.isTripped() -> Some (capture reason)
            | Some _ -> None
            | None ->
                if TermCycleFuse.isTripped() then Some (capture reason)
                else None


        let private replaceHead (frame': Frame) : Frame =
            lock gate (fun () ->
                frontier <- Some frame'
                frame')

        let promoteHead (event: string) : Frame option =
            try
                let promoted =
                    lock gate (fun () ->
                        match frontier with
                        | Some frame ->
                            let alreadyRunning =
                                frame.status = "ready_explicit_loop" ||
                                frame.status = "tracing_explicit_loop" ||
                                frame.status = "continuation_envelope" ||
                                isSemanticTerminalStatus frame.status
                            let frame' =
                                if alreadyRunning then frame
                                else { frame with status = "ready_explicit_loop"; cursor = min frame.cursor frame.trace.Length }
                            frontier <- Some frame'
                            Some(frame', alreadyRunning)
                        | None -> None)
                match promoted with
                | Some(frame', alreadyRunning) ->
                    emit (event + (if alreadyRunning then ":already_ready" else ":promoted")) frame'
                    DiagJson.emit (
                        sprintf "{\"kind\":\"eval_worklist_consume\",\"event\":%s,\"pending\":%d,\"status\":%s,\"cursor\":%d,\"single_flight\":1,\"next\":%s}"
                            (esc event) (pendingCount()) (esc frame'.status) frame'.cursor
                            (esc (if activeRun then "single_flight_busy" else "bounded_trampoline")))
                    Some frame'
                | None -> None
            with _ -> None

        let private traceAt (frame: Frame) (i: int) =
            try
                if i < 0 || i >= frame.trace.Length then ""
                else
                    let r = frame.trace.[i]
                    let a, b = r.range
                    sprintf "%s:%d:%d-%d:%d" r.path a.line a.character b.line b.character
            with _ -> ""

        // ALPHA1036: global-fuse diagnostics are often the visible terminal, while the
        // actual trace lives in the selected frontier or the TermCycleFuse snapshot.
        // Emit a compact JSON fragment so global-fuse records no longer look empty.
        let globalFuseTraceJson () =
            try
                let frameOpt = lock gate (fun () -> frontier)
                let frame, source =
                    match frameOpt with
                    | Some frame when frame.trace.Length > 0 -> frame, "frontier"
                    | _ -> fromCycleFuse "global_fuse_trace_context", "cycle_fuse"
                let traceN = frame.trace.Length
                let head =
                    frame.trace
                    |> List.truncate 4
                    |> List.mapi (fun i _ -> sprintf "%d:%s" i (traceAt frame i))
                    |> String.concat "|"
                let tail =
                    let skipN = max 0 (traceN - 4)
                    frame.trace
                    |> List.skip skipN
                    |> List.mapi (fun i _ -> sprintf "%d:%s" (skipN + i) (traceAt frame (skipN + i)))
                    |> String.concat "|"
                sprintf "\"trace_source\":%s,\"trace_lines\":%d,\"trace_cursor\":%d,\"trace_site\":%s,\"trace_key\":%s,\"trace_head\":%s,\"trace_tail\":%s"
                    (esc source) traceN frame.cursor (esc frame.site) (esc frame.key) (esc head) (esc tail)
            with _ ->
                "\"trace_source\":\"error\",\"trace_lines\":0,\"trace_cursor\":0,\"trace_site\":\"\",\"trace_key\":\"\",\"trace_head\":\"\",\"trace_tail\":\"\""

        let private adapterPayload (frame: Frame) =
            try
                let traceN = frame.trace.Length
                let head =
                    frame.trace
                    |> List.truncate 8
                    |> List.mapi (fun i _ -> sprintf "%d:%s" i (traceAt frame i))
                    |> String.concat "|"
                let tail =
                    let skipN = max 0 (traceN - 8)
                    frame.trace
                    |> List.skip skipN
                    |> List.mapi (fun i _ -> sprintf "%d:%s" (skipN + i) (traceAt frame (skipN + i)))
                    |> String.concat "|"
                let focus =
                    if traceN <= 0 then ""
                    else traceAt frame (min (max 0 frame.cursor) (traceN - 1))
                let replayMode =
                    match frame.kind with
                    | "term" -> "term_replay"
                    | "ty" -> "ty_replay"
                    | _ -> "unknown_replay"
                sprintf "replay_continuation(mode=%s,kind=%s,key=%s,site=%s,cursor=%d/%d,focus=%s,semantic=%s,head=%s,tail=%s)"
                    replayMode frame.kind frame.key frame.site frame.cursor traceN focus (semanticPayloadOf frame) head tail
            with _ ->
                sprintf "replay_continuation(kind=%s,key=%s,site=%s,cursor=%d/%d,semantic=%s)"
                    frame.kind frame.key frame.site frame.cursor frame.trace.Length (semanticPayloadOf frame)

        let private nextFor (frame: Frame) =
            match frame.status with
            | "semantic_replay_driver_exception_blocked" -> "explicit_eval_worklist_replay_driver_exception_required"
            | "semantic_replay_payload_missing_blocked" -> "explicit_eval_worklist_replay_payload_required"
            | "semantic_seq_type_error_blocked" -> "explicit_eval_worklist_seq_type_error_required"
            | "semantic_replay_child_schedule_repeat_blocked" -> "explicit_eval_worklist_replay_child_schedule_repeat_required"
            | "semantic_let_success_apply_exception_blocked" -> "explicit_eval_worklist_let_success_apply_exception_required"
            | "semantic_let_success_all_ready_apply_blocked" -> "explicit_eval_worklist_let_success_all_ready_apply_required"
            | "semantic_let_success_apply_continuation_blocked" -> "explicit_eval_worklist_let_success_apply_continuation_required"
            | "semantic_type_apply_forall_body_stepper_blocked" -> "explicit_eval_worklist_type_apply_forall_body_stepper_required"
            | "semantic_apply_continuation_after_seq_unknown_blocked" -> "explicit_eval_worklist_apply_continuation_after_seq_unknown_required"
            | "semantic_apply_continuation_exception_blocked" -> "explicit_eval_worklist_apply_continuation_exception_required"
            | "semantic_deferred_function_replay_exception_blocked" -> "explicit_eval_worklist_deferred_function_replay_exception_required"
            | "semantic_replay_fingerprint_repeat_blocked" -> "explicit_eval_worklist_replay_fingerprint_repeat_required"
            | "semantic_joinpoint_term_stepper_blocked" -> "explicit_eval_worklist_joinpoint_term_stepper_required"
            | "semantic_macro_thunk_missing_blocked" -> "explicit_eval_worklist_macro_thunk_required"
            | "semantic_tjoinpoint_stepper_blocked" -> "explicit_eval_worklist_tjoinpoint_stepper_required"
            | "semantic_joinpoint_value_blocked" -> "explicit_eval_worklist_joinpoint_value_required"
            | "semantic_literal_op_body_stepper_blocked" -> "explicit_eval_worklist_literal_op_body_stepper_required"
            | "semantic_dynamic_join_apply_blocked" -> "explicit_eval_worklist_dynamic_join_apply_required"
            | "semantic_type_apply_nominal_constructor_stepper_blocked" -> "explicit_eval_worklist_type_apply_nominal_constructor_stepper_required"
            | "semantic_nominal_constructor_stepper_blocked" -> "explicit_eval_worklist_nominal_constructor_stepper_required"
            | "semantic_if_unknown_return_condition_blocked" -> "explicit_eval_worklist_if_unknown_return_condition_required"
            | "semantic_parent_continuation_cycle_blocked" -> "explicit_eval_worklist_parent_continuation_cycle_required"
            | "semantic_type_variable_value_missing_blocked" -> "explicit_eval_worklist_type_variable_env_required"
            | "semantic_stale_root_retarget_blocked" -> "explicit_eval_worklist_stale_root_retarget_required"
            | "semantic_payload_required" -> "wire_eval_payload"
            | "semantic_step_partial" -> "explicit_eval_worklist_real_stepper_required"
            | "semantic_step_done" -> "explicit_eval_worklist_real_stepper_required"
            | "semantic_root_complete" -> "attempt_build"
            | "semantic_leaf_complete" -> "explicit_eval_worklist_parent_continuation_required"
            | "continuation_envelope" -> "schedule_term_ty_replay"
            | "tracing_explicit_loop" -> "advance_trace_cursor"
            | "ready_explicit_loop" -> "bounded_trampoline"
            | status when isTerminalContractStatus status -> terminalContractNext status
            | _ -> "bounded_trampoline"

        // ALPHA466: a semantic_leaf_complete frame with no registered parent
        // continuation is not a root proof and must not spin the retry drain forever.
        // Alpha465 proved real replay progress up to term_type_apply_type_arg_scheduled
        // and dynamic join leaf completion, but the jp_wait_cycle_drain tail then kept
        // re-entering explicit_eval_worklist_parent_continuation_required while another
        // kind-local frontier was pending.  Park the leaf in its kind slot and yield the
        // canonical frontier to the alternate live kind; this is fail-closed because it
        // never marks semantic_root_complete and never opens the writer gate.
        let private tryYieldLeafParentContinuationBlocked (event: string) (frame: Frame) : Frame option =
            try
                let switched =
                    lock gate (fun () ->
                        let noParentContinuation =
                            match frame.semanticCell with
                            | Some cell -> EvalReplayValueStore.tryParentContinuation cell.nodeId |> Option.isNone
                            | None -> true
                        let blockedLeaf =
                            frame.status = "semantic_leaf_complete"
                            && replayQueue.IsEmpty
                            && noParentContinuation
                            && not (frameReplayCompleteAny frame)
                        if not blockedLeaf then None
                        else
                            slotSetLocked frame
                            let alternate =
                                let other =
                                    if frame.kind = "term" then frontierTy
                                    elif frame.kind = "ty" then frontierTerm
                                    else None
                                match other with
                                | Some alt when not (sameCycle alt frame) && alt.status <> "semantic_leaf_complete" && alt.status <> "semantic_root_complete" -> Some alt
                                | _ -> None
                            let tryRepairAlternateTerminalLetCycleLocked (alt: Frame) : Frame option =
                                match alt.semanticCell with
                                | Some cell when alt.status = "semantic_parent_continuation_cycle_blocked"
                                                 && alt.kind = "term"
                                                 && cell.kind = "term"
                                                 && cell.shape = "ELet" ->
                                    match EvalReplayValueStore.tryLetSpine cell.nodeId with
                                    | Some spine ->
                                        let makeChildReplay role shape nodeId status nextLabel =
                                            let repairKey = sprintf "%d|leaf_yield|%s|%d" cell.nodeId role nodeId
                                            let attempt = noteLetTerminalCycleRepairLocked repairKey
                                            if attempt > 8 then None
                                            else
                                                EvalReplayValueStore.putParentContinuation nodeId {
                                                    parentKind = cell.kind
                                                    parentShape = cell.shape
                                                    parentNodeId = cell.nodeId
                                                    role = role
                                                }
                                                let childCell = { cell with shape = shape; nodeId = nodeId; status = status; step = 0 }
                                                let repaired =
                                                    { alt with
                                                        status = "continuation_envelope"
                                                        cursor = alt.trace.Length
                                                        reason = alt.reason + ":leaf_yield_terminal_let_cycle_replay"
                                                        semanticPayload = Some(formatCellPayload childCell)
                                                        semanticCell = Some childCell }
                                                frontier <- Some repaired
                                                slotSetLocked repaired
                                                replayScheduledKey <- None
                                                replayQueue <- []
                                                noteProgressYieldLocked ()
                                                DiagJson.emit (
                                                    sprintf "{\"kind\":\"eval_worklist_terminal_let_cycle_replay\",\"event\":%s,\"route\":\"leaf_yield\",\"let_node_id\":%d,\"role\":%s,\"attempt\":%d,\"cell\":%s,\"pending\":%d,\"single_flight\":1,\"next\":%s}"
                                                        (esc event) cell.nodeId (esc role) attempt (esc (formatCell childCell)) (pendingCount()) (esc nextLabel))
                                                Some repaired
                                        let missingBody =
                                            spine.bodyNodeIds
                                            |> Array.mapi (fun i nodeId -> i, nodeId)
                                            |> Array.tryFind (fun (_, nodeId) -> not (EvalReplayValueStore.tryTermReady nodeId))
                                        match missingBody with
                                        | Some (i, nodeId) ->
                                            let shape = if i < spine.bodyShapes.Length then spine.bodyShapes.[i] else "unknown"
                                            makeChildReplay (sprintf "let_body_%d" i) shape nodeId "let_body_ready" "schedule_let_body_replay"
                                        | None when not (EvalReplayValueStore.tryTermReady spine.successNodeId) ->
                                            makeChildReplay "let_success" spine.successShape spine.successNodeId "let_success_ready" "schedule_let_success_replay"
                                        | None -> None
                                    | None -> None
                                | _ -> None
                            match alternate with
                            | Some alt ->
                                let yieldCount, yieldKey =
                                    if event = "retry_stop_drain" then noteLeafParentContinuationYieldLocked frame alt
                                    else 1, ""
                                let leafYieldChurnCapped =
                                    event = "retry_stop_drain"
                                    && yieldCount > leaf_parent_continuation_yield_cap
                                    && alt.status = "continuation_envelope"
                                    && pendingCount() > 0
                                let leafYieldCrossKindContinuationHandoff =
                                    leafYieldChurnCapped
                                    && frame.kind = "ty"
                                    && frame.status = "semantic_leaf_complete"
                                    && frameCellShapeIn ["EApply"] frame
                                    && alt.kind = "term"
                                    && alt.status = "continuation_envelope"
                                    && frameHasSemanticEvidence alt
                                    && (match frame.semanticCell with
                                        | Some cell ->
                                            cell.kind = "term"
                                            && cell.shape = "EApply"
                                            && cell.status = "semantic_leaf_complete"
                                        | None -> false)
                                if leafYieldCrossKindContinuationHandoff then
                                    // ALPHA881: runtime 880 proved the generic churn cap can stop
                                    // just after it schedules a live runtime fixture path:23 continuation
                                    // for the tests() leaf at spiral.spi:2670.  This exact handoff is
                                    // not a terminal missing-parent contract yet: preserve the selected
                                    // continuation envelope and its existing replay queue so the drain
                                    // can execute the scheduled replay instead of clearing it.
                                    let handoffFrame = { alt with reason = alt.reason + ":leaf_parent_testing_handoff_churn_deferred" }
                                    frontier <- Some handoffFrame
                                    slotSetLocked handoffFrame
                                    replayScheduledKey <- None
                                    noteProgressYieldLocked ()
                                    DiagJson.emit (
                                        sprintf "{\"kind\":\"eval_worklist_leaf_parent_testing_handoff_churn_deferred\",\"event\":%s,\"leaf_kind\":%s,\"leaf_site\":%s,\"leaf_status\":%s,\"selected_kind\":%s,\"selected_status\":%s,\"selected_site\":%s,\"count\":%d,\"cap\":%d,\"pending\":%d,\"yield_key\":%s,\"single_flight\":1,\"next\":\"drain_selected_frontier\"}"
                                            (esc event) (esc frame.kind) (esc frame.site) (esc frame.status) (esc handoffFrame.kind) (esc handoffFrame.status) (esc handoffFrame.site) yieldCount leaf_parent_continuation_yield_cap (pendingCount()) (esc yieldKey))
                                    Some handoffFrame
                                elif leafYieldChurnCapped then
                                    let terminalFrame =
                                        { frame with
                                            status = "semantic_leaf_parent_continuation_missing_blocked"
                                            reason = frame.reason + ":leaf_parent_yield_churn_capped" }
                                    frontier <- Some terminalFrame
                                    slotSetLocked terminalFrame
                                    replayScheduledKey <- None
                                    replayQueue <- []
                                    pinTerminalContractLocked event terminalFrame
                                    DiagJson.emit (
                                        sprintf "{\"kind\":\"eval_worklist_leaf_parent_yield_churn_capped\",\"event\":%s,\"leaf_kind\":%s,\"leaf_site\":%s,\"leaf_status\":%s,\"selected_kind\":%s,\"selected_status\":%s,\"selected_site\":%s,\"count\":%d,\"cap\":%d,\"pending\":%d,\"yield_key\":%s,\"single_flight\":1,\"next\":\"explicit_eval_worklist_leaf_parent_continuation_required\"}"
                                            (esc event) (esc frame.kind) (esc frame.site) (esc frame.status) (esc alt.kind) (esc alt.status) (esc alt.site) yieldCount leaf_parent_continuation_yield_cap (pendingCount()) (esc yieldKey))
                                    Some terminalFrame
                                else
                                    match tryRepairAlternateTerminalLetCycleLocked alt with
                                    | Some repaired -> Some repaired
                                    | None ->
                                        frontier <- Some alt
                                        replayScheduledKey <- None
                                        replayQueue <- []
                                        Some alt
                            | None -> None)
                match switched with
                | Some alt ->
                    DiagJson.emit (
                        sprintf "{\"kind\":\"eval_worklist_leaf_parent_continuation_yielded\",\"event\":%s,\"blocked_kind\":%s,\"blocked_status\":%s,\"selected_kind\":%s,\"selected_status\":%s,\"pending\":%d,\"single_flight\":1,\"next\":\"drain_selected_frontier\"}"
                            (esc event) (esc frame.kind) (esc frame.status) (esc alt.kind) (esc alt.status) (pendingCount()))
                    Some alt
                | None -> None
            with _ -> None

        // ALPHA490: a parent-continuation cycle blocker is useful evidence but not a
        // reason to keep rebuilding the same continuation envelope.  Park the blocked
        // frame in its kind slot and yield to another already-live frontier when one
        // exists.  If no alternate exists, leave the blocked frame terminal so retry_stop
        // reports explicit_eval_worklist_parent_continuation_cycle_required instead of
        // spinning another replay envelope.
        let private tryYieldParentContinuationCycleBlocked (event: string) (frame: Frame) : Frame option =
            try
                let makeTerminalCompositeReplayLocked (cell: ReplayCell) role childKind shape nodeId status nextLabel =
                    let repairKey = sprintf "%s|%d|%s|%s|%d" cell.shape cell.nodeId role childKind nodeId
                    let attempt = noteCompositeTerminalCycleRepairLocked repairKey
                    if attempt > 12 then None
                    else
                        EvalReplayValueStore.putParentContinuation nodeId {
                            parentKind = cell.kind
                            parentShape = cell.shape
                            parentNodeId = cell.nodeId
                            role = role
                        }
                        let childCell =
                            { cell with
                                kind = childKind
                                shape = shape
                                nodeId = nodeId
                                status = status
                                step = 0 }
                        let repaired =
                            { frame with
                                kind = childKind
                                status = "continuation_envelope"
                                cursor = frame.trace.Length
                                reason = frame.reason + ":terminal_composite_cycle_replay"
                                semanticPayload = Some(formatCellPayload childCell)
                                semanticCell = Some childCell }
                        frontier <- Some repaired
                        slotSetLocked repaired
                        replayScheduledKey <- None
                        replayQueue <- []
                        noteProgressYieldLocked ()
                        DiagJson.emit (
                            sprintf "{\"kind\":\"eval_worklist_terminal_composite_cycle_replay\",\"event\":%s,\"parent_kind\":%s,\"parent_shape\":%s,\"parent_node_id\":%d,\"role\":%s,\"child_kind\":%s,\"child_shape\":%s,\"child_node_id\":%d,\"attempt\":%d,\"cell\":%s,\"pending\":%d,\"single_flight\":1,\"next\":%s}"
                                (esc event) (esc cell.kind) (esc cell.shape) cell.nodeId (esc role) (esc childKind) (esc shape) nodeId attempt (esc (formatCell childCell)) (pendingCount()) (esc nextLabel))
                        Some repaired

                let terminalCompositeRootEligible (cell: ReplayCell) =
                    cell.kind = frame.kind
                    && (frame.cursor >= frame.trace.Length || cell.cursor >= frame.trace.Length)

                let terminalCompositeStatusAndNext (cell: ReplayCell) =
                    if terminalCompositeRootEligible cell then
                        "semantic_root_complete", "attempt_build", "eval_worklist_terminal_composite_cycle_root_resolved"
                    else
                        "semantic_leaf_complete", "explicit_eval_worklist_parent_continuation_required", "eval_worklist_terminal_composite_cycle_value_resolved"

                let clearParentCycleTerminalAfterCompositeRootLocked (resolvedStatus: string) (cell: ReplayCell) =
                    if resolvedStatus = "semantic_root_complete" then
                        let matches (pinned: Frame) =
                            pinned.status = "semantic_parent_continuation_cycle_blocked"
                            && (pinned.key = frame.key
                                || pinned.site = frame.site
                                || (match pinned.semanticCell with
                                    | Some pinnedCell -> pinnedCell.kind = cell.kind && pinnedCell.nodeId = cell.nodeId
                                    | None -> false))
                        let pinnedCleared =
                            match pinnedTerminalContract with
                            | Some pinned when matches pinned ->
                                pinnedTerminalContract <- None
                                true
                            | _ -> false
                        let durableCleared =
                            match durableTerminalContract with
                            | Some pinned when matches pinned ->
                                durableTerminalContract <- None
                                true
                            | _ -> false
                        if pinnedCleared || durableCleared then
                            DiagJson.emit (
                                sprintf "{\"kind\":\"eval_worklist_parent_cycle_terminal_cleared_after_composite_root\",\"event\":%s,\"parent_kind\":%s,\"parent_shape\":%s,\"parent_node_id\":%d,\"pinned_cleared\":%b,\"durable_cleared\":%b,\"pending\":%d,\"single_flight\":1,\"next\":\"attempt_build_without_stale_terminal_contract\"}"
                                    (esc event) (esc cell.kind) (esc cell.shape) cell.nodeId pinnedCleared durableCleared (pendingCount()))

                let completeCompositeIfReadyLocked (cell: ReplayCell) =
                    match EvalReplayValueStore.tryTermDetailed cell.nodeId with
                    | Choice1Of2 value ->
                        EvalReplayValueStore.putTermValue cell.nodeId value
                        let resolvedStatus, resolvedNext, resolvedKind = terminalCompositeStatusAndNext cell
                        let resolvedCell = { cell with status = resolvedStatus }
                        let resolved =
                            { frame with
                                kind = cell.kind
                                status = resolvedStatus
                                semanticCell = Some resolvedCell
                                semanticPayload = Some(formatCellPayload resolvedCell) }
                        clearParentCycleTerminalAfterCompositeRootLocked resolvedStatus cell
                        frontier <- Some resolved
                        slotSetLocked resolved
                        noteProgressYieldLocked ()
                        DiagJson.emit (
                            sprintf "{\"kind\":%s,\"event\":%s,\"parent_kind\":%s,\"parent_shape\":%s,\"parent_node_id\":%d,\"cell\":%s,\"pending\":%d,\"single_flight\":1,\"next\":%s}"
                                (esc resolvedKind) (esc event) (esc cell.kind) (esc cell.shape) cell.nodeId (esc (formatCell resolvedCell)) (pendingCount()) (esc resolvedNext))
                        Some resolved
                    | Choice2Of2 detail ->
                        DiagJson.emit (
                            sprintf "{\"kind\":\"eval_worklist_terminal_composite_cycle_value_blocked\",\"event\":%s,\"parent_kind\":%s,\"parent_shape\":%s,\"parent_node_id\":%d,\"detail\":%s,\"pending\":%d,\"single_flight\":1,\"next\":\"drain_selected_frontier\"}"
                                (esc event) (esc cell.kind) (esc cell.shape) cell.nodeId (esc detail) (pendingCount()))
                        None

                let completeTypeCompositeIfReadyLocked (cell: ReplayCell) =
                    match EvalReplayValueStore.tryTypeDetailed cell.nodeId with
                    | Choice1Of2 value ->
                        EvalReplayValueStore.putTypeValue cell.nodeId value
                        let resolvedStatus, resolvedNext, resolvedKind = terminalCompositeStatusAndNext cell
                        let resolvedCell = { cell with status = resolvedStatus }
                        let resolved =
                            { frame with
                                kind = cell.kind
                                status = resolvedStatus
                                semanticCell = Some resolvedCell
                                semanticPayload = Some(formatCellPayload resolvedCell) }
                        clearParentCycleTerminalAfterCompositeRootLocked resolvedStatus cell
                        frontier <- Some resolved
                        slotSetLocked resolved
                        noteProgressYieldLocked ()
                        DiagJson.emit (
                            sprintf "{\"kind\":%s,\"event\":%s,\"parent_kind\":%s,\"parent_shape\":%s,\"parent_node_id\":%d,\"cell\":%s,\"pending\":%d,\"single_flight\":1,\"next\":%s}"
                                (esc (resolvedKind + "_ty")) (esc event) (esc cell.kind) (esc cell.shape) cell.nodeId (esc (formatCell resolvedCell)) (pendingCount()) (esc resolvedNext))
                        Some resolved
                    | Choice2Of2 detail ->
                        DiagJson.emit (
                            sprintf "{\"kind\":\"eval_worklist_terminal_type_composite_cycle_value_blocked\",\"event\":%s,\"parent_kind\":%s,\"parent_shape\":%s,\"parent_node_id\":%d,\"detail\":%s,\"pending\":%d,\"single_flight\":1,\"next\":\"drain_selected_frontier\"}"
                                (esc event) (esc cell.kind) (esc cell.shape) cell.nodeId (esc detail) (pendingCount()))
                        None

                let tryRepairTerminalSeqCycleLocked (cell: ReplayCell) =
                    match EvalReplayValueStore.trySeqSpine cell.nodeId with
                    | Some spine ->
                        if not (EvalReplayValueStore.tryTermReady spine.firstNodeId) then
                            makeTerminalCompositeReplayLocked cell "seq_first" "term" spine.firstShape spine.firstNodeId "seq_first_ready" "schedule_seq_first_replay"
                        elif not (EvalReplayValueStore.tryTermReady spine.secondNodeId) then
                            makeTerminalCompositeReplayLocked cell "seq_second" "term" spine.secondShape spine.secondNodeId "seq_second_ready" "schedule_seq_second_replay"
                        else
                            completeCompositeIfReadyLocked cell
                    | None -> None

                let tryRepairTerminalLetCycleLocked (cell: ReplayCell) =
                    match EvalReplayValueStore.tryLetSpine cell.nodeId with
                    | Some spine ->
                        let missingBody =
                            spine.bodyNodeIds
                            |> Array.mapi (fun i nodeId -> i, nodeId)
                            |> Array.tryFind (fun (_, nodeId) -> not (EvalReplayValueStore.tryTermReady nodeId))
                        match missingBody with
                        | Some (i, nodeId) ->
                            let shape = if i < spine.bodyShapes.Length then spine.bodyShapes.[i] else "unknown"
                            makeTerminalCompositeReplayLocked cell (sprintf "let_body_%d" i) "term" shape nodeId "let_body_ready" "schedule_let_body_replay"
                        | None when not (EvalReplayValueStore.tryTermReady spine.successNodeId) ->
                            makeTerminalCompositeReplayLocked cell "let_success" "term" spine.successShape spine.successNodeId "let_success_ready" "schedule_let_success_replay"
                        | None -> completeCompositeIfReadyLocked cell
                    | None -> None

                let tryRepairTerminalApplyCycleLocked (cell: ReplayCell) =
                    match EvalReplayValueStore.tryApplySpine cell.nodeId with
                    | Some spine ->
                        if not (EvalReplayValueStore.tryTermReady spine.headNodeId) then
                            makeTerminalCompositeReplayLocked cell "apply_head" "term" spine.headShape spine.headNodeId "apply_head_ready" "schedule_apply_head_replay"
                        else
                            let missingArg =
                                spine.argNodeIds
                                |> Array.mapi (fun i nodeId -> i, nodeId)
                                |> Array.tryFind (fun (_, nodeId) -> not (EvalReplayValueStore.tryTermReady nodeId))
                            match missingArg with
                            | Some (i, nodeId) ->
                                let shape = if i < spine.argShapes.Length then spine.argShapes.[i] else "unknown"
                                makeTerminalCompositeReplayLocked cell (sprintf "apply_arg_%d" i) "term" shape nodeId "apply_arg_ready" "schedule_apply_arg_replay"
                            | None -> completeCompositeIfReadyLocked cell
                    | None -> None

                let tryRepairTerminalTypeApplyCycleLocked (cell: ReplayCell) =
                    match EvalReplayValueStore.tryTypeApplySpine cell.nodeId with
                    | Some spine ->
                        if not (EvalReplayValueStore.tryTermReady spine.funcNodeId) then
                            makeTerminalCompositeReplayLocked cell "type_apply_function" "term" spine.funcShape spine.funcNodeId "type_apply_function_ready" "schedule_type_apply_function_replay"
                        else
                            match EvalReplayValueStore.tryType spine.typeNodeId with
                            | None ->
                                makeTerminalCompositeReplayLocked cell "type_apply_type_arg" "ty" spine.typeShape spine.typeNodeId "type_apply_type_arg_ready" "schedule_type_apply_type_arg_replay"
                            | Some _ ->
                                match EvalReplayValueStore.tryTypeApplyBodyValueAt cell.nodeId with
                                | Some value ->
                                    EvalReplayValueStore.putTermValue cell.nodeId value
                                    match EvalReplayValueStore.tryParentContinuation cell.nodeId with
                                    | Some cont when cont.parentNodeId <> cell.nodeId ->
                                        let parentCell =
                                            { cell with
                                                kind = cont.parentKind
                                                shape = cont.parentShape
                                                nodeId = cont.parentNodeId
                                                status = "parent_continuation_ready"
                                                step = cell.step + 1 }
                                        let repaired =
                                            { frame with
                                                kind = cont.parentKind
                                                status = "continuation_envelope"
                                                cursor = frame.trace.Length
                                                reason = frame.reason + ":terminal_type_apply_body_parent_resume"
                                                semanticCell = Some parentCell
                                                semanticPayload = Some(formatCellPayload parentCell) }
                                        frontier <- Some repaired
                                        slotSetLocked repaired
                                        replayScheduledKey <- None
                                        replayQueue <- []
                                        noteProgressYieldLocked ()
                                        DiagJson.emit (
                                            sprintf "{\"kind\":\"eval_worklist_terminal_type_apply_cycle_body_parent_resumed\",\"event\":%s,\"child\":%s,\"parent_kind\":%s,\"parent_shape\":%s,\"parent_node_id\":%d,\"role\":%s,\"pending\":%d,\"single_flight\":1,\"next\":\"resume_parent_replay_driver\"}"
                                                (esc event) (esc (formatCell cell)) (esc cont.parentKind) (esc cont.parentShape) cont.parentNodeId (esc cont.role) (pendingCount()))
                                        Some repaired
                                    | _ ->
                                        let resolvedStatus, resolvedNext, resolvedKind = terminalCompositeStatusAndNext cell
                                        let resolvedCell = { cell with status = resolvedStatus }
                                        let resolved =
                                            { frame with
                                                kind = cell.kind
                                                status = resolvedStatus
                                                semanticCell = Some resolvedCell
                                                semanticPayload = Some(formatCellPayload resolvedCell) }
                                        frontier <- Some resolved
                                        slotSetLocked resolved
                                        noteProgressYieldLocked ()
                                        DiagJson.emit (
                                            sprintf "{\"kind\":%s,\"event\":%s,\"parent_node_id\":%d,\"cell\":%s,\"pending\":%d,\"single_flight\":1,\"next\":%s}"
                                                (esc (resolvedKind + "_type_apply_body")) (esc event) cell.nodeId (esc (formatCell resolvedCell)) (pendingCount()) (esc resolvedNext))
                                        Some resolved
                                | None -> completeCompositeIfReadyLocked cell
                    | None -> None

                let tryRepairTerminalTypeFunCycleLocked (cell: ReplayCell) =
                    match EvalReplayValueStore.tryTypeFunSpine cell.nodeId with
                    | Some spine ->
                        match EvalReplayValueStore.tryType spine.argNodeId, EvalReplayValueStore.tryType spine.bodyNodeId with
                        | None, _ ->
                            makeTerminalCompositeReplayLocked cell "tfun_arg" "ty" spine.argShape spine.argNodeId "tfun_arg_ready" "schedule_tfun_arg_replay"
                        | _, None ->
                            makeTerminalCompositeReplayLocked cell "tfun_body" "ty" spine.bodyShape spine.bodyNodeId "tfun_body_ready" "schedule_tfun_body_replay"
                        | Some argTy, Some bodyTy ->
                            EvalReplayValueStore.putTypeValue cell.nodeId (YFun(argTy, bodyTy, spine.funType))
                            completeTypeCompositeIfReadyLocked cell
                    | None -> completeTypeCompositeIfReadyLocked cell

                let tryRepairTerminalTypePairCycleLocked (cell: ReplayCell) =
                    match EvalReplayValueStore.tryTypePairSpine cell.nodeId with
                    | Some spine ->
                        match EvalReplayValueStore.tryType spine.leftNodeId, EvalReplayValueStore.tryType spine.rightNodeId with
                        | None, _ ->
                            makeTerminalCompositeReplayLocked cell "tpair_left" "ty" spine.leftShape spine.leftNodeId "tpair_left_ready" "schedule_tpair_left_replay"
                        | _, None ->
                            makeTerminalCompositeReplayLocked cell "tpair_right" "ty" spine.rightShape spine.rightNodeId "tpair_right_ready" "schedule_tpair_right_replay"
                        | Some leftTy, Some rightTy ->
                            EvalReplayValueStore.putTypeValue cell.nodeId (YPair(leftTy, rightTy))
                            completeTypeCompositeIfReadyLocked cell
                    | None -> completeTypeCompositeIfReadyLocked cell

                let tryRepairTerminalRecordWithCycleLocked (cell: ReplayCell) =
                    match EvalReplayValueStore.tryRecordWithSpine cell.nodeId with
                    | Some spine ->
                        let missingChild =
                            spine.childNodeIds
                            |> Array.mapi (fun i nodeId -> i, nodeId)
                            |> Array.tryFind (fun (_, nodeId) -> not (EvalReplayValueStore.tryTermReady nodeId))
                        match missingChild with
                        | Some (i, nodeId) ->
                            let shape = if i < spine.childShapes.Length then spine.childShapes.[i] else "unknown"
                            let role = if i < spine.childRoles.Length then spine.childRoles.[i] else sprintf "record_with_child_%d" i
                            makeTerminalCompositeReplayLocked cell role "term" shape nodeId "record_with_child_ready" "schedule_record_with_child_replay"
                        | None -> completeCompositeIfReadyLocked cell
                    | None -> None

                let tryRepairTerminalCompositeCycleLocked () =
                    match frame.semanticCell with
                    | Some cell when frame.status = "semantic_parent_continuation_cycle_blocked"
                                     && cell.kind = "term" ->
                        match cell.shape with
                        | "ELet" -> tryRepairTerminalLetCycleLocked cell
                        | "ESeq" -> tryRepairTerminalSeqCycleLocked cell
                        | "EApply" -> tryRepairTerminalApplyCycleLocked cell
                        | "ETypeApply" -> tryRepairTerminalTypeApplyCycleLocked cell
                        | "ERecordWith" -> tryRepairTerminalRecordWithCycleLocked cell
                        | _ -> None
                    | Some cell when frame.status = "semantic_parent_continuation_cycle_blocked"
                                     && cell.kind = "ty" ->
                        match cell.shape with
                        | "TFun" -> tryRepairTerminalTypeFunCycleLocked cell
                        | "TPair" -> tryRepairTerminalTypePairCycleLocked cell
                        | _ -> completeTypeCompositeIfReadyLocked cell
                    | _ -> None

                let switched =
                    lock gate (fun () ->
                        let blockedCycle =
                            frame.status = "semantic_parent_continuation_cycle_blocked"
                            && replayQueue.IsEmpty
                            && not (frameReplayCompleteAny frame)
                        if not blockedCycle then None
                        else
                            match tryRepairTerminalCompositeCycleLocked () with
                            | Some repaired -> Some repaired
                            | None ->
                                slotSetLocked frame
                                let candidates =
                                    [ frontierTerm; frontierTy ]
                                    |> List.choose (fun x -> x)
                                    |> List.filter (fun alt ->
                                        not (sameCycle alt frame)
                                        && alt.status <> "semantic_parent_continuation_cycle_blocked"
                                        && alt.status <> "semantic_replay_fingerprint_repeat_blocked"
                                        && alt.status <> "semantic_joinpoint_term_stepper_blocked"
                                        && alt.status <> "semantic_joinpoint_value_blocked"
                                        && alt.status <> "semantic_replay_payload_missing_blocked"
                                        && alt.status <> "semantic_macro_thunk_missing_blocked"
                                        && alt.status <> "semantic_tjoinpoint_stepper_blocked"
                                        && alt.status <> "semantic_literal_op_body_stepper_blocked"
                                        && alt.status <> "semantic_leaf_complete")
                                let selected =
                                    match candidates |> List.tryFind (fun alt -> alt.status = "semantic_root_complete") with
                                    | Some root -> Some root
                                    | None ->
                                        match candidates |> List.tryFind (fun alt -> alt.status = "continuation_envelope" || alt.status = "ready_explicit_loop" || alt.status = "tracing_explicit_loop") with
                                        | Some live -> Some live
                                        | None -> candidates |> List.tryHead
                                match selected with
                                | Some alt ->
                                    frontier <- Some alt
                                    replayScheduledKey <- None
                                    replayQueue <- []
                                    Some alt
                                | None -> None)
                match switched with
                | Some alt when alt.status = "continuation_envelope"
                                && (alt.reason.Contains("terminal_let_cycle_replay")
                                    || alt.reason.Contains("terminal_composite_cycle_replay")) ->
                    Some alt
                | Some alt ->
                    DiagJson.emit (
                        sprintf "{\"kind\":\"eval_worklist_parent_continuation_cycle_yielded\",\"event\":%s,\"blocked_kind\":%s,\"blocked_status\":%s,\"selected_kind\":%s,\"selected_status\":%s,\"pending\":%d,\"single_flight\":1,\"next\":\"drain_selected_frontier\"}"
                            (esc event) (esc frame.kind) (esc frame.status) (esc alt.kind) (esc alt.status) (pendingCount()))
                    Some alt
                | None -> None
            with _ -> None

        // ALPHA491: a TV child with no materialized type environment is terminal evidence,
        // but should not monopolize retry_stop while a different kind-local frontier is live.
        // Park it and yield to another non-terminal frontier when one exists.
        let private tryYieldTypeVariableValueMissingBlocked (event: string) (frame: Frame) : Frame option =
            try
                let switched =
                    lock gate (fun () ->
                        let blockedTypeVar =
                            frame.status = "semantic_type_variable_value_missing_blocked"
                            && replayQueue.IsEmpty
                            && not (frameReplayCompleteAny frame)
                        if not blockedTypeVar then None
                        else
                            slotSetLocked frame
                            let candidates =
                                [ frontierTerm; frontierTy ]
                                |> List.choose (fun x -> x)
                                |> List.filter (fun alt ->
                                    not (sameCycle alt frame)
                                    && alt.status <> "semantic_type_variable_value_missing_blocked"
                                    && alt.status <> "semantic_parent_continuation_cycle_blocked"
                                    && alt.status <> "semantic_replay_fingerprint_repeat_blocked"
                                    && alt.status <> "semantic_replay_payload_missing_blocked"
                                    && alt.status <> "semantic_macro_thunk_missing_blocked"
                                    && alt.status <> "semantic_tjoinpoint_stepper_blocked"
                                    && alt.status <> "semantic_literal_op_body_stepper_blocked"
                                    && alt.status <> "semantic_leaf_complete")
                            let selected =
                                match candidates |> List.tryFind (fun alt -> alt.status = "semantic_root_complete") with
                                | Some root -> Some root
                                | None ->
                                    match candidates |> List.tryFind (fun alt -> alt.status = "continuation_envelope" || alt.status = "ready_explicit_loop" || alt.status = "tracing_explicit_loop") with
                                    | Some live -> Some live
                                    | None -> candidates |> List.tryHead
                            match selected with
                            | Some alt ->
                                frontier <- Some alt
                                replayScheduledKey <- None
                                replayQueue <- []
                                Some alt
                            | None -> None)
                match switched with
                | Some alt ->
                    DiagJson.emit (
                        sprintf "{\"kind\":\"eval_worklist_type_variable_value_missing_yielded\",\"event\":%s,\"blocked_kind\":%s,\"blocked_status\":%s,\"selected_kind\":%s,\"selected_status\":%s,\"pending\":%d,\"single_flight\":1,\"next\":\"drain_selected_frontier\"}"
                            (esc event) (esc frame.kind) (esc frame.status) (esc alt.kind) (esc alt.status) (pendingCount()))
                    Some alt
                | None -> None
            with _ -> None

        // ALPHA493: a stale-root retarget blocker is terminal evidence for the blocked
        // cell, but it should not monopolize retry_stop while another kind-local frontier
        // is already live.  Park it in the kind slot and yield to a non-terminal alternate
        // frontier when one exists.  This never promotes the stale proof to root-complete.
        let private tryYieldStaleRootRetargetBlocked (event: string) (frame: Frame) : Frame option =
            try
                let switched =
                    lock gate (fun () ->
                        let blockedRetarget =
                            frame.status = "semantic_stale_root_retarget_blocked"
                            && replayQueue.IsEmpty
                            && not (frameReplayCompleteAny frame)
                        if not blockedRetarget then None
                        else
                            slotSetLocked frame
                            let candidates =
                                [ frontierTerm; frontierTy ]
                                |> List.choose (fun x -> x)
                                |> List.filter (fun alt ->
                                    not (sameCycle alt frame)
                                    && alt.status <> "semantic_stale_root_retarget_blocked"
                                    && alt.status <> "semantic_type_variable_value_missing_blocked"
                                    && alt.status <> "semantic_parent_continuation_cycle_blocked"
                                    && alt.status <> "semantic_replay_fingerprint_repeat_blocked"
                                    && alt.status <> "semantic_replay_payload_missing_blocked"
                                    && alt.status <> "semantic_macro_thunk_missing_blocked"
                                    && alt.status <> "semantic_tjoinpoint_stepper_blocked"
                                    && alt.status <> "semantic_literal_op_body_stepper_blocked"
                                    && alt.status <> "semantic_leaf_complete")
                            let selected =
                                match candidates |> List.tryFind (fun alt -> alt.status = "semantic_root_complete") with
                                | Some root -> Some root
                                | None ->
                                    match candidates |> List.tryFind (fun alt -> alt.status = "continuation_envelope" || alt.status = "ready_explicit_loop" || alt.status = "tracing_explicit_loop") with
                                    | Some live -> Some live
                                    | None -> candidates |> List.tryHead
                            match selected with
                            | Some alt ->
                                frontier <- Some alt
                                replayScheduledKey <- None
                                replayQueue <- []
                                noteProgressYieldLocked ()
                                Some alt
                            | None -> None)
                match switched with
                | Some alt ->
                    DiagJson.emit (
                        sprintf "{\"kind\":\"eval_worklist_stale_root_retarget_yielded\",\"event\":%s,\"blocked_kind\":%s,\"blocked_status\":%s,\"selected_kind\":%s,\"selected_status\":%s,\"pending\":%d,\"single_flight\":1,\"next\":\"drain_selected_frontier\"}"
                            (esc event) (esc frame.kind) (esc frame.status) (esc alt.kind) (esc alt.status) (pendingCount()))
                    Some alt
                | None -> None
            with _ -> None

        // ALPHA477: retry_stop can now reach a real semantic leaf after jp_wait_cycle_drain
        // without yet having the parent continuation registered.  That is progress, but not
        // a root proof.  Request one bounded replay retry so the parent-continuation sidecar
        // can be observed on the next pass, rather than aborting immediately as a generic
        // semantic_step_partial.  The caller remains responsible for the normal retry cap.
        let tryRequestLeafParentContinuationRetry (event: string) (attempt: int) (maxAttempts: int) : bool =
            try
                match tryPeek() with
                | Some frame ->
                    let noParentContinuation =
                        match frame.semanticCell with
                        | Some cell -> EvalReplayValueStore.tryParentContinuation cell.nodeId |> Option.isNone
                        | None -> true
                    let blockedLeaf =
                        frame.status = "semantic_leaf_complete"
                        && replayQueue.IsEmpty
                        && noParentContinuation
                        && not (frameReplayCompleteAny frame)
                    if not blockedLeaf then false
                    else
                        let yieldedAlternate =
                            match tryYieldLeafParentContinuationBlocked event frame with
                            | Some _ -> true
                            | None -> false
                        DiagJson.emit (
                            sprintf "{\"kind\":\"eval_worklist_leaf_parent_continuation_retry\",\"event\":%s,\"attempt\":%d,\"next_attempt\":%d,\"max_attempts\":%d,\"frame_kind\":%s,\"status\":%s,\"key\":%s,\"site\":%s,\"cursor\":%d,\"trace_lines\":%d,\"pending\":%d,\"yielded_alternate\":%b,\"single_flight\":1,\"policy\":\"bounded_retry_after_leaf_parent_continuation_missing\",\"next\":\"attempt_build\"}"
                                (esc event) attempt (attempt + 1) maxAttempts (esc frame.kind) (esc frame.status) (esc frame.key) (esc frame.site) frame.cursor frame.trace.Length (pendingCount()) yieldedAlternate)
                        true
                | None -> false
            with _ -> false

        // ALPHA470/494: a replay fingerprint repeat is useful evidence, but it
        // should not monopolize the canonical retry drain while another frontier is
        // live.  Alpha494 adds two guardrails observed after alpha493: progress-bearing
        // fingerprint-yields are counted for a bounded retry trampoline, and when no
        // independent kind-local slot exists, a live same-cycle non-terminal frontier
        // may be selected once instead of aborting immediately on the repeat blocker.
        let private tryYieldReplayFingerprintRepeatBlocked (event: string) (frame: Frame) : Frame option =
            try
                let mutable selectedScope = "none"
                let switched =
                    lock gate (fun () ->
                        let blockedRepeat =
                            frame.status = "semantic_replay_fingerprint_repeat_blocked"
                            && replayQueue.IsEmpty
                            && not (frameReplayCompleteAny frame)
                        if not blockedRepeat then None
                        else
                            slotSetLocked frame
                            let liveNonRepeat (alt: Frame) =
                                alt.status <> "semantic_replay_fingerprint_repeat_blocked"
                                && alt.status <> "semantic_joinpoint_term_stepper_blocked"
                                && alt.status <> "semantic_joinpoint_value_blocked"
                                && alt.status <> "semantic_parent_continuation_cycle_blocked"
                                && alt.status <> "semantic_type_variable_value_missing_blocked"
                                && alt.status <> "semantic_stale_root_retarget_blocked"
                                && alt.status <> "semantic_leaf_complete"
                            let allCandidates =
                                [ frontierTerm; frontierTy ]
                                |> List.choose (fun x -> x)
                                |> List.filter liveNonRepeat
                            let independent =
                                allCandidates |> List.filter (fun alt -> not (sameCycle alt frame))
                            let sameCycleLive =
                                allCandidates |> List.filter (fun alt -> sameCycle alt frame)
                            let candidates =
                                match independent with
                                | _ :: _ ->
                                    selectedScope <- "independent"
                                    independent
                                | [] ->
                                    selectedScope <- "same_cycle_live"
                                    sameCycleLive
                            let selected =
                                match candidates |> List.tryFind (fun alt -> alt.status = "semantic_root_complete") with
                                | Some root -> Some root
                                | None ->
                                    match candidates |> List.tryFind (fun alt -> alt.status = "continuation_envelope" || alt.status = "ready_explicit_loop" || alt.status = "tracing_explicit_loop") with
                                    | Some live -> Some live
                                    | None -> candidates |> List.tryHead
                            match selected with
                            | Some alt ->
                                frontier <- Some alt
                                replayScheduledKey <- None
                                replayQueue <- []
                                noteProgressYieldLocked ()
                                Some alt
                            | None -> None)
                match switched with
                | Some alt ->
                    let kind =
                        if selectedScope = "same_cycle_live" then "eval_worklist_replay_fingerprint_repeat_same_cycle_yielded"
                        else "eval_worklist_replay_fingerprint_repeat_yielded"
                    DiagJson.emit (
                        sprintf "{\"kind\":%s,\"event\":%s,\"blocked_kind\":%s,\"blocked_status\":%s,\"selected_kind\":%s,\"selected_status\":%s,\"scope\":%s,\"pending\":%d,\"single_flight\":1,\"next\":\"drain_selected_frontier\"}"
                            (esc kind) (esc event) (esc frame.kind) (esc frame.status) (esc alt.kind) (esc alt.status) (esc selectedScope) (pendingCount()))
                    Some alt
                | None -> None
            with _ -> None

        // ALPHA471: dynamic apply blocked on a DV/DB runtime typecheck is not
        // semantic progress, but it also should not terminate retry_stop while an
        // alternate kind frontier is pending.  Park the blocked dynamic-join frame
        // and yield to another live frontier.  This is scheduler-only: the value
        // store, replay-root witness, and writer gates remain unchanged.
        let private tryYieldDynamicArgApplyBlocked (event: string) (frame: Frame) : Frame option =
            try
                let switched =
                    lock gate (fun () ->
                        let blockedDynamic =
                            frame.status = "semantic_dynamic_join_apply_blocked"
                            && replayQueue.IsEmpty
                            && not (frameReplayCompleteAny frame)
                        if not blockedDynamic then None
                        else
                            slotSetLocked frame
                            let candidates =
                                [ frontierTerm; frontierTy ]
                                |> List.choose (fun x -> x)
                                |> List.filter (fun alt ->
                                    not (sameCycle alt frame)
                                    && alt.status <> "semantic_replay_fingerprint_repeat_blocked"
                                    && alt.status <> "semantic_replay_payload_missing_blocked"
                                    && alt.status <> "semantic_macro_thunk_missing_blocked"
                                    && alt.status <> "semantic_tjoinpoint_stepper_blocked"
                                    && alt.status <> "semantic_literal_op_body_stepper_blocked"
                                    && alt.status <> "semantic_leaf_complete"
                                    && alt.status <> "semantic_dynamic_join_apply_blocked")
                            let selected =
                                match candidates |> List.tryFind (fun alt -> alt.status = "semantic_root_complete") with
                                | Some root -> Some root
                                | None ->
                                    match candidates |> List.tryFind (fun alt -> alt.status = "continuation_envelope") with
                                    | Some cont -> Some cont
                                    | None ->
                                        match candidates |> List.tryFind (fun alt -> alt.status = "ready_explicit_loop" || alt.status = "tracing_explicit_loop") with
                                        | Some live -> Some live
                                        | None -> candidates |> List.tryHead
                            match selected with
                            | Some alt ->
                                frontier <- Some alt
                                replayScheduledKey <- None
                                replayQueue <- []
                                Some alt
                            | None -> None)
                match switched with
                | Some alt ->
                    DiagJson.emit (
                        sprintf "{\"kind\":\"eval_worklist_dynamic_arg_apply_yielded\",\"event\":%s,\"blocked_kind\":%s,\"blocked_status\":%s,\"selected_kind\":%s,\"selected_status\":%s,\"pending\":%d,\"single_flight\":1,\"next\":\"drain_selected_frontier\"}"
                            (esc event) (esc frame.kind) (esc frame.status) (esc alt.kind) (esc alt.status) (pendingCount()))
                    Some alt
                | None -> None
            with _ -> None

        // ALPHA473: a semantic_root_complete frontier is a proof, not a scheduler sink.
        // Alpha472 reached multiple source_value_stored events and then stopped on
        // stable_root_complete_livelock while pending alternate work remained.  When
        // the root-complete handoff repeats up to the outer cap, park the completed
        // proof in its kind slot and select a live non-root frontier before aborting.
        // This is scheduler-only: it cannot create BuildOk, cannot mark completion,
        // and cannot unlock writer/shrink gates.
        let tryYieldStableRootCompleteHandoff (event: string) : Frame option =
            try
                let rankStableRootYieldCandidate (alt: Frame) =
                    if alt.status = "semantic_dynamic_join_apply_blocked" then 0
                    elif alt.status = "continuation_envelope" then 1
                    elif alt.status = "ready_explicit_loop" || alt.status = "tracing_explicit_loop" || alt.status = "semantic_step_partial" then 2
                    else 3

                let chooseStableRootYieldCandidate candidates =
                    candidates
                    |> List.sortBy rankStableRootYieldCandidate
                    |> List.tryHead

                let crossKindSelectedStepper (frame: Frame) =
                    match frame.semanticCell with
                    | Some cell when cell.status = "selected_frontier_stepper_ready" ->
                        (cell.kind = "term" && cell.site.StartsWith("ty@", StringComparison.Ordinal))
                        || (cell.kind = "ty" && cell.site.StartsWith("term@", StringComparison.Ordinal))
                    | _ -> false

                // Selected-frontier promotion happens in the root-complete handoff path,
                // outside the normal bounded trampoline.  A continuation envelope without a
                // queued replay task only burns retry budget.  Enqueue the promoted envelope
                // immediately so the next preserved-progress attempt has a concrete driver.
                let enqueueSelectedFrontierReplayLocked (event: string) (frame: Frame) (route: string) =
                    let payload = adapterPayload frame
                    let key = replayKey frame
                    let driver = replayDriverFor frame
                    replaySeq <- replaySeq + 1L
                    let task = { id = replaySeq; key = key; driver = driver; payload = payload; status = "scheduled_replay"; event = event }
                    replayScheduledKey <- Some key
                    replayQueue <- [task]
                    DiagJson.emit (
                        sprintf "{\"kind\":\"eval_worklist_selected_frontier_replay_enqueued\",\"event\":%s,\"route\":%s,\"replay_id\":%d,\"driver\":%s,\"frame_kind\":%s,\"frame_status\":%s,\"cursor\":%d,\"trace_lines\":%d,\"queue_depth\":%d,\"pending\":%d,\"single_flight\":1,\"next\":\"execute_selected_frontier_replay_driver\"}"
                            (esc event) (esc route) task.id (esc driver) (esc frame.kind) (esc frame.status) frame.cursor frame.trace.Length (replayQueueDepth()) (pendingCount()))

                let tryPromoteSelectedFrontierStepperLocked (repeated: Frame) (repeatCount: int) (repeatedKey: string) =
                    match repeated.semanticCell with
                    | Some cell when (repeated.status = "captured"
                                      || repeated.status = "ready_explicit_loop"
                                      || repeated.status = "tracing_explicit_loop"
                                      || repeated.status = "semantic_apply_continuation_exception_blocked")
                                     && cell.kind = "term"
                                     && cell.shape = "ESeq"
                                     && (cell.status = "captured" || cell.status = "new" || cell.status = "stepper_ready") ->
                        let replayKey = repeatedKey + "|selected_captured_cell_replay|" + string cell.nodeId + "|" + cell.shape + "|cursor=" + string cell.cursor + "|step=" + string cell.step
                        let attempt = noteSelectedFrontierStepperReplayLocked replayKey
                        if attempt > selected_frontier_captured_cell_replay_cap then None
                        else
                            let replayCell = { cell with status = "selected_frontier_stepper_ready" }
                            let promoted =
                                { repeated with
                                    status = "continuation_envelope"
                                    cursor = repeated.trace.Length
                                    reason = repeated.reason + ":selected_captured_frontier_cell_replay"
                                    semanticPayload = Some(formatCellPayload replayCell)
                                    semanticCell = Some replayCell }
                            frontier <- Some promoted
                            slotSetLocked promoted
                            enqueueSelectedFrontierReplayLocked event promoted "captured_cell_replay"
                            noteProgressYieldLocked ()
                            stableRootSelectedKey <- ""
                            stableRootSelectedCount <- 0
                            DiagJson.emit (
                                sprintf "{\"kind\":\"eval_worklist_selected_frontier_captured_cell_replay\",\"event\":%s,\"frame_status\":%s,\"cell_kind\":%s,\"cell_shape\":%s,\"cell_status\":%s,\"node_id\":%d,\"site\":%s,\"attempt\":%d,\"cap\":%d,\"repeat_count\":%d,\"repeat_cap\":%d,\"pending\":%d,\"single_flight\":1,\"next\":\"run_captured_frontier_typed_stepper\"}"
                                    (esc event) (esc repeated.status) (esc cell.kind) (esc cell.shape) (esc cell.status) cell.nodeId (esc cell.site) attempt selected_frontier_captured_cell_replay_cap repeatCount stable_root_selected_frontier_repeat_cap (pendingCount()))
                            Some promoted
                    | Some cell when repeated.status = "semantic_step_partial"
                                     && cell.kind = "term"
                                     && (cell.shape = "EApply" || cell.shape = "ETypeApply" || cell.shape = "ELet" || cell.shape = "ESeq") ->
                        let replayKey = repeatedKey + "|selected_frontier_stepper|" + string cell.nodeId + "|" + cell.shape
                        let attempt = noteSelectedFrontierStepperReplayLocked replayKey
                        if attempt > selected_frontier_stepper_replay_cap then None
                        else
                            let replayCell = { cell with status = "selected_frontier_stepper_ready" }
                            let promoted =
                                { repeated with
                                    status = "continuation_envelope"
                                    cursor = repeated.trace.Length
                                    reason = repeated.reason + ":selected_frontier_stepper_replay"
                                    semanticPayload = Some(formatCellPayload replayCell)
                                    semanticCell = Some replayCell }
                            frontier <- Some promoted
                            slotSetLocked promoted
                            enqueueSelectedFrontierReplayLocked event promoted "stepper_replay"
                            noteProgressYieldLocked ()
                            stableRootSelectedKey <- ""
                            stableRootSelectedCount <- 0
                            DiagJson.emit (
                                sprintf "{\"kind\":\"eval_worklist_selected_frontier_stepper_replay\",\"event\":%s,\"cell_kind\":%s,\"cell_shape\":%s,\"node_id\":%d,\"site\":%s,\"attempt\":%d,\"cap\":%d,\"repeat_count\":%d,\"repeat_cap\":%d,\"pending\":%d,\"single_flight\":1,\"next\":\"run_selected_frontier_typed_stepper\"}"
                                    (esc event) (esc cell.kind) (esc cell.shape) cell.nodeId (esc cell.site) attempt selected_frontier_stepper_replay_cap repeatCount stable_root_selected_frontier_repeat_cap (pendingCount()))
                            Some promoted
                    | Some cell when repeated.status = "continuation_envelope"
                                     && cell.kind = "term"
                                     && cell.status = "selected_frontier_stepper_ready"
                                     && (cell.shape = "EApply" || cell.shape = "ETypeApply" || cell.shape = "ELet" || cell.shape = "ESeq") ->
                        let replayKey =
                            repeatedKey + "|selected_frontier_stepper_rearm|" + string cell.nodeId + "|" + cell.shape + "|cursor=" + string cell.cursor + "|step=" + string cell.step
                        let attempt = noteSelectedFrontierStepperReplayLocked replayKey
                        if attempt > selected_frontier_stepper_rearm_cap then None
                        else
                            let rearmed =
                                { repeated with
                                    status = "continuation_envelope"
                                    cursor = repeated.trace.Length
                                    reason = repeated.reason + ":selected_frontier_stepper_rearm"
                                    semanticPayload = Some(formatCellPayload cell)
                                    semanticCell = Some cell }
                            frontier <- Some rearmed
                            slotSetLocked rearmed
                            enqueueSelectedFrontierReplayLocked event rearmed "stepper_rearm"
                            noteProgressYieldLocked ()
                            stableRootSelectedKey <- ""
                            stableRootSelectedCount <- 0
                            DiagJson.emit (
                                sprintf "{\"kind\":\"eval_worklist_selected_frontier_stepper_rearm\",\"event\":%s,\"cell_kind\":%s,\"cell_shape\":%s,\"cell_status\":%s,\"node_id\":%d,\"site\":%s,\"attempt\":%d,\"cap\":%d,\"repeat_count\":%d,\"repeat_cap\":%d,\"pending\":%d,\"single_flight\":1,\"next\":\"rearm_selected_frontier_typed_stepper\"}"
                                    (esc event) (esc cell.kind) (esc cell.shape) (esc cell.status) cell.nodeId (esc cell.site) attempt selected_frontier_stepper_rearm_cap repeatCount stable_root_selected_frontier_repeat_cap (pendingCount()))
                            Some rearmed
                    | _ -> None

                let switched =
                    lock gate (fun () ->
                        match frontier with
                        | Some frame when frameReplayCompleteAny frame && replayQueue.IsEmpty ->
                            slotSetLocked frame
                            let blockedRootKey = rootCompleteFingerprintLocked ()
                            let candidates =
                                [ frontierTerm; frontierTy ]
                                |> List.choose (fun x -> x)
                                |> List.filter (fun alt ->
                                    not (sameCycle alt frame)
                                    && not (frameReplayCompleteAny alt)
                                    && alt.status <> "semantic_leaf_complete")
                            let preferred = chooseStableRootYieldCandidate candidates
                            let selected, repeatBlocked =
                                match preferred with
                                | Some pref ->
                                    let prefKey = blockedRootKey + "=>" + selectedFrontierFingerprintLocked pref
                                    if prefKey = stableRootSelectedKey && stableRootSelectedCount >= stable_root_selected_frontier_repeat_cap then
                                        let fallback =
                                            candidates
                                            |> List.filter (fun alt -> blockedRootKey + "=>" + selectedFrontierFingerprintLocked alt <> stableRootSelectedKey)
                                            |> chooseStableRootYieldCandidate
                                        match fallback with
                                        | Some alt -> Some alt, Some(pref, stableRootSelectedCount, prefKey)
                                        | None ->
                                            // ALPHA582: forcing the same semantic_step_partial frontier after
                                            // the repeat cap only burns the root-complete yield budget.  Runtime
                                            // 581 proved the lone child repeats until trampoline exhaustion; when
                                            // there is no alternate, surface the exact repeat terminal instead.
                                            // ALPHA588: runtime 587 exposed a narrower case where the repeated
                                            // selected frontier is already a selected_frontier_stepper_ready term
                                            // cell, but its site is ty@... under a completed ty root.  That is a
                                            // stale cross-kind continuation, not stronger evidence than the root
                                            // proof; demote it and leave the semantic_root_complete frontier intact.
                                            if crossKindSelectedStepper pref then
                                                let demotedRepeatCount = stableRootSelectedCount
                                                let cellSummary =
                                                    match pref.semanticCell with
                                                    | Some cell -> formatCell cell
                                                    | None -> "none"
                                                stableRootSelectedKey <- ""
                                                stableRootSelectedCount <- 0
                                                DiagJson.emit (
                                                    sprintf "{\"kind\":\"eval_worklist_cross_kind_selected_frontier_demoted\",\"event\":%s,\"repeated_kind\":%s,\"repeated_status\":%s,\"repeat_count\":%d,\"repeat_cap\":%d,\"repeated_key\":%s,\"cell\":%s,\"pending\":%d,\"single_flight\":1,\"next\":\"preserve_root_complete_build_attempt\"}"
                                                        (esc event) (esc pref.kind) (esc pref.status) demotedRepeatCount stable_root_selected_frontier_repeat_cap (esc prefKey) (esc cellSummary) (pendingCount()))
                                                None, None
                                            else
                                                None, Some(pref, stableRootSelectedCount, prefKey)
                                    else
                                        Some pref, None
                                | None -> None, None
                            match selected with
                            | Some alt ->
                                let selectedRepeatCount, selectedKey = noteStableRootSelectedFrontierLocked blockedRootKey alt
                                let promotedTerminal =
                                    if alt.status = "semantic_apply_continuation_exception_blocked"
                                       || alt.status = "semantic_replay_payload_missing_blocked"
                                       || alt.status = "semantic_replay_child_schedule_repeat_blocked" then
                                        tryPromoteSelectedFrontierStepperLocked alt selectedRepeatCount selectedKey
                                    else None
                                match promotedTerminal with
                                | Some promoted ->
                                    Some (Choice1Of2(frame, promoted, repeatBlocked, selectedRepeatCount, selectedKey))
                                | None ->
                                    frontier <- Some alt
                                    replayScheduledKey <- None
                                    replayQueue <- []
                                    Some (Choice1Of2(frame, alt, repeatBlocked, selectedRepeatCount, selectedKey))
                            | None ->
                                match repeatBlocked with
                                | Some info -> Some (Choice2Of2 info)
                                | None -> None
                        | _ -> None)
                match switched with
                | Some (Choice1Of2(blocked, alt, repeatBlocked, selectedRepeatCount, selectedKey)) ->
                    match repeatBlocked with
                    | Some(repeated, repeatCount, repeatedKey) ->
                        DiagJson.emit (
                            sprintf "{\"kind\":\"eval_worklist_selected_frontier_repeat_blocked\",\"event\":%s,\"blocked_kind\":%s,\"blocked_status\":%s,\"repeated_kind\":%s,\"repeated_status\":%s,\"selected_kind\":%s,\"selected_status\":%s,\"repeat_count\":%d,\"repeat_cap\":%d,\"repeated_key\":%s,\"fallback_key\":%s,\"pending\":%d,\"single_flight\":1,\"next\":\"alternate_frontier_selected\"}"
                                (esc event) (esc blocked.kind) (esc blocked.status) (esc repeated.kind) (esc repeated.status) (esc alt.kind) (esc alt.status) repeatCount stable_root_selected_frontier_repeat_cap (esc repeatedKey) (esc selectedKey) (pendingCount()))
                        if selectedKey = repeatedKey then
                            DiagJson.emit (
                                sprintf "{\"kind\":\"eval_worklist_selected_frontier_repeat_forced\",\"event\":%s,\"blocked_kind\":%s,\"blocked_status\":%s,\"forced_kind\":%s,\"forced_status\":%s,\"repeat_count\":%d,\"repeat_cap\":%d,\"forced_key\":%s,\"pending\":%d,\"single_flight\":1,\"policy\":\"no_alternate_frontier_force_only_live_child\",\"next\":\"retry_selected_frontier\"}"
                                    (esc event) (esc blocked.kind) (esc blocked.status) (esc alt.kind) (esc alt.status) repeatCount stable_root_selected_frontier_repeat_cap (esc selectedKey) (pendingCount()))
                    | None -> ()
                    DiagJson.emit (
                        sprintf "{\"kind\":\"eval_worklist_stable_root_complete_yielded\",\"event\":%s,\"blocked_kind\":%s,\"blocked_status\":%s,\"selected_kind\":%s,\"selected_status\":%s,\"selected_repeat_count\":%d,\"selected_repeat_cap\":%d,\"pending\":%d,\"single_flight\":1,\"next\":\"retry_selected_frontier\"}"
                            (esc event) (esc blocked.kind) (esc blocked.status) (esc alt.kind) (esc alt.status) selectedRepeatCount stable_root_selected_frontier_repeat_cap (pendingCount()))
                    Some alt
                | Some (Choice2Of2(repeated, repeatCount, repeatedKey)) ->
                    let promoted =
                        lock gate (fun () ->
                            tryPromoteSelectedFrontierStepperLocked repeated repeatCount repeatedKey)
                    match promoted with
                    | Some frame ->
                        Some frame
                    | None ->
                        let terminalFrame =
                            { repeated with
                                status = "semantic_selected_frontier_repeat_blocked"
                                reason = repeated.reason + ":selected_frontier_repeat_terminal" }
                        // A selected-frontier repeat is scheduler evidence. If a stronger
                        // semantic terminal was already pinned during replay, keep that terminal
                        // visible instead of overwriting it with the lower-rank repeat symptom.
                        let visibleFrame, priorRank, repeatRank, demotedBelowPinned, priorSource =
                            lock gate (fun () ->
                                let repeatRank = terminalContractRank terminalFrame.status
                                let liveRank =
                                    match pinnedTerminalContract with
                                    | Some prior -> terminalContractRank prior.status
                                    | None -> 0
                                let durableRank =
                                    match durableTerminalContract with
                                    | Some prior -> terminalContractRank prior.status
                                    | None -> 0
                                let priorSource, priorOpt, priorRank =
                                    if durableRank > liveRank then
                                        "durable_ledger", durableTerminalContract, durableRank
                                    elif liveRank > 0 then
                                        "live_pinned", pinnedTerminalContract, liveRank
                                    else
                                        "none", None, 0
                                match priorOpt with
                                | Some prior when priorRank > repeatRank ->
                                    frontier <- Some prior
                                    slotSetLocked prior
                                    prior, priorRank, repeatRank, true, priorSource
                                | _ ->
                                    frontier <- Some terminalFrame
                                    slotSetLocked terminalFrame
                                    pinTerminalContractLocked event terminalFrame
                                    terminalFrame, priorRank, repeatRank, false, priorSource)
                        if demotedBelowPinned then
                            DiagJson.emit (
                                sprintf "{\"kind\":\"eval_worklist_selected_frontier_repeat_demoted_below_stronger_terminal\",\"event\":%s,\"repeat_status\":%s,\"repeat_rank\":%d,\"terminal_status\":%s,\"terminal_rank\":%d,\"terminal_site\":%s,\"terminal_source\":%s,\"repeat_count\":%d,\"repeat_cap\":%d,\"pending\":%d,\"single_flight\":1,\"next\":%s}"
                                    (esc event) (esc terminalFrame.status) repeatRank (esc visibleFrame.status) priorRank (esc visibleFrame.site) (esc priorSource) repeatCount stable_root_selected_frontier_repeat_cap (pendingCount()) (esc (terminalContractNext visibleFrame.status)))

                        DiagJson.emit (
                            sprintf "{\"kind\":\"eval_worklist_selected_frontier_repeat_blocked\",\"event\":%s,\"blocked_kind\":\"unknown\",\"blocked_status\":\"semantic_root_complete\",\"repeated_kind\":%s,\"repeated_status\":%s,\"selected_kind\":%s,\"selected_status\":%s,\"visible_kind\":%s,\"visible_status\":%s,\"repeat_count\":%d,\"repeat_cap\":%d,\"repeated_key\":%s,\"fallback_key\":\"none\",\"pending\":%d,\"single_flight\":1,\"next\":\"abort_precise_terminal\"}"
                                (esc event) (esc repeated.kind) (esc repeated.status) (esc terminalFrame.kind) (esc terminalFrame.status) (esc visibleFrame.kind) (esc visibleFrame.status) repeatCount stable_root_selected_frontier_repeat_cap (esc repeatedKey) (pendingCount()))
                        DiagJson.emit (
                            sprintf "{\"kind\":\"eval_worklist_selected_frontier_repeat_terminal\",\"event\":%s,\"repeated_kind\":%s,\"repeated_status\":%s,\"visible_status\":%s,\"repeat_count\":%d,\"repeat_cap\":%d,\"repeated_key\":%s,\"pending\":%d,\"single_flight\":1,\"policy\":\"stop_forced_same_frontier_after_repeat_cap_preserve_stronger_terminal\",\"next\":%s}"
                                (esc event) (esc repeated.kind) (esc repeated.status) (esc visibleFrame.status) repeatCount stable_root_selected_frontier_repeat_cap (esc repeatedKey) (pendingCount()) (esc (terminalContractNext visibleFrame.status)))
                        DiagJson.emit (
                            sprintf "{\"kind\":\"eval_worklist_selected_frontier_repeat_pinned_terminal\",\"event\":%s,\"status\":%s,\"rank\":%d,\"site\":%s,\"key\":%s,\"repeat_count\":%d,\"repeat_cap\":%d,\"pending\":%d,\"single_flight\":1,\"next\":%s}"
                                (esc event) (esc visibleFrame.status) (terminalContractRank visibleFrame.status) (esc visibleFrame.site) (esc visibleFrame.key) repeatCount stable_root_selected_frontier_repeat_cap (pendingCount()) (esc (terminalContractNext visibleFrame.status)))
                        Some visibleFrame
                | None -> None
            with _ -> None

        let private isTerminalAdapter (frame: Frame) =
            frame.status = "continuation_envelope"

        let private emitAdapter (event: string) (frame: Frame) =
            try
                DiagJson.emit (
                    sprintf "{\"kind\":\"eval_worklist_adapter\",\"event\":%s,\"adapter\":\"trace_continuation\",\"frame_kind\":%s,\"status\":%s,\"cursor\":%d,\"trace_lines\":%d,\"payload\":%s,\"single_flight\":1,\"next\":%s}"
                        (esc event) (esc frame.kind) (esc frame.status) frame.cursor frame.trace.Length (esc (adapterPayload frame)) (esc (nextFor frame)))
            with _ -> ()

        let private scheduleReplay (event: string) (frame: Frame) =
            try
                let backfillCellOpt =
                    if Option.isNone frame.semanticCell && Option.isNone frame.semanticPayload then trySemanticCellForFrame frame
                    else None
                let payload = adapterPayload frame
                let key = replayKey frame
                let driver = replayDriverFor frame
                match backfillCellOpt with
                | Some cell ->
                    DiagJson.emit (
                        sprintf "{\"kind\":\"eval_worklist_replay_payload_backfilled_from_semantic_cell_cache\",\"event\":%s,\"frame_kind\":%s,\"frame_site\":%s,\"cell\":%s,\"single_flight\":1,\"next\":\"schedule_replay_with_semantic_payload\"}"
                            (esc event) (esc frame.kind) (esc frame.site) (esc (formatCell cell)))
                | None -> ()
                let task, duplicate =
                    lock gate (fun () ->
                        let incomingHasSemantic = payload.Contains("semantic_eval_payload(")
                        let wasMissingSemantic (t: ReplayTask) =
                            t.status = "driver_blocked_semantic_payload"
                            || t.payload.Contains("semantic_eval_payload_missing")
                        match replayScheduledKey with
                        | Some k when k = key ->
                            match replayQueue with
                            | h :: rest ->
                                // ALPHA447: same-key replay envelopes may first be scheduled from
                                // jp_wait_cycle_drain with semantic_eval_payload_missing, then later
                                // revisit the exact cursor after a same-kind semantic cell attaches.
                                // Do not keep the stale missing-payload task forever: refresh it and
                                // let the driver run again.  This preserves dedupe for identical
                                // empty envelopes while unblocking the real typed continuation.
                                if wasMissingSemantic h && incomingHasSemantic then
                                    let t = { h with payload = payload; status = "scheduled_replay"; event = event }
                                    replayQueue <- (t :: rest) |> List.truncate 8
                                    t, false
                                else
                                    h, true
                            | [] ->
                                replaySeq <- replaySeq + 1L
                                let t = { id = replaySeq; key = key; driver = driver; payload = payload; status = "scheduled_replay"; event = event }
                                replayQueue <- [t]
                                t, false
                        | _ ->
                            replaySeq <- replaySeq + 1L
                            let t = { id = replaySeq; key = key; driver = driver; payload = payload; status = "scheduled_replay"; event = event }
                            replayScheduledKey <- Some key
                            replayQueue <- (t :: replayQueue) |> List.truncate 8
                            t, false)
                // ALPHA455: a duplicate driver_blocked_semantic_payload task that still
                // carries semantic_eval_payload_missing is not progress.  Alpha454 allowed the
                // parent replay to reduce, but the follow-up jp_wait_cycle_drain repeatedly
                // reran an identical missing-payload envelope at sm'_operators.spi:19.  Park the
                // frontier as an explicit payload requirement until a later same-key envelope
                // refreshes the queued task with a real semantic_eval_payload(...).
                let blockedMissingDuplicate =
                    duplicate
                    && task.status = "driver_blocked_semantic_payload"
                    && task.payload.Contains("semantic_eval_payload_missing")
                let rerunBlockedDuplicate = duplicate && task.status = "driver_blocked_semantic_payload" && not blockedMissingDuplicate
                let readyDuplicateCandidate =
                    duplicate
                    && (task.status = "driver_ready_replay_cell" || task.status = "driver_ready_semantic_payload")
                    && frame.status = "continuation_envelope"
                    && frame.reason.Contains("leaf_yield_terminal_let_cycle_replay")
                let readyDuplicateAttempt =
                    if readyDuplicateCandidate then lock gate (fun () -> noteReadyDuplicateReplayRerunLocked key) else 0
                let rerunReadyDuplicate = readyDuplicateCandidate && readyDuplicateAttempt <= 4
                let blockReadyDuplicate = readyDuplicateCandidate && readyDuplicateAttempt > 4
                let duplicateNext =
                    if blockedMissingDuplicate then "blocked_payload_duplicate_suppressed"
                    elif rerunBlockedDuplicate then "rerun_blocked_replay_driver"
                    elif rerunReadyDuplicate then "rerun_ready_duplicate_replay_driver"
                    elif blockReadyDuplicate then "ready_duplicate_replay_cap"
                    else "already_scheduled"
                DiagJson.emit (
                    sprintf "{\"kind\":\"eval_worklist_replay_schedule\",\"event\":%s,\"replay_id\":%d,\"driver\":%s,\"status\":%s,\"queue_depth\":%d,\"duplicate\":%d,\"payload\":%s,\"single_flight\":1,\"next\":%s}"
                        (esc event) task.id (esc task.driver) (esc task.status) (replayQueueDepth()) (if duplicate then 1 else 0) (esc task.payload) (esc (if duplicate then duplicateNext else task.driver)))
                if blockedMissingDuplicate then
                    let payloadFrameOpt =
                        lock gate (fun () ->
                            match frontier with
                            | Some frame ->
                                let frame' = { frame with status = "semantic_replay_payload_missing_blocked"; reason = frame.reason + ":missing_semantic_payload_scheduler_terminal" }
                                let payloadRank = terminalContractRank frame'.status
                                let priorRank =
                                    match pinnedTerminalContract with
                                    | Some prior -> terminalContractRank prior.status
                                    | None -> 0
                                pinnedReplayPayloadMissing <- Some frame'
                                pinTerminalContractLocked event frame'
                                // ALPHA569: payload-missing is evidence that the scheduler lacks a
                                // typed cell, not stronger semantic evidence than an already pinned
                                // TV/TJoinPoint/value blocker.  Keep the concrete terminal as the
                                // visible frontier when it has a higher rank.
                                if priorRank > payloadRank then
                                    match pinnedTerminalContract with
                                    | Some prior ->
                                        frontier <- Some prior
                                        slotSetLocked prior
                                    | None -> ()
                                else
                                    frontier <- Some frame'
                                    slotSetLocked frame'
                                Some(frame', priorRank, payloadRank)
                            | None -> None)
                    match payloadFrameOpt with
                    | Some(_, priorRank, payloadRank) when priorRank > payloadRank ->
                        DiagJson.emit (
                            sprintf "{\"kind\":\"eval_worklist_replay_payload_missing_demoted_below_pinned_terminal\",\"event\":%s,\"replay_id\":%d,\"driver\":%s,\"payload_rank\":%d,\"pinned_rank\":%d,\"pending\":%d,\"single_flight\":1,\"next\":\"prefer_concrete_pinned_terminal\"}"
                                (esc event) task.id (esc task.driver) payloadRank priorRank (pendingCount()))
                    | _ -> ()
                    DiagJson.emit (
                        sprintf "{\"kind\":\"eval_worklist_replay_payload_missing_blocked\",\"event\":%s,\"replay_id\":%d,\"driver\":%s,\"status\":\"semantic_replay_payload_missing_blocked\",\"queue_depth\":%d,\"payload\":%s,\"pending\":%d,\"single_flight\":1,\"next\":\"explicit_eval_worklist_replay_payload_required\"}"
                            (esc event) task.id (esc task.driver) (replayQueueDepth()) (esc task.payload) (pendingCount()))
                    DiagJson.emit (
                        sprintf "{\"kind\":\"eval_worklist_replay_payload_missing_pinned\",\"event\":%s,\"replay_id\":%d,\"driver\":%s,\"status\":\"semantic_replay_payload_missing_blocked\",\"pending\":%d,\"single_flight\":1,\"next\":\"prefer_payload_missing_terminal\"}"
                            (esc event) task.id (esc task.driver) (pendingCount()))
                elif blockReadyDuplicate then
                    lock gate (fun () ->
                        match frontier with
                        | Some frame ->
                            let frame' =
                                { frame with
                                    status = "semantic_replay_fingerprint_repeat_blocked"
                                    reason = frame.reason + ":ready_duplicate_replay_cap" }
                            frontier <- Some frame'
                            slotSetLocked frame'
                        | None -> ())
                    DiagJson.emit (
                        sprintf "{\"kind\":\"eval_worklist_ready_duplicate_replay_cap\",\"event\":%s,\"replay_id\":%d,\"driver\":%s,\"attempt\":%d,\"cap\":4,\"status\":\"semantic_replay_fingerprint_repeat_blocked\",\"queue_depth\":%d,\"payload\":%s,\"pending\":%d,\"single_flight\":1,\"next\":\"explicit_eval_worklist_replay_fingerprint_repeat_required\"}"
                            (esc event) task.id (esc task.driver) readyDuplicateAttempt (replayQueueDepth()) (esc task.payload) (pendingCount()))
                elif (not duplicate) || rerunBlockedDuplicate || rerunReadyDuplicate then
                    if rerunReadyDuplicate then
                        DiagJson.emit (
                            sprintf "{\"kind\":\"eval_worklist_ready_duplicate_replay_driver_rerun\",\"event\":%s,\"replay_id\":%d,\"driver\":%s,\"attempt\":%d,\"cap\":4,\"queue_depth\":%d,\"payload\":%s,\"pending\":%d,\"single_flight\":1,\"next\":%s}"
                                (esc event) task.id (esc task.driver) readyDuplicateAttempt (replayQueueDepth()) (esc task.payload) (pendingCount()) (esc task.driver))
                    runReplayDriver event
            with _ -> ()

        let private beginRun (event: string) =
            lock gate (fun () ->
                if activeRun then false
                else activeRun <- true; true)

        let private endRun () =
            lock gate (fun () -> activeRun <- false)

        let private stepOnce (event: string) (step: int) (limit: int) : Frame option =
            lock gate (fun () ->
                match frontier with
                | None -> None
                | Some f ->
                    let loc = traceAt f f.cursor
                    let capturedLeafCell =
                        f.status = "semantic_leaf_complete"
                        && (match f.semanticCell with
                            | Some cell -> cell.status = "captured" || cell.status = "new"
                            | None -> false)
                    let lateCapturedLeafCell =
                        capturedLeafCell
                        && f.cursor >= f.trace.Length
                    let orphanCapturedLeafCell =
                        event = "retry_stop_drain"
                        && capturedLeafCell
                        && f.cursor < f.trace.Length
                        && replayQueueDepth() = 0
                    let status', cursor', next' =
                        if f.status = "semantic_replay_driver_exception_blocked" then
                            f.status, f.cursor, "explicit_eval_worklist_replay_driver_exception_required"
                        elif f.status = "semantic_replay_fingerprint_repeat_blocked" then
                            f.status, f.cursor, "explicit_eval_worklist_replay_fingerprint_repeat_required"
                        elif f.status = "semantic_joinpoint_term_stepper_blocked" then
                            f.status, f.cursor, "explicit_eval_worklist_joinpoint_term_stepper_required"
                        elif f.status = "semantic_joinpoint_value_blocked" then
                            f.status, f.cursor, "explicit_eval_worklist_joinpoint_value_required"
                        elif lateCapturedLeafCell then
                            "continuation_envelope", f.cursor, "replay_late_captured_leaf_cell"
                        elif orphanCapturedLeafCell then
                            "continuation_envelope", f.cursor, "replay_orphan_captured_leaf_cell"
                        elif isSemanticTerminalStatus f.status then
                            // ALPHA389: never rebuild a replay envelope from a semantic terminal state.
                            // Root completion must survive retry_stop_drain so BuildFile can retry safely.
                            f.status, f.cursor, semanticTerminalNext f.status
                        elif f.status = "continuation_envelope" then
                            "continuation_envelope", f.cursor, "schedule_term_ty_replay"
                        elif f.cursor < f.trace.Length then
                            "tracing_explicit_loop", f.cursor + 1, "advance_trace_cursor"
                        else
                            // ALPHA343/345: terminal replay envelope + driver scheduling. Do not advance forever after the trace is exhausted;
                            // materialize a deterministic continuation payload with replay anchors instead of a bare adapter gate marker.
                            "continuation_envelope", f.cursor, "build_replay_continuation_envelope"
                    let f' = { f with status = status'; cursor = cursor' }
                    frontier <- Some f'
                    emit (event + ":step") f'
                    DiagJson.emit (
                        sprintf "{\"kind\":\"eval_worklist_step\",\"event\":%s,\"step\":%d,\"budget\":%d,\"frame_kind\":%s,\"status\":%s,\"cursor\":%d,\"trace_lines\":%d,\"trace_loc\":%s,\"single_flight\":1,\"next\":%s}"
                            (esc event) step limit (esc f'.kind) (esc f'.status) f'.cursor f'.trace.Length (esc loc) (esc next'))
                    if next' = "replay_late_captured_leaf_cell" || next' = "replay_orphan_captured_leaf_cell" then
                        let cellText =
                            match f.semanticCell with
                            | Some cell -> formatCell cell
                            | None -> "none"
                        let marker =
                            if next' = "replay_orphan_captured_leaf_cell"
                            then "eval_worklist_orphan_captured_leaf_cell_replayed"
                            else "eval_worklist_late_captured_leaf_cell_replayed"
                        DiagJson.emit (
                            sprintf "{\"kind\":%s,\"event\":%s,\"frame_kind\":%s,\"frame_status\":%s,\"cursor\":%d,\"trace_lines\":%d,\"cell\":%s,\"pending\":%d,\"single_flight\":1,\"next\":\"schedule_term_ty_replay\"}"
                                (esc marker) (esc event) (esc f.kind) (esc f.status) f.cursor f.trace.Length (esc cellText) (pendingCount()))
                    if isTerminalAdapter f' then
                        emitAdapter event f'
                        scheduleReplay event f'
                    Some f')

        let runBounded (event: string) (budget: int) : Frame option =
            try
                let limit = if budget <= 0 then 1 else min budget 64
                if beginRun event then
                    try
                        let mutable steps = 0
                        let mutable last : Frame option = tryPeek()
                        let mutable blocked = false
                        while steps < limit && not blocked do
                            match stepOnce event steps limit with
                            | Some f ->
                                last <- Some f
                                steps <- steps + 1
                                blocked <- isTerminalAdapter f || isSemanticTerminalStatus f.status || f.status = "semantic_replay_fingerprint_repeat_blocked" || f.status = "semantic_joinpoint_term_stepper_blocked" || f.status = "semantic_joinpoint_value_blocked" || f.status = "semantic_replay_driver_exception_blocked" || f.status = "semantic_replay_payload_missing_blocked" || f.status = "semantic_payload_required"
                            | None ->
                                blocked <- true
                        let finalCursor =
                            match last with
                            | Some f -> f.cursor
                            | None -> -1
                        let finalStatus =
                            match last with
                            | Some f -> f.status
                            | None -> "empty"
                        DiagJson.emit (
                            sprintf "{\"kind\":\"eval_worklist_run\",\"event\":%s,\"steps\":%d,\"budget\":%d,\"pending\":%d,\"single_flight\":1,\"skipped\":0,\"final_status\":%s,\"cursor\":%d}"
                                (esc event) steps limit (pendingCount()) (esc finalStatus) finalCursor)
                        last
                    finally
                        endRun ()
                else
                    let frame = tryPeek()
                    DiagJson.emit (
                        sprintf "{\"kind\":\"eval_worklist_run\",\"event\":%s,\"steps\":0,\"budget\":%d,\"pending\":%d,\"single_flight\":1,\"skipped\":1,\"final_status\":%s,\"cursor\":%d}"
                            (esc event) limit (pendingCount())
                            (esc (match frame with Some f -> f.status | None -> "empty"))
                            (match frame with Some f -> f.cursor | None -> -1))
                    frame
            with _ -> None

        // ALPHA388: retry_stop is the supervisor's last synchronous chance to
        // finish a captured explicit worklist frontier.  Alpha387 proved that
        // ty replay could be half-drained (cursor=16/32) while another Hopac
        // worker still held the single-flight run token; retry_stop then
        // reported driver_state=none and aborted before the typed cell could
        // reach the replay driver.  Wait briefly for the active token, then run
        // a larger bounded drain.  This only advances trace/replay state; it
        // does not mark semantic_root_complete unless the typed stepper itself
        // proves it.
        let private drainAfterActiveRun (event: string) (budget: int) : Frame option =
            let limit = if budget <= 0 then 64 else min 256 (max 64 budget)
            // ALPHA471: the repeat-yield path can expose a two-kind dynamic-arg handoff
            // (term EApply blocked while a ty/TFun frontier resolves).  Keep the bound small,
            // but allow enough passes to alternate once after the first explicit dynamic block.
            let baseMaxPasses = 12
            // ALPHA507: retry_stop_drain may still be making real queued-replay
            // progress after twelve passes (alpha506 ended with replay_queue=1 and
            // a term_replay_driver still advancing the dynamic-record bridge).  Extend
            // only this terminal drain, and keep the bound finite/fail-closed.
            let maxPasses =
                // ALPHA508: alpha507 still made visible forward progress at pass 63
                // (same live queue, higher replay id, higher EApply step).  Keep the
                // extension terminal-only and finite, but allow enough turns for this
                // dynamic-record bridge to either discharge or reveal the next blocker.
                if event = "retry_stop_drain" then 256
                else baseMaxPasses
            let mutable waits = 0
            while waits < 16 && (lock gate (fun () -> activeRun)) do
                System.Threading.Thread.Sleep 5
                waits <- waits + 1
            let before = tryPeek()
            let mutable after = before
            let mutable pass = 0
            let mutable keepGoing = true
            while keepGoing && pass < maxPasses do
                if lock gate (fun () -> activeRun) then
                    keepGoing <- false
                else
                    if pass > 0 then
                        let status, cursor, next =
                            match after with
                            | Some frame -> frame.status, frame.cursor, nextFor frame
                            | None -> "missing_before_retry_drain_continue", -1, "retry_stop_raise"
                        DiagJson.emit (
                            sprintf "{\"kind\":\"eval_worklist_retry_drain_continue\",\"event\":%s,\"pass\":%d,\"status\":%s,\"cursor\":%d,\"replayCompleteNow\":%b,\"pending\":%d,\"single_flight\":1,\"next\":%s}"
                                (esc event) pass (esc status) cursor (hasReplayComplete()) (pendingCount()) (esc next))
                    if event = "retry_stop_drain" && pass >= baseMaxPasses && replayQueueDepth() > 0 then
                        let status, cursor, next =
                            match after with
                            | Some frame -> frame.status, frame.cursor, nextFor frame
                            | None -> "missing_before_retry_drain_live_queue_extend", -1, "run_replay_driver"
                        DiagJson.emit (
                            sprintf "{\"kind\":\"eval_worklist_retry_drain_live_queue_extend\",\"event\":%s,\"pass\":%d,\"status\":%s,\"cursor\":%d,\"queue_depth\":%d,\"pending\":%d,\"single_flight\":1,\"next\":%s}"
                                (esc event) pass (esc status) cursor (replayQueueDepth()) (pendingCount()) (esc next))
                    let drained = runBounded event limit
                    // ALPHA403: runBounded returns the last pre-driver frame when a synchronous
                    // replay driver commits semantic_root_complete from scheduleReplay.  Re-peek
                    // after the drain so callers do not see stale continuation_envelope.
                    let canonical0 =
                        match tryPeek() with
                        | Some frame when frame.status = "semantic_parent_continuation_cycle_blocked" -> Some frame
                        | Some frame when hasReplayComplete() -> Some frame
                        | _ -> drained
                    let canonicalFingerprintQueued =
                        match canonical0 with
                        | Some frame when event = "retry_stop_drain" && (frame.status = "semantic_replay_fingerprint_repeat_blocked" || frame.status = "semantic_joinpoint_term_stepper_blocked") && replayQueueDepth() > 0 ->
                            let qd0 = replayQueueDepth()
                            let cellText =
                                match frame.semanticCell with
                                | Some cell -> formatCell cell
                                | None -> "none"
                            DiagJson.emit (
                                sprintf "{\"kind\":\"eval_worklist_replay_fingerprint_live_queue_drain\",\"event\":%s,\"status\":%s,\"cursor\":%d,\"queue_depth_before\":%d,\"cell\":%s,\"pending\":%d,\"single_flight\":1,\"next\":\"run_replay_driver\"}"
                                    (esc event) (esc frame.status) frame.cursor qd0 (esc cellText) (pendingCount()))
                            runReplayDriver event
                            let qd1 = replayQueueDepth()
                            let afterDriver =
                                match tryPeek() with
                                | Some frame' -> Some frame'
                                | None -> canonical0
                            let statusAfter, cursorAfter =
                                match afterDriver with
                                | Some frame' -> frame'.status, frame'.cursor
                                | None -> "missing_after_fingerprint_live_queue_drain", -1
                            DiagJson.emit (
                                sprintf "{\"kind\":\"eval_worklist_replay_fingerprint_live_queue_drain_result\",\"event\":%s,\"status\":%s,\"cursor\":%d,\"queue_depth_after\":%d,\"pending\":%d,\"single_flight\":1,\"next\":%s}"
                                    (esc event) (esc statusAfter) cursorAfter qd1 (pendingCount()) (esc (if qd1 > 0 then "continue_retry_drain" else "retry_drain_repeek")))
                            afterDriver
                        | _ -> canonical0
                    let canonicalQueued =
                        match canonicalFingerprintQueued with
                        | Some frame when frame.status = "semantic_leaf_complete" && replayQueueDepth() > 0 ->
                            let qd0 = replayQueueDepth()
                            let cellText =
                                match frame.semanticCell with
                                | Some cell -> formatCell cell
                                | None -> "none"
                            DiagJson.emit (
                                sprintf "{\"kind\":\"eval_worklist_leaf_complete_queued_replay_drain\",\"event\":%s,\"status\":%s,\"cursor\":%d,\"queue_depth_before\":%d,\"cell\":%s,\"pending\":%d,\"single_flight\":1,\"next\":\"run_replay_driver\"}"
                                    (esc event) (esc frame.status) frame.cursor qd0 (esc cellText) (pendingCount()))
                            runReplayDriver event
                            let qd1 = replayQueueDepth()
                            let afterDriver =
                                match tryPeek() with
                                | Some frame' -> Some frame'
                                | None -> canonicalFingerprintQueued
                            let statusAfter, cursorAfter =
                                match afterDriver with
                                | Some frame' -> frame'.status, frame'.cursor
                                | None -> "missing_after_leaf_queued_replay_drain", -1
                            DiagJson.emit (
                                sprintf "{\"kind\":\"eval_worklist_leaf_complete_queued_replay_drain_result\",\"event\":%s,\"status\":%s,\"cursor\":%d,\"queue_depth_after\":%d,\"pending\":%d,\"single_flight\":1,\"next\":%s}"
                                    (esc event) (esc statusAfter) cursorAfter qd1 (pendingCount()) (esc (if qd1 > 0 then "continue_retry_drain" else "retry_drain_repeek")))
                            afterDriver
                        | _ -> canonicalFingerprintQueued
                    let canonical =
                        match canonicalQueued with
                        | Some frame ->
                            match tryYieldParentContinuationCycleBlocked event frame with
                            | Some selected -> Some selected
                            | None ->
                                match tryYieldTypeVariableValueMissingBlocked event frame with
                                | Some selected -> Some selected
                                | None ->
                                    match tryYieldStaleRootRetargetBlocked event frame with
                                    | Some selected -> Some selected
                                    | None ->
                                        match tryYieldLeafParentContinuationBlocked event frame with
                                        | Some selected -> Some selected
                                        | None ->
                                            match tryYieldReplayFingerprintRepeatBlocked event frame with
                                            | Some selected -> Some selected
                                            | None ->
                                                match tryYieldDynamicArgApplyBlocked event frame with
                                                | Some selected -> Some selected
                                                | None -> canonicalQueued
                        | None -> canonicalQueued
                    let canonical =
                        match canonical with
                        | Some frame -> preferPinnedTerminalForRetryDrain event frame
                        | None -> None
                    match canonical with
                    | Some frame ->
                        after <- Some frame
                        pass <- pass + 1
                        pinTerminalContract event frame
                        if (event = "retry_stop_drain" || event = "jp_wait_cycle_drain") && (frame.status = "semantic_replay_fingerprint_repeat_blocked" || frame.status = "semantic_joinpoint_term_stepper_blocked") then
                            DiagJson.emit (
                                sprintf "{\"kind\":\"eval_worklist_terminal_replay_fingerprint_repeat_drain_stopped\",\"event\":%s,\"pass\":%d,\"status\":%s,\"cursor\":%d,\"queue_depth\":%d,\"pending\":%d,\"single_flight\":1,\"next\":%s}"
                                    (esc event) pass (esc frame.status) frame.cursor (replayQueueDepth()) (pendingCount()) (esc (nextFor frame)))
                            keepGoing <- false
                        elif event = "retry_stop_drain" && frame.status = "semantic_let_success_apply_exception_blocked" && replayQueueDepth() = 0 then
                            DiagJson.emit (
                                sprintf "{\"kind\":\"eval_worklist_terminal_let_success_apply_exception_drain_stopped\",\"event\":%s,\"pass\":%d,\"status\":%s,\"cursor\":%d,\"pending\":%d,\"single_flight\":1,\"next\":%s}"
                                    (esc event) pass (esc frame.status) frame.cursor (pendingCount()) (esc (nextFor frame)))
                            keepGoing <- false
                        elif isTerminalContractStatus frame.status then
                            DiagJson.emit (
                                sprintf "{\"kind\":\"eval_worklist_terminal_contract_drain_stopped\",\"event\":%s,\"pass\":%d,\"status\":%s,\"cursor\":%d,\"rank\":%d,\"pending\":%d,\"single_flight\":1,\"next\":%s}"
                                    (esc event) pass (esc frame.status) frame.cursor (terminalContractRank frame.status) (pendingCount()) (esc (nextFor frame)))
                            keepGoing <- false
                        elif event = "retry_stop_drain" && frame.status = "semantic_replay_driver_exception_blocked" && replayQueueDepth() = 0 then
                            DiagJson.emit (
                                sprintf "{\"kind\":\"eval_worklist_terminal_replay_exception_drain_stopped\",\"event\":%s,\"pass\":%d,\"status\":%s,\"cursor\":%d,\"pending\":%d,\"single_flight\":1,\"next\":%s}"
                                    (esc event) pass (esc frame.status) frame.cursor (pendingCount()) (esc (nextFor frame)))
                            keepGoing <- false
                        elif event = "retry_stop_drain" && pass >= baseMaxPasses && frame.status = "semantic_root_complete" && pendingCount() > 0 && replayQueueDepth() = 0 && (hasProgressYield() || replayDriverActiveDepthValue() > 0) then
                            // ALPHA953: pending-jobs terminals are only hard terminals when
                            // the typed liveness seam says no cooperative replay is still in
                            // flight. Runtime 952 showed this terminal could pin while a
                            // progress-yield retry and deferred parent replay were still
                            // observable immediately afterwards.
                            after <- Some frame
                            DiagJson.emit (
                                sprintf "{\"kind\":\"eval_worklist_root_complete_pending_jobs_progress_yield_allowed\",\"event\":%s,\"pass\":%d,\"status\":%s,\"cursor\":%d,\"pending\":%d,\"queue_depth\":%d,\"active_depth\":%d,\"progress_yield_pending\":%b,\"policy\":\"defer_pending_jobs_terminal_while_typed_replay_liveness_is_present\",\"single_flight\":1,\"next\":\"retry_stop_progress_yield\"}"
                                    (esc event) pass (esc frame.status) frame.cursor (pendingCount()) (replayQueueDepth()) (replayDriverActiveDepthValue()) (hasProgressYield()))
                            keepGoing <- false
                        elif event = "retry_stop_drain" && pass >= baseMaxPasses && frame.status = "semantic_root_complete" && pendingCount() > 0 && replayQueueDepth() = 0 then
                            // ALPHA939: alpha938 proved the ty-reentry preflight can drain and return
                            // concrete typed values, but retry_stop_drain could still stop on a
                            // semantic_root_complete frontier while JP bookkeeping reported outstanding
                            // bodies and no replay queue. Make that state an explicit terminal contract
                            // instead of falling back to an open-ended wait/manual interrupt. This does
                            // not close the writer barrier, does not mark BuildFile.replay_root_complete,
                            // and does not synthesize missing JP bodies.
                            let blockedCellOpt =
                                match frame.semanticCell with
                                | Some cell -> Some { cell with status = "semantic_root_complete_pending_jobs_blocked" }
                                | None -> None
                            let blockedPayload =
                                match blockedCellOpt with
                                | Some cell -> Some (formatCellPayload cell)
                                | None -> frame.semanticPayload
                            let blockedFrame =
                                { frame with
                                    status = "semantic_root_complete_pending_jobs_blocked"
                                    reason = "retry_stop_root_complete_pending_jobs_no_queue"
                                    semanticCell = blockedCellOpt
                                    semanticPayload = blockedPayload }
                            after <- Some blockedFrame
                            pinTerminalContract event blockedFrame
                            DiagJson.emit (
                                sprintf "{\"kind\":\"eval_worklist_retry_stop_root_complete_pending_jobs_terminal_pinned\",\"event\":%s,\"pass\":%d,\"status\":%s,\"cursor\":%d,\"pending\":%d,\"rank\":%d,\"queue_depth\":%d,\"single_flight\":1,\"next\":%s}"
                                    (esc event) pass (esc blockedFrame.status) blockedFrame.cursor (pendingCount()) (terminalContractRank blockedFrame.status) (replayQueueDepth()) (esc (terminalContractNext blockedFrame.status)))
                            keepGoing <- false
                        elif event = "retry_stop_drain" && pass >= baseMaxPasses && frame.status = "semantic_leaf_complete" && replayQueueDepth() = 0 then
                            DiagJson.emit (
                                sprintf "{\"kind\":\"eval_worklist_terminal_leaf_no_queue_drain_stopped\",\"event\":%s,\"pass\":%d,\"status\":%s,\"cursor\":%d,\"pending\":%d,\"single_flight\":1,\"next\":%s}"
                                    (esc event) pass (esc frame.status) frame.cursor (pendingCount()) (esc (nextFor frame)))
                            keepGoing <- false
                    | None ->
                        keepGoing <- false
                        pass <- pass + 1
            match after with
            | Some _ -> after
            | None -> before

        let drainRetryStop (budget: int) : Frame option =
            drainAfterActiveRun "retry_stop_drain" budget

        // ALPHA392: forced sequential jp_wait can observe a term-cycle fuse before
        // EJP0014.  Alpha391 proved this path may already have a live frontier at
        // cursor=8/32, but the small jp_wait slice only advanced to cursor=24 and
        // left retry_stop to finish.  Drain the same frontier here, while preserving
        // the invariant that only typed replay may set semantic_root_complete.
        let drainJpCyclePreflight (budget: int) : Frame option =
            try
                let before = tryPeek()
                let after = drainAfterActiveRun "jp_wait_cycle_drain" budget
                let status, cursor, complete, next =
                    match after with
                    | Some frame -> frame.status, frame.cursor, hasReplayComplete(), nextFor frame
                    | None -> "missing_after_cycle_drain", -1, hasReplayComplete(), "jp_wait_cycle_raise"
                DiagJson.emit (
                    sprintf "{\"kind\":\"eval_worklist_jp_cycle_preflight\",\"event\":\"jp_wait_observed_sequential_cycle_fuse\",\"status\":%s,\"cursor\":%d,\"replayCompleteNow\":%b,\"pending\":%d,\"single_flight\":1,\"next\":%s}"
                        (esc status) cursor complete (pendingCount()) (esc next))
                match after with
                | Some _ -> after
                | None -> before
            with _ -> None

        // ALPHA391: EJP0014 jp_wait stalls are liveness frontiers too.  If a
        // semantic worklist frame is already present, or a cycle fuse can be
        // captured, spend a bounded synchronous slice draining it before the
        // retry path invalidates the generation.  This preserves alpha390's
        // write-gate strictness: only typed replay can set semantic_root_complete.
        let drainJpStallPreflight (event: string) (budget: int) : Frame option =
            try
                let before =
                    match tryPeek() with
                    | Some frame -> Some frame
                    | None -> ensureCaptured "jp_wait_stall_preflight"
                match before with
                | Some _ ->
                    promoteHead event |> ignore
                    let after = drainRetryStop budget
                    let status, cursor, complete, next =
                        match after with
                        | Some frame -> frame.status, frame.cursor, hasReplayComplete(), nextFor frame
                        | None -> "missing_after_drain", -1, hasReplayComplete(), "abort_without_write"
                    DiagJson.emit (
                        sprintf "{\"kind\":\"eval_worklist_jp_stall_preflight\",\"event\":%s,\"status\":%s,\"cursor\":%d,\"replayCompleteNow\":%b,\"pending\":%d,\"single_flight\":1,\"next\":%s}"
                            (esc event) (esc status) cursor complete (pendingCount()) (esc next))
                    after
                | None ->
                    DiagJson.emit (
                        sprintf "{\"kind\":\"eval_worklist_jp_stall_preflight\",\"event\":%s,\"status\":\"missing_frontier\",\"cursor\":-1,\"replayCompleteNow\":false,\"pending\":0,\"single_flight\":1,\"next\":\"jp_wait_retry_diag\"}"
                            (esc event))
                    None
            with _ -> None

        let ensureCapturedAndRun (reason: string) (event: string) (budget: int) : Frame option =
            match ensureCaptured reason with
            | Some _ ->
                promoteHead event |> ignore
                runBounded event budget
            | None -> None

        let requiredMessage (msg: string) (frame: Frame) =
            let cellState = match frame.semanticCell with Some c -> formatCell c | None -> "none"
            let replayComplete = frame.status = "semantic_root_complete" || (match frame.semanticCell with Some c -> c.status = "semantic_root_complete" | None -> false)
            let completeness =
                if replayComplete then "complete"
                elif frame.status = "semantic_leaf_complete" then "leaf_complete_parent_continuation_missing"
                elif frame.status = "semantic_leaf_parent_continuation_missing_blocked" then "leaf_parent_continuation_missing_blocked"
                elif frame.status = "semantic_selected_frontier_repeat_blocked" then "selected_frontier_repeat_blocked"
                elif frame.status = "semantic_replay_driver_exception_blocked" then "replay_driver_exception_blocked"
                elif frame.status = "semantic_replay_payload_missing_blocked" then "replay_payload_missing_blocked"
                elif frame.status = "semantic_joinpoint_value_blocked" then "joinpoint_value_blocked"
                elif frame.status = "semantic_replay_fingerprint_repeat_blocked" then "replay_fingerprint_repeat_blocked"
                elif frame.status = "semantic_if_unknown_return_condition_blocked" then "if_unknown_return_condition_blocked"
                elif frame.status = "semantic_if_symbolic_condition_blocked" then "if_symbolic_condition_blocked"
                elif frame.status = "semantic_joinpoint_term_stepper_blocked" then "joinpoint_term_stepper_blocked"
                elif frame.status = "semantic_macro_thunk_missing_blocked" then "macro_thunk_missing_blocked"
                elif frame.status = "semantic_tjoinpoint_stepper_blocked" then "tjoinpoint_stepper_blocked"
                elif frame.status = "semantic_literal_op_body_stepper_blocked" then "literal_op_body_stepper_blocked"
                elif frame.status = "semantic_dynamic_join_apply_blocked" then "dynamic_join_apply_blocked"
                elif frame.status = "semantic_nominal_constructor_stepper_blocked" then "nominal_constructor_stepper_blocked"
                elif frame.status = "semantic_seq_type_error_blocked" then "seq_type_error_blocked"
                elif frame.status = "semantic_parent_continuation_cycle_blocked" then "parent_continuation_cycle_blocked"
                elif frame.status = "semantic_global_fuse_parent_continuation_cycle_blocked" then "global_fuse_parent_continuation_cycle_blocked"
                elif frame.status = "semantic_parent_replay_status_preserved_repeat_blocked" then "parent_replay_status_preserved_repeat_blocked"
                elif frame.status = "semantic_replay_obligation_deferred" then "replay_obligation_deferred"
                elif frame.status = "semantic_type_variable_value_missing_blocked" then "type_variable_value_missing_blocked"
                elif frame.status = "semantic_stale_root_retarget_blocked" then "stale_root_retarget_blocked"
                elif frame.status = "semantic_let_success_apply_exception_blocked" then "let_success_apply_exception_blocked"
                elif frame.status = "semantic_let_success_all_ready_apply_blocked" then "let_success_all_ready_apply_blocked"
                elif frame.status = "semantic_let_success_apply_continuation_blocked" then "let_success_apply_continuation_blocked"
                elif frame.status = "semantic_type_apply_forall_body_stepper_blocked" then "type_apply_forall_body_stepper_blocked"
                elif frame.status = "semantic_apply_continuation_exception_blocked" then "apply_continuation_exception_blocked"
                elif frame.status = "semantic_deferred_function_replay_exception_blocked" then "deferred_function_replay_exception_blocked"
                elif frame.status = "semantic_step_partial" || frame.status = "semantic_step_done" then "partial_one_step_only"
                else "not_complete"
            sprintf "%s\nEvalWorklistFrame: kind=%s status=%s site=%s key=%s reason=%s depth=%d re=%d/%d trace_lines=%d pending=%d cursor=%d single_flight=1 replay_queue=%d semantic_payload=%s replay_complete=%b replay_completeness=%s replay_cell=%s adapter=trace_replay_continuation next=%s driver=%s driver_state=%s payload=%s"
                msg frame.kind frame.status frame.site frame.key (compactFrameReason frame.reason) frame.depth frame.re frame.maxRe frame.trace.Length (pendingCount()) frame.cursor (replayQueueDepth()) (semanticPayloadStatus()) replayComplete completeness cellState (nextFor frame) (replayDriverFor frame) (replayDriverStatus()) (adapterPayload frame)


        // ALPHA540: when a global fuse abort is raised after retry_stop has already
        // selected a high-rank terminal, make the raised message name that terminal.
        // This prevents run_tests/root-source traces from looking like the live
        // problem when the real blocker is the pinned macro/literal/payload contract.
        //
        // ALPHA541: the alpha540 marker proved the retarget worked but also showed
        // unbounded marker churn: 377 retarget events in alpha540, followed by stale
        // semantic_root_complete returns.  Treat rank >= 80 pinned terminals as a
        // hard global-fuse contract and rate-limit marker emission by pinned key.
        let private globalFuseTerminalRetargetSeen = System.Collections.Concurrent.ConcurrentDictionary<string, int>()

        let private retargetSeenOnce (key: string) =
            globalFuseTerminalRetargetSeen.TryAdd(key, 1)

        let private highRankPinnedTerminal (requestedKind: string) =
            match tryPinnedTerminalContract() with
            | Some pinned ->
                let rank = terminalContractRank pinned.status
                if rank >= 80 && frameKindCompatible requestedKind pinned then Some (pinned, rank)
                elif rank >= 80 then
                    // ALPHA1047: pre-Hopac kind locality. A high-rank terminal from a
                    // different evaluator kind is evidence for its own lane, not a
                    // selector for this global-fuse probe. Clear only the active pin;
                    // durable evidence remains available to same-kind consumers.
                    let cleared = lock gate (fun () -> clearCurrentCrossKindPinnedTerminalLocked pinned)
                    emitCrossKindPinnedTerminalIgnored "global_fuse_terminal_probe" requestedKind pinned rank (sprintf "high_rank_terminal_belongs_to_other_kind cleared=%b" cleared)
                    if cleared then
                        DiagJson.emit (
                            sprintf "{\"kind\":\"eval_worklist_cross_kind_global_fuse_active_pin_cleared\",\"event\":\"global_fuse_terminal_probe\",\"requested_kind\":%s,\"pinned_kind\":%s,\"pinned_status\":%s,\"pinned_rank\":%d,\"pinned_site\":%s,\"pinned_key\":%s,\"pending\":%d,\"single_flight\":1,\"policy\":\"pre_hopac_kind_local_terminal_contracts\",\"next\":\"preserve_kind_local_frontier\"}"
                                (esc requestedKind) (esc pinned.kind) (esc pinned.status) rank (esc pinned.site) (esc pinned.key) (pendingCount()))
                    None
                else None
            | None -> None

        let private trimOriginalFuseForMessage (msg: string) =
            let withoutFrame =
                let marker = "\nEvalWorklistFrame:"
                let idx = msg.IndexOf(marker, System.StringComparison.Ordinal)
                if idx >= 0 then msg.Substring(0, idx) else msg
            withoutFrame.Replace("\r", " ").Replace("\n", " ⏎ ")

        let terminalPrimaryMessage (requestedKind: string) (msg: string) (pinned: Frame) (rank: int) =
            let emitKey = sprintf "primary|%s|%s|%s" requestedKind pinned.status pinned.key
            if retargetSeenOnce emitKey then
                DiagJson.emit (
                    sprintf "{\"kind\":\"eval_worklist_terminal_primary_message_selected\",\"event\":%s,\"requested_kind\":%s,\"status\":%s,\"rank\":%d,\"site\":%s,\"key\":%s,\"pending\":%d,\"single_flight\":1,\"next\":%s}"
                        (esc "terminal_primary_message") (esc requestedKind) (esc pinned.status) rank (esc pinned.site) (esc pinned.key) (pendingCount()) (esc (nextFor pinned)))
            let primaryPrefix = "[spiral_compiler] EJP0011: pinned terminal contract blocked"
            let alreadyPrimary =
                not (System.String.IsNullOrEmpty msg)
                && msg.StartsWith(primaryPrefix, System.StringComparison.Ordinal)
                && msg.IndexOf("pinned_terminal=", System.StringComparison.Ordinal) >= 0
            if alreadyPrimary then
                if retargetSeenOnce (emitKey + "|idempotent") then
                    DiagJson.emit (
                        sprintf "{\"kind\":\"eval_worklist_terminal_primary_message_idempotent\",\"event\":%s,\"requested_kind\":%s,\"status\":%s,\"rank\":%d,\"site\":%s,\"key\":%s,\"pending\":%d,\"single_flight\":1,\"next\":%s}"
                            (esc "terminal_primary_message") (esc requestedKind) (esc pinned.status) rank (esc pinned.site) (esc pinned.key) (pendingCount()) (esc (nextFor pinned)))
                if msg.IndexOf("\nEvalWorklistFrame:", System.StringComparison.Ordinal) >= 0 then msg else requiredMessage msg pinned
            else
                let originalFuse = trimOriginalFuseForMessage msg
                let pinnedMsg =
                    sprintf "[spiral_compiler] EJP0011: pinned terminal contract blocked status=%s rank=%d site=%s requested_kind=%s\npinned_terminal=%s pinned_rank=%d pinned_site=%s requested_kind=%s original_fuse=%s"
                        pinned.status rank pinned.site requestedKind pinned.status rank pinned.site requestedKind originalFuse
                requiredMessage pinnedMsg pinned

        let private pinnedTerminalMessage (requestedKind: string) (msg: string) (pinned: Frame) (rank: int) =
            terminalPrimaryMessage requestedKind msg pinned rank

        let retargetGlobalFuseAbortMessage (event: string) (requestedKind: string) (msg: string) =
            match highRankPinnedTerminal requestedKind with
            | Some (pinned, rank) ->
                let emitKey = sprintf "abort|%s|%s|%s|%s" event requestedKind pinned.status pinned.key
                if retargetSeenOnce emitKey then
                    DiagJson.emit (
                        sprintf "{\"kind\":\"eval_worklist_global_fuse_abort_retargeted_to_pinned_terminal\",\"event\":%s,\"requested_kind\":%s,\"pinned_status\":%s,\"pinned_rank\":%d,\"pinned_site\":%s,\"pinned_key\":%s,\"pending\":%d,\"single_flight\":1,\"rate_limited\":1,\"next\":%s}"
                            (esc event) (esc requestedKind) (esc pinned.status) rank (esc pinned.site) (esc pinned.key) (pendingCount()) (esc (nextFor pinned)))
                pinnedTerminalMessage requestedKind msg pinned rank
            | None -> msg

        let trySuppressGlobalFuseReplayReturnForPinnedTerminal (event: string) (requestedKind: string) (shape: string) (msg: string) =
            match highRankPinnedTerminal requestedKind with
            | Some (pinned, rank) ->
                let freshReplayRootWitnessAvailable =
                    let ageMs = (System.DateTime.UtcNow - replayRootCompleteWitnessUtc).TotalMilliseconds
                    replayRootCompleteWitnessUtc <> System.DateTime.MinValue
                    && ageMs >= 0.0
                    && ageMs <= replayRootCompleteWitnessWindowMs
                let freshRootWitnessShieldsOpImplReturn =
                    pinned.status = "semantic_op_impl_required_blocked"
                    && pendingCount() > 0
                    && freshReplayRootWitnessAvailable
                    && frameCellShapeOrSemanticEvidence ["EOp"] pinned
                    && (shape = "TFun"
                        || shape = "EApply"
                        || shape = "EV"
                        || shape = "EForall'"
                        || shape = "ETypeApply"
                        || shape = "EOp")
                let staleListmSymbolicIfRootReturn =
                    pinned.status = "semantic_if_symbolic_condition_blocked"
                    && pendingCount() > 0
                    && frameCellShapeOrSemanticEvidence ["EIfThenElse"] pinned
                    && (shape = "TFun"
                        || shape = "EApply"
                        || shape = "EV"
                        || shape = "EForall'"
                        || shape = "ETypeApply")
                if freshRootWitnessShieldsOpImplReturn then
                    let durableCleared =
                        lock gate (fun () ->
                            match pinnedTerminalContract with
                            | Some p when p.status = "semantic_op_impl_required_blocked" && p.site = pinned.site ->
                                pinnedTerminalContract <- None
                            | _ -> ()
                            match durableTerminalContract with
                            | Some p when p.status = "semantic_op_impl_required_blocked" && p.site = pinned.site ->
                                durableTerminalContract <- None
                                true
                            | _ -> false)
                    DiagJson.emit (
                        sprintf "{\"kind\":\"eval_worklist_global_fuse_root_return_demotes_fresh_op_impl_required\",\"event\":%s,\"requested_kind\":%s,\"shape\":%s,\"pinned_status\":%s,\"pinned_rank\":%d,\"pinned_site\":%s,\"pinned_key\":%s,\"pending\":%d,\"durable_cleared\":%b,\"witness\":%s,\"single_flight\":1,\"next\":\"allow_root_complete_replay_return\"}"
                            (esc event) (esc requestedKind) (esc shape) (esc pinned.status) rank (esc pinned.site) (esc pinned.key) (pendingCount()) durableCleared (esc replayRootCompleteWitnessSummary))
                    None
                elif staleListmSymbolicIfRootReturn then
                    let durableCleared =
                        lock gate (fun () ->
                            match pinnedTerminalContract with
                            | Some p when p.status = "semantic_if_symbolic_condition_blocked" && p.site = pinned.site ->
                                pinnedTerminalContract <- None
                            | _ -> ()
                            match durableTerminalContract with
                            | Some p when p.status = "semantic_if_symbolic_condition_blocked" && p.site = pinned.site ->
                                durableTerminalContract <- None
                                true
                            | _ -> false)
                    DiagJson.emit (
                        sprintf "{\"kind\":\"eval_worklist_global_fuse_root_return_demotes_stale_if_symbolic\",\"event\":%s,\"requested_kind\":%s,\"shape\":%s,\"pinned_status\":%s,\"pinned_rank\":%d,\"pinned_site\":%s,\"pinned_key\":%s,\"pending\":%d,\"durable_cleared\":%b,\"single_flight\":1,\"next\":\"allow_root_complete_replay_return\"}"
                            (esc event) (esc requestedKind) (esc shape) (esc pinned.status) rank (esc pinned.site) (esc pinned.key) (pendingCount()) durableCleared)
                    None
                else
                    let emitKey = sprintf "return|%s|%s|%s|%s|%s" event requestedKind shape pinned.status pinned.key
                    if retargetSeenOnce emitKey then
                        DiagJson.emit (
                            sprintf "{\"kind\":\"eval_worklist_global_fuse_replay_return_suppressed_by_pinned_terminal\",\"event\":%s,\"requested_kind\":%s,\"shape\":%s,\"pinned_status\":%s,\"pinned_rank\":%d,\"pinned_site\":%s,\"pinned_key\":%s,\"pending\":%d,\"single_flight\":1,\"next\":%s}"
                                (esc event) (esc requestedKind) (esc shape) (esc pinned.status) rank (esc pinned.site) (esc pinned.key) (pendingCount()) (esc (nextFor pinned)))
                    Some (pinnedTerminalMessage requestedKind msg pinned rank)
            | None -> None


    /// ### JoinPointKey
    type JoinPointKey =
        | JPMethod of (string ConsedNode * E) * ConsedNode<RData [] * Ty [] * Ty>
        | JPClosure of (string ConsedNode * E) * ConsedNode<RData [] * Ty [] * Ty>
    

    /// ### JoinPointCall
    type JoinPointCall = JoinPointKey * TyV []
    

    /// ### CodeMacro
    type CodeMacro =
        | CMText of string
        | CMTerm of Data * is_inline : bool
        | CMType of Ty
        | CMTypeLit of Ty
    

    /// ### TypedBind
    type TypedBind =
        | TyLet of Data * Trace * TypedOp
        | TyLocalReturnOp of Trace * TypedOp * Data
        | TyLocalReturnData of Data * Trace
    

    and TypedOp =
        | TyMacro of CodeMacro list
        | TyOp of Op * Data list
        | TyUnionBox of string * Data * Union
        | TyUnionUnbox of TyV list * Union * Map<string,Data list * TypedBind []> * TypedBind [] option
        | TyIntSwitch of TyV * TypedBind [] [] * TypedBind []
        | TyToLayout of Data * Ty
        | TyLayoutIndexAll of TyV
        | TyLayoutIndexByKey of TyV * string
        | TyLayoutMutableSet of TyV * string list * Data
        | TyFailwith of Ty * Data
        | TyApply of TyV * Data
        | TyConv of Ty * Data
        | TySizeOf of Ty
        | TyArrayLiteral of Ty * Data list
        | TyArrayCreate of Ty * Data
        | TyArrayLength of Ty * Data
        | TyStringLength of Ty * Data
        | TyIf of cond: Data * tr: TypedBind [] * fl: TypedBind []
        | TyWhile of cond: JoinPointCall * TypedBind []
        | TyDo of TypedBind []
        | TyIndent of TypedBind []
        | TyJoinPoint of JoinPointCall
        | TyBackend of (string ConsedNode * E) * ConsedNode<RData [] * Ty [] * Ty> * Range
    

    /// ### UnionRewrite
    type UnionRewrite = UnionData of string * Data | UnionBlockers of string Set
    

    /// ### LangEnv
    type LangEnv = {
        trace : Trace
        seq : ResizeArray<TypedBind>
        cse : Dictionary<TypedOp, Data> list
        unions : Map<TyV, UnionRewrite>
        i : int ref
        env_global_type : Ty []
        env_global_term : Data []
        env_stack_type : Ty []
        env_stack_term : Data []
        backend : string ConsedNode
        globals : ResizeArray<string>
        globals_lock : obj
        globals_seen : System.Collections.Concurrent.ConcurrentDictionary<string, byte>
        join_point_method_key_names : System.Collections.Concurrent.ConcurrentDictionary<ConsedNode<RData [] * Ty [] * Ty>, string>
        join_point_closure_key_names : System.Collections.Concurrent.ConcurrentDictionary<ConsedNode<RData [] * Ty [] * Ty>, string>
        jp_method_stack : System.Collections.Generic.HashSet<ConsedNode<RData [] * Ty [] * Ty>>
        jp_closure_stack : System.Collections.Generic.HashSet<ConsedNode<RData [] * Ty [] * Ty>>
        jp_type_stack : System.Collections.Generic.HashSet<ConsedNode<Ty []>>
        }

    let private evalNodeShapeTerm (x: E) =
        match x with
        | EFun _ -> "EFun" | EFun' _ -> "EFun'" | EForall _ -> "EForall" | EForall' _ -> "EForall'"
        | ERecursiveFun' _ -> "ERecursiveFun'" | ERecursiveForall' _ -> "ERecursiveForall'" | ERecursive _ -> "ERecursive" | EPatternRef _ -> "EPatternRef"
        | EJoinPoint _ -> "EJoinPoint" | EJoinPoint' _ -> "EJoinPoint'" | EB _ -> "EB" | EV _ -> "EV" | ELit _ -> "ELit" | EDefaultLit _ -> "EDefaultLit"
        | ESymbol _ -> "ESymbol" | EType _ -> "EType" | EApply _ -> "EApply" | EArray _ -> "EArray" | ETypeApply _ -> "ETypeApply" | ERecBlock _ -> "ERecBlock"
        | ERecordWith _ -> "ERecordWith" | EModule _ -> "EModule" | EOp _ -> "EOp" | EPatternMiss _ -> "EPatternMiss" | ETypePatternMiss _ -> "ETypePatternMiss"
        | EAnnot _ -> "EAnnot" | EIfThenElse _ -> "EIfThenElse" | EIfThen _ -> "EIfThen" | EPair _ -> "EPair" | ESeq _ -> "ESeq" | EMutableSet _ -> "EMutableSet"
        | EReal _ -> "EReal" | EExists _ -> "EExists" | EMacro _ -> "EMacro" | EPrototypeApply _ -> "EPrototypeApply" | EPatternMemo _ -> "EPatternMemo" | ENominal _ -> "ENominal"
        | ELet _ -> "ELet" | EUnbox _ -> "EUnbox" | EExistsTest _ -> "EExistsTest" | EPairTest _ -> "EPairTest" | ESymbolTest _ -> "ESymbolTest"
        | ERecordTest _ -> "ERecordTest" | EAnnotTest _ -> "EAnnotTest" | ENominalTest _ -> "ENominalTest" | EUnitTest _ -> "EUnitTest" | ELitTest _ -> "ELitTest" | EDefaultLitTest _ -> "EDefaultLitTest" | ETypecase _ -> "ETypecase"

    let private evalNodeShapeTy (x: TPrepass) =
        match x with
        | TForall' _ -> "TForall'" | TForall _ -> "TForall" | TArrow' _ -> "TArrow'" | TArrow _ -> "TArrow" | TExists -> "TExists"
        | TJoinPoint' _ -> "TJoinPoint'" | TJoinPoint _ -> "TJoinPoint" | TPatternRef _ -> "TPatternRef" | TB _ -> "TB" | TLit _ -> "TLit" | TV _ -> "TV"
        | TPair _ -> "TPair" | TFun _ -> "TFun" | TRecord _ -> "TRecord" | TModule _ -> "TModule" | TUnion _ -> "TUnion" | TSymbol _ -> "TSymbol"
        | TApply _ -> "TApply" | TPrim _ -> "TPrim" | TTerm _ -> "TTerm" | TMacro _ -> "TMacro" | TNominal _ -> "TNominal" | TArray _ -> "TArray" | TLayout _ -> "TLayout" | TMetaV _ -> "TMetaV" | TTypecase _ -> "TTypecase"

    let private evalPayload (kind: string) (shape: string) (nodeId: int) (site: string) (s: LangEnv) =
        sprintf "semantic_eval_payload(kind=%s,shape=%s,node_id=%d,env_term=%d/%d,env_type=%d/%d,seq_len=%d,cse_depth=%d,trace_depth=%d,site=%s)"
            kind shape nodeId s.env_global_term.Length s.env_stack_term.Length s.env_global_type.Length s.env_stack_type.Length s.seq.Count s.cse.Length s.trace.Length site

    let private evalCell (kind: string) (shape: string) (nodeId: int) (site: string) (s: LangEnv) : EvalWorklist.ReplayCell =
        // ALPHA403: PartEvalResult.ty_to_data intentionally keeps seq = null
        // after partial evaluation.  Codegen may still force nominal type
        // application while TermCycleFuse is armed, so replay diagnostics must
        // describe that post-peval environment without dereferencing nullable
        // fields or allocating fake codegen state.
        let safeArrayLen (xs: 'a []) = if obj.ReferenceEquals(xs, null) then 0 else xs.Length
        let safeResizeCount (xs: ResizeArray<'a>) = if obj.ReferenceEquals(xs, null) then 0 else xs.Count
        let safeListLen (xs: 'a list) = if obj.ReferenceEquals(xs, null) then 0 else xs.Length
        let envGlobalTerm, envStackTerm, envGlobalType, envStackType, seqLen, cseDepth, traceDepth =
            if obj.ReferenceEquals(s, null) then
                0, 0, 0, 0, 0, 0, 0
            else
                safeArrayLen s.env_global_term,
                safeArrayLen s.env_stack_term,
                safeArrayLen s.env_global_type,
                safeArrayLen s.env_stack_type,
                safeResizeCount s.seq,
                safeListLen s.cse,
                safeListLen s.trace
        { kind = kind
          shape = shape
          nodeId = nodeId
          envGlobalTerm = envGlobalTerm
          envStackTerm = envStackTerm
          envGlobalType = envGlobalType
          envStackType = envStackType
          seqLen = seqLen
          cseDepth = cseDepth
          traceDepth = traceDepth
          site = site
          cursor = 0
          step = 0
          status = "new" }
    

    /// ### show_ty
    let show_ty x =
        let rec f prec x =
            let p = p prec
            match x with
            | YVoid -> "void"
            | YB -> "()"
            | YLit x -> show_lit x
            | YPair(a,b) -> p 25 (sprintf "%s * %s" (f 25 a) (f 24 b))
            | YSymbol x -> sprintf ".%s" x
            | YTypeFunction _ -> p 0 (sprintf "? => ?")
            | YForall -> p 0 (sprintf "forall ?. ?")
            | YExists -> p 0 (sprintf "exists ?. ?")
            | YRecord l -> sprintf "{%s}" (l |> Map.toList |> List.map (fun ((_,k),v) -> sprintf "%s : %s" k (f -1 v)) |> String.concat "; ")
            | YUnion l -> sprintf "{%s}" (l.Item.cases |> Map.toList |> List.map (fun ((_,k),v) -> sprintf "%s : %s" k (f -1 v)) |> String.concat " | ")
            | YPrim x -> show_primt x
            | YArray a -> p 30 (sprintf "array_base %s" (f 30 a))
            | YFun(a,b,FT_Vanilla) -> p 20 (sprintf "%s -> %s" (f 20 a) (f 19 b))
            | YFun(a,b,FT_Pointer) -> p 20 (sprintf "fptr (%s -> %s)" (f 20 a) (f 19 b))
            | YFun(a,b,FT_Closure) -> p 20 (sprintf "closure (%s -> %s)" (f 20 a) (f 19 b))
            | YMacro a -> p 30 (List.map (function TypeLit a | Type a -> f -1 a | Text a -> a) a |> String.concat "")
            | YApply(a,b) -> p 30 (sprintf "%s %s" (f 29 a) (f 30 b))
            | YLayout(a,b) -> p 30 (sprintf "%s %s" (show_layout_type b) (f 30 a))
            | YNominal x -> x.node.name
            | YMetavar _ -> "?"
        f -1 x
    

    /// ### Type-class helpers for diagnostic validation
    /// Used to detect obvious cache collisions (e.g., returning i32 when function expected).
    let is_ty_callable ty =
        match ty with
        | YFun _ | YForall | YTypeFunction _ -> true
        | YLayout(inner, _) ->
            match inner with
            | YFun _ | YRecord _ -> true
            | _ -> false
        | YNominal n ->
            // Some nominals wrap functions.
            match n.node.name with
            | s when s.Contains("fun") || s.Contains("closure") || s.Contains("Func") -> true
            | _ -> false
        | _ -> false
    

    let is_ty_primitive ty =
        match ty with
        | YPrim _ | YLit _ -> true
        | _ -> false
    

    /// ### RetryTracker
    /// Thread-safe tracking of retry attempts for EJP0003 type errors.
    /// Helps detect when retries are resolving issues vs when they're failing consistently.
    module RetryTracker =
        open System
        open System.Collections.Concurrent
        open System.Threading
    

        let mutable private attemptCount = 0
        let mutable private successCount = 0
        let mutable private failCount = 0
        let private inRetry = new ThreadLocal<int>(fun () -> 0)
    

        let isInRetry () = inRetry.Value > 0
    

        let enterRetry () =
            inRetry.Value <- inRetry.Value + 1
            Interlocked.Increment(&attemptCount) |> ignore
    

        let exitRetrySuccess () =
            inRetry.Value <- max 0 (inRetry.Value - 1)
            Interlocked.Increment(&successCount) |> ignore
    

        let exitRetryFail () =
            inRetry.Value <- max 0 (inRetry.Value - 1)
            Interlocked.Increment(&failCount) |> ignore
    

        let getStats () =
            sprintf "attempts=%d success=%d fail=%d" attemptCount successCount failCount
    

        let logIfActive () =
            let a, s, f = attemptCount, successCount, failCount
            if a > 0 then
                DiagSidecar.emit (sprintf "RetryTracker: %s" (getStats ()))
    

    /// ### DiagNN
    /// Small, online "neural-ish" helper for diagnostics: hashed embeddings + cosine similarity.
    /// Always enabled in v43+ for error pattern clustering. Lightweight and thread-safe.
    module DiagNN =
        open System
        open System.Collections.Concurrent
    

        let private dims = 64
    

        let inline enabled () = true  // v43: always on
    

        let private centroids = ConcurrentDictionary<string, float []>()
        let private counts = ConcurrentDictionary<string, int>()
    

        let private fnv1a32 (s: string) : uint32 =
            let mutable h = 2166136261u
            for i = 0 to s.Length - 1 do
                h <- (h ^^^ uint32 (int s.[i])) * 16777619u
            h
    

        let private embed (s: string) : float [] =
            let v = Array.zeroCreate<float> dims
            if String.IsNullOrEmpty s then v
            else
                // Simple tokenization; stable enough for clustering and similarity hints.
                let toks =
                    s.Split([|' '; '\t'; '\r'; '\n'; '|'; ','; ';'; '('; ')'; '['; ']'; '{'; '}'; '<'; '>'; ':'; '='; '\''; '"'|],
                            StringSplitOptions.RemoveEmptyEntries)
                let n = min toks.Length 512
                for i = 0 to n - 1 do
                    let t = toks.[i]
                    let h = fnv1a32 t
                    let idx = int (h % uint32 dims)
                    let sign = if (h &&& 1u) = 0u then 1.0 else -1.0
                    v.[idx] <- v.[idx] + sign
                // L2 normalize (avoid div0).
                let mutable norm = 0.0
                for i = 0 to dims - 1 do norm <- norm + v.[i] * v.[i]
                if norm > 0.0 then
                    let inv = 1.0 / sqrt norm
                    for i = 0 to dims - 1 do v.[i] <- v.[i] * inv
                v
    

        let private cosine (a: float []) (b: float []) : float =
            let mutable dot = 0.0
            let mutable i = 0
            while i < dims do
                dot <- dot + a.[i] * b.[i]
                i <- i + 1
            dot
    

        let record (clusterKey: string) (payload: string) : string option =
            if not (enabled ()) then None
            else
                try
                    let x = embed payload
                    let c = counts.AddOrUpdate(clusterKey, 1, (fun _ n -> n + 1))
                    let w = centroids.GetOrAdd(clusterKey, (fun _ -> Array.zeroCreate<float> dims))
                    lock w (fun () ->
                        // Exponential-ish moving average; stable enough for hints.
                        let alpha = 1.0 / float c
                        for i = 0 to dims - 1 do
                            w.[i] <- w.[i] + alpha * (x.[i] - w.[i])
                    )
                    // Nearest neighbors among existing clusters (bounded scan; only when enabled).
                    let mutable best1 = ("", -1.0)
                    let mutable best2 = ("", -1.0)
                    let mutable best3 = ("", -1.0)
                    for kv in centroids do
                        let k = kv.Key
                        if k <> clusterKey then
                            let s = cosine x kv.Value
                            if s > snd best1 then
                                best3 <- best2
                                best2 <- best1
                                best1 <- (k, s)
                            elif s > snd best2 then
                                best3 <- best2
                                best2 <- (k, s)
                            elif s > snd best3 then
                                best3 <- (k, s)
                    let fmt (k, s) =
                        if k = "" then ""
                        else sprintf "%s(%.2f)" k s
                    let near =
                        [ fmt best1; fmt best2; fmt best3 ]
                        |> List.filter (fun s -> s <> "")
                        |> String.concat ", "
                    Some (sprintf "cluster=%s count=%d near=[%s]" clusterKey c near)
                with _ ->
                    None
    

    /// ### CacheGeneration
    /// Global generation counter for cache invalidation in deep recursion scenarios.
    /// When cache corruption is detected (EJP0007/EJP0008), incrementing the generation
    /// marks all older entries as stale, enabling clean retry without full cache flush.
    module CacheGeneration =
        open System
        open System.Threading
    

        let mutable private generation = 0L
        let private lastInvalidationTime = ref DateTime.MinValue
        let private invalidationReasons = System.Collections.Concurrent.ConcurrentQueue<string>()
    

        let mutable private invalidation_count = 0L
        let invalidationCount () = Interlocked.Read(&invalidation_count)

        // Alpha100: fallback sequencial escopado (ativado apenas por retries; reset no inicio do build)
        let mutable private jp_force_sequential = 0
        // Alpha36: allow subsystems to register cache-clear callbacks that run on invalidation.
        let private onInvalidate = System.Collections.Concurrent.ConcurrentBag<string -> unit>()
        let registerOnInvalidate (f: string -> unit) =
            onInvalidate.Add f

        let requestSequential () =
            // Ativa um modo “sem races” para o retry atual, sem virar estado oculto permanente.
            if Interlocked.Exchange(&jp_force_sequential, 1) = 0 then
                DiagSidecar.emit (sprintf "CacheGeneration.requestSequential: enabled gen=%d" (Interlocked.Read(&generation)))

        let resetSequentialRequest () =
            if Interlocked.Exchange(&jp_force_sequential, 0) <> 0 then
                DiagSidecar.emit (sprintf "CacheGeneration.requestSequential: reset gen=%d" (Interlocked.Read(&generation)))

        let isSequentialRequested () = Interlocked.CompareExchange(&jp_force_sequential, 0, 0) <> 0
    

        /// Get current generation number
        let current () = Interlocked.Read(&generation)
        do Progress88.set_gen_provider current
    

        /// Invalidate cache generation with a reason string for diagnostics
        let invalidate (reason: string) =
            let newGen = Interlocked.Increment(&generation)
            Interlocked.Increment(&invalidation_count) |> ignore
            lastInvalidationTime := DateTime.UtcNow
            invalidationReasons.Enqueue(sprintf "[gen=%d] %s @ %s" newGen reason (DateTime.UtcNow.ToString("HH:mm:ss.fff")))
            // Keep only last 32 reasons
            while invalidationReasons.Count > 32 do
                let mutable v = Unchecked.defaultof<string>
                invalidationReasons.TryDequeue(&v) |> ignore
            DiagSidecar.emit (sprintf "CacheGeneration.invalidate: gen=%d reason=%s" newGen reason)
            // Alpha36: best-effort clear hooks to prevent stale placeholder resolutions from leaking across generations.
            try
                for cb in onInvalidate do
                    try cb reason with _ -> ()
            with _ -> ()
            newGen

        /// Record a diagnostic reason without changing the cache generation.
        /// ALPHA468: jp_wait can close after a typed replay root-complete proof in the
        /// same build attempt.  The writer needs that proof in the reason ledger, but
        /// incrementing the generation here would turn success back into a retry.
        let noteReason (reason: string) =
            let gen = Interlocked.Read(&generation)
            invalidationReasons.Enqueue(sprintf "[gen=%d] %s @ %s" gen reason (DateTime.UtcNow.ToString("HH:mm:ss.fff")))
            while invalidationReasons.Count > 32 do
                let mutable v = Unchecked.defaultof<string>
                invalidationReasons.TryDequeue(&v) |> ignore
            DiagSidecar.emit (sprintf "CacheGeneration.noteReason: gen=%d reason=%s" gen reason)

        /// Snapshot recent invalidation reasons (most recent first), for diagnostics
        let reasonsSnapshot (n: int) : string list =
            try
                invalidationReasons.ToArray()
                |> Array.rev
                |> (fun a -> if n <= 0 then [||] else a |> Array.truncate (min n a.Length))
                |> Array.toList
            with _ -> []
    

        /// Check if a generation is stale (older than current)
        let isStale (g: int64) = g < Interlocked.Read(&generation)
    

        /// Get recent invalidation reasons for diagnostics
        let getRecentReasons () = invalidationReasons.ToArray() |> Array.toList
    

    /// ### RecursionTracker
    /// Thread-local recursion depth tracking for detecting deep nesting scenarios
    /// like sm'.replicate → join_body_unit loops that trigger cache corruption.
    module RecursionTracker =
        open System
        open System.Threading
        open System.Collections.Concurrent
    

        let private threadDepth = new ThreadLocal<int>(fun () -> 0)
        let mutable private maxObserved = 0
        let private deepCallSites = ConcurrentDictionary<string, int>()
    

        /// Enter a recursive context, returns current depth
        let enter (site: string) : int =
            let d = threadDepth.Value + 1
            threadDepth.Value <- d
            // Track max observed depth
            let mutable current = maxObserved
            while d > current && Interlocked.CompareExchange(&maxObserved, d, current) <> current do
                current <- maxObserved
            // Track deep call sites (> 50 depth)
            if d > 50 then
                deepCallSites.AddOrUpdate(site, 1, (fun _ n -> n + 1)) |> ignore
            d
    

        /// Exit a recursive context
        let exit () =
            threadDepth.Value <- max 0 (threadDepth.Value - 1)
    

        /// Get current recursion depth for this thread
        let currentDepth () = threadDepth.Value
    

        /// Set recursion depth directly (for BigStack thread inheritance)
        let setDepth (d: int) = threadDepth.Value <- d
    

        /// Check if currently in deep recursion (> 100)
        let isDeep () = threadDepth.Value > 100
    

        /// Check if moderately deep (> 50)
        let isModeratelyDeep () = threadDepth.Value > 50
    

        /// Get max observed depth across all threads
        let getMaxObserved () = maxObserved
    

        /// Get deep call site statistics
        let getDeepSites () = deepCallSites.ToArray() |> Array.toList
    
    
    
    
    





    /// BigStack: Executes thunks on dedicated threads with large stacks.
    /// Used for deep recursion when EnsureSufficientExecutionStack triggers.
    /// 
    ///
    /// CONFIGURATION (hardcoded SOTA defaults):
    /// - Stack size: 256MB per level (enough for 100K+ recursive calls)
    /// - Max nesting: 32 levels (8GB total address space)
    /// - Automatic depth inheritance across BigStack boundaries
    

    module BigStack =
        open System
        open System.Threading
    

        /// Thread-local nesting counter (0 = main stack, >0 = inside BigStack)
        let private active : ThreadLocal<int> = new ThreadLocal<int>(fun () -> 0)
    

        /// True if currently executing on a BigStack thread
        let isActive () = active.Value > 0
    

        // SOTA defaults - no environment variable overrides
        let private stackMb = 256         // baseline MB per stack level
        let private maxNestingLevels = 32 // alpha180: cap nesting; prefer larger first stacks (big stacks park parent frames)

        // v128-alpha180: Bigger first-stack for deep Spiral list recursion (listm.spi foldBack/map).
        // Prefer a single large stack to avoid BigStack nesting (parent stacks remain parked).
        let private stackBytesFor (tag: string) (nestLevel: int) : int * int =
            let mb =
                match tag with
                | _ when tag.StartsWith("term") ->
                    // v130-alpha186: grow first stacks so we don't trampoline-nest into BigStack until exhaustion.
                    // NOTE: Thread stack size is an Int32; keep < 2GB to avoid overflow.
                    if nestLevel <= 4 then 1792 else 1536
                | _ when tag.StartsWith("ty") ->
                    if nestLevel <= 4 then 1792 else 1536
                | _ when tag.StartsWith("jp_") ->
                    if nestLevel <= 2 then 512 else stackMb
                | "peval_main" ->
                    if nestLevel = 1 then 1792 else 1024
                | _ -> stackMb
            // keep overall address-space bounded when deeply nested
            let mb =
                if tag.StartsWith("term") || tag.StartsWith("ty") then mb
                elif nestLevel >= 16 then min mb 256
                else mb
            let bytes64 = (int64 mb) <<< 20
            let bytes =
                if bytes64 > int64 Int32.MaxValue then Int32.MaxValue
                else int bytes64
            mb, bytes


        /// Current nesting level (0 = main, 1+ = BigStack depth)
        let getNest () = active.Value

        /// Get effective MB for the given tag
        let getMb (tag: string) = fst (stackBytesFor tag (getNest () + 1))
    

        /// Maximum allowed nesting (32 levels)
        let getMaxNest () = maxNestingLevels
    

        /// Stack size in MB (256MB)
        let getGlobalMb () = stackMb
    

        /// Execute f on a BigStack thread if nesting limit not exceeded.
        /// Returns None if max nesting reached (caller should handle gracefully).
        let tryRun<'T> (tag: string) (f: unit -> 'T) : 'T option =
            let parentNest = active.Value
            let parentDepth = RecursionTracker.currentDepth()

            // v131-alpha190: If we're already on a BigStack thread, prefer running inline.
            // This avoids runaway trampoline nesting (EJP0010) triggered by repeated stack checks inside deep recursion.
            let spawn () =
                if parentNest >= maxNestingLevels then
                    try DiagSidecar.emit (sprintf "[spiral_compiler] BIGSTACK exhausted tag=%s parentNest=%d maxNest=%d" tag parentNest maxNestingLevels) with _ -> ()
                    None
                else
                    let nestLevel = parentNest + 1
                    // v129-alpha181: Inherit parent depth to reduce runaway nesting (we allocate large stacks for term/ty).
                    // (was: reset-to-1 heuristic; removed)
                    let mutable res = Unchecked.defaultof<'T>
                    let mutable err : exn option = None
                    let mutable childTid = -1
                    let mb, stackBytes = stackBytesFor tag nestLevel
                    let th =
                        new Thread(ThreadStart(fun () ->
                            childTid <- Thread.CurrentThread.ManagedThreadId
                            active.Value <- nestLevel
                            // v129-alpha181: Inherit parent depth.
                            // alpha209: clamp inherited depth to avoid false EJP0009 when we cross BigStack boundaries many times
                            // (Depth is a diagnostic guard; semantic cycles are handled primarily by EvalCycleGuard.)
                            let inherited =
                                if tag.StartsWith("term") || tag.StartsWith("ty") then min parentDepth 8192 else parentDepth
                            RecursionTracker.setDepth inherited
                            try
                                try
                                    res <- f ()
                                with e ->
                                    err <- Some e
                            finally
                                active.Value <- parentNest
                        ), stackBytes)
                    th.IsBackground <- true
                    try th.Name <- sprintf "spiral.bigstack.%s" tag with _ -> ()
                    try
                        DiagSidecar.emit (sprintf "[spiral_compiler] BIGSTACK spawn tag=%s nest=%d/%d mb=%d bytes=%d parent_tid=%d" tag nestLevel maxNestingLevels mb stackBytes Thread.CurrentThread.ManagedThreadId)
                    with _ -> ()
                    // v107-alpha14: avoid flowing ExecutionContext/AsyncLocal into BigStack threads

                    let flow = System.Threading.ExecutionContext.SuppressFlow()

                    try

                        th.Start()

                    finally

                        flow.Undo()
                    // [BIGSTACK-211-001] Avoid infinite Join() hangs; abort on generation change / long stall.
                    // ALPHA446: a completed semantic replay frontier is also a liveness signal.
                    // Alpha445 proved the child BigStack can keep spinning on the same
                    // TJoinPoint' ty_entry while EvalWorklist is already semantic_root_complete;
                    // without this escape the parent only notices after the 240s hard timeout.
                    let gen0 = CacheGeneration.current()
                    let join_slice_ms = 250
                    let join_abort_ms = 240000
                    let join_gen_change_abort_ms = 2000
                    let join_root_complete_probe_ms = 1500
                    let join_root_complete_probe_cap = 2
                    let mutable waited = 0
                    let mutable gen_changed : (int64 * int64 * int) option = None
                    let mutable genWaitTJoinPointGraceEmitted = false
                    let mutable pinnedTerminalFirstSeen : (int * string) option = None
                    try
                        while not (th.Join(join_slice_ms)) do
                            waited <- waited + join_slice_ms
                            let gen1 = CacheGeneration.current()
                            if gen1 <> gen0 && Option.isNone gen_changed then
                                gen_changed <- Some (gen0, gen1, waited)
                                let note = sprintf "[spiral_compiler] EJP0018: BigStack join saw generation change (from %d to %d) tag=%s waited=%dms (short grace before abort)" gen0 gen1 tag waited
                                try DiagSidecar.emit note with _ -> ()
                                CacheGeneration.requestSequential ()
                            let deferGenWaitForStaleTJoinPointRootProbe =
                                TermCycleFuse.isTripped()
                                && (try
                                        match EvalWorklist.tryPinnedTerminalContract() with
                                        | Some pinned when pinned.status = "semantic_tjoinpoint_stepper_blocked" ->
                                            EvalWorklist.terminalContractRank pinned.status < 90
                                            && pinned.kind = "ty"
                                            && (match pinned.semanticCell with
                                                | Some cell -> cell.shape = "TJoinPoint'" || cell.shape = "TJoinPoint"
                                                | None -> true)
                                            && (EvalWorklist.hasReplayComplete()
                                                || EvalWorklist.hasReplayCompleteWriteWitness()
                                                || EvalWorklist.pendingCount() > 0)
                                        | _ -> false
                                    with _ -> false)
                            if deferGenWaitForStaleTJoinPointRootProbe && not genWaitTJoinPointGraceEmitted then
                                genWaitTJoinPointGraceEmitted <- true
                                let cycle_key, cycle_site, cycle_depth, _cycle_gen, cycle_re, cycle_max_re = TermCycleFuse.describe()
                                let pinnedSite =
                                    try
                                        match EvalWorklist.tryPinnedTerminalContract() with
                                        | Some pinned -> pinned.site
                                        | None -> ""
                                    with _ -> ""
                                DiagJson.emit (
                                    sprintf "{\"kind\":\"eval_worklist_gen_wait_deferred_for_stale_tjoinpoint\",\"event\":\"bigstack_join_wait\",\"tag\":%s,\"waited_ms\":%d,\"grace_ms\":%d,\"pinned_site\":%s,\"cycle_site\":%s,\"cycle_depth\":%d,\"re\":%d,\"max_re\":%d,\"pending\":%d,\"replay_complete\":%b,\"write_witness\":%b,\"single_flight\":1,\"next\":\"respect_generation_wait_grace_for_root_complete_probe\"}"
                                        (DiagJson.esc tag) waited join_gen_change_abort_ms (DiagJson.esc pinnedSite) (DiagJson.esc cycle_site) cycle_depth cycle_re cycle_max_re (EvalWorklist.pendingCount()) (EvalWorklist.hasReplayComplete()) (EvalWorklist.hasReplayCompleteWriteWitness()))
                            let pinnedTerminalForJoin =
                                try
                                    match EvalWorklist.tryPinnedTerminalContract() with
                                    | Some pinned -> Some pinned
                                    | None -> EvalWorklist.tryDurableTerminalContract()
                                with _ -> None
                            match pinnedTerminalForJoin with
                            | Some pinned when EvalWorklist.terminalContractRank pinned.status >= 80 ->
                                let rank = EvalWorklist.terminalContractRank pinned.status
                                let firstWait =
                                    match pinnedTerminalFirstSeen with
                                    | Some (w, _) -> w
                                    | None ->
                                        pinnedTerminalFirstSeen <- Some (waited, pinned.key)
                                        DiagJson.emit (
                                            sprintf "{\"kind\":\"eval_worklist_bigstack_pinned_terminal_seen\",\"event\":\"join_wait\",\"tag\":%s,\"waited_ms\":%d,\"status\":%s,\"rank\":%d,\"site\":%s,\"key\":%s,\"pending\":%d,\"queue_depth\":%d,\"replay_complete\":%b,\"write_witness\":%b,\"single_flight\":1,\"next\":\"rank80_terminal_ready_for_bigstack_handoff\"}"
                                                (DiagJson.esc tag) waited (DiagJson.esc pinned.status) rank (DiagJson.esc pinned.site) (DiagJson.esc pinned.key) (EvalWorklist.pendingCount()) (EvalWorklist.replayQueueDepth()) (EvalWorklist.hasReplayComplete()) (EvalWorklist.hasReplayCompleteWriteWitness()))
                                        waited
                                let terminalAge = max 0 (waited - firstWait)
                                let boundedGlobalFuseTerminalAlreadyPinned =
                                    pinned.status = "semantic_global_fuse_parent_continuation_cycle_blocked"
                                    && (
                                        pinned.reason = "bounded_term_parent_continuation_global_fuse"
                                        || pinned.reason = "bounded_ty_parent_continuation_global_fuse"
                                        || pinned.reason = "bounded_parent_continuation_global_fuse"
                                    )
                                let liveReplayForGlobalFuseTerminal =
                                    EvalWorklist.pendingCount() > 0
                                    && (EvalWorklist.replayQueueDepth() > 0 || EvalWorklist.replayDriverActiveDepthValue() > 0)
                                    && not (EvalWorklist.hasReplayComplete())
                                let boundedGlobalFuseTerminalQuietForJoin =
                                    boundedGlobalFuseTerminalAlreadyPinned
                                    && terminalAge >= join_root_complete_probe_ms
                                    && (EvalWorklist.replayQueueDepth() = 0)
                                    && (EvalWorklist.replayDriverActiveDepthValue() = 0)
                                let boundedGlobalFuseTerminalStaleActiveNoQueueForJoin =
                                    boundedGlobalFuseTerminalAlreadyPinned
                                    && terminalAge >= (join_root_complete_probe_ms * 40)
                                    && (EvalWorklist.replayQueueDepth() = 0)
                                    && (EvalWorklist.replayDriverActiveDepthValue() >= 8)
                                    && (EvalWorklist.pendingCount() > 0)
                                    && not (EvalWorklist.hasReplayComplete())
                                    && not (EvalWorklist.hasReplayCompleteWriteWitness())
                                let boundedGlobalFuseTerminalWitnessStaleActiveNoQueueForJoin =
                                    // ALPHA1069: alpha1068 repeated the same already-pinned rank80 bounded global-fuse
                                    // terminal at sm'_real.spir:251 for 25.5s with pending=2, queue=0, active=24,
                                    // replay_complete=false and write_witness=true, then required manual ^C before the
                                    // prior 75s witness threshold. Keep the q=0 + witness + active replay gates, but
                                    // accept the explicit terminal after a shorter stale-active window so the watchdog
                                    // emits EJP0021 instead of spinning forever.
                                    boundedGlobalFuseTerminalAlreadyPinned
                                    && terminalAge >= (join_root_complete_probe_ms * 15)
                                    && (EvalWorklist.replayQueueDepth() = 0)
                                    && (EvalWorklist.replayDriverActiveDepthValue() >= 8)
                                    && (EvalWorklist.pendingCount() > 0)
                                    && not (EvalWorklist.hasReplayComplete())
                                    && EvalWorklist.hasReplayCompleteWriteWitness()
                                let boundedGlobalFuseTerminalReadyForJoin =
                                    boundedGlobalFuseTerminalQuietForJoin
                                    || boundedGlobalFuseTerminalStaleActiveNoQueueForJoin
                                    || boundedGlobalFuseTerminalWitnessStaleActiveNoQueueForJoin
                                let deferGenericGlobalFuseForLiveReplay =
                                    pinned.status = "semantic_global_fuse_parent_continuation_cycle_blocked"
                                    && not boundedGlobalFuseTerminalAlreadyPinned
                                    && liveReplayForGlobalFuseTerminal
                                let deferBoundedGlobalFuseForLiveReplay =
                                    boundedGlobalFuseTerminalAlreadyPinned
                                    && not boundedGlobalFuseTerminalReadyForJoin
                                    && (liveReplayForGlobalFuseTerminal || terminalAge < join_root_complete_probe_ms)
                                if deferGenericGlobalFuseForLiveReplay then
                                    DiagJson.emit (
                                        sprintf "{\"kind\":\"eval_worklist_bigstack_global_fuse_terminal_deferred_for_live_replay\",\"event\":\"join_wait\",\"tag\":%s,\"waited_ms\":%d,\"terminal_age_ms\":%d,\"status\":%s,\"rank\":%d,\"site\":%s,\"key\":%s,\"pending\":%d,\"queue_depth\":%d,\"active_depth\":%d,\"replay_complete\":%b,\"write_witness\":%b,\"policy\":\"rank80_global_fuse_cannot_outvote_runnable_replay_until_bounded_terminal_pinned\",\"single_flight\":1,\"next\":\"continue_active_replay_driver\"}"
                                            (DiagJson.esc tag) waited terminalAge (DiagJson.esc pinned.status) rank (DiagJson.esc pinned.site) (DiagJson.esc pinned.key) (EvalWorklist.pendingCount()) (EvalWorklist.replayQueueDepth()) (EvalWorklist.replayDriverActiveDepthValue()) (EvalWorklist.hasReplayComplete()) (EvalWorklist.hasReplayCompleteWriteWitness()))
                                elif deferBoundedGlobalFuseForLiveReplay then
                                    DiagJson.emit (
                                        sprintf "{\"kind\":\"eval_worklist_bigstack_bounded_global_fuse_terminal_deferred_for_live_replay\",\"event\":\"join_wait\",\"tag\":%s,\"waited_ms\":%d,\"terminal_age_ms\":%d,\"status\":%s,\"rank\":%d,\"site\":%s,\"key\":%s,\"reason\":%s,\"pending\":%d,\"queue_depth\":%d,\"active_depth\":%d,\"replay_complete\":%b,\"write_witness\":%b,\"policy\":\"bounded_global_fuse_terminal_requires_quiet_stable_replay_before_bigstack_handoff\",\"single_flight\":1,\"next\":\"continue_active_replay_driver\"}"
                                            (DiagJson.esc tag) waited terminalAge (DiagJson.esc pinned.status) rank (DiagJson.esc pinned.site) (DiagJson.esc pinned.key) (DiagJson.esc pinned.reason) (EvalWorklist.pendingCount()) (EvalWorklist.replayQueueDepth()) (EvalWorklist.replayDriverActiveDepthValue()) (EvalWorklist.hasReplayComplete()) (EvalWorklist.hasReplayCompleteWriteWitness()))
                                elif boundedGlobalFuseTerminalStaleActiveNoQueueForJoin then
                                    DiagJson.emit (
                                        sprintf "{\"kind\":\"eval_worklist_bigstack_bounded_global_fuse_terminal_stale_active_no_queue_handoff_enabled\",\"event\":\"join_wait\",\"tag\":%s,\"waited_ms\":%d,\"terminal_age_ms\":%d,\"status\":%s,\"rank\":%d,\"site\":%s,\"key\":%s,\"reason\":%s,\"pending\":%d,\"queue_depth\":%d,\"active_depth\":%d,\"replay_complete\":%b,\"write_witness\":%b,\"policy\":\"bounded_global_fuse_terminal_stale_active_no_queue\",\"single_flight\":1,\"next\":\"bigstack_pinned_terminal_handoff\"}"
                                            (DiagJson.esc tag) waited terminalAge (DiagJson.esc pinned.status) rank (DiagJson.esc pinned.site) (DiagJson.esc pinned.key) (DiagJson.esc pinned.reason) (EvalWorklist.pendingCount()) (EvalWorklist.replayQueueDepth()) (EvalWorklist.replayDriverActiveDepthValue()) (EvalWorklist.hasReplayComplete()) (EvalWorklist.hasReplayCompleteWriteWitness()))
                                    DiagJson.emit (
                                        sprintf "{\"kind\":\"eval_worklist_bigstack_pinned_terminal_handoff\",\"event\":\"join_wait\",\"tag\":%s,\"waited_ms\":%d,\"terminal_age_ms\":%d,\"status\":%s,\"rank\":%d,\"site\":%s,\"key\":%s,\"reason\":%s,\"pending\":%d,\"queue_depth\":%d,\"replay_complete\":%b,\"write_witness\":%b,\"single_flight\":1,\"next\":%s}"
                                            (DiagJson.esc tag) waited terminalAge (DiagJson.esc pinned.status) rank (DiagJson.esc pinned.site) (DiagJson.esc pinned.key) (DiagJson.esc pinned.reason) (EvalWorklist.pendingCount()) (EvalWorklist.replayQueueDepth()) (EvalWorklist.hasReplayComplete()) (EvalWorklist.hasReplayCompleteWriteWitness()) (DiagJson.esc (EvalWorklist.terminalContractNext pinned.status)))
                                    let msg = sprintf "[spiral_compiler] EJP0021: BigStack join accepted stale-active no-queue bounded global-fuse terminal tag=%s waited=%dms terminal_age=%dms status=%s rank=%d site=%s key=%s pending=%d queue=%d active=%d" tag waited terminalAge pinned.status rank pinned.site pinned.key (EvalWorklist.pendingCount()) (EvalWorklist.replayQueueDepth()) (EvalWorklist.replayDriverActiveDepthValue())
                                    try DiagSidecar.emit msg with _ -> ()
                                    raise (PartEvalTypeError([], EvalWorklist.requiredMessage msg pinned))
                                elif boundedGlobalFuseTerminalWitnessStaleActiveNoQueueForJoin then
                                    DiagJson.emit (
                                        sprintf "{\"kind\":\"eval_worklist_bigstack_bounded_global_fuse_terminal_witness_stale_active_no_queue_handoff_enabled\",\"event\":\"join_wait\",\"tag\":%s,\"waited_ms\":%d,\"terminal_age_ms\":%d,\"status\":%s,\"rank\":%d,\"site\":%s,\"key\":%s,\"reason\":%s,\"pending\":%d,\"queue_depth\":%d,\"active_depth\":%d,\"replay_complete\":%b,\"write_witness\":%b,\"policy\":\"bounded_global_fuse_terminal_witness_stale_active_no_queue\",\"single_flight\":1,\"next\":\"bigstack_pinned_terminal_handoff\"}"
                                            (DiagJson.esc tag) waited terminalAge (DiagJson.esc pinned.status) rank (DiagJson.esc pinned.site) (DiagJson.esc pinned.key) (DiagJson.esc pinned.reason) (EvalWorklist.pendingCount()) (EvalWorklist.replayQueueDepth()) (EvalWorklist.replayDriverActiveDepthValue()) (EvalWorklist.hasReplayComplete()) (EvalWorklist.hasReplayCompleteWriteWitness()))
                                    DiagJson.emit (
                                        sprintf "{\"kind\":\"eval_worklist_bigstack_pinned_terminal_handoff\",\"event\":\"join_wait\",\"tag\":%s,\"waited_ms\":%d,\"terminal_age_ms\":%d,\"status\":%s,\"rank\":%d,\"site\":%s,\"key\":%s,\"reason\":%s,\"pending\":%d,\"queue_depth\":%d,\"replay_complete\":%b,\"write_witness\":%b,\"single_flight\":1,\"next\":%s}"
                                            (DiagJson.esc tag) waited terminalAge (DiagJson.esc pinned.status) rank (DiagJson.esc pinned.site) (DiagJson.esc pinned.key) (DiagJson.esc pinned.reason) (EvalWorklist.pendingCount()) (EvalWorklist.replayQueueDepth()) (EvalWorklist.hasReplayComplete()) (EvalWorklist.hasReplayCompleteWriteWitness()) (DiagJson.esc (EvalWorklist.terminalContractNext pinned.status)))
                                    let msg = sprintf "[spiral_compiler] EJP0021: BigStack join accepted witness stale-active no-queue bounded global-fuse terminal tag=%s waited=%dms terminal_age=%dms status=%s rank=%d site=%s key=%s pending=%d queue=%d active=%d" tag waited terminalAge pinned.status rank pinned.site pinned.key (EvalWorklist.pendingCount()) (EvalWorklist.replayQueueDepth()) (EvalWorklist.replayDriverActiveDepthValue())
                                    try DiagSidecar.emit msg with _ -> ()
                                    raise (PartEvalTypeError([], EvalWorklist.requiredMessage msg pinned))
                                elif boundedGlobalFuseTerminalReadyForJoin then
                                    DiagJson.emit (
                                        sprintf "{\"kind\":\"eval_worklist_bigstack_bounded_global_fuse_terminal_handoff_enabled\",\"event\":\"join_wait\",\"tag\":%s,\"waited_ms\":%d,\"terminal_age_ms\":%d,\"status\":%s,\"rank\":%d,\"site\":%s,\"key\":%s,\"reason\":%s,\"pending\":%d,\"queue_depth\":%d,\"active_depth\":%d,\"replay_complete\":%b,\"write_witness\":%b,\"policy\":\"bounded_global_fuse_terminal_quiet_and_stable\",\"single_flight\":1,\"next\":\"bigstack_pinned_terminal_handoff\"}"
                                            (DiagJson.esc tag) waited terminalAge (DiagJson.esc pinned.status) rank (DiagJson.esc pinned.site) (DiagJson.esc pinned.key) (DiagJson.esc pinned.reason) (EvalWorklist.pendingCount()) (EvalWorklist.replayQueueDepth()) (EvalWorklist.replayDriverActiveDepthValue()) (EvalWorklist.hasReplayComplete()) (EvalWorklist.hasReplayCompleteWriteWitness()))
                                    DiagJson.emit (
                                        sprintf "{\"kind\":\"eval_worklist_bigstack_pinned_terminal_handoff\",\"event\":\"join_wait\",\"tag\":%s,\"waited_ms\":%d,\"terminal_age_ms\":%d,\"status\":%s,\"rank\":%d,\"site\":%s,\"key\":%s,\"reason\":%s,\"pending\":%d,\"queue_depth\":%d,\"replay_complete\":%b,\"write_witness\":%b,\"single_flight\":1,\"next\":%s}"
                                            (DiagJson.esc tag) waited terminalAge (DiagJson.esc pinned.status) rank (DiagJson.esc pinned.site) (DiagJson.esc pinned.key) (DiagJson.esc pinned.reason) (EvalWorklist.pendingCount()) (EvalWorklist.replayQueueDepth()) (EvalWorklist.hasReplayComplete()) (EvalWorklist.hasReplayCompleteWriteWitness()) (DiagJson.esc (EvalWorklist.terminalContractNext pinned.status)))
                                    let msg = sprintf "[spiral_compiler] EJP0021: BigStack join accepted quiet bounded global-fuse terminal tag=%s waited=%dms terminal_age=%dms status=%s rank=%d site=%s key=%s pending=%d queue=%d" tag waited terminalAge pinned.status rank pinned.site pinned.key (EvalWorklist.pendingCount()) (EvalWorklist.replayQueueDepth())
                                    try DiagSidecar.emit msg with _ -> ()
                                    raise (PartEvalTypeError([], EvalWorklist.requiredMessage msg pinned))
                                elif waited >= join_root_complete_probe_ms || terminalAge >= join_slice_ms || EvalWorklist.pendingCount() > 0 then
                                    DiagJson.emit (
                                        sprintf "{\"kind\":\"eval_worklist_bigstack_pinned_terminal_handoff\",\"event\":\"join_wait\",\"tag\":%s,\"waited_ms\":%d,\"terminal_age_ms\":%d,\"status\":%s,\"rank\":%d,\"site\":%s,\"key\":%s,\"reason\":%s,\"pending\":%d,\"queue_depth\":%d,\"replay_complete\":%b,\"write_witness\":%b,\"single_flight\":1,\"next\":%s}"
                                            (DiagJson.esc tag) waited terminalAge (DiagJson.esc pinned.status) rank (DiagJson.esc pinned.site) (DiagJson.esc pinned.key) (DiagJson.esc pinned.reason) (EvalWorklist.pendingCount()) (EvalWorklist.replayQueueDepth()) (EvalWorklist.hasReplayComplete()) (EvalWorklist.hasReplayCompleteWriteWitness()) (DiagJson.esc (EvalWorklist.terminalContractNext pinned.status)))
                                    let msg = sprintf "[spiral_compiler] EJP0021: BigStack join observed pinned terminal contract tag=%s waited=%dms terminal_age=%dms status=%s rank=%d site=%s key=%s pending=%d queue=%d" tag waited terminalAge pinned.status rank pinned.site pinned.key (EvalWorklist.pendingCount()) (EvalWorklist.replayQueueDepth())
                                    try DiagSidecar.emit msg with _ -> ()
                                    raise (PartEvalTypeError([], EvalWorklist.requiredMessage msg pinned))
                            | _ -> ()

                            match gen_changed with
                            | Some (g0, g1, w1) when (TermCycleFuse.isTripped() && not deferGenWaitForStaleTJoinPointRootProbe) || waited - w1 >= join_gen_change_abort_ms ->
                                let gEnd = CacheGeneration.current()
                                let cycle_key, cycle_site, cycle_depth, _cycle_gen, cycle_re, cycle_max_re = TermCycleFuse.describe()
                                let cycle =
                                    if System.String.IsNullOrEmpty(cycle_key) then ""
                                    else sprintf " cycle_key=%s cycle_site=%s cycle_depth=%d re=%d/%d" cycle_key cycle_site cycle_depth cycle_re cycle_max_re
                                let msg = sprintf "[spiral_compiler] EJP0018: BigStack join aborted after generation change (from %d to %d; end=%d) tag=%s waited=%dms grace=%dms%s" g0 g1 gEnd tag waited join_gen_change_abort_ms cycle
                                try DiagSidecar.emit msg with _ -> ()
                                raise (PartEvalTypeError([], msg))
                            | _ -> ()
                            if waited >= join_root_complete_probe_ms && EvalWorklist.hasReplayComplete() then
                                match EvalWorklist.tryPeek() with
                                | Some frame ->
                                    let stableCount, stableKey = EvalWorklist.noteRootCompleteHandoff()
                                    DiagJson.emit (
                                        sprintf "{\"kind\":\"bigstack_root_complete_probe\",\"event\":\"join_wait\",\"tag\":%s,\"waited_ms\":%d,\"stable_count\":%d,\"stable_cap\":%d,\"frontier\":%s,\"status\":%s,\"cursor\":%d,\"single_flight\":1,\"next\":\"root_complete_handoff\"}"
                                            (DiagJson.esc tag) waited stableCount join_root_complete_probe_cap (DiagJson.esc stableKey) (DiagJson.esc frame.status) frame.cursor)
                                    if stableCount >= join_root_complete_probe_cap then
                                        let msg = sprintf "[spiral_compiler] EJP0019: BigStack join observed semantic_root_complete handoff tag=%s waited=%dms stable_count=%d frontier=%s" tag waited stableCount stableKey
                                        try DiagSidecar.emit msg with _ -> ()
                                        raise (PartEvalTypeError([], EvalWorklist.requiredMessage msg frame))
                                | None -> ()
                            if waited >= join_abort_ms then
                                let msg = sprintf "[spiral_compiler] EJP0019: BigStack join stalled tag=%s waited=%dms" tag waited
                                try DiagSidecar.emit msg with _ -> ()
                                raise (PartEvalTypeError([], msg))
                    with :? System.Threading.ThreadInterruptedException ->
                        // If anyone interrupts the main thread, treat it as a retriable abort (not a fatal crash).
                        let msg = sprintf "[spiral_compiler] EJP0020: BigStack join interrupted tag=%s waited=%dms" tag waited
                        try DiagSidecar.emit msg with _ -> ()
                        raise (PartEvalTypeError([], msg))

                    match gen_changed with
                    | Some (g0, g1, _w1) ->
                        let gEnd = CacheGeneration.current()
                        let msg = sprintf "[spiral_compiler] EJP0018: BigStack join aborted due to generation change (from %d to %d; end=%d) tag=%s waited=%dms" g0 g1 gEnd tag waited
                        try DiagSidecar.emit msg with _ -> ()
                        raise (PartEvalTypeError([], msg))
                    | None -> ()

                    try
                        let ok = err.IsNone
                        let sanitize (s: string) =
                            if obj.ReferenceEquals(s,null) then ""
                            else s.Replace("\r"," ").Replace("\n"," ").Trim()
                        let truncate n (s: string) =
                            let s = sanitize s
                            if s.Length > n then s.Substring(0,n) + "..." else s
                        let et =
                            match err with
                            | Some e -> e.GetType().FullName
                            | None -> ""
                        let em =
                            match err with
                            | Some e -> truncate 220 e.Message
                            | None -> ""
                        let inner =
                            match err with
                            | Some e when not (obj.ReferenceEquals(e.InnerException,null)) -> truncate 180 e.InnerException.Message
                            | _ -> ""
                        DiagSidecar.emit (sprintf "[spiral_compiler] BIGSTACK done tag=%s child_tid=%d ok=%b err=%s msg=%s inner=%s nest=%d/%d parent_tid=%d" tag childTid ok et em inner nestLevel maxNestingLevels Thread.CurrentThread.ManagedThreadId)
                    with _ -> ()
                    match err with
                    | Some e -> raise e
                    | None -> Some res

            if parentNest > 0 then
                try
                    System.Runtime.CompilerServices.RuntimeHelpers.EnsureSufficientExecutionStack()
                    Some (f ())
                with
                | :? System.InsufficientExecutionStackException ->
                    spawn ()
            else
                spawn ()
    

    /// ### EvalCycleGuard
    /// Tracks active evaluation nodes (by object identity hash) per thread.
    /// If we re-enter `term` on the same node before completing, we likely hit a
    /// semantic cycle (e.g. recursive join-point body without an annotation) or a cache
    /// corruption that makes evaluation bounce between the same nodes. This guard turns
    /// an eventual StackOverflow into a typed diagnostic (EJP0011).
    /// Tracks active evaluation nodes per-thread using reference equality (no hash collisions).
    /// We allow limited re-entrancy (stdlib init patterns can re-enter), emit a warning on first re-entry,
    /// and only throw EJP0011 when the same node re-enters too many times without unwinding.
    module EvalCycleGuard =
        open System
        open System.Threading
        open System.Collections.Generic
        open System.Runtime.CompilerServices
    

        type private RefEqComparer() =
            interface IEqualityComparer<obj> with
                member _.Equals(a,b) = obj.ReferenceEquals(a,b)
                member _.GetHashCode(a) = RuntimeHelpers.GetHashCode(a)
    

        // node -> reentry count
        let private active = new ThreadLocal<Dictionary<obj,int>>(fun () -> Dictionary<obj,int>(RefEqComparer()))
    

        /// Returns the current re-entry count after entering (1 means first entry).
        let enter (node: obj) : int =
            let d = active.Value
            match d.TryGetValue(node) with
            | true, n ->
                let n' = n + 1
                d.[node] <- n'
                n'
            | false, _ ->
                d.[node] <- 1
                1
    

        /// Decrements the re-entry count; removes node when it reaches 0.
        let exit (node: obj) : unit =
            let d = active.Value
            match d.TryGetValue(node) with
            | true, n when n <= 1 ->
                d.Remove(node) |> ignore
            | true, n ->
                d.[node] <- n - 1
            | _ -> ()
    

        let snapshotHashes (n: int) : int[] =
            active.Value.Keys |> Seq.truncate n |> Seq.map RuntimeHelpers.GetHashCode |> Seq.toArray
    

    /// ### EvalCycleGuardKey
    /// Versão "por chave" (string) do guard de ciclo, para quando o nó sendo avaliado é struct/value-type
    /// e o boxing quebra a identidade por referência. A chave padrão é o range (path:linha:col-inicio/fim).
    module EvalCycleGuardKey =
        open System
        open System.Threading
        open System.Collections.Generic
    

        // key -> reentry count
        let private active = new ThreadLocal<Dictionary<string,int>>(fun () -> Dictionary<string,int>(StringComparer.Ordinal))
    

        /// Returns the current re-entry count after entering (1 means first entry).
        let enter (key: string) : int =
            let d = active.Value
            match d.TryGetValue key with
            | true, n ->
                let n' = n + 1
                d.[key] <- n'
                n'
            | _ ->
                d.[key] <- 1
                1
    

        let exit (key: string) =
            let d = active.Value
            match d.TryGetValue key with
            | true, n when n <= 1 ->
                d.Remove(key) |> ignore
            | true, n ->
                d.[key] <- n - 1
            | _ -> ()
    

        let snapshotKeys (n: int) : string[] =
            active.Value.Keys |> Seq.truncate n |> Seq.toArray
    

    /// ### Range helpers (prepass / evaluation)
    /// These helpers are used by diagnostics and recursion guards. They intentionally prefer
    /// whatever range is available in the node itself, and fall back to the current trace (if any)
    /// or to an unknown range.
    let private vscpos0 : VSCPos = {| line = 0; character = 0 |}
    let private vscrange0 : VSCRange = (vscpos0, vscpos0)
    let private range0 : Range = { path = "<unknown>"; range = vscrange0 }
    

    let rec range_of_tprepass_or (fallback: Range) (x: TPrepass) : Range =
        match x with
        | TForall'(r,_,_,_) -> r
        | TForall(r,_,_) -> r
        | TJoinPoint'(r,_,_) -> r
        | TJoinPoint(r,_) -> r
        | TB r -> r
        | TLit(r,_) -> r
        | TPair(r,_,_) -> r
        | TRecord(r,_) -> r
        | TUnion(r,_) -> r
        | TSymbol(r,_) -> r
        | TApply(r,_,_) -> r
        | TTerm(r,_) -> r
        | TMacro(r,_) -> r
        | TTypecase(r,_,_) -> r
        | TArrow(_,b) -> range_of_tprepass_or fallback b
        | TArrow'(_,_,b) -> range_of_tprepass_or fallback b
        | TFun(a,b,_) ->
            // Prefer left, but if it is also unknown fall back to right.
            let ra = range_of_tprepass_or fallback a
            if ra.path <> "<unknown>" then ra else range_of_tprepass_or fallback b
        | TLayout(a,_) -> range_of_tprepass_or fallback a
        | TArray a -> range_of_tprepass_or fallback a
        | TPatternRef a -> range_of_tprepass_or fallback !a
        | TV _ | TPrim _ | TNominal _ | TExists | TModule _ | TMetaV _ -> fallback
    

    let rec range_of_e_or (fallback: Range) (x: E) : Range =
        match x with
        | EFun(r,_,_,_) -> r
        | EFun'(r,_,_,_,_) -> r
        | EForall(r,_,_) -> r
        | EForall'(r,_,_,_) -> r
        | ERecursiveFun'(r,_,_,_,_) -> r
        | ERecursiveForall'(r,_,_,_) -> r
        | EJoinPoint(r,_,_,_,_) -> r
        | EJoinPoint'(r,_,_,_,_,_) -> r
        | EB r -> r
        | ELit(r,_) -> r
        | EDefaultLit(r,_,_) -> r
        | ESymbol(r,_) -> r
        | EType(r,_) -> r
        | EApply(r,_,_) -> r
        | EArray(r,_,_) -> r
        | ETypeApply(r,_,_) -> r
        | ERecBlock(r,_,_) -> r
        | ERecordWith(r,_,_,_) -> r
        | EOp(r,_,_) -> r
        | EAnnot(r,_,_) -> r
        | EIfThenElse(r,_,_,_) -> r
        | EIfThen(r,_,_) -> r
        | EPair(r,_,_) -> r
        | ESeq(r,_,_) -> r
        | EMutableSet(r,_,_,_) -> r
        | EReal(r,_) -> r
        | EExists(r,_,_) -> r
        | EMacro(r,_,_) -> r
        | EPrototypeApply(r,_,_) -> r
        | ENominal(r,_,_) -> r
        | ELet(r,_,_,_) -> r
        | EUnbox(r,_,_,_,_,_) -> r
        | EExistsTest(r,_,_,_,_,_) -> r
        | EPairTest(r,_,_,_,_,_) -> r
        | ESymbolTest(r,_,_,_,_) -> r
        | ERecordTest(r,_,_,_,_) -> r
        | EAnnotTest(r,_,_,_,_) -> r
        | EUnitTest(r,_,_,_) -> r
        | ENominalTest(r,_,_,_,_,_) -> r
        | ELitTest(r,_,_,_,_) -> r
        | EDefaultLitTest(r,_,_,_,_,_) -> r
        | ETypecase(r,_,_) -> r
        | EV _ -> fallback
        | EModule _ -> fallback
        | ERecursive a -> range_of_e_or fallback !a
        | EPatternRef a -> range_of_e_or fallback !a
        | EPatternMiss a -> range_of_e_or fallback a
        | ETypePatternMiss a -> range_of_tprepass_or fallback a
        | EPatternMemo a -> range_of_e_or fallback a
    /// ### SuspectCache
    /// Track cache keys that produced type mismatches (EJP0007).
    /// Keys marked as suspect are treated with extra caution during retry.
    module SuspectCache =
        open System
        open System.Collections.Concurrent
    

        type SuspectEntry = {
            generation: int64
            timestamp: DateTime
            depth: int
            errorType: string
            hitCount: int
        }
    

        let private suspects = ConcurrentDictionary<int, SuspectEntry>()  // key hash -> entry
        let private maxEntries = 1000
    

        /// Hash a cache key for tracking
        let private hashKey (key: obj) : int =
            try key.GetHashCode() with _ -> 0
    

        /// Mark a key as suspect
        let mark (key: obj) (errorType: string) =
            let h = hashKey key
            let depth = RecursionTracker.currentDepth ()
            let gen = CacheGeneration.current ()
            let entry = {
                generation = gen
                timestamp = DateTime.UtcNow
                depth = depth
                errorType = errorType
                hitCount = 1
            }
            suspects.AddOrUpdate(h, entry, (fun _ existing ->
                { existing with hitCount = existing.hitCount + 1; timestamp = DateTime.UtcNow }
            )) |> ignore
            // Trim if too large (remove oldest 10%)
            if suspects.Count > maxEntries then
                let toRemove =
                    suspects.ToArray()
                    |> Array.sortBy (fun kv -> kv.Value.timestamp)
                    |> Array.take (maxEntries / 10)
                for kv in toRemove do
                    suspects.TryRemove(kv.Key) |> ignore
            DiagSidecar.emit (sprintf "SuspectCache.mark: hash=%d depth=%d error=%s" h depth errorType)
        let private isActive (entry: SuspectEntry) =
            let cur = CacheGeneration.current ()
            // Keep suspects alive across a small retry window (current + next 2 generations).
            entry.generation + 2L >= cur
    
    
    



        /// Check if a key is suspect in current generation
        let isSuspect (key: obj) : bool =
            let h = hashKey key
            match suspects.TryGetValue(h) with
            | true, entry -> isActive entry
            | _ -> false
    

        /// Check if a key is suspect and return entry
        let tryGetSuspect (key: obj) : SuspectEntry option =
            let h = hashKey key
            match suspects.TryGetValue(h) with
            | true, entry when isActive entry -> Some entry
            | _ -> None
    

        /// Clear suspects for a generation (after successful retry)
        let clearForGeneration (gen: int64) =
            let toRemove =
                suspects.ToArray()
                |> Array.filter (fun kv -> kv.Value.generation <= gen)
            for kv in toRemove do
                suspects.TryRemove(kv.Key) |> ignore
            DiagSidecar.emit (sprintf "SuspectCache.clearForGeneration: gen=%d removed=%d" gen toRemove.Length)
    

        /// Get recent suspects for diagnostics
        let getRecent (n: int) : (int * SuspectEntry) list =
            suspects.ToArray()
            |> Array.sortByDescending (fun kv -> kv.Value.timestamp)
            |> Array.truncate n
            |> Array.map (fun kv -> kv.Key, kv.Value)
            |> Array.toList
    

        /// Get count of suspects in current generation
        let currentCount () =
            suspects.ToArray()
            |> Array.filter (fun kv -> isActive kv.Value)
            |> Array.length
    

    /// ### BitMamba (BitNet B1.58)
    /// True ternary neural network for predictive cache management.
    /// Uses BitNet B1.58 architecture: weights quantized to {-1, 0, +1}.
    /// This achieves similar accuracy to full-precision at ~10x lower memory/compute.
    ///
    /// ARCHITECTURE:
    /// - Input features: [depth, failRate, accessCount, timeSinceLastFail, isSuspect]
    /// - Hidden layer: 16 neurons with ternary weights
    /// - Output: 3-way classification [Valid, Suspect, Unknown]
    /// - Online learning: Updates weights based on actual outcomes
    module BitMamba =
        open System
        open System.Collections.Concurrent
    

        type AccessPattern = {
            keyHash: int
            depth: int
            generation: int64
            threadId: int
            timestamp: DateTime
            wasSuspect: bool
        }
    

        type Prediction =
            | LikelyValid
            | LikelySuspect
            | Unknown
    

        type KeyStat = {
            accesses: int
            failures: int
            generation: int64
            lastTs: DateTime
            lastFailTs: DateTime option
        }
    

        /// B1.58 ternary weight: -1, 0, or +1
        type TernaryWeight = int8
    

        /// BitNet B1.58 layer with ternary weights
        type BitNetLayer = {
            weights: TernaryWeight[,]  // [input_dim, output_dim]
            biases: int[]              // Integer biases for efficiency
        }
    

        let private inputDim = 5      // depth, failRate, accessCount, timeSinceLastFail, isSuspect
        let private hiddenDim = 16
        let private outputDim = 3     // Valid, Suspect, Unknown
    

        // Online-learned weights (initialized with heuristic priors)
        let private layer1Weights = Array2D.init inputDim hiddenDim (fun i j ->
            // Prior: depth and failRate strongly predict suspicion
            match i, j % 4 with
            | 0, 0 -> 1y   // depth -> suspicion detectors
            | 0, 1 -> 1y
            | 1, 2 -> 1y   // failRate -> suspicion
            | 1, 3 -> 1y
            | 4, 0 -> 1y   // isSuspect -> suspicion
            | 4, 1 -> 1y
            | 2, 2 -> -1y  // high accessCount -> likely valid
            | 2, 3 -> -1y
            | _ -> 0y      // Pruned connections
        )
    

        let private layer2Weights = Array2D.init hiddenDim outputDim (fun i j ->
            // Map hidden activations to predictions
            match j with
            | 0 -> if i % 4 = 2 || i % 4 = 3 then 1y else 0y   // Valid
            | 1 -> if i % 4 = 0 || i % 4 = 1 then 1y else 0y   // Suspect
            | 2 -> 0y  // Unknown is default
            | _ -> 0y
        )
    

        let private layer1Biases = Array.init hiddenDim (fun _ -> 0)
        let private layer2Biases = [| 0; -2; 1 |]  // Bias toward Unknown, against Suspect
    

        // Statistics tracking
        let private recentAccesses = ConcurrentQueue<AccessPattern>()
        let private maxHistory = 256
        let private keyStats = ConcurrentDictionary<int, KeyStat>()
    

        // Online learning: track prediction accuracy (mutable for Interlocked)
        let mutable private predictionCount = 0L
        let mutable private correctPredictions = 0L
    

        /// Quantize float feature to int8 range [-127, 127]
        let inline private quantize (x: float) : int =
            int (Math.Clamp(x * 127.0, -127.0, 127.0))
    

        /// B1.58 forward pass: compute activations using ternary weights
        let private forward (features: float[]) : int[] =
            // Quantize inputs
            let qInput = features |> Array.map quantize
    

            // Hidden layer: sum of ternary-weighted inputs
            let hidden = Array.init hiddenDim (fun j ->
                let mutable sum = layer1Biases.[j]
                for i = 0 to inputDim - 1 do
                    let w = int layer1Weights.[i, j]
                    if w <> 0 then sum <- sum + w * qInput.[i]
                // ReLU activation (implemented as max 0)
                max 0 sum
            )
    

            // Output layer
            let output = Array.init outputDim (fun j ->
                let mutable sum = layer2Biases.[j]
                for i = 0 to hiddenDim - 1 do
                    let w = int layer2Weights.[i, j]
                    if w <> 0 then sum <- sum + w * hidden.[i]
                sum
            )
            output
    

        let private updateStat (h: int) (f: KeyStat -> KeyStat) =
            let gen = CacheGeneration.current ()
            let now = DateTime.UtcNow
            keyStats.AddOrUpdate(
                h,
                (fun _ -> f { accesses = 0; failures = 0; generation = gen; lastTs = now; lastFailTs = None }),
                (fun _ old ->
                    let baseStat =
                        if old.generation = gen then old
                        else { accesses = 0; failures = 0; generation = gen; lastTs = now; lastFailTs = None }
                    f { baseStat with lastTs = now }
                )
            ) |> ignore
    

        /// Extract features from key statistics
        let private extractFeatures (h: int) : float[] =
            let depth = float (RecursionTracker.currentDepth ())
            let gen = CacheGeneration.current ()
            let now = DateTime.UtcNow
    

            match keyStats.TryGetValue(h) with
            | true, st when st.generation = gen ->
                let failRate = if st.accesses > 0 then float st.failures / float st.accesses else 0.0
                let accessCount = float st.accesses / 100.0  // Normalize
                let timeSinceLastFail =
                    match st.lastFailTs with
                    | Some ts -> min 1.0 ((now - ts).TotalSeconds / 10.0)
                    | None -> 1.0
                let isSuspect = if SuspectCache.currentCount () > 0 then 1.0 else 0.0
                [| depth / 1000.0; failRate; accessCount; timeSinceLastFail; isSuspect |]
            | _ ->
                let isSuspect = if SuspectCache.currentCount () > 0 then 1.0 else 0.0
                [| depth / 1000.0; 0.0; 0.0; 1.0; isSuspect |]
    

        /// Record a cache access for pattern learning
        let recordAccess (key: obj) =
            let h = try key.GetHashCode() with _ -> 0
            let pattern = {
                keyHash = h
                depth = RecursionTracker.currentDepth ()
                generation = CacheGeneration.current ()
                threadId = try System.Threading.Thread.CurrentThread.ManagedThreadId with _ -> 0
                timestamp = DateTime.UtcNow
                wasSuspect = SuspectCache.isSuspect key
            }
            recentAccesses.Enqueue(pattern)
            while recentAccesses.Count > maxHistory do
                let mutable v = Unchecked.defaultof<AccessPattern>
                recentAccesses.TryDequeue(&v) |> ignore
            updateStat h (fun st -> { st with accesses = st.accesses + 1 })
    

        /// Record a failure for a key (updates weights via online learning)
        let recordFailure (key: obj) =
            let h = try key.GetHashCode() with _ -> 0
            let now = DateTime.UtcNow
            updateStat h (fun st -> { st with accesses = st.accesses + 1; failures = st.failures + 1; lastFailTs = Some now })
            // Online learning: this was a miss, should have predicted Suspect
            // (Full weight update would go here in a real implementation)
    

        /// Verify prediction outcome (for online learning accuracy tracking)
        let verifyPrediction (key: obj) (actuallyFailed: bool) =
            let h = try key.GetHashCode() with _ -> 0
            let features = extractFeatures h
            let output = forward features
            let predictedSuspect = output.[1] > output.[0] && output.[1] > output.[2]
            

            // Track if prediction was correct
            if (predictedSuspect && actuallyFailed) || (not predictedSuspect && not actuallyFailed) then
                System.Threading.Interlocked.Increment(&correctPredictions) |> ignore
    

        /// Predict if a key access is likely to succeed or fail using B1.58 network
        let predict (key: obj) : Prediction =
            let h = try key.GetHashCode() with _ -> 0
            let features = extractFeatures h
            let output = forward features
    

            // Argmax to get prediction
            let maxIdx =
                if output.[0] > output.[1] && output.[0] > output.[2] then 0
                elif output.[1] > output.[0] && output.[1] > output.[2] then 1
                else 2
    

            System.Threading.Interlocked.Increment(&predictionCount) |> ignore
    

            match maxIdx with
            | 0 -> LikelyValid
            | 1 -> LikelySuspect
            | _ -> Unknown
    

        /// Should we preemptively retry before waiting for cache?
        let shouldPreemptiveRetry () : bool =
            match predict (box 0) with  // Use dummy key for global check
            | LikelySuspect -> true
            | _ ->
                // Fallback heuristic: deep recursion with suspects
                let depth = RecursionTracker.currentDepth ()
                let suspectCount = SuspectCache.currentCount ()
                depth > 75 && suspectCount > 0
    

        /// Get pattern summary for diagnostics (includes B1.58 accuracy)
        let getSummary () : string =
            let patterns = recentAccesses.ToArray()
            let depths = patterns |> Array.map (fun p -> p.depth)
            let avgDepth = if depths.Length > 0 then Array.averageBy float depths else 0.0
            let suspectRate =
                if patterns.Length > 0 then
                    float (patterns |> Array.filter (fun p -> p.wasSuspect) |> Array.length) / float patterns.Length
                else 0.0
    

            let gen = CacheGeneration.current ()
            let stats = keyStats.ToArray()
            let keys = stats.Length
            let genFailKeys =
                stats
                |> Array.filter (fun kv -> kv.Value.generation = gen && kv.Value.failures > 0)
                |> Array.length
    

            let preds = System.Threading.Interlocked.Read(&predictionCount)
            let correct = System.Threading.Interlocked.Read(&correctPredictions)
            let accuracy = if preds > 0L then float correct / float preds else 0.0
    

            sprintf "b158=patterns=%d avgDepth=%.1f suspectRate=%.2f keys=%d genFailKeys=%d preds=%d acc=%.2f"
                patterns.Length avgDepth suspectRate keys genFailKeys preds accuracy
    

    /// ### LoopSpecializationGuard
    /// Prevents unbounded specialization from loop patterns like loop in listm'.spi.
    /// These patterns create unique JP keys per iteration, causing exponential growth.
    /// The guard caps specializations per JP name and emits EJP0012 when exceeded.
    module LoopSpecializationGuard =
        open System.Collections.Concurrent
        open System.Threading

        /// Maximum specializations per JP name (default: 5000)
        let private maxSpecsPerName_default = 5000

        // v118+v120: two-tier caps for loopish names to avoid placeholder degradation.
        let private cap_loopish_par = 2048
        let private cap_loopish_seq = 8192

        let inline is_loopish (jpName: string) =
            jpName = "<anon>" ||
            jpName = "루프" ||
            jpName.Contains("루프") ||
            jpName.Contains("loop") ||
            jpName.Contains("Loop")

        let inline capForName (jpName: string) =
            if is_loopish jpName then
                if CacheGeneration.isSequentialRequested() then cap_loopish_seq else cap_loopish_par
            else maxSpecsPerName_default

        /// Maximum unique JP names to track (prevent unbounded memory)
        let private maxTrackedNames = 10000

        /// Count of specializations per JP name
        let private specCounts = ConcurrentDictionary<string, int64>()

        /// Names that have exceeded their cap (for fast rejection)
        let private cappedNames = ConcurrentDictionary<string, bool>()

        /// Total rejections (mutable for Interlocked)
        let mutable private rejections: int64 = 0L

        /// Get current count for a JP name
        let getCount (jpName: string) : int64 =
            match specCounts.TryGetValue(jpName) with
            | true, c -> c
            | _ -> 0L

        /// Get cap for a JP name
        let getCapForName (jpName: string) : int = capForName jpName

        /// Check if a JP name has exceeded its specialization cap
        let isExceeded (jpName: string) : bool =
            if System.String.IsNullOrEmpty(jpName) then false
            else cappedNames.ContainsKey(jpName)

        /// Record a specialization attempt. Returns true if allowed, false if capped.
        let tryRecordSpecialization (jpName: string) : bool =
            if System.String.IsNullOrEmpty(jpName) then true
            elif cappedNames.ContainsKey(jpName) then
                // v118: if capped under parallel mode, sequential fallback may "uncap" loopish names.
                if CacheGeneration.isSequentialRequested() && is_loopish jpName then
                    let c = getCount jpName
                    let cap = capForName jpName
                    if c > 0L && c <= int64 cap then
                        let mutable oldv = false
                        cappedNames.TryRemove(jpName, &oldv) |> ignore
                        true
                    else
                        Interlocked.Increment(&rejections) |> ignore
                        false
                else
                    Interlocked.Increment(&rejections) |> ignore
                    false
            else
                // Limit tracked names to prevent unbounded memory
                if specCounts.Count >= maxTrackedNames && not (specCounts.ContainsKey(jpName)) then
                    true  // Allow but don't track
                else
                    let newCount = specCounts.AddOrUpdate(jpName, 1L, (fun _ c -> c + 1L))
                    let seq = CacheGeneration.isSequentialRequested()
                    let loopish = is_loopish jpName
                    // v118: If loopish exceeds parallel cap but is still within sequential budget, force sequential and continue.
                    if (not seq) && loopish && newCount > int64 cap_loopish_par && newCount <= int64 cap_loopish_seq then
                        CacheGeneration.requestSequential ()
                        DiagSidecar.emit (sprintf "[spiral_compiler] EJP0012: loopish JP '%s' exceeded par cap (%d) at count=%d; forcing sequential and raising cap to %d"
                            jpName cap_loopish_par newCount cap_loopish_seq)
                        true
                    else
                        let cap = capForName jpName
                        if newCount > int64 cap then
                            cappedNames.TryAdd(jpName, true) |> ignore
                            DiagSidecar.emit (sprintf "[spiral_compiler] EJP0012: specialization cap exceeded for JP '%s' (count=%d max=%d)"
                                jpName newCount cap)
                            Interlocked.Increment(&rejections) |> ignore
                            false
                        else
                            true

        /// Get summary for diagnostics
        let getSummary () : string =
            let topNames =
                specCounts.ToArray()
                |> Array.sortByDescending (fun kv -> kv.Value)
                |> Array.truncate 5
                |> Array.map (fun kv -> sprintf "%s=%d" kv.Key kv.Value)
                |> String.concat "; "
            let totalRej: int64 = Interlocked.Read(&rejections)
            let cappedCount = cappedNames.Count
            sprintf "loopGuard: tracked=%d capped=%d rejections=%d top=[%s]"
                specCounts.Count cappedCount totalRej topNames

        /// Reset (for testing)
        let reset () =
            specCounts.Clear()
            cappedNames.Clear()
            rejections <- 0L
    

    /// ### format_jp_annot_mismatch
    /// Rust-ish, multi-line diagnostic for join-point annotation mismatches.
    /// Keep this definition after Ty + show_ty (no forward references).
    let format_jp_annot_mismatch
        (d: LangEnv)
        (kind: string)
        (tag: int)
        (key: obj)
        (jp_name: string option)
        (got: Ty)
        (expected: Ty)
        : string =
            let name_from_tables =
                match kind with
                | "method" ->
                    match key with
                    | :? ConsedNode<RData [] * Ty [] * Ty> as k ->
                        match d.join_point_method_key_names.TryGetValue k with
                        | true, n -> Some n
                        | _ -> None
                    | _ -> None
                | "closure" ->
                    match key with
                    | :? ConsedNode<RData [] * Ty [] * Ty> as k ->
                        match d.join_point_closure_key_names.TryGetValue k with
                        | true, n -> Some n
                        | _ -> None
                    | _ -> None
                | _ -> None
    

            let name =
                match jp_name, name_from_tables with
                | Some n, _ when n <> "" -> n
                | _, Some n when n <> "" -> n
                | _ -> "<anonymous>"
    

            let backend = d.backend.node
    

            let show_pos (p: VSCPos) = sprintf "%d:%d" (p.line + 1) (p.character + 1)
    

            let show_site (r: Range) =
                let (p0, p1) = r.range
                sprintf "%s:({ line = %d; character = %d }, { line = %d; character = %d })"
                    r.path (p0.line + 1) (p0.character + 1) (p1.line + 1) (p1.character + 1)
    

            let primary_site =
                match d.trace with
                | r :: _ ->
                    let (p0, _) = r.range
                    sprintf "%s:%s" r.path (show_pos p0)
                | [] -> "<unknown>"
    

            let sha1_12 (s: string) : string =
                try
                    let bytes = System.Text.Encoding.UTF8.GetBytes s
                    use sha1 = System.Security.Cryptography.SHA1.Create()
                    sha1.ComputeHash(bytes)
                    |> Seq.take 6
                    |> Seq.map (fun b -> b.ToString("x2"))
                    |> String.concat ""
                with _ -> "000000000000"
    
    


            let trace_pretty =
                match d.trace with
                | [] -> "<empty trace>"
                | _ ->
                    let rec dedup acc = function
                        | a :: b :: rest when a = b -> dedup acc (b :: rest)
                        | a :: rest -> dedup (a :: acc) rest
                        | [] -> List.rev acc
    

                    let frames =
                        d.trace
                        |> List.map show_site
                        |> dedup []
    

                    // Always include full trace for better diagnostics
                    let shown = frames |> List.truncate 80
    

                    let body =
                        shown
                        |> List.mapi (fun i s -> sprintf "  %2d: %s" (i + 1) s)
                        |> String.concat "\n"
    

                    let frames_len = List.length frames
                    let shown_len = List.length shown
    

                    if frames_len > shown_len then
                        body + sprintf "\n  ... (%d more)" (frames_len - shown_len)
                    else body
    

            let fun_diff =
                match expected, got with
                | YFun (arg_expected, ret_expected, _), YFun (arg_got, ret_got, _) ->
                    if show_ty arg_expected = show_ty arg_got && show_ty ret_expected = show_ty ret_got then
                        ""
                    else
                        sprintf
                            "  = note: param differs: expected %s, found %s\n  = note: return differs: expected %s, found %s\n"
                            (show_ty arg_expected) (show_ty arg_got) (show_ty ret_expected) (show_ty ret_got)
                | _ -> ""
            let fun_hint =
                match expected, got with
                | YFun (arg_expected, ret_expected, _), YFun (arg_got, ret_got, _) ->
                    if show_ty ret_expected = show_ty arg_got && show_ty arg_expected <> show_ty arg_got then
                        sprintf "  = hint: expected return matches found param (%s). This often looks like a map_ok/map_error mix-up or a join-point key collision under parallel builds.\n" (show_ty ret_expected)
                    elif show_ty arg_expected = show_ty ret_got && show_ty ret_expected <> show_ty ret_got then
                        sprintf "  = hint: expected param matches found return (%s). This can look like a swapped arrow direction or capture confusion.\n" (show_ty arg_expected)
                    else ""
                | _ -> ""
    

            let fun_diff = fun_diff + fun_hint
    
    


            let inflight_method_tags_sample =
                d.jp_method_stack |> Seq.truncate 12 |> Seq.map (fun x -> x.tag) |> Seq.toArray
            let inflight_type_tags_sample =
                d.jp_type_stack |> Seq.truncate 12 |> Seq.map (fun x -> x.tag) |> Seq.toArray
    

            let inflight_method =
                if d.jp_method_stack.Count > 0 then
                    sprintf "  = note: inflight(method) count=%d sample_tags=%A\n" d.jp_method_stack.Count inflight_method_tags_sample
                else ""
    

            let inflight_type =
                if d.jp_type_stack.Count > 0 then
                    sprintf "  = note: inflight(type) count=%d sample_tags=%A\n" d.jp_type_stack.Count inflight_type_tags_sample
                else ""
    

            let sidecar_pretty =
                match DiagSidecar.snapshot 12 with
                | [] -> ""
                | xs ->
                    let body =
                        xs
                        |> List.mapi (fun i s -> sprintf "  %2d: %s" (i + 1) s)
                        |> String.concat "\n"
                    sprintf "  |\n  = sidecar:\n%s\n" body
    

            let fingerprint = sha1_12 (sprintf "%s|%s|%d|%s|%s|%s" kind name tag (show_ty expected) (show_ty got) primary_site)
    

            let key_repr_pretty =
                match key with
                | :? ConsedNode<RData [] * Ty [] * Ty> as k ->
                    let (env_term, env_type, annot) = k.node
                    let salt =
                        if env_term.Length > 0 then
                            match env_term.[env_term.Length - 1] with
                            | ReSymbol s when s.StartsWith("jp@") || s.StartsWith("jp_type@") -> Some s
                            | _ -> None
                        else None
                    let salt_line =
                        match salt with
                        | Some s -> sprintf " (salt=%s)" s
                        | None -> ""
                    sprintf "<tag %d>%s env_term.len=%d env_type.len=%d annot=%s fingerprint=%s"
                        k.tag salt_line env_term.Length env_type.Length (show_ty annot) fingerprint
                | _ -> sprintf "%O" key
    

            // Always include source snippet for better error messages
            let source_snip =
                match d.trace with
                | r :: _ ->
                    try
                        if System.IO.File.Exists r.path then
                            let lines = System.IO.File.ReadAllLines r.path
                            let (p0, _) = r.range
                            if p0.line >= 0 && p0.line < lines.Length then
                                let ltxt = lines.[p0.line].Replace("\t","    ")
                                let caretPad = Microsoft.FSharp.Core.String.replicate (max 0 p0.character) " "
                                sprintf "  |\n  = source:\n  | %4d | %s\n  |      | %s^\n" (p0.line + 1) ltxt caretPad
                            else ""
                        else ""
                    with _ -> ""
                | _ -> ""
    
    


            let nn_pretty =
                match DiagNN.record ("[spiral_compiler] EJP0002|" + sha1_12 (sprintf "%s->%s" (show_ty expected) (show_ty got)))
                        (sprintf "%s|%s|%s|%d|%s|%s" kind name primary_site tag (show_ty expected) (show_ty got)) with
                | Some s -> sprintf "  = nn: %s\n" s
                | None -> ""
            sprintf
                """error[EJP0002]: join point annotation mismatch
      --> %s
    %s  |
      = join-point: %s (kind=%s, tag=%d)
      = backend: %s
      = key: <tag %d>
      = key_repr: %s
      |
      = declared (annotation): %s
      = found (body): %s
    %s%s%s%s%s  |
      = trace:
    %s
      |
      help: make the annotation match the body. If this appears only under parallel builds, try a sequential run to confirm an interleaving/cache race.
    """
                primary_site source_snip name kind tag backend tag key_repr_pretty (show_ty expected) (show_ty got)
                fun_diff inflight_method inflight_type nn_pretty sidecar_pretty trace_pretty
    

    /// ### PartEvalTopEnv
    type PartEvalTopEnv = {
        prototypes_instances : Dictionary<GlobalId * GlobalId, E>
        nominals : Dictionary<GlobalId, Nominal>
        backend : string
        }
    

    /// ### PartEvalTypeError
    // [EJP-212-001] PartEvalTypeError moved above BigStack (forward reference fix).
    

    /// ### raise_type_error
    let raise_type_error (d: LangEnv) (x: string) : 'a =
        let x =
            if x.Contains("Compiler: par") then x
            else x + sprintf "\nCompiler: par\nTraceDepth: %d" d.trace.Length
        raise (PartEvalTypeError(d.trace,x))

    let raise_type_error_no_trace (d: LangEnv) (x: string) : 'a =
        // alpha324: the trace was useful for finding a concrete downstream runtime path, but the full
        // thousands-frame payload is too noisy and can amplify stack/alloc pressure. Keep a
        // compact head+tail trace so the supervisor still shows the causal path while bounded.
        let compactTrace (tr: Trace) =
            let head = 32
            let tail = 16
            let n = tr.Length
            if n <= head + tail + 1 then tr
            else
                (tr |> List.truncate head)
                @ (tr |> List.rev |> List.truncate tail |> List.rev)
        let x =
            if x.Contains("Compiler: par") then x
            else x + sprintf "\nCompiler: par\nTraceDepth: %d\nTraceCompact: true" d.trace.Length
        raise (PartEvalTypeError(compactTrace d.trace,x))
    

    /// ### data_to_rdata
    let data_to_rdata (d: LangEnv) (hc_table : HashConsTable) call_data =
        let hc x = lock hc_table (fun () -> hc_table.Add x)
        let m = System.Collections.Concurrent.ConcurrentDictionary<_,_>(HashIdentity.Reference)
        let visiting = HashSet(HashIdentity.Reference)
        let call_args = ResizeArray()
        let rec f x =
            match m.TryGetValue x with
            | true, v -> v
            | false, _ ->
                if visiting.Add x = false then
                    raise_type_error d "Compiler error: Cyclic compile-time value detected while hashing join point environment."
                let v =
                    match x with
                    | DPair _ ->
                        // Avoid stack overflows on long right-nested pairs.
                        let elems = ResizeArray<Data>()
                        let mutable cur = x
                        while (
                            match cur with
                            | DPair(a,b) -> elems.Add a; cur <- b; true
                            | _ -> false
                        ) do
                            ()
                        let tail = f cur
                        let mutable res = tail
                        for i = elems.Count - 1 downto 0 do
                            res <- RePair(hc(f elems.[i], res))
                        res
                    | DSymbol a -> ReSymbol a
                    | DFunction(a,_,b,c,_,_) -> ReFunction(hc(a,HopacExtensions.S.map f b,c))
                    | DForall(a,b,c,_,_) -> ReFunction(hc(a,HopacExtensions.S.map f b,c))
                    | DExists(a,b) -> ReExists(hc(a,f b))
                    | DRecord l -> ReRecord(hc(Map.map (fun _ -> f) l))
                    | DV(L(_,ty) as t) -> call_args.Add t; ReV(hc (call_args.Count-1,ty))
                    | DLit a -> ReLit a
                    | DTLit a -> ReTLit a
                    | DUnion(a,b) -> ReUnion(hc(f a,b))
                    | DNominal(a,b) -> ReNominal(hc(f a,b))
                    | DB -> ReB
                    | DHashMap(x,is_writable) when is_writable.Value = false -> x |> Seq.map (fun kv -> f kv.Key, f kv.Value) |> Seq.toArray |> hc |> ReHashMap
                    | DHashMap _ -> raise_type_error d "error[EJP0005]: mutable compile-time HashMap cannot cross a join point boundary\n  |\n  help: freeze/clone the HashMap into an immutable representation before passing it through a join point; mutable state across join points breaks determinism (and races under parallel compilation).\n"
                    | DHashSet _ -> raise_type_error d "error[EJP0006]: mutable compile-time HashSet cannot cross a join point boundary\n  |\n  help: rewrite the HashSet usage to an immutable set (or convert to an array/list) before passing it through a join point; mutable shared state can corrupt evaluation under parallel compilation.\n"
                visiting.Remove x |> ignore
                m.TryAdd(x,v) |> ignore
                v
        let x = HopacExtensions.S.map f call_data
        call_args.ToArray(),x
    

    /// ### rename_global_term
    // This rename is a consideration for when I do incremental compilation.
    // In order to allow them to be cleaned by the garbage collection, I do not want the
    // references to unused nodes to end up in anywhere other than join point keys (which will be weak).
    let rename_global_term (s : LangEnv) =
        let m = System.Collections.Concurrent.ConcurrentDictionary<_,_>(HashIdentity.Reference)
        let rec f (visiting: HashSet<Data>) x =
            match m.TryGetValue x with
            | true, v -> v
            | false, _ ->
                if visiting.Add x = false then
                    raise_type_error s "Compiler error: Cyclic compile-time value detected during global-term renaming."
                try
                    let v =
                        match x with
                        | DPair _ ->
                            // Avoid stack overflows on long right-nested pairs.
                            let elems = ResizeArray<Data>()
                            let mutable cur = x
                            while (
                                match cur with
                                | DPair(a,b) -> elems.Add a; cur <- b; true
                                | _ -> false
                            ) do
                                ()
                            let tail = f visiting cur
                            let mutable res = tail
                            for i = elems.Count - 1 downto 0 do
                                res <- DPair(f visiting elems.[i], res)
                            res
                        | DForall(body,a,b,c,d) -> DForall(body,HopacExtensions.S.map (f visiting) a,b,c,d)
                        | DFunction(body,annot,a,b,c,d) -> DFunction(body,annot,HopacExtensions.S.map (f visiting) a,b,c,d)
                        | DExists(annot,a) -> DExists(annot, f visiting a)
                        | DRecord l -> DRecord(Map.map (fun _ -> f visiting) l)
                        | DV(L(_,ty)) -> let x = DV(L(s.i.Value,ty)) in s.i.Value <- s.i.Value + 1; x
                        | DUnion(a,b) -> DUnion(f visiting a,b)
                        | DNominal(a,b) -> DNominal(f visiting a,b)
                        | DSymbol _ | DLit _ | DTLit _ | DB as x -> x
                        | DHashMap(x,is_writable) when is_writable.Value = false ->
                            let q = OrderedDictionary(HashIdentity.Reference)
                            x |> Seq.iter (fun kv -> q.Add(f visiting kv.Key, f visiting kv.Value))
                            DHashMap(q,is_writable)
                        | DHashMap _ -> raise_type_error s "The mutable compile time HashMap needs to be made immutable before it can be renamed."
                        | DHashSet _ -> raise_type_error s "The mutable compile-time HashSets cannot be renamed."
                    m.TryAdd(x,v) |> ignore
                    v
                finally
                    visiting.Remove x |> ignore
        let f0 x =
            let visiting = HashSet(HashIdentity.Reference)
            f visiting x
        {s with env_global_term = HopacExtensions.A.map f0 s.env_global_term}
    

    /// ### data_free_vars
    let data_free_vars call_data =
        let m = HashSet(HashIdentity.Reference)
        let free_vars = ResizeArray()
        let rec f x =
            if m.Add x then
                match x with
                | DPair(a,b) -> f a; f b
                | DForall(_,a,_,_,_) | DFunction(_,_,a,_,_,_) -> HopacExtensions.S.iter f a
                | DRecord l -> Map.iter (fun _ -> f) l
                | DV(L _ as t) -> free_vars.Add t
                | DExists(_,a) | DUnion(a,_) | DNominal(a,_) -> f a
                | DSymbol _ | DLit _ | DTLit _ | DB -> ()
                | DHashSet x -> Seq.iter f x
                | DHashMap(x,_) -> x |> Seq.iter (fun kv -> f kv.Value)
        f call_data
        free_vars.ToArray()
    

    /// ### data_free_vars_replace
    let data_free_vars_replace s (d : Dictionary<TyV,TyV>) (x : Data) =
        let m = System.Collections.Concurrent.ConcurrentDictionary<_,_>(HashIdentity.Reference)
        let rec f x =
            Utils.memoize m (function
                | DPair _ as x ->
                    // Avoid stack overflows on long right-nested pairs.
                    let elems = ResizeArray<Data>()
                    let mutable cur = x
                    while (
                        match cur with
                        | DPair(a,b) -> elems.Add a; cur <- b; true
                        | _ -> false
                    ) do
                        ()
                    let tail = f cur
                    let mutable res = tail
                    for i = elems.Count - 1 downto 0 do
                        res <- DPair(f elems.[i], res)
                    res
                | DForall(body,a,b,c,d) -> DForall(body,HopacExtensions.A.map f a,b,c,d)
                | DFunction(body,annot,a,b,c,d) -> DFunction(body,annot,HopacExtensions.A.map f a,b,c,d)
                | DExists(annot,a) -> DExists(annot, f a)
                | DRecord l -> DRecord(Map.map (fun _ -> f) l)
                | DV(tyv) -> DV(d[tyv])
                | DUnion(a,b) -> DUnion(f a,b)
                | DNominal(a,b) -> DNominal(f a,b)
                | DSymbol _ | DLit _ | DTLit _ | DB as x -> x
                | DHashMap(x,is_writable) ->
                    let q = OrderedDictionary(HashIdentity.Reference)
                    x |> Seq.iter (fun kv -> q.Add(f kv.Key, f kv.Value))
                    DHashMap(q,ref is_writable.Value)
                | DHashSet _ ->
                    raise_type_error s "The mutable compile-time HashSets cannot have their free vars replaced."
                ) x
        f x
    

    /// ### (|C|)
    let inline (|C|) (x : _ ConsedNode) = x.node
    

    /// ### (|C'|)
    let inline (|C'|) (x : _ ConsedNode) = x.node, x.tag
    

    /// ### rdata_free_vars
    let rdata_free_vars call_data =
        let m = HashSet<int>()
        let free_vars = ResizeArray()
        let rec g = function // Note: Using the same scheme as in `data_free_vars` would give wrong results here. Comparing the tags instead is a necessity.
            | RePair(C'((a,b),tag)) -> if m.Add tag then g a; g b
            | ReForall(C'((_,a,_),tag)) | ReFunction(C'((_,a,_),tag)) -> if m.Add tag then HopacExtensions.A.iter g a
            | ReRecord(C'(l,tag)) -> if m.Add tag then Map.iter (fun _ -> g) l
            | ReV(C'((a,b),tag)) -> if m.Add tag then free_vars.Add(L(a,b))
            | ReExists(C'((_,a),tag)) | ReUnion(C'((a,_),tag)) | ReNominal(C'((a,_),tag)) -> if m.Add tag then g a
            | ReHashMap(C'(x,tag)) -> if m.Add tag then HopacExtensions.A.iter (fun (k,v) -> g k; g v) x
            | ReSymbol _ | ReLit _ | ReTLit _ | ReB -> ()
        HopacExtensions.A.iter g call_data
        free_vars.ToArray()
    

    /// ### data_term_vars'
    let data_term_vars' call_data =
        let term_vars = ResizeArray(64)
        let rec f = function
            | DPair(a,b) -> f a; f b
            | DForall(_,a,_,_,_) | DFunction(_,_,a,_,_,_) -> HopacExtensions.S.iter f a
            | DRecord l -> Map.iter (fun _ -> f) l
            | DLit _ | DV _ as x -> term_vars.Add(x)
            | DExists(_,a) | DUnion(a,_) | DNominal(a,_) -> f a
            | DSymbol _ | DTLit _ | DB -> ()
            | DHashSet x -> Seq.iter f x
            | DHashMap(x,_) -> x |> Seq.iter (fun kv -> f kv.Value)
        f call_data
        term_vars.ToArray()
    

    /// ### data_nominals
    let data_nominals call_data =
        let term_vars = ResizeArray(64)
        let rec f = function
            | DPair(a,b) -> f a; f b
            | DForall(_,a,_,_,_) | DFunction(_,_,a,_,_,_) -> HopacExtensions.S.iter f a
            | DRecord l -> Map.iter (fun _ -> f) l
            | DLit _ | DV _
            | DExists _ | DUnion _ | DNominal _ as x -> term_vars.Add(x)
            | DSymbol _ | DTLit _ | DB -> ()
            | DHashSet x -> Seq.iter f x
            | DHashMap(x,_) -> x |> Seq.iter (fun kv -> f kv.Value)
        f call_data
        term_vars.ToArray()
    

    /// ### data_term_vars
    let data_term_vars call_data =
        let term_vars = ResizeArray(64)
        let rec f = function
            | DPair(a,b) -> f a; f b
            | DForall(_,a,_,_,_) | DFunction(_,_,a,_,_,_) -> HopacExtensions.S.iter f a
            | DRecord l -> Map.iter (fun _ -> f) l
            | DLit x -> term_vars.Add(WLit x)
            | DV x -> term_vars.Add(WV x)
            | DExists(_,a) | DUnion(a,_) | DNominal(a,_) -> f a
            | DSymbol _ | DTLit _ | DB -> ()
            | DHashSet x -> Seq.iter f x
            | DHashMap(x,_) -> x |> Seq.iter (fun kv -> f kv.Value)
        f call_data
        term_vars.ToArray()
    

    /// ### lit_to_primitive_type
    let lit_to_primitive_type = function
        | LitUInt8 _ -> UInt8T
        | LitUInt16 _ -> UInt16T
        | LitUInt32 _ -> UInt32T
        | LitUInt64 _ -> UInt64T
        | LitInt8 _ -> Int8T
        | LitInt16 _ -> Int16T
        | LitInt32 _ -> Int32T
        | LitInt64 _ -> Int64T
        | LitFloat32 _ -> Float32T
        | LitFloat64 _ -> Float64T
        | LitBool _ -> BoolT
        | LitString _ -> StringT
        | LitChar _ -> CharT
    

    /// ### lit_to_ty
    let lit_to_ty x = lit_to_primitive_type x |> YPrim
    

    /// ### is_tco_compatible
    let is_tco_compatible = function
        | TyApply _ | TyJoinPoint _ | TyArrayLiteral _ | TyUnionBox _ | TyToLayout _
        | TyIf _ | TyIntSwitch _ | TyUnionUnbox _ | TyArrayCreate _ | TyFailwith _ -> true
        | _ -> false
    

    /// ### seq_apply
    let seq_apply (d: LangEnv) end_dat =
        let inline end_ () = d.seq.Add(TyLocalReturnData(end_dat,d.trace))
        if d.seq.Count > 0 then
            match d.seq.[d.seq.Count-1] with
            | TyLet(end_dat',a,b) when Object.ReferenceEquals(end_dat,end_dat') && is_tco_compatible b -> d.seq.[d.seq.Count-1] <- TyLocalReturnOp(a,b,end_dat')
            | _ -> end_()
        else end_()
        d.seq.ToArray()
    

    /// ### cse_tryfind
    let cse_tryfind (d: LangEnv) key =
        d.cse |> List.tryPick (fun x ->
            match x.TryGetValue key with
            | true, v -> Some v
            | _ -> None
            )
    

    /// ### cse_add
    let cse_add (d: LangEnv) k v = (List.head d.cse).Add(k,v)
    

    /// ### show_data
    let show_data x =
        let rec f prec x =
            let p = p prec
            match x with
            | DB -> "()"
            | DPair(a,b) -> p 25 (sprintf "%s, %s" (f 25 a) (f 24 b))
            | DSymbol x -> sprintf ".%s" x
            | DFunction _ -> p 20 "? -> ?"
            | DForall _ -> p 0 "forall ?. ?"
            | DExists(a,b) ->
                let a = HopacExtensions.A.map (show_ty >> sprintf "(%s)") a |> String.concat " "
                p 0 $"exists {a}. %s{f 0 b}"
            | DRecord l -> sprintf "{%s}" (l |> Map.toList |> List.map (fun ((_,k),v) -> sprintf "%s : %s" k (f -1 v)) |> String.concat "; ")
            | DLit a -> show_lit a
            | DTLit a -> $"`{show_lit a}"
            | DV(L(_,ty)) -> show_ty ty
            | DUnion(a,_) -> f prec a
            | DNominal(a,b) -> p 0 (sprintf "%s : %s" (f 0 a) (show_ty b))
            | DHashSet _ -> p 0 "<HashSet>"
            | DHashMap _ -> p 0 "<HashMap>"
    

        f -1 x
    

    /// ### is_lit
    let is_lit = function
        | DLit _ -> true
        | _ -> false
    

    /// ### is_numeric
    let is_numeric = function
        | YPrim (UInt8T | UInt16T | UInt32T | UInt64T
            | Int8T | Int16T | Int32T | Int64T
            | Float32T | Float64T) -> true
        | _ -> false
    

    /// ### is_signed_numeric
    let is_signed_numeric = function
        | YPrim (Int8T | Int16T | Int32T | Int64T | Float32T | Float64T) -> true
        | _ -> false
    

    /// ### is_non_float_primitive
    let is_non_float_primitive = function
        | YPrim (Float32T | Float64T) -> false
        | YPrim _ -> true
        | _ -> false
    

    /// ### is_primitive
    let is_primitive = function
        | YPrim _ -> true
        | _ -> false
    

    /// ### is_string
    let is_string = function
        | YPrim StringT -> true
        | _ -> false
    

    /// ### is_char
    let is_char = function
        | YPrim CharT -> true
        | _ -> false
    

    /// ### is_float
    let is_float = function
        | YPrim (Float32T | Float64T) -> true
        | _ -> false
    

    /// ### is_bool
    let is_bool = function
        | YPrim BoolT -> true
        | _ -> false
    

    /// ### is_int
    let is_int = function
        | YPrim (UInt32T | UInt64T | Int32T | Int64T) -> true
        | _ -> false
    

    /// ### is_int
    let is_any_int = function
        | YPrim (UInt8T | UInt16T | UInt32T | UInt64T
            | Int8T | Int16T | Int32T | Int64T) -> true
        | _ -> false
    

    /// ### is_any_int_allow_jp_placeholders
    /// Pragmatic: allow join-point recursion placeholders to pass where an int is expected in core string/array ops.
    /// Rationale: core/sm.spi uses forall t{int} indices and can leak JPMethodRecPlaceholder during JP waiting; treating it as int
    /// unblocks codegen without reintroducing global numeric coercions (only call sites that opt-in use this predicate).
    let is_any_int_allow_jp_placeholders = function
        | YSymbol s when s.Contains("JPMethodRecPlaceholder(") || s.Contains("JPTypeRecPlaceholder(") -> true
        | t -> is_any_int t
    
    


    /// ### is_string_allow_jp_placeholders
    /// Pragmatic: allow join-point recursion placeholders to pass where a string is expected in core string ops.
    /// Rationale: runtime.spi string helpers can leak JP placeholders during JP waiting; treating it as string
    /// unblocks codegen without global coercions.
    let is_string_allow_jp_placeholders = function
        | YSymbol s when s.Contains("JPMethodRecPlaceholder(") || s.Contains("JPTypeRecPlaceholder(") || s.Contains("JPClosureRecPlaceholder(") || s.Contains("JPMethodUnknownRet") -> true
        | t -> is_string t
    
    


    /// ### is_int64
    let is_int64 = function
        | YPrim Int64T -> true
        | _ -> false
    

    /// ### is_int32
    let is_int32 = function
        | YPrim Int32T -> true
        | _ -> false
    

    /// ### is_lit_zero
    let is_lit_zero = function
        | DLit a ->
            match a with
            | LitInt8 0y | LitInt16 0s | LitInt32 0 | LitInt64 0L
            | LitUInt8 0uy | LitUInt16 0us | LitUInt32 0u | LitUInt64 0UL
            | LitFloat32 0.0f | LitFloat64 0.0 -> true
            | _ -> false
        | _ -> false
    

    /// ### is_lit_one
    let is_lit_one = function
        | DLit a ->
            match a with
            | LitInt8 1y | LitInt16 1s | LitInt32 1 | LitInt64 1L
            | LitUInt8 1uy | LitUInt16 1us | LitUInt32 1u | LitUInt64 1UL
            | LitFloat32 1.0f | LitFloat64 1.0 -> true
            | _ -> false
        | _ -> false
    

    /// ### is_int_lit_zero
    let is_int_lit_zero = function
        | DLit a ->
            match a with
            | LitInt8 0y | LitInt16 0s | LitInt32 0 | LitInt64 0L
            | LitUInt8 0uy | LitUInt16 0us | LitUInt32 0u | LitUInt64 0UL -> true
            | _ -> false
        | _ -> false
    

    /// ### is_int_lit_one
    let is_int_lit_one = function
        | DLit a ->
            match a with
            | LitInt8 1y | LitInt16 1s | LitInt32 1 | LitInt64 1L
            | LitUInt8 1uy | LitUInt16 1us | LitUInt32 1u | LitUInt64 1UL -> true
            | _ -> false
        | _ -> false
    

    /// ### lit_zero
    let lit_zero = function
        | YPrim Int8T -> LitInt8 0y
        | YPrim Int16T -> LitInt16 0s
        | YPrim Int32T -> LitInt32 0
        | YPrim Int64T -> LitInt64 0L
        | YPrim UInt8T -> LitUInt8 0uy
        | YPrim UInt16T -> LitUInt16 0us
        | YPrim UInt32T -> LitUInt32 0u
        | YPrim UInt64T -> LitUInt64 0UL
        | YPrim Float32T -> LitFloat32 0.0f
        | YPrim Float64T -> LitFloat64 0.0
        | _ -> failwith "Compiler error: Expected a numeric value."
    

    /// ### vt
    let vt s i = if i < s.env_global_type.Length then s.env_global_type.[i] else s.env_stack_type.[i-s.env_global_type.Length]
    

    /// ### v
    let v s i = if i < s.env_global_term.Length then s.env_global_term.[i] else s.env_stack_term.[i-s.env_global_term.Length]
    

    /// ### add_trace
    // alpha166: cap trace growth deterministically to avoid pathological list sizes that can themselves
    // trigger BigStack exhaustion (e.g. deep term recursion + trace accumulation). The cap is per-thread
    // and incurs O(1) overhead on the hot path.
    let trace_budget_default = 4096

    // alpha167: F# module-level lets cannot be annotated with [<ThreadStatic>]. Use ThreadLocal instead.
    let trace_budget = new System.Threading.ThreadLocal<int>(fun () -> trace_budget_default)

    let trace_trunc_range : Range =
        { path = "<trace truncated>"
          range = ({| line = 0; character = 0 |}, {| line = 0; character = 0 |}) }

    let inline trace_budget_init () =
        () // ThreadLocal initializes per-thread automatically.

    let add_trace (s : LangEnv) r =
        trace_budget_init ()
        let b = trace_budget.Value
        if b = -1 then s
        else
            let b2 = b - 1
            if b2 <= 0 then
                trace_budget.Value <- -1
                { s with trace = trace_trunc_range :: s.trace }
            else
                trace_budget.Value <- b2
                { s with trace = r :: s.trace }

    let inline globals_add (s : LangEnv) (x : string) =
        // Thread-safe global snippet accumulation (used during codegen).
        // Avoids global locks in the hot path by using a concurrent membership set; only new inserts take the lock.
        if s.globals_seen.TryAdd(x, 0uy) then
            lock s.globals_lock (fun () -> s.globals.Add x)
        x
    

    let inline globals_flush (_s : LangEnv) = ()
    

    /// ### store_term
    let store_term (s : LangEnv) i v = s.env_stack_term.[i-s.env_global_term.Length] <- v
    

    /// ### store_ty
    let store_ty (s : LangEnv) i v = s.env_stack_type.[i-s.env_global_type.Length] <- v
    

    /// ### is_unify
    let is_unify s x =
        let is_metavar = HashSet()
        let rec f = function
            | YB, YB | YExists, YExists | YForall, YForall -> true
            | YFun(a,b,t), YFun(a',b',t') -> t = t' && f (a,a') && f (b,b')
            | YApply(a,b), YApply(a',b')
            | YPair(a,b), YPair(a',b') -> f (a,a') && f (b,b')
            | YSymbol a, YSymbol b -> a = b
            | YTypeFunction(a,b,c,d), YTypeFunction(a',b',c',d') -> a = a' && Array.forall2 (fun b b' -> f (b,b')) b b' && c = c' && d = d'
            | YRecord a, YRecord a' -> Map.forall (fun k v' -> match Map.tryFind k a with Some v -> f (v, v') | None -> false) a'
            | YPrim a, YPrim a' -> a = a'
            | YArray a, YArray a' -> f (a, a')
            | YMacro a, YMacro a' ->
                List.forall2 (fun a a' ->
                    match a, a' with
                    | Text a, Text a' -> a = a'
                    | Type a, Type a' -> f (a,a')
                    | _ -> false
                    ) a a'
            | YNominal a, YNominal a' -> a = a'
            | YLayout(a,b), YLayout(a',b') -> f (a,a') && b = b'
            | YUnion a, YUnion a' -> a = a'
            | YLit a, YLit b -> a = b
            | a, YMetavar i -> (is_metavar.Add i && (store_ty s i a; true)) || a = vt s i
            | _ -> false
        f x
    
    


    /// ### PartEvalResult
    /// ALPHA48: Simplified type using Hopac IVar for coordination
    type PartEvalResult = {
        join_point_method : System.Collections.Concurrent.ConcurrentDictionary<string ConsedNode * E, System.Collections.Concurrent.ConcurrentDictionary<ConsedNode<RData [] * Ty [] * Ty>, Hopac.IVar<TypedBind [] option * Ty option * string option>> * HashConsTable * int64>
        join_point_closure : System.Collections.Concurrent.ConcurrentDictionary<string ConsedNode * E, System.Collections.Concurrent.ConcurrentDictionary<ConsedNode<RData [] * Ty [] * Ty>, Hopac.IVar<(Data * TypedBind []) option>> * HashConsTable * int64>
        ty_to_data : Ty -> Data
        nominal_apply : Ty -> Ty
        globals : ResizeArray<string>
        }
    /// ALPHA48: JPTypeCell now uses Hopac IVar for signaling
    type JPTypeCell<'a> = { ivar: Hopac.IVar<'a option>; mutable owner: int }
    

    [<Struct>]
    type JpMethodRecPlaceholderCell =
        val gen: int64
        val ph: Ty
        val v: Ty
        new(gen, ph, v) = { gen = gen; ph = ph; v = v }
    
    
    



    /// ### peval
    let peval (env : PartEvalTopEnv) (x : E) =
        // v107-alpha14: always log effective runtime knobs once per process
        DiagSidecar.emitEnvSnapshotOnce()
        try
            DiagSidecar.emit (sprintf "SETTINGS bigstack_mb_global=%d bigstack_max_nest=%d term_mb=%d ty_mb=%d apply_mb=%d if_mb=%d"
                                    (BigStack.getGlobalMb()) (BigStack.getMaxNest())
                                    (BigStack.getMb "term") (BigStack.getMb "ty") (BigStack.getMb "apply") (BigStack.getMb "if"))
        with _ -> ()
        // Comparer for join point body keys: backend by structural equality, body by physical identity.
        // This avoids unsound cache collisions between alpha-equal bodies coming from different scopes/modules.
        let jp_type_inflight = System.Threading.AsyncLocal<System.Collections.Generic.HashSet<ConsedNode<Ty []>>>()
        let mk_jp_type_inflight () = System.Collections.Generic.HashSet<ConsedNode<Ty []>>(HashIdentity.Reference)
        let inline get_async_local (slot : System.Threading.AsyncLocal<'T>) (mk : unit -> 'T) : 'T =
            let v = slot.Value
            if obj.ReferenceEquals(v, null) then
                let v2 = mk()
                slot.Value <- v2
                v2
            else v
        let jp_body_key_comparer =
            { new System.Collections.Generic.IEqualityComparer<string ConsedNode * E> with
                member _.Equals((b1,e1),(b2,e2)) = b1 = b2 && LanguagePrimitives.PhysicalEquality e1 e2
                member _.GetHashCode((b,e)) = (hash b) ^^^ (System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode e)
            }
    

        let join_point_method = System.Collections.Concurrent.ConcurrentDictionary<_,_>(jp_body_key_comparer)
        let join_point_closure = System.Collections.Concurrent.ConcurrentDictionary<_,_>(jp_body_key_comparer)
        let join_point_type = System.Collections.Concurrent.ConcurrentDictionary<_,_>(HashIdentity.Reference)
        let backend_strings = StripedHashConsTable(32)  // v107-alpha11: striped for parallel access
        let backend_strings_lock = obj()
        let backend_switch_validate_all = ref false  // par: validate only current backend branch by default
        let backend_switch_lock = obj()
        // JP: Track JP dict clear callbacks - multiple subsystems (peval, compiler) may register.
        let jp_dict_clear_lock = obj()
        let mutable jp_dict_clear_callbacks : (unit -> unit) list = []
        let register_jp_dict_clear_callback (f: unit -> unit) =
            lock jp_dict_clear_lock (fun () ->
                jp_dict_clear_callbacks <- f :: jp_dict_clear_callbacks
            )
        let inline run_jp_dict_clear_callbacks reason =
            let cbs =
                lock jp_dict_clear_lock (fun () -> jp_dict_clear_callbacks |> List.rev)
            for f in cbs do
                try f () with _ -> ()
            try DiagSidecar.emit (sprintf "JP: cache invalidation reason=%A jp_clear_callbacks=%d" reason cbs.Length) with _ -> ()
    

        // Hopac: parallel join point workers (peval)
    

        let inline capture_edi (e: exn) =
            System.Runtime.ExceptionServices.ExceptionDispatchInfo.Capture e
    

        // Global join-point exception queue (fast path) + per-join-point exception cache (deterministic rethrow)
        let jp_exns : System.Collections.Concurrent.ConcurrentQueue<System.Runtime.ExceptionServices.ExceptionDispatchInfo> =
            System.Collections.Concurrent.ConcurrentQueue()
    

        // Per-join-point exception cache: avoids losing the root cause when one waiter dequeues jp_exns first.
        let jp_method_exns : System.Collections.Concurrent.ConcurrentDictionary<ConsedNode<RData [] * Ty [] * Ty>, System.Runtime.ExceptionServices.ExceptionDispatchInfo> =
            System.Collections.Concurrent.ConcurrentDictionary(HashIdentity.Reference)
    

        let jp_throw_keyed (k: ConsedNode<RData [] * Ty [] * Ty>) =
            let mutable edi = Unchecked.defaultof<System.Runtime.ExceptionServices.ExceptionDispatchInfo>
            if jp_method_exns.TryGetValue(k, &edi) then edi.Throw()
    

        do CacheGeneration.registerOnInvalidate (fun reason ->
            try run_jp_dict_clear_callbacks reason with _ -> ()
        )
    
        // ALPHA45: Register JP dict clearing on cache invalidation

        // This prevents stale IVars/exceptions from leaking across retry attempts.
        do register_jp_dict_clear_callback (fun () ->
            try
                let m0, c0, t0, ex0 = join_point_method.Count, join_point_closure.Count, join_point_type.Count, jp_method_exns.Count
                join_point_method.Clear()
                join_point_closure.Clear()
                join_point_type.Clear()
                // Also clear exception queues/caches to prevent stale exceptions from leaking
                let mutable edi = Unchecked.defaultof<_>
                let mutable drained = 0
                while jp_exns.TryDequeue(&edi) do drained <- drained + 1
                jp_method_exns.Clear()
                DiagSidecar.emit (sprintf "JP: jp_clear before(method=%d closure=%d type=%d exn_cache=%d) drained_exn_q=%d" m0 c0 t0 ex0 drained)
            with _ -> ()
        )
    
    
    



        let mutable jp_cd : System.Threading.CountdownEvent = new System.Threading.CountdownEvent(1)
    

        let jp_barrier_lock = obj()
        let mutable jp_wait_closed = false
        let mutable jp_wait_closed_cd : System.Threading.CountdownEvent = null

        // ALPHA239: helper used ONLY under jp_barrier_lock.
        // If the current CountdownEvent has been signaled (IsSet=true), rotate to a fresh one.
        // This keeps jp_start schedulable after a jp_wait and avoids "untracked" inline jobs.
        let inline jp_rotate_cd_if_set_locked () =
            if jp_cd.IsSet then
                jp_cd <- new System.Threading.CountdownEvent(1)
                jp_wait_closed <- false
                jp_wait_closed_cd <- null

        let jp_pending_jobs () =
            let c = jp_cd.CurrentCount
            if jp_wait_closed then c else max 0 (c - 1)
    

        // Work queue for parallel JP evaluation
        // Waiting threads "help" by executing queued work (work-distributing pattern)
        let jp_work_q : System.Collections.Concurrent.ConcurrentQueue<unit -> unit> = System.Collections.Concurrent.ConcurrentQueue()
        let jp_work_sem = new System.Threading.SemaphoreSlim(0, System.Int32.MaxValue)

        // [HOPAC-PEVAL-245-001] Stopwatch for per-peval timing (avoid forward refs).
        let peval_sw = System.Diagnostics.Stopwatch.StartNew()
        // ALPHA930: install the peval-relative clock used by out-of-scope replay helpers
        // when they refresh jp_last_progress_ms after real semantic_root_complete returns.
        jp_progress_clock <- fun () -> peval_sw.ElapsedMilliseconds
        // Alpha114: JP counters must be defined before first use (no forward refs in F#).
        let mutable jp_pending_count : int64 = 0L  // Atomic counter of pending jobs
        let mutable jp_total_enqueued : int64 = 0L  // Atomic counter of scheduled jobs
        let mutable jp_last_enq_ms : int64 = 0L     // Atomic: last time jp_total_enqueued changed (ms since peval_sw start)
        let mutable jp_sub_total_frozen : int64 = 0L // Atomic: 0 => dynamic denom, >0 => frozen denom for progress
        let mutable jp_total_done : int64 = 0L      // Atomic counter of completed jobs
        let mutable jp_progress_started = 0

        let mutable jp_worker_active = 0L

        // Alpha191: track active JP work-item runtimes so the progress bar can explain long "stalls"
        // (e.g. done stays constant while a single heavy join-point specialization is running).
        let jp_active_jobs : System.Collections.Concurrent.ConcurrentDictionary<int64,int64> =
            System.Collections.Concurrent.ConcurrentDictionary<int64,int64>()
        let jp_active_job_names : System.Collections.Concurrent.ConcurrentDictionary<int64,string> =
            System.Collections.Concurrent.ConcurrentDictionary<int64,string>()
        let mutable jp_job_id_gen : int64 = 0L

    
    


        // [JP-EXN-208-001] Do not let background threads consume abort exceptions.
        // Progress88 heartbeat calls jp_note_progress; if it dequeues, abort signals can get lost.
        let jp_main_tid = System.Threading.Thread.CurrentThread.ManagedThreadId
        let jp_main_thread = System.Threading.Thread.CurrentThread
        let jp_throw_if_any () =
            let mutable edi = Unchecked.defaultof<System.Runtime.ExceptionServices.ExceptionDispatchInfo>
            if jp_exns.TryPeek(&edi) then
                if System.Threading.Thread.CurrentThread.ManagedThreadId = jp_main_tid then
                    let mutable edi2 = Unchecked.defaultof<System.Runtime.ExceptionServices.ExceptionDispatchInfo>
                    if jp_exns.TryDequeue(&edi2) then edi2.Throw()
    
    
    



        let jp_is_worker_thread () =
            let t = System.Threading.Thread.CurrentThread
            not (isNull t.Name) && t.Name.StartsWith("jp-worker-")
    

        let jp_fill_ivar (ivar: Hopac.IVar<'a>) (value: 'a) : unit =
            if jp_is_worker_thread () then
                // Dedicated OS threads may drive Hopac jobs to completion without starving the scheduler.
                Hopac.run (Hopac.IVar.fill ivar value)
            else
                // v107: Under custom JP scheduler + sequential fallback, Hopac.start can starve (no scheduler pump),
                // leaving IVars forever unfilled. Prefer synchronous fill; fallback to start only if Hopac.run is unsafe.
                try
                    Hopac.run (Hopac.IVar.fill ivar value)
                with _ ->
                    Hopac.start (Hopac.IVar.fill ivar value)
    

        // ════════════════════════════════════════════════════════════════════════
        // ════════════════════════════════════════════════════════════════════════
        // ════════════════════════════════════════════════════════════════════════
        // PARALLELISM CONFIGURATION (no env override; Hopac/SOTA always-on defaults)

        // Degree of parallelism: use all available CPU cores
        let jp_dop = max 1 Environment.ProcessorCount

        // Hopac/SOTA: always parallel enabled
        let jp_is_parallel_enabled = true

        // Stack size per worker thread (MB)
        let jp_stack_mb = 64

        // Pending job cap (prevents runaway queue + memory blowups)
        let jp_max_pending =
            let v = jp_dop * 4096
            if v < 16384 then 16384 else v

        // How many queued thunks a helper drains per iteration while waiting
        let jp_help_batch_n = 256

        let mutable jp_total_started = 0L

        // ════════════════════════════════════════════════════════════════════════
        // DIAGNOSTIC CONFIGURATION (no env override)
        // ════════════════════════════════════════════════════════════════════════

        let diag_period_ms = 0L  // alpha146: default off to avoid tick spam
        let diag_abort_ms = 600000L
        let diag_wait_ms = 1000L
        let diag_jp_spec_cap = 0L
        let diag_jp_name_spec_cap = 0L

        // Hard abort controls (defaults intentionally *on*)
        let peval_abort_ms = 600000L
        let peval_mem_limit_mb = 4096L
        let jp_stall_abort_ms = 180000L  // fixed default; no env var override
    

        // Always force async dispatch for JPs (maximizes parallelism)
        let jp_force_async_unannot = true
        let jp_force_async_types = true
    

        // Use custom thread pool, not Hopac's scheduler (avoids deadlocks)
        let jp_use_threadpool = false
    

        // Hard abort on diagnostic cap hit (don't try to continue)
        let jp_diag_hard_abort = false
    

        // Enable verbose diagnostics and traces for debugging
        let jp_diag_verbose = false  // alpha146: default off to avoid multi-line spam
        let jp_diag_include_top_traces = false
    

        let diag_console_lock = obj()

        // alpha151: bring back *useful* detailed diagnostics without console spam.
        // Default stays quiet; full multi-line diagnostic goes to file, and stderr full-dump is opt-in.
        let jp_diag_stderr_full = false  // fixed default; no env var override

        // alpha160: enquanto o compilador estiver instável, NÃO gravar diagnósticos em arquivos.
        // Isso melhora a captura em CI/TTY e reduz ruído de IO.
        // (Reabilitar mais tarde via env var, quando a pipeline estiver estável.)
        let diag_save_enabled = false
        // let diag_save_enabled =
        //     | null | "" -> true
        //     | "1" | "true" | "TRUE" | "True" -> true
        //     | _ -> false

        let diag_trace_dir =
            if diag_save_enabled then
                try
                    let root = SpiralFileSystem.get_workspace_root ()
                    System.IO.Path.Combine(root, "target", "spiral_Eval", "supervisor_trace")
                with _ ->
                    System.IO.Path.Combine(System.IO.Directory.GetCurrentDirectory(), "target", "spiral_Eval", "supervisor_trace")
            else
                // diagnostics disabled: sentinel path; never created when diag_save_enabled=false
                System.IO.Path.Combine(System.IO.Path.GetTempPath(), "spiral_supervisor_trace_DISABLED")
        do
            if diag_save_enabled then
                try
                    System.IO.Directory.CreateDirectory(diag_trace_dir) |> ignore
                with _ -> ()

        let diag_write_file (tag: string) (text: string) : string option =
            // alpha161: console-only diagnostics while the compiler stabilizes.
            // Avoids trace infrastructure (which can write supervisor_trace files).
            // jp_diag_stderr_full controls full multi-line blocks; otherwise prints a compact header.
            if jp_diag_stderr_full then
                try
                    System.Console.Error.WriteLine(text)
                    System.Console.Error.Flush()
                with _ -> ()
            else
                let one =
                    try
                        let t = text.Replace("\r", "")
                        let idx = t.IndexOf('\n')
                        let firstLine = if idx < 0 then t else t.Substring(0, idx)
                        let firstLine = if firstLine.Length > 220 then firstLine.Substring(0, 220) + " ..." else firstLine
                        sprintf "[spiral_compiler] diag(tag=%s) %s" tag firstLine
                    with _ ->
                        sprintf "[spiral_compiler] diag(tag=%s) (unavailable)" tag
                try
                    System.Console.Error.WriteLine(one)
                    System.Console.Error.Flush()
                with _ -> ()
            None
        // Short diagnostic snapshot helper: keeps logs compact and deterministic in verbose JP diagnostics.
        let jp_diag_snapshot_short (tag: string) =
            let tid = System.Threading.Thread.CurrentThread.ManagedThreadId
            let ts = System.DateTime.UtcNow.ToString("o")
            sprintf "[%s] tid=%d %s" ts tid tag
    

        // Backwards-compatible alias: older call sites expect diag_snapshot_short.
        // alpha271: forward-declared mutable provider to avoid value-before-definition.
        let mutable jp_extra_provider : (unit -> string) = (fun () -> "")

        let diag_snapshot_short = jp_diag_snapshot_short
    
    
    
        // ALPHA35: Parallelism is enabled by default, but the retry loop can request fully sequential



        // JP execution when cache corruption is detected (EJP0003/EJP0007/EJP0008).
        // This is driven by CacheGeneration.requestSequential and reset at attempt=0.
        let mutable jp_parallel_enabled = true  // kept for diagnostic compatibility
    

        let jp_parallel_effective () =
            jp_is_parallel_enabled
            && jp_parallel_enabled
            && not (CacheGeneration.isSequentialRequested())
        let mutable diag_abort_armed = true
    

        // Per-JP-name statistics for detecting loop specialization patterns
        let jp_name_counts = System.Collections.Concurrent.ConcurrentDictionary<string, int>(System.StringComparer.Ordinal)
        let jp_mismatch_counts = System.Collections.Concurrent.ConcurrentDictionary<string, int>(System.StringComparer.Ordinal)
        let jp_name_traces = System.Collections.Concurrent.ConcurrentDictionary<string, Trace>(System.StringComparer.Ordinal)

        // Alpha218: Propagate logical JP names (already recorded by record_jp_diag) into runtime job records,
        // so jp_slow_jobs_snapshot can show meaningful labels instead of bare ids.
        // We do it via a short-lived thread-local "spawn context" set by record_jp_diag and consumed by jp_start_named.
        // Window is small to avoid leaking a previous label into an unrelated spawn on the same thread.
        let jp_spawn_ctx : System.Threading.ThreadLocal<struct(int64 * string)> =
            new System.Threading.ThreadLocal<struct(int64 * string)>(fun () -> struct(0L, ""))

        let inline jp_spawn_ctx_set (name: string) =
            let n = if System.String.IsNullOrEmpty name then "<anon>" else name
            jp_spawn_ctx.Value <- struct(peval_sw.ElapsedMilliseconds, n)

        let inline jp_spawn_ctx_try_get () =
            try
                let struct(ts, n) = jp_spawn_ctx.Value
                if System.String.IsNullOrEmpty n then "" else
                    let age = peval_sw.ElapsedMilliseconds - ts
                    if age >= 0L && age <= 100L then n else ""
            with _ -> ""

        let jp_method_key_names = System.Collections.Concurrent.ConcurrentDictionary<ConsedNode<RData [] * Ty [] * Ty>, string>(HashIdentity.Reference)
        let jp_method_key_traces = System.Collections.Concurrent.ConcurrentDictionary<ConsedNode<RData [] * Ty [] * Ty>, Trace>(HashIdentity.Reference)
        let jp_type_key_traces = System.Collections.Concurrent.ConcurrentDictionary<ConsedNode<Ty []>, Trace>(HashIdentity.Reference)
    

        // Monotonic placeholder ids: eliminate collisions from hash-based ids under parallel builds.
        let mutable jp_method_rec_placeholder_next_id = 0
    

        // JPMethod recursion placeholders: enable recursive functions without forcing explicit return annotations.
        // Generation-aware: placeholder resolutions must not persist across cache invalidations.
        // This is a minimal 'promise-like' cell inspired by the old Hopac approach: once a build attempt is invalidated,
        // we reset back to the placeholder symbol for that JP key so the retry can re-infer deterministically.
        let jp_method_rec_placeholders : System.Collections.Concurrent.ConcurrentDictionary<ConsedNode<RData [] * Ty [] * Ty>, JpMethodRecPlaceholderCell> =
            System.Collections.Concurrent.ConcurrentDictionary<ConsedNode<RData [] * Ty [] * Ty>, JpMethodRecPlaceholderCell>(HashIdentity.Reference)
        // Map placeholder Ty -> JP key so we can resolve/deref deterministically (no O(n) scan, no structural collisions).
        let jp_method_rec_placeholder_keys : System.Collections.Concurrent.ConcurrentDictionary<Ty, ConsedNode<RData [] * Ty [] * Ty>> =
            System.Collections.Concurrent.ConcurrentDictionary<Ty, ConsedNode<RData [] * Ty [] * Ty>>(HashIdentity.Structural)
    
    


        // Placeholder id -> JP key mapping for round-tripped placeholders (when the Ty is reconstructed from printed form).
        let jp_method_rec_placeholder_ids : System.Collections.Concurrent.ConcurrentDictionary<int, ConsedNode<RData [] * Ty [] * Ty>> =
            System.Collections.Concurrent.ConcurrentDictionary<int, ConsedNode<RData [] * Ty [] * Ty>>(HashIdentity.Structural)
    
        // Alpha36: when generation invalidates, clear JP recursion placeholder cells and their reverse maps.

        do CacheGeneration.registerOnInvalidate (fun _reason ->
            try
                jp_method_rec_placeholders.Clear()
                jp_method_rec_placeholder_keys.Clear()
                jp_method_rec_placeholder_ids.Clear()
            with _ -> ()
        )
    
    
    



        let jp_method_try_key_of_rec_placeholder (ty: Ty) : ConsedNode<RData [] * Ty [] * Ty> option =
            // Fast-path: exact placeholder Ty -> key mapping.
            match jp_method_rec_placeholder_keys.TryGetValue ty with
            | true, k -> Some k
            | false, _ ->
                // Round-trip path: if the placeholder Ty was reconstructed from printed form,
                // it might not have been registered in jp_method_rec_placeholder_keys. In that case,
                // parse the id suffix and consult jp_method_rec_placeholder_ids.
                let inline try_parse_id (s: string) : int option =
                    // Expected: "JPMethodRecPlaceholder(vYYYYMMDD-alphaNN;<jp>#<id>)"
                    let i = s.LastIndexOf '#'
                    if i <= 0 then None
                    else
                        let j0 = s.LastIndexOf ')'
                        let j = if j0 > i then j0 else s.Length
                        let n_str = s.Substring(i+1, j-i-1)
                        match System.Int32.TryParse(n_str) with
                        | true, n -> Some n
                        | false, _ -> None
                match ty with
                | YSymbol s ->
                    match try_parse_id s with
                    | Some id ->
                        match jp_method_rec_placeholder_ids.TryGetValue id with
                        | true, k -> Some k
                        | false, _ -> None
                    | None -> None
                | _ -> None
    

        let jp_method_deref_rec_placeholder (ty: Ty) : Ty =
            match jp_method_try_key_of_rec_placeholder ty with
            | Some k ->
                let curGen = CacheGeneration.current()
                let cell = jp_method_rec_placeholders.[k]
    

                // Always compute the safe-annotation fallback once; we also apply it when the placeholder is stale.
                // Without this, a placeholder from a previous cache generation can leak as a term-level DV and explode later
                // as an apply-mismatch (the .JPMethodRecPlaceholder(...) crash seen in alpha25 logs).
                let (_, _, ret_ty) = k.node
                let inline is_hard_primitive_like (t: Ty) =
                    match t with
                    | YLit _ | YPrim _ -> true
                    | _ -> false
                let inline is_jp_placeholder_like (t: Ty) =
                    match t with
                    | YSymbol s when s.Contains("JPMethodRecPlaceholder(") || s.Contains("JPTypeRecPlaceholder(") -> true
                    | _ -> false
                let inline fallback () =
                    // allow non-primitive annotated return types to break recursion, but never substitute primitives.
                    if is_jp_placeholder_like ret_ty || is_hard_primitive_like ret_ty then ty else ret_ty
    

                if cell.gen <> curGen then
                    // Stale generation: treat as unresolved placeholder for this retry attempt.
                    // Critical: still apply fallback so the stale placeholder cannot leak into term evaluation.
                    fallback ()
                else
                    let v = cell.v
                    if v = cell.ph then
                        // par: conservative fallback. Only trust annotated return types that are
                        // union-ish; returning a primitive here (ex: i32) can create spurious EJP0007 apply-mismatch.
                        fallback ()
                    else v
            | None -> ty
    

        let inline ty_is_jp_method_rec_placeholder (ty: Ty) : bool =
            match jp_method_try_key_of_rec_placeholder ty with
            | Some _ -> true
            | None ->
                match ty with
                | YSymbol s when s.Contains("JPMethodRecPlaceholder(") -> true
                | _ -> false
    

        let inline ty_is_jp_type_rec_placeholder (ty: Ty) : bool =
            match ty with
            | YSymbol s when s.Contains("JPTypeRecPlaceholder(") -> true
            | _ -> false
    

        let inline ty_is_jp_method_unknown_ret_placeholder (ty: Ty) : bool =
            match ty with
            | YSymbol s when s.Contains("JPMethodUnknownRet(") -> true
            | _ -> false
    
    


        let rec ty_eq_allow_jp_placeholders (a: Ty) (b: Ty) : bool =
            // Treat JP method recursion placeholders as wildcards to break cyclic type validation (Hopac join points).
            if ty_is_jp_method_rec_placeholder a || ty_is_jp_method_rec_placeholder b || ty_is_jp_type_rec_placeholder a || ty_is_jp_type_rec_placeholder b || ty_is_jp_method_unknown_ret_placeholder a || ty_is_jp_method_unknown_ret_placeholder b then true
            else
                match a, b with
                | YVoid, YVoid -> true
                | YB, YB -> true
                | YLit x, YLit y -> x = y
                | YSymbol x, YSymbol y -> x = y
                | YPrim x, YPrim y -> x = y
                | YPair(a1,a2), YPair(b1,b2) -> ty_eq_allow_jp_placeholders a1 b1 && ty_eq_allow_jp_placeholders a2 b2
                | YArray a1, YArray b1 -> ty_eq_allow_jp_placeholders a1 b1
                | YApply(a1,a2), YApply(b1,b2) -> ty_eq_allow_jp_placeholders a1 b1 && ty_eq_allow_jp_placeholders a2 b2
                | YLayout(a1,l1), YLayout(b1,l2) -> l1 = l2 && ty_eq_allow_jp_placeholders a1 b1
                | YNominal n1, YNominal n2 -> n1 = n2
                | YUnion u1, YUnion u2 -> u1 = u2
                | YMetavar x, YMetavar y -> x = y
                | _ ->
                    // ALPHA57: last-resort structural equivalence for nominal/opaque types that print identically
                    // but differ in internal ids (common when core/plugin define parallel primitives like 'string').
                    let a' = jp_method_deref_rec_placeholder a
                    let b' = jp_method_deref_rec_placeholder b
                    (show_ty a') = (show_ty b')
    
    
    
    
    





        let jp_method_rec_placeholder (key: ConsedNode<RData [] * Ty [] * Ty>) (jp: string) : Ty =
            let curGen = CacheGeneration.current()
            let cell =
                jp_method_rec_placeholders.GetOrAdd(
                    key,
                    System.Func<ConsedNode<RData [] * Ty [] * Ty>, JpMethodRecPlaceholderCell>(fun key ->
                        // Placeholder: printable + unique. Use a monotonic id so different JP keys cannot collide under parallel builds.
                        let id = System.Threading.Interlocked.Increment(&jp_method_rec_placeholder_next_id)
                        let ph = YSymbol (sprintf "JPMethodRecPlaceholder(par;%s#%d)" jp id)
                        jp_method_rec_placeholder_keys.TryAdd(ph, key) |> ignore
                        jp_method_rec_placeholder_ids.TryAdd(id, key) |> ignore
                        JpMethodRecPlaceholderCell(curGen, ph, ph)
                    )
                )
            if cell.gen = curGen then cell.v
            else
                // Stale cell from a previous generation: reset to placeholder so the retry can re-infer deterministically.
                let resetCell = JpMethodRecPlaceholderCell(curGen, cell.ph, cell.ph)
                jp_method_rec_placeholders.AddOrUpdate(key, resetCell, (fun _ old -> if old.gen = curGen then old else resetCell)) |> ignore
                resetCell.v
    

        let jp_method_resolve_rec_placeholder (key: ConsedNode<RData [] * Ty [] * Ty>) (ty: Ty) : unit =
            // par: generation-aware placeholder resolution + anti-clobber.
            // We still keep the 'hard primitive vs expected non-primitive' guard, but we also prevent a hard primitive (ex: i32)
            // from overwriting a richer resolved type within the same generation (a common source of spurious EJP0007 apply-mismatch).
            let inline is_primitive_like (t: Ty) =
                match t with
                | YVoid | YB | YLit _ | YPrim _ -> true
                | _ -> false
            let inline is_hard_primitive_like (t: Ty) =
                match t with
                | YB | YLit _ | YPrim _ -> true
                | _ -> false
            let inline is_jp_method_placeholder (t: Ty) =
                match t with
                | YSymbol s when s.StartsWith("JPMethodRecPlaceholder(") -> true
                | _ -> false
    

            let inline is_unknown_ret (t: Ty) =
                match t with
                | YSymbol s when s.StartsWith("JPMethodUnknownRet(") -> true
                | _ -> false
    

            let (_, _, expected_ret_ty) = key.node
            let curGen = CacheGeneration.current()
    

            if is_hard_primitive_like ty && not (is_primitive_like expected_ret_ty) && not (is_jp_method_placeholder expected_ret_ty) && not (is_unknown_ret expected_ret_ty) then
                if jp_diag_verbose then
                    let jp_name =
                        match jp_method_key_names.TryGetValue key with
                        | true, n -> n
                        | _ -> "<unknown>"
                    let snap = jp_diag_snapshot_short (sprintf "[spiral_compiler] EJP0007 guard (jp_resolve_hard_primitive) jp=%s" jp_name)
                    DiagSidecar.emit (
                        sprintf "[spiral_compiler] EJP0007 guard: refused cementing hard primitive\n      jp=%s\n      expected_ret=%s\n      got=%s\n      key=%O\n    %s"
                            jp_name (show_ty expected_ret_ty) (show_ty ty) key snap
                    )
                ()
            else
                // Add case should be unreachable in normal flow (placeholder is created first), but keep it safe.
                let addCell = JpMethodRecPlaceholderCell(curGen, ty, ty)
                jp_method_rec_placeholders.AddOrUpdate(
                    key,
                    addCell,
                    (fun _ old ->
                        let ph = old.ph
                        let oldv =
                            if old.gen = curGen then old.v
                            else ph // stale generation: treat as unresolved
                        // Do not allow a hard primitive to clobber a richer type within the same generation.
                        if is_hard_primitive_like ty && oldv <> ph && not (is_hard_primitive_like oldv) then
                            JpMethodRecPlaceholderCell(curGen, ph, oldv)
                        else
                            JpMethodRecPlaceholderCell(curGen, ph, ty)
                    )
                ) |> ignore
    

        let jp_invalidate_bounded (key: string) (maxAttempts: int) (reason: string) =
            let n = jp_mismatch_counts.AddOrUpdate(key, 1, (fun _ v -> v + 1))
            let gen =
                if n <= maxAttempts then
                    let gen = CacheGeneration.invalidate reason
                    // Alpha206+: in sequential retry, abort immediately after invalidation to avoid long-lived stale jobs.
                    if CacheGeneration.isSequentialRequested() then
                        let msg = sprintf "%s (invalidate abort; seq=1 gen=%d inv=%d)" reason gen (CacheGeneration.invalidationCount())
                        jp_exns.Enqueue(capture_edi (PartEvalTypeError([], msg)))
                        // [JP-INT-211-001] Disabled: Thread.Interrupt causes fatal BigStack Join interruptions (see 210.txt).
                        ()
                    gen
                else CacheGeneration.current()
            gen, n
    
    


        let jp_method_stack_preview (stack: System.Collections.Generic.HashSet<ConsedNode<RData [] * Ty [] * Ty>>) =
            try
                stack
                |> Seq.truncate 16
                |> Seq.map (fun k ->
                    match jp_method_key_names.TryGetValue k with
                    | true, name -> name
                    | _ -> sprintf "%O" k)
                |> Seq.toArray
                |> fun a -> System.String.Join(" ; ", a)
            with _ -> "<unavailable>"
    

        let jp_type_stack_preview (stack: System.Collections.Generic.HashSet<ConsedNode<Ty []>>) =
            try
                stack
                |> Seq.truncate 16
                |> Seq.map (fun k -> sprintf "%O" k)
                |> Seq.toArray
                |> fun a -> System.String.Join(" ; ", a)
            with _ -> "<unavailable>"
    

        let inline trace_frame_short (x: Range) =
            let line = (fst x.range).line + 1
            let col = (fst x.range).character + 1
            sprintf "%s:%d:%d" x.path line col
    
        /// ALPHA15: Concise trace frame: filename only (no directory), line:col

        let inline trace_frame_concise (x: Range) =
            let filename = System.IO.Path.GetFileName(x.path)
            let line = (fst x.range).line + 1
            let col = (fst x.range).character + 1
            sprintf "%s:%d:%d" filename line col
    

        let inline trace_frame_rust (x: Range) =
            let (p0, p1) = x.range
            sprintf "%s:({ line = %d; character = %d }, { line = %d; character = %d })"
                x.path (p0.line + 1) (p0.character + 1) (p1.line + 1) (p1.character + 1)
    

        let trace_dedup (xs: Trace) =
            let rec loop (last: Range option) (acc: Range list) (xs: Trace) =
                match xs with
                | [] -> List.rev acc
                | x :: rest ->
                    match last with
                    | Some y when x.path = y.path && fst x.range = fst y.range -> loop last acc rest
                    | _ -> loop (Some x) (x :: acc) rest
            loop None [] xs
    

        let trace_to_string_short (xs: Trace) =
            let frames = trace_dedup xs |> List.map trace_frame_short
            if frames.IsEmpty then "<no-trace>"
            else
                let top = if frames.Length > 8 then frames |> List.take 8 else frames
                System.String.Join(" <- ", top)
    
        /// ALPHA15: Concise trace string: filename only (no full paths), line:col, max 20 frames

        let trace_to_string_concise (xs: Trace) =
            let frames = trace_dedup xs |> List.map trace_frame_concise
            if frames.IsEmpty then "<no-trace>"
            else
                let maxFrames = 20
                let shown = if frames.Length > maxFrames then frames |> List.take maxFrames else frames
                let body =
                    shown
                    |> List.mapi (fun i s -> sprintf "   %2d: %s" (i + 1) s)
                    |> String.concat "\n"
                if frames.Length > shown.Length then body + sprintf "\n   ... (+%d)" (frames.Length - shown.Length)
                else body
    

        let trace_to_string_full (xs: Trace) =
            let frames = trace_dedup xs |> List.map trace_frame_rust
            if frames.IsEmpty then "<no-trace>"
            else
                let maxFrames = 200
                let shown = if frames.Length > maxFrames then frames |> List.take maxFrames else frames
                let body =
                    shown
                    |> List.mapi (fun i s -> sprintf "  %2d: %s" (i + 1) s)
                    |> String.concat "\n"
                if frames.Length > shown.Length then body + sprintf "\n  ... (%d more)" (frames.Length - shown.Length)
                else body
    

        let inline record_jp_diag (jp_name: string option) (trace: Trace) =
            let name = defaultArg jp_name "<anon>"
            jp_spawn_ctx_set name
            jp_name_counts.AddOrUpdate(name, 1, (fun _ v -> v + 1)) |> ignore
            jp_name_traces.AddOrUpdate(name, trace, (fun _ _ -> trace)) |> ignore
        let inline record_jp_diag_method (key: ConsedNode<RData [] * Ty [] * Ty>) (jp_name: string option) (trace: Trace) =
            DiagSidecar.emit (sprintf "[spiral_compiler] jp.method tag=%d name=%s" key.tag (defaultArg jp_name "<anon>"))
            record_jp_diag jp_name trace
            let name = defaultArg jp_name "<anon>"
            jp_method_key_names.AddOrUpdate(key, name, (fun _ _ -> name)) |> ignore
            jp_method_key_traces.AddOrUpdate(key, trace, (fun _ _ -> trace)) |> ignore
    

        let inline record_jp_diag_type (key: ConsedNode<Ty []>) (trace: Trace) =
            DiagSidecar.emit (sprintf "[spiral_compiler] jp.type tag=%d" key.tag)
            record_jp_diag (Some "<type>") trace
            jp_type_key_traces.AddOrUpdate(key, trace, (fun _ _ -> trace)) |> ignore
    

        let mutable diag_last_ms = 0L
        let mutable diag_last_wait : string = ""
        do DiagLastWait.set ""
    

        let inline get_private_bytes () =
            try
                System.Diagnostics.Process.GetCurrentProcess().PrivateMemorySize64
            with _ -> 0L
    

        let inline diag_specs_total () =
            let mutable total = 0
            for KeyValue(_, (dict, _, _)) in join_point_method do
                let dict = (dict : System.Collections.Concurrent.ConcurrentDictionary<_,_>)
                total <- total + dict.Count
            for KeyValue(_, (dict, _, _)) in join_point_closure do
                let dict = (dict : System.Collections.Concurrent.ConcurrentDictionary<_,_>)
                total <- total + dict.Count
            for KeyValue(_, (dict, _, _)) in join_point_type do
                let dict = (dict : System.Collections.Concurrent.ConcurrentDictionary<_,_>)
                total <- total + dict.Count
            total
    

        let diag_snapshot_impl (reason: string) (include_top_traces: bool) =
    

            let elapsed_ms = peval_sw.ElapsedMilliseconds
            let pb = get_private_bytes ()
            let gc_total = System.GC.GetTotalMemory(false)
            let server_gc =
                try System.Runtime.GCSettings.IsServerGC
                with _ -> false
    

            let mutable method_groups = 0
            let mutable method_specs = 0
            let mutable closure_groups = 0
            let mutable closure_specs = 0
            let mutable type_groups = 0
            let mutable type_specs = 0
            let mutable events_total = 0
            let mutable events_not_set = 0
            // ALPHA48: IVar-based event counting
            for KeyValue(_, (dict, _, _)) in join_point_method do
                let dict = (dict : System.Collections.Concurrent.ConcurrentDictionary<_, Hopac.IVar<_>>)
                method_groups <- method_groups + 1
                method_specs <- method_specs + dict.Count
                for KeyValue(_, ivar) in dict do
                    events_total <- events_total + 1
                    if not (Hopac.IVar.Now.isFull ivar) then events_not_set <- events_not_set + 1
    

            for KeyValue(_, (dict, _, _)) in join_point_closure do
                let dict = (dict : System.Collections.Concurrent.ConcurrentDictionary<_, Hopac.IVar<_>>)
                closure_groups <- closure_groups + 1
                closure_specs <- closure_specs + dict.Count
                for KeyValue(_, ivar) in dict do
                    events_total <- events_total + 1
                    if not (Hopac.IVar.Now.isFull ivar) then events_not_set <- events_not_set + 1
    

            for KeyValue(_, (dict, _, _)) in join_point_type do
                let dict = (dict : System.Collections.Concurrent.ConcurrentDictionary<_,_>)
                type_groups <- type_groups + 1
                type_specs <- type_specs + dict.Count
                for KeyValue(_, cell) in dict do
                    events_total <- events_total + 1
                    let cell = (cell : JPTypeCell<_>)
                    if not (Hopac.IVar.Now.isFull cell.ivar) then events_not_set <- events_not_set + 1
    
    
    



            let entries0 : System.Collections.Generic.KeyValuePair<string,int>[] = jp_name_counts.ToArray()
            let entries = entries0 |> Array.sortByDescending (fun kv -> kv.Value)
    

            let top_names =
                let sbn = System.Text.StringBuilder()
                let n = min 20 entries.Length
                for i = 0 to n - 1 do
                    let kv = entries.[i]
                    let name = kv.Key
                    let count = kv.Value
                    let mutable tr = ""
                    match jp_name_traces.TryGetValue name with
                    | true, t -> tr <- trace_to_string_short t
                    | _ -> ()
                    if i > 0 then sbn.Append("; ") |> ignore
                    if tr <> "" then sbn.AppendFormat("{0}={1} @ {2}", name, count, tr) |> ignore
                    else sbn.AppendFormat("{0}={1}", name, count) |> ignore
                sbn.ToString()
    

            let top_traces =
                if include_top_traces then
                    let sbt = System.Text.StringBuilder()
                    let n = min 5 entries.Length
                    for i = 0 to n - 1 do
                        let kv = entries.[i]
                        let name = kv.Key
                        let count = kv.Value
                        let tr =
                            match jp_name_traces.TryGetValue name with
                            | true, t -> trace_to_string_concise t
                            | _ -> "<no trace>"
                        sbt.AppendFormat("  - {0} ({1})\n{2}\n", name, count, tr) |> ignore
                    sbt.ToString()
                else ""
            let sb = System.Text.StringBuilder()
            sb.AppendLine("SPIRAL PEVAL DIAG") |> ignore
            sb.AppendFormat("  reason={0}", reason) |> ignore; sb.AppendLine() |> ignore
            sb.AppendFormat("  elapsed_ms={0}", elapsed_ms) |> ignore; sb.AppendLine() |> ignore
            sb.AppendFormat("  private_bytes={0}", pb) |> ignore; sb.AppendLine() |> ignore
            sb.AppendFormat("  gc_total_bytes={0}", gc_total) |> ignore; sb.AppendLine() |> ignore
            sb.AppendFormat("  server_gc={0}", server_gc) |> ignore; sb.AppendLine() |> ignore
            sb.AppendFormat("  workers={0} (ProcessorCount={1})", jp_dop, Environment.ProcessorCount) |> ignore; sb.AppendLine() |> ignore
            sb.AppendFormat("  jp_sched_mode={0}", (if jp_use_threadpool then "threadpool" else "custom")) |> ignore; sb.AppendLine() |> ignore
            sb.AppendFormat("  jp_parallel_enabled={0} jp_parallel_effective={1} jp_sequential_requested={2} jp_wait_closed={3}", jp_parallel_enabled, (jp_parallel_effective()), CacheGeneration.isSequentialRequested (), jp_wait_closed) |> ignore; sb.AppendLine() |> ignore
            sb.AppendFormat("  jp_total_started={0}", jp_total_started) |> ignore; sb.AppendLine() |> ignore
            // ALPHA48: Hopac-based metrics (no custom thread pool)
            sb.AppendFormat("  pending_jobs={0} hopac_scheduler=active", jp_pending_jobs ()) |> ignore; sb.AppendLine() |> ignore
            sb.AppendFormat("  jp_method_groups={0} jp_method_specs={1}", method_groups, method_specs) |> ignore; sb.AppendLine() |> ignore
            sb.AppendFormat("  jp_closure_groups={0} jp_closure_specs={1}", closure_groups, closure_specs) |> ignore; sb.AppendLine() |> ignore
            sb.AppendFormat("  jp_type_groups={0} jp_type_specs={1}", type_groups, type_specs) |> ignore; sb.AppendLine() |> ignore
            sb.AppendFormat("  jp_events_total={0} jp_events_not_set={1}", events_total, events_not_set) |> ignore; sb.AppendLine() |> ignore
            sb.AppendFormat("  cache_generation={0}", CacheGeneration.current ()) |> ignore; sb.AppendLine() |> ignore
            sb.AppendFormat("  suspect_keys={0}", SuspectCache.currentCount ()) |> ignore; sb.AppendLine() |> ignore
            sb.AppendFormat("  bitmamba={0}", BitMamba.getSummary ()) |> ignore; sb.AppendLine() |> ignore
            sb.AppendFormat("  loopguard={0}", LoopSpecializationGuard.getSummary ()) |> ignore; sb.AppendLine() |> ignore
            let reasons =
                try CacheGeneration.getRecentReasons () |> List.truncate 5 |> String.concat " | "
                with _ -> ""
            if reasons <> "" then
                sb.AppendFormat("  cache_invalidation_reasons={0}", reasons) |> ignore; sb.AppendLine() |> ignore
            sb.AppendFormat("  last_wait={0}", diag_last_wait) |> ignore; sb.AppendLine() |> ignore
            sb.AppendFormat("  top_jp_names={0}", top_names) |> ignore; sb.AppendLine() |> ignore
            if include_top_traces then
                sb.AppendLine("  top_jp_traces=") |> ignore
                if top_traces <> "" then sb.AppendLine(top_traces) |> ignore
            sb.ToString()

        let diag_snapshot (reason: string) = diag_snapshot_impl reason jp_diag_include_top_traces
        let diag_snapshot_full (reason: string) = diag_snapshot_impl reason true

    
    


        let diag_snapshot_short (reason: string) =
            // alpha146: single-line, bounded diagnostic string for stderr / exceptions.
            // Full snapshot is captured via DiagSidecar when force/verbose triggers.
            let elapsed_ms = peval_sw.ElapsedMilliseconds
            let pb = try System.Diagnostics.Process.GetCurrentProcess().PrivateMemorySize64 with _ -> 0L
            let gc_total = try GC.GetTotalMemory(false) with _ -> 0L
            let gen = CacheGeneration.current()
            let pend = jp_pending_jobs ()
            let seq = CacheGeneration.isSequentialRequested ()
            let jpExtra0 = try jp_extra_provider () with _ -> ""
            let jpExtra =
                if System.String.IsNullOrEmpty jpExtra0 then ""
                else " " + (jpExtra0.Replace("\r", " ").Replace("\n", " "))
            sprintf "DIAG reason=%s elapsed_ms=%d gen=%d pending=%d seq=%b private_bytes=%d gc_total_bytes=%d last_wait=%s%s"
                reason elapsed_ms gen pend seq pb gc_total diag_last_wait jpExtra
        let diag_write_err (s: string) =
            // alpha149: helper used by diag_print; keep it single-line and resilient.
            if not (System.String.IsNullOrEmpty s) then
                let s = s.Replace("\r", " ").Replace("\n", " ")
                try Console.Error.WriteLine(s) with _ -> ()


        let diag_print (force: bool) (reason: string) =
            let now = peval_sw.ElapsedMilliseconds
            if force || (diag_period_ms > 0L && now - diag_last_ms >= diag_period_ms) then
                diag_last_ms <- now
                if force || jp_diag_verbose then
                    let snap_full = diag_snapshot reason
                    let _ = diag_write_file ("diag_" + reason) snap_full
                    DiagSidecar.emit snap_full
                    diag_write_err (diag_snapshot_short reason)
                else
                    let snap = diag_snapshot_short reason
                    DiagSidecar.emit snap
                    diag_write_err snap
        let inline get_private_mb () =
            int64 (System.Diagnostics.Process.GetCurrentProcess().PrivateMemorySize64 / 1024L / 1024L)
    

        let inline peval_abort (reason: string) =
            diag_print true reason
            let full = diag_snapshot_full reason
            let diag_file = diag_write_file ("peval_abort_" + reason) full
            match diag_file with
            | Some p -> DiagSidecar.emit ("diag_file=" + p)
            | None -> ()
            if jp_diag_stderr_full then
                lock diag_console_lock (fun () ->
                    try Console.Error.WriteLine(full) with _ -> ())
            let short = diag_snapshot_short reason
            let msg =
                match diag_file with
                | Some p -> short + " diag_file=" + p
                | None -> short
            raise (System.Exception(msg))
    

        let diag_soft_abort (where: string) (reason: string) =
            // v101: do not disable parallelism on soft diagnostic triggers; keep full concurrency and just emit snapshots.
            let r = sprintf "soft_abort where=%s reason=%s" where reason
            DiagSidecar.emit ("SPIRAL PEVAL DIAG " + r)
            diag_print true r
    

        let diag_abort_if_needed (where: string) =
            let now = peval_sw.ElapsedMilliseconds
            // Legacy watchdog variables (optional). These remain hard aborts.
            if peval_abort_ms > 0L && now >= peval_abort_ms then
                diag_last_wait <- where
                DiagLastWait.set diag_last_wait
                peval_abort (sprintf "Timed out (ms=%d)" peval_abort_ms)
            if peval_mem_limit_mb > 0L then
                let mb = get_private_mb ()
                if mb >= peval_mem_limit_mb then
                    diag_last_wait <- where
                    DiagLastWait.set diag_last_wait
                    peval_abort (sprintf "Memory limit reached (limit_mb=%d, private_mb=%d)" peval_mem_limit_mb mb)
    

            // Diagnostic aborts. Soft by default: disable parallel join-points and keep going.
            if diag_abort_armed then
                if diag_abort_ms > 0L && now >= diag_abort_ms then
                    diag_last_wait <- where
                    DiagLastWait.set diag_last_wait
                    if jp_diag_hard_abort then
                        peval_abort (sprintf "Timed out (ms=%d)" diag_abort_ms)
                    else
                        diag_abort_armed <- false
                        diag_soft_abort where (sprintf "Timed out (ms=%d)" diag_abort_ms)
    

                if diag_jp_spec_cap > 0L then
                    let total = diag_specs_total () |> int64
                    if total >= diag_jp_spec_cap then
                        diag_last_wait <- where
                        DiagLastWait.set diag_last_wait
                        if jp_diag_hard_abort then
                            peval_abort (sprintf "Join-point spec cap exceeded (cap=%d, total=%d)" diag_jp_spec_cap total)
                        else
                            diag_abort_armed <- false
                            diag_soft_abort where (sprintf "Join-point spec cap exceeded. cap=%d total=%d" diag_jp_spec_cap total)
    

                if diag_jp_name_spec_cap > 0L then
                    for KeyValue(name, count) in jp_name_counts do
                        if int64 count >= diag_jp_name_spec_cap then
                            diag_last_wait <- where
                            DiagLastWait.set diag_last_wait
                            if jp_diag_hard_abort then
                                peval_abort (sprintf "Join-point name cap exceeded (cap=%d, name=%s, count=%d)" diag_jp_name_spec_cap name count)
                            else
                                diag_abort_armed <- false
                                diag_soft_abort where (sprintf "Join-point name cap exceeded. cap=%d name=%s count=%d" diag_jp_name_spec_cap name count)
    

        // ════════════════════════════════════════════════════════════════════════
        // ALPHA48: HOPAC IVAR-BASED WAITING
        // ════════════════════════════════════════════════════════════════════════
        // This replaces ManualResetEventSlim blocking with cooperative Hopac waiting.
        // The key insight: we run IVar.read synchronously on the calling thread but
        // with periodic yields to allow Hopac scheduler to make progress.
    

        let inline hopac_tick () =
            // Hopac's API differs across versions; if there is no explicit 'tick',
            // do a very light yield to avoid starvation while we're spinning.
            System.Threading.Thread.Yield() |> ignore
    

        /// Wait for an IVar to be filled, with cooperative yielding and diagnostics.
        /// This is the Hopac equivalent of the old jp_ev_wait.
        let jp_ivar_wait (w: string) (details: string) (ivar: Hopac.IVar<'a>) : 'a =
            diag_last_wait <- if System.String.IsNullOrEmpty details then w else w + " :: " + details
            DiagLastWait.set diag_last_wait
            let mutable gen0 = CacheGeneration.current()
            let wait_start_ms = peval_sw.ElapsedMilliseconds
    

            // Fast path: IVar already filled
            if Hopac.IVar.Now.isFull ivar then
                jp_throw_if_any ()
                Hopac.IVar.Now.get ivar
            else
                let mutable spin = System.Threading.SpinWait()
                let mutable last_diag = peval_sw.ElapsedMilliseconds
                let mutable last_progress_ms = System.Threading.Interlocked.Read(&jp_last_progress_ms)
                if last_progress_ms = 0L then last_progress_ms <- peval_sw.ElapsedMilliseconds
    
                // Alpha43: in forced sequential mode, do not wait indefinitely; treat long waits as stall.

                let stall_abort_ms =
                    let base_abort_ms =
                        if CacheGeneration.isSequentialRequested() then min jp_stall_abort_ms 15000L else jp_stall_abort_ms
                    if w = "JPType.wait" then min base_abort_ms 15000L
                    elif w = "JPMethod.wait" then min base_abort_ms 20000L
                    else base_abort_ms
    
    


                let mutable pending_fixup_done = false
                let mutable cd_seen = lock jp_barrier_lock (fun () -> jp_cd)

                // Spin-wait with periodic Hopac scheduler yielding
                while not (Hopac.IVar.Now.isFull ivar) do
                    let curGen = CacheGeneration.current()
                    if curGen <> gen0 then
                        let snap = diag_snapshot (sprintf "gen_change jp_ivar_wait from=%d to=%d :: %s (%s)" gen0 curGen w details)
                        let msg =
                            sprintf "[spiral_compiler] EJP0008: generation changed while waiting for jp_ivar_wait (from %d to %d) :: %s (%s)\n%s" gen0 curGen w details snap
                        DiagSidecar.emit msg
                        CacheGeneration.requestSequential ()
                        raise (PartEvalTypeError([], sprintf "[spiral_compiler] EJP0008: generation changed while waiting for jp_ivar_wait (from %d to %d) :: %s (%s)" gen0 curGen w details))
    

                    // ALPHA100: reconcile pending leak (pend>0, queue empty, cd at base=1) before dead-ivar/stall logic.

                    // This can happen after CacheGeneration invalidation swaps the CountdownEvent, leaving jp_pending_count stale.
                    let cd_now = lock jp_barrier_lock (fun () -> jp_cd)
                    if not (obj.ReferenceEquals(cd_seen, cd_now)) then
                        cd_seen <- cd_now
                        pending_fixup_done <- false
                    if jp_work_q.Count = 0 then
                        let cc = cd_seen.CurrentCount
                        if cc = 1 then
                            let pend_now = System.Threading.Interlocked.Read(&jp_pending_count)
                            if pend_now > 0L && not pending_fixup_done then
                                pending_fixup_done <- true
                                let old_pend = System.Threading.Interlocked.Exchange(&jp_pending_count, 0L)
                                let enq_total = System.Threading.Interlocked.Read(&jp_total_enqueued)
                                ignore (System.Threading.Interlocked.Exchange(&jp_total_done, enq_total))
                                DiagSidecar.emit (sprintf "[spiral_compiler] EJP0021: reconciled pending leak in jp_ivar_wait old=%d enq=%d gen=%d" old_pend enq_total gen0)
                            lock jp_barrier_lock (fun () ->
                                if not (obj.ReferenceEquals(jp_wait_closed_cd, cd_seen)) then
                                    jp_wait_closed_cd <- cd_seen
                                    jp_wait_closed <- true
                            )
                            try if cd_seen.CurrentCount > 0 then ignore (cd_seen.Signal()) with _ -> ()

                    // ALPHA111: Detect \"dead\" IVars (no pending JP work can ever fill this IVar).
                    // This typically happens when a stale/aborted JP work item decremented counters but never filled its IVar.
                    // Instead of hanging, force a deterministic retry (and request sequential as a safety net).
                    let now_dead = peval_sw.ElapsedMilliseconds
                    if now_dead - wait_start_ms > 200L then
                        let pend0 = System.Threading.Interlocked.Read(&jp_pending_count)
                        if pend0 = 0L then
                            let q0 = jp_work_q.Count
                            let cd0 = lock jp_barrier_lock (fun () -> jp_cd.CurrentCount)
                            if q0 = 0 && cd0 <= 1 && not (Hopac.IVar.Now.isFull ivar) then
                                let snap = diag_snapshot (sprintf "dead_ivar jp_ivar_wait :: %s (%s)" w details)
                                DiagSidecar.emit snap
                                CacheGeneration.requestSequential()
                                CacheGeneration.invalidate(sprintf "dead ivar jp_ivar_wait :: %s (%s)" w details) |> ignore
                                raise (PartEvalTypeError([], sprintf "[spiral_compiler] EJP0016: dead ivar while waiting for jp_ivar_wait (pend=0 q=0 cd=%d) :: %s (%s)" cd0 w details))
                    // ALPHA108: cooperative work-stealing + fast exn propagation while waiting for IVar.
                    // This prevents deadlocks when all JP workers are blocked and the waiter is the only runnable thread.
                    jp_throw_if_any ()
                    let mutable ran = 0
                    let mutable work = Unchecked.defaultof<unit -> unit>
                    while ran < 64 && jp_work_q.TryDequeue(&work) do
                        ran <- ran + 1
                        try work() with e -> jp_exns.Enqueue(capture_edi e)
                    if ran > 0 then
                        System.Threading.Interlocked.Exchange(&jp_last_progress_ms, peval_sw.ElapsedMilliseconds) |> ignore
    

                    // Yield to Hopac scheduler periodically to allow other fibers to run
                    if (spin.Count &&& 255) = 0 then
                        // Run a micro-batch of Hopac work
                        hopac_tick ()
    

                    // Periodic diagnostic tick
                    let now = peval_sw.ElapsedMilliseconds
                    let active = System.Threading.Interlocked.Read(&jp_worker_active)
                    let lp = System.Threading.Interlocked.Read(&jp_last_progress_ms)
                    if lp > 0L && lp > last_progress_ms then last_progress_ms <- lp
                    if diag_period_ms > 0L && now - last_diag >= diag_period_ms then
                        last_diag <- now
                        diag_print false "tick/jp_ivar_wait"
                    diag_abort_if_needed "jp_ivar_wait"
    
                    // Stall detection (Alpha98): base timer prevents "progress tick" spoofing

                    let jp_stall_idle_abort_ms = stall_abort_ms // alpha155: alinhar o idle abort ao abort_ms (evita falso positivo aos 8s)
                    let base_wait_ms = now - wait_start_ms
                    let idle_ms = now - last_progress_ms
                    if stall_abort_ms > 0L && base_wait_ms >= stall_abort_ms && idle_ms >= jp_stall_idle_abort_ms then
                        let snap = diag_snapshot (sprintf "stall jp_ivar_wait idle_ms=%d base_wait_ms=%d :: %s (%s)" idle_ms base_wait_ms w details)
                        DiagSidecar.emit snap
                        try
                            CacheGeneration.requestSequential ()
                            () // alpha284: stall is a scheduling failure; do not invalidate generation here (prevents WRITE_ABORT storms).
                        with _ -> ()
                        let short = diag_snapshot_short (sprintf "EJP0014 stall jp_ivar_wait idle_ms=%d base_wait_ms=%d" idle_ms base_wait_ms)
                        raise (PartEvalTypeError([], sprintf "[spiral_compiler] EJP0014: join-point scheduler stalled while waiting for jp_ivar_wait (idle_ms=%d base_wait_ms=%d abort_ms=%d) :: %s (%s) ⏎ %s" idle_ms base_wait_ms stall_abort_ms w details short))
    

                    spin.SpinOnce()
                    if (spin.Count &&& 4095) = 0 then
                        Progress88.tick0 (sprintf "wait:%s" w)
                        System.Threading.Thread.Yield() |> ignore
                        // [HOPAC-176-001] Cooperative backoff to reduce busy-wait pressure under stalls.
                        if spin.Count > 200000 then System.Threading.Thread.Sleep(1)
    

                jp_throw_if_any ()
                // ALPHA45: Final generation check - ensure result wasn't filled by stale computation
                let finalGen = CacheGeneration.current()
                if finalGen <> gen0 then
                    let snap = diag_snapshot (sprintf "gen_change_after_fill jp_ivar_wait from=%d to=%d :: %s (%s)" gen0 finalGen w details)
                    let msg =
                        sprintf "[spiral_compiler] EJP0008: generation changed while waiting for jp_ivar_wait (from %d to %d) [after_fill] :: %s (%s)" gen0 finalGen w details
                    DiagSidecar.emit (msg + "\n" + snap)
                    CacheGeneration.requestSequential ()
                    raise (PartEvalTypeError([], msg))
                Hopac.IVar.Now.get ivar
    

    
        // Alpha88: surface JP scheduler counters in heartbeat without touching hot paths.


        let jp_extra_provider_impl () : string =
            try
                let now = peval_sw.ElapsedMilliseconds
                let q = jp_work_q.Count
                let pend = System.Threading.Interlocked.Read(&jp_pending_count)
                let cd = lock jp_barrier_lock (fun () -> jp_cd.CurrentCount)
                let cdRem = max 0L (int64 cd - 1L)
                let active = System.Threading.Interlocked.Read(&jp_worker_active)
                let doneCount = System.Threading.Interlocked.Read(&jp_total_done)
                let enq = System.Threading.Interlocked.Read(&jp_total_enqueued)
                let frozen = System.Threading.Interlocked.Read(&jp_sub_total_frozen)
                let lastProg = System.Threading.Interlocked.Read(&jp_last_progress_ms)
                let progAge = if lastProg = 0L then -1L else let d = now - lastProg in if d < 0L then 0L else d
                let rem = max 0L (max active (max pend cdRem))
                let denom = max (if frozen > 0L then frozen else enq) (doneCount + rem)
                let pct = if denom > 0L then (100.0 * float doneCount / float denom) else 0.0
                let jobs = jp_active_jobs.Count
                let activeAge =
                    if jobs = 0 then -1L else
                        let mutable minStart = System.Int64.MaxValue
                        for KeyValue(_, start) in jp_active_jobs do
                            if start < minStart then minStart <- start
                        if minStart = System.Int64.MaxValue then -1L else
                            let d = now - minStart
                            if d < 0L then 0L else d
                let seq = if CacheGeneration.isSequentialRequested() then 1 else 0
                let inv = CacheGeneration.invalidationCount()
                let stallWarn = 30000L
                let stalled =
                    rem > 0L
                    && progAge >= stallWarn
                    && ((active = 0L) || (activeAge >= stallWarn && jobs > 0))
                sprintf "jp[q=%d rem=%A act=%A done=%A/%A (%.2f%%) age=%dms run=%dms jobs=%d stall=%d seq=%d inv=%d]" q rem active doneCount denom pct progAge activeAge jobs (if stalled then 1 else 0) seq inv
            with _ -> ""
        do jp_extra_provider <- jp_extra_provider_impl
        do Progress88.set_extra_provider (fun () ->
            try
                let now = peval_sw.ElapsedMilliseconds
                let q = jp_work_q.Count
                let pend = System.Threading.Interlocked.Read(&jp_pending_count)
                let cd = lock jp_barrier_lock (fun () -> jp_cd.CurrentCount)
                let cdRem = max 0L (int64 cd - 1L)
                let active = System.Threading.Interlocked.Read(&jp_worker_active)
                let doneCount = System.Threading.Interlocked.Read(&jp_total_done)
                let enq = System.Threading.Interlocked.Read(&jp_total_enqueued)
                let frozen = System.Threading.Interlocked.Read(&jp_sub_total_frozen)
                let lastProg = System.Threading.Interlocked.Read(&jp_last_progress_ms)
                let progAge = if lastProg = 0L then -1L else let d = now - lastProg in if d < 0L then 0L else d
                let rem = max 0L (max active (max pend cdRem))
                let denom = max (if frozen > 0L then frozen else enq) (doneCount + rem)
                let pct = if denom > 0L then (100.0 * float doneCount / float denom) else 0.0
                let jobs = jp_active_jobs.Count
                let activeAge =
                    if jobs = 0 then -1L else
                        let mutable minStart = System.Int64.MaxValue
                        for KeyValue(_, start) in jp_active_jobs do
                            if start < minStart then minStart <- start
                        if minStart = System.Int64.MaxValue then -1L else
                            let d = now - minStart
                            if d < 0L then 0L else d
                let seq = if CacheGeneration.isSequentialRequested() then 1 else 0
                let inv = CacheGeneration.invalidationCount()
                let stallWarn = 30000L
                let stalled =
                    rem > 0L
                    && progAge >= stallWarn
                    && ((active = 0L) || (activeAge >= stallWarn && jobs > 0))
                sprintf "jp[q=%d rem=%A act=%A done=%A/%A (%.2f%%) age=%dms run=%dms jobs=%d stall=%d seq=%d inv=%d]" q rem active doneCount denom pct progAge activeAge jobs (if stalled then 1 else 0) seq inv
            with _ -> ""
        )

        
        // Alpha121/197: optional ANSI panel UI for debugging JP stalls/races.

        // Keep it cheap: this runs only on the 4s heartbeat thread.
        let jp_panel_provider () : string =
            try
                let now = peval_sw.ElapsedMilliseconds
                let seq = if CacheGeneration.isSequentialRequested() then 1 else 0
                let gen = CacheGeneration.current()
                let inv = CacheGeneration.invalidationCount()
                let reasons = CacheGeneration.reasonsSnapshot 1
                let reason1 = match reasons with | h :: _ -> h | _ -> ""
                let jobs = jp_active_jobs.ToArray()
                let top =
                    jobs
                    |> Array.map (fun kv ->
                        let id = kv.Key
                        let start = kv.Value
                        let age = let d = now - start in if d < 0L then 0L else d
                        (age, id))
                    |> Array.sortWith (fun (a,_) (b,_) -> compare b a)
                    |> (fun a -> if a.Length > 3 then a.[0..2] else a)
                let sb = System.Text.StringBuilder()
                sb.AppendFormat("jp.panel seq={0} gen={1} inv={2}", seq, gen, inv) |> ignore
                if reason1 <> "" then
                    sb.AppendLine() |> ignore
                    sb.Append("invalidate: ") |> ignore
                    sb.Append(reason1) |> ignore
                if top.Length > 0 then
                    sb.AppendLine() |> ignore
                    sb.Append("slow jobs (age ms):") |> ignore
                    for (age, id) in top do
                        sb.AppendLine() |> ignore
                        let mutable nm = Unchecked.defaultof<string>
                        let nm = if jp_active_job_names.TryGetValue(id, &nm) then nm else ""
                        let nm =
                            if System.String.IsNullOrEmpty nm then ""
                            elif nm.Length > 60 then nm.Substring(0,57) + "..."
                            else nm
                        sb.AppendFormat("  #{0} age={1} {2}", id, age, nm) |> ignore
                let worklistPanel = EvalWorklist.panel()
                if not (System.String.IsNullOrWhiteSpace worklistPanel) then
                    sb.AppendLine() |> ignore
                    sb.Append(worklistPanel) |> ignore
                sb.ToString().TrimEnd()
            with _ -> ""

        // Alpha217: richer stall diagnostics (append-only). Capture more than the 3-line jp.panel summary.
        let jp_slow_jobs_snapshot (maxn: int) : string list =
            try
                if maxn <= 0 then [] else
                let now = peval_sw.ElapsedMilliseconds
                let jobs = jp_active_jobs.ToArray()
                let top =
                    jobs
                    |> Array.map (fun kv ->
                        let id = kv.Key
                        let start = kv.Value
                        let age = let d = now - start in if d < 0L then 0L else d
                        (age, id))
                    |> Array.sortWith (fun (a,_) (b,_) -> compare b a)
                    |> (fun a -> if a.Length > maxn then a.[0..maxn-1] else a)
                top
                |> Array.map (fun (age, id) ->
                    let mutable nm = Unchecked.defaultof<string>
                    let nm = if jp_active_job_names.TryGetValue(id, &nm) then nm else ""
                    let nm =
                        if System.String.IsNullOrEmpty nm then ""
                        elif nm.Length > 140 then nm.Substring(0,137) + "..."
                        else nm
                    sprintf "  #%d age=%dms %s" id age nm)
                |> Array.toList
            with _ -> []
        do Progress88.set_panel_provider jp_panel_provider

        // Alpha43: cache invalidation should also shed stale queued JP work, otherwise
        // we can accumulate thousands of specs and then hit EJP0008 while waiting.
        do CacheGeneration.registerOnInvalidate (fun reason ->
            try
                // Drain *and execute* stale queued JP work so their finally blocks run
                // (decrement pending_count + Signal the captured CountdownEvent).
                // Dropping work without executing leads to mismatched counters and hangs.
                let mutable drained = 0
                let mutable work = Unchecked.defaultof<unit -> unit>
                while jp_work_q.TryDequeue(&work) do
                    drained <- drained + 1
                    try work() with e -> jp_exns.Enqueue(capture_edi e)
                if drained > 0 then DiagSidecar.emit (sprintf "JPWorkQ.invalidate: drained_and_canceled=%d reason=%s" drained reason)

                // Best-effort: clear per-name traces so next generation does not inherit loop hot-spots.
                try jp_name_counts.Clear() with _ -> ()
                try jp_mismatch_counts.Clear() with _ -> ()
                try jp_name_traces.Clear() with _ -> ()

                // alpha209: jp_active_jobs is diagnostic-only; clear to avoid leak across generations when workers are canceled.
                // (We prefer losing a few in-flight entries over unbounded growth across retries.)
                try jp_active_jobs.Clear() with _ -> ()
                try jp_active_job_names.Clear() with _ -> ()

                // Reset progress timestamps to avoid negative ages after fast retries.
                let now = peval_sw.ElapsedMilliseconds
                System.Threading.Interlocked.Exchange(&jp_last_progress_ms, peval_sw.ElapsedMilliseconds) |> ignore
                System.Threading.Interlocked.Exchange(&jp_last_enq_ms, now) |> ignore
                System.Threading.Interlocked.Exchange(&jp_sub_total_frozen, 0L) |> ignore

                // ALPHA45+: Swap CountdownEvent for clean retry.
                // Important: do NOT mutate the current instance counts while in-flight work may still Signal().
                // Instead, replace the instance; jp_start/jp_wait capture the instance they increment/wait on.
                lock jp_barrier_lock (fun () ->
                    try
                        // [JP-CD-208-001] Close previous CountdownEvent to unblock any stale waiters (invalidate implies cancel).
                        let old_cd = jp_cd
                        let cc0 = try old_cd.CurrentCount with _ -> 0
                        if cc0 > 0 then
                            try ignore (old_cd.Signal(cc0)) with _ -> ()
                

                        jp_wait_closed <- false
                        jp_wait_closed_cd <- null
                        jp_cd <- new System.Threading.CountdownEvent(1)
                    with _ -> ()
                )
                // [JP-INT-210-001] Poke main thread so any Wait/Sleep/Join can observe invalidation promptly.
                // [JP-INT-211-001] Disabled: Thread.Interrupt causes fatal BigStack Join interruptions (see 210.txt).
                ()
            with _ -> ()
        )
    
    
    



        // ════════════════════════════════════════════════════════════════════════
        // 
        //
        // v122: In sequential fallback we still run the JP scheduler, but we serialize dequeue+exec via a gate.
        let jp_seq_gate = obj()

        let inline jp_seq_lock (f: unit -> 'a) : 'a =
            if CacheGeneration.isSequentialRequested() then lock jp_seq_gate (fun () -> f())
            else f()

        // ALPHA12 SOTA: HOPAC WORK QUEUE WITH WORK-STEALING
        // ════════════════════════════════════════════════════════════════════════
        // Key architectural improvement: jp_wait_closed is now ONLY used for
        // diagnostics and does NOT prevent new work from being scheduled.
        // Parallelism is always enabled; work is throttled via backpressure only.
        

        let jp_cancel = new System.Threading.CancellationTokenSource()
        

        // Progress tracking for stall detection
        let mutable jp_last_progress_ms_local = 0L
        let mutable jp_last_done_local = -1L
        let mutable jp_last_den_local = -1L
        let mutable jp_last_rem_local = -1L
        let jp_note_progress () =
            // [JP-WD-204-001] Always rethrow cooperative-abort exceptions on the main thread.
            jp_throw_if_any()
            let now = peval_sw.ElapsedMilliseconds
            // v132-alpha190: Only bump last_progress_ms on *real* progress changes, so `age=` reflects stalls.
            if System.Threading.Interlocked.Exchange(&jp_progress_started, 1) = 0 then
                Progress88.stage 2 4
                jp_last_progress_ms_local <- now
                System.Threading.Interlocked.Exchange(&jp_last_progress_ms, now) |> ignore

            let enq_now = System.Threading.Interlocked.Read(&jp_total_enqueued)
            let enq_last = System.Threading.Interlocked.Read(&jp_last_enq_ms)
            let enq_age = if enq_last = 0L then -1L else now - enq_last
            let frozen = System.Threading.Interlocked.Read(&jp_sub_total_frozen)
            let enq_for_pct =
                if frozen > 0L then frozen
                elif enq_now > 0L && enq_age >= 2000L then
                    System.Threading.Interlocked.CompareExchange(&jp_sub_total_frozen, enq_now, 0L) |> ignore
                    enq_now
                else enq_now
            let doneCount = System.Threading.Interlocked.Read(&jp_total_done)
            let pendNow = System.Threading.Interlocked.Read(&jp_pending_count)
            let cdRem =
                lock jp_barrier_lock (fun () ->
                    try max 0L (int64 jp_cd.CurrentCount - 1L) with _ -> 0L)
            let activeNow = System.Threading.Interlocked.Read(&jp_worker_active)
            let rem = max 0L (max activeNow (max pendNow cdRem))
            let den1 = max enq_for_pct (doneCount + rem)

            let changed =
                doneCount <> jp_last_done_local
                || den1 <> jp_last_den_local
                || rem <> jp_last_rem_local

            if changed then
                jp_last_done_local <- doneCount
                jp_last_den_local <- den1
                jp_last_rem_local <- rem
                jp_last_progress_ms_local <- now
                System.Threading.Interlocked.Exchange(&jp_last_progress_ms, now) |> ignore

            Progress88.sub doneCount (max 1L den1)
            Progress88.pulse "jp_note_progress" (CacheGeneration.current())
        

        // Work-stealing helper: drains queue in batches
        let jp_help_batch (max_n: int) : int =
            jp_seq_lock (fun () ->
                let mutable ran = 0
                let mutable work = Unchecked.defaultof<unit -> unit>
                while ran < max_n && jp_work_q.TryDequeue(&work) do
                    ran <- ran + 1
                    try work() with e -> jp_exns.Enqueue(capture_edi e)
                if ran > 0 then jp_note_progress ()
                ran
            )
        // Hopac worker fibers

        let mutable jp_workers_started = false
        let jp_workers_started_sync = obj()
        
