                                                                    if cc0 > 0 then
                                                                        try ignore (cd0.Signal(cc0)) with _ -> ()
                                                                    jp_exns.Enqueue(capture_edi (PartEvalTypeError([], msg)))
                                                                    // [JP-INT-211-001] Disabled: Thread.Interrupt causes fatal BigStack Join interruptions (see 210.txt).
                                                                    ()
                                                                with _ -> ()
                                        with _ -> ()
                                with _ -> ()
                            with _ -> ()
                        let th =
                            let start = System.Threading.ThreadStart(thread_body)
                            new System.Threading.Thread(start)
                        th.IsBackground <- true
                        th.Start()
                )

        // ALPHA16: Signal workers to shut down gracefully
        let jp_shutdown_workers () =
            jp_workers_shutdown <- true
            // Release semaphore to unblock any waiting workers
            try for _ in 1 .. (jp_dop * 8 + 16) do ignore (jp_work_sem.Release()) with _ -> ()
        

        let start_jp_workers () =
            if not jp_workers_started then
                lock jp_workers_started_sync (fun () ->
                    if not jp_workers_started then
                        jp_workers_started <- true
    
                        // ALPHA9: Dedicated OS threads (not Hopac fibers) so blocking waits do not starve the Hopac scheduler.

                        let worker (i: int) =
                            let th =
                                new System.Threading.Thread(System.Threading.ThreadStart(fun () ->
                                    let t = System.Threading.Thread.CurrentThread
                                    if isNull t.Name then t.Name <- sprintf "jp-worker-%d" i
