                                // promote this to BuildFile.replay_root_complete yet; clear the local fuse and
                                // let the waiter keep draining the outstanding JP work.
                                DiagJson.emit (
                                    sprintf "{\"kind\":\"eval_worklist_jp_wait_root_complete_pending_jobs_deferred\",\"event\":\"jp_wait_cycle_preflight\",\"status\":\"semantic_root_complete\",\"pending\":%d,\"enqueued\":%d,\"done\":%d,\"current_count\":%d,\"single_flight\":1,\"next\":\"continue_wait_for_jp_bodies\"}"
                                        pending_root_now enq_root_now done_root_now cc_root_now)
                                try TermCycleFuse.reset() with _ -> ()
                        elif frame.status = "semantic_root_complete" then
                            // ALPHA397/478: only close the local JP barrier when there are no outstanding
                            // JP body jobs.  This preserves the replay-root writer witness without allowing
                            // premature codegen placeholders to shrink existing generated files.
                            DiagJson.emit (
                                sprintf "{\"kind\":\"eval_worklist_resume\",\"event\":\"jp_wait_cycle_preflight\",\"status\":\"semantic_root_complete\",\"policy\":\"jp_wait_root_complete_barrier_closed_no_pending_jp_bodies\",\"pending\":%d,\"enqueued\":%d,\"done\":%d,\"current_count\":%d,\"single_flight\":1,\"next\":\"attempt_build\"}"
                                    pending_root_now enq_root_now done_root_now cc_root_now)
                            try
                                CacheGeneration.noteReason "BuildFile.replay_root_complete code=[spiral_compiler] EJP0011 source=jp_wait_cycle_preflight/no_pending_jp_bodies"
                                DiagJson.emit (
                                    sprintf "{\"kind\":\"eval_worklist_jp_wait_replay_root_reason_recorded\",\"event\":\"jp_wait_cycle_preflight\",\"status\":\"semantic_root_complete\",\"pending\":%d,\"enqueued\":%d,\"done\":%d,\"single_flight\":1,\"next\":\"attempt_build\"}"
                                        pending_root_now enq_root_now done_root_now)
                            with _ -> ()
                            try
                                ignore (System.Threading.Interlocked.Exchange(&jp_pending_count, 0L))
                                let enq_total = System.Threading.Interlocked.Read(&jp_total_enqueued)
                                ignore (System.Threading.Interlocked.Exchange(&jp_total_done, enq_total))
                                lock jp_barrier_lock (fun () ->
                                    if not (obj.ReferenceEquals(jp_wait_closed_cd, cd)) then
                                        jp_wait_closed_cd <- cd
                                        jp_wait_closed <- true)
                                let cc0 = cd.CurrentCount
                                if cc0 > 0 then
                                    try ignore (cd.Signal(cc0)) with _ -> ()
                                DiagJson.emit (
                                    sprintf "{\"kind\":\"eval_worklist_jp_wait_close\",\"event\":\"jp_wait_cycle_preflight\",\"status\":\"semantic_root_complete\",\"closed_count\":%d,\"pending\":%d,\"enqueued\":%d,\"done\":%d,\"single_flight\":1,\"next\":\"attempt_build\"}"
                                        cc0 pending_root_now enq_root_now done_root_now)
                            with _ -> ()
                        elif (frame.status = "continuation_envelope" || frame.status = "tracing_explicit_loop") && EvalWorklist.frameHasSemanticEvidence frame && not (EvalWorklist.hasReplayComplete()) then
                            // ALPHA913: the alpha912 runtime reached a live continuation envelope after
                            // the cycle preflight drain.  Raising EJP0011 here is too early: the frame
                            // already carries a typed replay payload and next=schedule_term_ty_replay, so
                            // the waiter should yield the tripped fuse and allow the queued/implicit replay
                            // path to make forward progress.  This is structural evidence only; no source
                            // file or line is part of the policy.
                            let frameShapeForDiag =
                                match frame.semanticCell with
                                | Some cell -> cell.shape
                                | None -> frame.kind
                            let frameNextForDiag = "schedule_term_ty_replay"
                            DiagJson.emit (
                                sprintf "{\"kind\":\"eval_worklist_jp_cycle_live_replay_deferred\",\"event\":\"jp_wait_cycle_preflight\",\"status\":%s,\"shape\":%s,\"pending\":%d,\"enqueued\":%d,\"done\":%d,\"current_count\":%d,\"queue_depth\":%d,\"single_flight\":1,\"next\":%s}"
                                    (DiagJson.esc frame.status) (DiagJson.esc frameShapeForDiag) pending_root_now enq_root_now done_root_now cc_root_now (EvalWorklist.replayQueueDepth()) (DiagJson.esc frameNextForDiag))
                            try TermCycleFuse.reset() with _ -> ()
                            try System.Threading.Thread.Yield() |> ignore with _ -> ()
                        else
                            let msg = sprintf "[spiral_compiler] EJP0011: jp_wait observed sequential term-cycle fuse key=%s site=%s depth=%d re=%d/%d" cycle_key cycle_site cycle_depth cycle_re cycle_max_re
                            DiagSidecar.emit (EvalWorklist.requiredMessage msg frame)
                            DiagSidecar.emit (EvalWorklist.panel())
                            EvalWorklistFrontier.emit EJPCodes.EJP0011 "jp_wait_observed_sequential_cycle_fuse" cycle_key cycle_site cycle_depth cycle_re cycle_max_re
                            raise (PartEvalTypeError(frame.trace, EvalWorklist.requiredMessage msg frame))
                    // ALPHA102: generation change while waiting is not benign here; abort and let the outer retry rebuild.
                    let curGen = CacheGeneration.current()
                    if curGen <> gen0 then
                        let snap = diag_snapshot (sprintf "gen_change jp_wait from=%d to=%d" gen0 curGen)
                        let msg = sprintf "[spiral_compiler] EJP0008: generation changed while waiting for jp_wait (from %d to %d)" gen0 curGen
                        DiagSidecar.emit (msg + "\n" + snap)
                        CacheGeneration.requestSequential ()
                        raise (PartEvalTypeError([], msg))
                    
                    // ALPHA119: base-count close + pending leak reconciliation

                    // CountdownEvent starts at 1. When the queue is empty and CurrentCount=1, no JP job can still complete.
                    // If pending_count > 0 in this situation, treat it as a leaked counter from a cancelled/stale job.
                    // ALPHA102: close base barrier whenever CurrentCount=1. Queue count can be misleading under races.
                    let cc = cd.CurrentCount
                    if cc = 1 then
                        let pend_now = System.Threading.Interlocked.Read(&jp_pending_count)
                        if pend_now > 0L && not pending_fixup_done then
                            pending_fixup_done <- true
                            let old_pend = System.Threading.Interlocked.Exchange(&jp_pending_count, 0L)
                            // Cancelled jobs must not keep progress stuck at 99.9%.
                            let enq_total = System.Threading.Interlocked.Read(&jp_total_enqueued)
                            ignore (System.Threading.Interlocked.Exchange(&jp_total_done, enq_total))
                            DiagSidecar.emit (sprintf "[spiral_compiler] EJP0020: reconciled pending leak old=%d enq=%d gen=%d" old_pend enq_total gen0)
                        // If there is no pending work, base-signal to complete the wait.
                        if System.Threading.Interlocked.Read(&jp_pending_count) = 0L then
                            lock jp_barrier_lock (fun () ->
                                if not (obj.ReferenceEquals(jp_wait_closed_cd, cd)) then
                                    jp_wait_closed_cd <- cd
                                    jp_wait_closed <- true
                            )
                            try if cd.CurrentCount > 0 then ignore (cd.Signal()) with _ -> ()
                            DiagSidecar.emit (sprintf "[spiral_compiler] EJP0019: jp_wait base-signal gen=%d cc=%d" gen0 cc)

                    // alpha332: stall detection now runs before work-stealing. In forced sequential
                    // fallback, the waiter must stay responsive; otherwise it can spend tens of seconds
                    // executing one more saturated evaluator job before it notices the elapsed fuse.
                    let now_ms = peval_sw.ElapsedMilliseconds
                    let lp = System.Threading.Interlocked.Read(&jp_last_progress_ms)
                    let base_ms = if lp > 0L then lp else wait_start_ms
                    let seq_wait_now = CacheGeneration.isSequentialRequested()
                    let jp_wait_stall_abort_ms =
                        if seq_wait_now then min jp_stall_abort_ms EvalFallbackPolicy.sequentialJpWaitStallMs
                        else jp_stall_abort_ms
                    let waited_ms = now_ms - wait_start_ms
                    let idle_or_elapsed_ms = if seq_wait_now then waited_ms else now_ms - base_ms
                    if jp_wait_stall_abort_ms > 0L && idle_or_elapsed_ms > jp_wait_stall_abort_ms then
                        let pending_now = System.Threading.Interlocked.Read(&jp_pending_count)
                        // Se não há trabalho pendente nem fila, isso é leak de barreira -> force-close antes de abortar.
                        if pending_now = 0L && jp_work_q.Count = 0 then
                            try
                                // Mark this CountdownEvent as closed to avoid double-Signal base (multiple jp_wait callers).
                                lock jp_barrier_lock (fun () ->
                                    if not (obj.ReferenceEquals(jp_wait_closed_cd, cd)) then
                                        jp_wait_closed_cd <- cd
                                        jp_wait_closed <- true
                                )
                                let cc0 = cd.CurrentCount
                                if cc0 > 0 then
                                    try
                                        ignore (cd.Signal(cc0))
                                    with _ ->
                                        // Best-effort stepwise close (handles races with in-flight Signal()).
                                        let mutable spins = 0
                                        while cd.CurrentCount > 0 && spins < 1024 do
                                            spins <- spins + 1
                                            try ignore (cd.Signal()) with _ -> spins <- 1024
                                DiagSidecar.emit (sprintf "[spiral_compiler] EJP0017: jp_wait force-closed after stall cc=%d gen=%d" cc0 gen0)
                            with _ -> ()
                        elif seq_wait_now && pending_now > 0L && jp_work_q.Count = 0 && EvalWorklist.hasReplayComplete() && EvalWorklist.hasReplayCompleteWriteWitness() && EvalWorklist.pendingCount() > 0 then
                            // ALPHA911: root-complete plus write witness is no longer enough to abort when
                            // the explicit worklist still has body-dict cells.  Runtime 910 proved that the
                            // previous fail-closed branch preserved correctness, but converted useful replay
                            // work into a retry.  Spend one bounded structural drain slice first; only close
                            // the JP barrier when the replay body dictionary is actually empty, and only throw
                            // if no explicit-worklist progress was made.  This is generic: it uses status,
                            // pending counters, write-witness freshness and terminal rank, never source paths.
                            let ewPendingBefore = EvalWorklist.pendingCount()
                            let drainedBodyFrame =
                                try EvalWorklist.drainJpStallPreflight "jp_wait_pending_body_dict_drain" 1024
                                with _ -> None
                            let ewPendingAfter = EvalWorklist.pendingCount()
                            let bodyFrameStatus = match drainedBodyFrame with Some frame -> frame.status | None -> "none"
                            let bodyFrameCursor = match drainedBodyFrame with Some frame -> frame.cursor | None -> -1
                            let bodyFrameNext =
                                match drainedBodyFrame with
                                | Some frame ->
                                    if frame.status = "semantic_root_complete" then "attempt_build"
                                    elif frame.status = "semantic_step_partial" then "continue_wait_for_body_dict_drain"
                                    else "explicit_eval_worklist_before_codegen"
                                | None -> "none"
                            let pinnedTerminalPresent =
                                try
                                    match EvalWorklist.tryPinnedTerminalContract() with
                                    | Some pinned when EvalWorklist.terminalContractRank pinned.status >= 90 -> true
                                    | _ -> false
                                with _ -> false
                            DiagJson.emit (
                                sprintf "{\"kind\":\"eval_worklist_jp_wait_pending_body_dict_drain\",\"event\":\"jp_wait_stall\",\"status\":\"semantic_root_complete\",\"pending\":%d,\"q\":%d,\"cc\":%d,\"ew_pending_before\":%d,\"ew_pending_after\":%d,\"frame_status\":%s,\"frame_cursor\":%d,\"frame_next\":%s,\"wait_ms\":%d,\"single_flight\":1,\"next\":\"body_dict_drain_or_fail_closed\"}"
                                    pending_now jp_work_q.Count cc ewPendingBefore ewPendingAfter (DiagJson.esc bodyFrameStatus) bodyFrameCursor (DiagJson.esc bodyFrameNext) idle_or_elapsed_ms)
                            if ewPendingAfter = 0 && not pinnedTerminalPresent && EvalWorklist.hasReplayComplete() && EvalWorklist.hasReplayCompleteWriteWitness() then
                                let old_pend = System.Threading.Interlocked.Exchange(&jp_pending_count, 0L)
                                let enq_total = System.Threading.Interlocked.Read(&jp_total_enqueued)
                                ignore (System.Threading.Interlocked.Exchange(&jp_total_done, enq_total))
                                lock jp_barrier_lock (fun () ->
                                    if not (obj.ReferenceEquals(jp_wait_closed_cd, cd)) then
                                        jp_wait_closed_cd <- cd
                                        jp_wait_closed <- true
                                )
                                let cc0 = cd.CurrentCount
                                if cc0 > 0 then
                                    try
                                        ignore (cd.Signal(cc0))
                                    with _ ->
                                        let mutable spins = 0
                                        while cd.CurrentCount > 0 && spins < 1024 do
                                            spins <- spins + 1
                                            try ignore (cd.Signal()) with _ -> spins <- 1024
                                DiagJson.emit (
                                    sprintf "{\"kind\":\"eval_worklist_jp_wait_pending_body_dict_drained_closed\",\"event\":\"jp_wait_stall\",\"status\":\"semantic_root_complete\",\"old_pending\":%d,\"pending\":%d,\"q\":%d,\"closed_count\":%d,\"ew_pending_before\":%d,\"ew_pending_after\":%d,\"wait_ms\":%d,\"single_flight\":1,\"next\":\"attempt_build\"}"
                                        old_pend pending_now jp_work_q.Count cc0 ewPendingBefore ewPendingAfter idle_or_elapsed_ms)
                                DiagSidecar.emit (sprintf "[spiral_compiler] jp_wait_pending_body_dict_drained_closed old_pending=%d ew_before=%d ew_after=%d cc=%d gen=%d" old_pend ewPendingBefore ewPendingAfter cc0 gen0)
                            elif ewPendingAfter < ewPendingBefore then
                                System.Threading.Interlocked.Exchange(&jp_last_progress_ms, peval_sw.ElapsedMilliseconds) |> ignore
                                DiagJson.emit (
                                    sprintf "{\"kind\":\"eval_worklist_jp_wait_pending_body_dict_drain_progress\",\"event\":\"jp_wait_stall\",\"status\":%s,\"pending\":%d,\"q\":%d,\"cc\":%d,\"ew_pending_before\":%d,\"ew_pending_after\":%d,\"wait_ms\":%d,\"single_flight\":1,\"next\":\"continue_wait_for_body_dict_drain\"}"
                                        (DiagJson.esc bodyFrameStatus) pending_now jp_work_q.Count cc ewPendingBefore ewPendingAfter idle_or_elapsed_ms)
                                DiagSidecar.emit (sprintf "[spiral_compiler] jp_wait pending body-dict drain progressed ew=%d->%d gen=%d" ewPendingBefore ewPendingAfter gen0)
                            else
                                let msg =
                                    sprintf "[spiral_compiler] EJP0011: jp_wait preserved root-complete pending bodies before codegen pending=%d q=%d cc=%d ew_pending=%d drained_status=%s"
                                        pending_now jp_work_q.Count cc ewPendingAfter bodyFrameStatus
                                DiagJson.emit (
                                    sprintf "{\"kind\":\"eval_worklist_jp_wait_root_complete_pending_body_dict_deferred\",\"event\":\"jp_wait_stall\",\"status\":\"semantic_root_complete\",\"pending\":%d,\"q\":%d,\"cc\":%d,\"ew_pending\":%d,\"wait_ms\":%d,\"policy\":\"fail_closed_after_bounded_body_dict_drain\",\"single_flight\":1,\"next\":\"explicit_eval_worklist_before_codegen\"}"
                                        pending_now jp_work_q.Count cc ewPendingAfter idle_or_elapsed_ms)
                                DiagSidecar.emit msg
                                raise (PartEvalTypeError([], msg))
                        elif seq_wait_now && pending_now > 0L && jp_work_q.Count = 0 && EvalWorklist.hasReplayComplete() then
                            // ALPHA589: runtime 588 reached semantic_root_complete, q=0 and cc=2 after
                            // the cycle preflight had already deferred exactly one pending JP body.  At
                            // this point no queued body remains to run; treating the stale counter as
                            // a fresh EJP0011/EJP0014 only restarts the same completed root handoff.
                            // Close the local barrier only when no high-rank terminal is pinned.
                            let pinnedTerminalPresent =
                                try
                                    match EvalWorklist.tryPinnedTerminalContract() with
                                    | Some pinned when EvalWorklist.terminalContractRank pinned.status >= 90 -> true
                                    | _ -> false
                                with _ -> false
                            if pinnedTerminalPresent then
                                let snap = diag_snapshot (sprintf "jp_wait stall iter=%d pending=%d" iterations pending_now)
                                let msg = sprintf "[spiral_compiler] EJP0014: jp_wait stalled for %dms iter=%d pending=%d q=%d cc=%d gen=%d abort_ms=%d clock=%s" idle_or_elapsed_ms iterations pending_now jp_work_q.Count cc gen0 jp_wait_stall_abort_ms (if seq_wait_now then "elapsed" else "idle")
                                DiagJson.emit (
                                    sprintf "{\"kind\":\"eval_worklist_jp_wait_root_complete_stale_pending_not_closed\",\"event\":\"jp_wait_stall\",\"status\":\"semantic_root_complete\",\"pending\":%d,\"q\":%d,\"cc\":%d,\"wait_ms\":%d,\"single_flight\":1,\"next\":\"explicit_pinned_terminal_contract\"}"
                                        pending_now jp_work_q.Count cc idle_or_elapsed_ms)
                                DiagSidecar.emit (msg + "\n" + snap)
                                raise (PartEvalTypeError([], msg))
                            else
                                try
                                    let old_pend = System.Threading.Interlocked.Exchange(&jp_pending_count, 0L)
                                    let enq_total = System.Threading.Interlocked.Read(&jp_total_enqueued)
                                    ignore (System.Threading.Interlocked.Exchange(&jp_total_done, enq_total))
                                    lock jp_barrier_lock (fun () ->
                                        if not (obj.ReferenceEquals(jp_wait_closed_cd, cd)) then
                                            jp_wait_closed_cd <- cd
                                            jp_wait_closed <- true
                                    )
                                    let cc0 = cd.CurrentCount
                                    if cc0 > 0 then
                                        try
                                            ignore (cd.Signal(cc0))
                                        with _ ->
                                            let mutable spins = 0
                                            while cd.CurrentCount > 0 && spins < 1024 do
                                                spins <- spins + 1
                                                try ignore (cd.Signal()) with _ -> spins <- 1024
                                    DiagJson.emit (
                                        sprintf "{\"kind\":\"eval_worklist_jp_wait_root_complete_stale_pending_closed\",\"event\":\"jp_wait_stall\",\"status\":\"semantic_root_complete\",\"old_pending\":%d,\"pending\":%d,\"q\":%d,\"closed_count\":%d,\"wait_ms\":%d,\"single_flight\":1,\"next\":\"attempt_build\"}"
                                            old_pend pending_now jp_work_q.Count cc0 idle_or_elapsed_ms)
                                    let replayRootReason =
                                        sprintf "BuildFile.replay_root_complete code=[spiral_compiler] EJP0011 source=jp_wait_stale_pending_closed old_pending=%d pending=%d q=%d"
                                            old_pend pending_now jp_work_q.Count
                                    try CacheGeneration.noteReason replayRootReason with _ -> ()
                                    DiagJson.emit (
                                        sprintf "{\"kind\":\"eval_worklist_jp_wait_stale_pending_replay_root_reason_recorded\",\"event\":\"jp_wait_stall\",\"status\":\"semantic_root_complete\",\"old_pending\":%d,\"pending\":%d,\"q\":%d,\"reason\":%s,\"single_flight\":1,\"next\":\"attempt_build\"}"
                                            old_pend pending_now jp_work_q.Count (DiagJson.esc replayRootReason))
                                    DiagSidecar.emit (sprintf "[spiral_compiler] jp_wait_root_pending_closure jp_wait closed stale root-complete pending old=%d cc=%d gen=%d" old_pend cc0 gen0)
                                with _ -> ()
                        else
                            let snap = diag_snapshot (sprintf "jp_wait stall iter=%d pending=%d" iterations pending_now)
                            let msg = sprintf "[spiral_compiler] EJP0014: jp_wait stalled for %dms iter=%d pending=%d q=%d cc=%d gen=%d abort_ms=%d clock=%s" idle_or_elapsed_ms iterations pending_now jp_work_q.Count cc gen0 jp_wait_stall_abort_ms (if seq_wait_now then "elapsed" else "idle")
                            // ALPHA553: drain before deciding whether the stall is really EJP0014.
                            // Runtime 552 showed the old path emitted the EJP0014 frontier first,
                            // then the explicit worklist made progress and later selected a true
                            // EJP0011 terminal.  Keep this fail-closed: no writer/root proof is
                            // produced here, but live explicit-worklist evidence should not be
                            // mislabeled as the original stall wrapper.
                            let stallPreflightFrame =
                                if seq_wait_now then
                                    try
                                        let drained = EvalWorklist.drainJpStallPreflight "jp_wait_stall" 256
                                        match drained with
                                        | Some frame ->
                                            DiagJson.emit (
                                                sprintf "{\"kind\":\"eval_worklist_jp_wait_stall_preflight_drained\",\"event\":\"jp_wait_stall\",\"status\":%s,\"cursor\":%d,\"pending\":%d,\"q\":%d,\"cc\":%d,\"wait_ms\":%d,\"single_flight\":1,\"next\":\"prefer_terminal_or_live_frame\"}"
                                                    (DiagJson.esc frame.status) frame.cursor pending_now jp_work_q.Count cc idle_or_elapsed_ms)
                                        | None ->
                                            DiagJson.emit (
                                                sprintf "{\"kind\":\"eval_worklist_jp_wait_stall_preflight_empty\",\"event\":\"jp_wait_stall\",\"pending\":%d,\"q\":%d,\"cc\":%d,\"wait_ms\":%d,\"single_flight\":1,\"next\":\"fallback_stall_policy\"}"
                                                    pending_now jp_work_q.Count cc idle_or_elapsed_ms)
                                        drained
                                    with _ -> None
                                else None

                            // ALPHA548/553: the stall preflight can discover and pin the true terminal while
                            // servicing a stale root-complete/pending-JP wait.  Surface that terminal now
                            // as EJP0011 rather than throwing the original EJP0014 wrapper.
                            let stallPinnedTerminal =
                                if seq_wait_now then
                                    try
                                        match EvalWorklist.tryPinnedTerminalContract() with
                                        | Some pinned when EvalWorklist.terminalContractRank pinned.status >= 90 -> Some pinned
                                        | _ -> None
                                    with _ -> None
                                else None
                            match stallPinnedTerminal with
                            | Some pinned ->
                                let rank = EvalWorklist.terminalContractRank pinned.status
                                DiagJson.emit (
                                    sprintf "{\"kind\":\"eval_worklist_jp_wait_stall_pinned_terminal_preempted\",\"event\":\"jp_wait_stall\",\"code\":%s,\"original_code\":%s,\"status\":%s,\"rank\":%d,\"site\":%s,\"key\":%s,\"wait_ms\":%d,\"pending\":%d,\"q\":%d,\"cc\":%d,\"single_flight\":1,\"next\":\"explicit_pinned_terminal_contract\"}"
                                        (DiagJson.esc EJPCodes.EJP0011) (DiagJson.esc EJPCodes.EJP0014) (DiagJson.esc pinned.status) rank (DiagJson.esc pinned.site) (DiagJson.esc pinned.key) idle_or_elapsed_ms pending_now jp_work_q.Count cc)
                                let terminalMsg =
                                    EvalWorklist.requiredMessage
                                        (sprintf "%s: jp_wait stall preflight found pinned terminal contract; original_code=%s wait_ms=%d pending=%d q=%d cc=%d"
                                            EJPCodes.EJP0011 EJPCodes.EJP0014 idle_or_elapsed_ms pending_now jp_work_q.Count cc)
                                        pinned
                                DiagSidecar.emit terminalMsg
                                raise (PartEvalTypeError([], terminalMsg))
                            | None ->
                                match stallPreflightFrame with
                                | Some frame when seq_wait_now && EvalWorklist.isLiveExplicitFrameStatus frame.status ->
                                    DiagJson.emit (
                                        sprintf "{\"kind\":\"eval_worklist_jp_wait_stall_live_frame_observed\",\"event\":\"jp_wait_stall\",\"code\":%s,\"original_code\":%s,\"status\":%s,\"site\":%s,\"key\":%s,\"wait_ms\":%d,\"pending\":%d,\"q\":%d,\"cc\":%d,\"single_flight\":1,\"next\":\"continue_wait_for_live_replay\"}"
                                            (DiagJson.esc EJPCodes.EJP0011) (DiagJson.esc EJPCodes.EJP0014) (DiagJson.esc frame.status) (DiagJson.esc frame.site) (DiagJson.esc frame.key) idle_or_elapsed_ms pending_now jp_work_q.Count cc)
                                    try ignore (System.Threading.Interlocked.Exchange(&jp_last_progress_ms, peval_sw.ElapsedMilliseconds)) with _ -> ()
                                | Some frame when seq_wait_now ->
                                    DiagJson.emit (
                                        sprintf "{\"kind\":\"eval_worklist_jp_wait_stall_non_live_frame_preempted\",\"event\":\"jp_wait_stall\",\"code\":%s,\"original_code\":%s,\"status\":%s,\"site\":%s,\"key\":%s,\"wait_ms\":%d,\"pending\":%d,\"q\":%d,\"cc\":%d,\"single_flight\":1,\"next\":\"explicit_non_live_frame_contract\"}"
                                            (DiagJson.esc EJPCodes.EJP0011) (DiagJson.esc EJPCodes.EJP0014) (DiagJson.esc frame.status) (DiagJson.esc frame.site) (DiagJson.esc frame.key) idle_or_elapsed_ms pending_now jp_work_q.Count cc)
                                    let liveMsg =
                                        EvalWorklist.requiredMessage
                                            (sprintf "%s: jp_wait stall preflight produced a non-live explicit-worklist frame; original_code=%s status=%s wait_ms=%d pending=%d q=%d cc=%d"
                                                EJPCodes.EJP0011 EJPCodes.EJP0014 frame.status idle_or_elapsed_ms pending_now jp_work_q.Count cc)
                                            frame
                                    DiagSidecar.emit liveMsg
                                | _ ->
                                    if seq_wait_now then
                                        try
                                            DiagJson.emit (sprintf "{\"kind\":\"eval_frontier\",\"code\":\"%s\",\"reason\":\"forced_seq_jp_wait_stall\",\"wait_ms\":%d,\"pending\":%d,\"q\":%d,\"cc\":%d,\"policy\":\"jp_liveness_or_stack_safe_worklist_required\",\"policy_next\":\"explicit_eval_worklist\"}" EJPCodes.EJP0014 idle_or_elapsed_ms pending_now jp_work_q.Count cc)
                                        with _ -> ()

                            // Alpha217/332: include current JP panel + top slow jobs. Under forced sequential
                            // keep this tiny; hotkey summaries in retry diagnostics carry the aggregate signal.
                            let panel0 = try jp_panel_provider () with _ -> ""
                            let panel =
                                if System.String.IsNullOrEmpty panel0 then ""
                                else "---- jp.panel ----\n" + panel0

                            let slow0 = jp_slow_jobs_snapshot (if seq_wait_now then EvalFallbackPolicy.sequentialJpWaitSlowJobs else 12)
                            let slow =
                                if slow0.IsEmpty then ""
                                else "---- jp slow jobs ----\n" + (slow0 |> String.concat "\n")

                            let diag =
                                [ msg
                                  panel
                                  slow
                                  snap ]
                                |> List.filter (fun s -> not (System.String.IsNullOrEmpty s))
                                |> String.concat "\n"

                            let livePreflightSuppressed =
                                match stallPinnedTerminal, stallPreflightFrame with
                                | None, Some frame when seq_wait_now && EvalWorklist.isLiveExplicitFrameStatus frame.status ->
                                    DiagJson.emit (
                                        sprintf "{\"kind\":\"eval_worklist_jp_wait_stall_live_frame_suppressed\",\"event\":\"jp_wait_stall\",\"code\":%s,\"original_code\":%s,\"status\":%s,\"site\":%s,\"key\":%s,\"wait_ms\":%d,\"pending\":%d,\"q\":%d,\"cc\":%d,\"single_flight\":1,\"next\":\"continue_wait_for_live_replay\"}"
                                            (DiagJson.esc EJPCodes.EJP0011) (DiagJson.esc EJPCodes.EJP0014) (DiagJson.esc frame.status) (DiagJson.esc frame.site) (DiagJson.esc frame.key) idle_or_elapsed_ms pending_now jp_work_q.Count cc)
                                    try ignore (System.Threading.Interlocked.Exchange(&jp_last_progress_ms, peval_sw.ElapsedMilliseconds)) with _ -> ()
                                    DiagSidecar.emit (sprintf "[spiral_compiler] jp_wait live frame suppressed stall status=%s pending=%d q=%d cc=%d wait_ms=%d next=continue_wait_for_live_replay" frame.status pending_now jp_work_q.Count cc idle_or_elapsed_ms)
                                    true
                                | None, None when seq_wait_now && pending_now > 0L && jp_work_q.Count = 0 && cc > 0 ->
                                    DiagJson.emit (
                                        sprintf "{\"kind\":\"eval_worklist_jp_wait_pending_no_frontier_deferred\",\"event\":\"jp_wait_stall\",\"code\":%s,\"original_code\":%s,\"pending\":%d,\"q\":%d,\"cc\":%d,\"wait_ms\":%d,\"single_flight\":1,\"next\":\"continue_wait_for_hidden_countdown_work\"}"
                                            (DiagJson.esc EJPCodes.EJP0011) (DiagJson.esc EJPCodes.EJP0014) pending_now jp_work_q.Count cc idle_or_elapsed_ms)
                                    try ignore (System.Threading.Interlocked.Exchange(&jp_last_progress_ms, peval_sw.ElapsedMilliseconds)) with _ -> ()
                                    DiagSidecar.emit (sprintf "[spiral_compiler] jp_wait pending without frontier deferred as live hidden countdown pending=%d q=%d cc=%d wait_ms=%d next=continue_wait_for_hidden_countdown_work" pending_now jp_work_q.Count cc idle_or_elapsed_ms)
                                    true
                                | _ -> false
                            if not livePreflightSuppressed then
                                DiagSidecar.emit diag
                                raise (PartEvalTypeError([], msg))

                    // Work-stealing: in forced-sequential fallback the waiter must not run evaluator jobs.
                    // A single stolen deep job was enough to push an 8s cap into ~13s. Keep the
                    // main waiter as a liveness observer; worker execution owns the actual job body.
                    let should_help_waiter =
                        (not seq_wait_now) || (EvalFallbackPolicy.sequentialJpWaitHelpWindowMs > 0L && waited_ms <= EvalFallbackPolicy.sequentialJpWaitHelpWindowMs)
                    if should_help_waiter then
                        let help_n = if seq_wait_now then 1 else jp_help_batch_n
                        ignore (jp_help_batch help_n)
                    elif (iterations &&& 255L) = 0L then
                        System.Threading.Thread.Yield() |> ignore

                    // ALPHA956: when forced-sequential jp_wait is no longer allowed to steal work,
                    // make the wait itself observable.  The previous runtime could sit with a small
                    // pending delta and require a manual interrupt before we saw which counters were
                    // stale.  Emit a compact muxed console heartbeat plus JSONL sidecar receipts from
                    // the waiter path, without fabricating completion or altering scheduling policy.
                    if seq_wait_now && (iterations &&& 1023L) = 0L then
                        try
                            let enq_now = System.Threading.Interlocked.Read(&jp_total_enqueued)
                            let done_now = System.Threading.Interlocked.Read(&jp_total_done)
                            let pending_now = System.Threading.Interlocked.Read(&jp_pending_count)
                            let ew_pending_now = EvalWorklist.pendingCount()
                            let replay_complete_now = EvalWorklist.hasReplayComplete()
                            let replay_witness_now = EvalWorklist.hasReplayCompleteWriteWitness()
                            let last_progress_now = System.Threading.Interlocked.Read(&jp_last_progress_ms)
                            let progress_age = if last_progress_now > 0L then peval_sw.ElapsedMilliseconds - last_progress_now else -1L
                            let line =
                                sprintf "[spiral_compiler] JP_WAIT_LIVE iter=%d wait_ms=%d pending=%d enqueued=%d done=%d q=%d cc=%d ew_pending=%d replay_complete=%b replay_witness=%b progress_age_ms=%d clock=%s next=wait_or_stall_diag"
                                    iterations waited_ms pending_now enq_now done_now jp_work_q.Count cc ew_pending_now replay_complete_now replay_witness_now progress_age (if seq_wait_now then "elapsed" else "idle")
                            Progress88.ConsoleMux88.writeLine line
                            DiagJson.emit (
                                sprintf "{\"kind\":\"eval_worklist_jp_wait_live_console\",\"event\":\"jp_wait\",\"iter\":%d,\"wait_ms\":%d,\"pending\":%d,\"enqueued\":%d,\"done\":%d,\"q\":%d,\"cc\":%d,\"ew_pending\":%d,\"replay_complete\":%b,\"replay_witness\":%b,\"progress_age_ms\":%d,\"single_flight\":1,\"next\":\"wait_or_stall_diag\"}"
                                    iterations waited_ms pending_now enq_now done_now jp_work_q.Count cc ew_pending_now replay_complete_now replay_witness_now progress_age)
                        with _ -> ()

                    // Yield to OS scheduler periodically
                    if (iterations &&& 63L) = 0L then
                        System.Threading.Thread.Yield() |> ignore
                // Log excessive iterations
                if iterations > 10000L then
                    DiagSidecar.emit (sprintf "jp_wait: iterations=%d pending=%d" iterations (System.Threading.Interlocked.Read(&jp_pending_count)))
                    

            finally
                // Mark as closed (and release the base barrier) exactly once per CountdownEvent instance.
                // Multiple concurrent jp_wait callers can otherwise over-Signal and crash.
                let mutable doSignalBase = false
                lock jp_barrier_lock (fun () ->
                    if not (obj.ReferenceEquals(jp_wait_closed_cd, cd)) then
                        jp_wait_closed_cd <- cd
                        jp_wait_closed <- true
                        doSignalBase <- true
                )

                if doSignalBase then
                    try if cd.CurrentCount > 0 then ignore (cd.Signal()) with _ -> ()
    

        // Legacy compatibility wrapper for old ManualResetEventSlim-based code
        // ALPHA15: More aggressive work-stealing + ThreadPool spawning for blocked workers
        let jp_ev_wait (w: string) (details: string) (ev: System.Threading.ManualResetEventSlim) =
            diag_last_wait <- if System.String.IsNullOrEmpty details then w else w + " :: " + details
            DiagLastWait.set diag_last_wait
            let mutable gen0 = CacheGeneration.current()
            if ev.IsSet then jp_throw_if_any ()
            else
                let mutable spin = System.Threading.SpinWait()
                let mutable last_diag = peval_sw.ElapsedMilliseconds
                let mutable spawned_helpers = 0
                while not ev.IsSet do
                    let curGen = CacheGeneration.current()
                    if curGen <> gen0 then
                        let snap = diag_snapshot (sprintf "gen_change jp_ev_wait from=%d to=%d :: %s (%s)" gen0 curGen w details)
                        let msg =
                            sprintf "[spiral_compiler] EJP0008: generation changed while waiting for jp_ev_wait (from %d to %d) :: %s (%s)" gen0 curGen w details
                        DiagSidecar.emit (msg + "\n" + snap)
                        CacheGeneration.requestSequential ()
                        raise (PartEvalTypeError([], msg))
                    let now = peval_sw.ElapsedMilliseconds
                    if diag_period_ms > 0L && now - last_diag >= diag_period_ms then
                        last_diag <- now
                        diag_print false "tick/jp_ev_wait"
                    diag_abort_if_needed "jp_ev_wait"
                    
                    // ALPHA15: More aggressive work-stealing - drain more work, more often

                    if jp_parallel_effective () then
                        let drained = jp_help_batch 64  // Drain up to 64 items each iteration
                        

                        // If we're stuck (nothing to drain) but queue has work, spawn ThreadPool helpers
                        // This breaks the deadlock when all Hopac workers are blocked
                        if drained = 0 && spawned_helpers < 4 && spin.Count > 1000 then
                            let q_count = jp_work_q.Count
                            if q_count > 0 then
                                spawned_helpers <- spawned_helpers + 1
                                System.Threading.ThreadPool.QueueUserWorkItem(fun _ ->
                                    try ignore (jp_help_batch 256) with _ -> ()
                                ) |> ignore
                    

                    if (spin.Count &&& 63) = 0 then
                        hopac_tick ()
                    spin.SpinOnce()
                    if (spin.Count &&& 511) = 0 then System.Threading.Thread.Yield() |> ignore
                jp_throw_if_any ()
    

        let jp_stack_bytes = 8 * 1024 * 1024  // For BigStack compatibility
    

        let rec ty_to_data s x =
            let f = ty_to_data s
            match x with
            | YVoid ->
                // par: The evaluator can transiently demand a term for YVoid during sequencing
                // or placeholder materialization under parallel retries. Coerce it to unit data (DB) instead of aborting.
                // Any semantically invalid usage should reappear later as a type mismatch rather than a fatal abort.
                DB
            | YB -> DB
            | YPair(a,b) -> DPair(f a, f b)
            | YSymbol a when a.StartsWith("JPMethodRecPlaceholder(") || a.StartsWith(".JPMethodRecPlaceholder(") ->
                // ALPHA40: If the JP method rec placeholder has already been resolved, deref it here so it cannot leak as a DV placeholder.
                let x' = jp_method_deref_rec_placeholder x
                if x' <> x then f x' else
                    let r = DV(L(s.i.Value,x))
                    s.i.Value <- s.i.Value + 1
                    r
            | YSymbol a -> DSymbol a
            | YRecord l -> DRecord(Map.map (fun _ -> f) l)
            | YForall | YExists | YUnion _ | YLayout _ | YPrim _ | YArray _ | YFun _ | YMacro _ as x -> let r = DV(L(s.i.Value,x)) in s.i.Value <- s.i.Value + 1; r
            | YNominal _ | YApply _ as a -> DNominal(nominal_type_apply s a |> ty_to_data s, a)
            | YLit x -> DTLit x
            | YTypeFunction _ -> raise_type_error s "Cannot turn a type function into a runtime variable."
            | YMetavar _ -> raise_type_error s "Compiler error: Cannot turn a metavar into a runtime variable."
        and assert_ty_lit s = function
            | YSymbol _ | YLit _ as x -> x
            | YNominal _ | YApply _ as x -> nominal_type_apply s x |> assert_ty_lit s
            | x -> raise_type_error s <| sprintf "Expected a type literal or a symbol.\nGot: %s" (show_ty x)
        and push_typedop_no_rewrite d op ret_ty =
            let ret = ty_to_data d ret_ty
            d.seq.Add(TyLet(ret,d.trace,op))
            ret
        and push_typedop (d: LangEnv) key ret_ty =
            match cse_tryfind d key with
            | Some x -> x
            | None ->
                let x = ty_to_data d ret_ty
                d.seq.Add(TyLet(x,d.trace,key))
                cse_add d key x
                x
        and push_op_no_rewrite' (d: LangEnv) op l ret_ty = push_typedop_no_rewrite d (TyOp(op,l)) ret_ty
        and push_op_no_rewrite d op a ret_ty = push_op_no_rewrite' d op [a] ret_ty
        and push_binop_no_rewrite d op (a,b) ret_ty = push_op_no_rewrite' d op [a;b] ret_ty
        and push_triop_no_rewrite d op (a,b,c) ret_ty = push_op_no_rewrite' d op [a;b;c] ret_ty
    

        and push_op' d op a ret_ty = push_typedop d (TyOp(op, a)) ret_ty
        and push_op d op a ret_ty = push_op' d op [a] ret_ty
        and push_binop d op (a,b) ret_ty = push_op' d op [a;b] ret_ty
        and push_triop d op (a,b,c) ret_ty = push_op' d op [a;b;c] ret_ty
        and closure_env s (body,annot,gl_term,gl_ty,sz_term,sz_ty) = {
            trace = s.trace
            seq = ResizeArray()
            cse = [Dictionary(HashIdentity.Structural)]
            unions = Map.empty
            i = ref 0
            env_global_type = gl_ty
            env_global_term = gl_term
            env_stack_type = Array.zeroCreate<_> sz_ty
            env_stack_term = Array.zeroCreate<_> sz_term
            backend = s.backend
            globals = s.globals
            globals_lock = s.globals_lock
            globals_seen = s.globals_seen
            join_point_method_key_names = s.join_point_method_key_names
            join_point_closure_key_names = s.join_point_closure_key_names
            jp_method_stack = System.Collections.Generic.HashSet<ConsedNode<RData [] * Ty [] * Ty>>(s.jp_method_stack, HashIdentity.Reference)
            jp_closure_stack = System.Collections.Generic.HashSet<ConsedNode<RData [] * Ty [] * Ty>>(s.jp_closure_stack, HashIdentity.Reference)
            jp_type_stack = System.Collections.Generic.HashSet<ConsedNode<Ty []>>(s.jp_type_stack, HashIdentity.Reference)
            }
        and closure_convert s (body,annot,gl_term,gl_ty,sz_term,sz_ty as args) =
            let join_point_key, call_args, fun_ty =
                let s : LangEnv = closure_env s args
                let domain, range, fun_ty =
                    match ty s annot with
                    | YFun(a,b,_) as x -> a,b,x
                    | annot -> raise_type_error s <| sprintf "Expected a function type in annotation during closure conversion. Got: %s" (show_ty annot)
                // ALPHA48: IVar-based dict - no separate dict_ev needed
                let (dict: System.Collections.Concurrent.ConcurrentDictionary<ConsedNode<RData [] * Ty [] * Ty>, Hopac.IVar<(Data * TypedBind []) option>>), hc_table, cache_gen =
                    Utils.memoize join_point_closure (fun _ ->
                        System.Collections.Concurrent.ConcurrentDictionary<ConsedNode<RData [] * Ty [] * Ty>, Hopac.IVar<(Data * TypedBind []) option>>(HashIdentity.Reference), HashConsTable(), CacheGeneration.current ()
                    ) (s.backend, body)
    

                let dict, hc_table =
                    if CacheGeneration.isStale cache_gen then
                        let fresh =
                            (System.Collections.Concurrent.ConcurrentDictionary<_,_>(HashIdentity.Reference),
                             HashConsTable(),
                             CacheGeneration.current ())
                        join_point_closure.[(s.backend, body)] <- fresh
                        let (d,h,_) = fresh
                        d,h
                    else dict, hc_table
                let call_args, env_global_value =
                    data_to_rdata s hc_table gl_term
                let join_point_key =
                    lock hc_table (fun () -> hc_table.Add(env_global_value, s.env_global_type, fun_ty))
                let _ =
                    // best-effort, stable-ish label to improve join-point diagnostics
                    let name = sprintf "closure<%d>" join_point_key.tag
                    s.join_point_closure_key_names.TryAdd(join_point_key, name) |> ignore
    

                match fun_ty with
                | YFun(_,_,FT_Pointer) when call_args.Length <> 0 -> raise_type_error s "Function pointers shouldn't have any runtime free variables in their environment."
                | _ -> ()
    

                // v107-alpha43: Check loop specialization guard for closures
                let closure_name = sprintf "closure<%d>" join_point_key.tag
                if not (LoopSpecializationGuard.tryRecordSpecialization closure_name) then
                    DiagSidecar.emit (sprintf "[spiral_compiler] EJP0012: closure specialization cap exceeded for '%s'" closure_name)
                    SuspectCache.mark join_point_key (sprintf "%s jp_closure cap name=%s" EJPCodes.EJP0012 closure_name)
                    ()
    
                // ALPHA48: Use IVar for coordination - create new IVar and TryAdd

                let jp_ivar = Hopac.IVar<(Data * TypedBind []) option>()
                if dict.TryAdd(join_point_key, jp_ivar) then
                    // We won the race - compute the result
                    let run () =
                        try
                            try
                                let s = rename_global_term s
                                s.jp_closure_stack.Add(join_point_key) |> ignore
                                let domain_data = ty_to_data s domain
                                s.env_stack_term.[0] <- domain_data
                                let seq,ty = term_scope'' s body (Some fun_ty)
                                let result = Some(domain_data, seq)
                                let ty =
                                    match ty with
                                    | YRecord a ->
                                        a
                                        |> Seq.map (fun (KeyValue ((i, k), v)) ->
                                            let i =
                                                match range with
                                                | YRecord a ->
                                                    a |> Map.tryPick (fun (i', k') _ -> if k = k' then Some i' else None)
                                                | _ -> None
                                                |> Option.defaultValue i
                                            (i, k), v
                                        )
                                        |> Map.ofSeq
                                        |> YRecord
                                    | _ -> ty
                                let ty_deref = jp_method_deref_rec_placeholder ty
                                let ty =
                                    // par: under parallel JP recursion, closure bodies can transiently infer a JP placeholder.
                                    // If the function has an explicit unit return annotation, treat placeholder as unit to avoid spurious hard-fails.
                                    if range = YB && (ty_is_jp_method_rec_placeholder ty || ty_is_jp_type_rec_placeholder ty || ty_is_jp_method_rec_placeholder ty_deref || ty_is_jp_type_rec_placeholder ty_deref) then
                                        if jp_diag_verbose then
                                            DiagSidecar.emit (sprintf "[spiral_compiler] EJP0002W: coerced closure return placeholder to unit\n  got=%s\n  got(deref)=%s\n  expected=%s\n  key=%O"
                                                (show_ty ty) (show_ty ty_deref) (show_ty range) join_point_key)
                                        range
                                    else
                                        if range <> ty then
                                            let got_s = show_ty ty
                                            let gotd_s = show_ty ty_deref
                                            let exp_s = show_ty range
                                            let has_jp (x:string) =
                                                x.Contains("JPMethodRecPlaceholder")
                                                || x.Contains("JPTypeRecPlaceholder")
                                                || x.Contains("JPClosureRecPlaceholder")
                                                || x.Contains("JPMethodUnknownRet")
                                            if has_jp got_s || has_jp gotd_s || has_jp exp_s then
                                                if jp_diag_verbose then
                                                    DiagSidecar.emit (sprintf "[spiral_compiler] EJP0002W: coerced closure return type to annotation due to JP placeholder\n  got=%s\n  got(deref)=%s\n  expected=%s\n  key=%O"
                                                        got_s gotd_s exp_s join_point_key)
                                                range
                                            else ty
                                        else ty
                                if range <> ty then raise_type_error s <| sprintf "The annotation of the function does not match its body's type.\nGot: %s\nExpected: %s" (show_ty ty) (show_ty range)
                                // ALPHA48: Fill IVar to signal completion
                                jp_fill_ivar jp_ivar result
                            with e ->
                                // Fill with None on error so waiters don't hang
                                try jp_fill_ivar jp_ivar None with _ -> ()
                                reraise()
                        finally
                            s.jp_closure_stack.Remove(join_point_key) |> ignore
                    jp_start_named (sprintf "JPClosure tag=%d" join_point_key.tag) run
                else
                    // Another worker is computing - wait on their IVar
                    if s.jp_closure_stack.Contains(join_point_key) then
                        // Recursive closure: don't wait
                        ()
                    else
                        match dict.TryGetValue(join_point_key) with
                        | true, existing_ivar ->
                            if not (Hopac.IVar.Now.isFull existing_ivar) then
                                // ALPHA48: Cooperative wait on IVar
                                jp_ivar_wait "JPClosure.wait" (sprintf "key=%O" join_point_key) existing_ivar |> ignore
                            jp_throw_if_any ()
                        | _ -> ()
                join_point_key, call_args, fun_ty
            push_typedop s (TyJoinPoint(JPClosure((s.backend,body),join_point_key),call_args)) fun_ty, fun_ty
        and data_to_ty s x =
            let m = System.Collections.Concurrent.ConcurrentDictionary<_,_>(HashIdentity.Reference)
            let rec f x =
                Utils.memoize m (function
                    | DPair _ as x ->
                        // Avoid stack overflows on long right-nested pairs.
                        let elems = ResizeArray<Data>()
                        let mutable cur = x
                        while (
                            match cur with
                            | DPair(a,b) -> elems.Add a; cur <- b; true
                            | _ -> false
                        ) do
                            ()
                        let tail_ty = f cur
                        let mutable res = tail_ty
                        for i = elems.Count - 1 downto 0 do
                            res <- YPair(f elems.[i], res)
                        res
                    | DSymbol a -> jp_method_deref_rec_placeholder (YSymbol a)
                    | DRecord l -> YRecord(Map.map (fun _ -> f) l)
                    | DUnion(_,a) -> YUnion a
                    | DNominal(_,a) | DV(L(_,a)) -> jp_method_deref_rec_placeholder a
                    | DLit x -> lit_to_ty x
                    | DTLit x -> YLit x
                    | DB -> YB
                    | DFunction(body,Some annot,gl_term,gl_ty,sz_term,sz_ty) -> ty (closure_env s (body,annot,gl_term,gl_ty,sz_term,sz_ty)) annot
                    | DExists _ -> YExists
                    | DFunction(_,None,_,_,_,_) -> raise_type_error s "Cannot convert a function that is not annotated into a type."
                    | DForall _ -> YForall
                    | DHashSet _ -> raise_type_error s "Cannot convert a compile time HashSet into a type."
                    | DHashMap _ -> raise_type_error s "Cannot convert a compile time HashMap into a type."
                    ) x
            f x |> jp_method_deref_rec_placeholder
        and dyn do_lit s x =
            let mutable dirty = false
            if do_lit then
                let m = Dictionary<_,_>(HashIdentity.Reference)
                let visiting = HashSet<_>(HashIdentity.Reference)
                let rec f x =
                    match m.TryGetValue x with
                    | true, v -> v
                    | _ ->
                        if visiting.Add x = false then
                            raise_type_error s <| sprintf "Compiler error: Dyn cycle detected.\nData: %s" (show_data x)
                        try
                            let v =
                                match x with
                                | DV _ | DB | DExists _ | DForall _ | DRecord _ | DUnion _ | DHashSet _ | DHashMap _ -> x
                                | DTLit x -> dirty <- true; DLit x
                                | DLit _ as x -> x
                                | DSymbol x -> dirty <- true; DLit (LitString x)
                                | DPair _ ->
                                    dirty <- true
                                    // Avoid stack overflows on long right-nested pairs.
                                    let elems = ResizeArray<Data>()
                                    let mutable cur = x
                                    while (
                                        match cur with
                                        | DPair(a,b) -> elems.Add a; cur <- b; true
                                        | _ -> false
                                    ) do
                                        ()
                                    let tail = f cur
                                    let mutable res = tail
                                    for i = elems.Count - 1 downto 0 do
                                        res <- DPair(f elems.[i], res)
                                    res
                                | DNominal(DForall(body,term,ty,sz_term,sz_ty), b') ->
                                    dirty <- true
                                    DNominal(DForall(body, HopacExtensions.A.map f term, ty, sz_term, sz_ty), b')
                                | DNominal(DExists(vars_type,term), b') -> dirty <- true; DNominal(DExists(vars_type, f term), b')
                                | DNominal(DRecord a,b') -> dirty <- true; DNominal(DRecord (Map.map (fun _ v -> f v) a), b')
                                | DNominal(DUnion(DPair(DSymbol k,v),u),b') ->
                                    dirty <- true
                                    push_typedop_no_rewrite s (TyUnionBox(k,f v,u)) b'
                                | DNominal(DUnion(_, _),_) -> raise_type_error s "Compiler error: Union should always have a tag in the first argument."
                                | DNominal(DFunction _,_) -> raise_type_error s <| sprintf "Expected an annotated function into runtime data.\nGot: %s\n" (show_data x)
                                | DNominal(a,b') ->
                                    dirty <- true
                                    match a with
                                    | DNominal _ ->
                                        // Collapse consecutive nominal wrappers to avoid stack overflows on deep nests.
                                        let wrappers = ResizeArray<_>()
                                        let mutable cur = x
                                        let mutable core = Unchecked.defaultof<Data>
                                        let mutable done' = false
                                        while not done' do
                                            match cur with
                                            | DNominal(DNominal _ as a', b'') ->
                                                wrappers.Add b''
                                                cur <- a'
                                            | _ ->
                                                core <- cur
                                                done' <- true
                                        let core' = f core
                                        let mutable res = core'
                                        for i = wrappers.Count - 1 downto 0 do
                                            res <- DNominal(res, wrappers.[i])
                                        res
                                    | _ ->
                                        DNominal(f a,b')
                                | DFunction(body,Some annot,term',ty',sz_term,sz_ty) -> dirty <- true; closure_convert s (body,annot,term',ty',sz_term,sz_ty) |> fst
                                | DFunction(_,None,_,_,_,_) -> raise_type_error s <| sprintf "Expected an annotated function into runtime data.\nGot: %s\n" (show_data x)
                            m.[x] <- v
                            v
                        finally
                            visiting.Remove x |> ignore
                let v = f x
                if dirty then v else x
            else
                let m = Dictionary<_,_>(HashIdentity.Reference)
                let visiting = HashSet<_>(HashIdentity.Reference)
                let mutable dirty = false
                let rec f x =
                    match m.TryGetValue x with
                    | true, v -> v
                    | _ ->
                        if visiting.Add x = false then
                            raise_type_error s <| sprintf "Compiler error: Dyn cycle detected.\nData: %s" (show_data x)
                        try
                            let v =
                                match x with
                                | DV _ | DB | DExists _ | DForall _ | DRecord _ | DUnion _ | DTLit _ | DSymbol _ | DLit _ | DHashSet _ | DHashMap _ -> x
                                | DPair _ ->
                                    dirty <- true
                                    // Avoid stack overflows on long right-nested pairs.
                                    let elems = ResizeArray<Data>()
                                    let mutable cur = x
                                    while (
                                        match cur with
                                        | DPair(a,b) -> elems.Add a; cur <- b; true
                                        | _ -> false
                                    ) do
                                        ()
                                    let tail = f cur
                                    let mutable res = tail
                                    for i = elems.Count - 1 downto 0 do
                                        res <- DPair(f elems.[i], res)
                                    res
                                | DNominal(DForall(body,term,ty,sz_term,sz_ty), b') ->
                                    dirty <- true
                                    DNominal(DForall(body, HopacExtensions.A.map f term, ty, sz_term, sz_ty), b')
                                | DNominal(DExists(vars_type,term), b') ->
                                    dirty <- true
                                    DNominal(DExists(vars_type, f term), b')
                                | DNominal(DRecord a,b') ->
                                    dirty <- true
                                    DNominal(DRecord (Map.map (fun _ v -> f v) a), b')
                                | DNominal(DUnion(DPair(DSymbol k,v),u),b') ->
                                    dirty <- true
                                    push_typedop_no_rewrite s (TyUnionBox(k,f v,u)) b'
                                | DNominal(DUnion(_, _),_) ->
                                    raise_type_error s "Compiler error: Union should always have a tag in the first argument."
                                | DNominal(DFunction _,_) ->
                                    raise_type_error s <| sprintf "Expected an annotated function into runtime data.\nGot: %s\n" (show_data x)
                                | DNominal(a,b') ->
                                    dirty <- true
                                    match a with
                                    | DNominal _ ->
                                        // Collapse consecutive nominal wrappers to avoid stack overflows on deep nests.
                                        let wrappers = ResizeArray<_>()
                                        let mutable cur = x
                                        let mutable core = Unchecked.defaultof<Data>
                                        let mutable done' = false
                                        while not done' do
                                            match cur with
                                            | DNominal(DNominal _ as a', b'') ->
                                                wrappers.Add b''
                                                cur <- a'
                                            | _ ->
                                                core <- cur
                                                done' <- true
                                        let core' = f core
                                        let mutable res = core'
                                        for i = wrappers.Count - 1 downto 0 do
                                            res <- DNominal(res, wrappers.[i])
                                        res
                                    | _ ->
                                        DNominal(f a,b')
                                | DFunction(body,Some annot,term',ty',sz_term,sz_ty) ->
                                    dirty <- true
                                    closure_convert s (body,annot,term',ty',sz_term,sz_ty) |> fst
                                | DFunction(_,None,_,_,_,_) ->
                                    raise_type_error s <| sprintf "Expected an annotated function into runtime data.\nGot: %s\n" (show_data x)
                            m.[x] <- v
                            v
                        finally
                            visiting.Remove x |> ignore
    

                let v = f x
                if dirty then v else x
    

        and term_real_nominal s x =
            let s = {s with seq=ResizeArray(); cse=Dictionary(HashIdentity.Structural) :: s.cse}
            term s x |> data_to_ty s
        and term_scope'' s x fun_ty =
            let x = term s x |> dyn false s
            let x =
                match x with
                | DRecord c ->
                    c
                    |> Seq.map (fun (KeyValue ((i, k), v)) ->
                        let i =
                            match fun_ty with
                            | Some (YFun (YNominal _, YRecord a, _) | YRecord a) ->
                                a |> Map.tryPick (fun (i', k') _ -> if k = k' then Some i' else None)
                            | _ -> None
                            |> Option.defaultValue i
                        (i, k), v
                    )
                    |> Map.ofSeq
                    |> DRecord
                | _ -> x
            let x_ty = data_to_ty s x
            seq_apply s x, x_ty
        and term_scope' s cse x = term_scope'' {s with seq=ResizeArray(); cse=cse :: s.cse} x None
        and term_scope s x = term_scope' s (Dictionary(HashIdentity.Structural)) x
        and nominal_type_apply s x =
            match x with
            | YApply(a,b) ->
                match nominal_type_apply s a with
                | YTypeFunction(body,gl_ty,sz_term,sz_ty) ->
                    let s = { s with env_global_type = gl_ty; env_global_term = [||]; env_stack_type = Array.zeroCreate<_> sz_ty; env_stack_term = Array.zeroCreate<_> sz_term }
                    s.env_stack_type.[0] <- b
                    ty s body
                | a -> raise_type_error s <| sprintf "Expected a type level function in nominal application.\nGot: %s" (show_ty a)
            | YNominal a -> ty s a.node.body
            | YPrim _ | YLit _ | YB | YVoid -> x
            | _ -> x
        and ty s x =
            // par: Proactive BigStack pivot based on observed recursion depth.
            // Type frames also carry large environments; pivot earlier to avoid hard StackOverflow.
            let d = RecursionTracker.currentDepth()
            let v =
                if (not (BigStack.isActive())) && d > 32 then
                    match BigStack.tryRun "ty_depth" (fun () -> ty_core s x) with
                    | Some v -> v
                    | None -> ty_core s x
                else
                    ty_core s x
            v |> jp_method_deref_rec_placeholder
    

        and ty_core s x =
            // v107-alpha13: emergency stack pivot must return the same type as the normal path
            // (the old version returned 'unit' in the try-branch, causing cascading 'unit' vs 'Ty' errors)
            try
                System.Runtime.CompilerServices.RuntimeHelpers.EnsureSufficientExecutionStack()
                ty_core_impl s x
            with
            | EvalReplayTyReturn value -> value
            | :? System.InsufficientExecutionStackException ->
                match BigStack.tryRun "ty_emergency" (fun () -> ty_core_impl s x) with
                | Some v -> v
                | None ->
                    let fallback = match s.trace with | r :: _ -> r | [] -> range0
                    let r0 = range_of_tprepass_or fallback x
                    raise_type_error (add_trace s r0) (sprintf "%s: stack overflow in ty (BigStack exhausted)" EJPCodes.EJP0010)
    

        and ty_core_impl s x =
            let fallback = match s.trace with | r :: _ -> r | [] -> range0
            let r0 = range_of_tprepass_or fallback x
            let site = sprintf "ty@%s:%d" r0.path (fst r0.range).line
            let typeShape0 = evalNodeShapeTy x
            let typeSourceKey0 =
                EvalReplayValueStore.typeSourceKey site typeShape0 s.env_global_term.Length s.env_stack_term.Length s.env_global_type.Length s.env_stack_type.Length s.trace.Length
            let semanticCellForTy nodeId =
                // ALPHA596: runtime 595 proved alpha595's post-fuse ETypeApply TV snapshot
                // was necessary but not sufficient: the final TV#5870566 was hydrated as a
                // replay cell, not as the registered type-apply argument.  When we still have
                // the concrete LangEnv and TPrepass here, snapshot in-bounds TV values before
                // attaching the semantic cell.  Missing/out-of-bounds TVs remain explicit
                // type-variable-env obligations.
                match x with
                | TV i ->
                    let globalTypeLen =
                        if obj.ReferenceEquals(s.env_global_type, null) then 0
                        else s.env_global_type.Length
                    let stackTypeLen =
                        if obj.ReferenceEquals(s.env_stack_type, null) then 0
                        else s.env_stack_type.Length
                    if i >= 0 && i < globalTypeLen then
                        EvalReplayValueStore.putTypeValue nodeId s.env_global_type.[i]
                        DiagJson.emit (
                            sprintf "{\"kind\":\"eval_worklist_direct_tv_cell_env_snapshot\",\"event\":\"semantic_cell_attach\",\"node_id\":%d,\"index\":%d,\"env\":\"global\",\"global_len\":%d,\"stack_len\":%d,\"site\":%s,\"single_flight\":1,\"next\":\"type_value_materialized\"}"
                                nodeId i globalTypeLen stackTypeLen (DiagJson.esc site))
                    elif i >= globalTypeLen && (i - globalTypeLen) >= 0 && (i - globalTypeLen) < stackTypeLen then
                        EvalReplayValueStore.putTypeValue nodeId s.env_stack_type.[i - globalTypeLen]
                        DiagJson.emit (
                            sprintf "{\"kind\":\"eval_worklist_direct_tv_cell_env_snapshot\",\"event\":\"semantic_cell_attach\",\"node_id\":%d,\"index\":%d,\"env\":\"stack\",\"global_len\":%d,\"stack_len\":%d,\"site\":%s,\"single_flight\":1,\"next\":\"type_value_materialized\"}"
                                nodeId i globalTypeLen stackTypeLen (DiagJson.esc site))
                    elif i >= globalTypeLen && stackTypeLen = 0 then
                        // ALPHA671: an empty type environment cannot satisfy a TV by lookup.
                        // Treat this as a free type metavariable, matching the existing
                        // alpha644 TFun.arg policy, rather than pinning a false env-missing
                        // terminal at top-level replay roots such as spiral.spi:2669.
                        EvalReplayValueStore.putTypeValue nodeId (YMetavar i)
                        DiagJson.emit (
                            sprintf "{\"kind\":\"eval_worklist_direct_tv_cell_free_metavar_snapshot\",\"event\":\"semantic_cell_attach\",\"node_id\":%d,\"index\":%d,\"global_len\":%d,\"stack_len\":%d,\"site\":%s,\"policy\":\"empty_type_env_tv_is_free_metavar\",\"single_flight\":1,\"next\":\"type_value_materialized_from_free_metavar\"}"
                                nodeId i globalTypeLen stackTypeLen (DiagJson.esc site))
                    else
                        DiagJson.emit (
                            sprintf "{\"kind\":\"eval_worklist_direct_tv_cell_env_snapshot_miss\",\"event\":\"semantic_cell_attach\",\"node_id\":%d,\"index\":%d,\"global_len\":%d,\"stack_len\":%d,\"site\":%s,\"single_flight\":1,\"next\":\"explicit_eval_worklist_type_variable_env_required\"}"
                                nodeId i globalTypeLen stackTypeLen (DiagJson.esc site))
                | _ -> ()
                evalCell "ty" typeShape0 nodeId site s
            let snapshotTypeVariableChildFromEnv (parentNodeId: int) (childNodeId: int) (role: string) (child: TPrepass) =
                match child with
                | TV i ->
                    let globalTypeLen =
                        if obj.ReferenceEquals(s.env_global_type, null) then 0
                        else s.env_global_type.Length
                    let stackTypeLen =
                        if obj.ReferenceEquals(s.env_stack_type, null) then 0
                        else s.env_stack_type.Length
                    match EvalReplayValueStore.putTypeVarEnvSnapshot childNodeId i s.env_global_type s.env_stack_type with
                    | Some (envName, _, _) ->
                        DiagJson.emit (
                            sprintf "{\"kind\":\"eval_worklist_type_fun_tv_child_env_snapshot\",\"event\":\"type_fun_child_register\",\"parent_node_id\":%d,\"child_node_id\":%d,\"role\":%s,\"index\":%d,\"env\":%s,\"global_len\":%d,\"stack_len\":%d,\"site\":%s,\"single_flight\":1,\"next\":\"type_value_materialized\"}"
                                parentNodeId childNodeId (DiagJson.esc role) i (DiagJson.esc envName) globalTypeLen stackTypeLen (DiagJson.esc site))
                    | None ->
                        if i >= globalTypeLen && stackTypeLen = 0 then
                            EvalReplayValueStore.putTypeValue childNodeId (YMetavar i)
                            DiagJson.emit (
                                sprintf "{\"kind\":\"eval_worklist_type_fun_tv_child_free_metavar_snapshot\",\"event\":\"type_fun_child_register\",\"parent_node_id\":%d,\"child_node_id\":%d,\"role\":%s,\"index\":%d,\"global_len\":%d,\"stack_len\":%d,\"site\":%s,\"policy\":\"empty_type_env_tv_is_free_metavar\",\"single_flight\":1,\"next\":\"type_value_materialized_from_free_metavar\"}"
                                    parentNodeId childNodeId (DiagJson.esc role) i globalTypeLen stackTypeLen (DiagJson.esc site))
                        else
                            DiagJson.emit (
                                sprintf "{\"kind\":\"eval_worklist_type_fun_tv_child_env_snapshot_miss\",\"event\":\"type_fun_child_register\",\"parent_node_id\":%d,\"child_node_id\":%d,\"role\":%s,\"index\":%d,\"global_len\":%d,\"stack_len\":%d,\"site\":%s,\"single_flight\":1,\"next\":\"explicit_eval_worklist_type_variable_env_required\"}"
                                    parentNodeId childNodeId (DiagJson.esc role) i globalTypeLen stackTypeLen (DiagJson.esc site))
                | _ -> ()
            // ALPHA409: split the literal backslash-n from alpha408 so strict F# sees the binding.
            // Type replay remains kind-local; term cells no longer satisfy a ty frontier.
            let rec registerReplayTy (nodeId: int) (expr: TPrepass) =
                let childType (label: string) (child: TPrepass) =
                    let childId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box child)
                    registerReplayTy childId child
                    match EvalReplayValueStore.tryType childId with
                    | Some value -> value
                    | None -> failwith ("type_fun_child_missing:" + label + ":" + evalNodeShapeTy child)
                match expr with
                | TV i ->
                    // TV is environment-dependent, so snapshot the current
                    // type environment when it is available instead of leaving a thunk
                    // that can be forced after another replay environment has reused
                    // the same AST node id.  Missing/out-of-bounds variables stay
                    // fail-closed through the old thunk and terminal TV diagnostic.
                    match EvalReplayValueStore.putTypeVarEnvSnapshot nodeId i s.env_global_type s.env_stack_type with
                    | Some _ -> ()
                    | None ->
                        let globalTypeLen =
                            if obj.ReferenceEquals(s.env_global_type, null) then 0
                            else s.env_global_type.Length
                        let stackTypeLen =
                            if obj.ReferenceEquals(s.env_stack_type, null) then 0
                            else s.env_stack_type.Length
                        if i >= globalTypeLen && stackTypeLen = 0 then
                            EvalReplayValueStore.putTypeValue nodeId (YMetavar i)
                            DiagJson.emit (
                                sprintf "{\"kind\":\"eval_worklist_register_ty_tv_free_metavar_snapshot\",\"event\":\"type_register\",\"node_id\":%d,\"index\":%d,\"global_len\":%d,\"stack_len\":%d,\"site\":%s,\"policy\":\"empty_type_env_tv_is_free_metavar\",\"single_flight\":1,\"next\":\"type_value_materialized_from_free_metavar\"}"
                                    nodeId i globalTypeLen stackTypeLen (DiagJson.esc site))
                        else
                            EvalReplayValueStore.putType nodeId (fun () -> vt s i)
                | TArrow'(scope,i,body) ->
                    EvalReplayValueStore.putType nodeId (fun () ->
                        assert (i = scope.ty.free_vars.Length)
                        YTypeFunction(body, HopacExtensions.A.map (vt s) scope.ty.free_vars, scope.term.stack_size, scope.ty.stack_size))
                | TLit(_,lit) -> EvalReplayValueStore.putType nodeId (fun () -> YLit lit)
                | TB _ -> EvalReplayValueStore.putType nodeId (fun () -> YB)
                | TExists -> EvalReplayValueStore.putType nodeId (fun () -> YExists)
                | TForall' _ -> EvalReplayValueStore.putType nodeId (fun () -> YForall)
                | TMetaV i -> EvalReplayValueStore.putType nodeId (fun () -> YMetavar i)
                // ALPHA394: the alpha393 log reached a clean type replay frontier
                // (TPrim/TFun) but stopped at explicit_eval_worklist_ty_stepper_required.
                // These constructors are exact type values.  Store conservative thunks so
                // the replay driver can resolve them through tryType; if recursive children
                // still trip a fuse, tryType returns None and the worklist remains closed.
                // ALPHA395: child constructors are registered recursively and read through
                // tryType, so TFun/TRecord do not invoke recursive ty from the replay driver.
                | TPrim a -> EvalReplayValueStore.putType nodeId (fun () -> YPrim a)
                | TSymbol(_,a) -> EvalReplayValueStore.putType nodeId (fun () -> YSymbol a)
                | TApply(_,a,b) ->
                    // ALPHA398: exact typed replay for type application.  Alpha397 could
                    // replay TFun/TRecord leaves but still stalled when the root was TApply.
                    // This mirrors ty_core_impl's TApply semantics but reads children from
                    // replay thunks first, so failures remain fail-closed via tryType -> None.
                    EvalReplayValueStore.putType nodeId (fun () ->
                        let aTy = childType "TApply.fn" a
                        let bTy = childType "TApply.arg" b
                        match aTy with
                        | YRecord fields ->
                            match bTy with
                            | YSymbol key ->
                                match fields |> Map.tryPick (fun (_, k) v -> if k = key then Some v else None) with
                                | Some value -> value
                                | None -> failwith ("type_apply_record_key_missing:" + key)
                            | got -> failwith ("type_apply_expected_symbol_for_record:" + show_ty got)
                        | YMetavar _ | YNominal _ | YApply _ as residualHead ->
                            YApply(residualHead, bTy)
                        | YTypeFunction(body,gl_ty,sz_term,sz_ty) ->
                            let s2 = { s with env_global_type = gl_ty; env_global_term = [||]; env_stack_type = Array.zeroCreate<_> sz_ty; env_stack_term = Array.zeroCreate<_> sz_term }
                            s2.env_stack_type.[0] <- bTy
                            ty s2 body
                        | got ->
                            failwith ("type_apply_expected_record_nominal_typefunction_or_metavar:" + show_ty got))
                | TNominal i -> EvalReplayValueStore.putType nodeId (fun () -> YNominal env.nominals.[i])
                | TPair(_,a,b) ->
                    let leftNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box a)
                    let rightNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box b)
                    registerReplayTy leftNodeId a
                    registerReplayTy rightNodeId b
                    EvalReplayValueStore.putTypePairSpine nodeId {
                        leftNodeId = leftNodeId
                        leftShape = evalNodeShapeTy a
                        rightNodeId = rightNodeId
                        rightShape = evalNodeShapeTy b
                    }
                    EvalReplayValueStore.putType nodeId (fun () -> YPair(childType "TPair.left" a, childType "TPair.right" b))
                | TFun(a,b,t) ->
                    let argNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box a)
                    let bodyNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box b)
                    snapshotTypeVariableChildFromEnv nodeId argNodeId "tfun_arg" a
                    snapshotTypeVariableChildFromEnv nodeId bodyNodeId "tfun_body" b
                    registerReplayTy argNodeId a
                    registerReplayTy bodyNodeId b
                    match a with
                    | TV i ->
                        let globalTypeLen =
                            if obj.ReferenceEquals(s.env_global_type, null) then 0
                            else s.env_global_type.Length
                        let stackTypeLen =
                            if obj.ReferenceEquals(s.env_stack_type, null) then 0
                            else s.env_stack_type.Length
                        if i >= globalTypeLen && stackTypeLen = 0 then
                            // ALPHA644: runtime 643 exposed TFun.arg TVs in trace.spi:117
                            // with no ambient type env.  Inside a TFun replay child this is
                            // not an arbitrary concrete type: it is the function's free type
                            // variable witness.  Use a YMetavar placeholder, not a concrete Ty,
                            // so downstream annotations can become structured YFun instead of
                            // collapsing to JPMethodUnknownRet(par).
                            EvalReplayValueStore.putTypeValue argNodeId (YMetavar i)
                            DiagJson.emit (
                                sprintf "{\"kind\":\"eval_worklist_tfun_arg_tv_free_metavar_snapshot\",\"event\":\"type_fun_child_register\",\"parent_node_id\":%d,\"child_node_id\":%d,\"role\":\"tfun_arg_free_metavar\",\"index\":%d,\"global_len\":%d,\"stack_len\":%d,\"site\":%s,\"single_flight\":1,\"next\":\"type_value_materialized_from_free_metavar\"}"
                                    nodeId argNodeId i globalTypeLen stackTypeLen (DiagJson.esc site))
                    | _ -> ()
                    match b with
                    | TV i ->
                        let globalTypeLen =
                            if obj.ReferenceEquals(s.env_global_type, null) then 0
                            else s.env_global_type.Length
                        let stackTypeLen =
                            if obj.ReferenceEquals(s.env_stack_type, null) then 0
                            else s.env_stack_type.Length
                        if i = globalTypeLen && stackTypeLen = 0 then
                            EvalReplayValueStore.putType bodyNodeId (fun () -> childType "TFun.body_immediate_binder" a)
                            DiagJson.emit (
                                sprintf "{\"kind\":\"eval_worklist_tfun_body_tv_binder_snapshot\",\"event\":\"type_fun_child_register\",\"parent_node_id\":%d,\"child_node_id\":%d,\"role\":\"tfun_body_immediate_binder\",\"index\":%d,\"global_len\":%d,\"stack_len\":%d,\"arg_node_id\":%d,\"site\":%s,\"single_flight\":1,\"next\":\"type_value_materialized_from_arg_binder\"}"
                                    nodeId bodyNodeId i globalTypeLen stackTypeLen argNodeId (DiagJson.esc site))
                    | _ -> ()
                    EvalReplayValueStore.putTypeFunSpine nodeId {
                        argNodeId = argNodeId
                        argShape = evalNodeShapeTy a
                        bodyNodeId = bodyNodeId
                        bodyShape = evalNodeShapeTy b
                        funType = t
                    }
                    EvalReplayValueStore.putType nodeId (fun () -> YFun(childType "TFun.arg" a, childType "TFun.body" b,t))
                | TModule a ->
                    EvalReplayValueStore.putType nodeId (fun () ->
                        YRecord(
                            a
                            |> Seq.mapi (fun i (KeyValue (k, v)) -> (i, k), childType ("TModule." + k) v)
                            |> Map.ofSeq))
                | TRecord(_,a) -> EvalReplayValueStore.putType nodeId (fun () -> YRecord(Map.map (fun k v -> childType (sprintf "TRecord.%A" k) v) a))
                | TArray a -> EvalReplayValueStore.putType nodeId (fun () -> YArray(childType "TArray.item" a))
                | TLayout(a,b) -> EvalReplayValueStore.putType nodeId (fun () -> YLayout(childType "TLayout.inner" a,b))
                // ALPHA412: conservative replay thunks for complex type forms that the
                // runtime frontier now exposes after active kind-local fuse reset.
                // These stay fail-closed through tryType: if the normal evaluator still
                // trips a JP/fuse cycle, the replay driver keeps the cell partial instead
                // of manufacturing a value.
                | TMacro(r,items) ->
                    // ALPHA433: replay TMacro without re-entering ty_core_impl on the same root.
                    // Alpha432 ran for minutes repeating ty_shape_dispatch_dispatched:TMacro at base.spi:67:
                    // the old thunk was `ty s expr`, so tryType re-entered the same fused type node and
                    // stayed semantic_step_partial forever. Build the macro from already-registered child
                    // type values instead; if a child is still unavailable, tryType remains fail-closed.
                    let macro_s = add_trace s r
                    let macroChildType label child =
                        let childId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box child)
                        registerReplayTy childId child
                        match EvalReplayValueStore.tryType childId with
                        | Some value -> value
                        | None -> failwith ("tmacro_child_missing:" + label + ":" + evalNodeShapeTy child)
                    EvalReplayValueStore.putType nodeId (fun () ->
                        YMacro(
                            items
                            |> List.mapi (fun i -> function
                                | TMText text -> PartEvalMacro.Text text
                                | TMType child -> PartEvalMacro.Type(macroChildType (sprintf "TMacro.type.%d" i) child)
                                | TMLitType child -> PartEvalMacro.TypeLit(macroChildType (sprintf "TMacro.lit.%d" i) child |> assert_ty_lit macro_s))))
                | TTerm(_,termExpr) ->
                    // ALPHA487: do not make TTerm a self-recursive type thunk.
                    // Register its embedded term as an explicit child and convert
                    // only after term_replay_driver has materialized the term value.
                    let termNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box termExpr)
                    let freshTTermEnv () =
                        { s with seq = ResizeArray(); cse = Dictionary(HashIdentity.Structural) :: s.cse }
                    EvalReplayValueStore.putTerm termNodeId (fun () -> term (freshTTermEnv()) termExpr)
                    EvalReplayValueStore.putTypeTermSpine nodeId {
                        termNodeId = termNodeId
                        termShape = evalNodeShapeTerm termExpr
                    }
                    EvalReplayValueStore.putType nodeId (fun () ->
                        match EvalReplayValueStore.tryTerm termNodeId with
                        | Some termValue -> data_to_ty (freshTTermEnv()) termValue
                        | None -> failwith ("tterm_term_value_missing:" + evalNodeShapeTerm termExpr))
                | TJoinPoint'(r,scope,body) ->
                    // ALPHA649: replay the type join-point body, not the join-point
                    // wrapper itself.  Runtime 648 reached a TJoinPoint' terminal at
                    // core/base.spi:16 because the old thunk re-entered ty s expr and
                    // rebuilt the same JP wait/fuse frontier.  This mirrors the real
                    // evaluator's scoped environment but skips the JP cache wrapper;
                    // failures still flow through tryTypeDetailed fail-closed.
                    let bodyNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box body)
                    let env_global_type = scope.ty.free_vars |> HopacExtensions.A.map (fun i -> vt s i)
                    let env_global_term = scope.term.free_vars |> HopacExtensions.A.map (fun i -> v s i)
                    let s2 : LangEnv =
                        { s with
                            trace = r :: s.trace
                            seq = ResizeArray()
                            cse = [Dictionary(HashIdentity.Structural)]
                            unions = Map.empty
                            i = ref 0
                            env_global_type = env_global_type
                            env_global_term = env_global_term
                            env_stack_type = Array.zeroCreate<_> scope.ty.stack_size
                            env_stack_term = Array.zeroCreate<_> scope.term.stack_size }
                    EvalReplayValueStore.putType bodyNodeId (fun () -> ty (rename_global_term s2) body)
                    EvalReplayValueStore.putTypeJoinPointSpine nodeId {
                        bodyNodeId = bodyNodeId
                        bodyShape = evalNodeShapeTy body
                    }
                    EvalReplayValueStore.putType nodeId (fun () ->
                        match EvalReplayValueStore.tryType bodyNodeId with
                        | Some bodyTy -> bodyTy
                        | None -> failwith ("tjoinpoint_body_type_missing:" + evalNodeShapeTy body))
                | TTypecase _ | TUnion _ ->
                    EvalReplayValueStore.putType nodeId (fun () -> ty s expr)
                | _ -> ()
            let returnReplayTypeIfComplete (event: string) (nodeIdReturn: int) (frameOpt: EvalWorklist.Frame option) =
                // ALPHA403: runBounded can return the pre-replay continuation_envelope even though
                // the synchronous replay driver committed semantic_root_complete before control
                // returns to the caller.  Trust the canonical EvalWorklist witness as well as the
                // stale local frame, otherwise the catch path burns retry budget on a completed TFun.
                let complete =
                    match frameOpt with
                    | Some frame when EvalWorklist.frameReplayCompleteKind "ty" frame -> true
                    | Some _ -> EvalWorklist.hasReplayCompleteKind "ty"
                    | None -> EvalWorklist.hasReplayCompleteKind "ty"
                if complete then
                    match EvalReplayValueStore.tryType nodeIdReturn with
                    | Some value ->
                        // ALPHA929: direct replay returns are existing root-complete values and must refresh JP progress.
                        System.Threading.Interlocked.Exchange(&jp_last_progress_ms, peval_sw.ElapsedMilliseconds) |> ignore
                        DiagJson.emit (
                            sprintf "{\"kind\":\"eval_worklist_root_complete_replay_progress_marked\",\"event\":%s,\"scope\":\"direct_ty_replay_return\",\"status\":\"semantic_root_complete\",\"kind2\":\"ty\",\"shape\":%s,\"single_flight\":1,\"next\":\"watchdog_progress_refreshed\"}"
                                (DiagJson.esc event) (DiagJson.esc (evalNodeShapeTy x)))
                        DiagJson.emit (
                            sprintf "{\"kind\":\"eval_worklist_direct_cycle_replay_return\",\"event\":%s,\"status\":\"semantic_root_complete\",\"shape\":%s,\"single_flight\":1,\"next\":\"return_ty_value\"}"
                                (DiagJson.esc event) (DiagJson.esc (evalNodeShapeTy x)))
                        DiagJson.emit (
                            sprintf "{\"kind\":\"eval_worklist_fuse_clear_after_replay_return\",\"event\":%s,\"status\":\"semantic_root_complete\",\"shape\":%s,\"single_flight\":1,\"next\":\"return_ty_value\"}"
                                (DiagJson.esc event) (DiagJson.esc (evalNodeShapeTy x)))
                        TermCycleFuse.reset ()
                        raise (EvalReplayTyReturn value)
                    | None -> ()
            if TermCycleFuse.isTripped() then
                let fuseKindKey0, fuseKindSite0, _, _, _, _ = TermCycleFuse.describe()
                let activeFuseKind =
                    if fuseKindKey0.StartsWith("ty:") || fuseKindSite0.StartsWith("ty@") then "ty" else "term"
                if activeFuseKind <> "ty" then
                    DiagJson.emit (
                        sprintf "{\"kind\":\"eval_worklist_kind_local_active_reset\",\"event\":\"ty_entry_global_fuse\",\"active_kind\":%s,\"requested_kind\":\"ty\",\"single_flight\":1,\"next\":\"continue_ty_eval\"}"
                            (DiagJson.esc activeFuseKind))
                    EvalWorklist.parkActiveAndSelectKind "ty" |> ignore
                    TermCycleFuse.reset()
                else
                    match EvalReplayValueStore.tryTypeSourceValue typeSourceKey0 with
                    | Some value ->
                        DiagJson.emit (
                            sprintf "{\"kind\":\"eval_worklist_type_source_value_replay_return\",\"event\":\"ty_entry_global_fuse\",\"status\":\"semantic_root_complete\",\"shape\":%s,\"source_key\":%s,\"single_flight\":1,\"next\":\"return_ty_value\"}"
                                (DiagJson.esc typeShape0) (DiagJson.esc typeSourceKey0))
                        TermCycleFuse.reset ()
                        raise (EvalReplayTyReturn value)
                    | None ->
                        let nodeId0 = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box x)
                        registerReplayTy nodeId0 x
                        EvalWorklist.ensureCaptured "ty_entry_global_fuse" |> ignore
                        EvalWorklist.attachSemanticCell "ty_entry" (semanticCellForTy nodeId0)
                        let frameOpt = EvalWorklist.ensureCapturedAndRun "ty_entry_global_fuse" "ty_entry" 8
                        let globalReplayComplete =
                            match frameOpt with
                            | Some frame when EvalWorklist.frameReplayCompleteKind "ty" frame -> true
                            | Some _ -> EvalWorklist.hasReplayCompleteKind "ty"
                            | None -> EvalWorklist.hasReplayCompleteKind "ty"
                        if globalReplayComplete then
                            let shape0 = typeShape0
                            let k0, s0, d0, g0, re0, max0 = TermCycleFuse.describe()
                            let replayReturnMsg =
                                sprintf "%s: global type replay return suppressed after pinned terminal first_key=%s first_site=%s first_depth=%d gen=%d re=%d/%d" EJPCodes.EJP0011 k0 s0 d0 g0 re0 max0
                            match EvalWorklist.trySuppressGlobalFuseReplayReturnForPinnedTerminal "ty_entry_global_fuse" "ty" shape0 replayReturnMsg with
                            | Some msg -> raise_type_error s msg
                            | None ->
                                match EvalReplayValueStore.tryType nodeId0 with
                                | Some value ->
                                    EvalReplayValueStore.putTypeSourceValue typeSourceKey0 value
                                    // ALPHA929: global-fuse type replay returns are real progress for the JP watchdog.
                                    System.Threading.Interlocked.Exchange(&jp_last_progress_ms, peval_sw.ElapsedMilliseconds) |> ignore
                                    let sourceStoreRepeat =
                                        jp_note_source_value_store (sprintf "ty|ty_entry_global_fuse|global_fuse_replay_return_store|%s|%s" shape0 typeSourceKey0)
                                    if jp_should_emit_source_value_store sourceStoreRepeat then
                                        DiagJson.emit (
                                            sprintf "{\"kind\":\"eval_worklist_root_complete_replay_progress_marked\",\"event\":\"ty_entry_global_fuse\",\"scope\":\"global_fuse_ty_return\",\"status\":\"semantic_root_complete\",\"kind2\":\"ty\",\"shape\":%s,\"repeat_count\":%d,\"sampled\":1,\"single_flight\":1,\"next\":\"watchdog_progress_refreshed\"}"
                                                (DiagJson.esc shape0) sourceStoreRepeat)
                                        DiagJson.emit (
                                            sprintf "{\"kind\":\"eval_worklist_type_source_value_stored\",\"event\":\"ty_entry_global_fuse\",\"status\":\"semantic_root_complete\",\"shape\":%s,\"source_key\":%s,\"policy\":\"global_fuse_replay_return_store\",\"repeat_count\":%d,\"sampled\":1,\"single_flight\":1,\"next\":\"return_ty_value\"}"
                                                (DiagJson.esc shape0) (DiagJson.esc typeSourceKey0) sourceStoreRepeat)
                                    DiagJson.emit (
                                        sprintf "{\"kind\":\"eval_worklist_global_fuse_replay_return\",\"event\":\"ty_entry_global_fuse\",\"status\":\"semantic_root_complete\",\"shape\":%s,\"single_flight\":1,\"next\":\"return_ty_value\"}"
                                            (DiagJson.esc shape0))
                                    DiagJson.emit (
                                        sprintf "{\"kind\":\"eval_worklist_fuse_clear_after_replay_return\",\"event\":\"ty_entry_global_fuse\",\"status\":\"semantic_root_complete\",\"shape\":%s,\"single_flight\":1,\"next\":\"return_ty_value\"}"
                                            (DiagJson.esc shape0))
                                    TermCycleFuse.reset ()
                                    raise (EvalReplayTyReturn value)
                                | None ->
                                    raise_type_error s (sprintf "%s: global term-cycle fuse completed but replay type value was missing first_key=%s first_site=%s first_depth=%d gen=%d re=%d/%d" EJPCodes.EJP0011 k0 s0 d0 g0 re0 max0)
                        else
                            if EvalWorklist.hasReplayCompleteOtherKind "ty" then
                                DiagJson.emit "{\"kind\":\"eval_worklist_kind_local_fuse_reset\",\"event\":\"ty_entry_global_fuse\",\"completed_kind\":\"other\",\"requested_kind\":\"ty\",\"single_flight\":1,\"next\":\"continue_ty_eval\"}"
                                EvalWorklist.parkActiveAndSelectKind "ty" |> ignore
                                TermCycleFuse.reset()
                            else
                                let k0, s0, d0, g0, re0, max0 = TermCycleFuse.describe()
                                let tyLiveReplayPayload =
                                    EvalWorklist.pendingCount() > 0
                                    && (EvalWorklist.replayQueueDepth() > 0
                                        || EvalWorklist.replayDriverActiveDepthValue() > 0
                                        || EvalWorklist.hasProgressYield()
                                        || EvalReplayValueStore.hasDeferredReplayCell()
                                        || EvalWorklist.semanticPayloadStatus() = "cell"
                                        || EvalWorklist.semanticPayloadStatus().Contains("continuation"))
                                let orphanTyGlobalFuseWithLiveReplay =
                                    System.String.IsNullOrWhiteSpace k0
                                    && System.String.IsNullOrWhiteSpace s0
                                    && d0 = 0
                                    && tyLiveReplayPayload
                                let keyedTyParentContinuationFuseWithRunnableReplay =
                                    (not (System.String.IsNullOrWhiteSpace k0))
                                    && (not (System.String.IsNullOrWhiteSpace s0))
                                    && tyLiveReplayPayload
                                if orphanTyGlobalFuseWithLiveReplay then
                                    let orphanKey = sprintf "ty|%s|%s|cursor=%d|pending=%d|orphan_global_fuse" typeShape0 site 0 (EvalWorklist.pendingCount())
                                    let orphanRepeat = jp_note_global_fuse_partial_current orphanKey
                                    let orphanCap = 96
                                    let orphanDecision =
                                        if orphanRepeat > orphanCap then
                                            EvalWorklist.OrphanGlobalFuseBlocked(orphanRepeat, orphanCap)
                                        else
                                            EvalWorklist.OrphanGlobalFuseDeferred(orphanRepeat, orphanCap)
                                    let orphanStatus = EvalWorklist.globalFuseReplayDecisionStatusText orphanDecision
                                    let orphanRepeat = EvalWorklist.globalFuseReplayDecisionRepeat orphanDecision
                                    let orphanCap = EvalWorklist.globalFuseReplayDecisionCap orphanDecision
                                    match orphanDecision with
                                    | EvalWorklist.OrphanGlobalFuseBlocked _ ->
                                        DiagJson.emit (
                                            sprintf "{\"kind\":\"eval_worklist_ty_orphan_global_fuse_live_replay_repeat_blocked\",\"event\":\"ty_entry_global_fuse\",\"status\":%s,\"shape\":%s,\"site\":%s,\"pending\":%d,\"queue_depth\":%d,\"active_depth\":%d,\"payload_status\":%s,\"repeat\":%d,\"cap\":%d,%s,\"single_flight\":1,\"next\":\"typed_terminal_after_bounded_ty_orphan_global_fuse_replay\"}"
                                                (DiagJson.esc orphanStatus) (DiagJson.esc typeShape0) (DiagJson.esc site) (EvalWorklist.pendingCount()) (EvalWorklist.replayQueueDepth()) (EvalWorklist.replayDriverActiveDepthValue()) (DiagJson.esc (EvalWorklist.semanticPayloadStatus())) orphanRepeat orphanCap (EvalWorklist.globalFuseTraceJson()))
                                        let msg = sprintf "%s: global term-cycle fuse already tripped first_key=%s first_site=%s first_depth=%d gen=%d re=%d/%d; aborting ty worker before StackOverflow" EJPCodes.EJP0011 k0 s0 d0 g0 re0 max0
                                        let msg = EvalWorklist.retargetGlobalFuseAbortMessage "ty_entry_global_fuse" "ty" msg
                                        raise_type_error s msg
                                    | EvalWorklist.OrphanGlobalFuseDeferred _ ->
                                        DiagJson.emit (
                                            sprintf "{\"kind\":\"eval_worklist_ty_orphan_global_fuse_live_replay_deferred\",\"event\":\"ty_entry_global_fuse\",\"status\":%s,\"shape\":%s,\"site\":%s,\"pending\":%d,\"queue_depth\":%d,\"active_depth\":%d,\"payload_status\":%s,\"repeat\":%d,\"cap\":%d,%s,\"policy\":\"empty_ty_global_fuse_descriptor_cannot_outvote_live_replay_payload\",\"single_flight\":1,\"next\":\"fallthrough_ty_eval\"}"
                                                (DiagJson.esc orphanStatus) (DiagJson.esc typeShape0) (DiagJson.esc site) (EvalWorklist.pendingCount()) (EvalWorklist.replayQueueDepth()) (EvalWorklist.replayDriverActiveDepthValue()) (DiagJson.esc (EvalWorklist.semanticPayloadStatus())) orphanRepeat orphanCap (EvalWorklist.globalFuseTraceJson()))
                                        EvalWorklist.parkActiveAndSelectKind "ty" |> ignore
                                        TermCycleFuse.reset()
                                    | _ -> ()
                                elif keyedTyParentContinuationFuseWithRunnableReplay then
                                    let parentFuseShape = typeShape0
                                    let parentFuseActiveDepth = EvalWorklist.replayDriverActiveDepthValue()
                                    let parentFuseHighPressure =
                                        parentFuseActiveDepth >= 16
                                        || (BigStack.isActive()
                                            && parentFuseActiveDepth >= 1
                                            && EvalWorklist.replayQueueDepth() > 0
                                            && EvalWorklist.pendingCount() > 0)
                                    let parentFuseRepeatKey =
                                        // ALPHA998: mirror alpha995's term-side high-pressure key for ty.
                                        // Runtime 997 showed 59 ty global-fuse blocked/deferred events, mostly
                                        // around base/backend continuations, while first_key churn kept typed
                                        // obligations alive after the bounded terminal was already meaningful.
                                        // In the high-pressure band, key by current type shape+site and use cap=2.
                                        if parentFuseHighPressure then
                                            sprintf "ty|%s|%s|active_depth_parent_continuation_global_fuse_site_pressure"
                                                parentFuseShape site
                                        else
                                            sprintf "ty|%s|%s|%s|parent_continuation_global_fuse_site_pressure"
                                                k0 s0 site
                                    let parentFuseRepeat = jp_note_global_fuse_partial_current parentFuseRepeatKey
                                    let parentFuseCap =
                                        if parentFuseHighPressure then 2
                                        elif EvalWorklist.replayQueueDepth() > 0 && EvalWorklist.pendingCount() > 0 then 16
                                        else 64
                                    let parentFuseCapExhausted = parentFuseRepeat > parentFuseCap
                                    let parentFuseRunnableReplayStillLive =
                                        parentFuseCapExhausted
                                        && EvalWorklist.pendingCount() > 0
                                        && (EvalWorklist.replayQueueDepth() > 0 || EvalWorklist.replayDriverActiveDepthValue() > 0)
                                        && ((not (EvalWorklist.hasReplayComplete())) || EvalWorklist.hasReplayCompleteWriteWitness())
                                    let parentFuseHighActiveReplayStarved =
                                        parentFuseRunnableReplayStillLive
                                        && parentFuseRepeat > (parentFuseCap * 8)
                                        && EvalWorklist.replayDriverActiveDepthValue() >= 16
                                    let parentFuseLowActiveReplayStarved =
                                        parentFuseRunnableReplayStillLive
                                        && parentFuseRepeat > (parentFuseCap * 4)
                                        && EvalWorklist.replayQueueDepth() <= 1
                                        && EvalWorklist.replayDriverActiveDepthValue() <= 4
                                    let parentFuseMidActiveNoQueueReplayStarved =
                                        parentFuseRunnableReplayStillLive
                                        && parentFuseRepeat > (parentFuseCap * 8)
                                        && EvalWorklist.replayQueueDepth() = 0
                                        && EvalWorklist.replayDriverActiveDepthValue() >= 5
                                        && EvalWorklist.replayDriverActiveDepthValue() <= 8
                                    let parentFuseMidActiveQueuedReplayStarved =
                                        parentFuseRunnableReplayStillLive
                                        && parentFuseRepeat > (parentFuseCap * 4)
                                        && EvalWorklist.replayQueueDepth() <= 2
                                        && EvalWorklist.replayDriverActiveDepthValue() >= 5
                                        && EvalWorklist.replayDriverActiveDepthValue() <= 8
                                    let parentFuseLowCapMidActiveQueuedReplayPlateau =
                                        parentFuseRunnableReplayStillLive
                                        && parentFuseCap <= 2
                                        && parentFuseRepeat >= (parentFuseCap * 4)
                                        && EvalWorklist.replayQueueDepth() <= 2
                                        && EvalWorklist.replayDriverActiveDepthValue() >= 5
                                        && EvalWorklist.replayDriverActiveDepthValue() <= 8
                                    let parentFuseQueuedPlateauReplayStarved =
                                        parentFuseRunnableReplayStillLive
                                        && parentFuseRepeat > (parentFuseCap * 8)
                                        && EvalWorklist.replayQueueDepth() <= 2
                                        && EvalWorklist.replayDriverActiveDepthValue() >= 9
                                        && EvalWorklist.replayDriverActiveDepthValue() <= 15
                                    let parentFuseLowCapHighActiveQueuedReplayPlateau =
                                        parentFuseRunnableReplayStillLive
                                        && parentFuseCap <= 2
                                        && parentFuseRepeat >= (parentFuseCap + 1)
                                        && EvalWorklist.replayQueueDepth() <= 2
                                        && EvalWorklist.replayDriverActiveDepthValue() >= 16
                                    let parentFuseMidActiveQueuedSlowRepeatPlateau =
                                        parentFuseRunnableReplayStillLive
                                        && parentFuseCap >= 16
                                        && parentFuseRepeat >= 4
                                        && EvalWorklist.replayQueueDepth() <= 1
                                        && EvalWorklist.replayDriverActiveDepthValue() >= 5
                                        && EvalWorklist.replayDriverActiveDepthValue() <= 8
                                    let parentFuseRunnableReplayStarved =
                                        parentFuseHighActiveReplayStarved || parentFuseLowActiveReplayStarved || parentFuseMidActiveNoQueueReplayStarved || parentFuseMidActiveQueuedReplayStarved || parentFuseLowCapMidActiveQueuedReplayPlateau || parentFuseQueuedPlateauReplayStarved || parentFuseLowCapHighActiveQueuedReplayPlateau || parentFuseMidActiveQueuedSlowRepeatPlateau
                                    let parentFuseDecision =
                                        if parentFuseRunnableReplayStarved then
                                            EvalWorklist.ParentContinuationFuseBlocked(parentFuseRepeat, parentFuseCap)
                                        elif parentFuseCapExhausted && not parentFuseRunnableReplayStillLive then
                                            EvalWorklist.ParentContinuationFuseBlocked(parentFuseRepeat, parentFuseCap)
                                        else
                                            EvalWorklist.ParentContinuationFuseDeferred(parentFuseRepeat, parentFuseCap)
                                    if parentFuseRunnableReplayStillLive then
                                        DiagJson.emit (
                                            sprintf "{\"kind\":\"eval_worklist_ty_global_fuse_terminal_deferred_after_cap_due_live_replay\",\"event\":\"ty_entry_global_fuse\",\"shape\":%s,\"site\":%s,\"first_key\":%s,\"first_site\":%s,\"first_depth\":%d,\"pending\":%d,\"queue_depth\":%d,\"active_depth\":%d,\"payload_status\":%s,\"repeat\":%d,\"cap\":%d,%s,\"starved\":%b,\"policy\":\"do_not_pin_rank80_global_fuse_while_replay_runnable_until_lowcap_midqueued_or_high8_low_midqueued_or_queued_plateau_starvation_bound\",\"single_flight\":1,\"next\":\"continue_ty_replay_driver_or_emit_starvation_terminal\"}"
                                                (DiagJson.esc typeShape0) (DiagJson.esc site) (DiagJson.esc k0) (DiagJson.esc s0) d0 (EvalWorklist.pendingCount()) (EvalWorklist.replayQueueDepth()) (EvalWorklist.replayDriverActiveDepthValue()) (DiagJson.esc (EvalWorklist.semanticPayloadStatus())) parentFuseRepeat parentFuseCap (EvalWorklist.globalFuseTraceJson()) parentFuseRunnableReplayStarved)
                                    if parentFuseLowCapHighActiveQueuedReplayPlateau then
                                        DiagJson.emit (
                                            sprintf "{\"kind\":\"eval_worklist_ty_lowcap_high_active_queued_global_fuse_plateau_bounded\",\"event\":\"ty_entry_global_fuse\",\"shape\":%s,\"site\":%s,\"first_key\":%s,\"first_site\":%s,\"first_depth\":%d,\"pending\":%d,\"queue_depth\":%d,\"active_depth\":%d,\"repeat\":%d,\"cap\":%d,%s,\"policy\":\"lowcap_high_active_queued_plateau_beats_manual_ctrl_c\",\"single_flight\":1,\"next\":\"explicit_eval_worklist_ty_live_global_fuse_starvation_required\"}"
                                                (DiagJson.esc typeShape0) (DiagJson.esc site) (DiagJson.esc k0) (DiagJson.esc s0) d0 (EvalWorklist.pendingCount()) (EvalWorklist.replayQueueDepth()) (EvalWorklist.replayDriverActiveDepthValue()) parentFuseRepeat parentFuseCap (EvalWorklist.globalFuseTraceJson()))
                                    if parentFuseRunnableReplayStarved then
                                        DiagJson.emit (
                                            sprintf "{\"kind\":\"eval_worklist_ty_live_global_fuse_starvation_bounded\",\"event\":\"ty_entry_global_fuse\",\"shape\":%s,\"site\":%s,\"first_key\":%s,\"first_site\":%s,\"first_depth\":%d,\"pending\":%d,\"queue_depth\":%d,\"active_depth\":%d,\"repeat\":%d,\"cap\":%d,%s,\"policy\":\"bounded_starvation_terminal_beats_manual_ctrl_c\",\"single_flight\":1,\"next\":\"explicit_eval_worklist_ty_live_global_fuse_starvation_required\"}"
                                                (DiagJson.esc typeShape0) (DiagJson.esc site) (DiagJson.esc k0) (DiagJson.esc s0) d0 (EvalWorklist.pendingCount()) (EvalWorklist.replayQueueDepth()) (EvalWorklist.replayDriverActiveDepthValue()) parentFuseRepeat parentFuseCap (EvalWorklist.globalFuseTraceJson()))
                                    let parentFuseStatus = EvalWorklist.globalFuseReplayDecisionStatusText parentFuseDecision
                                    let parentFuseRepeat = EvalWorklist.globalFuseReplayDecisionRepeat parentFuseDecision
                                    let parentFuseCap = EvalWorklist.globalFuseReplayDecisionCap parentFuseDecision
                                    match parentFuseDecision with
                                    | EvalWorklist.ParentContinuationFuseBlocked _
                                    | EvalWorklist.OrphanGlobalFuseBlocked _ ->
                                        DiagJson.emit (
                                            sprintf "{\"kind\":\"eval_worklist_ty_global_fuse_parent_continuation_cycle_blocked\",\"event\":\"ty_entry_global_fuse\",\"status\":%s,\"shape\":%s,\"site\":%s,\"first_key\":%s,\"first_site\":%s,\"first_depth\":%d,\"pending\":%d,\"queue_depth\":%d,\"active_depth\":%d,\"payload_status\":%s,\"repeat\":%d,\"cap\":%d,%s,\"single_flight\":1,\"next\":\"typed_terminal_after_bounded_ty_parent_continuation_global_fuse\"}"
                                                (DiagJson.esc parentFuseStatus) (DiagJson.esc typeShape0) (DiagJson.esc site) (DiagJson.esc k0) (DiagJson.esc s0) d0 (EvalWorklist.pendingCount()) (EvalWorklist.replayQueueDepth()) (EvalWorklist.replayDriverActiveDepthValue()) (DiagJson.esc (EvalWorklist.semanticPayloadStatus())) parentFuseRepeat parentFuseCap (EvalWorklist.globalFuseTraceJson()))
                                        EvalWorklist.pinSemanticTerminalContract "ty_entry_global_fuse" "ty" parentFuseStatus k0 site d0 parentFuseRepeat parentFuseCap "bounded_ty_parent_continuation_global_fuse"
                                        let msg = sprintf "%s: global term-cycle fuse already tripped first_key=%s first_site=%s first_depth=%d gen=%d re=%d/%d; ty parent-continuation replay cap exhausted before StackOverflow" EJPCodes.EJP0011 k0 s0 d0 g0 re0 max0
                                        let msg = EvalWorklist.retargetGlobalFuseAbortMessage "ty_entry_global_fuse" "ty" msg
                                        raise_type_error s msg
                                    | EvalWorklist.ParentContinuationFuseDeferred _
                                    | EvalWorklist.OrphanGlobalFuseDeferred _ ->
                                        DiagJson.emit (
                                            sprintf "{\"kind\":\"eval_worklist_ty_global_fuse_parent_continuation_cycle_deferred\",\"event\":\"ty_entry_global_fuse\",\"status\":%s,\"shape\":%s,\"site\":%s,\"first_key\":%s,\"first_site\":%s,\"first_depth\":%d,\"pending\":%d,\"queue_depth\":%d,\"active_depth\":%d,\"payload_status\":%s,\"repeat\":%d,\"cap\":%d,%s,\"policy\":\"typed_global_fuse_cannot_outvote_runnable_parent_continuation_replay\",\"single_flight\":1,\"next\":\"fallthrough_ty_eval\"}"
                                                (DiagJson.esc parentFuseStatus) (DiagJson.esc typeShape0) (DiagJson.esc site) (DiagJson.esc k0) (DiagJson.esc s0) d0 (EvalWorklist.pendingCount()) (EvalWorklist.replayQueueDepth()) (EvalWorklist.replayDriverActiveDepthValue()) (DiagJson.esc (EvalWorklist.semanticPayloadStatus())) parentFuseRepeat parentFuseCap (EvalWorklist.globalFuseTraceJson()))
                                        EvalWorklist.parkActiveAndSelectKind "ty" |> ignore
                                        TermCycleFuse.reset()
                                else
                                    let msg = sprintf "%s: global term-cycle fuse already tripped first_key=%s first_site=%s first_depth=%d gen=%d re=%d/%d; aborting ty worker before StackOverflow" EJPCodes.EJP0011 k0 s0 d0 g0 re0 max0
                                    let msg = EvalWorklist.retargetGlobalFuseAbortMessage "ty_entry_global_fuse" "ty" msg
                                    raise_type_error s msg
            let depth = RecursionTracker.enter site
            use _rec_guard = { new System.IDisposable with member _.Dispose() = RecursionTracker.exit() }
    

            // Cycle guards: detect infinite re-entrancy into the same expression
            let nodeObj = box x
            let nodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode nodeObj
            registerReplayTy nodeId x
            let reCount = EvalCycleGuard.enter nodeObj
            let (a0,b0) = r0.range
            let nodeKey = sprintf "%s:%d:%d-%d:%d" r0.path a0.line a0.character b0.line b0.character
            let reKey = EvalCycleGuardKey.enter nodeKey

            use _cycle_guard = { new System.IDisposable with member _.Dispose() = EvalCycleGuard.exit nodeObj }
            use _cycle_guard_key = { new System.IDisposable with member _.Dispose() = EvalCycleGuardKey.exit nodeKey }

    

            // Re-entrancy limits: keep them bounded so real cycles fail fast (and avoid multi-minute JP stalls).
            // These handle legitimate re-entrancy from staging loops (e.g., listm'.spi)
            let invNow = CacheGeneration.invalidationCount()
            let seqNow = CacheGeneration.isSequentialRequested()
            let max_reentry_base = EvalFallbackPolicy.maxReentry seqNow invNow depth
            let max_reentry = max_reentry_base // alpha316/326: no BigStack multiplier; forced sequential gets a centralized legacy budget
            let max_reentry_key = max_reentry
            let warn_reentry = EvalFallbackPolicy.warnReentry max_reentry_base
    

            let hashSnapShort () =
                EvalCycleGuard.snapshotHashes 12 |> Seq.map string |> String.concat ","
            let keySnapShort () =
                EvalCycleGuardKey.snapshotKeys 12 |> String.concat " | "
            if reCount > 1 then
                if reCount = 2 then
                    DiagSidecar.emit (sprintf "[spiral_compiler] EJP0011W ty re-entry (non-fatal): nodeId=%d depth=%d site=%s" nodeId depth site)
                if reCount > max_reentry then
                    let hs = hashSnapShort ()
                    let ks = keySnapShort ()
                    let big = BigStack.isActive()
                    CacheGeneration.requestSequential ()
                    let genNow = int (CacheGeneration.current())
                    DiagSidecar.emit (sprintf "%s ty cycle: nodeId=%d depth=%d site=%s gen=%d re=%d/%d big=%b hs=[%s] ks=[%s]" EJPCodes.EJP0011 nodeId depth site genNow reCount max_reentry big hs ks)
                    let frameOpt =
                        if big || depth > 512 then
                            TermCycleFuse.tripWithTrace (sprintf "ty#%d" nodeId) site depth genNow reCount max_reentry s.trace
                            EvalWorklist.ensureCaptured "direct_ty_cycle_node" |> ignore
                            EvalWorklist.attachSemanticCell "ty_cycle" (semanticCellForTy nodeId)
                            EvalWorklist.ensureCapturedAndRun "direct_ty_cycle_node" "ty_cycle" 16
                        else None
                    // ALPHA400: do not throw away a completed typed replay at the direct cycle site.
                    returnReplayTypeIfComplete "direct_ty_cycle_node" nodeId frameOpt
                    let errEnv = if depth > 256 then s else (add_trace s r0)
                    let msg = sprintf "%s: re-entrant type evaluation cycle detected at %s (nodeId=%d depth=%d gen=%d re=%d/%d big=%b)" EJPCodes.EJP0011 site nodeId depth genNow reCount max_reentry big
                    let msg = match frameOpt with Some frame -> EvalWorklist.requiredMessage msg frame | None -> msg
                    if depth > 256 then
                        raise_type_error_no_trace errEnv msg
                    else
                        raise_type_error errEnv msg
            if reKey > 1 then
                if reKey = 2 then
                    DiagSidecar.emitKeyedSample (sprintf "[spiral_compiler] EJP0011W|ty|%s" nodeKey) (sprintf "[spiral_compiler] EJP0011W ty re-entry (key, non-fatal): key=%s depth=%d site=%s" nodeKey depth site)
                    // ALPHA393: EJP0014 can stall before the hard EJP0011 threshold, but these keyed
                    // sidecar warnings already identify a typed re-entry frontier.  In forced
                    // sequential mode, prefetch one conservative frame for the jp_stall_preflight
                    // path; completion still requires the typed replay driver.
                    if CacheGeneration.isSequentialRequested() && depth >= 8 && not (TermCycleFuse.isTripped()) then
                        try
                            let genNow = int (CacheGeneration.current())
                            TermCycleFuse.tripWithTrace ("ty:" + nodeKey) site depth genNow reKey max_reentry_key s.trace
                            EvalWorklist.ensureCaptured "sidecar_ty_reentry_prefetch" |> ignore
                            EvalWorklist.attachSemanticCell "ty_reentry_prefetch" (semanticCellForTy nodeId)
                            let frameOpt = EvalWorklist.ensureCapturedAndRun "sidecar_ty_reentry_prefetch" "ty_reentry_prefetch" 16
                            let preflightStatus = match frameOpt with Some frame -> frame.status | None -> "missing_after_prefetch"
                            let preflightCursor = match frameOpt with Some frame -> frame.cursor | None -> -1
                            let preflightComplete = EvalWorklist.hasReplayCompleteKind "ty"
                            DiagJson.emit (
                                sprintf "{\"kind\":\"eval_worklist_ty_reentry_prefetch_replay_drained\",\"event\":\"ty_reentry\",\"key\":%s,\"site\":%s,\"depth\":%d,\"re\":%d,\"max_re\":%d,\"status\":%s,\"cursor\":%d,\"replayCompleteNow\":%b,\"single_flight\":1,\"next\":\"return_or_continue_type_replay\"}"
                                    (DiagJson.esc nodeKey) (DiagJson.esc site) depth reKey max_reentry_key (DiagJson.esc preflightStatus) preflightCursor preflightComplete)
                            returnReplayTypeIfComplete "sidecar_ty_reentry_prefetch" nodeId frameOpt
                            DiagJson.emit (
                                sprintf "{\"kind\":\"eval_worklist_sidecar_prefetch\",\"event\":\"ty_reentry\",\"key\":%s,\"site\":%s,\"depth\":%d,\"re\":%d,\"max_re\":%d,\"single_flight\":1,\"next\":\"jp_stall_preflight_drained\"}"
                                    (DiagJson.esc nodeKey) (DiagJson.esc site) depth reKey max_reentry_key)
                        with
                        | EvalReplayTyReturn value -> raise (EvalReplayTyReturn value)
                        | _ -> ()
                if reKey > max_reentry_key then
                    let hs = hashSnapShort ()
                    let ks = keySnapShort ()
                    let big = BigStack.isActive()
                    CacheGeneration.requestSequential ()
                    let genNow = int (CacheGeneration.current())
                    DiagSidecar.emit (sprintf "%s ty cycle(key): key=%s depth=%d site=%s gen=%d re=%d/%d big=%b hs=[%s] ks=[%s]" EJPCodes.EJP0011 nodeKey depth site genNow reKey max_reentry_key big hs ks)
                    let tc_count = TermCycleWatchdog.note ("ty:" + nodeKey) genNow
                    let tc_panic = big || tc_count >= 2
                    let frameOpt =
                        if tc_panic then
                            DiagSidecar.emit (sprintf "%s ty cycle watchdog: PANIC key=%s gen=%d count=%d" EJPCodes.EJP0011 nodeKey genNow tc_count)
                            TermCycleFuse.tripWithTrace ("ty:" + nodeKey) site depth genNow reKey max_reentry_key s.trace
                            EvalWorklist.ensureCaptured "direct_ty_cycle_key" |> ignore
                            EvalWorklist.attachSemanticCell "ty_cycle" (semanticCellForTy nodeId)
                            EvalWorklist.ensureCapturedAndRun "direct_ty_cycle_key" "ty_cycle" 16
                        else None
                    // ALPHA400: direct keyed cycle replay can be a valid typed value, not just a retry-stop witness.
                    returnReplayTypeIfComplete "direct_ty_cycle_key" nodeId frameOpt
                    DiagJson.termCycle ("ty:" + nodeKey) depth site genNow reKey max_reentry_key big hs ks tc_count tc_panic
                    let errEnv = if depth > 256 then s else (add_trace s r0)
                    let msg = sprintf "%s: re-entrant type evaluation cycle detected at %s (key=%s depth=%d gen=%d re=%d/%d big=%b)" EJPCodes.EJP0011 site nodeKey depth genNow reKey max_reentry_key big
                    let msg = match frameOpt with Some frame -> EvalWorklist.requiredMessage msg frame | None -> msg
                    if depth > 256 then
                        raise_type_error_no_trace errEnv msg
                    else
                        raise_type_error errEnv msg
                

            // Maximum recursion depth before triggering BigStack pivot.
            // Parallel/degraded attempts stay conservative, but once alpha318+ has forced a
            // sequential fallback we give the old non-parallel path more room. The runtime
            // stack check remains active, so this is bounded legacy compatibility rather than
            // returning to unguarded recursion.
            let max_depth_base = EvalFallbackPolicy.depthBase
            let max_depth_big = EvalFallbackPolicy.maxDepthBig seqNow
            let max_depth = if BigStack.isActive() then max_depth_big else max_depth_base

            let deepSitesShort () =
                RecursionTracker.getDeepSites()
                |> List.sortByDescending (fun (kv: System.Collections.Generic.KeyValuePair<string,int>) -> kv.Value)
                |> List.truncate 8
                |> List.map (fun (kv: System.Collections.Generic.KeyValuePair<string,int>) -> sprintf "%s=%d" kv.Key kv.Value)
                |> String.concat ";"
    

            let inline stack_check (tag: string) =
                try
                    System.Runtime.CompilerServices.RuntimeHelpers.EnsureSufficientExecutionStack()
                with :? System.InsufficientExecutionStackException ->
                    let newGen = CacheGeneration.current()
                    jp_mismatch_counts.AddOrUpdate(sprintf "%s|ty_insufficient_stack" EJPCodes.EJP0010, 1, (fun _ n -> n + 1)) |> ignore
                    let reasons = CacheGeneration.reasonsSnapshot 6 |> String.concat " | "
                    let deepSites = deepSitesShort ()
                    DiagSidecar.emitEnvSnapshotOnce()
                    let tid = System.Threading.Thread.CurrentThread.ManagedThreadId
                    let bigActive = BigStack.isActive()
                    let nest = BigStack.getNest()
                    let mbTy = BigStack.getMb "ty"
                    let mem = try System.GC.GetTotalMemory(false) with _ -> 0L
                    DiagSidecar.emit (sprintf "%s ty insufficient_stack depth=%d site=%s gen=%d tag=%s tid=%d bigActive=%b nest=%d mb=%d mem=%d deepSites=[%s] reasons=[%s]"
                                            EJPCodes.EJP0010 depth site newGen tag tid bigActive nest mbTy mem deepSites reasons)
                    // Always use non-fatal mode: reraise to allow BigStack pivot
                    reraise()
    

            // Stack guard mais agressivo para evitar StackOverflow (especialmente com lambdas locais grandes).
            // A cadência aumenta com a profundidade: checamos pouco no início e muito quando está ficando perigoso.
            if depth <= 16 then
                if (depth &&& 3) = 0 then stack_check "d<=16"
            elif depth <= 64 then
                if (depth &&& 1) = 0 then stack_check "d<=64"
            else
    
                stack_check "d>64"

            if depth > max_depth then
                let newGen = CacheGeneration.current() // alpha27: do not invalidate on ty depth exceeded; make it a terminal error
                jp_mismatch_counts.AddOrUpdate(sprintf "%s|ty_depth_exceeded" EJPCodes.EJP0009, 1, (fun _ n -> n + 1)) |> ignore
                let deepSites = deepSitesShort ()
                let reasons = CacheGeneration.reasonsSnapshot 6 |> String.concat " | "
                let bigActive = BigStack.isActive()
                let mbTy = BigStack.getMb "ty"
                DiagSidecar.emit (sprintf "%s ty recursion depth exceeded depth=%d max=%d base=%d bigActive=%b mb=%d site=%s gen=%d deepSites=[%s] reasons=[%s]" EJPCodes.EJP0009 depth max_depth max_depth_base bigActive mbTy site newGen deepSites reasons)
                let errEnv = if depth > 256 then s else (add_trace s r0)
                if depth > 256 then
                    raise_type_error_no_trace errEnv (sprintf "%s: ty recursion depth exceeded (depth=%d max=%d) at %s" EJPCodes.EJP0009 depth max_depth site)
                else
                    raise_type_error errEnv (sprintf "%s: ty recursion depth exceeded (depth=%d max=%d) at %s" EJPCodes.EJP0009 depth max_depth site)
    

            match x with
            | TPatternRef _ -> failwith "Compiler error: TPatternRef should have been eliminated during the prepass."
            | TForall _ | TArrow _ | TJoinPoint _ -> failwith "Compiler error: Should have been transformed during the prepass."
            | TMetaV i -> YMetavar i
            | TArrow'(scope,i,body) ->
                assert (i = scope.ty.free_vars.Length)
                YTypeFunction(body,HopacExtensions.A.map (vt s) scope.ty.free_vars,scope.term.stack_size,scope.ty.stack_size)
            | TForall' _ -> YForall
            | TExists -> YExists
            | TJoinPoint'(r,scope,body) ->
                let env_global_type = scope.ty.free_vars |> HopacExtensions.A.map (fun i -> vt s i)
                let env_global_term = scope.term.free_vars |> HopacExtensions.A.map (fun i -> v s i)
                let (dict: System.Collections.Concurrent.ConcurrentDictionary<ConsedNode<Ty []>, JPTypeCell<Ty>>), hc_table, cache_gen =
                    Utils.memoize join_point_type (fun _ ->
                        System.Collections.Concurrent.ConcurrentDictionary<ConsedNode<Ty []>, JPTypeCell<Ty>>(HashIdentity.Reference), HashConsTable(), CacheGeneration.current ()
                    ) body
    

                let dict, hc_table =
                    if CacheGeneration.isStale cache_gen then
                        let fresh =
                            (System.Collections.Concurrent.ConcurrentDictionary<_,_>(HashIdentity.Reference),
                             HashConsTable(),
                             CacheGeneration.current ())
                        join_point_type.[body] <- fresh
                        let (d,h,_) = fresh
                        d,h
                    else dict, hc_table
    

                // Include source range in JP key for better cache uniqueness
                let env_global_type_key =
                    let (sp, ep) = r.range
                    let rk = sprintf "jp_type@%s:%d:%d-%d:%d" r.path sp.line sp.character ep.line ep.character
                    Array.append env_global_type [| YLit (LitString rk) |]
    

                let join_point_key = lock hc_table (fun () -> hc_table.Add(env_global_type_key))
                
                // ALPHA48: Use IVar-based cell for coordination

                let jp_cell = dict.GetOrAdd(join_point_key, fun _ -> { ivar = Hopac.IVar<Ty option>(); owner = 0 })
                

                // Fast path: IVar already filled
                if Hopac.IVar.Now.isFull jp_cell.ivar then
                    match Hopac.IVar.Now.get jp_cell.ivar with
                    | Some ret_ty -> ret_ty
                    | None -> raise_type_error (add_trace s r) "error[EJP0004]: type join point completed with no value"
                else
                    // Recursion guard based on per-evaluation stack
                    if s.jp_type_stack.Contains join_point_key then
                        let cur = trace_to_string_short (r :: s.trace)
                        let first_seen =
                            match jp_type_key_traces.TryGetValue join_point_key with
                            | true, tr -> trace_to_string_short tr
                            | _ -> "<unknown>"
                        let stack_prev = jp_type_stack_preview s.jp_type_stack
                        raise_type_error (add_trace s r)
                            (sprintf "error[EJP0001]: recursive join point requires annotation\n  |\n  = kind: type\n  = key: %O\n  = jp_type_stack: %d\n  = stack: %s\n  = first_seen: %s\n  = trace: %s\n"
                                join_point_key s.jp_type_stack.Count stack_prev first_seen cur)
                    

                    let tid = try System.Threading.Thread.CurrentThread.ManagedThreadId with _ -> 0
                    let owner0 = jp_cell.owner
                    

                    if owner0 = tid && owner0 <> 0 then
                        // par: break same-thread recursion by returning a placeholder instead of failing.
                        // This keeps the type JP cache acyclic during definition and pushes failures to a later, more informative point if needed.
                        record_jp_diag_type join_point_key (r :: s.trace)
                        YSymbol (sprintf "JPTypeRecPlaceholder(par;%O)" join_point_key)
                    elif owner0 <> 0 then
                        if SuspectCache.currentCount () > 0 then
                            // Global recovery mode: do not wait on potentially poisoned IVars/cells.
                            CacheGeneration.requestSequential ()
                            record_jp_diag_type join_point_key (r :: s.trace)
                            let jp_method_stack = System.Collections.Generic.HashSet<ConsedNode<RData [] * Ty [] * Ty>>(s.jp_method_stack, HashIdentity.Reference)
                            let jp_closure_stack = System.Collections.Generic.HashSet<ConsedNode<RData [] * Ty [] * Ty>>(s.jp_closure_stack, HashIdentity.Reference)
                            let jp_type_stack = System.Collections.Generic.HashSet<ConsedNode<Ty []>>(s.jp_type_stack, HashIdentity.Reference)
                            jp_type_stack.Add join_point_key |> ignore
                            let s : LangEnv = {
                                trace = r :: s.trace
                                seq = ResizeArray()
                                cse = [Dictionary(HashIdentity.Structural)]
                                unions = Map.empty
                                i = ref 0
                                env_global_type = env_global_type
                                env_global_term = env_global_term
                                env_stack_type = Array.zeroCreate<_> scope.ty.stack_size
                                env_stack_term = Array.zeroCreate<_> scope.term.stack_size
                                backend = s.backend
                                globals = s.globals
                                globals_lock = s.globals_lock
                                globals_seen = s.globals_seen
                                join_point_method_key_names = s.join_point_method_key_names
                                join_point_closure_key_names = s.join_point_closure_key_names
                                jp_method_stack = jp_method_stack
                                jp_closure_stack = jp_closure_stack
                                jp_type_stack = jp_type_stack
                                }
                            let s = rename_global_term s
                            let recursion_site = sprintf "JPType.recovery_bypass@%s:%d" r.path (fst r.range).line
                            let entry_depth = RecursionTracker.enter recursion_site
                            try
                                BitMamba.recordAccess join_point_key
                                let compute_ty () = ty s body
                                let ret_ty =
                                    if entry_depth > 64 then
                                        match BigStack.tryRun (sprintf "jp_type_recovery_%d" join_point_key.tag) compute_ty with
                                        | Some v -> v
                                        | None -> compute_ty ()
                                    else compute_ty ()
                                ret_ty
                            finally
                                RecursionTracker.exit ()
                        else
                            // Another thread owns this - wait on IVar cooperatively
                            let result = jp_ivar_wait "JPType.wait" (sprintf "key=%O owner=%d" join_point_key owner0) jp_cell.ivar
                            jp_throw_if_any ()
                            match result with
                            | Some ret_ty -> ret_ty
                            | None -> raise_type_error (add_trace s r) "error[EJP0004]: type join point completed with no value"
                    else
                        // Try to become owner
                        if System.Threading.Interlocked.CompareExchange(&jp_cell.owner, tid, 0) = 0 then
                            record_jp_diag_type join_point_key (r :: s.trace)
                            assert (0 = scope.term.free_vars.Length)
                            

                            let run () =
                                let inflight = get_async_local jp_type_inflight mk_jp_type_inflight
                                let inflight_added = inflight.Add join_point_key
                                try
                                    try
                                        jp_cell.owner <- tid
                                        let jp_method_stack = System.Collections.Generic.HashSet<ConsedNode<RData [] * Ty [] * Ty>>(s.jp_method_stack, HashIdentity.Reference)
                                        let jp_closure_stack = System.Collections.Generic.HashSet<ConsedNode<RData [] * Ty [] * Ty>>(s.jp_closure_stack, HashIdentity.Reference)
                                        let jp_type_stack = System.Collections.Generic.HashSet<ConsedNode<Ty []>>(s.jp_type_stack, HashIdentity.Reference)
                                        jp_type_stack.Add join_point_key |> ignore
                                        let s : LangEnv = {
                                            trace = r :: s.trace
                                            seq = ResizeArray()
                                            cse = [Dictionary(HashIdentity.Structural)]
                                            unions = Map.empty
                                            i = ref 0
                                            env_global_type = env_global_type
                                            env_global_term = env_global_term
                                            env_stack_type = Array.zeroCreate<_> scope.ty.stack_size
                                            env_stack_term = Array.zeroCreate<_> scope.term.stack_size
                                            backend = s.backend
                                            globals = s.globals
                                            globals_lock = s.globals_lock
                                            globals_seen = s.globals_seen
                                            join_point_method_key_names = s.join_point_method_key_names
                                            join_point_closure_key_names = s.join_point_closure_key_names
                                            jp_method_stack = jp_method_stack
                                            jp_closure_stack = jp_closure_stack
                                            jp_type_stack = jp_type_stack
                                            }
                                        let s = rename_global_term s
                                    
                                        // ALPHA48: Simplified evaluation - just evaluate and fill IVar

                                        let recursion_site = sprintf "JPType@%s:%d" r.path (fst r.range).line
                                        let entry_depth = RecursionTracker.enter recursion_site
                                        BitMamba.recordAccess join_point_key
                                    

                                        let ret_ty = ty s body
                                    

                                        // Fill IVar to signal completion
                                        jp_fill_ivar jp_cell.ivar (Some ret_ty)
                                        ()
                                    with e ->
                                        // Fill with None so waiters don't hang
                                        try jp_fill_ivar jp_cell.ivar None with _ -> ()
                                        reraise()
                                finally
                                    RecursionTracker.exit ()
                                    jp_cell.owner <- 0
                                    if inflight_added then inflight.Remove join_point_key |> ignore
                            
                            // ALPHA48: Always schedule via Hopac, then wait cooperatively

                            jp_start_named (sprintf "JPType tag=%d" join_point_key.tag) run
                            let result = jp_ivar_wait "JPType.wait" (sprintf "key=%O" join_point_key) jp_cell.ivar
                            jp_throw_if_any ()
                            match result with
                            | Some ret_ty -> ret_ty
                            | None -> raise_type_error (add_trace s r) "error[EJP0004]: type join point evaluation failed"
                        else
                            // Lost the race - if we're in global recovery, recompute instead of waiting on a potentially poisoned cell.
                            if SuspectCache.currentCount () > 0 then
                                CacheGeneration.requestSequential ()
                                record_jp_diag_type join_point_key (r :: s.trace)
                                let jp_method_stack = System.Collections.Generic.HashSet<ConsedNode<RData [] * Ty [] * Ty>>(s.jp_method_stack, HashIdentity.Reference)
                                let jp_closure_stack = System.Collections.Generic.HashSet<ConsedNode<RData [] * Ty [] * Ty>>(s.jp_closure_stack, HashIdentity.Reference)
                                let jp_type_stack = System.Collections.Generic.HashSet<ConsedNode<Ty []>>(s.jp_type_stack, HashIdentity.Reference)
                                jp_type_stack.Add join_point_key |> ignore
                                let s : LangEnv = {
                                    trace = r :: s.trace
                                    seq = ResizeArray()
                                    cse = [Dictionary(HashIdentity.Structural)]
                                    unions = Map.empty
                                    i = ref 0
                                    env_global_type = env_global_type
                                    env_global_term = env_global_term
                                    env_stack_type = Array.zeroCreate<_> scope.ty.stack_size
                                    env_stack_term = Array.zeroCreate<_> scope.term.stack_size
                                    backend = s.backend
                                    globals = s.globals
                                    globals_lock = s.globals_lock
                                    globals_seen = s.globals_seen
                                    join_point_method_key_names = s.join_point_method_key_names
                                    join_point_closure_key_names = s.join_point_closure_key_names
                                    jp_method_stack = jp_method_stack
                                    jp_closure_stack = jp_closure_stack
                                    jp_type_stack = jp_type_stack
                                    }
                                let s = rename_global_term s
                                let recursion_site = sprintf "JPType.recovery_bypass@%s:%d" r.path (fst r.range).line
                                let entry_depth = RecursionTracker.enter recursion_site
                                try
                                    BitMamba.recordAccess join_point_key
                                    let compute_ty () = ty s body
                                    let ret_ty =
                                        if entry_depth > 64 then
                                            match BigStack.tryRun (sprintf "jp_type_recovery_%d" join_point_key.tag) compute_ty with
                                            | Some v -> v
                                            | None -> compute_ty ()
                                        else compute_ty ()
                                    ret_ty
                                finally
                                    RecursionTracker.exit ()
                            else
                                // Lost the race - wait on winner's IVar
                                let result = jp_ivar_wait "JPType.wait" (sprintf "key=%O" join_point_key) jp_cell.ivar
                                jp_throw_if_any ()
                                match result with
                                | Some ret_ty -> ret_ty
                                | None -> raise_type_error (add_trace s r) "error[EJP0004]: type join point completed with no value"
    

            | TB _ -> YB
            | TLit(_,x) -> YLit x
            | TV i -> vt s i
            | TPair(_,a,b) -> YPair(ty s a, ty s b)
            | TFun(a,b,t) -> YFun(ty s a, ty s b,t)
            | TModule a ->
                YRecord(
                    a
                    |> Seq.mapi (fun i (KeyValue (k, v)) -> (i, k), (v |> ty s))
                    |> Map.ofSeq
                )
            | TRecord(_,a) -> YRecord(Map.map (fun _ -> ty s) a)
            | TUnion(_,(a,b)) ->
                let tags = Dictionary()
                let tag_cases = Array.zeroCreate (Map.count a)
                let mutable is_degenerate = true
                let cases =
                    Map.fold (fun cases (i,k) v ->
                        let v = Option.defaultValue (fst v) (snd v) // If the union case is generalized, use the specialized destructor instead of the constructor to evaluate the type.
                        match ty s v with
                        | YVoid -> cases
                        | v ->
                            is_degenerate <- is_degenerate && match v with YB -> true | _ -> false
                            tags.[k] <- i
                            tag_cases.[i] <- (k,v)
                            Map.add (i,k) v cases
                        ) Map.empty a
                YUnion(H {|cases=cases; layout=b; tags=tags; tag_cases=tag_cases; is_degenerate=is_degenerate|})
            | TTypecase(r,a,b) ->
                let s = add_trace s r
                let a = ty s a
                let rec loop = function
                    | (a',b) :: rest -> if is_unify s (a,ty s a') then Some(ty s b) else loop rest
                    | [] -> None
                match loop b with
                | Some r -> r
                | None -> YVoid
            | TSymbol(_,a) -> YSymbol a
            | TApply(r,a,b) ->
                let s = add_trace s r
                match ty s a with
                | YRecord a ->
                    match ty s b with
                    | YSymbol b ->
                        match a |> Map.tryPick (fun (_, k) v -> if k = b then Some v else None) with
                        | Some x -> x
                        | None -> raise_type_error s <| sprintf  "Cannot find key %s in the record." b
                    | b -> raise_type_error s <| sprintf "Expected a symbol in the record application.\nGot: %s" (show_ty b)
                | YMetavar _ | YNominal _ | YApply _ as a -> YApply(a,ty s b)
                | YTypeFunction(body,gl_ty,sz_term,sz_ty) ->
                    let b = ty s b
                    let s = { s with env_global_type = gl_ty; env_global_term = [||]; env_stack_type = Array.zeroCreate<_> sz_ty; env_stack_term = Array.zeroCreate<_> sz_term }
                    s.env_stack_type.[0] <- b
                    ty s body
                | a -> raise_type_error s <| sprintf "Expected a record, nominal or a type function. Or a metavar when in typecase.\nGot: %s" (show_ty a)
            | TPrim a -> YPrim a
            | TTerm(_,a) -> term_real_nominal s a
            | TMacro(r,a) ->
                let s = add_trace s r
                YMacro(a |> List.map (function TMText a -> PartEvalMacro.Text a | TMType a -> Type(ty s a) | TMLitType a -> TypeLit(ty s a |> assert_ty_lit s)))
            | TNominal i -> YNominal env.nominals.[i]
            | TArray a -> YArray(ty s a)
            | TLayout(a,b) -> YLayout(ty s a,b)
        and term (s : LangEnv) x =
            // par: Proactive BigStack pivot based on observed recursion depth.
            // The main stack can overflow around ~100 nested term frames because these lambdas carry huge environments.
            // If we are already deep and not on BigStack, rerun the step on BigStack to avoid hard StackOverflow.
            let d = RecursionTracker.currentDepth()
            if (not (BigStack.isActive())) && d > 32 then
                match BigStack.tryRun "term_depth" (fun () -> term_core s x) with
                | Some v -> v
                | None -> term_core s x
            else
                term_core s x
    

        and term_core (s : LangEnv) x =
            // v107-alpha13: emergency stack pivot must return the same type as the normal path
            // (the old version returned 'unit' in the try-branch, causing cascading 'unit' vs 'Data' errors)
            try
                System.Runtime.CompilerServices.RuntimeHelpers.EnsureSufficientExecutionStack()
                term_core_impl s x
            with
            | EvalReplayTermReturn value -> value
            | :? System.InsufficientExecutionStackException ->
                match BigStack.tryRun "term_emergency" (fun () -> term_core_impl s x) with
                | Some v -> v
                | None ->
                    let fallback = match s.trace with | r :: _ -> r | [] -> range0
                    let r0 = range_of_e_or fallback x
                    let site = sprintf "term@%s:%d" r0.path (fst r0.range).line
                    raise_type_error (add_trace s r0) (sprintf "%s: stack overflow in term at %s (BigStack exhausted)" EJPCodes.EJP0010 site)
    

        and term_core_impl (s : LangEnv) x =
    

            let fallback = match s.trace with | r :: _ -> r | [] -> range0
            let r0 = range_of_e_or fallback x
            let site = sprintf "term@%s:%d" r0.path (fst r0.range).line
            let termShape0 = evalNodeShapeTerm x
            let termSourceKey0 =
                EvalReplayValueStore.termSourceKey site termShape0 s.env_global_term.Length s.env_stack_term.Length s.env_global_type.Length s.env_stack_type.Length s.trace.Length
            let semanticCellForTerm nodeId = evalCell "term" termShape0 nodeId site s
            if TermCycleFuse.isTripped() then
                match EvalReplayValueStore.tryTermSourceValue termSourceKey0 with
                | Some value ->
                    DiagJson.emit (
                        sprintf "{\"kind\":\"eval_worklist_source_value_replay_return\",\"event\":\"term_entry_global_fuse\",\"status\":\"semantic_root_complete\",\"shape\":%s,\"source_key\":%s,\"single_flight\":1,\"next\":\"return_term_value\"}"
                            (DiagJson.esc termShape0) (DiagJson.esc termSourceKey0))
                    TermCycleFuse.reset ()
                    raise (EvalReplayTermReturn value)
                | None -> ()
                let nodeId0 = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box x)
                let rec registerReplayTerm (nodeId: int) (expr: E) =
                    match expr with
                    | EB _ -> EvalReplayValueStore.putTermValue nodeId DB
                    | EV a -> EvalReplayValueStore.putTerm nodeId (fun () -> v s a)
                    | ELit(_,lit) -> EvalReplayValueStore.putTermValue nodeId (DLit lit)
                    | ESymbol(_,sym) -> EvalReplayValueStore.putTermValue nodeId (DSymbol sym)
                    | EFun'(_,freeVars,i,body,annot) ->
                        EvalReplayValueStore.putTerm nodeId (fun () ->
                            if freeVars.term.free_vars.Length <> i then failwith "Replay function free-var arity mismatch."
                            DFunction(body, annot, HopacExtensions.A.map (v s) freeVars.term.free_vars, HopacExtensions.A.map (vt s) freeVars.ty.free_vars, freeVars.term.stack_size, freeVars.ty.stack_size))
                    | ERecursiveFun'(_,freeVars,i,body,annot) ->
                        EvalReplayValueStore.putTerm nodeId (fun () ->
                            if freeVars.term.free_vars.Length <> i then failwith "Replay recursive function free-var arity mismatch."
                            DFunction(body.Value, annot, HopacExtensions.A.map (v s) freeVars.term.free_vars, HopacExtensions.A.map (vt s) freeVars.ty.free_vars, freeVars.term.stack_size, freeVars.ty.stack_size))
                    | EForall'(_,freeVars,i,body) ->
                        EvalReplayValueStore.putTerm nodeId (fun () ->
                            if freeVars.ty.free_vars.Length <> i then failwith "Replay forall free-var arity mismatch."
                            DForall(body, HopacExtensions.A.map (v s) freeVars.term.free_vars, HopacExtensions.A.map (vt s) freeVars.ty.free_vars, freeVars.term.stack_size, freeVars.ty.stack_size))
                    | ERecursiveForall'(_,freeVars,i,body) ->
                        EvalReplayValueStore.putTerm nodeId (fun () ->
                            if freeVars.ty.free_vars.Length <> i then failwith "Replay recursive forall free-var arity mismatch."
                            DForall(body.Value, HopacExtensions.A.map (v s) freeVars.term.free_vars, HopacExtensions.A.map (vt s) freeVars.ty.free_vars, freeVars.term.stack_size, freeVars.ty.stack_size))
                    | EJoinPoint'(_,_,_,_,_,_) ->
                        // ALPHA559: EJoinPoint' is a first-class term value computation.
                        // Register the existing evaluator thunk so the replay driver can
                        // attempt real join-point materialization instead of falling through
                        // to the opaque E* dispatcher and repeating term_shape_dispatch.
                        EvalReplayValueStore.putTerm nodeId (fun () -> term s expr)
                    | EUnbox(r,k,id,a,on_succ,on_fail) ->
                        // ALPHA646: EUnbox is a real evaluator form, not an opaque E* leaf.
                        // The 645 runtime showed an EApply body at resultm.spi:343 scheduling
                        // EUnbox and then repeating child scheduling because no replay thunk
                        // existed for the unbox node.  Register the real evaluator fail-closed.
                        // ALPHA1022: also expose the scrutinee and branch children so replay
                        // can drive listm/core unboxes without black-box re-entry.
                        let bindNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box a)
                        let successNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box on_succ)
                        let failNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box on_fail)
                        registerReplayTerm bindNodeId a
                        EvalReplayValueStore.putTerm failNodeId (fun () -> term (add_trace s r) on_fail)
                        EvalReplayValueStore.putTerm successNodeId (fun () ->
                            let s = add_trace s r
                            match term s a with
                            | DNominal(DUnion(DPair(DSymbol k', payload),_),_) when k = k' ->
                                store_term s id payload
                                term s on_succ
                            | _ -> term s expr)
                        EvalReplayValueStore.putUnboxSpine nodeId {
                            bindNodeId = bindNodeId
                            bindShape = evalNodeShapeTerm a
                            caseName = k
                            binderId = id
                            successNodeId = successNodeId
                            successShape = evalNodeShapeTerm on_succ
                            failNodeId = failNodeId
                            failShape = evalNodeShapeTerm on_fail
                        }
                        EvalReplayValueStore.putTerm nodeId (fun () -> term s expr)
                    | EAnnot(_,inner,annotTy) ->
                        // ALPHA653: runtime 652 ended with current_shape=EAnnot after a
                        // root-complete witness.  Register annotation as a real thunk so
                        // stale-root fallthrough can evaluate the ordinary term/type check.
                        let innerNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box inner)
                        let typeNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box annotTy)
                        registerReplayTerm innerNodeId inner
                        EvalReplayValueStore.putType typeNodeId (fun () -> ty s annotTy)
                        EvalReplayValueStore.putAnnotSpine nodeId {
                            innerNodeId = innerNodeId
                            innerShape = evalNodeShapeTerm inner
                            typeNodeId = typeNodeId
                            typeShape = evalNodeShapeTy annotTy
                        }
                        EvalReplayValueStore.putTerm nodeId (fun () -> term s expr)
                    | ENominal(_,inner,nomTy) ->
                        let innerNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box inner)
                        let typeNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box nomTy)
                        registerReplayTerm innerNodeId inner
                        EvalReplayValueStore.putType typeNodeId (fun () -> ty s nomTy)
                        EvalReplayValueStore.putNominalSpine nodeId {
                            innerNodeId = innerNodeId
                            innerShape = evalNodeShapeTerm inner
                            typeNodeId = typeNodeId
                            typeShape = evalNodeShapeTy nomTy
                        }
                        EvalReplayValueStore.putTerm nodeId (fun () -> term s expr)
                    | EType(_,texpr) ->
                        // ALPHA579: EType is not a term value, but EOp has legal raw-type
                        // argument forms.  Register the same node in the type store so the
                        // type-aware op bridge can consume it without scheduling term/EType.
                        // ALPHA640: runtime 639 showed EOp can still resume through the generic
                        // term child path for raw EType arguments.  Expose the real typed value as
                        // Data via ty_to_data, fail-closed through the existing type evaluator.
                        EvalReplayValueStore.putType nodeId (fun () -> ty s texpr)
                        EvalReplayValueStore.putTerm nodeId (fun () -> ty_to_data s (ty s texpr))
                    | EDefaultLit(_,_,_) -> ()
                    | ELet _ ->
                        // ALPHA408: conservative replay for let-spines exposed by alpha407.
                        // Alpha407 installed a whole-chain thunk, but the 407 runtime log showed
                        // current_shape=ELet staying partial when the canonical frontier was a
                        // type witness.  Pre-register every body/success child and read replay
                        // values first, so the let chain does not re-enter term_core merely to
                        // shuttle already-captured values across the local environment.
                        // ALPHA444: also materialize the child spine so missing bodies are scheduled
                        // explicitly.  Alpha443 ended with replay_let_body_value_missing:EApply at
                        // runtime fixture path:5 and the retry drain kept re-running the same parent let.
                        let letBodyIds = ResizeArray<int>()
                        let letBodyShapes = ResizeArray<string>()
                        let mutable letSuccessId = nodeId
                        let mutable letSuccessShape = "ELet"
                        let rec registerLetChildren (e: E) =
                            match e with
                            | ELet(_,_,body,on_succ) ->
                                let bodyId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box body)
                                letBodyIds.Add bodyId
                                letBodyShapes.Add (evalNodeShapeTerm body)
                                registerReplayTerm bodyId body
                                registerLetChildren on_succ
                            | other ->
                                let otherId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box other)
                                letSuccessId <- otherId
                                letSuccessShape <- evalNodeShapeTerm other
                                if otherId <> nodeId then registerReplayTerm otherId other
                        registerLetChildren expr
                        EvalReplayValueStore.putLetSpine nodeId {
                            bodyNodeIds = letBodyIds.ToArray()
                            bodyShapes = letBodyShapes.ToArray()
                            successNodeId = letSuccessId
                            successShape = letSuccessShape
                        }
                        EvalReplayValueStore.putTerm nodeId (fun () ->
                            let mutable replay_s = s
                            let mutable replay_e = expr
                            let mutable replay_result = DB
                            let mutable replay_done = false
                            while not replay_done do
                                match replay_e with
                                | ELet(rr, bind, body, on_succ) ->
                                    replay_s <- add_trace replay_s rr
                                    let bodyId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box body)
                                    let bodyValue =
                                        match EvalReplayValueStore.tryTerm bodyId with
                                        | Some value -> value
                                        | None -> failwith ("replay_let_body_value_missing:" + evalNodeShapeTerm body)
                                    store_term replay_s bind bodyValue
                                    replay_e <- on_succ
                                | _ ->
                                    let replayId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box replay_e)
                                    match EvalReplayValueStore.tryTerm replayId with
                                    | Some value ->
                                        replay_result <- value
                                        replay_done <- true
                                    | None -> failwith ("replay_let_success_value_missing:" + evalNodeShapeTerm replay_e)
                            replay_result)
                    | ESeq(_,first,second) ->
                        let firstNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box first)
                        let secondNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box second)
                        registerReplayTerm firstNodeId first
                        registerReplayTerm secondNodeId second
                        match first with
                        | EB _ -> EvalReplayValueStore.putTermValue firstNodeId DB
                        | EV a -> EvalReplayValueStore.putTerm firstNodeId (fun () -> v s a)
                        | ELit(_,lit) -> EvalReplayValueStore.putTermValue firstNodeId (DLit lit)
                        | ESymbol(_,sym) -> EvalReplayValueStore.putTermValue firstNodeId (DSymbol sym)
                        | EFun'(_,freeVars,i,body,annot) ->
                            EvalReplayValueStore.putTerm firstNodeId (fun () ->
                                if freeVars.term.free_vars.Length <> i then failwith "Replay seq-first function free-var arity mismatch."
                                DFunction(body, annot, HopacExtensions.A.map (v s) freeVars.term.free_vars, HopacExtensions.A.map (vt s) freeVars.ty.free_vars, freeVars.term.stack_size, freeVars.ty.stack_size))
                        | EForall'(_,freeVars,i,body) ->
                            EvalReplayValueStore.putTerm firstNodeId (fun () ->
                                if freeVars.ty.free_vars.Length <> i then failwith "Replay seq-first forall free-var arity mismatch."
                                DForall(body, HopacExtensions.A.map (v s) freeVars.term.free_vars, HopacExtensions.A.map (vt s) freeVars.ty.free_vars, freeVars.term.stack_size, freeVars.ty.stack_size))
                        | _ -> ()
                        match second with
                        | EB _ -> EvalReplayValueStore.putTermValue secondNodeId DB
                        | EV a -> EvalReplayValueStore.putTerm secondNodeId (fun () -> v s a)
                        | ELit(_,lit) -> EvalReplayValueStore.putTermValue secondNodeId (DLit lit)
                        | ESymbol(_,sym) -> EvalReplayValueStore.putTermValue secondNodeId (DSymbol sym)
                        | EFun'(_,freeVars,i,body,annot) ->
                            EvalReplayValueStore.putTerm secondNodeId (fun () ->
                                if freeVars.term.free_vars.Length <> i then failwith "Replay seq-second function free-var arity mismatch."
                                DFunction(body, annot, HopacExtensions.A.map (v s) freeVars.term.free_vars, HopacExtensions.A.map (vt s) freeVars.ty.free_vars, freeVars.term.stack_size, freeVars.ty.stack_size))
                        | EForall'(_,freeVars,i,body) ->
                            EvalReplayValueStore.putTerm secondNodeId (fun () ->
                                if freeVars.ty.free_vars.Length <> i then failwith "Replay seq-second forall free-var arity mismatch."
                                DForall(body, HopacExtensions.A.map (v s) freeVars.term.free_vars, HopacExtensions.A.map (vt s) freeVars.ty.free_vars, freeVars.term.stack_size, freeVars.ty.stack_size))
                        | _ -> ()
                        EvalReplayValueStore.putSeqSpine nodeId {
                            firstNodeId = firstNodeId
                            firstShape = evalNodeShapeTerm first
                            secondNodeId = secondNodeId
                            secondShape = evalNodeShapeTerm second
                        }
                        EvalReplayValueStore.putTerm nodeId (fun () ->
                            let isUnknownReturnWitness value =
                                match value with
                                | DSymbol sym when sym.Contains("JPMethodUnknownRet(") -> true
                                | DV(L(_,YSymbol sym)) when sym.Contains("JPMethodUnknownRet(") -> true
                                | _ -> false
                            let unitLike value =
                                match value with
                                | DB -> true
                                | DSymbol sym when sym.Contains("JPMethodRecPlaceholder(") || sym.Contains("JPTypeRecPlaceholder(") -> true
                                | DV(L(_,YSymbol sym)) when sym.Contains("JPMethodRecPlaceholder(") || sym.Contains("JPTypeRecPlaceholder(") -> true
                                | _ -> false
                            let discardableApplyLiteral value =
                                match value with
                                | DLit _ when evalNodeShapeTerm first = "EApply" -> true
                                | DSymbol _ when evalNodeShapeTerm first = "EApply" -> true
                                | _ -> false
                            match EvalReplayValueStore.tryTerm firstNodeId with
                            | Some firstValue when isUnknownReturnWitness firstValue && evalNodeShapeTerm first = "EApply" ->
                                match EvalReplayValueStore.tryTerm secondNodeId with
                                | Some secondValue -> secondValue
                                | None -> failwith ("replay_seq_second_value_missing_after_apply_unknown_return:" + evalNodeShapeTerm second)
                            | Some firstValue when isUnknownReturnWitness firstValue ->
                                failwith (sprintf "replay_seq_unknown_return_witness:%s" (show_data firstValue))
                            | Some firstValue when unitLike firstValue ->
                                match EvalReplayValueStore.tryTerm secondNodeId with
                                | Some secondValue -> secondValue
                                | None -> failwith ("replay_seq_second_value_missing:" + evalNodeShapeTerm second)
                            | Some firstValue when discardableApplyLiteral firstValue ->
                                match EvalReplayValueStore.tryTerm secondNodeId with
                                | Some secondValue -> secondValue
                                | None -> failwith ("replay_seq_second_value_missing_after_apply_literal:" + evalNodeShapeTerm second)
                            | Some other -> failwith (sprintf "replay_seq_expected_unit:%s" (show_data other))
                            | None -> failwith ("replay_seq_first_value_missing:" + evalNodeShapeTerm first))
                    | EPair(_,left,right) ->
                        // ALPHA567: repair alpha566 offside indentation in this global-fuse registration branch.
                        // The semantic intent is unchanged: register both children and materialize DPair only when ready.
                        let leftNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box left)
                        let rightNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box right)
                        registerReplayTerm leftNodeId left
                        registerReplayTerm rightNodeId right
                        EvalReplayValueStore.putTermPairSpine nodeId {
                            leftNodeId = leftNodeId
                            leftShape = evalNodeShapeTerm left
                            rightNodeId = rightNodeId
                            rightShape = evalNodeShapeTerm right
                        }
                        EvalReplayValueStore.putTerm nodeId (fun () ->
                            match EvalReplayValueStore.tryTerm leftNodeId, EvalReplayValueStore.tryTerm rightNodeId with
                            | Some leftValue, Some rightValue -> DPair(leftValue, rightValue)
                            | None, _ -> failwith ("pair_left_value_missing:" + evalNodeShapeTerm left)
                            | _, None -> failwith ("pair_right_value_missing:" + evalNodeShapeTerm right))
                    | EPairTest(r,bind,p1,p2,on_succ,on_fail) ->
                        // ALPHA650: pair-test bodies need replay branch spines just
                        // like EUnitTest/EAnnotTest.  The success branch is evaluated
                        // under the concrete pair destructuring environment; the fail
                        // branch keeps the original environment.
                        let succNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box on_succ)
                        let failNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box on_fail)
                        try
                            let s2 = add_trace s r
                            EvalReplayValueStore.putPairTestBindValue nodeId (v s2 bind)
                        with _ -> ()
                        EvalReplayValueStore.putTerm succNodeId (fun () ->
                            let s2 = add_trace s r
                            match v s2 bind with
                            | DPair(a,b) ->
                                store_term s2 p1 a
                                store_term s2 p2 b
                                term s2 on_succ
                            | other -> failwith (sprintf "pair_test_success_branch_not_selected:%s" (show_data other)))
                        EvalReplayValueStore.putTerm failNodeId (fun () ->
                            let s2 = add_trace s r
                            match v s2 bind with
                            | DPair _ -> failwith "pair_test_fail_branch_not_selected:DPair"
                            | _ -> term s2 on_fail)
                        EvalReplayValueStore.putPairTestSpine nodeId {
                            successNodeId = succNodeId
                            successShape = evalNodeShapeTerm on_succ
                            failNodeId = failNodeId
                            failShape = evalNodeShapeTerm on_fail
                        }
                        EvalReplayValueStore.putTerm nodeId (fun () ->
                            let s2 = add_trace s r
                            match v s2 bind with
                            | DPair(a,b) ->
                                store_term s2 p1 a
                                store_term s2 p2 b
                                match EvalReplayValueStore.tryTerm succNodeId with
                                | Some value -> value
                                | None -> failwith ("pair_test_success_branch_value_missing:" + evalNodeShapeTerm on_succ)
                            | _ ->
                                match EvalReplayValueStore.tryTerm failNodeId with
                                | Some value -> value
                                | None -> failwith ("pair_test_fail_branch_value_missing:" + evalNodeShapeTerm on_fail))
                    | EAnnotTest(r,annotTy,bind,on_succ,on_fail) ->
                        // ALPHA652: runtime 651 proved EAnnotTest can surface from the global
                        // replay path (sm'_real.spir:287) with no AnnotTestSpine, even though
                        // function-body replay already knows how to build that spine.  Register
                        // annotation type + both branches here as a normal composite term.
                        let typeNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box annotTy)
                        let trueNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box on_succ)
                        let falseNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box on_fail)
                        let annotEnv () = add_trace s r
                        EvalReplayValueStore.putAnnotTestContext nodeId (box (annotEnv()))
                        try EvalReplayValueStore.putAnnotTestBindValue nodeId (v (annotEnv()) bind)
                        with _ -> ()
                        EvalReplayValueStore.putType typeNodeId (fun () -> ty (annotEnv()) annotTy)
                        registerReplayTerm trueNodeId on_succ
                        registerReplayTerm falseNodeId on_fail
                        EvalReplayValueStore.putTerm trueNodeId (fun () -> term (annotEnv()) on_succ)
                        EvalReplayValueStore.putTerm falseNodeId (fun () -> term (annotEnv()) on_fail)
                        EvalReplayValueStore.putAnnotTestSpine nodeId {
                            typeNodeId = typeNodeId
                            typeShape = evalNodeShapeTy annotTy
                            trueNodeId = trueNodeId
                            trueShape = evalNodeShapeTerm on_succ
                            falseNodeId = falseNodeId
                            falseShape = evalNodeShapeTerm on_fail
                        }
                        EvalReplayValueStore.putTerm nodeId (fun () ->
                            let s2 = annotEnv()
                            let branch, branchNodeId =
                                let bindTy = data_to_ty s2 (v s2 bind)
                                let annotTy2 = ty s2 annotTy
                                if ty_eq_allow_jp_placeholders bindTy annotTy2 then on_succ, trueNodeId
                                else on_fail, falseNodeId
                            match EvalReplayValueStore.tryTerm branchNodeId with
                            | Some value -> value
                            | None -> failwith ("annot_test_branch_value_missing:" + evalNodeShapeTerm branch))
                    | EUnitTest(r,bind,on_succ,on_fail) ->
                        // ALPHA408: replay pattern-test branches when the unit check is already decidable.
                        // The 407 log exposed EUnitTest as a residual term under a completed type
                        // witness.  Store the selected branch as a normal child; failures remain
                        // partial rather than re-entering the global fuse.
                        // ALPHA935: the 934 runtime reached an EUnitTest whose direct thunk
                        // failed with NullReferenceException before a branch_missing marker.
                        // Register the bind as a first-class replay child so the worklist can
                        // materialize the discriminator before retrying success/fail selection.
                        let bindNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box bind)
                        let succNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box on_succ)
                        let failNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box on_fail)
                        // ALPHA936: bind is an Id, not an E. Do not pass it through
                        // registerReplayTerm/evalNodeShapeTerm. The replay child is a
                        // value thunk backed by the existing variable evaluator.
                        registerReplayTerm succNodeId on_succ
                        registerReplayTerm failNodeId on_fail
                        EvalReplayValueStore.putTerm bindNodeId (fun () -> v (add_trace s r) bind)
                        EvalReplayValueStore.putUnitTestSpine nodeId {
                            bindNodeId = bindNodeId
                            bindShape = "EV"
                            successNodeId = succNodeId
                            successShape = evalNodeShapeTerm on_succ
                            failNodeId = failNodeId
                            failShape = evalNodeShapeTerm on_fail
                        }
                        EvalReplayValueStore.putTerm nodeId (fun () ->
                            let s2 = add_trace s r
                            let branch, branchNodeId =
                                match v s2 bind with
                                | DB -> on_succ, succNodeId
                                | _ -> on_fail, failNodeId
                            match EvalReplayValueStore.tryTerm branchNodeId with
                            | Some value -> value
                            | None -> failwith ("unit_test_branch_value_missing:" + evalNodeShapeTerm branch))
                    | ETypeApply(_,func,typeArg) ->
                        let funcNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box func)
                        let typeNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box typeArg)
                        registerReplayTerm funcNodeId func
                        match func with
                        | EV a -> EvalReplayValueStore.putTerm funcNodeId (fun () -> v s a)
                        | EForall'(_,freeVars,i,body) ->
                            EvalReplayValueStore.putTerm funcNodeId (fun () ->
                                if freeVars.ty.free_vars.Length <> i then failwith "Replay type-apply forall free-var arity mismatch."
                                DForall(body, HopacExtensions.A.map (v s) freeVars.term.free_vars, HopacExtensions.A.map (vt s) freeVars.ty.free_vars, freeVars.term.stack_size, freeVars.ty.stack_size))
                        | ERecursiveForall'(_,freeVars,i,body) ->
                            EvalReplayValueStore.putTerm funcNodeId (fun () ->
                                if freeVars.ty.free_vars.Length <> i then failwith "Replay type-apply recursive forall free-var arity mismatch."
                                DForall(body.Value, HopacExtensions.A.map (v s) freeVars.term.free_vars, HopacExtensions.A.map (vt s) freeVars.ty.free_vars, freeVars.term.stack_size, freeVars.ty.stack_size))
                        | _ -> ()
                        let snapshotTypeVariableChildFromEnv (parentNodeId: int) (childNodeId: int) (role: string) (child: TPrepass) =
                            match child with
                            | TV i ->
                                let globalTypeLen =
                                    if obj.ReferenceEquals(s.env_global_type, null) then 0
                                    else s.env_global_type.Length
                                let stackTypeLen =
                                    if obj.ReferenceEquals(s.env_stack_type, null) then 0
                                    else s.env_stack_type.Length
                                match EvalReplayValueStore.putTypeVarEnvSnapshot childNodeId i s.env_global_type s.env_stack_type with
                                | Some (envName, _, _) ->
                                    DiagJson.emit (
                                        sprintf "{\"kind\":\"eval_worklist_type_fun_tv_child_env_snapshot\",\"event\":\"type_fun_child_register\",\"parent_node_id\":%d,\"child_node_id\":%d,\"role\":%s,\"index\":%d,\"env\":%s,\"global_len\":%d,\"stack_len\":%d,\"site\":%s,\"single_flight\":1,\"next\":\"type_value_materialized\"}"
                                            parentNodeId childNodeId (DiagJson.esc role) i (DiagJson.esc envName) globalTypeLen stackTypeLen (DiagJson.esc site))
                                | None ->
                                    DiagJson.emit (
                                        sprintf "{\"kind\":\"eval_worklist_type_fun_tv_child_env_snapshot_miss\",\"event\":\"type_fun_child_register\",\"parent_node_id\":%d,\"child_node_id\":%d,\"role\":%s,\"index\":%d,\"global_len\":%d,\"stack_len\":%d,\"site\":%s,\"single_flight\":1,\"next\":\"explicit_eval_worklist_type_variable_env_required\"}"
                                            parentNodeId childNodeId (DiagJson.esc role) i globalTypeLen stackTypeLen (DiagJson.esc site))
                            | _ -> ()
                        // The ETypeApply type-argument mirror must register
                        // composite type children like the normal registerReplayTy path.
                        // Runtime 574 reached a ty/TV terminal at trace.spi:314 from a
                        // TFun inside a type-argument continuation; without child spines
                        // the nested TV can be forced only through stale raw ty recursion.
                        let rec registerTypeApplyArgReplay (replayNodeId: int) (texpr: TPrepass) =
                            let childType label child =
                                let childNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box child)
                                registerTypeApplyArgReplay childNodeId child
                                match EvalReplayValueStore.tryType childNodeId with
                                | Some value -> value
                                | None -> failwith ("type_apply_arg_child_missing:" + label + ":" + evalNodeShapeTy child)
                            match texpr with
                            | TV i ->
                                let globalTypeLen =
                                    if obj.ReferenceEquals(s.env_global_type, null) then 0
                                    else s.env_global_type.Length
                                let stackTypeLen =
                                    if obj.ReferenceEquals(s.env_stack_type, null) then 0
                                    else s.env_stack_type.Length
                                if i >= 0 && i < globalTypeLen then
                                    EvalReplayValueStore.putTypeValue replayNodeId s.env_global_type.[i]
                                elif i >= globalTypeLen && (i - globalTypeLen) >= 0 && (i - globalTypeLen) < stackTypeLen then
                                    EvalReplayValueStore.putTypeValue replayNodeId s.env_stack_type.[i - globalTypeLen]
                                else
                                    EvalReplayValueStore.putType replayNodeId (fun () -> vt s i)
                            | TPrim a -> EvalReplayValueStore.putType replayNodeId (fun () -> YPrim a)
                            | TSymbol(_,a) -> EvalReplayValueStore.putType replayNodeId (fun () -> YSymbol a)
                            | TNominal i -> EvalReplayValueStore.putType replayNodeId (fun () -> YNominal env.nominals.[i])
                            | TLit(_,lit) -> EvalReplayValueStore.putType replayNodeId (fun () -> YLit lit)
                            | TB _ -> EvalReplayValueStore.putType replayNodeId (fun () -> YB)
                            | TExists -> EvalReplayValueStore.putType replayNodeId (fun () -> YExists)
                            | TForall' _ -> EvalReplayValueStore.putType replayNodeId (fun () -> YForall)
                            | TMetaV i -> EvalReplayValueStore.putType replayNodeId (fun () -> YMetavar i)
                            | TArrow'(scope,i,body) ->
                                EvalReplayValueStore.putType replayNodeId (fun () ->
                                    assert (i = scope.ty.free_vars.Length)
                                    YTypeFunction(body, HopacExtensions.A.map (vt s) scope.ty.free_vars, scope.term.stack_size, scope.ty.stack_size))
                            | TPair(_,a,b) ->
                                let leftNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box a)
                                let rightNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box b)
                                registerTypeApplyArgReplay leftNodeId a
                                registerTypeApplyArgReplay rightNodeId b
                                EvalReplayValueStore.putTypePairSpine replayNodeId {
                                    leftNodeId = leftNodeId
                                    leftShape = evalNodeShapeTy a
                                    rightNodeId = rightNodeId
                                    rightShape = evalNodeShapeTy b
                                }
                                EvalReplayValueStore.putType replayNodeId (fun () -> YPair(childType "TApplyArg.TPair.left" a, childType "TApplyArg.TPair.right" b))
                            | TFun(a,b,t) ->
                                let argNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box a)
                                let bodyNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box b)
                                registerTypeApplyArgReplay argNodeId a
                                registerTypeApplyArgReplay bodyNodeId b
                                match a with
                                | TV i ->
                                    let globalTypeLen =
                                        if obj.ReferenceEquals(s.env_global_type, null) then 0
                                        else s.env_global_type.Length
                                    let stackTypeLen =
                                        if obj.ReferenceEquals(s.env_stack_type, null) then 0
                                        else s.env_stack_type.Length
                                    if i >= globalTypeLen && stackTypeLen = 0 then
                                        // ALPHA644: mirror the TFun.arg free-metavar witness
                                        // for nested type-argument replay.
                                        EvalReplayValueStore.putTypeValue argNodeId (YMetavar i)
                                        DiagJson.emit (
                                            sprintf "{\"kind\":\"eval_worklist_tfun_arg_tv_free_metavar_snapshot\",\"event\":\"type_apply_arg_register\",\"parent_node_id\":%d,\"child_node_id\":%d,\"role\":\"type_apply_arg_tfun_arg_free_metavar\",\"index\":%d,\"global_len\":%d,\"stack_len\":%d,\"site\":%s,\"single_flight\":1,\"next\":\"type_value_materialized_from_free_metavar\"}"
                                                replayNodeId argNodeId i globalTypeLen stackTypeLen (DiagJson.esc site))
                                | _ -> ()
                                match b with
                                | TV i ->
                                    let globalTypeLen =
                                        if obj.ReferenceEquals(s.env_global_type, null) then 0
                                        else s.env_global_type.Length
                                    let stackTypeLen =
                                        if obj.ReferenceEquals(s.env_stack_type, null) then 0
                                        else s.env_stack_type.Length
                                    if i = globalTypeLen && stackTypeLen = 0 then
                                        EvalReplayValueStore.putType bodyNodeId (fun () -> childType "TApplyArg.TFun.body_immediate_binder" a)
                                        DiagJson.emit (
                                            sprintf "{\"kind\":\"eval_worklist_tfun_body_tv_binder_snapshot\",\"event\":\"type_apply_arg_register\",\"parent_node_id\":%d,\"child_node_id\":%d,\"role\":\"type_apply_arg_tfun_body_immediate_binder\",\"index\":%d,\"global_len\":%d,\"stack_len\":%d,\"arg_node_id\":%d,\"site\":%s,\"single_flight\":1,\"next\":\"type_value_materialized_from_arg_binder\"}"
                                                replayNodeId bodyNodeId i globalTypeLen stackTypeLen argNodeId (DiagJson.esc site))
                                | _ -> ()
                                EvalReplayValueStore.putTypeFunSpine replayNodeId {
                                    argNodeId = argNodeId
                                    argShape = evalNodeShapeTy a
                                    bodyNodeId = bodyNodeId
                                    bodyShape = evalNodeShapeTy b
                                    funType = t
                                }
                                EvalReplayValueStore.putType replayNodeId (fun () -> YFun(childType "TApplyArg.TFun.arg" a, childType "TApplyArg.TFun.body" b,t))
                            | _ -> ()
                        match typeArg with
                        | TV i ->
                            // ALPHA568: mirror registerReplayTy's TV snapshot policy for
                            // ETypeApply type arguments.  The alpha567 runtime showed the
                            // final blocker is a TV whose replay thunk lost its type env.
                            // In-bounds variables become stable replay values; out-of-bounds
                            // entries remain fail-closed through vt/terminal TV diagnostics.
                            let globalTypeLen =
                                if obj.ReferenceEquals(s.env_global_type, null) then 0
                                else s.env_global_type.Length
                            let stackTypeLen =
                                if obj.ReferenceEquals(s.env_stack_type, null) then 0
                                else s.env_stack_type.Length
                            if i >= 0 && i < globalTypeLen then
                                EvalReplayValueStore.putTypeValue typeNodeId s.env_global_type.[i]
                            elif i >= globalTypeLen && (i - globalTypeLen) >= 0 && (i - globalTypeLen) < stackTypeLen then
                                EvalReplayValueStore.putTypeValue typeNodeId s.env_stack_type.[i - globalTypeLen]
                            elif i >= globalTypeLen && stackTypeLen = 0 then
                                EvalReplayValueStore.putTypeValue typeNodeId (YMetavar i)
                                DiagJson.emit (
                                    sprintf "{\"kind\":\"eval_worklist_type_apply_arg_tv_free_metavar_snapshot\",\"event\":\"type_apply_arg_register\",\"parent_node_id\":%d,\"child_node_id\":%d,\"index\":%d,\"global_len\":%d,\"stack_len\":%d,\"site\":%s,\"policy\":\"empty_type_env_tv_is_free_metavar\",\"single_flight\":1,\"next\":\"type_value_materialized_from_free_metavar\"}"
                                        nodeId typeNodeId i globalTypeLen stackTypeLen (DiagJson.esc site))
                            else
                                EvalReplayValueStore.putType typeNodeId (fun () -> vt s i)
                        | TArrow'(scope,i,body) ->
                            EvalReplayValueStore.putType typeNodeId (fun () ->
                                assert (i = scope.ty.free_vars.Length)
                                YTypeFunction(body, HopacExtensions.A.map (vt s) scope.ty.free_vars, scope.term.stack_size, scope.ty.stack_size))
                        | TLit(_,lit) -> EvalReplayValueStore.putType typeNodeId (fun () -> YLit lit)
                        | TB _ -> EvalReplayValueStore.putType typeNodeId (fun () -> YB)
                        | TExists -> EvalReplayValueStore.putType typeNodeId (fun () -> YExists)
                        | TForall' _ -> EvalReplayValueStore.putType typeNodeId (fun () -> YForall)
                        | TMetaV i -> EvalReplayValueStore.putType typeNodeId (fun () -> YMetavar i)
                        // ALPHA394: mirror constructive type replay for type-apply args.
                        | TPrim a -> EvalReplayValueStore.putType typeNodeId (fun () -> YPrim a)
                        | TSymbol(_,a) -> EvalReplayValueStore.putType typeNodeId (fun () -> YSymbol a)
                        | TNominal i -> EvalReplayValueStore.putType typeNodeId (fun () -> YNominal env.nominals.[i])
                        | TPair _ -> registerTypeApplyArgReplay typeNodeId typeArg
                        | TFun _ -> registerTypeApplyArgReplay typeNodeId typeArg
                        | TModule a ->
                            EvalReplayValueStore.putType typeNodeId (fun () ->
                                YRecord(
                                    a
                                    |> Seq.mapi (fun i (KeyValue (k, v)) -> (i, k), (v |> ty s))
                                    |> Map.ofSeq))
                        | TRecord(_,a) -> EvalReplayValueStore.putType typeNodeId (fun () -> YRecord(Map.map (fun _ -> ty s) a))
                        | TArray a -> EvalReplayValueStore.putType typeNodeId (fun () -> YArray(ty s a))
                        | TLayout(a,b) -> EvalReplayValueStore.putType typeNodeId (fun () -> YLayout(ty s a,b))
                        | _ -> ()
                        EvalReplayValueStore.putTypeApplySpine nodeId {
                            funcNodeId = funcNodeId
                            funcShape = evalNodeShapeTerm func
                            typeNodeId = typeNodeId
                            typeShape = evalNodeShapeTy typeArg
                        }
                        EvalReplayValueStore.putTypeApplyContext nodeId (box s)
                        // ALPHA370: value-gated DForall body replay for ETypeApply.
                        // This mirrors type_apply but remains a thunk inside the replay value
                        // store.  If evaluating the forall body still hits a cycle, tryTerm
                        // catches the exception and the worklist remains semantic_step_partial.
                        EvalReplayValueStore.putTerm nodeId (fun () ->
                            let funcValue =
                                match EvalReplayValueStore.tryTerm funcNodeId with
                                | Some value -> value
                                | None -> failwith ("type_apply_func_value_missing:" + evalNodeShapeTerm func)
                            let typeValue =
                                match EvalReplayValueStore.tryType typeNodeId with
                                | Some value -> value
                                | None -> failwith ("type_apply_arg_value_missing:" + evalNodeShapeTy typeArg)
                            match funcValue with
                            | DForall(body,gl_term,gl_ty,sz_term,sz_ty) ->
                                let s' = { s with env_global_type = gl_ty; env_global_term = gl_term; env_stack_type = Array.zeroCreate<_> sz_ty; env_stack_term = Array.zeroCreate<_> sz_term }
                                s'.env_stack_type.[0] <- typeValue
                                term s' body
                            | DV(L(_,YForall)) -> failwith "Replay type-apply cannot apply runtime forall during partial evaluation."
                            | a -> failwith (sprintf "Replay type-apply expected forall; got %s" (show_data a)))
                    | EMacro(r,a,b) ->
                        // ALPHA443/647: macros are real replay values and composites.
                        // Register child terms/types plus the result type before the
                        // fail-closed thunk, so replay can drive a missing macro child
                        // instead of repeating the full macro thunk.
                        let rec registerMacroTypeReplay (macroTypeNodeId: int) (texpr: TPrepass) =
                            // ALPHA648: keep EMacro type children local to this registerReplayTerm
                            // branch.  Alpha647 accidentally called registerReplayTy here, but
                            // that helper is scoped to another registration path.
                            let childType (label: string) (child: TPrepass) =
                                let childNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box child)
                                registerMacroTypeReplay childNodeId child
                                match EvalReplayValueStore.tryType childNodeId with
                                | Some value -> value
                                | None -> failwith ("macro_type_child_missing:" + label + ":" + evalNodeShapeTy child)
                            match texpr with
                            | TV i ->
                                let globalTypeLen =
                                    if obj.ReferenceEquals(s.env_global_type, null) then 0
                                    else s.env_global_type.Length
                                let stackTypeLen =
                                    if obj.ReferenceEquals(s.env_stack_type, null) then 0
                                    else s.env_stack_type.Length
                                if i >= 0 && i < globalTypeLen then
                                    EvalReplayValueStore.putTypeValue macroTypeNodeId s.env_global_type.[i]
                                elif i >= globalTypeLen && (i - globalTypeLen) >= 0 && (i - globalTypeLen) < stackTypeLen then
                                    EvalReplayValueStore.putTypeValue macroTypeNodeId s.env_stack_type.[i - globalTypeLen]
                                else
                                    EvalReplayValueStore.putType macroTypeNodeId (fun () -> vt s i)
                            | TPrim a -> EvalReplayValueStore.putType macroTypeNodeId (fun () -> YPrim a)
                            | TSymbol(_,a) -> EvalReplayValueStore.putType macroTypeNodeId (fun () -> YSymbol a)
                            | TNominal i -> EvalReplayValueStore.putType macroTypeNodeId (fun () -> YNominal env.nominals.[i])
                            | TLit(_,lit) -> EvalReplayValueStore.putType macroTypeNodeId (fun () -> YLit lit)
                            | TB _ -> EvalReplayValueStore.putType macroTypeNodeId (fun () -> YB)
                            | TExists -> EvalReplayValueStore.putType macroTypeNodeId (fun () -> YExists)
                            | TForall' _ -> EvalReplayValueStore.putType macroTypeNodeId (fun () -> YForall)
                            | TMetaV i -> EvalReplayValueStore.putType macroTypeNodeId (fun () -> YMetavar i)
                            | TArrow'(scope,i,body) ->
                                EvalReplayValueStore.putType macroTypeNodeId (fun () ->
                                    assert (i = scope.ty.free_vars.Length)
                                    YTypeFunction(body, HopacExtensions.A.map (vt s) scope.ty.free_vars, scope.term.stack_size, scope.ty.stack_size))
                            | TPair(_,a,b) ->
                                let leftNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box a)
                                let rightNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box b)
                                registerMacroTypeReplay leftNodeId a
                                registerMacroTypeReplay rightNodeId b
                                EvalReplayValueStore.putTypePairSpine macroTypeNodeId {
                                    leftNodeId = leftNodeId
                                    leftShape = evalNodeShapeTy a
                                    rightNodeId = rightNodeId
                                    rightShape = evalNodeShapeTy b
                                }
                                EvalReplayValueStore.putType macroTypeNodeId (fun () -> YPair(childType "EMacro.TPair.left" a, childType "EMacro.TPair.right" b))
                            | TFun(a,b,t) ->
                                let argNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box a)
                                let bodyNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box b)
                                registerMacroTypeReplay argNodeId a
                                registerMacroTypeReplay bodyNodeId b
                                EvalReplayValueStore.putTypeFunSpine macroTypeNodeId {
                                    argNodeId = argNodeId
                                    argShape = evalNodeShapeTy a
                                    bodyNodeId = bodyNodeId
                                    bodyShape = evalNodeShapeTy b
                                    funType = t
                                }
                                EvalReplayValueStore.putType macroTypeNodeId (fun () -> YFun(childType "EMacro.TFun.arg" a, childType "EMacro.TFun.body" b,t))
                            | TModule a ->
                                EvalReplayValueStore.putType macroTypeNodeId (fun () ->
                                    YRecord(
                                        a
                                        |> Seq.mapi (fun i (KeyValue (k, v)) -> (i, k), (v |> ty s))
                                        |> Map.ofSeq))
                            | TRecord(_,a) -> EvalReplayValueStore.putType macroTypeNodeId (fun () -> YRecord(Map.map (fun _ -> ty s) a))
                            | TArray a -> EvalReplayValueStore.putType macroTypeNodeId (fun () -> YArray(ty s a))
                            | TLayout(a,b) -> EvalReplayValueStore.putType macroTypeNodeId (fun () -> YLayout(ty s a,b))
                            | _ -> EvalReplayValueStore.putType macroTypeNodeId (fun () -> ty s texpr)
                        let macroTermChildren =
                            a
                            |> List.choose (function MTerm(x,_) -> Some x | _ -> None)
                            |> List.toArray
                        let macroTypeChildren =
                            a
                            |> List.choose (function MType x | MLitType x -> Some x | _ -> None)
                            |> List.toArray
                        let macroTermNodeIds = macroTermChildren |> Array.map (fun x -> System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box x))
                        let macroTermShapes = macroTermChildren |> Array.map evalNodeShapeTerm
                        let macroTypeNodeIds = macroTypeChildren |> Array.map (fun x -> System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box x))
                        let macroTypeShapes = macroTypeChildren |> Array.map evalNodeShapeTy
                        macroTermChildren |> Array.iteri (fun i child -> registerReplayTerm macroTermNodeIds.[i] child)
                        macroTypeChildren |> Array.iteri (fun i child -> registerMacroTypeReplay macroTypeNodeIds.[i] child)
                        let macroResultTypeNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box b)
                        registerMacroTypeReplay macroResultTypeNodeId b
                        EvalReplayValueStore.putMacroSpine nodeId {
                            termNodeIds = macroTermNodeIds
                            termShapes = macroTermShapes
                            typeNodeIds = macroTypeNodeIds
                            typeShapes = macroTypeShapes
                            resultTypeNodeId = macroResultTypeNodeId
                            resultTypeShape = evalNodeShapeTy b
                        }
                        EvalReplayValueStore.putTerm nodeId (fun () ->
                            let s2 = add_trace s r
                            let mutable macroTermIx = 0
                            let mutable macroTypeIx = 0
                            let cachedTerm label idx =
                                if idx >= 0 && idx < macroTermNodeIds.Length then
                                    match EvalReplayValueStore.tryTerm macroTermNodeIds.[idx] with
                                    | Some value -> value
                                    | None -> failwith ("macro_cached_term_missing:" + label + ":" + string idx)
                                else failwith ("macro_cached_term_index_oob:" + label + ":" + string idx)
                            let cachedType label idx =
                                if idx >= 0 && idx < macroTypeNodeIds.Length then
                                    match EvalReplayValueStore.tryType macroTypeNodeIds.[idx] with
                                    | Some value -> value
                                    | None -> failwith ("macro_cached_type_missing:" + label + ":" + string idx)
                                else failwith ("macro_cached_type_index_oob:" + label + ":" + string idx)
                            let macroItems =
                                a |> List.map (function
                                    | MText x -> CMText x
                                    | MTerm (_,is_inline) ->
                                        let idx = macroTermIx
                                        macroTermIx <- macroTermIx + 1
                                        CMTerm(cachedTerm "MTerm" idx |> dyn false s2, is_inline)
                                    | MType _ ->
                                        let idx = macroTypeIx
                                        macroTypeIx <- macroTypeIx + 1
                                        CMType(cachedType "MType" idx)
                                    | MLitType _ ->
                                        let idx = macroTypeIx
                                        macroTypeIx <- macroTypeIx + 1
                                        CMTypeLit(cachedType "MLitType" idx |> assert_ty_lit s2))
                            let resultTy =
                                match EvalReplayValueStore.tryType macroResultTypeNodeId with
                                | Some value -> value
                                | None -> failwith "macro_cached_result_type_missing"
                            DiagJson.emit (
                                sprintf "{\"kind\":\"eval_worklist_macro_cached_children_used\",\"event\":\"term_thunk\",\"node_id\":%d,\"shape\":\"EMacro\",\"term_children\":%d,\"type_children\":%d,\"single_flight\":1,\"next\":\"push_typedop_macro\"}"
                                    nodeId macroTermNodeIds.Length macroTypeNodeIds.Length)
                            push_typedop_no_rewrite s2 (TyMacro(macroItems)) resultTy)
                    | ERecordWith(r,vars,withs,withouts) ->
                        let recordChildTerms =
                            let xs = ResizeArray<string * E>()
                            vars |> List.iteri (fun i (_, child) -> xs.Add(sprintf "record_path_%d" i, child))
                            withs |> List.iteri (fun i item ->
                                match item with
                                | RSymbol((_, key), child) -> xs.Add(sprintf "record_with_symbol_%d:%s" i key, child)
                                | RSymbolModify((_, key), child) -> xs.Add(sprintf "record_modify_symbol_%d:%s" i key, child)
                                | RVar((_, keyExpr), child) ->
                                    xs.Add(sprintf "record_with_var_key_%d" i, keyExpr)
                                    xs.Add(sprintf "record_with_var_value_%d" i, child)
                                | RVarModify((_, keyExpr), child) ->
                                    xs.Add(sprintf "record_modify_var_key_%d" i, keyExpr)
                                    xs.Add(sprintf "record_modify_var_value_%d" i, child))
                            withouts |> List.iteri (fun i item ->
                                match item with
                                | WSymbol _ -> ()
                                | WVar(_, keyExpr) -> xs.Add(sprintf "record_without_var_%d" i, keyExpr))
                            xs.ToArray()
                        let recordChildNodeIds =
                            recordChildTerms
                            |> Array.map (fun (_, child) -> System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box child))
                        let recordChildShapes = recordChildTerms |> Array.map (fun (_, child) -> evalNodeShapeTerm child)
                        let recordChildRoles = recordChildTerms |> Array.map fst
                        recordChildTerms
                        |> Array.iteri (fun i (_, child) ->
                            registerReplayTerm recordChildNodeIds.[i] child)
                        EvalReplayValueStore.putRecordWithSpine nodeId {
                            childNodeIds = recordChildNodeIds
                            childShapes = recordChildShapes
                            childRoles = recordChildRoles
                        }
                        EvalReplayValueStore.putTerm nodeId (fun () ->
                            let base_s = add_trace s r
                            let tryPickKey (key: string) (m: Map<int * string, Data>) =
                                m |> Map.tryPick (fun (i, k) v -> if k = key then Some (i, v) else None)
                            // ALPHA570: once RecordWith children have been scheduled by the replay spine,
                            // consume their materialized values instead of re-entering the original
                            // evaluator.  Falling back to term keeps the old fail-closed behavior when
                            // a child has not been materialized yet.
                            let recordChildValue (traceRange: Range option) (child: E) =
                                let childNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box child)
                                match EvalReplayValueStore.tryTerm childNodeId with
                                | Some value -> value
                                | None ->
                                    match traceRange with
                                    | Some rr -> term (add_trace base_s rr) child
                                    | None -> term base_s child
                            let var rr a =
                                match recordChildValue (Some rr) a with
                                | DSymbol k -> k
                                | other -> failwith (sprintf "Replay record-with expected symbol; got %s" (show_data other))
                            let applyMap (m0: Map<int * string, Data>) =
                                let mutable m = m0
                                let mutable xs = withs
                                while not xs.IsEmpty do
                                    match xs with
                                    | x :: rest ->
                                        let sym a b =
                                            let i =
                                                m
                                                |> Map.tryPick (fun (i, k) _ -> if k = a then Some i else None)
                                                |> Option.defaultValue m.Count
                                            m <- Map.add (i, a) (recordChildValue None b) m
                                        let symMod rr a b =
                                            match tryPickKey a m with
                                            | Some (i, oldValue) -> m <- Map.add (i, a) (EvalReplayValueStore.runApplyAfterDefinition (box base_s) (recordChildValue (Some rr) b) oldValue) m
                                            | None -> failwith (sprintf "Replay record-with cannot find key %s" a)
                                        match x with
                                        | RSymbol((_, a), b) -> sym a b
                                        | RSymbolModify((rr, a), b) -> symMod rr a b
                                        | RVar((rr, a), b) -> sym (var rr a) b
                                        | RVarModify((rr, a), b) -> symMod rr (var rr a) b
                                        xs <- rest
                                    | [] -> ()
                                let mutable ys = withouts
                                while not ys.IsEmpty do
                                    match ys with
                                    | x :: rest ->
                                        match x with
                                        | WSymbol(_, a) ->
                                            m <- m |> Map.filter (fun (_, k) _ -> k <> a)
                                        | WVar(rr, a) ->
                                            let a = var rr a
                                            m <- m |> Map.filter (fun (_, k) _ -> k <> a)
                                        ys <- rest
                                    | [] -> ()
                                m
                            let updateNested (root: Map<int * string, Data>) (xs: (Range * E) list) =
                                let path = ResizeArray<struct(Range * string)>()
                                let mutable cur = xs
                                while not cur.IsEmpty do
                                    match cur with
                                    | (rr, x) :: rest ->
                                        match recordChildValue (Some rr) x with
                                        | DSymbol k -> path.Add(struct(rr, k))
                                        | other -> failwith (sprintf "Replay record-with path expected symbol; got %s" (show_data other))
                                        cur <- rest
                                    | [] -> ()
                                let mutable curMap = root
                                let parents = ResizeArray<struct(int * string * Map<int * string, Data>)>()
                                for i = 0 to path.Count - 1 do
                                    let struct(rr, k) = path.[i]
                                    match tryPickKey k curMap with
                                    | Some (idx, DRecord sub) ->
                                        parents.Add(struct(idx, k, curMap))
                                        curMap <- sub
                                    | Some (_, other) -> failwith (sprintf "Replay record-with path expected record; got %s" (show_data other))
                                    | None -> failwith (sprintf "Replay record-with cannot find key %s" k)
                                let mutable updated = applyMap curMap
                                for i = parents.Count - 1 downto 0 do
                                    let struct(idx, k, parent) = parents.[i]
                                    updated <- Map.add (idx, k) (DRecord updated) parent
                                updated
                            let out =
                                match vars with
                                | (rr, x) :: xs ->
                                    match recordChildValue (Some rr) x with
                                    | DRecord root -> updateNested root xs
                                    | other -> failwith (sprintf "Replay record-with expected base record; got %s" (show_data other))
                                | [] -> applyMap Map.empty
                            DRecord out)
                    | EOp(_,op,args) ->
                        let argArray = args |> List.toArray
                        for arg in argArray do
                            let argNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box arg)
                            registerReplayTerm argNodeId arg
                            match arg with
                            | EV a -> EvalReplayValueStore.putTerm argNodeId (fun () -> v s a)
                            | ELit(_,lit) -> EvalReplayValueStore.putTermValue argNodeId (DLit lit)
                            | ESymbol(_,sym) -> EvalReplayValueStore.putTermValue argNodeId (DSymbol sym)
                            | EType(_,texpr) ->
                                EvalReplayValueStore.putType argNodeId (fun () -> ty s texpr)
                                EvalReplayValueStore.putTerm argNodeId (fun () -> ty_to_data s (ty s texpr))
                            | EDefaultLit(_,_,_) -> ()
                            | _ -> ()
                        let opReplayNodeIds = argArray |> Array.map (fun e -> System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box e))
                        let opReplayName = sprintf "%A" op
                        EvalReplayValueStore.putOpContext nodeId (box s)
                        EvalReplayValueStore.putApplyContext nodeId (box s)
                        EvalReplayValueStore.putOpSpine nodeId {
                            opName = opReplayName
                            argCount = argArray.Length
                            argNodeIds = opReplayNodeIds
                            argShapes = argArray |> Array.map evalNodeShapeTerm
                        }
                        EvalReplayValueStore.putTerm nodeId (fun () ->
                            match EvalReplayValueStore.tryResolvePureOpWithContext nodeId opReplayName opReplayNodeIds with
                            | Some value -> value
                            | None -> failwith (sprintf "op_value_missing:%s/%d" opReplayName argArray.Length))
                    | EIfThenElse(_,cond,onTrue,onFalse) ->
                        let condNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box cond)
                        let trueNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box onTrue)
                        let falseNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box onFalse)
                        // ALPHA654: the unknown-return branch probe can schedule
                        // a non-leaf branch (observed ELet at core/listm.spi:6).
                        // Register all three children recursively so scheduled
                        // branch cells have their normal thunks/spines available.
                        registerReplayTerm condNodeId cond
                        registerReplayTerm trueNodeId onTrue
                        registerReplayTerm falseNodeId onFalse
                        DiagJson.emit (
                            sprintf "{\"kind\":\"eval_worklist_if_branch_children_registered\",\"event\":\"term_entry_global_fuse\",\"node_id\":%d,\"shape\":\"EIfThenElse\",\"site\":%s,\"condition_node_id\":%d,\"true_node_id\":%d,\"true_shape\":%s,\"false_node_id\":%d,\"false_shape\":%s,\"single_flight\":1,\"next\":\"if_children_ready_for_branch_probe\"}"
                                nodeId (DiagJson.esc site) condNodeId trueNodeId (DiagJson.esc (evalNodeShapeTerm onTrue)) falseNodeId (DiagJson.esc (evalNodeShapeTerm onFalse)))
                        match cond with
                        | EV a -> EvalReplayValueStore.putTerm condNodeId (fun () -> v s a)
                        | ELit(_,lit) -> EvalReplayValueStore.putTermValue condNodeId (DLit lit)
                        | ESymbol(_,sym) -> EvalReplayValueStore.putTermValue condNodeId (DSymbol sym)
                        | _ -> ()
                        match onTrue with
                        | EV a -> EvalReplayValueStore.putTerm trueNodeId (fun () -> v s a)
                        | ELit(_,lit) -> EvalReplayValueStore.putTermValue trueNodeId (DLit lit)
                        | ESymbol(_,sym) -> EvalReplayValueStore.putTermValue trueNodeId (DSymbol sym)
                        | _ -> ()
                        match onFalse with
                        | EV a -> EvalReplayValueStore.putTerm falseNodeId (fun () -> v s a)
                        | ELit(_,lit) -> EvalReplayValueStore.putTermValue falseNodeId (DLit lit)
                        | ESymbol(_,sym) -> EvalReplayValueStore.putTermValue falseNodeId (DSymbol sym)
                        | _ -> ()
                        EvalReplayValueStore.putIfThenElse nodeId {
                            condNodeId = condNodeId
                            condShape = evalNodeShapeTerm cond
                            trueNodeId = trueNodeId
                            trueShape = evalNodeShapeTerm onTrue
                            falseNodeId = falseNodeId
                            falseShape = evalNodeShapeTerm onFalse
                        }
                    | EApply _ ->
                        let args = ResizeArray<E>()
                        let mutable cur = expr
                        let mutable running = true
                        while running do
                            match cur with
                            | EApply(_, a, b) ->
                                args.Add b
                                cur <- a
                            | _ -> running <- false
                        let headNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box cur)
                        registerReplayTerm headNodeId cur
                        match cur with
                        | EB _ -> EvalReplayValueStore.putTermValue headNodeId DB
                        | EV a -> EvalReplayValueStore.putTerm headNodeId (fun () -> v s a)
                        | ELit(_,lit) -> EvalReplayValueStore.putTermValue headNodeId (DLit lit)
                        | ESymbol(_,sym) -> EvalReplayValueStore.putTermValue headNodeId (DSymbol sym)
                        | EFun'(_,freeVars,i,body,annot) ->
                            EvalReplayValueStore.putTerm headNodeId (fun () ->
                                if freeVars.term.free_vars.Length <> i then failwith "Replay apply-head function free-var arity mismatch."
                                DFunction(body, annot, HopacExtensions.A.map (v s) freeVars.term.free_vars, HopacExtensions.A.map (vt s) freeVars.ty.free_vars, freeVars.term.stack_size, freeVars.ty.stack_size))
                        | ERecursiveFun'(_,freeVars,i,body,annot) ->
                            EvalReplayValueStore.putTerm headNodeId (fun () ->
                                if freeVars.term.free_vars.Length <> i then failwith "Replay apply-head recursive function free-var arity mismatch."
                                DFunction(body.Value, annot, HopacExtensions.A.map (v s) freeVars.term.free_vars, HopacExtensions.A.map (vt s) freeVars.ty.free_vars, freeVars.term.stack_size, freeVars.ty.stack_size))
                        | EForall'(_,freeVars,i,body) ->
                            EvalReplayValueStore.putTerm headNodeId (fun () ->
                                if freeVars.ty.free_vars.Length <> i then failwith "Replay apply-head forall free-var arity mismatch."
                                DForall(body, HopacExtensions.A.map (v s) freeVars.term.free_vars, HopacExtensions.A.map (vt s) freeVars.ty.free_vars, freeVars.term.stack_size, freeVars.ty.stack_size))
                        | ERecursiveForall'(_,freeVars,i,body) ->
                            EvalReplayValueStore.putTerm headNodeId (fun () ->
                                if freeVars.ty.free_vars.Length <> i then failwith "Replay apply-head recursive forall free-var arity mismatch."
                                DForall(body.Value, HopacExtensions.A.map (v s) freeVars.term.free_vars, HopacExtensions.A.map (vt s) freeVars.ty.free_vars, freeVars.term.stack_size, freeVars.ty.stack_size))
                        | _ -> ()
                        for arg in args do
                            let argNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box arg)
                            registerReplayTerm argNodeId arg
                            match arg with
                            | EB _ -> EvalReplayValueStore.putTermValue argNodeId DB
                            | EV a -> EvalReplayValueStore.putTerm argNodeId (fun () -> v s a)
                            | ELit(_,lit) -> EvalReplayValueStore.putTermValue argNodeId (DLit lit)
                            | ESymbol(_,sym) -> EvalReplayValueStore.putTermValue argNodeId (DSymbol sym)
                            | _ -> ()
                        let replayArgs = args.ToArray()
                        EvalReplayValueStore.putApplySpine nodeId {
                            headNodeId = headNodeId
                            headShape = evalNodeShapeTerm cur
                            argCount = replayArgs.Length
                            argNodeIds = replayArgs |> Array.map (fun e -> System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box e))
                            argShapes = replayArgs |> Array.map evalNodeShapeTerm
                        }
                        EvalReplayValueStore.putApplyContext nodeId (box s)
                        // ALPHA380: register a whole-spine thunk without lexically capturing apply.
                        // The real apply function is installed later through EvalReplayValueStore after
                        // its definition.  Until then this thunk fails closed under tryTerm.
                        EvalReplayValueStore.putTerm nodeId (fun () ->
                            let mutable current =
                                match EvalReplayValueStore.tryTerm headNodeId with
                                | Some value -> value
                                | None -> failwith ("apply_head_value_missing:" + evalNodeShapeTerm cur)
                            for i = replayArgs.Length - 1 downto 0 do
                                let arg = replayArgs.[i]
                                let argNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box arg)
                                let argValue =
                                    match EvalReplayValueStore.tryTerm argNodeId with
                                    | Some value -> value
                                    | None -> failwith ("apply_arg_value_missing:" + evalNodeShapeTerm arg)
                                current <- EvalReplayValueStore.runApplyAfterDefinition (box s) current argValue
                            current)
                    | _ -> ()
                let fuseKindKey0, fuseKindSite0, _, _, _, _ = TermCycleFuse.describe()
                let activeFuseKind =
                    if fuseKindKey0.StartsWith("ty:") || fuseKindSite0.StartsWith("ty@") then "ty" else "term"
                if activeFuseKind <> "term" then
                    DiagJson.emit (
                        sprintf "{\"kind\":\"eval_worklist_kind_local_active_reset\",\"event\":\"term_entry_global_fuse\",\"active_kind\":%s,\"requested_kind\":\"term\",\"single_flight\":1,\"next\":\"continue_term_eval\"}"
                            (DiagJson.esc activeFuseKind))
                    EvalWorklist.parkActiveAndSelectKind "term" |> ignore
                    TermCycleFuse.reset()
                else
                    registerReplayTerm nodeId0 x
                    EvalWorklist.ensureCaptured "term_entry_global_fuse" |> ignore
                    EvalWorklist.attachSemanticCell "term_entry" (semanticCellForTerm nodeId0)
                    let frameOpt = EvalWorklist.ensureCapturedAndRun "term_entry_global_fuse" "term_entry" 8
                    let globalReplayComplete =
                        match frameOpt with
                        | Some frame when EvalWorklist.frameReplayCompleteKind "term" frame -> true
                        | Some _ -> EvalWorklist.hasReplayCompleteKind "term"
                        | None -> EvalWorklist.hasReplayCompleteKind "term"
                    if globalReplayComplete then
                        let k0, s0, d0, g0, re0, max0 = TermCycleFuse.describe()
                        let replayReturnMsg =
                            sprintf "%s: global term replay return suppressed after pinned terminal first_key=%s first_site=%s first_depth=%d gen=%d re=%d/%d" EJPCodes.EJP0011 k0 s0 d0 g0 re0 max0
                        match EvalWorklist.trySuppressGlobalFuseReplayReturnForPinnedTerminal "term_entry_global_fuse" "term" termShape0 replayReturnMsg with
                        | Some msg -> raise_type_error s msg
                        | None ->
                            match EvalReplayValueStore.tryTerm nodeId0 with
                            | Some value ->
                                // ALPHA929: global-fuse term replay returns may repeat while the
                                // drain is alive. Refresh JP progress so EJP0030 does not treat
                                // semantic_root_complete source returns as an idle scheduler.
                                System.Threading.Interlocked.Exchange(&jp_last_progress_ms, peval_sw.ElapsedMilliseconds) |> ignore
                                DiagJson.emit (
                                    sprintf "{\"kind\":\"eval_worklist_root_complete_replay_progress_marked\",\"event\":\"term_entry_global_fuse\",\"scope\":\"global_fuse_term_return\",\"status\":\"semantic_root_complete\",\"kind2\":\"term\",\"shape\":%s,\"single_flight\":1,\"next\":\"watchdog_progress_refreshed\"}"
                                        (DiagJson.esc (evalNodeShapeTerm x)))
                                DiagJson.emit (
                                    sprintf "{\"kind\":\"eval_worklist_global_fuse_term_replay_return\",\"event\":\"term_entry_global_fuse\",\"status\":\"semantic_root_complete\",\"shape\":%s,\"single_flight\":1,\"next\":\"return_term_value\"}"
                                        (DiagJson.esc (evalNodeShapeTerm x)))
                                DiagJson.emit (
                                    sprintf "{\"kind\":\"eval_worklist_fuse_clear_after_replay_return\",\"event\":\"term_entry_global_fuse\",\"status\":\"semantic_root_complete\",\"shape\":%s,\"single_flight\":1,\"next\":\"return_term_value\"}"
                                        (DiagJson.esc termShape0))
                                EvalReplayValueStore.putTermSourceValue termSourceKey0 value
                                DiagJson.emit (
                                    sprintf "{\"kind\":\"eval_worklist_source_value_stored\",\"event\":\"term_entry_global_fuse\",\"status\":\"semantic_root_complete\",\"shape\":%s,\"source_key\":%s,\"single_flight\":1,\"next\":\"return_term_value\"}"
                                        (DiagJson.esc termShape0) (DiagJson.esc termSourceKey0))
                                TermCycleFuse.reset ()
                                raise (EvalReplayTermReturn value)
                            | None ->
                                DiagJson.emit (
                                    sprintf "{\"kind\":\"eval_worklist_global_fuse_term_value_missing\",\"event\":\"term_entry_global_fuse\",\"status\":\"semantic_step_partial\",\"shape\":%s,\"single_flight\":1,\"next\":\"explicit_eval_worklist_record_or_term_stepper_required\"}"
                                        (DiagJson.esc (evalNodeShapeTerm x)))
                            // ALPHA441: alpha440 reached ESeq after a different term replay
                            // had already produced a root-complete witness.  That proof is
                            // useful for the worklist but not a value for the current term;
                            // treating it as fatal loses the next concrete trace.  For ESeq,
                            // EAnnot and now ENominal, clear the stale fuse and fall through to
                            // ordinary term evaluation so the real term/check path can expose the
                            // next blocker or settle the constructor through its stored spine.
                            let recoverableStaleRootShape =
                                termShape0 = "ESeq" || termShape0 = "EAnnot" || termShape0 = "ENominal"
                            let pendingRootWitnessCanDrain =
                                // ALPHA892: alpha891 proved the scheduler no longer dies at the
                                // previous app-root terminal pin, but a broader global-fuse path
                                // can still abort with a valid root-complete witness while the
                                // current term is partial (observed: ERecordTest) and pending
                                // replay work is alive.  Treat that as a coordinator state, not
                                // as semantic failure: clear the stale fuse and let the existing
                                // worklist drain reveal the next real blocker or complete root.
                                EvalWorklist.pendingCount() > 0
                            if recoverableStaleRootShape || pendingRootWitnessCanDrain then
                                let recoveryPolicy =
                                    if recoverableStaleRootShape then "recoverable_stale_root_shape"
                                    else "pending_root_witness_can_drain"
                                let partialCurrentKey = sprintf "%s|%s|%s|%d|%s" termShape0 k0 s0 d0 recoveryPolicy
                                let partialCurrentRepeat = jp_note_global_fuse_partial_current partialCurrentKey
                                let partialCurrentRepeatCap = 32
                                if partialCurrentRepeat > partialCurrentRepeatCap then
                                    DiagJson.emit (
                                        sprintf "{\"kind\":\"eval_worklist_global_fuse_root_witness_partial_current_repeat_blocked\",\"event\":\"term_entry_global_fuse\",\"status\":\"semantic_global_fuse_root_witness_partial_current_blocked\",\"shape\":%s,\"first_key\":%s,\"first_site\":%s,\"first_depth\":%d,\"pending\":%d,\"recovery\":%s,\"repeat\":%d,\"cap\":%d,%s,\"single_flight\":1,\"next\":\"typed_terminal_after_bounded_global_fuse_partial_current_repeat\"}"
                                            (DiagJson.esc termShape0) (DiagJson.esc k0) (DiagJson.esc s0) d0 (EvalWorklist.pendingCount()) (DiagJson.esc recoveryPolicy) partialCurrentRepeat partialCurrentRepeatCap (EvalWorklist.globalFuseTraceJson()))
                                    EvalWorklist.parkActiveAndSelectKind "term" |> ignore
                                    TermCycleFuse.reset ()
                                    raise_type_error s (sprintf "%s: global term-cycle fuse kept a root-complete witness while current term stayed partial after %d/%d deferrals first_key=%s first_site=%s first_depth=%d current_shape=%s recovery=%s" EJPCodes.EJP0011 partialCurrentRepeat partialCurrentRepeatCap k0 s0 d0 termShape0 recoveryPolicy)
                                else
                                    DiagJson.emit (
                                        sprintf "{\"kind\":\"eval_worklist_global_fuse_root_witness_partial_current_deferred\",\"event\":\"term_entry_global_fuse\",\"status\":\"semantic_step_partial\",\"shape\":%s,\"first_key\":%s,\"first_site\":%s,\"first_depth\":%d,\"pending\":%d,\"recovery\":%s,\"repeat\":%d,\"cap\":%d,%s,\"single_flight\":1,\"next\":\"fallthrough_term_eval\"}"
                                            (DiagJson.esc termShape0) (DiagJson.esc k0) (DiagJson.esc s0) d0 (EvalWorklist.pendingCount()) (DiagJson.esc recoveryPolicy) partialCurrentRepeat partialCurrentRepeatCap (EvalWorklist.globalFuseTraceJson()))
                                    EvalWorklist.parkActiveAndSelectKind "term" |> ignore
                                    TermCycleFuse.reset ()
                            else
                                raise_type_error s (sprintf "%s: global term-cycle fuse has a root-complete witness but current term value is still partial first_key=%s first_site=%s first_depth=%d gen=%d re=%d/%d current_shape=%s" EJPCodes.EJP0011 k0 s0 d0 g0 re0 max0 (evalNodeShapeTerm x))
                    else
                        if EvalWorklist.hasReplayCompleteOtherKind "term" then
                            DiagJson.emit "{\"kind\":\"eval_worklist_kind_local_fuse_reset\",\"event\":\"term_entry_global_fuse\",\"completed_kind\":\"other\",\"requested_kind\":\"term\",\"single_flight\":1,\"next\":\"continue_term_eval\"}"
                            EvalWorklist.parkActiveAndSelectKind "term" |> ignore
                            TermCycleFuse.reset()
                        else
                            let k0, s0, d0, g0, re0, max0 = TermCycleFuse.describe()
                            let orphanGlobalFuseWithLiveReplay =
                                // ALPHA973: alpha972 exposed an empty global-fuse descriptor
                                // (first_key=/first_site=/depth=0) while the worklist still had a
                                // continuation-envelope term replay cell and pending jobs.  That is
                                // not a durable terminal contract; it is an orphan coordinator fuse
                                // produced after the real frame was already moved into the replay
                                // payload.  Reset only this empty-key fuse while live replay evidence
                                // exists, otherwise keep the historical fail-closed StackOverflow
                                // guard intact.
                                System.String.IsNullOrWhiteSpace k0
                                && System.String.IsNullOrWhiteSpace s0
                                && d0 = 0
                                && EvalWorklist.pendingCount() > 0
                                && (EvalWorklist.replayQueueDepth() > 0
                                    || EvalWorklist.replayDriverActiveDepthValue() > 0
                                    || EvalWorklist.hasProgressYield()
                                    || EvalReplayValueStore.hasDeferredReplayCell()
                                    || EvalWorklist.semanticPayloadStatus() = "cell"
                                    || EvalWorklist.semanticPayloadStatus().Contains("continuation"))
                            if orphanGlobalFuseWithLiveReplay then
                                let orphanKey = sprintf "term|%s|%s|cursor=%d|pending=%d|orphan_global_fuse" (evalNodeShapeTerm x) site 0 (EvalWorklist.pendingCount())
                                let orphanRepeat = jp_note_global_fuse_partial_current orphanKey
                                let orphanCap = 96
                                if orphanRepeat > orphanCap then
                                    DiagJson.emit (
                                        sprintf "{\"kind\":\"eval_worklist_orphan_global_fuse_live_replay_repeat_blocked\",\"event\":\"term_entry_global_fuse\",\"status\":\"semantic_orphan_global_fuse_repeat_blocked\",\"shape\":%s,\"site\":%s,\"pending\":%d,\"queue_depth\":%d,\"active_depth\":%d,\"payload_status\":%s,\"repeat\":%d,\"cap\":%d,%s,\"single_flight\":1,\"next\":\"typed_terminal_after_bounded_orphan_global_fuse_replay\"}"
                                            (DiagJson.esc (evalNodeShapeTerm x)) (DiagJson.esc site) (EvalWorklist.pendingCount()) (EvalWorklist.replayQueueDepth()) (EvalWorklist.replayDriverActiveDepthValue()) (DiagJson.esc (EvalWorklist.semanticPayloadStatus())) orphanRepeat orphanCap (EvalWorklist.globalFuseTraceJson()))
                                    let msg = sprintf "%s: global term-cycle fuse already tripped first_key=%s first_site=%s first_depth=%d gen=%d re=%d/%d; aborting term worker before StackOverflow" EJPCodes.EJP0011 k0 s0 d0 g0 re0 max0
                                    let msg = EvalWorklist.retargetGlobalFuseAbortMessage "term_entry_global_fuse" "term" msg
                                    raise_type_error s msg
                                else
                                    DiagJson.emit (
                                        sprintf "{\"kind\":\"eval_worklist_orphan_global_fuse_live_replay_deferred\",\"event\":\"term_entry_global_fuse\",\"status\":\"semantic_step_partial\",\"shape\":%s,\"site\":%s,\"pending\":%d,\"queue_depth\":%d,\"active_depth\":%d,\"payload_status\":%s,\"repeat\":%d,\"cap\":%d,%s,\"policy\":\"empty_global_fuse_descriptor_cannot_outvote_live_replay_payload\",\"single_flight\":1,\"next\":\"fallthrough_term_eval\"}"
                                            (DiagJson.esc (evalNodeShapeTerm x)) (DiagJson.esc site) (EvalWorklist.pendingCount()) (EvalWorklist.replayQueueDepth()) (EvalWorklist.replayDriverActiveDepthValue()) (DiagJson.esc (EvalWorklist.semanticPayloadStatus())) orphanRepeat orphanCap (EvalWorklist.globalFuseTraceJson()))
                                    EvalWorklist.parkActiveAndSelectKind "term" |> ignore
                                    TermCycleFuse.reset()
                            else
                                let keyedParentContinuationFuseWithRunnableReplay =
                                    // ALPHA978: alpha977 reached a real non-empty global fuse key
                                    // (spiral.spi:2671) while the frame itself was a parent-continuation
                                    // cycle with replay_queue=1, pending=2, replay_complete=false and a
                                    // live semantic payload.  A keyed fuse is normally stronger than the
                                    // alpha973 orphan-fuse demotion, but it still must not outvote an
                                    // already scheduled parent replay driver tick.
                                    (not (System.String.IsNullOrWhiteSpace k0))
                                    && (not (System.String.IsNullOrWhiteSpace s0))
                                    && EvalWorklist.pendingCount() > 0
                                    && (EvalWorklist.replayQueueDepth() > 0
                                        || EvalWorklist.replayDriverActiveDepthValue() > 0)
                                    && (EvalWorklist.semanticPayloadStatus() = "cell"
                                        || EvalWorklist.semanticPayloadStatus().Contains("continuation")
                                        || EvalReplayValueStore.hasDeferredReplayCell()
                                        || EvalWorklist.hasProgressYield())
                                if keyedParentContinuationFuseWithRunnableReplay then
                                    let parentFuseShape = evalNodeShapeTerm x
                                    let parentFuseActiveDepth = EvalWorklist.replayDriverActiveDepthValue()
                                    let parentFuseHighPressure =
                                        parentFuseActiveDepth >= 16
                                        || (BigStack.isActive()
                                            && parentFuseActiveDepth >= 1
                                            && EvalWorklist.replayQueueDepth() > 0
                                            && EvalWorklist.pendingCount() > 0)
                                    let parentFuseRepeatKey =
                                        // ALPHA995: alpha989's first_key+current-site key is still right while the
                                        // replay frontier is moving. Runtime 994 proved that once active_depth reaches
                                        // the high-pressure band, first_key churn through sm'_real EAnnot/EAnnotTest
                                        // wrappers keeps every repeat local to 1 before manual interruption. In that
                                        // band, collapse to current shape+site so one concrete wrapper loop hits the
                                        // existing fail-closed bounded terminal instead of relying on Ctrl+C.
                                        if parentFuseHighPressure then
                                            sprintf "term|%s|%s|active_depth_parent_continuation_global_fuse_site_pressure"
                                                parentFuseShape site
                                        else
                                            sprintf "term|%s|%s|%s|parent_continuation_global_fuse_site_pressure"
                                                k0 s0 site
                                    let parentFuseRepeat = jp_note_global_fuse_partial_current parentFuseRepeatKey
                                    let parentFuseCap =
                                        if parentFuseHighPressure then 2
                                        elif EvalWorklist.replayQueueDepth() > 0 && EvalWorklist.pendingCount() > 0 then 16
                                        else 64
                                    let parentFuseCapExhausted = parentFuseRepeat > parentFuseCap
                                    let parentFuseRunnableReplayStillLive =
                                        parentFuseCapExhausted
                                        && EvalWorklist.pendingCount() > 0
                                        && (EvalWorklist.replayQueueDepth() > 0 || EvalWorklist.replayDriverActiveDepthValue() > 0)
                                        && not (EvalWorklist.hasReplayComplete())
                                    let parentFuseHighActiveReplayStarved =
                                        parentFuseRunnableReplayStillLive
                                        && parentFuseRepeat > (parentFuseCap * 8)
                                        && EvalWorklist.replayDriverActiveDepthValue() >= 16
                                    let parentFuseLowActiveReplayStarved =
                                        parentFuseRunnableReplayStillLive
                                        && parentFuseRepeat > (parentFuseCap * 4)
                                        && EvalWorklist.replayQueueDepth() <= 1
                                        && EvalWorklist.replayDriverActiveDepthValue() <= 4
                                    let parentFuseMidActiveNoQueueReplayStarved =
                                        parentFuseRunnableReplayStillLive
                                        && parentFuseRepeat > (parentFuseCap * 8)
                                        && EvalWorklist.replayQueueDepth() = 0
                                        && EvalWorklist.replayDriverActiveDepthValue() >= 5
                                        && EvalWorklist.replayDriverActiveDepthValue() <= 8
                                    let parentFuseMidActiveQueuedReplayStarved =
                                        parentFuseRunnableReplayStillLive
                                        && parentFuseRepeat > (parentFuseCap * 4)
                                        && EvalWorklist.replayQueueDepth() <= 2
                                        && EvalWorklist.replayDriverActiveDepthValue() >= 5
                                        && EvalWorklist.replayDriverActiveDepthValue() <= 8
                                    let parentFuseLowCapMidActiveQueuedReplayPlateau =
                                        parentFuseRunnableReplayStillLive
                                        && parentFuseCap <= 2
                                        && parentFuseRepeat >= (parentFuseCap * 4)
                                        && EvalWorklist.replayQueueDepth() <= 2
                                        && EvalWorklist.replayDriverActiveDepthValue() >= 5
                                        && EvalWorklist.replayDriverActiveDepthValue() <= 8
                                    let parentFuseQueuedPlateauReplayStarved =
                                        parentFuseRunnableReplayStillLive
                                        && parentFuseRepeat > (parentFuseCap * 8)
                                        && EvalWorklist.replayQueueDepth() <= 2
                                        && EvalWorklist.replayDriverActiveDepthValue() >= 9
                                        && EvalWorklist.replayDriverActiveDepthValue() <= 15
                                    let parentFuseLowCapHighActiveQueuedReplayPlateau =
                                        parentFuseRunnableReplayStillLive
                                        && parentFuseCap <= 2
                                        && parentFuseRepeat >= (parentFuseCap + 1)
                                        && EvalWorklist.replayQueueDepth() <= 2
                                        && EvalWorklist.replayDriverActiveDepthValue() >= 16
                                    let parentFuseMidActiveQueuedSlowRepeatPlateau =
                                        parentFuseRunnableReplayStillLive
                                        && parentFuseCap >= 16
                                        && parentFuseRepeat >= 4
                                        && EvalWorklist.replayQueueDepth() <= 1
                                        && EvalWorklist.replayDriverActiveDepthValue() >= 5
                                        && EvalWorklist.replayDriverActiveDepthValue() <= 8
                                    let parentFuseRunnableReplayStarved =
                                        parentFuseHighActiveReplayStarved || parentFuseLowActiveReplayStarved || parentFuseMidActiveNoQueueReplayStarved || parentFuseMidActiveQueuedReplayStarved || parentFuseLowCapMidActiveQueuedReplayPlateau || parentFuseQueuedPlateauReplayStarved || parentFuseLowCapHighActiveQueuedReplayPlateau || parentFuseMidActiveQueuedSlowRepeatPlateau
                                    let parentFuseDecision =
                                        if parentFuseRunnableReplayStarved then
                                            EvalWorklist.ParentContinuationFuseBlocked(parentFuseRepeat, parentFuseCap)
                                        elif parentFuseCapExhausted && not parentFuseRunnableReplayStillLive then
                                            EvalWorklist.ParentContinuationFuseBlocked(parentFuseRepeat, parentFuseCap)
                                        else
                                            EvalWorklist.ParentContinuationFuseDeferred(parentFuseRepeat, parentFuseCap)
                                    if parentFuseRunnableReplayStillLive then
                                        DiagJson.emit (
                                            sprintf "{\"kind\":\"eval_worklist_global_fuse_terminal_deferred_after_cap_due_live_replay\",\"event\":\"term_entry_global_fuse\",\"shape\":%s,\"site\":%s,\"first_key\":%s,\"first_site\":%s,\"first_depth\":%d,\"pending\":%d,\"queue_depth\":%d,\"active_depth\":%d,\"payload_status\":%s,\"repeat\":%d,\"cap\":%d,%s,\"starved\":%b,\"policy\":\"do_not_pin_rank80_global_fuse_while_replay_runnable_until_lowcap_midqueued_or_high8_low_midqueued_or_queued_plateau_starvation_bound\",\"single_flight\":1,\"next\":\"continue_term_replay_driver_or_emit_starvation_terminal\"}"
                                                (DiagJson.esc (evalNodeShapeTerm x)) (DiagJson.esc site) (DiagJson.esc k0) (DiagJson.esc s0) d0 (EvalWorklist.pendingCount()) (EvalWorklist.replayQueueDepth()) (EvalWorklist.replayDriverActiveDepthValue()) (DiagJson.esc (EvalWorklist.semanticPayloadStatus())) parentFuseRepeat parentFuseCap (EvalWorklist.globalFuseTraceJson()) parentFuseRunnableReplayStarved)
                                    if parentFuseLowCapHighActiveQueuedReplayPlateau then
                                        DiagJson.emit (
                                            sprintf "{\"kind\":\"eval_worklist_term_lowcap_high_active_queued_global_fuse_plateau_bounded\",\"event\":\"term_entry_global_fuse\",\"shape\":%s,\"site\":%s,\"first_key\":%s,\"first_site\":%s,\"first_depth\":%d,\"pending\":%d,\"queue_depth\":%d,\"active_depth\":%d,\"repeat\":%d,\"cap\":%d,%s,\"policy\":\"lowcap_high_active_queued_plateau_beats_manual_ctrl_c\",\"single_flight\":1,\"next\":\"explicit_eval_worklist_term_live_global_fuse_starvation_required\"}"
                                                (DiagJson.esc (evalNodeShapeTerm x)) (DiagJson.esc site) (DiagJson.esc k0) (DiagJson.esc s0) d0 (EvalWorklist.pendingCount()) (EvalWorklist.replayQueueDepth()) (EvalWorklist.replayDriverActiveDepthValue()) parentFuseRepeat parentFuseCap (EvalWorklist.globalFuseTraceJson()))
                                    if parentFuseMidActiveQueuedSlowRepeatPlateau then
                                        DiagJson.emit (
                                            sprintf "{\"kind\":\"eval_worklist_term_mid_active_queued_slow_global_fuse_plateau_bounded\",\"event\":\"term_entry_global_fuse\",\"shape\":%s,\"site\":%s,\"first_key\":%s,\"first_site\":%s,\"first_depth\":%d,\"pending\":%d,\"queue_depth\":%d,\"active_depth\":%d,\"repeat\":%d,\"cap\":%d,%s,\"policy\":\"mid_active_queued_slow_plateau_beats_manual_ctrl_c\",\"single_flight\":1,\"next\":\"explicit_eval_worklist_term_live_global_fuse_starvation_required\"}"
                                                (DiagJson.esc (evalNodeShapeTerm x)) (DiagJson.esc site) (DiagJson.esc k0) (DiagJson.esc s0) d0 (EvalWorklist.pendingCount()) (EvalWorklist.replayQueueDepth()) (EvalWorklist.replayDriverActiveDepthValue()) parentFuseRepeat parentFuseCap (EvalWorklist.globalFuseTraceJson()))
                                    if parentFuseRunnableReplayStarved then
                                        DiagJson.emit (
                                            sprintf "{\"kind\":\"eval_worklist_term_live_global_fuse_starvation_bounded\",\"event\":\"term_entry_global_fuse\",\"shape\":%s,\"site\":%s,\"first_key\":%s,\"first_site\":%s,\"first_depth\":%d,\"pending\":%d,\"queue_depth\":%d,\"active_depth\":%d,\"repeat\":%d,\"cap\":%d,%s,\"policy\":\"bounded_starvation_terminal_beats_manual_ctrl_c\",\"single_flight\":1,\"next\":\"explicit_eval_worklist_term_live_global_fuse_starvation_required\"}"
                                                (DiagJson.esc (evalNodeShapeTerm x)) (DiagJson.esc site) (DiagJson.esc k0) (DiagJson.esc s0) d0 (EvalWorklist.pendingCount()) (EvalWorklist.replayQueueDepth()) (EvalWorklist.replayDriverActiveDepthValue()) parentFuseRepeat parentFuseCap (EvalWorklist.globalFuseTraceJson()))
                                    let parentFuseStatus = EvalWorklist.globalFuseReplayDecisionStatusText parentFuseDecision
                                    let parentFuseRepeat = EvalWorklist.globalFuseReplayDecisionRepeat parentFuseDecision
                                    let parentFuseCap = EvalWorklist.globalFuseReplayDecisionCap parentFuseDecision
                                    match parentFuseDecision with
                                    | EvalWorklist.ParentContinuationFuseBlocked _
                                    | EvalWorklist.OrphanGlobalFuseBlocked _ ->
                                        DiagJson.emit (
                                            sprintf "{\"kind\":\"eval_worklist_global_fuse_parent_continuation_cycle_blocked\",\"event\":\"term_entry_global_fuse\",\"status\":%s,\"shape\":%s,\"site\":%s,\"first_key\":%s,\"first_site\":%s,\"first_depth\":%d,\"pending\":%d,\"queue_depth\":%d,\"active_depth\":%d,\"payload_status\":%s,\"repeat\":%d,\"cap\":%d,%s,\"single_flight\":1,\"next\":\"typed_terminal_after_bounded_parent_continuation_global_fuse\"}"
                                                (DiagJson.esc parentFuseStatus) (DiagJson.esc (evalNodeShapeTerm x)) (DiagJson.esc site) (DiagJson.esc k0) (DiagJson.esc s0) d0 (EvalWorklist.pendingCount()) (EvalWorklist.replayQueueDepth()) (EvalWorklist.replayDriverActiveDepthValue()) (DiagJson.esc (EvalWorklist.semanticPayloadStatus())) parentFuseRepeat parentFuseCap (EvalWorklist.globalFuseTraceJson()))
                                        EvalWorklist.pinSemanticTerminalContract "term_entry_global_fuse" "term" parentFuseStatus k0 site d0 parentFuseRepeat parentFuseCap "bounded_term_parent_continuation_global_fuse"
                                        let msg = sprintf "%s: global term-cycle fuse already tripped first_key=%s first_site=%s first_depth=%d gen=%d re=%d/%d; parent-continuation replay cap exhausted before StackOverflow" EJPCodes.EJP0011 k0 s0 d0 g0 re0 max0
                                        let msg = EvalWorklist.retargetGlobalFuseAbortMessage "term_entry_global_fuse" "term" msg
                                        raise_type_error s msg
                                    | EvalWorklist.ParentContinuationFuseDeferred _
                                    | EvalWorklist.OrphanGlobalFuseDeferred _ ->
                                        DiagJson.emit (
                                            sprintf "{\"kind\":\"eval_worklist_global_fuse_parent_continuation_cycle_deferred\",\"event\":\"term_entry_global_fuse\",\"status\":%s,\"shape\":%s,\"site\":%s,\"first_key\":%s,\"first_site\":%s,\"first_depth\":%d,\"pending\":%d,\"queue_depth\":%d,\"active_depth\":%d,\"payload_status\":%s,\"repeat\":%d,\"cap\":%d,%s,\"policy\":\"keyed_global_fuse_cannot_outvote_runnable_parent_continuation_replay\",\"single_flight\":1,\"next\":\"fallthrough_term_eval\"}"
                                                (DiagJson.esc parentFuseStatus) (DiagJson.esc (evalNodeShapeTerm x)) (DiagJson.esc site) (DiagJson.esc k0) (DiagJson.esc s0) d0 (EvalWorklist.pendingCount()) (EvalWorklist.replayQueueDepth()) (EvalWorklist.replayDriverActiveDepthValue()) (DiagJson.esc (EvalWorklist.semanticPayloadStatus())) parentFuseRepeat parentFuseCap (EvalWorklist.globalFuseTraceJson()))
                                        EvalWorklist.parkActiveAndSelectKind "term" |> ignore
                                        TermCycleFuse.reset()
                                else
                                    let msg = sprintf "%s: global term-cycle fuse already tripped first_key=%s first_site=%s first_depth=%d gen=%d re=%d/%d; aborting term worker before StackOverflow" EJPCodes.EJP0011 k0 s0 d0 g0 re0 max0
                                    let msg = EvalWorklist.retargetGlobalFuseAbortMessage "term_entry_global_fuse" "term" msg
                                    raise_type_error s msg
    

            let depth = RecursionTracker.enter site
            use _rec_guard = { new System.IDisposable with member _.Dispose() = RecursionTracker.exit() }
    

            // Cycle guards: detect infinite re-entrancy into the same expression
            let nodeObj = box x
            let nodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode nodeObj
            let rec registerReplayTerm (nodeId: int) (expr: E) =
                match expr with
                | EB _ -> EvalReplayValueStore.putTermValue nodeId DB
                | EV a -> EvalReplayValueStore.putTerm nodeId (fun () -> v s a)
                | ELit(_,lit) -> EvalReplayValueStore.putTermValue nodeId (DLit lit)
                | ESymbol(_,sym) -> EvalReplayValueStore.putTermValue nodeId (DSymbol sym)
                | EFun'(_,freeVars,i,body,annot) ->
                    EvalReplayValueStore.putTerm nodeId (fun () ->
                        if freeVars.term.free_vars.Length <> i then failwith "Replay function free-var arity mismatch."
                        DFunction(body, annot, HopacExtensions.A.map (v s) freeVars.term.free_vars, HopacExtensions.A.map (vt s) freeVars.ty.free_vars, freeVars.term.stack_size, freeVars.ty.stack_size))
                | ERecursiveFun'(_,freeVars,i,body,annot) ->
                    EvalReplayValueStore.putTerm nodeId (fun () ->
                        if freeVars.term.free_vars.Length <> i then failwith "Replay recursive function free-var arity mismatch."
                        DFunction(body.Value, annot, HopacExtensions.A.map (v s) freeVars.term.free_vars, HopacExtensions.A.map (vt s) freeVars.ty.free_vars, freeVars.term.stack_size, freeVars.ty.stack_size))
                | EForall'(_,freeVars,i,body) ->
                    EvalReplayValueStore.putTerm nodeId (fun () ->
                        if freeVars.ty.free_vars.Length <> i then failwith "Replay forall free-var arity mismatch."
                        DForall(body, HopacExtensions.A.map (v s) freeVars.term.free_vars, HopacExtensions.A.map (vt s) freeVars.ty.free_vars, freeVars.term.stack_size, freeVars.ty.stack_size))
                | ERecursiveForall'(_,freeVars,i,body) ->
                    EvalReplayValueStore.putTerm nodeId (fun () ->
                        if freeVars.ty.free_vars.Length <> i then failwith "Replay recursive forall free-var arity mismatch."
                        DForall(body.Value, HopacExtensions.A.map (v s) freeVars.term.free_vars, HopacExtensions.A.map (vt s) freeVars.ty.free_vars, freeVars.term.stack_size, freeVars.ty.stack_size))
                | EJoinPoint'(_,_,_,_,_,_) ->
                    // ALPHA559: mirror the global-fuse registration path for
                    // normal retry/replay.  The EJoinPoint' branch below remains
                    // fail-closed if the real evaluator still cannot materialize it.
                    EvalReplayValueStore.putTerm nodeId (fun () -> term s expr)
                | EUnbox(r,k,id,a,on_succ,on_fail) ->
                    // ALPHA646: mirror the global-fuse EUnbox replay thunk in the
                    // normal post-fuse registration path.  This lets scheduled unbox
                    // bodies run through the real evaluator before any generic E* fallback.
                    // ALPHA1022: mirror the explicit UnboxSpine too; the 1021 frontier
                    // proved this shape needs child-first replay, not another terminal pin.
                    let bindNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box a)
                    let successNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box on_succ)
                    let failNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box on_fail)
                    registerReplayTerm bindNodeId a
                    EvalReplayValueStore.putTerm failNodeId (fun () -> term (add_trace s r) on_fail)
                    EvalReplayValueStore.putTerm successNodeId (fun () ->
                        let s = add_trace s r
                        match term s a with
                        | DNominal(DUnion(DPair(DSymbol k', payload),_),_) when k = k' ->
                            store_term s id payload
                            term s on_succ
                        | _ -> term s expr)
                    EvalReplayValueStore.putUnboxSpine nodeId {
                        bindNodeId = bindNodeId
                        bindShape = evalNodeShapeTerm a
                        caseName = k
                        binderId = id
                        successNodeId = successNodeId
                        successShape = evalNodeShapeTerm on_succ
                        failNodeId = failNodeId
                        failShape = evalNodeShapeTerm on_fail
                    }
                    EvalReplayValueStore.putTerm nodeId (fun () -> term s expr)
                | EAnnot(_,inner,annotTy) ->
                    // ALPHA653/942: mirror the global-fuse annotation thunk and AnnotSpine
                    // in the normal post-fuse registration path.  Without the spine,
                    // repeated annot wrappers can only be replayed as opaque terms after
                    // the global-fuse path is no longer active.
                    let innerNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box inner)
                    let typeNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box annotTy)
                    registerReplayTerm innerNodeId inner
                    EvalReplayValueStore.putType typeNodeId (fun () -> ty s annotTy)
                    EvalReplayValueStore.putAnnotSpine nodeId {
                        innerNodeId = innerNodeId
                        innerShape = evalNodeShapeTerm inner
                        typeNodeId = typeNodeId
                        typeShape = evalNodeShapeTy annotTy
                    }
                    EvalReplayValueStore.putTerm nodeId (fun () -> term s expr)
                | ENominal(_,inner,nomTy) ->
                    let innerNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box inner)
                    let typeNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box nomTy)
                    registerReplayTerm innerNodeId inner
                    EvalReplayValueStore.putType typeNodeId (fun () -> ty s nomTy)
                    EvalReplayValueStore.putNominalSpine nodeId {
                        innerNodeId = innerNodeId
                        innerShape = evalNodeShapeTerm inner
                        typeNodeId = typeNodeId
                        typeShape = evalNodeShapeTy nomTy
                    }
                    EvalReplayValueStore.putTerm nodeId (fun () -> term s expr)
                | EDefaultLit(_,_,_) -> ()
                | ESeq(_,first,second) ->
                    let firstNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box first)
                    let secondNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box second)
                    registerReplayTerm firstNodeId first
                    registerReplayTerm secondNodeId second
                    match first with
                    | EB _ -> EvalReplayValueStore.putTermValue firstNodeId DB
                    | EV a -> EvalReplayValueStore.putTerm firstNodeId (fun () -> v s a)
                    | ELit(_,lit) -> EvalReplayValueStore.putTermValue firstNodeId (DLit lit)
                    | ESymbol(_,sym) -> EvalReplayValueStore.putTermValue firstNodeId (DSymbol sym)
                    | _ -> ()
                    match second with
                    | EB _ -> EvalReplayValueStore.putTermValue secondNodeId DB
                    | EV a -> EvalReplayValueStore.putTerm secondNodeId (fun () -> v s a)
                    | ELit(_,lit) -> EvalReplayValueStore.putTermValue secondNodeId (DLit lit)
                    | ESymbol(_,sym) -> EvalReplayValueStore.putTermValue secondNodeId (DSymbol sym)
                    | _ -> ()
                    EvalReplayValueStore.putSeqSpine nodeId {
                        firstNodeId = firstNodeId
                        firstShape = evalNodeShapeTerm first
                        secondNodeId = secondNodeId
                        secondShape = evalNodeShapeTerm second
                    }
                    EvalReplayValueStore.putTerm nodeId (fun () ->
                        let isUnknownReturnWitness value =
                            match value with
                            | DSymbol sym when sym.Contains("JPMethodUnknownRet(") -> true
                            | DV(L(_,YSymbol sym)) when sym.Contains("JPMethodUnknownRet(") -> true
                            | _ -> false
                        let unitLike value =
                            match value with
                            | DB -> true
                            | DSymbol sym when sym.Contains("JPMethodRecPlaceholder(") || sym.Contains("JPTypeRecPlaceholder(") -> true
                            | DV(L(_,YSymbol sym)) when sym.Contains("JPMethodRecPlaceholder(") || sym.Contains("JPTypeRecPlaceholder(") -> true
                            | _ -> false
                        let discardableApplyLiteral value =
                            match value with
                            | DLit _ when evalNodeShapeTerm first = "EApply" -> true
                            | DSymbol _ when evalNodeShapeTerm first = "EApply" -> true
                            | _ -> false
                        match EvalReplayValueStore.tryTerm firstNodeId with
                        | Some firstValue when isUnknownReturnWitness firstValue && evalNodeShapeTerm first = "EApply" ->
                            match EvalReplayValueStore.tryTerm secondNodeId with
                            | Some secondValue -> secondValue
                            | None -> failwith ("replay_seq_second_value_missing_after_apply_unknown_return:" + evalNodeShapeTerm second)
                        | Some firstValue when isUnknownReturnWitness firstValue ->
                            failwith (sprintf "replay_seq_unknown_return_witness:%s" (show_data firstValue))
                        | Some firstValue when unitLike firstValue ->
                            match EvalReplayValueStore.tryTerm secondNodeId with
                            | Some secondValue -> secondValue
                            | None -> failwith ("replay_seq_second_value_missing:" + evalNodeShapeTerm second)
                        | Some firstValue when discardableApplyLiteral firstValue ->
                            match EvalReplayValueStore.tryTerm secondNodeId with
                            | Some secondValue -> secondValue
                            | None -> failwith ("replay_seq_second_value_missing_after_apply_literal:" + evalNodeShapeTerm second)
                        | Some other -> failwith (sprintf "replay_seq_expected_unit:%s" (show_data other))
                        | None -> failwith ("replay_seq_first_value_missing:" + evalNodeShapeTerm first))
                | EPair(_,left,right) ->
                    // ALPHA566: constructive pair replay.  Register both children and
                    // only materialize DPair when both child values are available.
                    let leftNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box left)
                    let rightNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box right)
                    registerReplayTerm leftNodeId left
                    registerReplayTerm rightNodeId right
                    EvalReplayValueStore.putTermPairSpine nodeId {
                        leftNodeId = leftNodeId
                        leftShape = evalNodeShapeTerm left
                        rightNodeId = rightNodeId
                        rightShape = evalNodeShapeTerm right
                    }
                    EvalReplayValueStore.putTerm nodeId (fun () ->
                        match EvalReplayValueStore.tryTerm leftNodeId, EvalReplayValueStore.tryTerm rightNodeId with
                        | Some leftValue, Some rightValue -> DPair(leftValue, rightValue)
                        | None, _ -> failwith ("pair_left_value_missing:" + evalNodeShapeTerm left)
                        | _, None -> failwith ("pair_right_value_missing:" + evalNodeShapeTerm right))
                | EPairTest(r,bind,p1,p2,on_succ,on_fail) ->
                    // ALPHA650: pair-test bodies need replay branch spines just
                    // like EUnitTest/EAnnotTest.  The success branch is evaluated
                    // under the concrete pair destructuring environment; the fail
                    // branch keeps the original environment.
                    let succNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box on_succ)
                    let failNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box on_fail)
                    try
                        let s2 = add_trace s r
                        EvalReplayValueStore.putPairTestBindValue nodeId (v s2 bind)
                    with _ -> ()
                    EvalReplayValueStore.putTerm succNodeId (fun () ->
                        let s2 = add_trace s r
                        match v s2 bind with
                        | DPair(a,b) ->
                            store_term s2 p1 a
                            store_term s2 p2 b
                            term s2 on_succ
                        | other -> failwith (sprintf "pair_test_success_branch_not_selected:%s" (show_data other)))
                    EvalReplayValueStore.putTerm failNodeId (fun () ->
                        let s2 = add_trace s r
                        match v s2 bind with
                        | DPair _ -> failwith "pair_test_fail_branch_not_selected:DPair"
                        | _ -> term s2 on_fail)
                    EvalReplayValueStore.putPairTestSpine nodeId {
                        successNodeId = succNodeId
                        successShape = evalNodeShapeTerm on_succ
                        failNodeId = failNodeId
                        failShape = evalNodeShapeTerm on_fail
                    }
                    EvalReplayValueStore.putTerm nodeId (fun () ->
                        let s2 = add_trace s r
                        match v s2 bind with
                        | DPair(a,b) ->
                            store_term s2 p1 a
                            store_term s2 p2 b
                            match EvalReplayValueStore.tryTerm succNodeId with
                            | Some value -> value
                            | None -> failwith ("pair_test_success_branch_value_missing:" + evalNodeShapeTerm on_succ)
                        | _ ->
                            match EvalReplayValueStore.tryTerm failNodeId with
                            | Some value -> value
                            | None -> failwith ("pair_test_fail_branch_value_missing:" + evalNodeShapeTerm on_fail))
                | EUnitTest(r,bind,on_succ,on_fail) ->
                    // ALPHA560: mirror the global-fuse registration path for normal retry/replay.
                    // ALPHA935: also mirror bind registration; otherwise a unit-test
                    // discriminator failure is opaque and pins semantic_unit_test_value_blocked.
                    let bindNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box bind)
                    let succNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box on_succ)
                    let failNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box on_fail)
                    // ALPHA936: bind is an Id, not an E. Do not pass it through
                    // registerReplayTerm/evalNodeShapeTerm. The replay child is a
                    // value thunk backed by the existing variable evaluator.
                    registerReplayTerm succNodeId on_succ
                    registerReplayTerm failNodeId on_fail
                    EvalReplayValueStore.putTerm bindNodeId (fun () -> v (add_trace s r) bind)
                    EvalReplayValueStore.putUnitTestSpine nodeId {
                        bindNodeId = bindNodeId
                        bindShape = "EV"
                        successNodeId = succNodeId
                        successShape = evalNodeShapeTerm on_succ
                        failNodeId = failNodeId
                        failShape = evalNodeShapeTerm on_fail
                    }
                    EvalReplayValueStore.putTerm nodeId (fun () ->
                        let s2 = add_trace s r
                        let branch, branchNodeId =
                            match v s2 bind with
                            | DB -> on_succ, succNodeId
                            | _ -> on_fail, failNodeId
                        match EvalReplayValueStore.tryTerm branchNodeId with
                        | Some value -> value
                        | None -> failwith ("unit_test_branch_value_missing:" + evalNodeShapeTerm branch))
                | ETypeApply(_,func,typeArg) ->
                    let funcNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box func)
                    let typeNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box typeArg)
                    match func with
                    | EV a -> EvalReplayValueStore.putTerm funcNodeId (fun () -> v s a)
                    | EForall'(_,freeVars,i,body) ->
                        EvalReplayValueStore.putTerm funcNodeId (fun () ->
                            if freeVars.ty.free_vars.Length <> i then failwith "Replay type-apply forall free-var arity mismatch."
                            DForall(body, HopacExtensions.A.map (v s) freeVars.term.free_vars, HopacExtensions.A.map (vt s) freeVars.ty.free_vars, freeVars.term.stack_size, freeVars.ty.stack_size))
                    | ERecursiveForall'(_,freeVars,i,body) ->
                        EvalReplayValueStore.putTerm funcNodeId (fun () ->
                            if freeVars.ty.free_vars.Length <> i then failwith "Replay type-apply recursive forall free-var arity mismatch."
                            DForall(body.Value, HopacExtensions.A.map (v s) freeVars.term.free_vars, HopacExtensions.A.map (vt s) freeVars.ty.free_vars, freeVars.term.stack_size, freeVars.ty.stack_size))
                    | _ -> ()
                    let snapshotTypeVariableChildFromEnv (parentNodeId: int) (childNodeId: int) (role: string) (child: TPrepass) =
                        match child with
                        | TV i ->
                            let globalTypeLen =
                                if obj.ReferenceEquals(s.env_global_type, null) then 0
                                else s.env_global_type.Length
                            let stackTypeLen =
                                if obj.ReferenceEquals(s.env_stack_type, null) then 0
                                else s.env_stack_type.Length
                            match EvalReplayValueStore.putTypeVarEnvSnapshot childNodeId i s.env_global_type s.env_stack_type with
                            | Some (envName, _, _) ->
                                DiagJson.emit (
                                    sprintf "{\"kind\":\"eval_worklist_type_fun_tv_child_env_snapshot\",\"event\":\"type_fun_child_register\",\"parent_node_id\":%d,\"child_node_id\":%d,\"role\":%s,\"index\":%d,\"env\":%s,\"global_len\":%d,\"stack_len\":%d,\"site\":%s,\"single_flight\":1,\"next\":\"type_value_materialized\"}"
                                        parentNodeId childNodeId (DiagJson.esc role) i (DiagJson.esc envName) globalTypeLen stackTypeLen (DiagJson.esc site))
                            | None ->
                                DiagJson.emit (
                                    sprintf "{\"kind\":\"eval_worklist_type_fun_tv_child_env_snapshot_miss\",\"event\":\"type_fun_child_register\",\"parent_node_id\":%d,\"child_node_id\":%d,\"role\":%s,\"index\":%d,\"global_len\":%d,\"stack_len\":%d,\"site\":%s,\"single_flight\":1,\"next\":\"explicit_eval_worklist_type_variable_env_required\"}"
                                        parentNodeId childNodeId (DiagJson.esc role) i globalTypeLen stackTypeLen (DiagJson.esc site))
                        | _ -> ()
                    // Mirror the global-fuse ETypeApply argument
                    // repair in the normal post-fuse register path as well.
                    let rec registerTypeApplyArgReplay (replayNodeId: int) (texpr: TPrepass) =
                        let childType label child =
                            let childNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box child)
                            registerTypeApplyArgReplay childNodeId child
                            match EvalReplayValueStore.tryType childNodeId with
                            | Some value -> value
                            | None -> failwith ("type_apply_arg_child_missing:" + label + ":" + evalNodeShapeTy child)
                        match texpr with
                        | TV i ->
                            match EvalReplayValueStore.putTypeVarEnvSnapshot replayNodeId i s.env_global_type s.env_stack_type with
                            | Some _ -> ()
                            | None -> EvalReplayValueStore.putType replayNodeId (fun () -> vt s i)
                        | TPrim a -> EvalReplayValueStore.putType replayNodeId (fun () -> YPrim a)
                        | TSymbol(_,a) -> EvalReplayValueStore.putType replayNodeId (fun () -> YSymbol a)
                        | TNominal i -> EvalReplayValueStore.putType replayNodeId (fun () -> YNominal env.nominals.[i])
                        | TLit(_,lit) -> EvalReplayValueStore.putType replayNodeId (fun () -> YLit lit)
                        | TB _ -> EvalReplayValueStore.putType replayNodeId (fun () -> YB)
                        | TExists -> EvalReplayValueStore.putType replayNodeId (fun () -> YExists)
                        | TForall' _ -> EvalReplayValueStore.putType replayNodeId (fun () -> YForall)
                        | TMetaV i -> EvalReplayValueStore.putType replayNodeId (fun () -> YMetavar i)
                        | TArrow'(scope,i,body) ->
                            EvalReplayValueStore.putType replayNodeId (fun () ->
                                assert (i = scope.ty.free_vars.Length)
                                YTypeFunction(body, HopacExtensions.A.map (vt s) scope.ty.free_vars, scope.term.stack_size, scope.ty.stack_size))
                        | TPair(_,a,b) ->
                            let leftNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box a)
                            let rightNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box b)
                            registerTypeApplyArgReplay leftNodeId a
                            registerTypeApplyArgReplay rightNodeId b
                            EvalReplayValueStore.putTypePairSpine replayNodeId {
                                leftNodeId = leftNodeId
                                leftShape = evalNodeShapeTy a
                                rightNodeId = rightNodeId
                                rightShape = evalNodeShapeTy b
                            }
                            EvalReplayValueStore.putType replayNodeId (fun () -> YPair(childType "TApplyArg.TPair.left" a, childType "TApplyArg.TPair.right" b))
                        | TFun(a,b,t) ->
                            let argNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box a)
                            let bodyNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box b)
                            snapshotTypeVariableChildFromEnv replayNodeId argNodeId "type_apply_arg_tfun_arg" a
                            snapshotTypeVariableChildFromEnv replayNodeId bodyNodeId "type_apply_arg_tfun_body" b
                            registerTypeApplyArgReplay argNodeId a
                            registerTypeApplyArgReplay bodyNodeId b
                            match a with
                            | TV i ->
                                let globalTypeLen =
                                    if obj.ReferenceEquals(s.env_global_type, null) then 0
                                    else s.env_global_type.Length
                                let stackTypeLen =
                                    if obj.ReferenceEquals(s.env_stack_type, null) then 0
                                    else s.env_stack_type.Length
                                if i >= globalTypeLen && stackTypeLen = 0 then
                                    // ALPHA644: mirror the TFun.arg free-metavar witness
                                    // for the normal post-fuse ETypeApply argument replay path.
                                    EvalReplayValueStore.putTypeValue argNodeId (YMetavar i)
                                    DiagJson.emit (
                                        sprintf "{\"kind\":\"eval_worklist_tfun_arg_tv_free_metavar_snapshot\",\"event\":\"type_apply_arg_register\",\"parent_node_id\":%d,\"child_node_id\":%d,\"role\":\"type_apply_arg_tfun_arg_free_metavar\",\"index\":%d,\"global_len\":%d,\"stack_len\":%d,\"site\":%s,\"single_flight\":1,\"next\":\"type_value_materialized_from_free_metavar\"}"
                                            replayNodeId argNodeId i globalTypeLen stackTypeLen (DiagJson.esc site))
                            | _ -> ()
                            match b with
                            | TV i ->
                                let globalTypeLen =
                                    if obj.ReferenceEquals(s.env_global_type, null) then 0
                                    else s.env_global_type.Length
                                let stackTypeLen =
                                    if obj.ReferenceEquals(s.env_stack_type, null) then 0
                                    else s.env_stack_type.Length
                                if i = globalTypeLen && stackTypeLen = 0 then
                                    EvalReplayValueStore.putType bodyNodeId (fun () -> childType "TApplyArg.TFun.body_immediate_binder" a)
                                    DiagJson.emit (
                                        sprintf "{\"kind\":\"eval_worklist_tfun_body_tv_binder_snapshot\",\"event\":\"type_apply_arg_register\",\"parent_node_id\":%d,\"child_node_id\":%d,\"role\":\"type_apply_arg_tfun_body_immediate_binder\",\"index\":%d,\"global_len\":%d,\"stack_len\":%d,\"arg_node_id\":%d,\"site\":%s,\"single_flight\":1,\"next\":\"type_value_materialized_from_arg_binder\"}"
                                            replayNodeId bodyNodeId i globalTypeLen stackTypeLen argNodeId (DiagJson.esc site))
                            | _ -> ()
                            EvalReplayValueStore.putTypeFunSpine replayNodeId {
                                argNodeId = argNodeId
                                argShape = evalNodeShapeTy a
                                bodyNodeId = bodyNodeId
                                bodyShape = evalNodeShapeTy b
                                funType = t
                            }
                            EvalReplayValueStore.putType replayNodeId (fun () -> YFun(childType "TApplyArg.TFun.arg" a, childType "TApplyArg.TFun.body" b,t))
                        | _ -> ()
                    match typeArg with
                    | TV i ->
                        // ALPHA595: the normal post-fuse ETypeApply argument path still used
                        // a late vt thunk while the global-fuse path had already learned to
                        // snapshot in-bounds type variables.  Runtime 594 selected the concrete
                        // durable terminal semantic_type_variable_value_missing_blocked at
                        // runtime fixture path:27 from this missing snapshot.  Mirror the same
                        // fail-closed policy here: materialize only in-bounds env entries; keep
                        // out-of-bounds TVs as explicit vt thunks and terminal obligations.
                        let globalTypeLen =
                            if obj.ReferenceEquals(s.env_global_type, null) then 0
                            else s.env_global_type.Length
                        let stackTypeLen =
                            if obj.ReferenceEquals(s.env_stack_type, null) then 0
                            else s.env_stack_type.Length
                        if i >= 0 && i < globalTypeLen then
                            EvalReplayValueStore.putTypeValue typeNodeId s.env_global_type.[i]
                            DiagJson.emit (
                                sprintf "{\"kind\":\"eval_worklist_type_apply_arg_tv_env_snapshot\",\"event\":\"type_apply_register\",\"scope\":\"post_fuse\",\"node_id\":%d,\"index\":%d,\"env\":\"global\",\"global_len\":%d,\"stack_len\":%d,\"single_flight\":1,\"next\":\"type_value_materialized\"}"
                                    typeNodeId i globalTypeLen stackTypeLen)
                        elif i >= globalTypeLen && (i - globalTypeLen) >= 0 && (i - globalTypeLen) < stackTypeLen then
                            EvalReplayValueStore.putTypeValue typeNodeId s.env_stack_type.[i - globalTypeLen]
                            DiagJson.emit (
                                sprintf "{\"kind\":\"eval_worklist_type_apply_arg_tv_env_snapshot\",\"event\":\"type_apply_register\",\"scope\":\"post_fuse\",\"node_id\":%d,\"index\":%d,\"env\":\"stack\",\"global_len\":%d,\"stack_len\":%d,\"single_flight\":1,\"next\":\"type_value_materialized\"}"
                                    typeNodeId i globalTypeLen stackTypeLen)
                        else
                            EvalReplayValueStore.putType typeNodeId (fun () -> vt s i)
                            DiagJson.emit (
                                sprintf "{\"kind\":\"eval_worklist_type_apply_arg_tv_env_snapshot_miss\",\"event\":\"type_apply_register\",\"scope\":\"post_fuse\",\"node_id\":%d,\"index\":%d,\"global_len\":%d,\"stack_len\":%d,\"single_flight\":1,\"next\":\"explicit_eval_worklist_type_variable_env_required\"}"
                                    typeNodeId i globalTypeLen stackTypeLen)
                    | TArrow'(scope,i,body) ->
                        EvalReplayValueStore.putType typeNodeId (fun () ->
                            assert (i = scope.ty.free_vars.Length)
                            YTypeFunction(body, HopacExtensions.A.map (vt s) scope.ty.free_vars, scope.term.stack_size, scope.ty.stack_size))
                    | TLit(_,lit) -> EvalReplayValueStore.putType typeNodeId (fun () -> YLit lit)
                    | TB _ -> EvalReplayValueStore.putType typeNodeId (fun () -> YB)
                    | TExists -> EvalReplayValueStore.putType typeNodeId (fun () -> YExists)
                    | TForall' _ -> EvalReplayValueStore.putType typeNodeId (fun () -> YForall)
                    | TMetaV i -> EvalReplayValueStore.putType typeNodeId (fun () -> YMetavar i)
                    // ALPHA394: mirror constructive type replay for type-apply args.
                    | TPrim a -> EvalReplayValueStore.putType typeNodeId (fun () -> YPrim a)
                    | TSymbol(_,a) -> EvalReplayValueStore.putType typeNodeId (fun () -> YSymbol a)
                    | TNominal i -> EvalReplayValueStore.putType typeNodeId (fun () -> YNominal env.nominals.[i])
                    | TPair _ -> registerTypeApplyArgReplay typeNodeId typeArg
                    | TFun _ -> registerTypeApplyArgReplay typeNodeId typeArg
                    | TModule a ->
                        EvalReplayValueStore.putType typeNodeId (fun () ->
                            YRecord(
                                a
                                |> Seq.mapi (fun i (KeyValue (k, v)) -> (i, k), (v |> ty s))
                                |> Map.ofSeq))
                    | TRecord(_,a) -> EvalReplayValueStore.putType typeNodeId (fun () -> YRecord(Map.map (fun _ -> ty s) a))
                    | TArray a -> EvalReplayValueStore.putType typeNodeId (fun () -> YArray(ty s a))
                    | TLayout(a,b) -> EvalReplayValueStore.putType typeNodeId (fun () -> YLayout(ty s a,b))
                    // ALPHA412: allow type-apply argument replay to cover the same
                    // complex type frontier exposed by file_system.spi:993.
                    | TJoinPoint'(r,scope,body) ->
                        // ALPHA649: mirror direct TJoinPoint' body replay in the
                        // ETypeApply type-argument registration path.
                        EvalReplayValueStore.putType typeNodeId (fun () ->
                            let env_global_type = scope.ty.free_vars |> HopacExtensions.A.map (fun i -> vt s i)
                            let env_global_term = scope.term.free_vars |> HopacExtensions.A.map (fun i -> v s i)
                            let s2 : LangEnv =
                                { s with
                                    trace = r :: s.trace
                                    seq = ResizeArray()
                                    cse = [Dictionary(HashIdentity.Structural)]
                                    unions = Map.empty
                                    i = ref 0
                                    env_global_type = env_global_type
                                    env_global_term = env_global_term
                                    env_stack_type = Array.zeroCreate<_> scope.ty.stack_size
                                    env_stack_term = Array.zeroCreate<_> scope.term.stack_size }
                            ty (rename_global_term s2) body)
                    | TTerm _ | TTypecase _ | TUnion _ | TMacro _ ->
                        EvalReplayValueStore.putType typeNodeId (fun () -> ty s typeArg)
                    | _ -> ()
                    EvalReplayValueStore.putTypeApplySpine nodeId {
                        funcNodeId = funcNodeId
                        funcShape = evalNodeShapeTerm func
                        typeNodeId = typeNodeId
                        typeShape = evalNodeShapeTy typeArg
                    }
                    EvalReplayValueStore.putTypeApplyContext nodeId (box s)
                    // ALPHA370: value-gated DForall body replay for ETypeApply.
                    // This mirrors type_apply but remains a thunk inside the replay value
                    // store.  If evaluating the forall body still hits a cycle, tryTerm
                    // catches the exception and the worklist remains semantic_step_partial.
                    EvalReplayValueStore.putTerm nodeId (fun () ->
                        let funcValue =
                            match EvalReplayValueStore.tryTerm funcNodeId with
                            | Some value -> value
                            | None -> failwith ("type_apply_func_value_missing:" + evalNodeShapeTerm func)
                        let typeValue =
                            match EvalReplayValueStore.tryType typeNodeId with
                            | Some value -> value
                            | None -> failwith ("type_apply_arg_value_missing:" + evalNodeShapeTy typeArg)
                        match funcValue with
                        | DForall(body,gl_term,gl_ty,sz_term,sz_ty) ->
                            let s' = { s with env_global_type = gl_ty; env_global_term = gl_term; env_stack_type = Array.zeroCreate<_> sz_ty; env_stack_term = Array.zeroCreate<_> sz_term }
                            s'.env_stack_type.[0] <- typeValue
                            term s' body
                        | DV(L(_,YForall)) -> failwith "Replay type-apply cannot apply runtime forall during partial evaluation."
                        | a -> failwith (sprintf "Replay type-apply expected forall; got %s" (show_data a)))
                | EMacro(r,a,b) ->
                    // ALPHA553/647: the normal post-fuse registerReplayTerm path must
                    // mirror the global-fuse EMacro thunk and child spine.  Runtime 646
                    // parked an EMacro at trace.spi:295 under fingerprint repeat; the
                    // child spine lets replay schedule term/type/result-type children.
                    let macroTermChildren =
                        a
                        |> List.choose (function MTerm(x,_) -> Some x | _ -> None)
                        |> List.toArray
                    let macroTypeChildren =
                        a
                        |> List.choose (function MType x | MLitType x -> Some x | _ -> None)
                        |> List.toArray
                    let macroTermNodeIds = macroTermChildren |> Array.map (fun x -> System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box x))
                    let macroTermShapes = macroTermChildren |> Array.map evalNodeShapeTerm
                    let macroTypeNodeIds = macroTypeChildren |> Array.map (fun x -> System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box x))
                    let macroTypeShapes = macroTypeChildren |> Array.map evalNodeShapeTy
                    macroTermChildren |> Array.iteri (fun i child -> registerReplayTerm macroTermNodeIds.[i] child)
                    macroTypeChildren |> Array.iteri (fun i child -> EvalReplayValueStore.putType macroTypeNodeIds.[i] (fun () -> ty s child))
                    let macroResultTypeNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box b)
                    EvalReplayValueStore.putType macroResultTypeNodeId (fun () -> ty s b)
                    EvalReplayValueStore.putMacroSpine nodeId {
                        termNodeIds = macroTermNodeIds
                        termShapes = macroTermShapes
                        typeNodeIds = macroTypeNodeIds
                        typeShapes = macroTypeShapes
                        resultTypeNodeId = macroResultTypeNodeId
                        resultTypeShape = evalNodeShapeTy b
                    }
                    EvalReplayValueStore.putTerm nodeId (fun () ->
                        let s2 = add_trace s r
                        let mutable macroTermIx = 0
                        let mutable macroTypeIx = 0
                        let cachedTerm label idx =
                            if idx >= 0 && idx < macroTermNodeIds.Length then
                                match EvalReplayValueStore.tryTerm macroTermNodeIds.[idx] with
                                | Some value -> value
                                | None -> failwith ("macro_cached_term_missing:" + label + ":" + string idx)
                            else failwith ("macro_cached_term_index_oob:" + label + ":" + string idx)
                        let cachedType label idx =
                            if idx >= 0 && idx < macroTypeNodeIds.Length then
                                match EvalReplayValueStore.tryType macroTypeNodeIds.[idx] with
                                | Some value -> value
                                | None -> failwith ("macro_cached_type_missing:" + label + ":" + string idx)
                            else failwith ("macro_cached_type_index_oob:" + label + ":" + string idx)
                        let macroItems =
                            a |> List.map (function
                                | MText x -> CMText x
                                | MTerm (_,is_inline) ->
                                    let idx = macroTermIx
                                    macroTermIx <- macroTermIx + 1
                                    CMTerm(cachedTerm "MTerm" idx |> dyn false s2, is_inline)
                                | MType _ ->
                                    let idx = macroTypeIx
                                    macroTypeIx <- macroTypeIx + 1
                                    CMType(cachedType "MType" idx)
                                | MLitType _ ->
                                    let idx = macroTypeIx
                                    macroTypeIx <- macroTypeIx + 1
                                    CMTypeLit(cachedType "MLitType" idx |> assert_ty_lit s2))
                        let resultTy =
                            match EvalReplayValueStore.tryType macroResultTypeNodeId with
                            | Some value -> value
                            | None -> failwith "macro_cached_result_type_missing"
                        DiagJson.emit (
                            sprintf "{\"kind\":\"eval_worklist_macro_cached_children_used\",\"event\":\"term_thunk\",\"node_id\":%d,\"shape\":\"EMacro\",\"term_children\":%d,\"type_children\":%d,\"single_flight\":1,\"next\":\"push_typedop_macro\"}"
                                nodeId macroTermNodeIds.Length macroTypeNodeIds.Length)
                        push_typedop_no_rewrite s2 (TyMacro(macroItems)) resultTy)
                | ERecordWith(r,vars,withs,withouts) ->
                    let recordChildTerms =
                        let xs = ResizeArray<string * E>()
                        vars |> List.iteri (fun i (_, child) -> xs.Add(sprintf "record_path_%d" i, child))
                        withs |> List.iteri (fun i item ->
                            match item with
                            | RSymbol((_, key), child) -> xs.Add(sprintf "record_with_symbol_%d:%s" i key, child)
                            | RSymbolModify((_, key), child) -> xs.Add(sprintf "record_modify_symbol_%d:%s" i key, child)
                            | RVar((_, keyExpr), child) ->
                                xs.Add(sprintf "record_with_var_key_%d" i, keyExpr)
                                xs.Add(sprintf "record_with_var_value_%d" i, child)
                            | RVarModify((_, keyExpr), child) ->
                                xs.Add(sprintf "record_modify_var_key_%d" i, keyExpr)
                                xs.Add(sprintf "record_modify_var_value_%d" i, child))
                        withouts |> List.iteri (fun i item ->
                            match item with
                            | WSymbol _ -> ()
                            | WVar(_, keyExpr) -> xs.Add(sprintf "record_without_var_%d" i, keyExpr))
                        xs.ToArray()
                    let recordChildNodeIds =
                        recordChildTerms
                        |> Array.map (fun (_, child) -> System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box child))
                    let recordChildShapes = recordChildTerms |> Array.map (fun (_, child) -> evalNodeShapeTerm child)
                    let recordChildRoles = recordChildTerms |> Array.map fst
                    recordChildTerms
                    |> Array.iteri (fun i (_, child) ->
                        registerReplayTerm recordChildNodeIds.[i] child)
                    EvalReplayValueStore.putRecordWithSpine nodeId {
                        childNodeIds = recordChildNodeIds
                        childShapes = recordChildShapes
                        childRoles = recordChildRoles
                    }
                    EvalReplayValueStore.putTerm nodeId (fun () ->
                        let base_s = add_trace s r
                        let tryPickKey (key: string) (m: Map<int * string, Data>) =
                            m |> Map.tryPick (fun (i, k) v -> if k = key then Some (i, v) else None)
                        // ALPHA570: once RecordWith children have been scheduled by the replay spine,
                        // consume their materialized values instead of re-entering the original
                        // evaluator.  Falling back to term keeps the old fail-closed behavior when
                        // a child has not been materialized yet.
                        let recordChildValue (traceRange: Range option) (child: E) =
                            let childNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box child)
                            match EvalReplayValueStore.tryTerm childNodeId with
                            | Some value -> value
                            | None ->
                                match traceRange with
                                | Some rr -> term (add_trace base_s rr) child
                                | None -> term base_s child
                        let var rr a =
                            match recordChildValue (Some rr) a with
                            | DSymbol k -> k
                            | other -> failwith (sprintf "Replay record-with expected symbol; got %s" (show_data other))
                        let applyMap (m0: Map<int * string, Data>) =
                            let mutable m = m0
                            let mutable xs = withs
                            while not xs.IsEmpty do
                                match xs with
                                | x :: rest ->
                                    let sym a b =
                                        let i =
                                            m
                                            |> Map.tryPick (fun (i, k) _ -> if k = a then Some i else None)
                                            |> Option.defaultValue m.Count
                                        m <- Map.add (i, a) (recordChildValue None b) m
                                    let symMod rr a b =
                                        match tryPickKey a m with
                                        | Some (i, oldValue) -> m <- Map.add (i, a) (EvalReplayValueStore.runApplyAfterDefinition (box base_s) (recordChildValue (Some rr) b) oldValue) m
                                        | None -> failwith (sprintf "Replay record-with cannot find key %s" a)
                                    match x with
                                    | RSymbol((_, a), b) -> sym a b
                                    | RSymbolModify((rr, a), b) -> symMod rr a b
                                    | RVar((rr, a), b) -> sym (var rr a) b
                                    | RVarModify((rr, a), b) -> symMod rr (var rr a) b
                                    xs <- rest
                                | [] -> ()
                            let mutable ys = withouts
                            while not ys.IsEmpty do
                                match ys with
                                | x :: rest ->
                                    match x with
                                    | WSymbol(_, a) ->
                                        m <- m |> Map.filter (fun (_, k) _ -> k <> a)
                                    | WVar(rr, a) ->
                                        let a = var rr a
                                        m <- m |> Map.filter (fun (_, k) _ -> k <> a)
                                    ys <- rest
                                | [] -> ()
                            m
                        let updateNested (root: Map<int * string, Data>) (xs: (Range * E) list) =
                            let path = ResizeArray<struct(Range * string)>()
                            let mutable cur = xs
                            while not cur.IsEmpty do
                                match cur with
                                | (rr, x) :: rest ->
                                    match recordChildValue (Some rr) x with
                                    | DSymbol k -> path.Add(struct(rr, k))
                                    | other -> failwith (sprintf "Replay record-with path expected symbol; got %s" (show_data other))
                                    cur <- rest
                                | [] -> ()
                            let mutable curMap = root
                            let parents = ResizeArray<struct(int * string * Map<int * string, Data>)>()
                            for i = 0 to path.Count - 1 do
                                let struct(rr, k) = path.[i]
                                match tryPickKey k curMap with
                                | Some (idx, DRecord sub) ->
                                    parents.Add(struct(idx, k, curMap))
                                    curMap <- sub
                                | Some (_, other) -> failwith (sprintf "Replay record-with path expected record; got %s" (show_data other))
                                | None -> failwith (sprintf "Replay record-with cannot find key %s" k)
                            let mutable updated = applyMap curMap
                            for i = parents.Count - 1 downto 0 do
                                let struct(idx, k, parent) = parents.[i]
                                updated <- Map.add (idx, k) (DRecord updated) parent
                            updated
                        let out =
                            match vars with
                            | (rr, x) :: xs ->
                                match recordChildValue (Some rr) x with
                                | DRecord root -> updateNested root xs
                                | other -> failwith (sprintf "Replay record-with expected base record; got %s" (show_data other))
                            | [] -> applyMap Map.empty
                        DRecord out)
                | EOp(_,op,args) ->
                    let argArray = args |> List.toArray
                    for arg in argArray do
                        let argNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box arg)
                        registerReplayTerm argNodeId arg
                        match arg with
                        | EV a -> EvalReplayValueStore.putTerm argNodeId (fun () -> v s a)
                        | ELit(_,lit) -> EvalReplayValueStore.putTermValue argNodeId (DLit lit)
                        | ESymbol(_,sym) -> EvalReplayValueStore.putTermValue argNodeId (DSymbol sym)
                        | EType(_,texpr) ->
                            EvalReplayValueStore.putType argNodeId (fun () -> ty s texpr)
                            EvalReplayValueStore.putTerm argNodeId (fun () -> ty_to_data s (ty s texpr))
                        | EDefaultLit(_,_,_) -> ()
                        | _ -> ()
                    EvalReplayValueStore.putOpContext nodeId (box s)
                    EvalReplayValueStore.putApplyContext nodeId (box s)
                    EvalReplayValueStore.putOpSpine nodeId {
                        opName = sprintf "%A" op
                        argCount = argArray.Length
                        argNodeIds = argArray |> Array.map (fun e -> System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box e))
                        argShapes = argArray |> Array.map evalNodeShapeTerm
                    }
                | EIfThenElse(_,cond,onTrue,onFalse) ->
                    let condNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box cond)
                    let trueNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box onTrue)
                    let falseNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box onFalse)
                    // ALPHA654: mirror recursive child registration in the
                    // post-fuse path, where deferred branch cells may resume
                    // after the active driver unwinds.
                    registerReplayTerm condNodeId cond
                    registerReplayTerm trueNodeId onTrue
                    registerReplayTerm falseNodeId onFalse
                    DiagJson.emit (
                        sprintf "{\"kind\":\"eval_worklist_if_branch_children_registered\",\"event\":\"term_entry_post_fuse\",\"node_id\":%d,\"shape\":\"EIfThenElse\",\"site\":%s,\"condition_node_id\":%d,\"true_node_id\":%d,\"true_shape\":%s,\"false_node_id\":%d,\"false_shape\":%s,\"single_flight\":1,\"next\":\"if_children_ready_for_branch_probe\"}"
                            nodeId (DiagJson.esc site) condNodeId trueNodeId (DiagJson.esc (evalNodeShapeTerm onTrue)) falseNodeId (DiagJson.esc (evalNodeShapeTerm onFalse)))
                    match cond with
                    | EV a -> EvalReplayValueStore.putTerm condNodeId (fun () -> v s a)
                    | ELit(_,lit) -> EvalReplayValueStore.putTermValue condNodeId (DLit lit)
                    | ESymbol(_,sym) -> EvalReplayValueStore.putTermValue condNodeId (DSymbol sym)
                    | _ -> ()
                    match onTrue with
                    | EV a -> EvalReplayValueStore.putTerm trueNodeId (fun () -> v s a)
                    | ELit(_,lit) -> EvalReplayValueStore.putTermValue trueNodeId (DLit lit)
                    | ESymbol(_,sym) -> EvalReplayValueStore.putTermValue trueNodeId (DSymbol sym)
                    | _ -> ()
                    match onFalse with
                    | EV a -> EvalReplayValueStore.putTerm falseNodeId (fun () -> v s a)
                    | ELit(_,lit) -> EvalReplayValueStore.putTermValue falseNodeId (DLit lit)
                    | ESymbol(_,sym) -> EvalReplayValueStore.putTermValue falseNodeId (DSymbol sym)
                    | _ -> ()
                    EvalReplayValueStore.putIfThenElse nodeId {
                        condNodeId = condNodeId
                        condShape = evalNodeShapeTerm cond
                        trueNodeId = trueNodeId
                        trueShape = evalNodeShapeTerm onTrue
                        falseNodeId = falseNodeId
                        falseShape = evalNodeShapeTerm onFalse
                    }
                | EApply _ ->
                    let args = ResizeArray<E>()
                    let mutable cur = expr
                    let mutable running = true
                    while running do
                        match cur with
                        | EApply(_, a, b) ->
                            args.Add b
                            cur <- a
                        | _ -> running <- false
                    let headNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box cur)
                    // ALPHA1060: post-fuse EApply children may themselves be EApply.
                    // Register them recursively just like the global-fuse path; otherwise
                    // a scheduled apply_arg_child can arrive at replay with no ApplySpine
                    // and no term thunk, yielding semantic_apply_spine_missing_direct_value_blocked.
                    registerReplayTerm headNodeId cur
                    match cur with
                    | EB _ -> EvalReplayValueStore.putTermValue headNodeId DB
                    | EV a -> EvalReplayValueStore.putTerm headNodeId (fun () -> v s a)
                    | ELit(_,lit) -> EvalReplayValueStore.putTermValue headNodeId (DLit lit)
                    | ESymbol(_,sym) -> EvalReplayValueStore.putTermValue headNodeId (DSymbol sym)
                    | EFun'(_,freeVars,i,body,annot) ->
                        EvalReplayValueStore.putTerm headNodeId (fun () ->
                            if freeVars.term.free_vars.Length <> i then failwith "Replay apply-head function free-var arity mismatch."
                            DFunction(body, annot, HopacExtensions.A.map (v s) freeVars.term.free_vars, HopacExtensions.A.map (vt s) freeVars.ty.free_vars, freeVars.term.stack_size, freeVars.ty.stack_size))
                    | ERecursiveFun'(_,freeVars,i,body,annot) ->
                        EvalReplayValueStore.putTerm headNodeId (fun () ->
                            if freeVars.term.free_vars.Length <> i then failwith "Replay apply-head recursive function free-var arity mismatch."
                            DFunction(body.Value, annot, HopacExtensions.A.map (v s) freeVars.term.free_vars, HopacExtensions.A.map (vt s) freeVars.ty.free_vars, freeVars.term.stack_size, freeVars.ty.stack_size))
                    | _ -> ()
                    for arg in args do
                        let argNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box arg)
                        registerReplayTerm argNodeId arg
                        match arg with
                        | EB _ -> EvalReplayValueStore.putTermValue argNodeId DB
                        | EV a -> EvalReplayValueStore.putTerm argNodeId (fun () -> v s a)
                        | ELit(_,lit) -> EvalReplayValueStore.putTermValue argNodeId (DLit lit)
                        | ESymbol(_,sym) -> EvalReplayValueStore.putTermValue argNodeId (DSymbol sym)
                        | _ -> ()
                    let replayArgs = args.ToArray()
                    EvalReplayValueStore.putApplySpine nodeId {
                        headNodeId = headNodeId
                        headShape = evalNodeShapeTerm cur
                        argCount = replayArgs.Length
                        argNodeIds = replayArgs |> Array.map (fun e -> System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box e))
                        argShapes = replayArgs |> Array.map evalNodeShapeTerm
                    }
                    DiagJson.emit (
                        sprintf "{\"kind\":\"eval_worklist_apply_spine_post_fuse_recursive_children_registered\",\"event\":\"term_entry_post_fuse\",\"node_id\":%d,\"shape\":\"EApply\",\"site\":%s,\"head_node_id\":%d,\"head_shape\":%s,\"arg_count\":%d,\"single_flight\":1,\"next\":\"apply_children_ready_for_replay\"}"
                            nodeId (DiagJson.esc site) headNodeId (DiagJson.esc (evalNodeShapeTerm cur)) replayArgs.Length)
                    // ALPHA382: direct term-cycle replay must carry the same LangEnv handle
                    // as term-entry capture.  Alpha381 proved VarIs/1 root completion, then
                    // attempt 2 reached EApply at listm.spi:13 and failed solely because the
                    // parent node had no apply context.  Store it here before the whole-spine
                    // thunk so late-bound DFunction body replay can enter the real apply path.
                    EvalReplayValueStore.putApplyContext nodeId (box s)
                    // ALPHA380: register a whole-spine thunk without lexically capturing apply.
                    // The real apply function is installed later through EvalReplayValueStore after
                    // its definition.  Until then this thunk fails closed under tryTerm.
                    EvalReplayValueStore.putTerm nodeId (fun () ->
                        let mutable current =
                            match EvalReplayValueStore.tryTerm headNodeId with
                            | Some value -> value
                            | None -> term s cur
                        for i = replayArgs.Length - 1 downto 0 do
                            let arg = replayArgs.[i]
                            let argNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box arg)
                            let argValue =
                                match EvalReplayValueStore.tryTerm argNodeId with
                                | Some value -> value
                                | None -> term s arg
                            current <- EvalReplayValueStore.runApplyAfterDefinition (box s) current argValue
                        current)
                | _ -> ()
            registerReplayTerm nodeId x
            let reCount = EvalCycleGuard.enter nodeObj
            let (a0,b0) = r0.range
            let nodeKey = sprintf "%s:%d:%d-%d:%d" r0.path a0.line a0.character b0.line b0.character
            let reKey = EvalCycleGuardKey.enter nodeKey

            use _cycle_guard = { new System.IDisposable with member _.Dispose() = EvalCycleGuard.exit nodeObj }
            use _cycle_guard_key = { new System.IDisposable with member _.Dispose() = EvalCycleGuardKey.exit nodeKey }

    

            // Re-entrancy limits: keep them bounded so real cycles fail fast (and avoid multi-minute JP stalls).
            let invNow = CacheGeneration.invalidationCount()
            let seqNow = CacheGeneration.isSequentialRequested()
            let max_reentry_base = EvalFallbackPolicy.maxReentry seqNow invNow depth
            let max_reentry = max_reentry_base // alpha316/326: no BigStack multiplier; forced sequential gets a centralized legacy budget
            let max_reentry_key = max_reentry
            let warn_reentry = EvalFallbackPolicy.warnReentry max_reentry_base
    

            let hashSnapShort () =
                EvalCycleGuard.snapshotHashes 12 |> Seq.map string |> String.concat ","
            let keySnapShort () =
                EvalCycleGuardKey.snapshotKeys 12 |> String.concat " | "
            if reCount > 1 then
                if reCount = 2 then
                    DiagSidecar.emit (sprintf "[spiral_compiler] EJP0011W term re-entry (non-fatal): nodeId=%d depth=%d site=%s" nodeId depth site)
                if reCount = warn_reentry then
                    let hs = hashSnapShort ()
                    let ks = keySnapShort ()
                    DiagSidecar.emit (sprintf "[spiral_compiler] EJP0011W term re-entry hot: re=%d/%d nodeId=%d depth=%d site=%s hs=[%s] ks=[%s]" reCount max_reentry nodeId depth site hs ks)
                    CacheGeneration.requestSequential ()
                if reCount > max_reentry then
                    let hs = hashSnapShort ()
                    let ks = keySnapShort ()
                    let big = BigStack.isActive()
                    CacheGeneration.requestSequential ()
                    let newGen = int (CacheGeneration.current())
                    // ALPHA313: EJP0011 is non-retryable. Do not invalidate generation on term cycles;
                    // invalidation turns a local recursion bug into a global retry storm.
                    DiagSidecar.emit (sprintf "%s term cycle(no_invalidate): nodeId=%d depth=%d site=%s gen=%d re=%d/%d big=%b hs=[%s] ks=[%s]" EJPCodes.EJP0011 nodeId depth site newGen reCount max_reentry big hs ks)
                    let frameOpt =
                        if big || depth > 512 then
                            TermCycleFuse.tripWithTrace (sprintf "term#%d" nodeId) site depth newGen reCount max_reentry s.trace
                            EvalWorklist.ensureCaptured "direct_term_cycle_node" |> ignore
                            EvalWorklist.attachSemanticCell "term_cycle" (semanticCellForTerm nodeId)
                            EvalWorklist.ensureCapturedAndRun "direct_term_cycle_node" "term_cycle" 16
                        else None
                    let errEnv = if depth > 256 then s else (add_trace s r0)
                    let msg = sprintf "%s: re-entrant term evaluation cycle detected at %s (nodeId=%d depth=%d gen=%d re=%d/%d big=%b)" EJPCodes.EJP0011 site nodeId depth newGen reCount max_reentry big
                    let msg = match frameOpt with Some frame -> EvalWorklist.requiredMessage msg frame | None -> msg
                    if depth > 256 then
                        raise_type_error_no_trace errEnv msg
                    else
                        raise_type_error errEnv msg
            if reKey > 1 then
                if reKey = 2 then
                    DiagSidecar.emitKeyedSample (sprintf "[spiral_compiler] EJP0011W|term|%s" nodeKey) (sprintf "[spiral_compiler] EJP0011W term re-entry (key, non-fatal): key=%s depth=%d site=%s" nodeKey depth site)
                    // ALPHA393: mirror the typed prefetch for term keyed warnings.  This is only
                    // enabled after forced-sequential fallback and only seeds a replayable frontier;
                    // it does not treat the warning itself as semantic completion.
                    if CacheGeneration.isSequentialRequested() && depth >= 8 && not (TermCycleFuse.isTripped()) then
                        try
                            let genNow = int (CacheGeneration.current())
                            TermCycleFuse.tripWithTrace nodeKey site depth genNow reKey max_reentry_key s.trace
                            EvalWorklist.ensureCaptured "sidecar_term_reentry_prefetch" |> ignore
                            EvalWorklist.attachSemanticCell "term_reentry_prefetch" (semanticCellForTerm nodeId)
                            let frameOpt = EvalWorklist.ensureCapturedAndRun "sidecar_term_reentry_prefetch" "term_reentry_prefetch" 16
                            let preflightStatus = match frameOpt with Some frame -> frame.status | None -> "missing_after_prefetch"
                            let preflightCursor = match frameOpt with Some frame -> frame.cursor | None -> -1
                            let preflightComplete =
                                match frameOpt with
                                | Some frame when EvalWorklist.frameReplayCompleteKind "term" frame -> true
                                | Some _ -> EvalWorklist.hasReplayCompleteKind "term"
                                | None -> EvalWorklist.hasReplayCompleteKind "term"
                            DiagJson.emit (
                                sprintf "{\"kind\":\"eval_worklist_term_reentry_prefetch_replay_drained\",\"event\":\"term_reentry\",\"key\":%s,\"site\":%s,\"depth\":%d,\"re\":%d,\"max_re\":%d,\"status\":%s,\"cursor\":%d,\"replayCompleteNow\":%b,\"single_flight\":1,\"next\":\"return_or_continue_term_replay\"}"
                                    (DiagJson.esc nodeKey) (DiagJson.esc site) depth reKey max_reentry_key (DiagJson.esc preflightStatus) preflightCursor preflightComplete)
                            if preflightComplete then
                                match EvalReplayValueStore.tryTerm nodeId with
                                | Some value ->
                                    System.Threading.Interlocked.Exchange(&jp_last_progress_ms, peval_sw.ElapsedMilliseconds) |> ignore
                                    DiagJson.emit (
                                        sprintf "{\"kind\":\"eval_worklist_root_complete_replay_progress_marked\",\"event\":\"sidecar_term_reentry_prefetch\",\"scope\":\"direct_term_replay_return\",\"status\":\"semantic_root_complete\",\"kind2\":\"term\",\"shape\":%s,\"single_flight\":1,\"next\":\"watchdog_progress_refreshed\"}"
                                            (DiagJson.esc termShape0))
                                    DiagJson.emit (
                                        sprintf "{\"kind\":\"eval_worklist_direct_term_reentry_replay_return\",\"event\":\"term_reentry\",\"status\":\"semantic_root_complete\",\"shape\":%s,\"single_flight\":1,\"next\":\"return_term_value\"}"
                                            (DiagJson.esc termShape0))
                                    TermCycleFuse.reset ()
                                    raise (EvalReplayTermReturn value)
                                | None -> ()
                            DiagJson.emit (
                                sprintf "{\"kind\":\"eval_worklist_sidecar_prefetch\",\"event\":\"term_reentry\",\"key\":%s,\"site\":%s,\"depth\":%d,\"re\":%d,\"max_re\":%d,\"single_flight\":1,\"next\":\"jp_stall_preflight_drained\"}"
                                    (DiagJson.esc nodeKey) (DiagJson.esc site) depth reKey max_reentry_key)
                        with
                        | EvalReplayTermReturn value -> raise (EvalReplayTermReturn value)
                        | _ -> ()
                if reKey = warn_reentry then
                    let hs = hashSnapShort ()
                    let ks = keySnapShort ()
                    DiagSidecar.emitKeyedSample (sprintf "[spiral_compiler] EJP0011W|term_hot|%s" nodeKey) (sprintf "[spiral_compiler] EJP0011W term re-entry hot(key): re=%d/%d key=%s depth=%d site=%s hs=[%s] ks=[%s]" reKey max_reentry_key nodeKey depth site hs ks)
                    CacheGeneration.requestSequential ()
                if reKey > max_reentry_key then
                    let hs = hashSnapShort ()
                    let ks = keySnapShort ()
                    let big = BigStack.isActive()
                    CacheGeneration.requestSequential ()
                    let newGen = int (CacheGeneration.current())
                    // ALPHA313: keyed EJP0011 is also non-retryable. Keep the current generation
                    // so the caller gets one deterministic typed failure instead of retry churn.
                    DiagSidecar.emit (sprintf "%s term cycle(key,no_invalidate): key=%s depth=%d site=%s gen=%d re=%d/%d big=%b hs=[%s] ks=[%s]" EJPCodes.EJP0011 nodeKey depth site newGen reKey max_reentry_key big hs ks)
                    let tc_count = TermCycleWatchdog.note nodeKey (int newGen)
                    let tc_panic = big || tc_count >= 2
                    let frameOpt =
                        if tc_panic then
                            DiagSidecar.emit (sprintf "%s term cycle watchdog: PANIC key=%s gen=%d count=%d" EJPCodes.EJP0011 nodeKey (int newGen) tc_count)
                            TermCycleFuse.tripWithTrace nodeKey site depth (int newGen) reKey max_reentry_key s.trace
                            EvalWorklist.ensureCaptured "direct_term_cycle_key" |> ignore
                            EvalWorklist.attachSemanticCell "term_cycle" (semanticCellForTerm nodeId)
                            EvalWorklist.ensureCapturedAndRun "direct_term_cycle_key" "term_cycle" 16
                        else None
                    DiagJson.termCycle nodeKey depth site (int newGen) reKey max_reentry_key big hs ks tc_count tc_panic
                    let errEnv = if depth > 256 then s else (add_trace s r0)
                    let msg = sprintf "%s: re-entrant term evaluation cycle detected at %s (key=%s depth=%d gen=%d re=%d/%d big=%b)" EJPCodes.EJP0011 site nodeKey depth (int newGen) reKey max_reentry_key big
                    let msg = match frameOpt with Some frame -> EvalWorklist.requiredMessage msg frame | None -> msg
                    raise_type_error errEnv msg
                

            // Maximum term recursion depth. Keep parallel attempts conservative, but give
            // forced-sequential fallback a larger legacy-style budget. This is the bridge toward
            // stack-safe evaluators: enough room for old list folds, still bounded by stack_check.
            let max_depth_base = EvalFallbackPolicy.depthBase
            let max_depth_big = EvalFallbackPolicy.maxDepthBig seqNow
            let max_depth = if BigStack.isActive() then max_depth_big else max_depth_base
    

            let deepSitesShort () =
                RecursionTracker.getDeepSites()
                |> List.sortByDescending (fun (kv: System.Collections.Generic.KeyValuePair<string,int>) -> kv.Value)
                |> List.truncate 8
                |> List.map (fun (kv: System.Collections.Generic.KeyValuePair<string,int>) -> sprintf "%s=%d" kv.Key kv.Value)
                |> String.concat ";"
    

            let inline stack_check (tag: string) =
                try
                    System.Runtime.CompilerServices.RuntimeHelpers.EnsureSufficientExecutionStack()
                with :? System.InsufficientExecutionStackException ->
                    let newGen = CacheGeneration.current()
                    jp_mismatch_counts.AddOrUpdate(sprintf "%s|term_insufficient_stack" EJPCodes.EJP0010, 1, (fun _ n -> n + 1)) |> ignore
                    let reasons = CacheGeneration.reasonsSnapshot 6 |> String.concat " | "
                    let deepSites = deepSitesShort ()
                    DiagSidecar.emitEnvSnapshotOnce()
                    let tid = System.Threading.Thread.CurrentThread.ManagedThreadId
                    let bigActive = BigStack.isActive()
                    let nest = BigStack.getNest()
                    let mbTerm = BigStack.getMb "term"
                    let mem = try System.GC.GetTotalMemory(false) with _ -> 0L
                    DiagSidecar.emit (sprintf "%s term insufficient_stack depth=%d site=%s gen=%d tag=%s tid=%d bigActive=%b nest=%d mb=%d mem=%d deepSites=[%s] reasons=[%s]"
                                            EJPCodes.EJP0010 depth site newGen tag tid bigActive nest mbTerm mem deepSites reasons)
                    // Always use non-fatal mode: reraise to allow BigStack pivot
                    reraise()
    

            if depth <= 32 then
                if (depth &&& 7) = 0 then stack_check "d<=32"
            elif depth <= 128 then
                if (depth &&& 1) = 0 then stack_check "d<=128"
            else
    
                stack_check "d>128"

            if depth > max_depth then
                let newGen = CacheGeneration.current() // alpha27: do not invalidate on term depth guard (avoids JP gen-change loops)
                jp_mismatch_counts.AddOrUpdate(sprintf "%s|term_depth_exceeded" EJPCodes.EJP0009, 1, (fun _ n -> n + 1)) |> ignore
                let deepSites = deepSitesShort ()
                let reasons = CacheGeneration.reasonsSnapshot 6 |> String.concat " | "
                let tid = System.Threading.Thread.CurrentThread.ManagedThreadId
                let bigActive = BigStack.isActive()
                let mbTerm = BigStack.getMb "term"
                let maxObs = RecursionTracker.getMaxObserved()
                let traceShort =
                    s.trace
                    |> List.truncate 8
                    |> List.map (fun r -> let (a,_) = r.range in sprintf "%s:%d:%d" r.path a.line a.character)
                    |> String.concat " <- "
                DiagSidecar.emit (sprintf "%s term recursion depth exceeded depth=%d max=%d maxObs=%d site=%s gen=%d tid=%d bigActive=%b mb=%d trace=%s deepSites=[%s] reasons=[%s]" EJPCodes.EJP0009 depth max_depth maxObs site newGen tid bigActive mbTerm traceShort deepSites reasons)
                let errEnv = if depth > 256 then s else (add_trace s r0)
                if depth > 256 then
                    raise_type_error_no_trace errEnv (sprintf "%s: term recursion depth exceeded (depth=%d max=%d) at %s" EJPCodes.EJP0009 depth max_depth site)
                else
                    raise_type_error errEnv (sprintf "%s: term recursion depth exceeded (depth=%d max=%d) at %s" EJPCodes.EJP0009 depth max_depth site)
    
    


            let global' (x: string) = globals_add s x
    
    


            let term2 s a b = term s a, term s b
            let term3 s a b c = term s a, term s b, term s c
            let type_apply s a b =
                match a with
                | DForall(body,gl_term,gl_ty,sz_term,sz_ty) ->
                    let s = { s with env_global_type = gl_ty; env_global_term = gl_term; env_stack_type = Array.zeroCreate<_> sz_ty; env_stack_term = Array.zeroCreate<_> sz_term }
                    s.env_stack_type.[0] <- b
                    term s body
                | DV(L(_,YForall)) -> raise_type_error s <| sprintf "Cannot apply a runtime forall during the partial evaluation stage."
                | a -> raise_type_error s <| sprintf "Expected a forall.\nGot: %s" (show_data a)
            EvalReplayValueStore.installTypeApplyAfterDefinition (fun sObj head typeArg ->
                type_apply (unbox<LangEnv> sObj) head typeArg)
            EvalReplayValueStore.installTypeApplyBodyReplayAfterDefinition (fun sObj parentNodeId head typeArg ->
                let s = unbox<LangEnv> sObj
                match head with
                | DForall(body,gl_term,gl_ty,sz_term,sz_ty) ->
                    let bodyNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box body)
                    // ALPHA417: do not overwrite an already-resolved forall body child.
                    // Alpha416 proved the child EForall' can resolve before the parent
                    // ETypeApply schedules its body.  Replacing that value with a fresh
                    // term s' body thunk reintroduced the same cyclic type_apply failure.
                    // Keep existing store entries and only install a thunk when the body
                    // is genuinely absent.
                    EvalReplayValueStore.putParentContinuation bodyNodeId { parentKind = "term"; parentShape = "ETypeApply"; parentNodeId = parentNodeId; role = "type_apply_forall_body" }
                    EvalReplayValueStore.putTypeApplyBodyNode parentNodeId bodyNodeId
                    if not (EvalReplayValueStore.hasTermValue bodyNodeId) then
                        // A type-apply body can itself be a first-class term value (EForall'/EFun').
                        // Materialize those directly in the concrete type-apply environment instead
                        // of calling term while a fuse is already tripped.  Non-value bodies keep the
                        // old fail-closed thunk path.
                        let s' = { s with env_global_type = gl_ty; env_global_term = gl_term; env_stack_type = Array.zeroCreate<_> sz_ty; env_stack_term = Array.zeroCreate<_> sz_term }
                        s'.env_stack_type.[0] <- typeArg
                        let directBodyValue =
                            try
                                match body with
                                | EB _ -> Choice1Of2 DB
                                | ELit(_,lit) -> Choice1Of2 (DLit lit)
                                | ESymbol(_,sym) -> Choice1Of2 (DSymbol sym)
                                | EFun'(_,freeVars,i,fnBody,annot) ->
                                    if freeVars.term.free_vars.Length <> i then Choice2Of2 "type_apply_body_function_free_var_arity_mismatch"
                                    else Choice1Of2 (DFunction(fnBody, annot, HopacExtensions.A.map (v s') freeVars.term.free_vars, HopacExtensions.A.map (vt s') freeVars.ty.free_vars, freeVars.term.stack_size, freeVars.ty.stack_size))
                                | ERecursiveFun'(_,freeVars,i,fnBody,annot) ->
                                    if freeVars.term.free_vars.Length <> i then Choice2Of2 "type_apply_body_recursive_function_free_var_arity_mismatch"
                                    else Choice1Of2 (DFunction(fnBody.Value, annot, HopacExtensions.A.map (v s') freeVars.term.free_vars, HopacExtensions.A.map (vt s') freeVars.ty.free_vars, freeVars.term.stack_size, freeVars.ty.stack_size))
                                | EForall'(_,freeVars,i,forallBody) ->
                                    if freeVars.ty.free_vars.Length <> i then Choice2Of2 "type_apply_body_forall_free_var_arity_mismatch"
                                    else Choice1Of2 (DForall(forallBody, HopacExtensions.A.map (v s') freeVars.term.free_vars, HopacExtensions.A.map (vt s') freeVars.ty.free_vars, freeVars.term.stack_size, freeVars.ty.stack_size))
                                | ERecursiveForall'(_,freeVars,i,forallBody) ->
                                    if freeVars.ty.free_vars.Length <> i then Choice2Of2 "type_apply_body_recursive_forall_free_var_arity_mismatch"
                                    else Choice1Of2 (DForall(forallBody.Value, HopacExtensions.A.map (v s') freeVars.term.free_vars, HopacExtensions.A.map (vt s') freeVars.ty.free_vars, freeVars.term.stack_size, freeVars.ty.stack_size))
                                | ENominal _ ->
                                    // A nominal constructor is not a first-class closure, but when it is the
                                    // immediate body of a type-apply replay we can try it under the already
                                    // materialized type argument before falling back to the old thunk path.
                                    Choice1Of2 (term s' body)
                                | _ -> Choice2Of2 "type_apply_body_not_immediate_value"
                            with ex -> Choice2Of2 ("type_apply_body_direct_value_failed:" + ex.GetType().Name)
                        match directBodyValue with
                        | Choice1Of2 value ->
                            EvalReplayValueStore.putTermValue bodyNodeId value
                            DiagJson.emit (
                                sprintf "{\"kind\":\"eval_worklist_type_apply_body_direct_value_materialized\",\"event\":\"type_apply_body_register\",\"parent_node_id\":%d,\"body_node_id\":%d,\"body_shape\":%s,\"site\":%s,\"single_flight\":1,\"next\":\"type_apply_body_value_materialized\"}"
                                    parentNodeId bodyNodeId (DiagJson.esc (evalNodeShapeTerm body)) (DiagJson.esc site))
                        | Choice2Of2 detail ->
                            EvalReplayValueStore.putTerm bodyNodeId (fun () -> term s' body)
                            if detail <> "type_apply_body_not_immediate_value" then
                                DiagJson.emit (
                                    sprintf "{\"kind\":\"eval_worklist_type_apply_body_direct_value_blocked\",\"event\":\"type_apply_body_register\",\"parent_node_id\":%d,\"body_node_id\":%d,\"body_shape\":%s,\"site\":%s,\"detail\":%s,\"single_flight\":1,\"next\":\"fallback_type_apply_body_thunk\"}"
                                        parentNodeId bodyNodeId (DiagJson.esc (evalNodeShapeTerm body)) (DiagJson.esc site) (DiagJson.esc detail))
                    Choice1Of2 (bodyNodeId, evalNodeShapeTerm body)
                | DV(L(_,YForall)) -> Choice2Of2 "type_apply_body_runtime_forall"
                | a -> Choice2Of2 (sprintf "type_apply_body_expected_forall:%s" (show_data a)))

            let rec apply s (a0, b0) =
                // v107-alpha24: Removed proactive depth-based BigStack spawning
                // Rely only on EnsureSufficientExecutionStack in apply_core for reactive spawning
                apply_core s (a0, b0)
    

            and apply_core s (a0, b0) =
                // v107-alpha11: define site/r0 locally for error messages
                let r0 = match s.trace with | r :: _ -> r | [] -> range0
                let site =
                    match s.trace with
                    | r :: _ ->
                        let (a,_) = r.range
                        sprintf "apply@%s:%d:%d" r.path a.line a.character
                    | _ -> "apply@unknown"
                // ### v75: stack guard + one-shot big-stack fallback (evita falha em folds profundos no bootstrap/stdlib)
                // apply participates in the term<->apply recursion; guard here too so we never hard-crash.
                let mutable stack_fallback : Data option = None
                try
                    System.Runtime.CompilerServices.RuntimeHelpers.EnsureSufficientExecutionStack()
                with :? System.InsufficientExecutionStackException ->
                    // v75: tente reexecutar em thread com stack maior (uma vez por thread)
                    try
                        stack_fallback <- BigStack.tryRun "apply" (fun () -> apply s (a0, b0))
                    with :? System.InsufficientExecutionStackException ->
                        stack_fallback <- None
                    if stack_fallback.IsNone then
                        let newGen = CacheGeneration.invalidate (System.String.Format("{0}: apply insufficient_stack site={1}", EJPCodes.EJP0010, site))
                        jp_mismatch_counts.AddOrUpdate(System.String.Format("{0}|apply_insufficient_stack", EJPCodes.EJP0010), 1, (fun _ n -> n + 1)) |> ignore
                        let depthA = RecursionTracker.currentDepth()
                        let maxObs = RecursionTracker.getMaxObserved()
                        let deepSites = deepSitesShort ()
                        let reasons = CacheGeneration.reasonsSnapshot 6 |> String.concat " | "
                        let tid = System.Threading.Thread.CurrentThread.ManagedThreadId
                        let bigActive = BigStack.isActive()
                        let mbApply = BigStack.getMb "apply"
                        let traceShort =
                            s.trace
                            |> List.truncate 6
                            |> List.map (fun r -> let (a,_) = r.range in sprintf "%s:%d:%d" r.path a.line a.character)
                            |> String.concat " <- "
                        DiagSidecar.emit (System.String.Format("{0} apply insufficient_stack gen={1} site={2} depth={3} maxObs={4} tid={5} bigActive={6} mb={7} trace={8} deepSites=[{9}] reasons=[{10}]",
                            EJPCodes.EJP0010, newGen, site, depthA, maxObs, tid, bigActive, mbApply, traceShort, deepSites, reasons))
                        raise_type_error (add_trace s r0) (System.String.Format("{0}: insufficient execution stack in apply at {1} (gen={2} depth={3} maxObs={4} tid={5} bigActive={6} mb={7})",
                            EJPCodes.EJP0010, site, newGen, depthA, maxObs, tid, bigActive, mbApply))
    

                match stack_fallback with
                | Some v ->
                    jp_mismatch_counts.AddOrUpdate(System.String.Format("{0}|apply_bigstack_ok", EJPCodes.EJP0010), 1, (fun _ n -> n + 1)) |> ignore
                    DiagSidecar.emit (System.String.Format("{0} apply bigstack_ok site={1} depth={2}", EJPCodes.EJP0010, site, RecursionTracker.currentDepth()))
                    v
                | None ->
                    let mutable a = a0
                    let mutable b = b0
                    let mutable unwrapping = true
                    while unwrapping do
                        match a with
                        | DNominal(DUnion _, _) -> raise_type_error s "Unions cannot be applied."
                        | DNominal(a', _) -> a <- a'
                        | _ -> unwrapping <- false
    

                    match a, b with
                    | DRecord a, DSymbol b ->
                        match a |> Map.tryPick (fun (_, k) v -> if k = b then Some v else None) with
                        | Some a -> a
                        | None -> raise_type_error s <| sprintf "Cannot find the key %s inside the record." b
                    | DFunction(body,_,gl_term,gl_ty,sz_term,sz_ty), b ->
                        let s : LangEnv = { s with env_global_type = gl_ty; env_global_term = gl_term; env_stack_type = Array.zeroCreate<_> sz_ty; env_stack_term = Array.zeroCreate<_> sz_term }
                        s.env_stack_term.[0] <- b
                        term s body
                    | DV(L(_,YForall)), _ -> raise_type_error s "Cannot apply a runtime forall, and not with a term. Foralls have to be known at compile time and applied with a type."
                    | DForall _, _ -> raise_type_error s "Cannot apply a forall with a term."
                    | DV(L(_,YFun(domain,range,t) & a_ty) & a), b ->
                        let b = dyn false s b
                        let b_ty = data_to_ty s b
                        let b_ty0 = data_to_ty s b
                        let b_ty = jp_method_deref_rec_placeholder b_ty0
                        if ty_eq_allow_jp_placeholders domain b_ty then push_typedop_no_rewrite s (TyApply(a,b)) range
                        else raise_type_error s <| sprintf "Cannot apply an argument of type %s to a function of type: %s" (show_ty b_ty0) (show_ty a_ty)
                    | DV(L(i,YLayout(ty,layout)) as tyv) as a, DSymbol b ->
                        let key = TyLayoutIndexByKey(tyv, b)
                        let ret_ty =
                            match ty with
                            | YRecord r ->
                                match r |> Map.tryPick (fun (i, k) v -> if k = b then Some (i,v) else None) with
                                | Some (_i, a) -> a
                                | None -> raise_type_error s <| sprintf "Cannot find the key %s inside the layout type's record." b
                            | _ -> raise_type_error s <| sprintf "Expected a record inside the layout type.\nGot: %s" (show_ty ty)
                        match layout with
                        | Heap | StackMutable | HeapMutable -> push_typedop_no_rewrite s key ret_ty
                    | DV(L(_,YLayout _)), b -> raise_type_error s <| sprintf "Expected a symbol as the index into the layout type.\nGot: %s" (show_data b)
                    | a, b ->
                        // ### v44: Enhanced EJP0007 handling with depth tracking and cache management ###
                        // EJP0007: Apply type mismatch - often indicates cache corruption under parallel builds.
                        // When we get a primitive (like i32) where a function is expected, it's almost always
                        // due to a race condition in the join point cache.
                        let is_primitive_mismatch =
                            match a with
                            | DV(L(_, YPrim _)) | DLit _ -> true
                            | _ -> false
    

                        let depth = RecursionTracker.currentDepth ()
                        let tid = System.Threading.Thread.CurrentThread.ManagedThreadId
                        let gen0 = CacheGeneration.current ()
                        let site =
                            match s.trace with
                            | r :: _ ->
                                let (a,_) = r.range
                                sprintf "%s:%d:%d" r.path a.line a.character
                            | _ -> "unknown"
    

                        let got_ty = data_to_ty s a
                        let got_ty_deref = jp_method_deref_rec_placeholder got_ty
    

                        if is_primitive_mismatch then
                            // Record for pattern learning
                            BitMamba.recordFailure a
    

                            // Mark as suspect in cache
                            SuspectCache.mark a EJPCodes.EJP0007
    

                            jp_mismatch_counts.AddOrUpdate(sprintf "%s|apply_primitive" EJPCodes.EJP0007, 1, (fun _ n -> n + 1)) |> ignore
                            let snap = if jp_diag_verbose then diag_snapshot_short (sprintf "%s apply_mismatch site=%s" EJPCodes.EJP0007 site) else ""
                            DiagSidecar.emit (sprintf "%s apply mismatch: expected callable, got %s Got(ty=%s deref=%s) depth=%d site=%s\n%s" EJPCodes.EJP0007 (show_data a) (show_ty got_ty) (show_ty got_ty_deref) depth site snap)
                            // v45+: bounded invalidation at shallow depth only.
                            // Deep recursion tends to be deterministic; invalidating here causes a generation storm.
                            let invKey = sprintf "%s|apply_deep_recursion|%s" EJPCodes.EJP0008 site
                            let invN = jp_mismatch_counts.AddOrUpdate(invKey, 1, (fun _ n -> n + 1))
                            if invN <= 1 && depth <= 256 then
                                let wasSeq = CacheGeneration.isSequentialRequested ()
                                CacheGeneration.requestSequential ()
                                // [EJP0008-220-001] Do NOT invalidate on apply mismatch.
                                // SuspectCache.mark already poisons join_point_key so memoization is bypassed.
                                // Invalidation bumps generation and can cascade into BigStack join aborts (EJP0018),
                                // sometimes leaving JP in a liveness-bug state (stage 4/4 stall).
                                let genNow = CacheGeneration.current()
                                if not wasSeq then
                                    DiagSidecar.emit (sprintf "%s apply mismatch -> requestSequential (no invalidate; gen=%d) depth=%d site=%s" EJPCodes.EJP0008 genNow depth site)
                                else
                                    DiagSidecar.emit (sprintf "%s apply mismatch -> already sequential (no invalidate; gen=%d) depth=%d site=%s" EJPCodes.EJP0008 genNow depth site)
                        let is_jp_placeholder_apply =
                            match got_ty_deref with
                            | YSymbol s when s.Contains("JPMethodRecPlaceholder(") || s.Contains("JPTypeRecPlaceholder(") || s.Contains("JPClosureRecPlaceholder(") || s.Contains("JPMethodUnknownRet") -> true
                            | _ -> false
    

                        let liveReplayApplyMismatchHandoff =
                            (try
                                EvalWorklist.pendingCount() > 0
                                || EvalWorklist.replayQueueDepth() > 0
                                || EvalWorklist.replayDriverActiveDepthValue() > 0
                                || EvalWorklist.hasProgressYield()
                             with _ -> false)
                        let recordLikeLiveReplayApplyMismatch =
                            liveReplayApplyMismatchHandoff
                            && ((show_data a).StartsWith("{", StringComparison.Ordinal)
                                || (show_ty got_ty_deref).StartsWith("{", StringComparison.Ordinal))
                        if is_jp_placeholder_apply then
                            SuspectCache.mark a (sprintf "%s apply_jp_placeholder" EJPCodes.EJP0007)
                            jp_mismatch_counts.AddOrUpdate(sprintf "%s|apply_jp_placeholder" EJPCodes.EJP0007, 1, (fun _ n -> n + 1)) |> ignore
                            let snap = if jp_diag_verbose then diag_snapshot_short (sprintf "%s apply_jp_placeholder site=%s" EJPCodes.EJP0007 site) else ""
                            DiagSidecar.emit (sprintf "%s apply mismatch: JP placeholder callable (soft), returning arg (no invalidate). got=%s ty=%s deref=%s depth=%d site=%s\n%s" EJPCodes.EJP0007 (show_data a) (show_ty got_ty) (show_ty got_ty_deref) depth site snap)
                            // ALPHA111: JP placeholder apply is soft; no cache invalidation/sequential request.
                            b
                        elif recordLikeLiveReplayApplyMismatch then
                            let pendingNow = EvalWorklist.pendingCount()
                            let queueDepthNow = EvalWorklist.replayQueueDepth()
                            let activeDepthNow = EvalWorklist.replayDriverActiveDepthValue()
                            let progressYieldNow = EvalWorklist.hasProgressYield()
                            DiagJson.emit (
                                sprintf "{\"kind\":\"eval_worklist_record_apply_type_error_deferred\",\"event\":\"apply_type_mismatch\",\"site\":%s,\"got\":%s,\"got_ty\":%s,\"got_ty_deref\":%s,\"pending\":%d,\"queue_depth\":%d,\"active_depth\":%d,\"progress_yield_pending\":%b,\"policy\":\"do_not_surface_record_apply_type_error_while_replay_handoff_is_live\",\"single_flight\":1,\"next\":\"retry_active_replay_handoff\"}"
                                    (DiagJson.esc site) (DiagJson.esc (show_data a)) (DiagJson.esc (show_ty got_ty)) (DiagJson.esc (show_ty got_ty_deref)) pendingNow queueDepthNow activeDepthNow progressYieldNow)
                            TermCycleFuse.reset ()
                            raise_type_error s <| sprintf "%s: active replay apply mismatch handoff deferred site=%s pending=%d queue_depth=%d active_depth=%d progress_yield_pending=%b got=%s got_ty=%s got_ty_deref=%s" EJPCodes.EJP0011 site pendingNow queueDepthNow activeDepthNow progressYieldNow (show_data a) (show_ty got_ty) (show_ty got_ty_deref)
                        else
                            raise_type_error s <| sprintf "Expected a function, closure, record or a layout type possibly inside a nominal.\nGot: %s\nGot(ty): %s\nGot(ty_deref): %s" (show_data a) (show_ty got_ty) (show_ty got_ty_deref)
    
    


            EvalReplayValueStore.installApplyAfterDefinition (fun sObj head arg ->
                apply (unbox<LangEnv> sObj) (head, arg))

            EvalReplayValueStore.installApplyFunctionBodyReplayAfterDefinition (fun sObj parentNodeId head arg ->
                let s = unbox<LangEnv> sObj
                match head with
                | DFunction(body, _annot, gl_term, gl_ty, sz_term, sz_ty) ->
                    let bodyNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box body)
                    EvalReplayValueStore.putParentContinuation bodyNodeId { parentKind = "term"; parentShape = "EApply"; parentNodeId = parentNodeId; role = "apply_function_body" }
                    EvalReplayValueStore.putApplyFunctionBodyNode parentNodeId bodyNodeId
                    let mkBodyEnv () =
                        let s' = { s with env_global_type = gl_ty; env_global_term = gl_term; env_stack_type = Array.zeroCreate<_> sz_ty; env_stack_term = Array.zeroCreate<_> sz_term }
                        s'.env_stack_term.[0] <- arg
                        s'
                    match body with
                    | EPairTest(r, bind, p1, p2, onSucc, onFail) ->
                        let succNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box onSucc)
                        let failNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box onFail)
                        let pairEnvForBind () = add_trace (mkBodyEnv()) r
                        try
                            let bindEnv = pairEnvForBind()
                            EvalReplayValueStore.putPairTestBindValue bodyNodeId (v bindEnv bind)
                        with _ -> ()
                        EvalReplayValueStore.putTerm succNodeId (fun () ->
                            let branchEnv = pairEnvForBind()
                            match v branchEnv bind with
                            | DPair(a,b) ->
                                store_term branchEnv p1 a
                                store_term branchEnv p2 b
                                term branchEnv onSucc
                            | other -> failwith (sprintf "pair_test_success_branch_not_selected:%s" (show_data other)))
                        EvalReplayValueStore.putTerm failNodeId (fun () ->
                            let branchEnv = pairEnvForBind()
                            match v branchEnv bind with
                            | DPair _ -> failwith "pair_test_fail_branch_not_selected:DPair"
                            | _ -> term branchEnv onFail)
                        EvalReplayValueStore.putPairTestSpine bodyNodeId {
                            successNodeId = succNodeId
                            successShape = evalNodeShapeTerm onSucc
                            failNodeId = failNodeId
                            failShape = evalNodeShapeTerm onFail
                        }
                    | EAnnotTest(_, annotTy, bind, onSucc, onFail) ->
                        let typeNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box annotTy)
                        let trueNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box onSucc)
                        let falseNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box onFail)
                        let annotEnv () = mkBodyEnv()
                        EvalReplayValueStore.putAnnotTestContext bodyNodeId (box (annotEnv()))
                        try EvalReplayValueStore.putAnnotTestBindValue bodyNodeId (v (annotEnv()) bind)
                        with _ -> ()
                        EvalReplayValueStore.putType typeNodeId (fun () -> ty (annotEnv()) annotTy)
                        EvalReplayValueStore.putTerm trueNodeId (fun () -> term (annotEnv()) onSucc)
                        EvalReplayValueStore.putTerm falseNodeId (fun () -> term (annotEnv()) onFail)
                        EvalReplayValueStore.putAnnotTestSpine bodyNodeId {
                            typeNodeId = typeNodeId
                            typeShape = evalNodeShapeTy annotTy
                            trueNodeId = trueNodeId
                            trueShape = evalNodeShapeTerm onSucc
                            falseNodeId = falseNodeId
                            falseShape = evalNodeShapeTerm onFail
                        }
                        EvalReplayValueStore.putTerm bodyNodeId (fun () ->
                            let s2 = annotEnv()
                            let branch, branchNodeId =
                                let bindTy = data_to_ty s2 (v s2 bind)
                                let annotTy2 = ty s2 annotTy
                                if ty_eq_allow_jp_placeholders bindTy annotTy2 then onSucc, trueNodeId
                                else onFail, falseNodeId
                            match EvalReplayValueStore.tryTerm branchNodeId with
                            | Some value -> value
                            | None -> failwith ("annot_test_branch_value_missing:" + evalNodeShapeTerm branch))
                    | EUnitTest(r, bind, onSucc, onFail) ->
                        // ALPHA1055: runtime 1054 reached EUnitTest branches whose selected
                        // child was EAnnotTest, but the function-body replay bridge had only
                        // a direct thunk and no branch-local AnnotTestSpine.  Register the
                        // UnitTest discriminator plus selected branches in the body env, and
                        // materialize nested EAnnotTest spines with the same body env so
                        // term_annot_test_spine_missing cannot repeat as a fingerprint loop.
                        let bindNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box bind)
                        let succNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box onSucc)
                        let failNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box onFail)
                        let unitEnv () = add_trace (mkBodyEnv()) r
                        let registerBodyBranchTerm (branchNodeId: int) (branchExpr: E) =
                            match branchExpr with
                            | EAnnotTest(ar, branchAnnotTy, branchBind, branchOnSucc, branchOnFail) ->
                                let branchTypeNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box branchAnnotTy)
                                let branchTrueNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box branchOnSucc)
                                let branchFalseNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box branchOnFail)
                                let branchEnv () = add_trace (unitEnv()) ar
                                EvalReplayValueStore.putAnnotTestContext branchNodeId (box (branchEnv()))
                                try EvalReplayValueStore.putAnnotTestBindValue branchNodeId (v (branchEnv()) branchBind)
                                with _ -> ()
                                EvalReplayValueStore.putType branchTypeNodeId (fun () -> ty (branchEnv()) branchAnnotTy)
                                EvalReplayValueStore.putTerm branchTrueNodeId (fun () -> term (branchEnv()) branchOnSucc)
                                EvalReplayValueStore.putTerm branchFalseNodeId (fun () -> term (branchEnv()) branchOnFail)
                                EvalReplayValueStore.putAnnotTestSpine branchNodeId {
                                    typeNodeId = branchTypeNodeId
                                    typeShape = evalNodeShapeTy branchAnnotTy
                                    trueNodeId = branchTrueNodeId
                                    trueShape = evalNodeShapeTerm branchOnSucc
                                    falseNodeId = branchFalseNodeId
                                    falseShape = evalNodeShapeTerm branchOnFail
                                }
                                DiagJson.emit (
                                    sprintf "{\"kind\":\"eval_worklist_unit_test_branch_annot_spine_materialized\",\"event\":\"apply_function_body_replay\",\"unit_node_id\":%d,\"branch_node_id\":%d,\"type_node_id\":%d,\"true_node_id\":%d,\"false_node_id\":%d,\"branch_shape\":%s,\"single_flight\":1,\"next\":\"explicit_eval_worklist_annot_test_branch_stepper_required\"}"
                                        bodyNodeId branchNodeId branchTypeNodeId branchTrueNodeId branchFalseNodeId (DiagJson.esc (evalNodeShapeTerm branchExpr)))
                                EvalReplayValueStore.putTerm branchNodeId (fun () ->
                                    let s2 = branchEnv()
                                    let selectedBranch, selectedNodeId =
                                        let bindTy = data_to_ty s2 (v s2 branchBind)
                                        let annotTy2 = ty s2 branchAnnotTy
                                        if ty_eq_allow_jp_placeholders bindTy annotTy2 then branchOnSucc, branchTrueNodeId
                                        else branchOnFail, branchFalseNodeId
                                    match EvalReplayValueStore.tryTerm selectedNodeId with
                                    | Some value -> value
                                    | None -> failwith ("annot_test_branch_value_missing:" + evalNodeShapeTerm selectedBranch))
                            | _ ->
                                EvalReplayValueStore.putTerm branchNodeId (fun () -> term (unitEnv()) branchExpr)
                        registerBodyBranchTerm succNodeId onSucc
                        registerBodyBranchTerm failNodeId onFail
                        EvalReplayValueStore.putTerm bindNodeId (fun () -> v (unitEnv()) bind)
                        EvalReplayValueStore.putUnitTestSpine bodyNodeId {
                            bindNodeId = bindNodeId
                            bindShape = "EV"
                            successNodeId = succNodeId
                            successShape = evalNodeShapeTerm onSucc
                            failNodeId = failNodeId
                            failShape = evalNodeShapeTerm onFail
                        }
                        EvalReplayValueStore.putTerm bodyNodeId (fun () ->
                            let s2 = unitEnv()
                            let branch, branchNodeId =
                                match v s2 bind with
                                | DB -> onSucc, succNodeId
                                | _ -> onFail, failNodeId
                            match EvalReplayValueStore.tryTerm branchNodeId with
                            | Some value -> value
                            | None -> failwith ("unit_test_branch_value_missing:" + evalNodeShapeTerm branch))
                    | EOp(_, op, args) ->
                        let bodyEnv = mkBodyEnv()
                        let argArray = args |> List.toArray
                        for argExpr in argArray do
                            let argNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box argExpr)
                            match argExpr with
                            | EV a -> EvalReplayValueStore.putTerm argNodeId (fun () -> v bodyEnv a)
                            | ELit(_,lit) -> EvalReplayValueStore.putTermValue argNodeId (DLit lit)
                            | ESymbol(_,sym) -> EvalReplayValueStore.putTermValue argNodeId (DSymbol sym)
                            | EB _ -> EvalReplayValueStore.putTermValue argNodeId DB
                            | _ -> EvalReplayValueStore.putTerm argNodeId (fun () -> term bodyEnv argExpr)
                        EvalReplayValueStore.putOpContext bodyNodeId (box bodyEnv)
                        EvalReplayValueStore.putApplyContext bodyNodeId (box bodyEnv)
                        EvalReplayValueStore.putOpSpine bodyNodeId {
                            opName = sprintf "%A" op
                            argCount = argArray.Length
                            argNodeIds = argArray |> Array.map (fun e -> System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box e))
                            argShapes = argArray |> Array.map evalNodeShapeTerm
                        }
                    | EApply _ ->
                        // ALPHA643: function-body replay can surface a nested EApply as the
                        // selected child before the normal registerReplayTerm pass has seen it.
                        // Materialize the same ApplySpine here, in the concrete body env, so
                        // term_apply_spine_missing_store becomes a child/arg replay instead of
                        // a replay-fingerprint terminal.  This only records existing syntax and
                        // existing thunks; the eventual value is still produced by apply/term.
                        let bodyEnv = mkBodyEnv()
                        let args = ResizeArray<E>()
                        let mutable cur = body
                        let mutable running = true
                        while running do
                            match cur with
                            | EApply(_, a, b) ->
                                args.Add b
                                cur <- a
                            | _ -> running <- false
                        let headNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box cur)
                        let inline putReplayTermLeaf nodeId expr =
                            match expr with
                            | EB _ -> EvalReplayValueStore.putTermValue nodeId DB
                            | EV a -> EvalReplayValueStore.putTerm nodeId (fun () -> v bodyEnv a)
                            | ELit(_,lit) -> EvalReplayValueStore.putTermValue nodeId (DLit lit)
                            | ESymbol(_,sym) -> EvalReplayValueStore.putTermValue nodeId (DSymbol sym)
                            | EFun'(_,freeVars,i,body,annot) ->
                                EvalReplayValueStore.putTerm nodeId (fun () ->
                                    if freeVars.term.free_vars.Length <> i then failwith "Replay function-body apply-head free-var arity mismatch."
                                    DFunction(body, annot, HopacExtensions.A.map (v bodyEnv) freeVars.term.free_vars, HopacExtensions.A.map (vt bodyEnv) freeVars.ty.free_vars, freeVars.term.stack_size, freeVars.ty.stack_size))
                            | ERecursiveFun'(_,freeVars,i,body,annot) ->
                                EvalReplayValueStore.putTerm nodeId (fun () ->
                                    if freeVars.term.free_vars.Length <> i then failwith "Replay function-body recursive apply-head free-var arity mismatch."
                                    DFunction(body.Value, annot, HopacExtensions.A.map (v bodyEnv) freeVars.term.free_vars, HopacExtensions.A.map (vt bodyEnv) freeVars.ty.free_vars, freeVars.term.stack_size, freeVars.ty.stack_size))
                            | _ -> EvalReplayValueStore.putTerm nodeId (fun () -> term bodyEnv expr)
                        putReplayTermLeaf headNodeId cur
                        for argExpr in args do
                            let argNodeId = System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box argExpr)
                            putReplayTermLeaf argNodeId argExpr
                        let replayArgs = args.ToArray()
                        EvalReplayValueStore.putApplyContext bodyNodeId (box bodyEnv)
                        EvalReplayValueStore.putApplySpine bodyNodeId {
                            headNodeId = headNodeId
                            headShape = evalNodeShapeTerm cur
                            argCount = replayArgs.Length
                            argNodeIds = replayArgs |> Array.map (fun e -> System.Runtime.CompilerServices.RuntimeHelpers.GetHashCode (box e))
                            argShapes = replayArgs |> Array.map evalNodeShapeTerm
                        }
                    | _ -> ()
                    if not (EvalReplayValueStore.hasTerm bodyNodeId) then
                        EvalReplayValueStore.putTerm bodyNodeId (fun () -> term (mkBodyEnv()) body)
                    Choice1Of2 (bodyNodeId, evalNodeShapeTerm body)
                | DV(L(_,YFun _)) ->
                    Choice2Of2 "apply_function_body_runtime_fun"
                | a ->
                    Choice2Of2 (sprintf "apply_function_body_expected_function:%s" (show_data a)))

            EvalReplayValueStore.installDynamicJoinApplyAfterDefinition (fun sObj head arg ->
                // ALPHA386: this bridge now covers both DFunction+dynamic-arg and
                // dynamic-placeholder-head+dynamic-arg.  The latter is the curried
                // continuation exposed by alpha385 as unsupported_head:DV@arg1.
                let s = unbox<LangEnv> sObj
                let inline normalizeRetTy (t: Ty) =
                    let t = jp_method_deref_rec_placeholder t
                    match t with
                    | YSymbol sym when sym.Contains("JPMethodRecPlaceholder(") || sym.Contains("JPTypeRecPlaceholder(") || sym.Contains("JPClosureRecPlaceholder(") || sym.Contains("JPMethodUnknownRet") ->
                        YSymbol "JPMethodUnknownRet(par)"
                    | _ -> t
                let retTy =
                    match head with
                    | DFunction(_, Some annot, _, _, _, _) ->
                        try normalizeRetTy (ty s annot)
                        with _ -> YSymbol "JPMethodUnknownRet(par)"
                    | DV(L(_, YFun(_, range, _))) ->
                        normalizeRetTy range
                    | _ ->
                        YSymbol "JPMethodUnknownRet(par)"
                let retTy =
                    match retTy with
                    | YVoid -> YSymbol "JPMethodUnknownRet(par)"
                    | _ -> retTy
                let i = s.i.Value
                s.i.Value <- i + 1
                let placeholder = DV(L(i, retTy))
                DiagSidecar.emit (sprintf "[spiral_compiler] EJP0011 dynamic_join_apply replay placeholder ret=%s head=%s arg=%s" (show_ty retTy) (show_data head) (show_data arg))
                placeholder)

            let rec if_ s cond on_succ on_fail =
                // v107-alpha24: Removed proactive depth-based BigStack spawning
                // Rely only on EnsureSufficientExecutionStack in if_core for reactive spawning
                if_core s cond on_succ on_fail
    

            and if_core s cond on_succ on_fail =
                // v107-alpha13: emergency stack pivot must return the same type as the normal path
                try
                    System.Runtime.CompilerServices.RuntimeHelpers.EnsureSufficientExecutionStack()
                    if_core_impl s cond on_succ on_fail
                with :? System.InsufficientExecutionStackException ->
                    match BigStack.tryRun "if_emergency" (fun () -> if_core_impl s cond on_succ on_fail) with
                    | Some v -> v
                    | None ->
                        let r0 = match s.trace with | r :: _ -> r | [] -> range0
                        raise_type_error (add_trace s r0) (sprintf "%s: stack overflow in if_ (BigStack exhausted)" EJPCodes.EJP0010)
    

            and if_core_impl s cond on_succ on_fail =
                let lit_tr = DLit(LitBool true)
                let lit_fl = DLit(LitBool false)
                let type_bool = YPrim BoolT
                let cond =
                    let visiting = HashSet(HashIdentity.Reference)
                    let rec norm cond =
                        if visiting.Add cond = false then cond
                        else
                            match cond with
                            | DV(L(_,YPrim BoolT & type_bool)) as cond ->
                                match cse_tryfind s (TyOp(EQ, [cond; lit_tr])) with
                                | Some cond' when cond' <> cond -> norm cond'
                                | Some _ | None -> cond
                            | DV(L(v,ty)) as cond when ty_is_jp_method_rec_placeholder ty ->
                                match jp_method_try_key_of_rec_placeholder ty with
                                | Some k -> jp_method_resolve_rec_placeholder k type_bool
                                | None -> ()
                                DV(L(v, type_bool))
                            | DV(L(v,YSymbol sym)) when sym.Contains("JPMethodUnknownRet(") ->
                                // A join-point unknown-return placeholder used as an if condition is
                                // constrained by the syntactic context to BoolT.  Do not terminalize it
                                // as a symbolic condition; normalize it into the same dynamic-bool path
                                // already used by unresolved recursive join-point placeholders.
                                DV(L(v, type_bool))
                            | _ -> cond
                    norm cond
                match cond with
                | DLit (LitBool true) -> term s on_succ
                | DLit (LitBool false) -> term s on_fail
                | DV(L(_,YPrim BoolT & type_bool)) ->
                    let add_rewrite_cases is_true =
                        let cse = Dictionary(HashIdentity.Structural)
                        let tr,fl = if is_true then lit_tr, lit_fl else lit_fl, lit_tr
                        let inline op op cond' res = cse.Add(TyOp(op,[cond;cond']),res); cse.Add(TyOp(op,[cond';cond]),res)
                        op EQ lit_tr tr; op NEQ lit_tr fl; op EQ lit_fl fl; op NEQ lit_fl tr
                        cse
                    let tr, type_tr = term_scope' s (add_rewrite_cases true) on_succ
                    let fl, type_fl = term_scope' s (add_rewrite_cases false) on_fail
                    let type_tr, type_fl =
                        match type_tr, type_fl with
                        | YRecord tr, YRecord fl ->
                            let tr =
                                tr
                                |> Seq.map (fun (KeyValue ((i, k), v)) ->
                                    let i =
                                        fl |> Map.tryPick (fun (i', k') _ -> if k = k' then Some i' else None)
                                        |> Option.defaultValue i
                                    (i, k), v
                                )
                                |> Map.ofSeq
                                |> YRecord
    

                            let fl =
                                fl
                                |> Seq.map (fun (KeyValue ((i, k), v)) ->
                                    k, ((i, k), v)
                                )
                                |> Seq.distinctBy fst
                                |> Seq.map snd
                                |> Map.ofSeq
                                |> YRecord
    

                            tr, fl
    

                        | _ ->
                            type_tr, type_fl
    

                    if type_tr = type_fl then
                        if tr.Length = 1 && fl.Length = 1 then
                            match tr.[0], fl.[0] with
                            | TyLocalReturnOp(_,tr,_), TyLocalReturnOp(_,fl,_) when tr = fl -> push_typedop_no_rewrite s tr type_tr
                            | TyLocalReturnData(tr',_), TyLocalReturnData(fl',_) ->
                                match tr', fl' with
                                | tr, fl when tr = fl -> tr
                                | DLit(LitBool false), DLit(LitBool true) -> push_binop s EQ (cond,lit_fl) type_bool
                                | DLit(LitBool false), fl when cond = fl -> lit_fl
                                | DLit(LitBool true), fl -> // boolean or
                                    match fl with
                                    | DLit (LitBool false) -> cond
                                    | _ -> if cond = fl then cond else push_binop s BoolOr (cond,fl) type_bool
                                | tr, DLit(LitBool false) -> // boolean and
                                    match tr with
                                    | DLit(LitBool true) -> cond
                                    | _ -> if cond = tr then cond else push_binop s BoolAnd (cond,tr) type_bool
                                | _ -> push_typedop_no_rewrite s (TyIf(cond,tr,fl)) type_tr
                            | _ -> push_typedop_no_rewrite s (TyIf(cond,tr,fl)) type_tr
                        else push_typedop_no_rewrite s (TyIf(cond,tr,fl)) type_tr
                    else
                        // ALPHA100: JPMethod recursion placeholders can leak into composite branch types during parallel JP evaluation.
                        // Treat placeholders as unification holes recursively (pairs/arrays/apply/layout/fun/records).
                        let inline try_resolve_jp_placeholder (a: Ty) (b: Ty) : Ty option =
                            try
                                let k_opt =
                                    match jp_method_try_key_of_rec_placeholder a with
                                    | Some k -> Some k
                                    | None ->
                                        jp_method_rec_placeholders |> Seq.tryPick (fun (KeyValue(k,c)) -> if c.ph = a || c.v = a then Some k else None)
                                k_opt |> Option.map (fun k -> jp_method_resolve_rec_placeholder k b; b)
                            with _ -> None

                        let rec try_resolve_jp_placeholder_deep (a: Ty) (b: Ty) : Ty option =
                            match try_resolve_jp_placeholder a b with
                            | Some _ -> Some b
                            | None ->
                                match a, b with
                                | YPair(a1,a2), YPair(b1,b2) ->
                                    let r1 = try_resolve_jp_placeholder_deep a1 b1
                                    let r2 = try_resolve_jp_placeholder_deep a2 b2
                                    if r1.IsSome || r2.IsSome then Some b else None
                                | YArray a1, YArray b1 ->
                                    try_resolve_jp_placeholder_deep a1 b1 |> Option.map (fun _ -> b)
                                | YApply(a1,a2), YApply(b1,b2) ->
                                    let r1 = try_resolve_jp_placeholder_deep a1 b1
                                    let r2 = try_resolve_jp_placeholder_deep a2 b2
                                    if r1.IsSome || r2.IsSome then Some b else None
                                | YLayout(a1,l1), YLayout(b1,l2) when l1 = l2 ->
                                    try_resolve_jp_placeholder_deep a1 b1 |> Option.map (fun _ -> b)
                                | YFun(a1,r1,ft1), YFun(a2,r2,ft2) when ft1 = ft2 ->
                                    let rA = try_resolve_jp_placeholder_deep a1 a2
                                    let rR = try_resolve_jp_placeholder_deep r1 r2
                                    if rA.IsSome || rR.IsSome then Some b else None
                                | YRecord ra, YRecord rb ->
                                    let mutable changed = false
                                    for KeyValue((_, k), va) in ra do
                                        let vb_opt =
                                            rb |> Map.tryPick (fun (_, k') vb -> if k = k' then Some vb else None)
                                        match vb_opt with
                                        | Some vb ->
                                            if try_resolve_jp_placeholder_deep va vb |> Option.isSome then changed <- true
                                        | None -> ()
                                    if changed then Some b else None
                                | _ -> None

                        match try_resolve_jp_placeholder_deep type_tr type_fl with
                        | Some ty -> push_typedop_no_rewrite s (TyIf(cond,tr,fl)) ty
                        | None ->
                            match try_resolve_jp_placeholder_deep type_fl type_tr with
                            | Some ty -> push_typedop_no_rewrite s (TyIf(cond,tr,fl)) ty
                            | None ->
                                raise_type_error s <| sprintf "Types in branches of If do not match.\nGot: %s and %s" (show_ty type_tr) (show_ty type_fl)
                | cond -> raise_type_error s <| sprintf "Expected a bool in conditional.\nGot: %s" (show_data cond)
    

            let eq s a b =
                let inline op a b = a = b
                match a,b with
                | DLit a, DLit b ->
                    match a, b with
                    | LitInt8 a, LitInt8 b -> op a b |> LitBool |> DLit
                    | LitInt16 a, LitInt16 b -> op a b |> LitBool |> DLit
                    | LitInt32 a, LitInt32 b -> op a b |> LitBool |> DLit
                    | LitInt64 a, LitInt64 b -> op a b |> LitBool |> DLit
                    | LitUInt8 a, LitUInt8 b -> op a b |> LitBool |> DLit
                    | LitUInt16 a, LitUInt16 b -> op a b |> LitBool |> DLit
                    | LitUInt32 a, LitUInt32 b -> op a b |> LitBool |> DLit
                    | LitUInt64 a, LitUInt64 b -> op a b |> LitBool |> DLit
                    | LitFloat32 a, LitFloat32 b -> op a b |> LitBool |> DLit
                    | LitFloat64 a, LitFloat64 b -> op a b |> LitBool |> DLit
                    | LitString a, LitString b -> op a b |> LitBool |> DLit
                    | LitChar a, LitChar b -> op a b |> LitBool |> DLit
                    | LitBool a, LitBool b -> op a b |> LitBool |> DLit
                    | a, b -> raise_type_error s <| sprintf "The two literals must be equal in type.\nGot: %s and %s" (show_lit a) (show_lit b)
                | DSymbol a, DLit (LitString b)
                | DLit (LitString b), DSymbol a ->
                    op a b |> LitBool |> DLit
                | DV(L(a,a_ty)), DV(L(b,_)) when a = b && is_non_float_primitive a_ty -> LitBool true |> DLit
                | a, b ->
                    let a_ty, b_ty = data_to_ty s a, data_to_ty s b
                    if ty_eq_allow_jp_placeholders a_ty b_ty then
                        match a, b with
                        | DLit (LitBool true), x | x, DLit (LitBool true) -> x
                        | _ ->
                            let prim_ty_opt =
                                if is_primitive a_ty then Some a_ty
                                elif is_primitive b_ty then Some b_ty
                                else None
                            match prim_ty_opt with
                            | Some _ -> push_binop s EQ (a,b) (YPrim BoolT)
                            | None ->
                                raise_type_error s <| sprintf "The type of the two arguments needs to be a primitive type.\nGot: %s and %s" (show_ty a_ty) (show_ty b_ty)
                    else
                        raise_type_error s <| sprintf "The two sides need to have the same primitive types.\nGot: %s and %s." (show_ty a_ty) (show_ty b_ty)
            let default_lit s (a : string) b =
                let inline f string_to_val val_to_lit val_dsc =
                    match string_to_val a with
                    | true, x -> val_to_lit x
                    | false, _ -> raise_type_error s <| sprintf "Cannot parse the literal as: %s" val_dsc
                match b with
                | YPrim Float32T -> f Single.TryParse LitFloat32 "f32"
                | YPrim Float64T -> f Double.TryParse LitFloat64 "f64"
                | YPrim Int8T -> f SByte.TryParse LitInt8 "i8"
                | YPrim Int16T -> f Int16.TryParse LitInt16 "i16"
                | YPrim Int32T -> f Int32.TryParse LitInt32 "i32"
                | YPrim Int64T -> f Int64.TryParse LitInt64 "i64"
                | YPrim UInt8T -> f Byte.TryParse LitUInt8 "u8"
                | YPrim UInt16T -> f UInt16.TryParse LitUInt16 "u16"
                | YPrim UInt32T -> f UInt32.TryParse LitUInt32 "u32"
                | YPrim UInt64T -> f UInt64.TryParse LitUInt64 "u64"
                | b -> raise_type_error s <| sprintf "Expected a numberic type (f32,f64,i8,i16,i32,i64,u8,u16,u32,u64) as the type of literal.\nGot: %s" (show_ty b)
    

            let lit_test s a bind on_succ on_fail =
                let b = v s bind
                match a, b with
                | LitString a', DSymbol b' ->
                    if a' = b' then term s on_succ else term s on_fail
                | _ ->
                    if lit_to_ty a = data_to_ty s b then if_ s (eq s (DLit a) b) on_succ on_fail
                    else term s on_fail
    

            let inline nan_guardf32 x = if Single.IsNaN x then raise_type_error s "A 32-bit floating point operation resulting in a nan detected at compile time." else x
            let inline nan_guardf64 x = if Double.IsNaN x then raise_type_error s "A 64-bit floating point operation resulting in a nan detected at compile time." else x
    

            let eforall (free_vars : Scope,i,body) =
                assert (free_vars.ty.free_vars.Length = i)
                DForall(body,HopacExtensions.A.map (v s) free_vars.term.free_vars,HopacExtensions.A.map (vt s) free_vars.ty.free_vars,free_vars.term.stack_size,free_vars.ty.stack_size)
    

            let efun (free_vars : Scope,i,body,annot) =
                assert (free_vars.term.free_vars.Length = i)
                DFunction(body,annot,HopacExtensions.A.map (v s) free_vars.term.free_vars,HopacExtensions.A.map (vt s) free_vars.ty.free_vars,free_vars.term.stack_size,free_vars.ty.stack_size)
    

            let enominal (r,a,b) =
                let a = term s a
                let b = ty s b
                let tryCoerceBareSymbolToExpectedUnion expectedTy value =
                    // ALPHA990: Runtime 989 reached a real semantic type error at
                    // `Debug |> Some`: the outer Option constructor already knows
                    // that `Some` expects trace_level, but the inner bare union
                    // case can still arrive as DSymbol("Debug") and therefore
                    // type as string.  When the expected payload is a known union
                    // and the symbol is one of its cases, reify the symbol as that
                    // union case instead of fabricating success elsewhere.
                    let expectedTy' = jp_method_deref_rec_placeholder expectedTy
                    let expectedUnion =
                        match expectedTy' with
                        | YUnion caseUnion -> Some (expectedTy', caseUnion)
                        | YNominal _ | YApply _ ->
                            match nominal_type_apply s expectedTy' with
                            | YUnion caseUnion -> Some (expectedTy', caseUnion)
                            | _ -> None
                        | _ -> None
                    match value, expectedUnion with
                    | DSymbol caseName, Some (expectedNominalTy, caseUnion) ->
                        match Map.tryPick (fun (_, name') casePayloadTy -> if caseName = name' then Some casePayloadTy else None) (union_cases caseUnion) with
                        | Some casePayloadTy ->
                            let casePayload = ty_to_data s casePayloadTy
                            Some (DNominal(DUnion(DPair(DSymbol caseName, casePayload), caseUnion), expectedNominalTy))
                        | None -> None
                    | _ -> None
                match nominal_type_apply s b with
                | YUnion h ->
                    match a with
                    | DPair(DSymbol k, v) ->
                        let v_ty = data_to_ty s v
                        match Map.tryPick (fun (_, name') v -> if k = name' then Some v else None) (union_cases h) with
                        | Some v_ty' when ty_eq_allow_jp_placeholders v_ty v_ty' -> DNominal(DUnion(a,h),b)
                        | Some v_ty' ->
                            match tryCoerceBareSymbolToExpectedUnion v_ty' v with
                            | Some v' when ty_eq_allow_jp_placeholders (data_to_ty s v') v_ty' -> DNominal(DUnion(DPair(DSymbol k, v'),h),b)
                            | _ -> raise_type_error s <| sprintf "For key %s, The type of the value does not match the union case.\nGot: %s\nGot(deref): %s\nExpected: %s\nExpected(deref): %s" k (show_ty v_ty) (show_ty (jp_method_deref_rec_placeholder v_ty)) (show_ty v_ty') (show_ty (jp_method_deref_rec_placeholder v_ty'))
                        | None -> raise_type_error s <| sprintf "The union does not have key %s.\nGot: %s" k (show_ty b)
                    | _ -> raise_type_error s <| sprintf "Expected key/value pair.\nGot: %s" (show_data a)
                | b' ->
                    let a =
                        match a with
                        | DRecord a ->
                            a
                            |> Seq.map (fun (KeyValue ((i, k), v)) ->
                                k, ((i, k), v)
                            )
                            |> Seq.distinctBy fst
                            |> Seq.map snd
                            |> Map.ofSeq
                            |> DRecord
                        | _ -> a
    

                    let a_ty = data_to_ty s a
    

                    if ty_eq_allow_jp_placeholders a_ty b' then DNominal(a,b)
                    else raise_type_error s <| sprintf "Type error in nominal constructor.\nGot: %s\nExpected: %s" (show_ty a_ty) (show_ty b')
    

            let ty_union s x =
                let x = ty s x
                match nominal_type_apply s x with
                | YUnion x -> x
                | _ -> raise_type_error s <| sprintf "Expected an union.\nGot: %s" (show_ty x)
    

            let ty_record s x =
                match ty s x with
                | YRecord l -> l
                | x -> raise_type_error s <| sprintf "Expected a type record.\nGot: %s" (show_ty x)
    

            let to_i32 x =
                try
                    match x with
                    | LitUInt8 x -> Convert.ToInt32(x)
                    | LitUInt16 x -> Convert.ToInt32(x)
                    | LitUInt32 x -> Convert.ToInt32(x)
                    | LitUInt64 x -> Convert.ToInt32(x)
                    | LitInt8 x -> Convert.ToInt32(x)
                    | LitInt16 x -> Convert.ToInt32(x)
                    | LitInt32 x -> Convert.ToInt32(x)
                    | LitInt64 x -> Convert.ToInt32(x)
                    | x -> raise_type_error s <| sprintf "Expected an int convertible to an i32.\nGot: %s" (show_lit x)
                with :? System.OverflowException -> raise_type_error s <| sprintf "The literal cannot be converted to an i32 as it is either too small or to big.\nGot: %s" (show_lit x)
    

            let record2 (a,b) (a',b') = DRecord(Map.empty |> Map.add a b |> Map.add a' b')
            let record3 (a,b) (a',b') (a'',b'') = DRecord(Map.empty |> Map.add a b |> Map.add a' b' |> Map.add a'' b'')

            EvalReplayValueStore.installTypeAwareOpReplayAfterDefinition (fun sObj opName argNodeIds ->
                let s = unbox<LangEnv> sObj
                let termAt i =
                    if i >= 0 && i < argNodeIds.Length then EvalReplayValueStore.tryTerm argNodeIds.[i]
                    else None
                let typeAt i =
                    if i >= 0 && i < argNodeIds.Length then EvalReplayValueStore.tryType argNodeIds.[i]
                    else None
                let rec typeLitToData t =
                    match t with
                    | YLit a -> Choice1Of2 (DLit a)
                    | YSymbol a -> Choice1Of2 (DSymbol a)
                    | YNominal _ | YApply _ as a -> typeLitToData (nominal_type_apply s a)
                    | a -> Choice2Of2 (sprintf "type_lit_expected_lit_or_symbol:%s" (show_ty a))
                let recordTyAt i =
                    match typeAt i with
                    | Some (YRecord fields) -> Choice1Of2 fields
                    | Some other -> Choice2Of2 (sprintf "expected_record_type:%s" (show_ty other))
                    | None -> Choice2Of2 "type_arg_missing"
                let compactOpExn (ex: exn) =
                    let msg =
                        if isNull ex.Message then ""
                        else ex.Message.Replace("\r"," ").Replace("\n"," ").Replace("\t"," ")
                    let msg = if msg.Length > 180 then msg.Substring(0, 180) + "..." else msg
                    ex.GetType().Name + ":" + msg
                let rec typeAwareReplayUnwrapNominalData = function
                    | DNominal(d, _) -> typeAwareReplayUnwrapNominalData d
                    | d -> d
                let typeAwareReplayTryCompareLiteral (opName: string) a b =
                    let out x = Some (DLit (LitBool x))
                    match opName, a, b with
                    | "EQ", LitInt8 a, LitInt8 b -> out (a = b)
                    | "NEQ", LitInt8 a, LitInt8 b -> out (a <> b)
                    | "EQ", LitInt16 a, LitInt16 b -> out (a = b)
                    | "NEQ", LitInt16 a, LitInt16 b -> out (a <> b)
                    | "EQ", LitInt32 a, LitInt32 b -> out (a = b)
                    | "NEQ", LitInt32 a, LitInt32 b -> out (a <> b)
                    | "EQ", LitInt64 a, LitInt64 b -> out (a = b)
                    | "NEQ", LitInt64 a, LitInt64 b -> out (a <> b)
                    | "EQ", LitUInt8 a, LitUInt8 b -> out (a = b)
                    | "NEQ", LitUInt8 a, LitUInt8 b -> out (a <> b)
                    | "EQ", LitUInt16 a, LitUInt16 b -> out (a = b)
                    | "NEQ", LitUInt16 a, LitUInt16 b -> out (a <> b)
                    | "EQ", LitUInt32 a, LitUInt32 b -> out (a = b)
                    | "NEQ", LitUInt32 a, LitUInt32 b -> out (a <> b)
                    | "EQ", LitUInt64 a, LitUInt64 b -> out (a = b)
                    | "NEQ", LitUInt64 a, LitUInt64 b -> out (a <> b)
                    | "EQ", LitFloat32 a, LitFloat32 b -> out (a = b)
                    | "NEQ", LitFloat32 a, LitFloat32 b -> out (a <> b)
                    | "EQ", LitFloat64 a, LitFloat64 b -> out (a = b)
                    | "NEQ", LitFloat64 a, LitFloat64 b -> out (a <> b)
                    | "EQ", LitChar a, LitChar b -> out (a = b)
                    | "NEQ", LitChar a, LitChar b -> out (a <> b)
                    | "EQ", LitString a, LitString b -> out (a = b)
                    | "NEQ", LitString a, LitString b -> out (a <> b)
                    | "EQ", LitBool a, LitBool b -> out (a = b)
                    | "NEQ", LitBool a, LitBool b -> out (a <> b)
                    | "LT", LitInt8 a, LitInt8 b -> out (a < b)
                    | "LTE", LitInt8 a, LitInt8 b -> out (a <= b)
                    | "GT", LitInt8 a, LitInt8 b -> out (a > b)
                    | "GTE", LitInt8 a, LitInt8 b -> out (a >= b)
                    | "LT", LitInt16 a, LitInt16 b -> out (a < b)
                    | "LTE", LitInt16 a, LitInt16 b -> out (a <= b)
                    | "GT", LitInt16 a, LitInt16 b -> out (a > b)
                    | "GTE", LitInt16 a, LitInt16 b -> out (a >= b)
                    | "LT", LitInt32 a, LitInt32 b -> out (a < b)
                    | "LTE", LitInt32 a, LitInt32 b -> out (a <= b)
                    | "GT", LitInt32 a, LitInt32 b -> out (a > b)
                    | "GTE", LitInt32 a, LitInt32 b -> out (a >= b)
                    | "LT", LitInt64 a, LitInt64 b -> out (a < b)
                    | "LTE", LitInt64 a, LitInt64 b -> out (a <= b)
                    | "GT", LitInt64 a, LitInt64 b -> out (a > b)
                    | "GTE", LitInt64 a, LitInt64 b -> out (a >= b)
                    | "LT", LitUInt8 a, LitUInt8 b -> out (a < b)
                    | "LTE", LitUInt8 a, LitUInt8 b -> out (a <= b)
                    | "GT", LitUInt8 a, LitUInt8 b -> out (a > b)
                    | "GTE", LitUInt8 a, LitUInt8 b -> out (a >= b)
                    | "LT", LitUInt16 a, LitUInt16 b -> out (a < b)
                    | "LTE", LitUInt16 a, LitUInt16 b -> out (a <= b)
                    | "GT", LitUInt16 a, LitUInt16 b -> out (a > b)
                    | "GTE", LitUInt16 a, LitUInt16 b -> out (a >= b)
                    | "LT", LitUInt32 a, LitUInt32 b -> out (a < b)
                    | "LTE", LitUInt32 a, LitUInt32 b -> out (a <= b)
                    | "GT", LitUInt32 a, LitUInt32 b -> out (a > b)
                    | "GTE", LitUInt32 a, LitUInt32 b -> out (a >= b)
                    | "LT", LitUInt64 a, LitUInt64 b -> out (a < b)
                    | "LTE", LitUInt64 a, LitUInt64 b -> out (a <= b)
                    | "GT", LitUInt64 a, LitUInt64 b -> out (a > b)
                    | "GTE", LitUInt64 a, LitUInt64 b -> out (a >= b)
                    | "LT", LitFloat32 a, LitFloat32 b -> out (a < b)
                    | "LTE", LitFloat32 a, LitFloat32 b -> out (a <= b)
                    | "GT", LitFloat32 a, LitFloat32 b -> out (a > b)
                    | "GTE", LitFloat32 a, LitFloat32 b -> out (a >= b)
                    | "LT", LitFloat64 a, LitFloat64 b -> out (a < b)
                    | "LTE", LitFloat64 a, LitFloat64 b -> out (a <= b)
                    | "GT", LitFloat64 a, LitFloat64 b -> out (a > b)
                    | "GTE", LitFloat64 a, LitFloat64 b -> out (a >= b)
                    | "LT", LitChar a, LitChar b -> out (a < b)
                    | "LTE", LitChar a, LitChar b -> out (a <= b)
                    | "GT", LitChar a, LitChar b -> out (a > b)
                    | "GTE", LitChar a, LitChar b -> out (a >= b)
                    | "LT", LitString a, LitString b -> out (a < b)
                    | "LTE", LitString a, LitString b -> out (a <= b)
                    | "GT", LitString a, LitString b -> out (a > b)
                    | "GTE", LitString a, LitString b -> out (a >= b)
                    | "LT", LitBool a, LitBool b -> out (a < b)
                    | "LTE", LitBool a, LitBool b -> out (a <= b)
                    | "GT", LitBool a, LitBool b -> out (a > b)
                    | "GTE", LitBool a, LitBool b -> out (a >= b)
                    | _ -> None
                let replayStringIndex () =
                    match termAt 0, termAt 1 with
                    | Some (DLit (LitString str)), Some (DLit idxLit) ->
                        try
                            let idx = to_i32 idxLit
                            if 0 <= idx && idx < str.Length then
                                let value = DLit (LitChar str.[idx])
                                DiagJson.emit (
                                    sprintf "{\"kind\":\"eval_worklist_type_aware_string_index_literal_replay_resolved\",\"context_node_id\":%d,\"index\":%d,\"string_len\":%d,\"single_flight\":1,\"next\":\"term_op_pure_value_resolved\"}"
                                        -1 idx str.Length)
                                Choice1Of2 value
                            else Choice2Of2 (sprintf "string_index_literal_oob:index=%d:length=%d" idx str.Length)
                        with ex -> Choice2Of2 ("string_index_literal_replay_failed:" + compactOpExn ex)
                    | Some a, Some b ->
                        try
                            let at, bt = data_to_ty s a, data_to_ty s b
                            if is_string_allow_jp_placeholders at && is_any_int_allow_jp_placeholders bt then
                                let value = push_binop s StringIndex (a, b) (YPrim CharT)
                                DiagJson.emit (
                                    sprintf "{\"kind\":\"eval_worklist_type_aware_string_index_replay_resolved\",\"context_node_id\":%d,\"lhs_ty\":%s,\"rhs_ty\":%s,\"single_flight\":1,\"next\":\"term_op_pure_value_resolved\"}"
                                        -1 (DiagJson.esc (show_ty at)) (DiagJson.esc (show_ty bt)))
                                Choice1Of2 value
                            else Choice2Of2 (sprintf "string_index_expected_string_int:%s:%s" (show_ty at) (show_ty bt))
                        with ex -> Choice2Of2 ("string_index_replay_failed:" + compactOpExn ex)
                    | None, _ -> Choice2Of2 "string_index_string_arg_missing"
                    | _, None -> Choice2Of2 "string_index_index_arg_missing"

                let replayBackendSwitch (unsafeMode: bool) =
                    match termAt 0 with
                    | Some (DRecord l) ->
                        if unsafeMode then
                            try
                                match map_try_find_by_string s.backend.node l with
                                | Some b -> Choice1Of2 (apply s (b, DB))
                                | None -> Choice2Of2 (sprintf "backend_switch_backend_missing:%s" s.backend.node)
                            with ex -> Choice2Of2 ("unsafe_backend_switch_apply_failed:" + compactOpExn ex)
                        else
                            try
                                let mutable t = None
                                let mutable d = None
                                let normalize_backend_switch_ty x =
                                    jp_method_deref_rec_placeholder x
                                let validate_type t' =
                                    let t' = normalize_backend_switch_ty t'
                                    match t with
                                    | Some t0 ->
                                        let t0 = normalize_backend_switch_ty t0
                                        if not (ty_eq_allow_jp_placeholders t0 t') then
                                            raise_type_error s $"The backend switch needs to have the same type for all of its branches.\nGot: {show_ty t'}\nExpected: {show_ty t0}"
                                    | None -> t <- Some t'
                                if lock backend_switch_lock (fun () -> backend_switch_validate_all.Value) = false then
                                    match map_try_find_by_string s.backend.node l with
                                    | Some b ->
                                        let d' = apply s (b, DB)
                                        validate_type (data_to_ty s d')
                                        d <- Some d'
                                    | None -> ()
                                else
                                    l |> Map.iter (fun (_,backend) b ->
                                        if backend = s.backend.node then
                                            let d' = apply s (b, DB)
                                            validate_type (data_to_ty s d')
                                            d <- Some d'
                                        else
                                            let stackOk =
                                                try
                                                    System.Runtime.CompilerServices.RuntimeHelpers.EnsureSufficientExecutionStack()
                                                    true
                                                with :? System.InsufficientExecutionStackException ->
                                                    false
                                            let gen0 = CacheGeneration.current ()
                                            let doValidation () =
                                                let old = lock backend_switch_lock (fun () -> backend_switch_validate_all.Value)
                                                lock backend_switch_lock (fun () -> backend_switch_validate_all.Value <- false)
                                                try
                                                    let s = {s with seq=ResizeArray(); cse=Dictionary HashIdentity.Structural :: s.cse; backend=lock backend_strings_lock (fun () -> backend_strings.Add backend)}
                                                    let d' = apply s (b, DB)
                                                    if CacheGeneration.isStale gen0 then
                                                        DiagSidecar.emit (sprintf "BACKEND_SWITCH_REPLAY: Generation changed during backend_switch replay validation for '%s' - skipping type check" backend)
                                                    else
                                                        validate_type (data_to_ty s d')
                                                finally
                                                    lock backend_switch_lock (fun () -> backend_switch_validate_all.Value <- old)
                                            if CacheGeneration.isStale gen0 then
                                                DiagSidecar.emit (sprintf "BACKEND_SWITCH_REPLAY: Skipping backend_switch replay validation for '%s' (generation stale)" backend)
                                            elif stackOk then
                                                doValidation ()
                                            else
                                                match BigStack.tryRun "backend_switch_replay_validate" doValidation with
                                                | Some () -> ()
                                                | None -> DiagSidecar.emit (sprintf "BACKEND_SWITCH_REPLAY: Skipping backend_switch replay validation for '%s' (stack exhausted, BigStack unavailable)" backend)
                                        )
                                match d with
                                | Some cur -> Choice1Of2 cur
                                | None -> Choice2Of2 (sprintf "backend_switch_backend_missing:%s" s.backend.node)
                            with ex -> Choice2Of2 ("backend_switch_apply_failed:" + compactOpExn ex)
                    | Some other -> Choice2Of2 (sprintf "backend_switch_expected_record:%s" (show_data other))
                    | None -> Choice2Of2 "backend_switch_arg_missing"
                match opName with
                | "StringIndex" -> replayStringIndex ()
                | "BackendSwitch" -> replayBackendSwitch false
                | "UnsafeBackendSwitch" -> replayBackendSwitch true
                | "Global" ->
                    match termAt 0 with
                    | Some (DLit (LitString text) as a) ->
                        DiagJson.emit (
                            sprintf "{\"kind\":\"eval_worklist_global_replay_resolved\",\"op\":\"Global\",\"text_len\":%d,\"same_backend\":%b,\"single_flight\":1,\"next\":\"term_op_pure_value_resolved\"}"
                                text.Length (s.backend.node = env.backend))
                        if s.backend.node = env.backend then
                            global' text |> ignore
                        Choice1Of2 (push_op_no_rewrite s Global a YB)
                    | Some other -> Choice2Of2 (sprintf "global_expected_string_lit:%s" (show_data other))
                    | None -> Choice2Of2 "global_arg_missing"
                | "LayoutIndex" ->
                    match termAt 0 with
                    | Some (DV(L(_,YLayout(ty,layout)) as tyv)) ->
                        DiagJson.emit (
                            sprintf "{\"kind\":\"eval_worklist_layout_index_replay_resolved\",\"op\":\"LayoutIndex\",\"context_node_id\":%d,\"layout\":%s,\"single_flight\":1,\"next\":\"term_op_pure_value_resolved\"}"
                                -1 (DiagJson.esc (sprintf "%A" layout)))
                        match layout with
                        | StackMutable | HeapMutable -> Choice1Of2 (push_typedop_no_rewrite s (TyLayoutIndexAll tyv) ty)
                        | Heap ->
                            match ty with
                            | YRecord l -> Choice1Of2 (DRecord(Map.map (fun (_,b) ty -> push_typedop s (TyLayoutIndexByKey(tyv,b)) ty) l))
                            | _ -> Choice1Of2 (push_typedop s (TyLayoutIndexAll tyv) ty)
                    | Some other -> Choice2Of2 (sprintf "layout_index_expected_layout:%s" (show_data other))
                    | None -> Choice2Of2 "layout_index_arg_missing"
                | "TypeToVar" ->
                    match typeAt 0 with
                    | Some t -> Choice1Of2 (push_typedop_no_rewrite s (TyOp(TypeToVar,[])) t)
                    | None -> Choice2Of2 "type_to_var_type_missing"
                | "TypeToSymbol" ->
                    match typeAt 0 with
                    | Some (YSymbol a) -> Choice1Of2 (DSymbol a)
                    | Some a -> Choice2Of2 (sprintf "type_to_symbol_expected_symbol:%s" (show_ty a))
                    | None -> Choice2Of2 "type_to_symbol_type_missing"
                | "TypeLitToLit" ->
                    match typeAt 0 with
                    | Some t -> typeLitToData t
                    | None -> Choice2Of2 "type_lit_to_lit_type_missing"
                | "RecordTypeLength" ->
                    match recordTyAt 0 with
                    | Choice1Of2 fields -> Choice1Of2 (Map.count fields |> LitInt32 |> DLit)
                    | Choice2Of2 detail -> Choice2Of2 detail
                | "RecordTypeTryFind" ->
                    match recordTyAt 0, termAt 1 with
                    | Choice1Of2 fields, Some (DSymbol key) ->
                        match fields |> Map.tryPick (fun (_, k) v -> if k = key then Some v else None) with
                        | Some tyValue ->
                            match termAt 2, termAt 3 with
                            | Some onSucc, _ -> Choice1Of2 (type_apply s onSucc tyValue)
                            | _, Some onFail -> Choice1Of2 (apply s (onFail, DB))
                            | _ -> Choice2Of2 "record_type_try_find_branch_missing"
                        | None ->
                            match termAt 3 with
                            | Some onFail -> Choice1Of2 (apply s (onFail, DB))
                            | None -> Choice2Of2 "record_type_try_find_fail_missing"
                    | Choice2Of2 detail, _ -> Choice2Of2 detail
                    | _, Some other -> Choice2Of2 (sprintf "record_type_try_find_expected_symbol:%s" (show_data other))
                    | _, None -> Choice2Of2 "record_type_try_find_key_missing"
                | "EQ" | "NEQ" | "LT" | "LTE" | "GT" | "GTE" ->
                    match termAt 0, termAt 1 with
                    | Some a, Some b ->
                        match typeAwareReplayUnwrapNominalData a, typeAwareReplayUnwrapNominalData b with
                        | DLit la, DLit lb ->
                            match typeAwareReplayTryCompareLiteral opName la lb with
                            | Some value ->
                                DiagJson.emit (
                                    sprintf "{\"kind\":\"eval_worklist_type_aware_literal_compare_replay_resolved\",\"op\":%s,\"context_node_id\":%d,\"lhs\":%s,\"rhs\":%s,\"single_flight\":1,\"next\":\"term_op_pure_value_resolved\"}"
                                        (DiagJson.esc opName) -1 (DiagJson.esc (show_data a)) (DiagJson.esc (show_data b)))
                                Choice1Of2 value
                            | None -> Choice2Of2 (sprintf "type_aware_compare_literal_mismatch:%s:%s:%s" opName (show_lit la) (show_lit lb))
                        | _ ->
                            try
                                let aTy, bTy = data_to_ty s a, data_to_ty s b
                                let primTy = if is_primitive aTy then aTy elif is_primitive bTy then bTy else aTy
                                if ty_eq_allow_jp_placeholders aTy bTy && is_primitive primTy then
                                    let opCase =
                                        match opName with
                                        | "EQ" -> EQ
                                        | "NEQ" -> NEQ
                                        | "LT" -> LT
                                        | "LTE" -> LTE
                                        | "GT" -> GT
                                        | _ -> GTE
                                    let value = push_binop s opCase (a, b) (YPrim BoolT)
                                    DiagJson.emit (
                                        sprintf "{\"kind\":\"eval_worklist_type_aware_primitive_compare_replay_resolved\",\"op\":%s,\"context_node_id\":%d,\"lhs_ty\":%s,\"rhs_ty\":%s,\"single_flight\":1,\"next\":\"term_op_pure_value_resolved\"}"
                                            (DiagJson.esc opName) -1 (DiagJson.esc (show_ty aTy)) (DiagJson.esc (show_ty bTy)))
                                    Choice1Of2 value
                                else Choice2Of2 (sprintf "type_aware_compare_expected_same_primitive:%s:%s:%s" opName (show_ty aTy) (show_ty bTy))
                            with ex -> Choice2Of2 ("type_aware_compare_replay_failed:" + opName + ":" + compactOpExn ex)
                    | None, _ -> Choice2Of2 ("type_aware_compare_lhs_missing:" + opName)
                    | _, None -> Choice2Of2 ("type_aware_compare_rhs_missing:" + opName)
                | _ -> Choice2Of2 ("type_aware_op_unhandled:" + opName))

            EvalReplayValueStore.installTypeAwareOpReplayScheduleAfterDefinition (fun sObj contextNodeId opName argNodeIds ->
                let s = unbox<LangEnv> sObj
                let termAt i =
                    if i >= 0 && i < argNodeIds.Length then EvalReplayValueStore.tryTerm argNodeIds.[i]
                    else None
                let typeAt i =
                    if i >= 0 && i < argNodeIds.Length then EvalReplayValueStore.tryType argNodeIds.[i]
                    else None
                let recordTyAt i =
                    match typeAt i with
                    | Some (YRecord fields) -> Choice1Of2 fields
                    | Some other -> Choice2Of2 (sprintf "expected_record_type:%s" (show_ty other))
                    | None -> Choice2Of2 "type_arg_missing"
                let compactOpExn (ex: exn) =
                    let msg =
                        if isNull ex.Message then ""
                        else ex.Message.Replace("\r"," ").Replace("\n"," ").Replace("\t"," ")
                    let msg = if msg.Length > 180 then msg.Substring(0, 180) + "..." else msg
                    ex.GetType().Name + ":" + msg
                let rec typeAwareScheduleUnwrapNominalData = function
                    | DNominal(d, _) -> typeAwareScheduleUnwrapNominalData d
                    | d -> d
                let typeAwareScheduleTryCompareLiteral (opName: string) a b =
                    let out x = Some (DLit (LitBool x))
                    match opName, a, b with
                    | "EQ", LitInt8 a, LitInt8 b -> out (a = b)
                    | "NEQ", LitInt8 a, LitInt8 b -> out (a <> b)
                    | "EQ", LitInt16 a, LitInt16 b -> out (a = b)
                    | "NEQ", LitInt16 a, LitInt16 b -> out (a <> b)
                    | "EQ", LitInt32 a, LitInt32 b -> out (a = b)
                    | "NEQ", LitInt32 a, LitInt32 b -> out (a <> b)
                    | "EQ", LitInt64 a, LitInt64 b -> out (a = b)
                    | "NEQ", LitInt64 a, LitInt64 b -> out (a <> b)
                    | "EQ", LitUInt8 a, LitUInt8 b -> out (a = b)
                    | "NEQ", LitUInt8 a, LitUInt8 b -> out (a <> b)
                    | "EQ", LitUInt16 a, LitUInt16 b -> out (a = b)
                    | "NEQ", LitUInt16 a, LitUInt16 b -> out (a <> b)
                    | "EQ", LitUInt32 a, LitUInt32 b -> out (a = b)
                    | "NEQ", LitUInt32 a, LitUInt32 b -> out (a <> b)
                    | "EQ", LitUInt64 a, LitUInt64 b -> out (a = b)
                    | "NEQ", LitUInt64 a, LitUInt64 b -> out (a <> b)
                    | "EQ", LitFloat32 a, LitFloat32 b -> out (a = b)
                    | "NEQ", LitFloat32 a, LitFloat32 b -> out (a <> b)
                    | "EQ", LitFloat64 a, LitFloat64 b -> out (a = b)
                    | "NEQ", LitFloat64 a, LitFloat64 b -> out (a <> b)
                    | "EQ", LitChar a, LitChar b -> out (a = b)
                    | "NEQ", LitChar a, LitChar b -> out (a <> b)
                    | "EQ", LitString a, LitString b -> out (a = b)
                    | "NEQ", LitString a, LitString b -> out (a <> b)
                    | "EQ", LitBool a, LitBool b -> out (a = b)
                    | "NEQ", LitBool a, LitBool b -> out (a <> b)
                    | "LT", LitInt8 a, LitInt8 b -> out (a < b)
                    | "LTE", LitInt8 a, LitInt8 b -> out (a <= b)
                    | "GT", LitInt8 a, LitInt8 b -> out (a > b)
                    | "GTE", LitInt8 a, LitInt8 b -> out (a >= b)
                    | "LT", LitInt16 a, LitInt16 b -> out (a < b)
                    | "LTE", LitInt16 a, LitInt16 b -> out (a <= b)
                    | "GT", LitInt16 a, LitInt16 b -> out (a > b)
                    | "GTE", LitInt16 a, LitInt16 b -> out (a >= b)
                    | "LT", LitInt32 a, LitInt32 b -> out (a < b)
                    | "LTE", LitInt32 a, LitInt32 b -> out (a <= b)
                    | "GT", LitInt32 a, LitInt32 b -> out (a > b)
                    | "GTE", LitInt32 a, LitInt32 b -> out (a >= b)
                    | "LT", LitInt64 a, LitInt64 b -> out (a < b)
                    | "LTE", LitInt64 a, LitInt64 b -> out (a <= b)
                    | "GT", LitInt64 a, LitInt64 b -> out (a > b)
                    | "GTE", LitInt64 a, LitInt64 b -> out (a >= b)
                    | "LT", LitUInt8 a, LitUInt8 b -> out (a < b)
                    | "LTE", LitUInt8 a, LitUInt8 b -> out (a <= b)
                    | "GT", LitUInt8 a, LitUInt8 b -> out (a > b)
                    | "GTE", LitUInt8 a, LitUInt8 b -> out (a >= b)
                    | "LT", LitUInt16 a, LitUInt16 b -> out (a < b)
                    | "LTE", LitUInt16 a, LitUInt16 b -> out (a <= b)
                    | "GT", LitUInt16 a, LitUInt16 b -> out (a > b)
                    | "GTE", LitUInt16 a, LitUInt16 b -> out (a >= b)
                    | "LT", LitUInt32 a, LitUInt32 b -> out (a < b)
                    | "LTE", LitUInt32 a, LitUInt32 b -> out (a <= b)
                    | "GT", LitUInt32 a, LitUInt32 b -> out (a > b)
                    | "GTE", LitUInt32 a, LitUInt32 b -> out (a >= b)
                    | "LT", LitUInt64 a, LitUInt64 b -> out (a < b)
                    | "LTE", LitUInt64 a, LitUInt64 b -> out (a <= b)
                    | "GT", LitUInt64 a, LitUInt64 b -> out (a > b)
                    | "GTE", LitUInt64 a, LitUInt64 b -> out (a >= b)
                    | "LT", LitFloat32 a, LitFloat32 b -> out (a < b)
                    | "LTE", LitFloat32 a, LitFloat32 b -> out (a <= b)
                    | "GT", LitFloat32 a, LitFloat32 b -> out (a > b)
                    | "GTE", LitFloat32 a, LitFloat32 b -> out (a >= b)
                    | "LT", LitFloat64 a, LitFloat64 b -> out (a < b)
                    | "LTE", LitFloat64 a, LitFloat64 b -> out (a <= b)
                    | "GT", LitFloat64 a, LitFloat64 b -> out (a > b)
                    | "GTE", LitFloat64 a, LitFloat64 b -> out (a >= b)
                    | "LT", LitChar a, LitChar b -> out (a < b)
                    | "LTE", LitChar a, LitChar b -> out (a <= b)
                    | "GT", LitChar a, LitChar b -> out (a > b)
                    | "GTE", LitChar a, LitChar b -> out (a >= b)
                    | "LT", LitString a, LitString b -> out (a < b)
                    | "LTE", LitString a, LitString b -> out (a <= b)
                    | "GT", LitString a, LitString b -> out (a > b)
                    | "GTE", LitString a, LitString b -> out (a >= b)
                    | "LT", LitBool a, LitBool b -> out (a < b)
                    | "LTE", LitBool a, LitBool b -> out (a <= b)
                    | "GT", LitBool a, LitBool b -> out (a > b)
                    | "GTE", LitBool a, LitBool b -> out (a >= b)
                    | _ -> None
                let schedulePrimitiveCompare () =
                    match termAt 0, termAt 1 with
                    | Some a, Some b ->
                        match typeAwareScheduleUnwrapNominalData a, typeAwareScheduleUnwrapNominalData b with
                        | DLit la, DLit lb ->
                            match typeAwareScheduleTryCompareLiteral opName la lb with
                            | Some value ->
                                EvalReplayValueStore.putTermValue contextNodeId value
                                DiagJson.emit (
                                    sprintf "{\"kind\":\"eval_worklist_type_aware_literal_compare_replay_resolved\",\"op\":%s,\"context_node_id\":%d,\"lhs\":%s,\"rhs\":%s,\"single_flight\":1,\"next\":\"term_op_pure_value_resolved\"}"
                                        (DiagJson.esc opName) contextNodeId (DiagJson.esc (show_data a)) (DiagJson.esc (show_data b)))
                                Choice1Of2 (contextNodeId, "EOp", "type_aware_literal_compare:" + opName)
                            | None -> Choice2Of2 (sprintf "type_aware_compare_literal_mismatch:%s:%s:%s" opName (show_lit la) (show_lit lb))
                        | _ ->
                            try
                                let aTy, bTy = data_to_ty s a, data_to_ty s b
                                let primTy = if is_primitive aTy then aTy elif is_primitive bTy then bTy else aTy
                                if ty_eq_allow_jp_placeholders aTy bTy && is_primitive primTy then
                                    let opCase =
                                        match opName with
                                        | "EQ" -> EQ
                                        | "NEQ" -> NEQ
                                        | "LT" -> LT
                                        | "LTE" -> LTE
                                        | "GT" -> GT
                                        | _ -> GTE
                                    let value = push_binop s opCase (a, b) (YPrim BoolT)
                                    EvalReplayValueStore.putTermValue contextNodeId value
                                    DiagJson.emit (
                                        sprintf "{\"kind\":\"eval_worklist_type_aware_primitive_compare_replay_resolved\",\"op\":%s,\"context_node_id\":%d,\"lhs_ty\":%s,\"rhs_ty\":%s,\"single_flight\":1,\"next\":\"term_op_pure_value_resolved\"}"
                                            (DiagJson.esc opName) contextNodeId (DiagJson.esc (show_ty aTy)) (DiagJson.esc (show_ty bTy)))
                                    Choice1Of2 (contextNodeId, "EOp", "type_aware_primitive_compare:" + opName)
                                else Choice2Of2 (sprintf "type_aware_compare_expected_same_primitive:%s:%s:%s" opName (show_ty aTy) (show_ty bTy))
                            with ex -> Choice2Of2 ("type_aware_compare_schedule_failed:" + opName + ":" + compactOpExn ex)
                    | None, _ -> Choice2Of2 ("type_aware_compare_lhs_missing:" + opName)
                    | _, None -> Choice2Of2 ("type_aware_compare_rhs_missing:" + opName)
                let scheduleTypeEq () =
                    match typeAt 0, typeAt 1 with
                    | Some aTy, Some bTy ->
                        let result = (aTy = bTy)
                        let value = DLit (LitBool result)
                        EvalReplayValueStore.putTermValue contextNodeId value
                        DiagJson.emit (
                            sprintf "{\"kind\":\"eval_worklist_type_aware_type_eq_replay_resolved\",\"context_node_id\":%d,\"lhs_ty\":%s,\"rhs_ty\":%s,\"result\":%b,\"single_flight\":1,\"next\":\"term_op_pure_value_resolved\"}"
                                contextNodeId (DiagJson.esc (show_ty aTy)) (DiagJson.esc (show_ty bTy)) result)
                        Choice1Of2 (contextNodeId, "EOp", "type_aware_type_eq_resolved")
                    | None, _ -> Choice2Of2 "type_aware_type_eq_lhs_missing"
                    | _, None -> Choice2Of2 "type_aware_type_eq_rhs_missing"
                let scheduleDyn () =
                    match termAt 0 with
                    | Some arg ->
                        try
                            let value = dyn true s arg
                            EvalReplayValueStore.putTermValue contextNodeId value
                            DiagJson.emit (
                                sprintf "{\"kind\":\"eval_worklist_type_aware_dyn_replay_resolved\",\"context_node_id\":%d,\"arg\":%s,\"single_flight\":1,\"next\":\"term_op_pure_value_resolved\"}"
                                    contextNodeId (DiagJson.esc (show_data arg)))
                            Choice1Of2 (contextNodeId, "EOp", "type_aware_dyn_resolved")
                        with ex -> Choice2Of2 ("type_aware_dyn_schedule_failed:" + compactOpExn ex)
                    | None -> Choice2Of2 "type_aware_dyn_arg_missing"
                let scheduleStringIndex () =
                    match termAt 0, termAt 1 with
                    | Some (DLit (LitString str)), Some (DLit idxLit) ->
                        try
                            let idx = to_i32 idxLit
                            if 0 <= idx && idx < str.Length then
                                let value = DLit (LitChar str.[idx])
                                EvalReplayValueStore.putTermValue contextNodeId value
                                DiagJson.emit (
                                    sprintf "{\"kind\":\"eval_worklist_type_aware_string_index_literal_replay_resolved\",\"context_node_id\":%d,\"index\":%d,\"string_len\":%d,\"single_flight\":1,\"next\":\"term_op_pure_value_resolved\"}"
                                        contextNodeId idx str.Length)
                                Choice1Of2 (contextNodeId, "EOp", "string_index_literal")
                            else Choice2Of2 (sprintf "string_index_literal_oob:index=%d:length=%d" idx str.Length)
                        with ex -> Choice2Of2 ("string_index_literal_schedule_failed:" + compactOpExn ex)
                    | Some a, Some b ->
                        try
                            let at, bt = data_to_ty s a, data_to_ty s b
                            if is_string_allow_jp_placeholders at && is_any_int_allow_jp_placeholders bt then
                                let value = push_binop s StringIndex (a, b) (YPrim CharT)
                                EvalReplayValueStore.putTermValue contextNodeId value
                                DiagJson.emit (
                                    sprintf "{\"kind\":\"eval_worklist_type_aware_string_index_replay_resolved\",\"context_node_id\":%d,\"lhs_ty\":%s,\"rhs_ty\":%s,\"single_flight\":1,\"next\":\"term_op_pure_value_resolved\"}"
                                        contextNodeId (DiagJson.esc (show_ty at)) (DiagJson.esc (show_ty bt)))
                                Choice1Of2 (contextNodeId, "EOp", "string_index_typed")
                            else Choice2Of2 (sprintf "string_index_expected_string_int:%s:%s" (show_ty at) (show_ty bt))
                        with ex -> Choice2Of2 ("string_index_schedule_failed:" + compactOpExn ex)
                    | None, _ -> Choice2Of2 "string_index_string_arg_missing"
                    | _, None -> Choice2Of2 "string_index_index_arg_missing"

                let scheduleBackendSwitch () =
                    match termAt 0 with
                    | Some (DRecord l) ->
                        match map_try_find_by_string s.backend.node l with
                        | Some branch ->
                            try
                                match EvalReplayValueStore.tryScheduleApplyFunctionBodyReplayAt contextNodeId branch DB with
                                | Choice1Of2 (bodyNodeId, bodyShape) ->
                                    EvalReplayValueStore.putTypeAwareOpResultNode contextNodeId bodyNodeId
                                    EvalReplayValueStore.putParentContinuation bodyNodeId { parentKind = "term"; parentShape = "EOp"; parentNodeId = contextNodeId; role = "backend_switch_branch" }
                                    DiagJson.emit (
                                        sprintf "{\"kind\":\"eval_worklist_backend_switch_branch_replay_scheduled\",\"context_node_id\":%d,\"backend\":%s,\"body_node_id\":%d,\"body_shape\":%s,\"single_flight\":1,\"next\":\"schedule_backend_switch_branch_replay\"}"
                                            contextNodeId (DiagJson.esc s.backend.node) bodyNodeId (DiagJson.esc bodyShape))
                                    Choice1Of2 (bodyNodeId, bodyShape, sprintf "backend_switch_branch:%s" s.backend.node)
                                | Choice2Of2 detail -> Choice2Of2 ("backend_switch_branch_schedule_failed:" + detail)
                            with ex -> Choice2Of2 ("backend_switch_branch_schedule_exception:" + compactOpExn ex)
                        | None -> Choice2Of2 (sprintf "backend_switch_backend_missing:%s" s.backend.node)
                    | Some other -> Choice2Of2 (sprintf "backend_switch_expected_record:%s" (show_data other))
                    | None -> Choice2Of2 "backend_switch_arg_missing"
                let scheduleRecordMap () =
                    let tryScheduleRecordMapField mapper (fields: Map<int * string, Data>) orderTag =
                        if fields.IsEmpty then
                            EvalReplayValueStore.putTermValue contextNodeId (DRecord Map.empty)
                            DiagJson.emit (
                                sprintf "{\"kind\":\"eval_worklist_record_map_empty_replay_resolved\",\"context_node_id\":%d,\"order\":%s,\"single_flight\":1,\"next\":\"term_op_pure_value_resolved\"}"
                                    contextNodeId (DiagJson.esc orderTag))
                            Choice1Of2 (contextNodeId, "EOp", "record_map_empty:" + orderTag)
                        else
                            let mutable first : (int * string * Data) option = None
                            for KeyValue((i, k), v) in fields do
                                if first.IsNone then first <- Some (i, k, v)
                            match first with
                            | Some (_i, k, v) ->
                                let arg =
                                    DRecord(
                                        Map.empty
                                        |> Map.add (fields.Count, "key") (DSymbol k)
                                        |> Map.add ((fields.Count + 1), "value") v)
                                try
                                    match EvalReplayValueStore.tryScheduleApplyFunctionBodyReplayAt contextNodeId mapper arg with
                                    | Choice1Of2 (bodyNodeId, bodyShape) ->
                                        EvalReplayValueStore.putTypeAwareOpResultNode contextNodeId bodyNodeId
                                        EvalReplayValueStore.putParentContinuation bodyNodeId { parentKind = "term"; parentShape = "EOp"; parentNodeId = contextNodeId; role = "record_map_field" }
                                        DiagJson.emit (
                                            sprintf "{\"kind\":\"eval_worklist_record_map_field_replay_scheduled\",\"context_node_id\":%d,\"field\":%s,\"order\":%s,\"body_node_id\":%d,\"body_shape\":%s,\"single_flight\":1,\"next\":\"schedule_record_map_field_replay\"}"
                                                contextNodeId (DiagJson.esc k) (DiagJson.esc orderTag) bodyNodeId (DiagJson.esc bodyShape))
                                        Choice1Of2 (bodyNodeId, bodyShape, "record_map_field:" + orderTag + ":" + k)
                                    | Choice2Of2 detail -> Choice2Of2 ("record_map_field_schedule_failed:" + orderTag + ":" + detail)
                                with ex -> Choice2Of2 ("record_map_field_schedule_exception:" + orderTag + ":" + compactOpExn ex)
                            | None -> Choice2Of2 "record_map_fields_empty_after_nonempty"
                    match termAt 0, termAt 1 with
                    | Some mapper, Some (DRecord fields) ->
                        tryScheduleRecordMapField mapper fields "mapper_record"
                    | Some (DRecord fields), Some mapper ->
                        // ALPHA884: runtime 883 showed this RecordMap site with the
                        // record materialized in arg0 and the mapper function in arg1
                        // (the old branch surfaced record_map_expected_record:? -> ?).
                        // Preserve the same concrete field scheduling path, but accept
                        // the observed operand order instead of pinning a false op impl terminal.
                        DiagJson.emit (
                            sprintf "{\"kind\":\"eval_worklist_record_map_operand_order_repaired\",\"context_node_id\":%d,\"order\":\"record_mapper\",\"single_flight\":1,\"next\":\"schedule_record_map_field_replay\"}"
                                contextNodeId)
                        tryScheduleRecordMapField mapper fields "record_mapper"
                    | Some left, Some right ->
                        Choice2Of2 (sprintf "record_map_expected_mapper_record:left=%s:right=%s" (show_data left) (show_data right))
                    | Some _, None -> Choice2Of2 "record_map_record_arg_missing"
                    | None, Some _ -> Choice2Of2 "record_map_mapper_arg_missing"
                    | None, None -> Choice2Of2 "record_map_arg_missing"
                let scheduleRecordTypeTryFind () =
                    EvalReplayValueStore.putApplyContext contextNodeId sObj
                    EvalReplayValueStore.putTypeApplyContext contextNodeId sObj
                    let scheduleFail onFail =
                        try
                            match EvalReplayValueStore.tryScheduleApplyFunctionBodyReplayAt contextNodeId onFail DB with
                            | Choice1Of2 (bodyNodeId, bodyShape) ->
                                EvalReplayValueStore.putTypeAwareOpResultNode contextNodeId bodyNodeId
                                EvalReplayValueStore.putParentContinuation bodyNodeId { parentKind = "term"; parentShape = "EOp"; parentNodeId = contextNodeId; role = "record_type_try_find_fail" }
                                DiagJson.emit (
                                    sprintf "{\"kind\":\"eval_worklist_record_type_try_find_fail_replay_scheduled\",\"context_node_id\":%d,\"body_node_id\":%d,\"body_shape\":%s,\"single_flight\":1,\"next\":\"schedule_record_type_try_find_fail_replay\"}"
                                        contextNodeId bodyNodeId (DiagJson.esc bodyShape))
                                Choice1Of2 (bodyNodeId, bodyShape, "record_type_try_find_fail")
                            | Choice2Of2 detail -> Choice2Of2 ("record_type_try_find_fail_schedule_failed:" + detail)
                        with ex -> Choice2Of2 ("record_type_try_find_fail_schedule_exception:" + compactOpExn ex)
                    match recordTyAt 0, termAt 1 with
                    | Choice1Of2 fields, Some (DSymbol key) ->
                        match fields |> Map.tryPick (fun (_, k) v -> if k = key then Some v else None) with
                        | Some tyValue ->
                            match termAt 2 with
                            | Some onSucc ->
                                try
                                    match EvalReplayValueStore.tryScheduleTypeApplyBodyReplayAt contextNodeId onSucc tyValue with
                                    | Choice1Of2 (bodyNodeId, bodyShape) ->
                                        EvalReplayValueStore.putTypeAwareOpResultNode contextNodeId bodyNodeId
                                        EvalReplayValueStore.putParentContinuation bodyNodeId { parentKind = "term"; parentShape = "EOp"; parentNodeId = contextNodeId; role = "record_type_try_find_success" }
                                        DiagJson.emit (
                                            sprintf "{\"kind\":\"eval_worklist_record_type_try_find_success_replay_scheduled\",\"context_node_id\":%d,\"key\":%s,\"body_node_id\":%d,\"body_shape\":%s,\"single_flight\":1,\"next\":\"schedule_record_type_try_find_success_replay\"}"
                                                contextNodeId (DiagJson.esc key) bodyNodeId (DiagJson.esc bodyShape))
                                        Choice1Of2 (bodyNodeId, bodyShape, "record_type_try_find_success:" + key)
                                    | Choice2Of2 detail -> Choice2Of2 ("record_type_try_find_success_schedule_failed:" + detail)
                                with ex -> Choice2Of2 ("record_type_try_find_success_schedule_exception:" + compactOpExn ex)
                            | None ->
                                match termAt 3 with
                                | Some onFail -> scheduleFail onFail
                                | None -> Choice2Of2 "record_type_try_find_branch_missing"
                        | None ->
                            match termAt 3 with
                            | Some onFail -> scheduleFail onFail
                            | None -> Choice2Of2 "record_type_try_find_fail_missing"
                    | Choice2Of2 detail, _ -> Choice2Of2 detail
                    | _, Some other -> Choice2Of2 (sprintf "record_type_try_find_expected_symbol:%s" (show_data other))
                    | _, None -> Choice2Of2 "record_type_try_find_key_missing"
                let scheduleRecordTypeFoldBack () =
                    EvalReplayValueStore.putApplyContext contextNodeId sObj
                    EvalReplayValueStore.putTypeApplyContext contextNodeId sObj
                    let scheduleFoldChild (role: string) (field: string) (bodyNodeId: int) (bodyShape: string) =
                        EvalReplayValueStore.putTypeAwareOpResultNode contextNodeId bodyNodeId
                        EvalReplayValueStore.putParentContinuation bodyNodeId { parentKind = "term"; parentShape = "EOp"; parentNodeId = contextNodeId; role = role }
                        DiagJson.emit (
                            sprintf "{\"kind\":\"eval_worklist_record_type_fold_back_step_replay_scheduled\",\"context_node_id\":%d,\"field\":%s,\"role\":%s,\"body_node_id\":%d,\"body_shape\":%s,\"single_flight\":1,\"next\":\"schedule_record_type_fold_back_step_replay\"}"
                                contextNodeId (DiagJson.esc field) (DiagJson.esc role) bodyNodeId (DiagJson.esc bodyShape))
                        Choice1Of2 (bodyNodeId, bodyShape, role + ":" + field)
                    match termAt 0, termAt 1, recordTyAt 2 with
                    | Some folder, Some state0, Choice1Of2 fields ->
                        if fields.IsEmpty then
                            EvalReplayValueStore.putTermValue contextNodeId state0
                            DiagJson.emit (
                                sprintf "{\"kind\":\"eval_worklist_record_type_fold_back_empty_resolved\",\"context_node_id\":%d,\"field_count\":0,\"single_flight\":1,\"next\":\"term_op_pure_value_resolved\"}"
                                    contextNodeId)
                            Choice1Of2 (contextNodeId, "EOp", "record_type_fold_back_empty")
                        else
                            let mutable folded = Some state0
                            let mutable failed : string option = None
                            let mutable scheduled : Choice<int * string * string, string> option = None
                            for KeyValue((_i, k), tyValue) in fields |> Seq.rev do
                                match folded, scheduled with
                                | Some state, None ->
                                    let keyArg = DSymbol k
                                    let keyedFolderOpt =
                                        try Some (apply s (folder, keyArg))
                                        with ex ->
                                            match EvalReplayValueStore.tryScheduleApplyFunctionBodyReplayAt contextNodeId folder keyArg with
                                            | Choice1Of2 (bodyNodeId, bodyShape) ->
                                                scheduled <- Some (scheduleFoldChild "record_type_fold_back_keyed_folder" k bodyNodeId bodyShape)
                                                None
                                            | Choice2Of2 detail ->
                                                failed <- Some ("record_type_fold_back_keyed_folder_schedule_failed:" + k + ":" + detail + ":" + compactOpExn ex)
                                                None
                                    match keyedFolderOpt, scheduled with
                                    | Some keyedFolder, None ->
                                        let typedFolderOpt =
                                            try Some (type_apply s keyedFolder tyValue)
                                            with ex ->
                                                match EvalReplayValueStore.tryScheduleTypeApplyBodyReplayAt contextNodeId keyedFolder tyValue with
                                                | Choice1Of2 (bodyNodeId, bodyShape) ->
                                                    scheduled <- Some (scheduleFoldChild "record_type_fold_back_typed_folder" k bodyNodeId bodyShape)
                                                    None
                                                | Choice2Of2 detail ->
                                                    failed <- Some ("record_type_fold_back_typed_folder_schedule_failed:" + k + ":" + detail + ":" + compactOpExn ex)
                                                    None
                                        match typedFolderOpt, scheduled with
                                        | Some typedFolder, None ->
                                            try
                                                folded <- Some (apply s (typedFolder, state))
                                            with ex ->
                                                match EvalReplayValueStore.tryScheduleApplyFunctionBodyReplayAt contextNodeId typedFolder state with
                                                | Choice1Of2 (bodyNodeId, bodyShape) ->
                                                    scheduled <- Some (scheduleFoldChild "record_type_fold_back_fold_step" k bodyNodeId bodyShape)
                                                    folded <- None
                                                | Choice2Of2 detail ->
                                                    failed <- Some ("record_type_fold_back_step_schedule_failed:" + k + ":" + detail + ":" + compactOpExn ex)
                                                    folded <- None
                                        | _ ->
                                            folded <- None
                                    | _ ->
                                        folded <- None
                                | _ -> ()
                            match scheduled, folded, failed with
                            | Some scheduledChild, _, _ -> scheduledChild
                            | None, Some value, _ ->
                                EvalReplayValueStore.putTermValue contextNodeId value
                                DiagJson.emit (
                                    sprintf "{\"kind\":\"eval_worklist_record_type_fold_back_replay_resolved\",\"context_node_id\":%d,\"field_count\":%d,\"single_flight\":1,\"next\":\"term_op_pure_value_resolved\"}"
                                        contextNodeId fields.Count)
                                Choice1Of2 (contextNodeId, "EOp", "record_type_fold_back_value_materialized")
                            | None, None, Some detail -> Choice2Of2 detail
                            | None, None, None -> Choice2Of2 "record_type_fold_back_unknown"
                    | None, _, _ -> Choice2Of2 "record_type_fold_back_folder_missing"
                    | _, None, _ -> Choice2Of2 "record_type_fold_back_state_missing"
                    | _, _, Choice2Of2 detail -> Choice2Of2 detail
                match opName with
                | "Dyn" -> scheduleDyn ()
                | "StringIndex" -> scheduleStringIndex ()
                | "TypeEq" -> scheduleTypeEq ()
                | "BackendSwitch" | "UnsafeBackendSwitch" -> scheduleBackendSwitch ()
                | "RecordMap" -> scheduleRecordMap ()
                | "RecordTypeTryFind" -> scheduleRecordTypeTryFind ()
                | "RecordTypeFoldBack" -> scheduleRecordTypeFoldBack ()
                | "EQ" | "NEQ" | "EQ" | "NEQ" | "LT" | "LTE" | "GT" | "GTE" -> schedulePrimitiveCompare ()
                | _ -> Choice2Of2 ("type_aware_op_schedule_unhandled:" + opName))

            EvalReplayValueStore.installAnnotTestBranchAfterDefinition (fun sObj bindValue annotTy ->
                let s = unbox<LangEnv> sObj
                try
                    let bindTy = data_to_ty s bindValue
                    Choice1Of2 (ty_eq_allow_jp_placeholders bindTy annotTy)
                with ex ->
                    let msg =
                        if isNull ex.Message then ex.GetType().Name
                        else ex.GetType().Name + ":" + ex.Message.Replace("\r"," ").Replace("\n"," ").Replace("\t"," ")
                    let msg = if msg.Length > 180 then msg.Substring(0, 180) + "..." else msg
                    Choice2Of2 msg)
    

            match x with
            | EPatternRef _ -> failwith "Compiler error: EPatternRef should have been eliminated during the prepass."
            | EB _ -> DB
            | EV a -> v s a
            | ELit(_,a) -> DLit a
            | ESymbol(_,a) -> DSymbol a
            | EFun _ -> failwith "Compiler error: Raw functions should be transformed during the prepass."
            | EFun'(_,free_vars,i,body,annot) -> efun (free_vars,i,body,annot)
            | ERecursiveFun'(_,free_vars,i,body,annot) -> efun (free_vars,i,body.Value,annot)
            | EForall _ -> failwith "Compiler error: Raw foralls should be transformed during the prepass."
            | EForall'(_,free_vars,i,body) -> eforall (free_vars,i,body)
            | ERecursiveForall'(_,free_vars,i,body) -> eforall (free_vars,i,body.Value)
            | ERecursive a -> term s a.Value
            | ERecBlock _ -> failwith "Compiler error: Recursive blocks should be inlined and eliminated during the prepass."
            | EJoinPoint _ -> failwith "error[EJPX003]: internal compiler error\n  |\n  = raw join point survived prepass\n  help: this indicates a missing transformation pass; capture the stack trace and prepass inputs.\n"
            | EJoinPoint'(r,scope,body,annot,backend,jp_name) ->
                let env_global_type = HopacExtensions.A.map (vt s) scope.ty.free_vars
                let env_global_term = HopacExtensions.A.map (v s) scope.term.free_vars
    

                let backend' = match backend with None -> s.backend | Some (_,backend) -> lock backend_strings_lock (fun () -> backend_strings.Add backend)
                // ALPHA48: IVar-based dict - no separate dict_ev needed
                let (dict: System.Collections.Concurrent.ConcurrentDictionary<ConsedNode<RData [] * Ty [] * Ty>, Hopac.IVar<TypedBind [] option * Ty option * string option>>), hc_table, cache_gen =
                    Utils.memoize join_point_method (fun _ ->
                        System.Collections.Concurrent.ConcurrentDictionary<ConsedNode<RData [] * Ty [] * Ty>, Hopac.IVar<TypedBind [] option * Ty option * string option>>(HashIdentity.Reference), HashConsTable(), CacheGeneration.current ()
                    ) (backend', body)
    

                let dict, hc_table =
                    if CacheGeneration.isStale cache_gen then
                        let fresh =
                            (System.Collections.Concurrent.ConcurrentDictionary<_,_>(HashIdentity.Reference),
                             HashConsTable(),
                             CacheGeneration.current ())
                        join_point_method.[(backend', body)] <- fresh
                        let (d,h,_) = fresh
                        d,h
                    else dict, hc_table
    

                // NOTE: join-point bodies can be polymorphic; when the same body is reached through different
                // instantiations, caching solely by the free-variable environment can accidentally reuse the wrong
                // specialization (especially under parallel builds). We therefore salt the key with the local
                // annotation type when one is available at this call site.
                let annot_ty_for_key : Ty option =
                    try Option.map (ty s) annot
                    with _ -> None
                let env_global_type_key =
                    match annot_ty_for_key with
                    | Some t -> Array.append env_global_type [| t |]
                    | None -> env_global_type
    

                let call_args, env_global_value =
                    data_to_rdata s hc_table env_global_term
    

                // Include source range in JP key for cache uniqueness
                let (sp, ep) = r.range
                let rk = sprintf "jp@%s:%d:%d-%d:%d" r.path sp.line sp.character ep.line ep.character
    

                let env_global_value_key =
                    Array.append env_global_value [| ReSymbol rk |]
    

                let inline normalize_jp_key_ret (t: Ty) : Ty =
                    let t = jp_method_deref_rec_placeholder t
                    match t with
                    | YVoid | YB | YLit _ | YPrim _ -> t
                    | YSymbol s when s.Contains("JPMethodRecPlaceholder(") || s.Contains("JPTypeRecPlaceholder(") -> YSymbol "JPMethodUnknownRet(par)"
                    | YSymbol s when s.StartsWith("JPMethodUnknownRet(") -> YSymbol "JPMethodUnknownRet(par)"
                    | _ -> t
    

                let annot_ty_for_key_norm : Ty =
                    match annot_ty_for_key with
                    | Some t -> normalize_jp_key_ret t
                    | None -> YSymbol "JPMethodUnknownRet(par)"
    

                let join_point_key =
                    lock hc_table (fun () -> hc_table.Add(env_global_value_key, env_global_type_key, annot_ty_for_key_norm))
                let _ =
                    // record a stable label for better join-point diagnostics
                    let base_name =
                        match jp_name with
                        | Some n when n <> "" -> n
                        | _ -> sprintf "<anonymous:%d>" join_point_key.tag
                    let name = base_name + " @" + rk
                    s.join_point_method_key_names.TryAdd(join_point_key, name) |> ignore
    
                // ALPHA48: Create IVar for this JP specialization

                let jp_ivar = Hopac.IVar<TypedBind [] option * Ty option * string option>()
    

                let ret_ty =
                    // ALPHA48: Check if IVar already exists (another thread is computing)
                    match dict.TryGetValue(join_point_key) with
                    | true, existing_ivar when Hopac.IVar.Now.isFull existing_ivar ->
                        // Already computed - get result
                        let (_, ret_ty_opt, _) = Hopac.IVar.Now.get existing_ivar
                        match ret_ty_opt with
                        | Some ret_ty -> ret_ty
                        | None ->
                            jp_throw_keyed join_point_key
                            raise_type_error (add_trace s r) (sprintf "error[EJP0001]: JP computation completed but no return type\n  = key: %O\n  = backend: %O\n" join_point_key backend')
                    | true, existing_ivar ->
                        // In progress - wait for it
                        let jp = defaultArg jp_name "<anon>"
                        if SuspectCache.currentCount () > 0 then
                            // Global recovery mode: do not wait on potentially poisoned IVars.
                            CacheGeneration.requestSequential ()
                            record_jp_diag_method join_point_key jp_name (r :: s.trace)
                            let mutable removed = Unchecked.defaultof<_>
                            dict.TryRemove(join_point_key, &removed) |> ignore
                            let annot_val = Option.map (ty s) annot
                            let jp_method_stack = System.Collections.Generic.HashSet<ConsedNode<RData [] * Ty [] * Ty>>(s.jp_method_stack, HashIdentity.Reference)
                            let jp_closure_stack = System.Collections.Generic.HashSet<ConsedNode<RData [] * Ty [] * Ty>>(s.jp_closure_stack, HashIdentity.Reference)
                            let jp_type_stack = System.Collections.Generic.HashSet<ConsedNode<Ty []>>(s.jp_type_stack, HashIdentity.Reference)
                            jp_method_stack.Add join_point_key |> ignore
                            let s : LangEnv = {
                                trace = r :: s.trace
                                seq = ResizeArray()
                                cse = [Dictionary(HashIdentity.Structural)]
                                unions = Map.empty
                                i = ref 0
                                env_global_type = env_global_type
                                env_global_term = env_global_term
                                env_stack_type = Array.zeroCreate<_> scope.ty.stack_size
                                env_stack_term = Array.zeroCreate<_> scope.term.stack_size
                                backend = backend'
                                globals = s.globals
                                globals_lock = s.globals_lock
                                globals_seen = s.globals_seen
                                join_point_method_key_names = s.join_point_method_key_names
                                join_point_closure_key_names = s.join_point_closure_key_names
                                jp_method_stack = jp_method_stack
                                jp_closure_stack = jp_closure_stack
                                jp_type_stack = jp_type_stack
                                }
                            let s = rename_global_term s
                            let recursion_site = sprintf "JPMethod.recovery_bypass@%s:%d" r.path (fst r.range).line
                            let entry_depth = RecursionTracker.enter recursion_site
                            try
                                BitMamba.recordAccess join_point_key
                                let compute_term () = term_scope'' s body annot_val
                                let seq, ty =
                                    if entry_depth > 64 then
                                        match BigStack.tryRun (sprintf "jp_method_recovery_%d" join_point_key.tag) compute_term with
                                        | Some v -> v
                                        | None -> compute_term ()
                                    else compute_term ()
                                jp_method_resolve_rec_placeholder join_point_key ty
                                ty
                            finally
                                RecursionTracker.exit ()
                        elif s.jp_method_stack.Contains join_point_key then
                            let cur = trace_to_string_short (r :: s.trace)
                            let snap = diag_snapshot (sprintf "JPMethod.recursive jp=%s" jp)
                            let ivar_full = Hopac.IVar.Now.isFull existing_ivar
                            let first_seen =
                                match jp_method_key_traces.TryGetValue join_point_key with
                                | true, tr -> trace_to_string_short tr
                                | _ ->
                                    match jp_name_traces.TryGetValue jp with
                                    | true, tr -> trace_to_string_short tr
                                    | _ -> "<unknown>"
                            let stack_prev = jp_method_stack_preview s.jp_method_stack
                            jp_method_rec_placeholder join_point_key jp
                        else
                            // ALPHA48: Wait on IVar cooperatively
                            let result = jp_ivar_wait "JPMethod.wait" (sprintf "key=%O backend=%O" join_point_key backend') existing_ivar
                            jp_throw_if_any ()
                            match result with
                            | (_, Some ret_ty, _) -> ret_ty
                            | _ ->
                                jp_throw_keyed join_point_key
                                raise_type_error (add_trace s r) (sprintf "error[EJP0001]: JP completed without return type\n  = key: %O\n  = backend: %O\n" join_point_key backend')
                    | false, _ ->
                        let annot_val = Option.map (ty s) annot
                        // v107-alpha43: Check loop specialization guard before creating new spec
                        let jp_name_str = defaultArg jp_name "<anon>"
                        if not (LoopSpecializationGuard.tryRecordSpecialization jp_name_str) then
                            // Specialization cap exceeded - degrade instead of aborting the whole compilation.
                            // Returning a placeholder Ty here prevents unbounded specialization from patterns like loop in listm'.spi.
                            // It is intentionally conservative: downstream equality treats JP placeholders as wildcards.
                            let cap = LoopSpecializationGuard.getCapForName jp_name_str
                            let cnt = LoopSpecializationGuard.getCount jp_name_str
                            let snap = diag_snapshot (sprintf "[spiral_compiler] EJP0012: loop specialization cap exceeded for '%s' (count=%d cap=%d)" jp_name_str cnt cap)
                            SuspectCache.mark join_point_key (sprintf "%s jp_method cap name=%s" EJPCodes.EJP0012 jp_name_str)
                            let inline is_loopish_name (n: string) =
                                n = "<anon>" || n = "루프" || n.Contains("루프") || n.Contains("loop") || n.Contains("Loop")
                            if is_loopish_name jp_name_str then
                                let ph = jp_method_rec_placeholder join_point_key jp_name_str
                                // If we have a union annotation, attach it to the placeholder so EUnbox can infer cases.
                                match annot_val with
                                | Some t ->
                                    match nominal_type_apply s t with
                                    | YUnion _ -> jp_method_resolve_rec_placeholder join_point_key t
                                    | _ -> ()
                                | None -> ()
                                DiagSidecar.emit (sprintf "[spiral_compiler] EJP0012: capped loopish JP '%s' -> placeholder=%s (count=%d tag=%d)\n%s"
                                    jp_name_str (show_ty ph) (LoopSpecializationGuard.getCount jp_name_str) join_point_key.tag snap)
                                ph
                            else
                                match annot_val with
                                | Some t ->
                                    // par: never return a primitive/placeholder annotation for a capped JP.
                                    // Doing so can leak a hard primitive into callable positions and trigger spurious EJP0007.
                                    let inline is_primitive_like (t: Ty) =
                                        match t with
                                        | YVoid | YB | YLit _ | YPrim _ -> true
                                        | _ -> false
                                    let inline is_jp_placeholder_like (t: Ty) =
                                        match t with
                                        | YSymbol s when s.Contains("JPMethodRecPlaceholder(") || s.Contains("JPTypeRecPlaceholder(") -> true
                                        | _ -> false
                                    if is_primitive_like t || is_jp_placeholder_like t then
                                        let ph = jp_method_rec_placeholder join_point_key jp_name_str
                                        DiagSidecar.emit (sprintf "[spiral_compiler] EJP0012: ignoring primitive/placeholder annotation for capped JP '%s' -> placeholder=%s (count=%d tag=%d)\n%s"
                                            jp_name_str (show_ty ph) (LoopSpecializationGuard.getCount jp_name_str) join_point_key.tag snap)
                                        ph
                                    else
                                        DiagSidecar.emit (sprintf "[spiral_compiler] EJP0012: using annotation type for capped JP '%s' (count=%d tag=%d)"
                                            jp_name_str (LoopSpecializationGuard.getCount jp_name_str) join_point_key.tag)
                                        t
                                | None ->
                                    let ph = jp_method_rec_placeholder join_point_key jp_name_str
                                    DiagSidecar.emit (sprintf "[spiral_compiler] EJP0012: degrading capped JP '%s' to placeholder=%s (count=%d tag=%d)\n%s"
                                        jp_name_str (show_ty ph) (LoopSpecializationGuard.getCount jp_name_str) join_point_key.tag snap)
                                    ph
    

                        // If a JP key was marked suspect in a previous generation, avoid memoization for this key.
                        // This is a stabilizer for EJP0003/EJP0007 style cache corruption: recompute deterministically instead of reusing a potentially poisoned cell.
                        elif (SuspectCache.currentCount () > 0) || SuspectCache.isSuspect join_point_key then
                            CacheGeneration.requestSequential ()
                            record_jp_diag_method join_point_key jp_name (r :: s.trace)
                            let jp_method_stack = System.Collections.Generic.HashSet<ConsedNode<RData [] * Ty [] * Ty>>(s.jp_method_stack, HashIdentity.Reference)
                            let jp_closure_stack = System.Collections.Generic.HashSet<ConsedNode<RData [] * Ty [] * Ty>>(s.jp_closure_stack, HashIdentity.Reference)
                            let jp_type_stack = System.Collections.Generic.HashSet<ConsedNode<Ty []>>(s.jp_type_stack, HashIdentity.Reference)
                            jp_method_stack.Add join_point_key |> ignore
                            let s : LangEnv = {
                                trace = r :: s.trace
                                seq = ResizeArray()
                                cse = [Dictionary(HashIdentity.Structural)]
                                unions = Map.empty
                                i = ref 0
                                env_global_type = env_global_type
