                                                            DiagJson.emit (
                                                                sprintf "{\"kind\":\"eval_worklist_generation_wait_after_seq_cycle_abort\",\"event\":\"retry_stop\",\"attempt\":%d,\"max_attempts\":%d,\"yield_used\":%d,\"yield_cap\":%d,\"pending\":%d,\"cycle_site\":%s,\"policy\":\"alpha329_fail_closed_when_no_pending_drain_slot\",\"single_flight\":1,\"next\":\"abort_without_write\"}"
                                                                    attempt max_attempts frontier_yield_retry_count frontier_yield_retry_cap pendingAfterGenWaitCycle (DiagJson.esc cycle_site))
                                                            raise (PartEvalTypeError(e.Data0, e.Data1))

                                                    let is_depth_after_seq =
                                                        code = EJPCodes.EJP0009
                                                        && attempt > 0
                                                        && CacheGeneration.isSequentialRequested()

                                                    if is_depth_after_seq then
                                                        let depth_site, depth_value, depth_max =
                                                            let m = System.Text.RegularExpressions.Regex.Match(msg, @"depth=(\d+) max=(\d+)\) at ([^\r\n]+)")
                                                            if m.Success then
                                                                m.Groups.[3].Value, int m.Groups.[1].Value, int m.Groups.[2].Value
                                                            else "", 0, 0
                                                        DiagJson.retryStop code "stack_depth_after_sequential_retry" attempt max_attempts file backend "" depth_site depth_value 0 depth_max
                                                        // alpha322/323: once forced-sequential fallback reaches the recursion-depth fuse,
                                                        // further retries only replay the same stack-safe failure and hide the real work.
                                                        // alpha323 also exports the depth/site/max fields so the next move is clear.
                                                        raise (PartEvalTypeError(e.Data0, e.Data1))

                                                    let is_jp_stall =
                                                        code = EJPCodes.EJP0014

                                                    let jpStallPinnedTerminal =
                                                        if is_jp_stall && CacheGeneration.isSequentialRequested() then
                                                            try
                                                                EvalWorklist.drainJpStallPreflight "jp_stall_terminal_preflight" 256 |> ignore
                                                                match EvalWorklist.tryPinnedTerminalContract() with
                                                                | Some pinned when EvalWorklist.terminalContractRank pinned.status >= 90 -> Some pinned
                                                                | _ ->
                                                                    match EvalWorklist.waitForPinnedTerminalContract "jp_stall_terminal_preflight_wait" 96 10 with
                                                                    | Some pinned -> Some pinned
                                                                    | None ->
                                                                        match EvalWorklist.tryPinnedTerminalContract() with
                                                                        | Some pinned when EvalWorklist.terminalContractRank pinned.status > 0 ->
                                                                            let rank = EvalWorklist.terminalContractRank pinned.status
                                                                            DiagJson.emit (
                                                                                sprintf "{\"kind\":\"eval_worklist_jp_stall_any_rank_terminal_abort_without_retry\",\"event\":\"jp_stall_terminal_preflight\",\"code\":%s,\"terminal_code\":%s,\"original_code\":%s,\"status\":%s,\"rank\":%d,\"site\":%s,\"key\":%s,\"attempt\":%d,\"max_attempts\":%d,\"pending\":%d,\"single_flight\":1,\"next\":%s}"
                                                                                    (DiagJson.esc EJPCodes.EJP0011) (DiagJson.esc EJPCodes.EJP0011) (DiagJson.esc code) (DiagJson.esc pinned.status) rank (DiagJson.esc pinned.site) (DiagJson.esc pinned.key) attempt max_attempts (EvalWorklist.pendingCount()) (DiagJson.esc "explicit_eval_worklist_terminal_contract_required"))
                                                                            Some pinned
                                                                        | _ -> None
                                                            with _ -> None
                                                        else None

                                                    match jpStallPinnedTerminal with
                                                    | Some pinned ->
                                                        let rank = EvalWorklist.terminalContractRank pinned.status
                                                        let terminalCode = EJPCodes.EJP0011
                                                        DiagJson.emit (
                                                            sprintf "{\"kind\":\"eval_worklist_jp_stall_pinned_terminal_abort_without_retry\",\"event\":\"jp_stall_terminal_preflight\",\"code\":%s,\"terminal_code\":%s,\"original_code\":%s,\"status\":%s,\"rank\":%d,\"site\":%s,\"key\":%s,\"attempt\":%d,\"max_attempts\":%d,\"pending\":%d,\"single_flight\":1,\"next\":\"abort_without_write\"}"
                                                                (DiagJson.esc terminalCode) (DiagJson.esc terminalCode) (DiagJson.esc code) (DiagJson.esc pinned.status) rank (DiagJson.esc pinned.site) (DiagJson.esc pinned.key) attempt max_attempts (EvalWorklist.pendingCount()))
                                                        DiagJson.retryStop terminalCode "jp_wait_stall_pinned_terminal_abort_without_retry" attempt max_attempts file backend pinned.key pinned.site pinned.depth pinned.re pinned.maxRe
                                                        let terminalMsg =
                                                            let msg =
                                                                sprintf "%s: pinned terminal contract blocked jp_wait stall; original_code=%s"
                                                                    terminalCode code
                                                            EvalWorklist.requiredMessage
                                                                (sprintf "%s\njp_stall_terminal_abort_without_retry=1 original_code=%s" msg code)
                                                                pinned
                                                        raise (PartEvalTypeError(e.Data0, terminalMsg))
                                                    | None -> ()

                                                    let jp_stall_replay_complete =
                                                        is_jp_stall
                                                        && CacheGeneration.isSequentialRequested()
                                                        && (match EvalWorklist.drainJpStallPreflight "jp_stall_retry_preflight" 256 with
                                                            | Some _ -> EvalWorklist.hasReplayComplete()
                                                            | None -> EvalWorklist.hasReplayComplete())

                                                    if jp_stall_replay_complete && attempt + 1 < max_attempts then
                                                        DiagJson.emit (
                                                            sprintf "{\"kind\":\"eval_worklist_resume\",\"event\":\"jp_stall_retry_preflight\",\"status\":\"semantic_root_complete\",\"attempt\":%d,\"next_attempt\":%d,\"max_attempts\":%d,\"policy\":\"retry_after_jp_stall_replay_root_complete\",\"single_flight\":1,\"next\":\"attempt_build\"}"
                                                                attempt (attempt + 1) max_attempts)
                                                        CacheGeneration.invalidate (sprintf "BuildFile.replay_root_complete code=%s attempt=%d file=%s backend=%s jp_stall_preflight=1" code attempt file backend) |> ignore
                                                        raise (System.InvalidOperationException(sprintf "__SPIRAL_REPLAY_RETRY__:%d" (attempt + 1)))

                                                    let is_jp_stall_after_seq =
                                                        is_jp_stall
                                                        && attempt > 0
                                                        && CacheGeneration.isSequentialRequested()

                                                    if is_jp_stall_after_seq then
                                                        // alpha327: EJP0014 under forced sequential is not a harmless soft abort anymore.
                                                        // It means the legacy fallback is waiting on a poisoned/stalled JP graph.
                                                        // Stop after one generation-clearing retry instead of burning minutes in a retry storm.
                                                        DiagJson.retryStop code "jp_wait_stall_after_sequential_retry" attempt max_attempts file backend "" (DiagLastWait.get()) 0 0 0
                                                        raise (PartEvalTypeError(e.Data0, e.Data1))

                                                    let is_soft_abort =
                                                        is_gen_wait
                                                        || (is_jp_stall && not (CacheGeneration.isSequentialRequested()))
                                                        || code = EJPCodes.EJP0018
                                                        || code = EJPCodes.EJP0020
                                                        || code = EJPCodes.EJP0030

                                                    let is_no_invalidate =
                                                        is_gen_wait
                                                        || is_term_cycle_fuse
                                                    // alpha327: EJP0014 is intentionally excluded from no-invalidate.
                                                    // A JP wait stall should clear the generation once, otherwise the retry resumes the same stale wait graph.
                                                    // For non-generation-change errors, force sequential execution for determinism.
                                                    // alpha318: EJP0011 is treated as a parallel-poison/fallback signal first;
                                                    // retry sequentially, consuming attempt budget but without invalidating the whole generation. If it is a real
                                                    // semantic cycle, the sequential retry will reproduce it and bubble cleanly.
                                                    if not is_gen_wait then
                                                        HopacExtensions.forceConcurrencyForRetry 1
                                                        CacheGeneration.requestSequential ()
                                                    let mutable gen_after =
                                                        if is_no_invalidate then CacheGeneration.current ()
                                                        else CacheGeneration.invalidate (sprintf "BuildFile.retry code=%s attempt=%d file=%s backend=%s" code attempt file backend)
    
                                                    // ALPHA49: SupervisorState doesn't own JP per-env caches (they live in LangEnv); rely on invalidate callbacks.

                                                    if not is_gen_wait then
                                                        ()
    

                                                    if is_gen_wait then System.Threading.Thread.Yield() |> ignore
    

                                                    let will_retry_ejp0011 =
                                                        is_term_cycle_fuse
                                                        && not is_term_cycle_after_seq
                                                        && attempt + 1 < max_attempts

                                                    let trace_lines0, _ =
                                                        if will_retry_ejp0011 then [], ""
                                                        else show_trace s e.Data0 e.Data1
                                                    let trace_lines =
                                                        let max_trace = if is_term_cycle_fuse then 96 else 320
                                                        let is_big_stack =
                                                            code = EJPCodes.EJP0010
                                                            || msg.Contains("stack overflow")
                                                            || msg.Contains("StackOverflow")
                                                        if is_big_stack then
                                                            let head = 40
                                                            let tail = 40
                                                            let n = List.length trace_lines0
                                                            if n <= head + tail + 1 then trace_lines0
                                                            else
                                                                (trace_lines0 |> List.truncate head)
                                                                @ [ $"[spiral_compiler] ... ({n - head - tail} frames omitted) ..." ]
                                                                @ (trace_lines0 |> List.rev |> List.truncate tail |> List.rev)
                                                        else
                                                            let n = List.length trace_lines0
                                                            if n <= max_trace then trace_lines0
                                                            else
                                                                (trace_lines0 |> List.truncate max_trace)
                                                                @ [ $"[spiral_compiler] ... ({n - max_trace} frames omitted) ..." ]
                                                    let sidecar =
                                                        // alpha331: retry diagnostics should preserve causal breadcrumbs without
                                                        // flooding the console. EJP0014 sidecars are especially noisy because
                                                        // they often contain hundreds of sampled EJP0011W re-entry warnings;
                                                        // hotkey summaries below carry the aggregate signal.
                                                        if will_retry_ejp0011 then []
                                                        elif code = EJPCodes.EJP0014 then DiagSidecar.snapshot 16
                                                        elif is_term_cycle_fuse then DiagSidecar.snapshot 32
                                                        else DiagSidecar.snapshot 96
                                                    let reasons = CacheGeneration.reasonsSnapshot (if is_term_cycle_fuse then 24 else 64)
                                                    let had_apply_mismatch = reasons |> List.exists (fun x -> x.Contains("apply mismatch"))
                                                    if is_gen_wait && had_apply_mismatch then
                                                        // alpha220: avoid invalidation storms; keep this as pure sequential-soft.
                                                        // The mismatch site already invalidated the generation; a second invalidation inside a gen-wait retry
                                                        // can create generation storms and break JP liveness (observed as a single job stuck forever).
                                                        CacheGeneration.requestSequential ()
                                                        HopacExtensions.forceConcurrency 1
                                                        ()
    

                                                    let suspects =
                                                        SuspectCache.getRecent 32
                                                        |> List.map (fun (h, se) -> sprintf "%d gen=%d depth=%d hits=%d type=%s ts=%O" h (int se.generation) se.depth se.hitCount se.errorType se.timestamp)
                                                    DiagSidecar.emit (sprintf "BuildFile.retry: %s gen=%d->%d attempt=%d file=%s backend=%s gen_wait=%b" code (int gen_before) (int gen_after) attempt file backend is_gen_wait)
                                                    DiagJson.retry code (int gen_before) (int gen_after) attempt max_attempts file backend is_gen_wait (CacheGeneration.isSequentialRequested()) (HopacExtensions.envForcedConcurrency()) (HopacExtensions.peekForcedConcurrency())
                                                    let prefix = "[spiral_compiler] "
                                                    let prefixLine (s: string) =
                                                        if System.String.IsNullOrEmpty s then prefix.TrimEnd()
                                                        elif s.StartsWith(prefix) then s
                                                        else prefix + s

                                                    let msg_lines =
                                                        msg.Split([| "\r\n"; "\r"; "\n" |], System.StringSplitOptions.None)
                                                        |> Array.toList

                                                    let diag_lines =
                                                        [ sprintf "%s retry diagnostics" code
                                                          sprintf "file=%s" file
                                                          sprintf "backend=%s" backend
                                                          sprintf "attempt=%d/%d" (attempt + 1) max_attempts
                                                          sprintf "gen=%d -> %d" gen_before gen_after
                                                          sprintf "dop_env=%d dop_forced=%d" (HopacExtensions.envForcedConcurrency()) (HopacExtensions.peekForcedConcurrency())
                                                          sprintf "last_wait=%s" (DiagLastWait.get())
                                                          sprintf "jp_parallel=%s sequential_requested=%b term_cycle_fuse=%b"
                                                              (if is_gen_wait then "kept"
                                                               else if CacheGeneration.isSequentialRequested() then "forced=0" else "forced=1")
                                                              (CacheGeneration.isSequentialRequested())
                                                              is_term_cycle_fuse
                                                          sprintf "term_cycle_after_seq=%b seq_stop_count=%d fuse_key=%s fuse_site=%s"
                                                              is_term_cycle_after_seq term_cycle_seq_stop_count term_cycle_key term_cycle_site
                                                          sprintf "fallback_policy=%s" (EvalFallbackPolicy.describe (CacheGeneration.isSequentialRequested()) (CacheGeneration.invalidationCount()) term_cycle_depth)
                                                          "---- message ----" ] @ msg_lines @
                                                        [ "---- trace ----" ] @ trace_lines @
                                                        [ "---- sidecar ----" ] @ sidecar @
                                                        [ "---- hotkeys ----"
                                                          sprintf "term_hot %s" (let s = DiagSidecar.snapshotTopKeyedShort "[spiral_compiler] EJP0011W|term_hot|" 8 in if System.String.IsNullOrWhiteSpace s then "(none)" else s)
                                                          sprintf "ty_hot %s" (let s = DiagSidecar.snapshotTopKeyedShort "[spiral_compiler] EJP0011W|ty_hot|" 8 in if System.String.IsNullOrWhiteSpace s then "(none)" else s) ] @
                                                        [ "---- cache invalidations ----" ] @ reasons @
                                                        [ "---- suspects ----" ] @ suspects

                                                    let diag =
                                                        diag_lines
                                                        |> List.collect (fun l -> l.Split([| "\r\n"; "\r"; "\n" |], System.StringSplitOptions.None) |> Array.toList)
                                                        |> List.map prefixLine
                                                        |> String.concat "\n"

                                                    let diag_block =
                                                        [ sprintf "%s === RETRY DIAG BEGIN ===" code
                                                          diag
                                                          sprintf "%s === RETRY DIAG END ===" code ]
                                                        |> String.concat "\n"
                                                    // alpha158: retry diag is console-only while compiler stabilizes (no file IO).

                                                    ()
                                                    if not retry_diag_logged then
                                                        retry_diag_logged <- true
                                                        let codeShort =
                                                            if System.String.IsNullOrEmpty(code) then code
                                                            elif code.StartsWith("[spiral_compiler]") then code.Substring(16).TrimStart()
                                                            else code
                                                        let emit_retry_diag (s: string) =
                                                            ConsoleX.errLine s




                                                        // Trim extremely large diags to keep consoles usable.
                                                        let diag_block' =
                                                            if diag_block.Length > 12000 then
                                                                diag_block.Substring(0, 12000) + "\n[spiral_compiler] ... truncated ..."
                                                            else diag_block

                                                        emit_retry_diag (sprintf "[spiral_compiler] %s retry diag:\n%s" codeShort diag_block')

                                                    if is_soft_abort && soft_abort_count < soft_abort_cap then
                                                        soft_abort_count <- soft_abort_count + 1
                                                        // Soft abort: retry without consuming attempt budget (typically generation-change aborts).
                                                        try
                                                            attempt_build attempt max_attempts
                                                        finally
                                                            HopacExtensions.clearForcedConcurrencyForRetry ()
                                                    elif attempt + 1 < max_attempts then
                                                        try
                                                            attempt_build (attempt + 1) max_attempts
                                                        finally
                                                            HopacExtensions.clearForcedConcurrencyForRetry ()
                                                    else
                                                        // Out of attempts: bubble as fatal.
                                                        raise (PartEvalTypeError(e.Data0, e.Data1))
                                                | _ ->
                                                    reraise ()
    
                                    // ALPHA421/424/425: normal retry stays fixed; root-complete caps were hoisted before attempt_build.

                                    let replayRetryPrefix = "__SPIRAL_REPLAY_RETRY__:"
                                    let parseReplayRetryAttempt (msg: string) =
                                        if System.String.IsNullOrEmpty msg || not (msg.StartsWith replayRetryPrefix) then None
                                        else
                                            let mutable n = 0
                                            if System.Int32.TryParse(msg.Substring(replayRetryPrefix.Length), &n) then Some n else None
                                    let attempt_driver initialAttempt =
                                        let mutable currentAttempt = initialAttempt
                                        let mutable completed = false
                                        let mutable buildResult = Unchecked.defaultof<_>
                                        while not completed do
                                            try
                                                buildResult <- attempt_build currentAttempt max_attempts
                                                completed <- true
                                            with
                                            | :? System.InvalidOperationException as ex ->
                                                match parseReplayRetryAttempt ex.Message with
                                                | Some nextAttempt when nextAttempt >= 0 && nextAttempt <= root_complete_replay_attempt_cap ->
                                                    currentAttempt <- nextAttempt
                                                | Some nextAttempt when nextAttempt >= 0
                                                                           && nextAttempt <= rootCompleteReplayExtendedAttemptCap()
                                                                           && root_complete_yield_retry_count > 0
                                                                           && root_complete_yield_retry_count <= root_complete_yield_retry_cap ->
                                                    DiagJson.emit (
                                                        sprintf "{\"kind\":\"eval_worklist_root_complete_trampoline_extended\",\"event\":\"root_complete_trampoline\",\"attempt\":%d,\"max_attempts\":%d,\"base_cap\":%d,\"yield_used\":%d,\"yield_cap\":%d,\"policy\":\"allow_progress_bearing_root_complete_yield_retry\",\"single_flight\":1,\"next\":\"attempt_selected_frontier\"}"
                                                            nextAttempt max_attempts root_complete_replay_attempt_cap root_complete_yield_retry_count root_complete_yield_retry_cap)
                                                    currentAttempt <- nextAttempt
                                                | Some nextAttempt when nextAttempt >= 0
                                                                     && replay_root_finalization_requested
                                                                     && root_complete_yield_retry_count < root_complete_yield_retry_cap
                                                                     && EvalWorklist.pendingCount() > 0
                                                                     && (EvalWorklist.hasReplayCompleteWriteWitness()
                                                                         || EvalWorklist.semanticPayloadStatus() = "cell"
                                                                         || EvalWorklist.replayQueueDepth() > 0
                                                                         || EvalWorklist.replayDriverActiveDepthValue() > 0) ->
                                                    let pendingNow = EvalWorklist.pendingCount()
                                                    let queueDepthNow = EvalWorklist.replayQueueDepth()
                                                    let activeDepthNow = EvalWorklist.replayDriverActiveDepthValue()
                                                    let payloadStatusNow = EvalWorklist.semanticPayloadStatus()
                                                    noteRootCompleteYieldRetryBudget "root_complete_trampoline_pending_handoff" (max 0 (nextAttempt - 1)) nextAttempt
                                                    DiagJson.emit (
                                                        sprintf "{\"kind\":\"eval_worklist_root_complete_trampoline_pending_handoff_extended\",\"event\":\"root_complete_trampoline\",\"attempt\":%d,\"max_attempts\":%d,\"base_cap\":%d,\"yield_used\":%d,\"yield_cap\":%d,\"pending\":%d,\"queue_depth\":%d,\"active_depth\":%d,\"payload_status\":%s,\"policy\":\"pending_replay_root_handoff_counts_as_progress_yield_before_exhaustion\",\"single_flight\":1,\"next\":\"attempt_pending_root_handoff\"}"
                                                            nextAttempt max_attempts root_complete_replay_attempt_cap root_complete_yield_retry_count root_complete_yield_retry_cap pendingNow queueDepthNow activeDepthNow (DiagJson.esc payloadStatusNow))
                                                    currentAttempt <- nextAttempt
                                                | Some nextAttempt ->
                                                    DiagJson.emit (
                                                        sprintf "{\"kind\":\"eval_worklist_resume_blocked\",\"event\":\"root_complete_trampoline_exhausted\",\"attempt\":%d,\"max_attempts\":%d,\"cap\":%d,\"yield_used\":%d,\"yield_cap\":%d,\"policy\":\"bounded_root_complete_trampoline\",\"single_flight\":1,\"next\":\"abort_without_fatal_sentinel\"}"
                                                            nextAttempt max_attempts root_complete_replay_attempt_cap root_complete_yield_retry_count root_complete_yield_retry_cap)
                                                    raise (PartEvalTypeError([], sprintf "semantic_root_complete replay handoff exhausted at attempt=%d cap=%d yield_used=%d yield_cap=%d" nextAttempt root_complete_replay_attempt_cap root_complete_yield_retry_count root_complete_yield_retry_cap))
                                                | _ -> reraise ()
                                        buildResult
                                    let build_result =
                                        try
                                            attempt_driver 0
                                        finally
                                            HopacExtensions.clearForcedConcurrencyForRetry ()
                                    build_result
    

                                with
                                    | :? PartEvalTypeError as e -> BuildErrorTrace(show_trace s e.Data0 e.Data1)
                                    | :? CodegenError as e -> BuildFatalError(e.Data1)
                                    | :? CodegenErrorWithPos as e -> BuildErrorTrace(show_trace s e.Data0 e.Data1)
                                    | ex ->
                                        if diag_save_enabled && System.IO.Directory.Exists traceDir then
                                            let guid = System.DateTime.Now |> SpiralDateTime.new_guid_from_date_time
                                            let trace_file = traceDir </> $"{guid}_error.json"
                                            HopacExtensions.start (job {
                                                try
                                                    do! Job.fromAsync ($"{ex}" |> SpiralFileSystem.write_all_text_async trace_file)
                                                with ex ->
                                                    trace Verbose (fun () -> $"Supervisor.supervisor_server.BuildFile.file_build / ex: {ex |> SpiralSm.format_exception}") _locals
                                            })
                                        trace Critical (fun () -> $"Supervisor.supervisor_server.BuildFile.file_build / ex: %A{ex}") _locals
                                        BuildFatalError(ex.Message)
                            | None -> BuildFatalError $"Cannot find `main` in file {Path.GetFileNameWithoutExtension file}."
    

                        // The partial evaluator is using too much stack space, so as a temporary fix, I am running it on a separate thread with much more of it.
                        let result = IVar()
                        let thread = new System.Threading.Thread(System.Threading.ThreadStart(body >> IVar.fill result >> HopacExtensions.start), 1536 <<< 20) // Stack space = 1536MB (1.5GB) for deep staging recursion
                        thread.Start()
                        result >>= handle_build_result
                        )
                let file_find (s : SupervisorState) pdir =
                    trace Verbose (fun () -> $"Supervisor.supervisor_server.BuildFile.file_find / pdir: {pdir}") _locals
                    let uid = (fst s.package_ids).[pdir]
                    match Map.tryFind uid s.packages_infer.ok, Map.tryFind uid s.packages_prepass.ok with
                    | Some a, Some b ->
                        let rec loop = function
                            | ProjFilesTree.Directory(_,_,l) -> list l
                            | ProjFilesTree.File(mid,path,_) ->
                                trace Verbose (fun () -> $"Supervisor.supervisor_server.BuildFile.file_find.loop | File(mid,path,_) / path: {path}") _locals
                                if file = path then file_build s mid (a, b); true else false
                        and list l = List.exists loop l
                        if list b.files.files.tree = false then fatal $"File {Path.GetFileNameWithoutExtension file} cannot be found in the project {spiproj_suffix pdir}"
    

                        s
                    | None, None -> fatal $"Owner of file {Path.GetFileNameWithoutExtension file} has an error. Location: {spiproj_suffix pdir}"; s
                    | _ -> failwith "Compiler error: The project status should be the same in both infer and prepass."
                let update_owner pdir =
                    let order,dirty_packages = topological_sort' (fst s.graph) [pdir]
                    let packages_prepass = wdiff_projenvr_prepass default_env (fst s.package_ids) s.packages s.packages_infer.ok s.packages_prepass (dirty_packages, order.ToArray())
                    file_find {s with packages_prepass = packages_prepass} pdir
                let rec find_owner (x : DirectoryInfo) =
                    if x = null then fatal $"Cannot find the package file of {file}"; s
                    else
                        let x' = x.FullName |> SpiralFileSystem.standardize_path
                        let _diag_bslash = "\\\\"
                        let _diag_pipe = "|"
                        trace Verbose (fun () -> $"Supervisor.supervisor_server.BuildFile.find_owner / x.FullName: {x.FullName |> SpiralSm.replace _diag_bslash _diag_pipe} / x': {x'}") _locals
                        let x_ = x
                        let x = {| FullName = x' |}
                        if Map.containsKey x.FullName s.packages then update_owner x.FullName
                        else find_owner x_.Parent
                find_owner (Directory.GetParent(file))
    

        Job.iterateServer {
            packages = Map.empty
            modules = Map.empty
            packages_infer = {ok=Map.empty; error=Map.empty}
            packages_prepass = {ok=Map.empty; error=Map.empty}
            graph = mirrored_graph_empty
            package_ids = Map.empty, Map.empty
            } loop
    

    /// ### ClientReq
    type ClientReq =
        | ProjectFileOpen of {|uri : string; spiprojText : string|}
        | ProjectFileChange of {|uri : string; spiprojText : string|}
        | ProjectFileLinks of {|uri : string|}
        | ProjectCodeActionExecute of {|uri : string; action : ProjectCodeAction|}
        | ProjectCodeActions of {|uri : string|}
        | FileOpen of {|uri : string; spiText : string|}
        | FileChange of {|uri : string; spiEdit : SpiEdit|}
        | FileDelete of {|uris : string []|} // Also works for project files and directories.
        | FileTokenRange of {|uri : string; range : VSCRange|}
        | HoverAt of {|uri : string; pos : VSCPos|}
        | BuildFile of {|uri : string; backend : string|}
        | Ping of bool
        | Exit of bool
    

    /// ### ClientErrorsRes
    type ClientErrorsRes =
        | FatalError of string
        | TracedError of TracedError
        | PackageErrors of {|uri : string; errors : RString list|}
        | TokenizerErrors of {|uri : string; errors : RString list|}
        | ParserErrors of {|uri : string; errors : RString list|}
        | TypeErrors of {|uri : string; errors : RString list|}
    

    /// ### Supervisor
    type Supervisor = {
        supervisor_ch : SupervisorReq Ch
        }
    

